/**
 * IngredientPriceEngine — CANONICAL pricing pipeline.
 *
 * Pipeline per ingredient:
 *   1. parseIngredientAmount  → grams / ml / pieces
 *   2. lookupCanonical        → canonical entry
 *   3. Convert pieces → grams via PIECE_WEIGHTS
 *   4. Compute cost from price_per_100g or price_per_100ml
 *   5. Apply edible_ratio
 *   6. Apply category floor (prevents absurdly low values)
 *   7. Apply region multiplier
 *   8. Sanity-guard: cap at $50, enforce protein/seafood minimums
 *
 * Country-aware: region multiplier is resolved from currency/locale context.
 */

import {
  CANONICAL_INGREDIENTS,
  CATEGORY_FLOORS,
  COUNTRY_MULTIPLIERS,
  REGION_MULTIPLIERS,
  PIECE_WEIGHTS,
  lookupCanonical,
  getCountryMultiplier,
} from './CanonicalIngredientDatabase';

// ── PricingEnginePro: new v2 engine integrated as primary pipeline ─────────────
import { computeIngredientCostPro, priceRecipeIngredientsPro } from './PricingEnginePro';

// ── Region/country detection ──────────────────────────────────────────────────
// Accepts both old region codes (US, EU, UK, AU, ASIA, SA) and ISO country codes
function getRegionMultiplier(region = 'US') {
  return getCountryMultiplier(region);
}

// ── Liquid density approximations (g/ml) ─────────────────────────────────────
const LIQUID_DENSITIES = {
  oil: 0.92, honey: 1.40, syrup: 1.32, milk: 1.03, cream: 1.01,
  sauce: 1.05, broth: 1.00, stock: 1.00, juice: 1.04, vinegar: 1.01,
  default: 1.00,
};

function getLiquidDensity(ingredientName) {
  const lower = (ingredientName || '').toLowerCase();
  for (const [key, density] of Object.entries(LIQUID_DENSITIES)) {
    if (lower.includes(key)) return density;
  }
  return LIQUID_DENSITIES.default;
}

// ── Unit conversion tables ────────────────────────────────────────────────────
const UNIT_TO_GRAMS = {
  g: 1, gram: 1, grams: 1, kg: 1000, kilogram: 1000, kilograms: 1000,
  oz: 28.35, lb: 453.59, pound: 453.59, pounds: 453.59,
};
const UNIT_TO_ML = {
  ml: 1, milliliter: 1, milliliters: 1,
  l: 1000, liter: 1000, litre: 1000, liters: 1000, litres: 1000,
  cup: 240, cups: 240,
  tbsp: 15, tablespoon: 15, tablespoons: 15,
  tsp: 5, teaspoon: 5, teaspoons: 5,
  'fl oz': 29.57, floz: 29.57,
};

// ── Amount parser ─────────────────────────────────────────────────────────────
function parseIngredientAmount(amountStr, ingredientName = '') {
  if (!amountStr) return null;
  const s = String(amountStr).trim().toLowerCase();
  const ing = ingredientName.toLowerCase();

  // PRIORITY 1: Parenthetical gram/ml hint — e.g. "1 can (400g)"
  const parenG = s.match(/\((?:about\s*|approximately\s*|~\s*)?(\d+(?:\.\d+)?)\s*g\)/i);
  if (parenG) return { grams: parseFloat(parenG[1]), ml: null, pieces: null, raw_quantity: parseFloat(parenG[1]), raw_unit: 'g' };

  const parenMl = s.match(/\((?:about\s*|approximately\s*|~\s*)?(\d+(?:\.\d+)?)\s*ml\)/i);
  if (parenMl) return { grams: null, ml: parseFloat(parenMl[1]), pieces: null, raw_quantity: parseFloat(parenMl[1]), raw_unit: 'ml' };

  // PRIORITY 2: Fraction / mixed-number parser
  function parseFrac(str) {
    const frac = str.match(/^(\d+)\s*\/\s*(\d+)$/);
    if (frac) return parseFloat(frac[1]) / parseFloat(frac[2]);
    const mixed = str.match(/^(\d+)\s+(\d+)\s*\/\s*(\d+)$/);
    if (mixed) return parseFloat(mixed[1]) + parseFloat(mixed[2]) / parseFloat(mixed[3]);
    return parseFloat(str.replace(',', '.'));
  }

  const numMatch = s.match(/^([\d.,]+(?:\s+\d+\s*\/\s*\d+)?|\d+\s*\/\s*\d+)/);
  if (!numMatch) return null;

  const quantity = parseFrac(numMatch[1].trim());
  if (!Number.isFinite(quantity) || quantity <= 0) return null;

  const rest = s.slice(numMatch[0].length).trim();

  // PRIORITY 3: Explicit weight unit
  for (const [unit, factor] of Object.entries(UNIT_TO_GRAMS)) {
    if (new RegExp(`^${unit}\\b`, 'i').test(rest)) {
      return { grams: quantity * factor, ml: null, pieces: null, raw_quantity: quantity, raw_unit: unit };
    }
  }

  // PRIORITY 4: Explicit volume unit
  for (const [unit, factor] of Object.entries(UNIT_TO_ML)) {
    if (new RegExp(`^${unit}\\b`, 'i').test(rest)) {
      return { grams: null, ml: quantity * factor, pieces: null, raw_quantity: quantity, raw_unit: unit };
    }
  }

  // PRIORITY 5: Countable piece words
  const countableWords = [
    'piece', 'pieces', 'slice', 'slices', 'rasher', 'rashers',
    'egg', 'eggs', 'yolk', 'yolks', 'white', 'whites',
    'clove', 'cloves', 'can', 'cans', 'bunch', 'bunches',
    'stalk', 'stalks', 'fillet', 'fillets', 'strip', 'strips',
    'head', 'breast', 'breasts', 'thigh', 'thighs',
    'half', 'halves',
  ];

  for (const word of countableWords) {
    if (rest.startsWith(word) || (!rest && ing.includes(word))) {
      // "half avocado" → 0.5 × avocado piece weight
      const effectiveQty = word === 'half' || word === 'halves' ? quantity * 0.5 : quantity;
      for (const [key, grams] of Object.entries(PIECE_WEIGHTS)) {
        if (ing.includes(key) || key.includes(ing.split(' ')[0])) {
          return { grams: effectiveQty * grams, ml: null, pieces: effectiveQty, raw_quantity: quantity, raw_unit: word };
        }
      }
      if (PIECE_WEIGHTS[word]) {
        return { grams: effectiveQty * PIECE_WEIGHTS[word], ml: null, pieces: effectiveQty, raw_quantity: quantity, raw_unit: word };
      }
      return { grams: null, ml: null, pieces: effectiveQty, raw_quantity: quantity, raw_unit: word };
    }
  }

  // PRIORITY 6: No explicit unit — check ingredient has known piece weight
  if (!rest || /^(about|approximately|~|of|fresh|dried|large|medium|small)/.test(rest)) {
    for (const [key, grams] of Object.entries(PIECE_WEIGHTS)) {
      if (ing.includes(key)) {
        return { grams: quantity * grams, ml: null, pieces: quantity, raw_quantity: quantity, raw_unit: key };
      }
    }
  }

  // PRIORITY 7: Raw number → treat as pieces
  return { grams: null, ml: null, pieces: quantity, raw_quantity: quantity, raw_unit: 'pieces' };
}

// ── Sanity bounds (per-category expected USD per gram, for validation) ─────────
const SANITY_MAX_PER_GRAM = {
  pantry: 0.05,    // Salt, sugar: max $50/kg (very generous)
  spice: 0.30,     // Spices: max $300/kg (some premium spices ok)
  vegetable: 0.02, // Veg: max $20/kg
  fruit: 0.03,     // Fruit: max $30/kg
  grain: 0.015,    // Grains: max $15/kg
  dairy: 0.05,     // Dairy: max $50/kg
  cheese: 0.08,    // Cheese: max $80/kg (truffle cheese ok)
  eggs: 0.05,
  poultry: 0.06,
  meat: 0.10,      // Premium steak ~$100/kg is real
  seafood: 0.12,   // Lobster/caviar edge
  oil: 0.02,
  condiment: 0.03,
  default: 0.10,
};

// ── Core pricing function ─────────────────────────────────────────────────────
/**
 * Compute cost for a single ingredient in USD.
 *
 * @param {string} ingredientName
 * @param {string} amountStr
 * @param {string} [region]        - region code (US, EU, UK, AU, ASIA, SA)
 * @param {number|null} [baseGrams] - pre-normalized grams (from AI generation pipeline)
 * @returns {number|null}
 */
export function computeIngredientCost(ingredientName, amountStr, region = 'US', baseGrams = null) {
  // ── Route through PricingEnginePro v2 ─────────────────────────────────────
  const { cost } = computeIngredientCostPro(ingredientName, amountStr, region, baseGrams);
  if (cost !== null) return cost;

  // ── Legacy fallback (original pipeline) ───────────────────────────────────
  const entry = lookupCanonical(ingredientName);
  const regionMult = getRegionMultiplier(region);

  // ── Fast path: pre-computed base_grams (from AI generation) ─────────────
  if (baseGrams !== null && Number.isFinite(baseGrams) && baseGrams > 0) {
    return _computeFromGrams(ingredientName, baseGrams, entry, regionMult);
  }

  // ── Parse amount string ──────────────────────────────────────────────────
  const parsed = parseIngredientAmount(amountStr, ingredientName);
  if (!parsed) return null;

  let { grams, ml, pieces } = parsed;

  // ── Convert ml → grams if entry is gram-based ────────────────────────────
  if (grams == null && ml != null && entry?.price_per_100g != null) {
    grams = ml * getLiquidDensity(ingredientName);
    ml = null;
  }

  // ── Piece resolution ─────────────────────────────────────────────────────
  if (grams == null && ml == null && pieces != null) {
    // Direct per-piece pricing
    if (entry?.price_per_piece != null) {
      const rawCost = pieces * entry.price_per_piece;
      const floor = CATEGORY_FLOORS[entry.category] ?? CATEGORY_FLOORS.default;
      const pieceWeight = PIECE_WEIGHTS[ingredientName.toLowerCase().split(' ')[0]] ?? 50;
      const minCost = (pieces * pieceWeight / 100) * floor;
      return parseFloat((Math.max(rawCost, minCost) * regionMult).toFixed(3));
    }
    // Convert pieces → grams via PIECE_WEIGHTS
    const ing = ingredientName.toLowerCase();
    for (const [key, g] of Object.entries(PIECE_WEIGHTS)) {
      if (ing.includes(key) || key.includes(ing.split(' ')[0])) {
        grams = pieces * g;
        break;
      }
    }
    // Generic fallback: 100g/piece for unknown items
    if (grams == null) grams = pieces * 100;
  }

  // ── Compute cost from resolved grams or ml ───────────────────────────────
  if (grams != null && grams > 0) {
    return _computeFromGrams(ingredientName, grams, entry, regionMult);
  }
  if (ml != null && ml > 0) {
    return _computeFromMl(ingredientName, ml, entry, regionMult);
  }

  return null;
}

function _computeFromGrams(ingredientName, grams, entry, regionMult) {
  const floor = entry
    ? (CATEGORY_FLOORS[entry.category] ?? CATEGORY_FLOORS.default)
    : CATEGORY_FLOORS.default;

  let rawCost = null;

  if (entry?.price_per_100g != null) {
    const edible = entry.edible_ratio ?? 1.0;
    const edibleG = grams * edible;
    rawCost = (edibleG / 100) * entry.price_per_100g;
  } else if (entry?.price_per_100ml != null) {
    // Liquid measured in grams — convert via density
    const ml = grams / getLiquidDensity(ingredientName);
    const edible = entry.edible_ratio ?? 1.0;
    rawCost = (ml * edible / 100) * entry.price_per_100ml;
  } else {
    // No canonical match — use smart category-inferred floor
    rawCost = (grams / 100) * _inferFallbackPrice(ingredientName, floor);
  }

  // Apply category floor
  const minCost = (grams / 100) * floor;
  rawCost = Math.max(rawCost, minCost);

  // Apply protein/seafood hard minimums
  rawCost = _enforceProteinMinimums(rawCost, grams, entry);

  // Apply region multiplier
  const finalCost = rawCost * regionMult;

  // Sanity guard
  return _sanityCap(finalCost, grams, ingredientName, entry);
}

function _computeFromMl(ingredientName, ml, entry, regionMult) {
  const floor = entry
    ? (CATEGORY_FLOORS[entry.category] ?? CATEGORY_FLOORS.default)
    : CATEGORY_FLOORS.default;

  let rawCost = null;

  if (entry?.price_per_100ml != null) {
    const edible = entry.edible_ratio ?? 1.0;
    rawCost = (ml * edible / 100) * entry.price_per_100ml;
  } else if (entry?.price_per_100g != null) {
    const grams = ml * getLiquidDensity(ingredientName);
    const edible = entry.edible_ratio ?? 1.0;
    rawCost = (grams * edible / 100) * entry.price_per_100g;
  } else {
    rawCost = (ml / 100) * _inferFallbackPrice(ingredientName, floor);
  }

  const minCost = (ml / 100) * floor;
  rawCost = Math.max(rawCost, minCost);

  const finalCost = rawCost * regionMult;
  return _sanityCap(finalCost, ml, ingredientName, entry);
}

function _inferFallbackPrice(ingredientName, floorPrice) {
  const ing = ingredientName.toLowerCase();
  if (/chicken|turkey|duck|poultry|breast|thigh/i.test(ing)) return CATEGORY_FLOORS.poultry;
  if (/beef|pork|lamb|meat|steak|veal|venison/i.test(ing)) return CATEGORY_FLOORS.meat;
  if (/fish|salmon|tuna|shrimp|prawn|seafood|cod|tilapia|scallop|squid|calamari/i.test(ing)) return CATEGORY_FLOORS.seafood;
  if (/egg/i.test(ing)) return CATEGORY_FLOORS.eggs;
  if (/cheese|mozzarella|parmesan|cheddar|feta/i.test(ing)) return CATEGORY_FLOORS.cheese;
  if (/milk|cream|yogurt|butter|dairy/i.test(ing)) return CATEGORY_FLOORS.dairy;
  if (/oil|fat|lard|ghee/i.test(ing)) return CATEGORY_FLOORS.oil;
  if (/spice|herb|cumin|paprika|oregano|thyme|pepper|basil/i.test(ing)) return CATEGORY_FLOORS.spice;
  if (/sauce|dressing|vinegar|condiment/i.test(ing)) return CATEGORY_FLOORS.condiment;
  if (/flour|rice|pasta|bread|grain|noodle|oat/i.test(ing)) return CATEGORY_FLOORS.grain;
  return floorPrice ?? CATEGORY_FLOORS.default;
}

function _enforceProteinMinimums(cost, grams, entry) {
  if (!entry || grams <= 0) return cost;
  const SEAFOOD_MIN = 0.010; // $10/kg absolute floor
  const PROTEIN_MIN = 0.005; // $5/kg absolute floor
  const pricePerGram = cost / grams;
  if (entry.category === 'seafood' && pricePerGram < SEAFOOD_MIN) {
    return grams * SEAFOOD_MIN;
  }
  if (['poultry', 'meat'].includes(entry.category) && pricePerGram < PROTEIN_MIN) {
    return grams * PROTEIN_MIN;
  }
  return cost;
}

function _sanityCap(cost, quantity, ingredientName, entry) {
  if (!Number.isFinite(cost) || cost < 0) return null;

  // Per-ingredient cap: $50 max
  const MAX_INGREDIENT_USD = 50;
  if (cost > MAX_INGREDIENT_USD) {
    const category = entry?.category ?? 'default';
    const maxPerG = SANITY_MAX_PER_GRAM[category] ?? SANITY_MAX_PER_GRAM.default;
    const capped = Math.min(cost, quantity * maxPerG * 1.5, MAX_INGREDIENT_USD);
    console.warn(
      `[PriceEngine] Capped: ${ingredientName} $${cost.toFixed(2)} → $${capped.toFixed(2)} ` +
      `(qty=${quantity}, category=${category})`
    );
    return parseFloat(capped.toFixed(3));
  }

  return parseFloat(cost.toFixed(3));
}

// ── Culinary validity filter ──────────────────────────────────────────────────
const SUPPLEMENT_PATTERNS = [
  /\bprotein\s*powder\b/i, /\bwhey\b/i, /\bcasein\b/i,
  /\berythritol\b/i, /\bxylitol\b/i, /\ballulose\b/i,
  /\bcreatine\b/i, /\bpre.?workout\b/i, /\bcaffeine\s*powder\b/i,
  /\bcollagen\s*powder\b/i, /\bcollagen\s*peptide\b/i,
];
const SAVORY_DISH_PATTERNS = [
  /pizza/i, /pasta/i, /stir.?fry/i, /curry/i, /soup/i, /stew/i,
  /risotto/i, /burger/i, /taco/i, /sandwich/i, /salad/i, /wrap/i,
  /rice\s*bowl/i, /noodle/i, /ramen/i, /sauté/i, /roast/i, /grill/i,
  /chicken/i, /beef/i, /pork/i, /fish/i, /salmon/i,
];

function isSavoryDish(recipe) {
  const title = (recipe.title || '').toLowerCase();
  const meal = (recipe.meal_type || '').toLowerCase();
  if (meal === 'breakfast' || meal === 'snack') return false;
  return SAVORY_DISH_PATTERNS.some(p => p.test(title));
}

function filterCulinaryInvalids(recipe) {
  if (!isSavoryDish(recipe)) return recipe;
  return {
    ...recipe,
    ingredients: (recipe.ingredients || []).map(group => {
      if ((group.group || '').toLowerCase().includes('optional')) return group;
      if ((group.group || '').toLowerCase().includes('suggested')) return group;
      return {
        ...group,
        items: (group.items || []).filter(item => {
          if (!item?.name) return true;
          if (SUPPLEMENT_PATTERNS.some(p => p.test(item.name))) {
            console.warn(`[PriceEngine] Removed supplement: "${item.name}" in "${recipe.title}"`);
            return false;
          }
          return true;
        }),
      };
    }).filter(g => (g.items || []).length > 0),
  };
}

// ── Recipe pricer (main export) ───────────────────────────────────────────────
/**
 * Price all ingredients in a recipe and return enriched recipe object.
 *
 * @param {object} recipe
 * @param {array}  [pantryItems]   - unused, kept for API compat
 * @param {array}  [shopProducts]  - unused, kept for API compat
 * @param {string} [region]        - region code for multiplier
 * @returns {object} enriched recipe with ingredient_cost fields + totals
 */
export function priceRecipeIngredients(recipe, pantryItems = [], shopProducts = [], region = 'US') {
  if (!recipe?.ingredients?.length) return recipe;

  // Use PricingEnginePro v2 as primary pipeline
  return priceRecipeIngredientsPro(recipe, pantryItems, shopProducts, region);

  // ── Legacy pipeline below (kept for reference, unreachable unless above fails) ──
  // eslint-disable-next-line no-unreachable
  const filteredRecipe = filterCulinaryInvalids(recipe);
  const baseServings = filteredRecipe.servings || 1;

  let totalCost = 0;
  let hasAnyPriced = false;
  let allRequiredPriced = true;

  const pricedIngredients = filteredRecipe.ingredients.map(group => ({
    ...group,
    items: (group.items || []).map(item => {
      if (!item?.name) return item;

      const cost = computeIngredientCost(
        item.name,
        item.amount || '',
        region,
        item.base_grams ?? null
      );

      if (cost != null && cost > 0) {
        hasAnyPriced = true;
        totalCost += cost;
        const entry = lookupCanonical(item.name);
        return {
          ...item,
          ingredient_cost: parseFloat(cost.toFixed(3)),
          _price_source: {
            type: 'canonical',
            confidence: entry?.match_confidence ?? (entry ? 0.8 : 0.4),
            match_method: entry?.match_method ?? 'unmatched',
            canonical_name: entry?.name ?? null,
            category: entry?.category ?? null,
            country_used: region,
            country_multiplier: getRegionMultiplier(region),
          },
        };
      } else {
        if (!item.optional) allRequiredPriced = false;
        return { ...item, ingredient_cost: null, _price_source: { confidence: 'unknown' } };
      }
    }),
  }));

  const pricingStatus = hasAnyPriced
    ? (allRequiredPriced ? 'known' : 'partial')
    : 'unknown';

  return {
    ...filteredRecipe,
    ingredients: pricedIngredients,
    total_cost: hasAnyPriced ? parseFloat(totalCost.toFixed(2)) : null,
    cost_per_serving: hasAnyPriced && baseServings > 0
      ? parseFloat((totalCost / baseServings).toFixed(2))
      : null,
    has_unknown_pricing: !hasAnyPriced,
    pricing_status: pricingStatus,
    pricing_currency: 'USD',
    pricing_region: region,
  };
}

import React from "react";
import { Lock, Eye, ShieldAlert } from "lucide-react";
import { cn } from "@/lib/utils";

/**
 * PrivacyBadge — Shows the visibility/moderation state of a recipe.
 *
 * CRITICAL STATE PRECEDENCE:
 * 1. moderation_status = removed_by_moderation → ALWAYS shows "Removed" badge (rose/red)
 *    This MUST override any is_public/private state — they are separate concerns.
 * 2. is_public = true and moderation_status = active → no badge (public)
 * 3. is_public = false and moderation_status = active → "Private" badge (gray)
 *
 * A removed recipe must NEVER show as "Private". They are completely different states.
 */
export default function PrivacyBadge({ isPublic, visibility, moderationStatus, source, size = "sm", className = "" }) {
  const sizeMap = {
    xs: { icon: 11, padding: "px-1.5 py-0.5", text: "text-[9px]" },
    sm: { icon: 13, padding: "px-2 py-0.5", text: "text-[10px]" },
    md: { icon: 15, padding: "px-2.5 py-1", text: "text-xs" },
  };
  const config = sizeMap[size] || sizeMap.sm;

  // ── MODERATION REMOVED — highest priority, overrides all user visibility ──
  if (moderationStatus === 'removed_by_moderation') {
    return (
      <div
        className={cn(
          "inline-flex items-center gap-1 rounded-full bg-rose-100 text-rose-700 font-bold flex-shrink-0",
          config.padding,
          config.text,
          className
        )}
        title="This recipe was removed by moderation"
      >
        <ShieldAlert style={{ width: config.icon, height: config.icon }} />
        <span>Removed</span>
      </div>
    );
  }

  // ── AI-generated recipe: show beautiful "Reciply Generated" tag ──
  if (source === 'generated') {
    return (
      <div
        className={cn(
          "inline-flex items-center gap-1 rounded-full font-bold flex-shrink-0 overflow-hidden relative",
          config.padding,
          config.text,
          className
        )}
        style={{
          background: "linear-gradient(135deg, #f97316 0%, #fb923c 50%, #f97316 100%)",
          backgroundSize: "200% 100%",
          color: "#fff",
          boxShadow: "0 2px 8px rgba(249,115,22,0.45), inset 0 1px 0 rgba(255,255,255,0.25)",
          border: "1px solid rgba(255,255,255,0.2)",
        }}
        title="AI-generated recipe"
      >
        {/* light wave sweep animation */}
        <span
          className="absolute inset-0 pointer-events-none"
          style={{
            background: "linear-gradient(105deg, transparent 35%, rgba(255,255,255,0.38) 50%, transparent 65%)",
            backgroundSize: "200% 100%",
            animation: "aiTagWave 2.4s ease-in-out infinite",
          }}
        />
        <style>{`
          @keyframes aiTagWave {
            0%   { background-position: -100% center; }
            100% { background-position: 220% center; }
          }
        `}</style>
        <span style={{ fontSize: 8 }}>✦</span>
        <span className="relative z-10">Reciply AI</span>
      </div>
    );
  }

  // ── Normal user-controlled privacy ──
  if (isPublic && !visibility) return null;
  if (visibility === "public") return null;

  if (visibility === "friends") {
    return (
      <div
        className={cn(
          "inline-flex items-center gap-1 rounded-full bg-blue-100 text-blue-600 font-medium flex-shrink-0",
          config.padding,
          config.text,
          className
        )}
        title="Only visible to your followers"
      >
        <Eye style={{ width: config.icon, height: config.icon }} />
        <span>Friends Only</span>
      </div>
    );
  }

  // Private (is_public=false, active moderation state)
  return (
    <div
      className={cn(
        "inline-flex items-center gap-1 rounded-full bg-slate-100 text-slate-600 font-medium flex-shrink-0",
        config.padding,
        config.text,
        className
      )}
      title="This recipe is private and only visible to you"
    >
      <Lock style={{ width: config.icon, height: config.icon }} />
      <span>Private</span>
    </div>
  );
}

/**
 * VipRecipeCard — Premium horizontal recipe card.
 */
import React, { useState, useEffect } from "react";
import { resolveAvatarUrl } from "../../utils/avatarResolver";
import { useAuthorIdentity } from "./useAuthorIdentity";
import { motion, AnimatePresence } from "framer-motion";
import {
  Heart, Bookmark, Clock, Star, ChefHat,
  MoreHorizontal, Flame, Beef, ShieldAlert, ShoppingCart, Check as CheckIcon
} from "lucide-react";
import { createPageUrl } from "../../utils";
import { navigateToPost } from "../../lib/postNavigation";
import RecipeCostRow from "./RecipeCostRow";
import PrivacyBadge from "./PrivacyBadge";
import { formatCostForDisplay } from "./formatCostForDisplay";
