/**
 * Get nutrition with full fallback chain:
 *   1. nutrition_total_for_recipe (authoritative stored total)
 *   2. nutrition_per_serving * servings
 *   3. legacy nutrition field
 *   4. Compute from ingredients via NutritionEngine (never returns null)
 */
function getNutrition(recipe) {
  const s = Math.max(1, recipe.servings || 1);

  // 1. nutrition_total_for_recipe — authoritative total
  const t = recipe.nutrition_total_for_recipe;
  if (t?.calories > 0) {
    return {
      calories: Math.round(t.calories),
      protein:  Math.round(t.protein ?? t.protein_g ?? 0),
    };
  }

  // 2. nutrition_per_serving stored → derive total
  const ps = recipe.nutrition_per_serving;
  if (ps?.calories > 0) {
    return {
      calories: Math.round(ps.calories * s),
      protein:  Math.round((ps.protein ?? ps.protein_g ?? 0) * s),
    };
  }

  // 3. Legacy nutrition field (treat as total)
  const leg = recipe.nutrition;
  if (leg?.calories > 0) {
    return {
      calories: Math.round(leg.calories),
      protein:  Math.round(leg.protein ?? leg.protein_g ?? 0),
    };
  }

  // 4. Compute from ingredients as last resort
  if (recipe.ingredients?.length > 0) {
    const result = computeNutrition(recipe.ingredients, s, s);
    if (result?.invariants?.pass && result.total?.calories > 0) {
      return {
        calories: Math.round(result.total.calories),
        protein:  Math.round(result.total.protein_g ?? 0),
      };
    }
  }

  return null;
}

// Arrow right SVG inline — ensures no import issues
function ArrowRightSVG() {
  return (
    <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.8" strokeLinecap="round" strokeLinejoin="round">
      <line x1="5" y1="12" x2="19" y2="12" />
      <polyline points="12 5 19 12 12 19" />
    </svg>
  );
}

export default function VipRecipeCard({
  recipe,
  currentUser = null,
  showCreator = false,
  showLike = false,
  showSave = false,
  showCook = true,
  showMenu = false,
  isLiked = false,
  isSaved = false,
  // postId: if caller knows the linked Post entity ID, pass it for direct removed-post routing
  postId = null,
  onLike, onSave, onMenu, onClick,
}) {
  const { t } = useLocalization();
  const { displayName: authorName, avatarUrl: authorAvatar } = useAuthorIdentity(recipe, currentUser);
  const { viewer_has_liked: localLiked, like_count: localCount, disabled: likeBlocked, toggleLike: controllerToggle } = useLikeUnified(
    'recipe',
    showLike ? recipe.id : null,
    isLiked,
    recipe.likes_count ?? recipe.like_count ?? 0
  );

  // Unified save store — mirrors like system, syncs across all mounted surfaces
  const { viewer_has_saved: storeSaved, disabled: saveBlocked, toggleSave } = useSaveUnified(
    showSave && recipe.source !== 'generated' ? recipe.id : null,
    isSaved,
    recipe.saves_count ?? 0
  );

  const [imgErr,    setImgErr]    = useState(false);
  const [likePop,   setLikePop]   = useState(false);
  const [btnHover,  setBtnHover]  = useState(false);
  const [cartState, setCartState] = useState("idle"); // idle | adding | added

  const handleAddToShopping = async (e) => {
    e.stopPropagation();
    if (cartState !== "idle" || !recipe.ingredients?.length) return;
    setCartState("adding");
    try {
      const allItems = recipe.ingredients.flatMap(g => (g.items || []).filter(i => !i.optional));
      const existing = await base44.entities.ShoppingList.filter({ recipe_id: recipe.id }).catch(() => []);
      const existingNames = new Set(existing.map(e => e.name?.toLowerCase()));
      const toAdd = allItems.filter(i => !existingNames.has(i.name?.toLowerCase()));
      if (toAdd.length > 0) {
        await base44.entities.ShoppingList.bulkCreate(
          toAdd.map(i => ({
            name: i.name,
            amount: i.amount || "",
            recipe_id: recipe.id,
            recipe_title: recipe.title,
            is_bought: false,
            cost: i.ingredient_cost || null,
          }))
        );
      }
      setCartState("added");
      setTimeout(() => setCartState("idle"), 2500);
    } catch {
      setCartState("idle");
    }
  };



  // For generated recipes, fall back to prop-driven isSaved (different system)
  const saved = recipe.source === 'generated' ? isSaved : storeSaved;

  const totalTime = (recipe.cook_time || 0) + (recipe.prep_time || 0);
  const nut       = getNutrition(recipe);
  const rating    = recipe.avg_rating || 0;
  const reviews   = recipe.review_count || 0;
  const calStr    = nut?.calories > 0 ? `${Math.round(nut.calories)}` : null;
  const protStr   = (nut?.protein ?? 0) > 0 ? `${Math.round(nut.protein)}g` : null;
  const totalCost = recipe.total_cost && recipe.total_cost > 0 ? recipe.total_cost : null;
  const perServCost = recipe.cost_per_serving && recipe.cost_per_serving > 0 ? recipe.cost_per_serving : null;
  const costStr   = totalCost ? formatCostForDisplay(totalCost) : null;
  const costPerStr = perServCost ? `${formatCostForDisplay(perServCost)}/srv` : null;
  const desc      = clampDescription(recipe.description);

  const isModRemoved = recipe.moderation_status === 'removed_by_moderation';

  const go = () => {
    if (onClick) { onClick(); return; }
    // Use canonical resolver — handles removed/active routing correctly
    navigateToPost({
      recipeId: recipe.id,
      postId: postId || recipe.post_id || null,
      moderationStatus: recipe.moderation_status,
      viewerId: currentUser?.id,
      ownerId: recipe.author_id,
      ownerEmail: recipe.author_email,
      viewerEmail: currentUser?.email,
    });
  };

  const goUser = (e) => {
    e.stopPropagation();
    if (!recipe.author_id) return;
    // If recipe was uploaded to a shop, go to shop; otherwise go to user profile
    if (recipe.shop_id) {
      window.location.href = createPageUrl("Shop") + `?id=${recipe.shop_id}`;
    } else {
      window.location.href = createPageUrl("UserProfile") + `?userId=${recipe.author_id}`;
    }
  };

  const handleLike = async (e) => {
    e.stopPropagation();
    e.preventDefault();
    if (!showLike || likeBlocked) return;
    setLikePop(true);
    setTimeout(() => setLikePop(false), 500);
    await controllerToggle(e);
  };

  // Intercept card click — if like is on cooldown and user clicked the like area, swallow it
  const handleCardClick = (e) => {
    if (likeBlocked && e.target.closest('[data-like-btn]')) {
      e.stopPropagation();
      e.preventDefault();
      return;
    }
    go();
  };

  const handleSave = async (e) => {
    e.stopPropagation();
    if (saveBlocked) return;
    if (recipe.source === 'generated') {
      // AI-generated recipes: toggle recipe.is_saved via Recipe entity (separate system)
      const next = !saved;
      try {
        await base44.entities.Recipe.update(recipe.id, { is_saved: next });
        onSave?.(recipe);
      } catch {}
    } else {
      // Normal recipes: use unified save store (toggleRecipeSave called inside)
      await toggleSave(e);
      onSave?.(recipe);
    }
  };

  return (
    <motion.div
      onClick={handleCardClick}
      whileTap={{ scale: 0.977 }}
      transition={{ type: "spring", stiffness: 420, damping: 32 }}
      className="w-full cursor-pointer select-none group"
      style={{
        background: isModRemoved ? "#f8f8f8" : "#fff",
        borderRadius: 22,
        border: isModRemoved ? "1.5px solid rgba(239,68,68,0.25)" : "1px solid rgba(15,23,42,0.07)",
        boxShadow: "0 2px 10px rgba(0,0,0,0.055), 0 8px 28px rgba(0,0,0,0.07)",
        overflow: "hidden",
        display: "flex",
        flexDirection: "row",
        minHeight: 196,
        opacity: isModRemoved ? 0.78 : 1,
      }}
    >
      {/* ── IMAGE ─────────────────────────────────────────── */}
      <div className="relative flex-shrink-0 overflow-hidden" style={{ width: 152, minHeight: 196 }}>
        {!imgErr ? (
          <img
            src={recipe.hero_image_url || recipe.image_url ||
              "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=500&h=600&fit=crop"}
            alt={recipe.title}
            className="absolute inset-0 w-full h-full transition-transform duration-500 group-hover:scale-[1.04]"
            style={{ objectFit: "cover", objectPosition: "center" }}
            loading="eager"
            decoding="async"
            onError={() => setImgErr(true)}
          />
        ) : (
          <div className="absolute inset-0 flex items-center justify-center"
            style={{ background: "linear-gradient(135deg,#fef3c7,#fed7aa)" }}>
            <ChefHat className="w-10 h-10" style={{ color: "#f97316" }} />
          </div>
        )}

        {/* Scrim */}
        <div className="absolute inset-0 pointer-events-none"
          style={{ background: "linear-gradient(to top, rgba(0,0,0,0.38) 0%, transparent 55%)" }} />

        {/* Moderation removed overlay */}
        {isModRemoved && (
          <div className="absolute inset-0 flex flex-col items-center justify-center gap-1 pointer-events-none"
            style={{ background: "rgba(0,0,0,0.55)", backdropFilter: "blur(3px)" }}>
            <ShieldAlert className="w-7 h-7 text-rose-300" />
            <span style={{ fontSize: 9, fontWeight: 800, color: "#fca5a5", letterSpacing: "0.05em" }}>REMOVED</span>
          </div>
        )}

        {/* Time + Difficulty chips — global premium chip system */}
        <div className="absolute bottom-2 left-2 right-2 flex items-center justify-between gap-1">
          {totalTime > 0 ? <TimeChip minutes={totalTime} variant="light" size="sm" /> : <span />}
          {recipe.difficulty && recipe.source !== "generated" && (
            <DifficultyChip difficulty={recipe.difficulty} size="sm" />
          )}
        </div>
      </div>

      {/* ── CONTENT ───────────────────────────────────────── */}
      <div
        className="flex-1 flex flex-col min-w-0 px-3 pt-2.5 pb-2.5"
        style={{ maxWidth: "calc(100% - 152px)", WebkitFontSmoothing: "antialiased", MozOsxFontSmoothing: "grayscale" }}
      >
        {/* Top row: privacy + actions (shopping cart, menu, bookmark) */}
        <div className="flex items-center justify-between gap-1 mb-0.5 flex-shrink-0" style={{ minHeight: 22 }}>
          <PrivacyBadge isPublic={recipe.is_public} moderationStatus={recipe.moderation_status} source={recipe.source} size="xs" />
          <div className="flex items-center gap-1">
            {/* Shopping cart — top right for clean bottom row */}
            {recipe.id && recipe.ingredients?.length > 0 && (
              <motion.button
                whileTap={{ scale: 0.82 }}
                onClick={handleAddToShopping}
                className="w-7 h-7 rounded-full flex items-center justify-center flex-shrink-0 transition-all"
                style={cartState === "added"
                  ? { background: "linear-gradient(135deg,#10b981,#059669)", border: "1.5px solid rgba(16,185,129,0.4)" }
                  : { background: "rgba(16,185,129,0.08)", border: "1.5px solid rgba(16,185,129,0.2)" }
                }
                title={t('shopping.add_ingredients', 'Add ingredients to shopping list')}
              >
                {cartState === "adding" ? (
                  <span className="w-3 h-3 rounded-full border border-emerald-400 border-t-transparent animate-spin" />
                ) : cartState === "added" ? (
                  <CheckIcon className="w-3 h-3 text-white" strokeWidth={3} />
                ) : (
                  <ShoppingCart className="w-3.5 h-3.5" style={{ color: "#10b981" }} />
                )}
              </motion.button>
            )}
            {showMenu && !isModRemoved && (
              <motion.button whileTap={{ scale: 0.72 }}
                aria-label="More options"
                onClick={(e) => { e.stopPropagation(); onMenu?.(recipe); }}
                className="w-7 h-7 flex items-center justify-center rounded-full hover:bg-slate-100">
                <MoreHorizontal className="w-3.5 h-3.5" style={{ color: "#94a3b8" }} />
              </motion.button>
            )}
            {showSave && !isModRemoved && (
              <motion.button whileTap={{ scale: 0.7 }}
                aria-label={saved ? "Unsave recipe" : "Save recipe"}
                onClick={handleSave}
                disabled={saveBlocked && recipe.source !== 'generated'}
                className="w-7 h-7 flex items-center justify-center rounded-full hover:bg-orange-50">
                <Bookmark className="w-3.5 h-3.5"
                  style={{ fill: saved ? "#f97316" : "transparent", color: saved ? "#f97316" : "#cbd5e1", strokeWidth: 2, opacity: saveBlocked ? 0.5 : 1 }} />
              </motion.button>
            )}
          </div>
        </div>

        {/* Title */}
        <h3
          className="leading-snug mb-0.5 flex-shrink-0 truncate"
          style={{ fontSize: 14.5, fontWeight: 800, color: "#0f172a", letterSpacing: "-0.022em", fontFamily: "'Inter', -apple-system, sans-serif" }}
        >
          {recipe.title?.length > 23 ? recipe.title.slice(0, 23).trimEnd() + "…" : recipe.title}
        </h3>

        {/* Description — 2 lines max with ellipsis */}
         <p
           className="flex-shrink-0 mb-0.5 line-clamp-2 break-words"
           style={{
             fontSize: 10.5, color: "#94a3b8", lineHeight: 1.4, wordBreak: "break-word"
           }}
         >
           {desc || <span style={{ opacity: 0.4 }}>No description</span>}
         </p>

        {/* Recipe by / Shop by — clickable; shop recipes get gold treatment */}
        {(showCreator || recipe.author_name || recipe.source === "generated") && (
          <>
            {recipe.source === "generated" ? (
              <>
                <span style={{ fontSize: 10, color: "#64748b", fontWeight: 700, letterSpacing: "0.01em", display: "block", marginBottom: 4 }}>{t('recipe.by', 'Recipe by')}:</span>
                <span style={{ fontSize: 10, fontWeight: 700, color: "#0f172a", display: "block", marginBottom: 8 }}>Reciply AI</span>
              </>
            ) : recipe.shop_id ? (
              <div className="flex flex-col items-start mb-1 flex-shrink-0">
                {/* Line 1: plain label */}
                <span style={{ fontSize: 10, color: "#64748b", fontWeight: 700, letterSpacing: "0.01em", marginBottom: 3 }}>{t('recipe.shop_by', 'Shop by')}:</span>
                {/* Line 2: gold pill with avatar + display name */}
                <button 
                  onClick={goUser}
                  className="inline-flex items-center gap-1.5 hover:opacity-90 transition-opacity px-2 py-0.5 rounded-full"
                  style={{ cursor: "pointer", background: "linear-gradient(135deg, #B8860B 0%, #DAA520 30%, #F7C948 60%, #DAA520 100%)", boxShadow: "0 1px 6px rgba(218,165,32,0.3), inset 0 1px 0 rgba(255,255,255,0.3)", border: "none" }}
                >
                  <div
                    className="w-[16px] h-[16px] rounded-full overflow-hidden flex-shrink-0"
                    style={{ background: authorAvatar ? 'transparent' : 'rgba(255,255,255,0.3)' }}
                  >
                    {authorAvatar
                      ? <img src={authorAvatar} alt="" className="w-full h-full object-cover" />
                      : <span className="w-full h-full flex items-center justify-center text-[7px] font-bold text-white leading-none">
                          {(authorName?.trim()?.charAt(0) || '?').toUpperCase()}
                        </span>
                    }
                  </div>
                  <span style={{ fontSize: 10, fontWeight: 700, color: "#3d1f00", maxWidth: 80 }} className="truncate">
                    {authorName}
                  </span>
                </button>
              </div>
            ) : (
              <>
                <span style={{ fontSize: 10, color: "#64748b", fontWeight: 700, letterSpacing: "0.01em", display: "block", marginBottom: 4 }}>{t('recipe.by', 'Recipe by')}:</span>
                <button 
                  onClick={goUser}
                  className="flex items-center gap-1.5 mb-1 hover:opacity-75 w-fit flex-shrink-0 transition-opacity"
                  style={{ cursor: "pointer" }}
                >
                  <div
                    className="w-[18px] h-[18px] rounded-full overflow-hidden flex-shrink-0"
                    style={{ background: authorAvatar ? 'transparent' : 'linear-gradient(135deg, #818cf8, #a78bfa)' }}
                  >
                    {authorAvatar
                      ? <img src={authorAvatar} alt="" className="w-full h-full object-cover" />
                      : <span className="w-full h-full flex items-center justify-center text-[7px] font-bold text-white leading-none">
                          {(authorName?.trim()?.charAt(0) || '?').toUpperCase()}
                        </span>
                    }
                  </div>
                  <span style={{ fontSize: 10, fontWeight: 700, color: "#0f172a", maxWidth: 80 }} className="truncate">
                    {authorName}
                  </span>
                </button>
              </>
            )}
          </>
        )}

        {/* Rating */}
        <div className="flex items-center gap-[2px] mb-1 flex-shrink-0">
          {[1,2,3,4,5].map(i => (
            <Star key={i} className="w-[8px] h-[8px]"
              style={{
                fill: rating > 0 && i <= Math.round(rating) ? "#f59e0b" : "#e2e8f0",
                color: rating > 0 && i <= Math.round(rating) ? "#f59e0b" : "#e2e8f0",
              }} />
          ))}
          {rating > 0 ? (
            <>
              <span className="text-[9px] font-semibold ml-1" style={{ color: "#f59e0b" }}>{rating.toFixed(1)}</span>
              <span className="text-[8px] ml-0.5" style={{ color: "#cbd5e1" }}>({reviews})</span>
            </>
          ) : (
            <span className="text-[8.5px] ml-1" style={{ color: "#cbd5e1" }}>{t('recipe.not_rated', 'Not rated (0)')}</span>
          )}
        </div>

        {/* Cal · Protein */}
        <div className="flex items-center gap-2 mb-0.5 flex-shrink-0">
          <span className="flex items-center gap-[3px] whitespace-nowrap" style={{ fontSize: 10, color: "#64748b", fontWeight: 600 }}>
            <Flame className="w-[9px] h-[9px] flex-shrink-0" style={{ color: "#f97316" }} />
            <span>{calStr ?? "—"}</span>
            <span style={{ color: "#cbd5e1", fontWeight: 400 }}>cal</span>
          </span>
          <span style={{ color: "#e2e8f0", fontSize: 9 }}>·</span>
          <span className="flex items-center gap-[3px] whitespace-nowrap" style={{ fontSize: 10, color: "#6366f1", fontWeight: 600 }}>
            <Beef className="w-[9px] h-[9px] flex-shrink-0" style={{ color: "#6366f1" }} />
            <span>{protStr ?? "—"}</span>
            <span style={{ color: "#cbd5e1", fontWeight: 400 }}>prot</span>
          </span>
        </div>

        {/* Pricing row — locale-aware currency via PriceTag */}
        {(recipe.total_cost > 0 || recipe.cost_per_serving > 0) && (
          <div className="flex items-center justify-between mb-1 flex-shrink-0 gap-1">
            {recipe.total_cost > 0 && (
              <span style={{ fontSize: 10, color: "#94a3b8", fontWeight: 600 }}>
                {t('recipe.total', 'Total')}: <PriceTag usdAmount={recipe.total_cost} variant="plain" className="text-slate-800" />
              </span>
            )}
            {recipe.cost_per_serving > 0 && (
              <PriceTag usdAmount={recipe.cost_per_serving} variant="pill" />
            )}
          </div>
        )}

        {/* Bottom actions — like + view recipe (shopping cart moved to top-right) */}
        <div className="mt-auto pt-1 flex items-center gap-1.5 flex-shrink-0 pr-1">
          {showLike && (
            <motion.button
              whileTap={likeBlocked ? {} : { scale: 0.72 }}
              onClick={handleLike}
              onDoubleClick={(e) => e.preventDefault()} // Block accidental double-tap
              disabled={likeBlocked}
              aria-label={localLiked ? "Unlike recipe" : "Like recipe"}
              data-like-btn
              className="relative flex items-center gap-[5px] rounded-full flex-shrink-0 transition-opacity"
              style={{
                height: 28, paddingInline: 10, width: 'fit-content',
                background: localLiked ? "#fff1f2" : "#f8fafc",
                border: `1.5px solid ${localLiked ? "#fca5a5" : "#e2e8f0"}`,
                pointerEvents: likeBlocked ? 'none' : 'auto',
                opacity: likeBlocked ? 0.5 : 1,
                cursor: likeBlocked ? 'not-allowed' : 'pointer',
              }}>
              <AnimatePresence>
                {likePop && !likeBlocked && (
                  <motion.span className="absolute inset-0 flex items-center justify-center pointer-events-none text-sm"
                    initial={{ scale: 0.6, opacity: 1 }} animate={{ scale: 2, opacity: 0 }}
                    exit={{}} transition={{ duration: 0.35 }}>❤️</motion.span>
                )}
              </AnimatePresence>
              <Heart className="w-[11px] h-[11px]"
                style={{ fill: localLiked ? "#ef4444" : "transparent", color: localLiked ? "#ef4444" : "#94a3b8" }} />
              <span className="text-[10.5px] font-bold tabular-nums"
                style={{ color: localLiked ? "#ef4444" : "#94a3b8" }}>{localCount}</span>
            </motion.button>
          )}

          {showCook && recipe.id && (
            <motion.button
              whileHover={{ scale: 1.06, y: -1 }}
              whileTap={{ scale: 0.88 }}
              onClick={(e) => {
                e.stopPropagation();
                go();
              }}
              onHoverStart={() => setBtnHover(true)}
              onHoverEnd={() => setBtnHover(false)}
              className="flex items-center justify-center gap-[5px] text-white rounded-xl relative overflow-hidden text-center"
              style={{
                height: 32,
                minWidth: showLike ? '100px' : '80px',
                maxWidth: showLike ? '130px' : '100%',
                flex: '1 1 auto',
                paddingLeft: '8px',
                paddingRight: '8px',
                background: "linear-gradient(135deg, #f97316 0%, #ef4444 100%)",
                boxShadow: btnHover
                  ? "0 6px 20px rgba(249,115,22,0.65), 0 2px 8px rgba(239,68,68,0.4)"
                  : "0 3px 12px rgba(249,115,22,0.42)",
                transition: "box-shadow 0.2s ease",
              }}
            >
              {/* shimmer on hover */}
              <AnimatePresence>
                {btnHover && (
                  <motion.span
                    initial={{ x: "-110%", skewX: "-20deg" }}
                    animate={{ x: "220%" }}
                    exit={{ opacity: 0 }}
                    transition={{ duration: 0.5, ease: "easeOut" }}
                    className="absolute inset-0 pointer-events-none"
                    style={{
                      width: "50%",
                      background: "linear-gradient(90deg, transparent, rgba(255,255,255,0.35), transparent)",
                    }}
                  />
                )}
              </AnimatePresence>
              <ArrowRightSVG />
              <span style={{
                fontSize: 11,
                fontWeight: 800,
                letterSpacing: "0.01em",
                fontFamily: "'Inter', -apple-system, sans-serif",
                position: "relative",
                zIndex: 1,
                lineHeight: 1.2,
              }}>
                {t('recipe.view', 'View Recipe')}
              </span>
            </motion.button>
          )}
        </div>
      </div>
    </motion.div>
  );
}

/**
 * generationRetryOrchestrator
 *
 * Single controlled retry loop used by the Generate page.
 * Runs ONE user-initiated generation across up to 2 LLM attempts (original + 1 reinforcement)
 * inside a SINGLE awaited scope. Never uses setTimeout-based recursive re-entry.
 *
 * GUARANTEES:
 *  - `generating` state stays true across the full loop (no button re-enable between attempts).
 *  - Failed attempts are refunded before the next attempt fires.
 *  - Image generation is part of the same loop — a recipe is never surfaced without an image.
 *  - After final failure → refund + set error state. No self-restart.
 *
 * The caller provides:
 *   - runGeneration(prompt, clientRequestId) → Promise<{ recipe, eventId, quota, error? }>
 *   - validateRecipe(recipe, prompt) → { ok, missingProteins?, finalRecipe }
 *   - buildReinforcedPrompt(originalPrompt, missingProteins) → string
 *   - generateImage(recipe) → Promise<url|null>
 *   - refundEvent(eventId, reason) → Promise<{ quota? }>
 *
 * This file has NO React dependency — pure logic for testability.
 */

export const MAX_ATTEMPTS = 2; // original + 1 reinforcement

export async function runGenerateWithRetries({
  originalPrompt,
  runGeneration,
  validateRecipe,
  buildReinforcedPrompt,
  generateImage,
  refundEvent,
  applyQuota,
}) {
  let attempt = 0;
  let currentPrompt = originalPrompt;
  let lastError = null;
  let lastQuota = null;

  while (attempt < MAX_ATTEMPTS) {
    attempt += 1;

    // --- 1. Backend LLM call (atomically consumes a credit, attaches quota) ---
    const clientRequestId = crypto.randomUUID();
    let genResult;
    try {
      genResult = await runGeneration(currentPrompt, clientRequestId);
    } catch (err) {
      // Backend error. If err.quota present, apply it; backend already refunded on LLM_FAILED/LLM_INVALID.
      if (err?.quota && applyQuota) applyQuota(err.quota);
      return { ok: false, error: err, attempts: attempt, finalRecipe: null, eventId: err?.event_id || null };
    }

    const { recipe, eventId, quota } = genResult;
    if (quota && applyQuota) applyQuota(quota);
    lastQuota = quota || lastQuota;

    // --- 2. Validate fidelity (wrong protein? wrong structure?) ---
    const validation = validateRecipe(recipe, originalPrompt);
    if (!validation.ok) {
      // Refund this attempt — it's a failed attempt for the user.
      if (eventId) {
        try {
          const refundRes = await refundEvent(eventId, 'fidelity_failed_attempt_' + attempt);
          if (refundRes?.quota && applyQuota) applyQuota(refundRes.quota);
        } catch {}
      }

      if (attempt < MAX_ATTEMPTS && validation.missingProteins?.length) {
        // Reinforce and try the next attempt IN THE SAME LOOP (no setTimeout, no state flap).
        currentPrompt = buildReinforcedPrompt(originalPrompt, validation.missingProteins);
        lastError = { code: 'FIDELITY_RETRY', missing: validation.missingProteins };
        continue;
      }

      // All attempts exhausted — broken recipe is NEVER surfaced.
      return {
        ok: false,
        error: { code: 'FIDELITY_FINAL', missing: validation.missingProteins || [] },
        attempts: attempt, finalRecipe: null, eventId,
      };
    }

    const validRecipe = validation.finalRecipe || recipe;

    // --- 3. Image generation — a recipe is never surfaced without an image ---
    let imageUrl = null;
    try {
      imageUrl = await generateImage(validRecipe);
    } catch (imgErr) {
      imageUrl = null;
    }

    if (!imageUrl) {
      // Refund + fail cleanly. Never show recipe without image.
      if (eventId) {
        try {
          const refundRes = await refundEvent(eventId, 'image_failed');
          if (refundRes?.quota && applyQuota) applyQuota(refundRes.quota);
        } catch {}
      }
      return {
        ok: false,
        error: { code: 'IMAGE_FAILED' },
        attempts: attempt, finalRecipe: null, eventId,
      };
    }

    validRecipe.hero_image_url = imageUrl;

    // --- 4. SUCCESS ---
    return { ok: true, finalRecipe: validRecipe, eventId, attempts: attempt, quota: lastQuota };
  }

  // Should be unreachable
  return { ok: false, error: lastError || { code: 'UNKNOWN' }, attempts: attempt, finalRecipe: null };
}

/**
 * CanonicalIngredientEnforcer
 * 
 * Post-generation validator that decomposes processed/composite ingredient names
 * into their real canonical components. Runs AFTER AI generation, BEFORE display.
 *
 * Rule: Every ingredient must be a REAL, purchasable base ingredient.
 * "Chickpea Patty" → chickpeas + breadcrumbs + cumin + salt
 * "Vegetable Blend" → specific vegetables
 * "Chicken Mix" → chicken breast + spices
 */

// Map of composite ingredient patterns → their canonical decomposition
const COMPOSITE_DECOMPOSITIONS = {
  'chickpea patty': [
    { name: 'Chickpeas (canned, drained)', amount: '400g', base_grams: 400 },
    { name: 'Breadcrumbs', amount: '30g', base_grams: 30 },
