    { name: 'Breadcrumbs', amount: '30g', base_grams: 30 },
    { name: 'Cumin', amount: '1 tsp', base_grams: 3 },
    { name: 'Onion (finely diced)', amount: '50g', base_grams: 50 },
  ],
  'black bean patty': [
    { name: 'Black beans (canned, drained)', amount: '400g', base_grams: 400 },
    { name: 'Breadcrumbs', amount: '30g', base_grams: 30 },
    { name: 'Smoked paprika', amount: '1 tsp', base_grams: 3 },
    { name: 'Onion (finely diced)', amount: '50g', base_grams: 50 },
  ],
  'vegetable blend': [
    { name: 'Zucchini (diced)', amount: '100g', base_grams: 100 },
    { name: 'Bell pepper (diced)', amount: '100g', base_grams: 100 },
    { name: 'Carrot (diced)', amount: '80g', base_grams: 80 },
  ],
  'chicken mix': [
    { name: 'Chicken breast', amount: '300g', base_grams: 300 },
    { name: 'Paprika', amount: '1 tsp', base_grams: 3 },
    { name: 'Garlic powder', amount: '0.5 tsp', base_grams: 1.5 },
  ],
  'veggie burger': [
    { name: 'Chickpeas (canned, drained)', amount: '400g', base_grams: 400 },
    { name: 'Oats', amount: '40g', base_grams: 40 },
    { name: 'Onion (finely diced)', amount: '60g', base_grams: 60 },
    { name: 'Cumin', amount: '1 tsp', base_grams: 3 },
  ],
  'falafel mix': [
    { name: 'Chickpeas (canned, drained)', amount: '400g', base_grams: 400 },
    { name: 'Fresh parsley', amount: '20g', base_grams: 20 },
    { name: 'Cumin', amount: '1 tsp', base_grams: 3 },
    { name: 'Garlic', amount: '2 cloves', base_grams: 6 },
  ],
  'protein blend': [
    { name: 'Chicken breast', amount: '250g', base_grams: 250 },
    { name: 'Eggs', amount: '2 eggs', base_grams: 100 },
  ],
  'stir fry sauce': [
    { name: 'Soy sauce', amount: '2 tbsp', base_grams: 30 },
    { name: 'Sesame oil', amount: '1 tsp', base_grams: 5 },
    { name: 'Ginger (grated)', amount: '1 tsp', base_grams: 5 },
  ],
};

// Patterns that indicate a composite/processed ingredient
const COMPOSITE_PATTERNS = [
  /\b(patty|patties)\b/i,
  /\b(blend|mix|mixture)\b/i,
  /\b(ready.?made|pre.?made|store.?bought)\b/i,
  /\b(frozen)\s+(patty|burger|nugget|finger)/i,
  /\b(burger)\b(?!\s*bun)/i, // "burger" alone (not "burger bun")
  /\b(nugget|finger|strip)s?\b/i,
];

// These are ALLOWED composite names (they're real purchasable items)
const ALLOWED_COMPOSITES = new Set([
  'burger bun', 'brioche bun', 'sesame bun', 'whole wheat bun',
  'pita bread', 'flatbread', 'tortilla', 'naan',
  'tomato sauce', 'tomato paste', 'soy sauce', 'fish sauce',
  'peanut butter', 'tahini', 'hummus', 'pesto',
  'pasta', 'spaghetti', 'penne', 'fusilli', 'noodles',
  'rice', 'quinoa', 'couscous', 'bulgur',
  'bread', 'sourdough', 'baguette',
  'cream cheese', 'sour cream', 'coconut milk', 'coconut cream',
  'maple syrup', 'honey', 'dijon mustard', 'worcestershire sauce',
  'miso paste', 'curry paste', 'harissa', 'gochujang',
  'breadcrumbs', 'panko',
]);

/**
 * Check if an ingredient name is a disallowed composite/processed form.
 */
function isCompositeIngredient(name) {
  const lower = (name || '').toLowerCase().trim();

  // Check allowed composites first
  for (const allowed of ALLOWED_COMPOSITES) {
    if (lower === allowed || lower.includes(allowed)) return false;
  }

  // Check against composite patterns
  for (const pattern of COMPOSITE_PATTERNS) {
    if (pattern.test(lower)) return true;
  }

  return false;
}

/**
 * Find decomposition for a composite ingredient.
 * Returns array of canonical ingredients, or null if no decomposition found.
 */
function findDecomposition(name) {
  const lower = (name || '').toLowerCase().trim();

  // Exact match first
  if (COMPOSITE_DECOMPOSITIONS[lower]) {
    return COMPOSITE_DECOMPOSITIONS[lower];
  }

  // Partial match
  for (const [key, decomposition] of Object.entries(COMPOSITE_DECOMPOSITIONS)) {
    if (lower.includes(key) || key.includes(lower)) {
      return decomposition;
    }
  }

  return null;
}

/**
 * Enforce canonical ingredients on a generated recipe.
 * Replaces composite/processed ingredients with their real components.
 * 
 * @param {object} recipe - generated recipe object
 * @returns {object} { recipe, decomposed: string[], warnings: string[] }
 */
export function enforceCanonicalIngredients(recipe) {
  if (!recipe?.ingredients?.length) {
    return { recipe, decomposed: [], warnings: [] };
  }

  const decomposed = [];
  const warnings = [];
  let modified = false;

  const newIngredients = recipe.ingredients.map(group => {
    const newItems = [];

    for (const item of (group.items || [])) {
      if (!item?.name) {
        newItems.push(item);
        continue;
      }

      if (!isCompositeIngredient(item.name)) {
        newItems.push(item);
        continue;
      }

      // This is a composite ingredient — try to decompose
      const decomposition = findDecomposition(item.name);

      if (decomposition) {
        // Replace with canonical components
        decomposed.push(`"${item.name}" → ${decomposition.map(d => d.name).join(' + ')}`);
        modified = true;

        for (const component of decomposition) {
          // Check if this component already exists in the recipe
          const exists = newItems.some(existing => 
            existing.name?.toLowerCase() === component.name.toLowerCase()
          );
          if (!exists) {
            newItems.push({
              name: component.name,
              amount: component.amount,
              base_grams: component.base_grams,
              optional: item.optional || false,
              missing: item.missing || false,
            });
          }
        }
      } else {
        // No decomposition found — keep it but warn
        warnings.push(`Composite ingredient "${item.name}" has no decomposition — kept as-is`);
        newItems.push(item);
      }
    }

    return { ...group, items: newItems };
  }).filter(g => g.items.length > 0);

  if (modified) {
    console.log('[CanonicalEnforcer] Decomposed:', decomposed);
  }

  return {
    recipe: modified ? { ...recipe, ingredients: newIngredients } : recipe,
    decomposed,
    warnings,
  };
}

/**
 * HardConstraintValidator — CRITICAL post-generation validation.
 *
 * Ensures that hard-constraint recipes (protein/budget targets) are ACTUALLY satisfied
 * before being shown to the user. No silent failures.
 *
 * API:
 *   validateHardConstraints(recipe, constraints) → { valid, passed, failed, report, adjustmentSuggestions }
 */

/**
 * Main validation: check if final recipe satisfies hard constraints.
 *
 * @param {object} recipe - finalized recipe with nutrition + pricing
 * @param {object} constraints - { protein_min, protein_max, budget_max, ... }
 * @returns { valid, passed, failed, report, adjustmentSuggestions }
 */
export function validateHardConstraints(recipe, constraints = {}) {
  const report = [];
  const passed = [];
  const failed = [];

  if (!recipe || !constraints || Object.keys(constraints).length === 0) {
    return { valid: true, passed, failed, report, adjustmentSuggestions: [] };
  }

  // ── PROTEIN VALIDATION ─────────────────────────────────────────────────────
  if (constraints.protein_min !== null && constraints.protein_min !== undefined) {
    const actualProtein = recipe.nutrition_total_for_recipe?.protein || 
                         (recipe.nutrition_per_serving?.protein || 0) * (recipe.servings || 1) ||
                         0;
    const tolerance = 3; // allow ±3g tolerance for rounding

    if (actualProtein >= constraints.protein_min - tolerance) {
      passed.push(`Protein: ${Math.round(actualProtein)}g ✓ (required ≥${constraints.protein_min}g)`);
    } else {
      failed.push({
        constraint: 'protein_min',
        required: constraints.protein_min,
        actual: Math.round(actualProtein),
        gap: Math.round(constraints.protein_min - actualProtein)
      });
      report.push(`HARD CONSTRAINT FAILED: Protein target not met. Required: ≥${constraints.protein_min}g, Got: ${Math.round(actualProtein)}g`);
    }
  }

  if (constraints.protein_max !== null && constraints.protein_max !== undefined) {
    const actualProtein = recipe.nutrition_total_for_recipe?.protein || 
                         (recipe.nutrition_per_serving?.protein || 0) * (recipe.servings || 1) ||
                         0;
    const tolerance = 3;

    if (actualProtein <= constraints.protein_max + tolerance) {
      passed.push(`Protein ceiling: ${Math.round(actualProtein)}g ✓ (max ${constraints.protein_max}g)`);
    } else {
      failed.push({
        constraint: 'protein_max',
        required: constraints.protein_max,
        actual: Math.round(actualProtein),
        excess: Math.round(actualProtein - constraints.protein_max)
      });
      report.push(`HARD CONSTRAINT FAILED: Protein exceeds max. Required: ≤${constraints.protein_max}g, Got: ${Math.round(actualProtein)}g`);
    }
  }

  // ── BUDGET VALIDATION ──────────────────────────────────────────────────────
  if (constraints.budget_max !== null && constraints.budget_max !== undefined) {
    const actualCost = recipe.total_cost || 0;
    const tolerance = 0.5; // allow ±$0.50 tolerance

    if (actualCost <= constraints.budget_max + tolerance) {
      passed.push(`Budget: $${actualCost.toFixed(2)} ✓ (max $${constraints.budget_max})`);
    } else {
      failed.push({
        constraint: 'budget_max',
        required: constraints.budget_max,
        actual: Number(actualCost.toFixed(2)),
        excess: Number((actualCost - constraints.budget_max).toFixed(2))
      });
      report.push(`HARD CONSTRAINT FAILED: Budget exceeded. Required: ≤$${constraints.budget_max}, Got: $${actualCost.toFixed(2)}`);
    }
  }

  // ── CALORIE CAP (if provided as hard max) ───────────────────────────────
  if (constraints.calorie_max !== null && constraints.calorie_max !== undefined) {
    const actualCalories = recipe.nutrition_total_for_recipe?.calories || 
                          (recipe.nutrition_per_serving?.calories || 0) * (recipe.servings || 1) ||
                          0;
    const tolerance = 20;

    if (actualCalories <= constraints.calorie_max + tolerance) {
      passed.push(`Calories: ${Math.round(actualCalories)} ✓ (max ${constraints.calorie_max})`);
    } else {
      failed.push({
        constraint: 'calorie_max',
        required: constraints.calorie_max,
        actual: Math.round(actualCalories),
        excess: Math.round(actualCalories - constraints.calorie_max)
      });
      report.push(`HARD CONSTRAINT FAILED: Calories exceed max. Required: ≤${constraints.calorie_max}, Got: ${Math.round(actualCalories)}`);
    }
  }

  // ── FINAL STATE ────────────────────────────────────────────────────────────
  const valid = failed.length === 0;

  const adjustmentSuggestions = [];
  if (!valid) {
    for (const f of failed) {
      if (f.constraint === 'protein_min') {
        adjustmentSuggestions.push(
          `Protein is ${f.gap}g short. Try adding more lean protein (chicken, fish, eggs) or request help from the AI.`
        );
      } else if (f.constraint === 'budget_max') {
        adjustmentSuggestions.push(
          `Budget exceeded by $${f.excess}. Try a higher budget, cheaper ingredients, or fewer servings.`
        );
      } else if (f.constraint === 'calorie_max') {
        adjustmentSuggestions.push(
          `Calories exceed max by ${f.excess}. Try reducing portion sizes or using lower-calorie ingredients.`
        );
      }
    }
  }

  if (passed.length > 0) {
    console.log('[HardConstraintValidator] Constraints passed:', passed);
  }
  if (failed.length > 0) {
    console.error('[HardConstraintValidator] CONSTRAINT VIOLATIONS:', failed, report);
  }

  return { valid, passed, failed, report, adjustmentSuggestions };
}

/**
 * Check if both protein AND budget can realistically be satisfied together.
 * Used pre-generation to warn user if constraints are impossible.
 */
export function canSatisfyBothConstraints(proteinMin, budgetMax, servings = 2, cushion = 0.1) {
  // Average cost per gram of lean protein: roughly $0.15–$0.25
  const proteinCostPerGram = 0.20;
  const costForProtein = proteinMin * proteinCostPerGram;
  const remainingBudget = budgetMax - costForProtein;

  // Minimal cost for vegetables/carbs/preparation: roughly $0.30–$0.50 per serving
  const minExtraPerServing = 0.40;
  const minExtraTotal = minExtraPerServing * servings;

  const feasible = remainingBudget >= minExtraTotal;
  const report = {
    proteinCost: costForProtein,
    remainingBudgetAfterProtein: remainingBudget,
    minExtraNeeded: minExtraTotal,
    feasible,
  };

  if (!feasible) {
    console.warn(`[HardConstraintValidator] Protein (${proteinMin}g) + Budget ($${budgetMax}) may be impossible:`, report);
  }

  return { feasible, report };
}

