// ── Date grouping (timezone-aware) ────────────────────────────────────────────
function groupByDate(notifications) {
  // Use user's local date for grouping — not UTC
  const nowLocal = new Date();
  const todayStr = nowLocal.toLocaleDateString('en-CA'); // YYYY-MM-DD local
  const yesterdayDate = new Date(nowLocal);
  yesterdayDate.setDate(yesterdayDate.getDate() - 1);
  const yesterdayStr = yesterdayDate.toLocaleDateString('en-CA');
  const weekAgo = new Date(nowLocal);
  weekAgo.setDate(weekAgo.getDate() - 7);
  const weekAgoStr = weekAgo.toLocaleDateString('en-CA');

  const groups = { Today: [], Yesterday: [], 'This Week': [], Older: [] };
  notifications.forEach(n => {
    const dStr = new Date(n.created_date).toLocaleDateString('en-CA');
    if (dStr === todayStr) groups.Today.push(n);
    else if (dStr === yesterdayStr) groups.Yesterday.push(n);
    else if (dStr >= weekAgoStr) groups['This Week'].push(n);
    else groups.Older.push(n);
  });
  return groups;
}

