// ── Follow Request Accept/Decline inline actions ──────────────────────────────
function FollowRequestActions({ notif, onActioned }) {
  const [loading, setLoading] = useState(null); // 'accept' | 'decline' | null
  const [done, setDone] = useState(null); // 'accepted' | 'declined' | null
  const qc = useQueryClient();

  if (done === 'accepted') {
    return <span className="text-[11px] font-bold text-emerald-600 px-2 py-1 rounded-full bg-emerald-50">Accepted ✓</span>;
  }
  if (done === 'declined') {
    return <span className="text-[11px] font-bold text-slate-400 px-2 py-1 rounded-full bg-slate-100">Declined</span>;
  }

  const handleAccept = async (e) => {
    e.stopPropagation();
    if (loading) return;
    setLoading('accept');
    try {
      await base44.functions.invoke('toggleFollowState', {
        target_user_id: notif.from_user_id,
        action: 'accept_request',
        requester_id: notif.from_user_id,
      });
      setDone('accepted');
      // Invalidate follow lists so counts update
      qc.invalidateQueries({ queryKey: ['my-followers-count'] });
      qc.invalidateQueries({ queryKey: ['follow-list-followers'] });
      qc.invalidateQueries({ queryKey: ['my-notifications'] });
      onActioned?.(notif.id);
    } catch {
      toast.error('Failed to accept. Try again.');
    } finally {
      setLoading(null);
    }
  };

  const handleDecline = async (e) => {
    e.stopPropagation();
    if (loading) return;
    setLoading('decline');
    try {
      await base44.functions.invoke('toggleFollowState', {
        target_user_id: notif.from_user_id,
        action: 'decline_request',
        requester_id: notif.from_user_id,
      });
      setDone('declined');
      qc.invalidateQueries({ queryKey: ['my-notifications'] });
      onActioned?.(notif.id);
    } catch {
      toast.error('Failed to decline. Try again.');
    } finally {
      setLoading(null);
    }
  };

  return (
    <div className="flex gap-1.5 mt-2" onClick={e => e.stopPropagation()}>
      <button
        onClick={handleAccept}
        disabled={!!loading}
        className="flex items-center gap-1 px-3 py-1.5 rounded-full text-[11px] font-bold text-white disabled:opacity-60 transition-all active:scale-95"
        style={{ background: 'linear-gradient(135deg, #10b981, #059669)' }}
      >
        {loading === 'accept' ? (
          <span className="w-3 h-3 border border-white/50 border-t-white rounded-full animate-spin inline-block" />
        ) : <Check className="w-3 h-3" />}
        Accept
      </button>
      <button
        onClick={handleDecline}
        disabled={!!loading}
        className="flex items-center gap-1 px-3 py-1.5 rounded-full text-[11px] font-bold text-slate-600 bg-slate-100 hover:bg-slate-200 disabled:opacity-60 transition-all active:scale-95"
      >
        {loading === 'decline' ? (
          <span className="w-3 h-3 border border-slate-400/50 border-t-slate-600 rounded-full animate-spin inline-block" />
        ) : <X className="w-3 h-3" />}
        Decline
      </button>
    </div>
  );
}

