      {/* Left accent stripe — instant type recognition */}
      <div
        className="absolute left-0 top-2 bottom-2 rounded-r-full"
        style={{ width: 3, background: cfg.accentColor, opacity: isUnread ? 0.85 : 0.35 }}
      />

      {/* Avatar + badge */}
