function SlotCard({ slot, category = "onboarding", existing, onUploaded }) {
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState("");
  const inputRef = React.useRef(null);

  const handleFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    setError("");
    try {
      const { file_url } = await base44.integrations.Core.UploadFile({ file });

      if (existing) {
        await base44.entities.RipoAsset.update(existing.id, {
          file_url,
          is_active: true,
        });
      } else {
        await base44.entities.RipoAsset.create({
          key: slot.key,
          name: slot.name,
          asset_type: "mp4",
          category,
          file_url,
          is_active: true,
          notes: slot.desc,
        });
      }
      onUploaded();
    } catch (err) {
      setError(err.message || "Upload failed");
    } finally {
      setUploading(false);
    }
  };

  const isDone = !!existing?.file_url;

  return (
    <div className={`rounded-2xl border-2 p-4 transition-all ${isDone ? "bg-emerald-50 border-emerald-200" : "bg-white border-slate-200"}`}>
      <div className="flex items-start gap-3">
        <div className={`w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 ${isDone ? "bg-emerald-100" : "bg-slate-100"}`}>
          {isDone ? <CheckCircle2 className="w-5 h-5 text-emerald-600" /> : <Upload className="w-5 h-5 text-slate-400" />}
        </div>
        <div className="flex-1 min-w-0">
          <p className="text-sm font-bold text-slate-800">{slot.name}</p>
          <p className="text-xs text-slate-400 mt-0.5">{slot.desc}</p>
          {isDone && (
            <div className="mt-1.5">
              <video src={existing.file_url} className="w-full max-w-[140px] rounded-xl" autoPlay loop muted playsInline style={{ aspectRatio: "1/1", objectFit: "cover" }} />
            </div>
          )}
          {error && <p className="text-xs text-rose-500 mt-1">{error}</p>}
        </div>
        <div className="flex-shrink-0">
          <input ref={inputRef} type="file" accept="video/mp4,video/*" className="hidden" onChange={handleFile} />
          <button
            onClick={() => inputRef.current?.click()}
            disabled={uploading}
            className={`px-3 py-1.5 rounded-xl text-xs font-bold transition-all ${isDone ? "bg-emerald-600 text-white hover:bg-emerald-700" : "bg-indigo-600 text-white hover:bg-indigo-700"} disabled:opacity-60`}
          >
            {uploading ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : isDone ? "Replace" : "Upload"}
          </button>
        </div>
      </div>
    </div>
  );
}

