    feedbackAssets.some(a => a.key === s.key && a.file_url)
  ).length;

  if (loading || !user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-white">
        <Loader2 className="w-8 h-8 animate-spin text-indigo-500" />
