  return (
    <div className="min-h-screen bg-slate-50 pb-16">
      <div className="bg-white border-b border-slate-100 px-5 pt-12 pb-4">
        <button
          onClick={() => window.history.back()}
          className="flex items-center gap-2 text-sm text-slate-500 font-medium mb-4"
        >
          <ArrowLeft className="w-4 h-4" />
          Back
        </button>
        <h1 className="text-xl font-black text-slate-900">Ripo Asset Manager</h1>
        <p className="text-sm text-slate-500 mt-1">Upload onboarding & feedback animations</p>
        <div className="mt-3 flex gap-2 flex-wrap">
          <div className="px-3 py-1.5 rounded-xl bg-indigo-50 border border-indigo-100 inline-flex items-center gap-1.5">
            <span className="text-xs font-bold text-indigo-700">Onboarding: {completedCount}/{ONBOARDING_SLOTS.length}</span>
