/**
 * PageShell — CRITICAL SAFETY WRAPPER
 * 
 * Ensures EVERY page:
 * 1. NEVER renders white/blank
 * 2. Always shows skeleton loading OR content OR error state
 * 3. Handles late-arriving async data (user, critical queries)
 * 4. Provides safe error boundaries
 * 
 * This is the anti-white-screen mechanism.
 */

import React from "react";
import { cn } from "@/lib/utils";

/**
 * PageShell wraps page content to guarantee one of these states:
 * - Bootstrap: waiting for critical auth/user data
 * - Loading: critical data is loading (show skeleton)
 * - Ready: critical data exists, render content
 * - Error: unrecoverable error (show error state)
 */
export default function PageShell({
  isReady,           // boolean: is critical data loaded?
  isLoading,         // boolean: is critical data in flight?
  error,             // null or error object
  children,          // content to render when ready
  skeleton,          // JSX: skeleton UI to show during loading
  fallback = null,   // JSX: shown if no skeleton provided during loading
  fullHeight = true, // boolean: min-h-screen (fills viewport)
  errorTitle,        // string: localized "Something went wrong" override
  errorDesc,         // string: localized "Unable to load this page" override
  retryLabel,        // string: localized "Try Again" override
}) {
  // CRITICAL: These three states are MUTUALLY EXCLUSIVE

  if (!isReady && isLoading) {
    // STATE 1: LOADING
    // Page data is in flight. Show skeleton, NEVER blank white.
    return (
      <div className={cn(
        "bg-slate-50",
        fullHeight && "min-h-screen"
      )}>
        {skeleton || fallback || (
          // Minimal fallback: better than blank white
          <div className="p-6 space-y-4">
            <div className="h-8 bg-slate-200 rounded w-1/3 animate-pulse" />
            <div className="h-64 bg-slate-100 rounded animate-pulse" />
          </div>
        )}
      </div>
    );
  }

  if (error) {
    // STATE 2: ERROR
    // Unrecoverable error. Show error message, allow retry.
    return (
      <div className={cn(
        "bg-slate-50 flex flex-col items-center justify-center",
        fullHeight && "min-h-screen"
      )}>
        <div className="bg-white rounded-2xl p-8 shadow-sm border border-slate-200 max-w-sm text-center">
          <div className="w-12 h-12 rounded-full bg-red-50 flex items-center justify-center mx-auto mb-4">
            <span className="text-2xl">⚠️</span>
          </div>
          <h2 className="text-lg font-bold text-slate-900 mb-2">{errorTitle || "Something went wrong"}</h2>
          <p className="text-sm text-slate-500 mb-4">{errorDesc || error?.message || "Unable to load this page"}</p>
          <button
            onClick={() => window.location.reload()}
            className="px-6 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors"
          >
            {retryLabel || "Try Again"}
          </button>
        </div>
      </div>
    );
  }

  if (!isReady) {
    // STATE 3: BOOTSTRAP (critical data not ready, not actively loading)
    // This is a rare state—usually isLoading is true if !isReady.
    // But we handle it to be safe: show minimal skeleton.
    return (
      <div className={cn(
        "bg-slate-50",
        fullHeight && "min-h-screen"
      )}>
        <div className="p-6">
          <div className="h-8 bg-slate-200 rounded w-1/3 animate-pulse mb-4" />
          <div className="space-y-4">
            {[1, 2, 3].map(i => (
              <div key={i} className="h-20 bg-slate-100 rounded animate-pulse" />
            ))}
          </div>
        </div>
      </div>
    );
  }

  // STATE 4: READY
  // Critical data is loaded and no error. Render content.
  return <>{children}</>;
}

