);

// ─── Moderation — delegates to centralized contentSafety ──────────────────────
import { checkPublicTextSafety } from "@/lib/contentSafety";

function containsExplicitContent(rawInput) {
  if (!rawInput) return false;
  return !checkPublicTextSafety(rawInput).safe;
}

// ─── Validation ───────────────────────────────────────────────────────────────
// Validation functions — returns a translation key pair {key, fallback} or null
function validateDisplayName(name) {
  const trimmed = (name || '').trim();
  if (!trimmed) return { key: 'validation.display_name_required', fallback: 'Display name is required' };
  if (trimmed.length < DISPLAY_NAME_MIN) return { key: 'validation.min_2_chars', fallback: 'Must be at least 2 characters' };
  if (trimmed.length > DISPLAY_NAME_MAX) return { key: 'validation.max_14_chars', fallback: 'Must be 14 characters or fewer' };
  if (containsExplicitContent(trimmed)) return { key: 'validation.inappropriate_content', fallback: 'Display name contains inappropriate content' };
  return null;
}

function validateUsernameFormat(username) {
  const trimmed = (username || '').trim().toLowerCase();
  if (!trimmed) return { key: 'validation.username_required', fallback: 'Username is required' };
  if (trimmed.length < 2) return { key: 'validation.min_2_chars', fallback: 'Must be at least 2 characters' };
  if (trimmed.length > 14) return { key: 'validation.max_14_chars', fallback: 'Must be 14 characters or fewer' };
  if (!/^[a-z0-9_.]+$/.test(trimmed)) return { key: 'validation.username_chars', fallback: 'Only letters, numbers, underscores, and dots allowed' };
  if (containsExplicitContent(trimmed)) return { key: 'validation.inappropriate_content', fallback: 'Username contains inappropriate content' };
  return null;
}

// ─── Debounce hook ─────────────────────────────────────────────────────────────
function useDebounce(value, delay) {
  const [debounced, setDebounced] = useState(value);
  useEffect(() => {
    const t = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(t);
  }, [value, delay]);
  return debounced;
}

// ─── Animated validation indicator ────────────────────────────────────────────
const ValidationIcon = ({ status }) => {
  if (status === 'checking') return <Loader2 className="w-4 h-4 text-slate-400 animate-spin" />;
  if (status === 'valid' || status === 'available' || status === 'same') {
    return <CheckCircle2 className="w-4 h-4 text-emerald-500" />;
  }
  if (status === 'error' || status === 'taken' || status === 'invalid') {
    return (
      <span className="relative inline-flex items-center justify-center w-5 h-5">
        <span className="absolute w-5 h-5 rounded-full bg-rose-300 opacity-50 animate-ping" />
        <XCircle className="w-4 h-4 text-rose-500 relative z-10" />
      </span>
    );
  }
  return null;
};

