export default function EditProfilePage() {
  const queryClient = useQueryClient();
  const { t } = useLocalization();
  const dietOptions = getLocalizedOptions(DIET_MANIFEST, t);
  const allergyOptions = getLocalizedOptions(ALLERGY_MANIFEST_WITH_ICONS, t);
  const equipOptions = getLocalizedOptions(EQUIPMENT_MANIFEST, t);
  const goalOptions = getLocalizedOptions(GOAL_MANIFEST, t);

  const [user, setUser] = useState(null);

  // Display name — completely separate from username
  const [editName, setEditName] = useState('');
  const [nameError, setNameError] = useState(null);
  const [nameStatus, setNameStatus] = useState(null); // null | 'valid' | 'error'

  // Username / handle — completely separate from display name
  const [editUsername, setEditUsername] = useState('');
  const [usernameStatus, setUsernameStatus] = useState(null); // null | 'checking' | 'available' | 'taken' | 'invalid' | 'same' | 'error'
  const [usernameError, setUsernameError] = useState('');
  const [usernameCooldown, setUsernameCooldown] = useState(null); // { hours, minutes, remaining_ms } | null

  // Other fields
  const [editBio, setEditBio] = useState('');
  const [editDietary, setEditDietary] = useState([]);
  const [editEquipment, setEditEquipment] = useState([]);
  const [editSkill, setEditSkill] = useState('beginner');
  const [editGoals, setEditGoals] = useState([]);
  const [editAllergies, setEditAllergies] = useState([]);
  const [avatarChange, setAvatarChange] = useState(null); // { type:'starter', avatarId } | { type:'photo', file, previewUrl }
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [saveSuccess, setSaveSuccess] = useState(false);
  const [isDirty, setIsDirty] = useState(false);
  // Snapshot of original values to detect changes
  const originalRef = React.useRef(null);

  const sourceParam = new URLSearchParams(window.location.search).get('source') || 'profile';
  const debouncedUsername = useDebounce(editUsername, 500);

  // ── Load user — strict field separation on hydration ──────────────────────
  useEffect(() => {
    base44.auth.me().then(u => {
      setUser(u);
      // Display name: prefer display_name, fall back to full_name only. NEVER use username.
      const name = u.display_name || u.full_name || '';
      setEditName(name);
      if (name.trim().length >= 2) setNameStatus('valid');

      // Username: prefer username field only. NEVER fall back to display_name.
      const uname = u.username || '';
      setEditUsername(uname);
      if (uname) setUsernameStatus('same');

      // Cooldown: compute from username_last_changed_at
      if (u.username_last_changed_at) {
        const COOLDOWN_MS = 24 * 60 * 60 * 1000;
        const elapsed = Date.now() - new Date(u.username_last_changed_at).getTime();
        const remaining = COOLDOWN_MS - elapsed;
        if (remaining > 0) {
          const totalMinutes = Math.ceil(remaining / 60000);
          setUsernameCooldown({
            hours: Math.floor(totalMinutes / 60),
            minutes: totalMinutes % 60,
            remaining_ms: remaining,
          });
        }
      }

      const bio = u.bio || '';
      const dietary = u.dietary_preferences || [];
      const equipment = u.equipment || [];
      const skill = u.skill_level || 'beginner';
      const goals = Array.isArray(u.goals) ? u.goals : (u.goals ? [u.goals] : []);
      const allergies = Array.isArray(u.allergies) ? u.allergies : [];
      setEditBio(bio);
      setEditDietary(dietary);
      setEditEquipment(equipment);
      setEditSkill(skill);
      setEditGoals(goals);
      setEditAllergies(allergies);
      // Snapshot original values for dirty detection
      originalRef.current = {
        name: u.display_name || u.full_name || '',
        username: u.username || '',
        bio, dietary, equipment, skill, goals, allergies,
      };
    }).catch(() => {});
  }, []);

  // ── Username live availability check ──────────────────────────────────────
  useEffect(() => {
    if (!user || !debouncedUsername) return;
    const normalized = debouncedUsername.trim().toLowerCase();
    if (!normalized) {
      setUsernameStatus(null);
      setUsernameError('');
      return;
    }

    // Same as current username — no check needed
    if (normalized === (user.username || '').toLowerCase()) {
      setUsernameStatus('same');
      setUsernameError('');
      return;
    }

    // Frontend format + moderation check first
    const formatErrObj = validateUsernameFormat(normalized);
    if (formatErrObj) {
      setUsernameStatus('invalid');
      setUsernameError(t(formatErrObj.key, formatErrObj.fallback));
      return;
    }

    // Backend availability check
    setUsernameStatus('checking');
    base44.functions.invoke('checkUsernameAvailable', { username: normalized })
      .then(res => {
        if (res.data.available) {
          setUsernameStatus('available');
          setUsernameError('');
        } else {
          setUsernameStatus('taken');
          setUsernameError(t('validation.username_taken', 'Username is already taken'));
        }
      })
      .catch(() => {
        setUsernameStatus(null);
        setUsernameError('');
      });
  }, [debouncedUsername, user?.id]);

  // ── Dirty check ───────────────────────────────────────────────────────────
  const checkDirty = (overrides = {}) => {
    if (!originalRef.current) return;
    const o = originalRef.current;
    const cur = {
      name: editName, username: editUsername, bio: editBio,
      dietary: editDietary, equipment: editEquipment, skill: editSkill,
      goals: editGoals, allergies: editAllergies,
      ...overrides,
    };
    const changed =
      cur.name !== o.name ||
      cur.username !== o.username ||
      cur.bio !== o.bio ||
      cur.skill !== o.skill ||
      JSON.stringify([...cur.dietary].sort()) !== JSON.stringify([...o.dietary].sort()) ||
      JSON.stringify([...cur.equipment].sort()) !== JSON.stringify([...o.equipment].sort()) ||
      JSON.stringify([...cur.goals].sort()) !== JSON.stringify([...o.goals].sort()) ||
      JSON.stringify([...cur.allergies].sort()) !== JSON.stringify([...o.allergies].sort()) ||
      !!avatarChange;
    setIsDirty(changed);
  };

  // ── Display name change handler ───────────────────────────────────────────
  const handleDisplayNameChange = (val) => {
    // Hard-clamp to max before updating state so UI never shows a longer value
    const clamped = val.slice(0, DISPLAY_NAME_MAX);
    setEditName(clamped);
    const errObj = validateDisplayName(clamped);
    setNameError(errObj ? t(errObj.key, errObj.fallback) : null);
    setNameStatus(errObj ? 'error' : (clamped.trim().length >= DISPLAY_NAME_MIN ? 'valid' : null));
    checkDirty({ name: clamped });
  };

  // ── Username change handler ───────────────────────────────────────────────
  const handleUsernameChange = (val) => {
    // Strip invalid chars immediately on input
    const cleaned = val.toLowerCase().replace(/[^a-z0-9_.]/g, '');
    setEditUsername(cleaned);
    setUsernameStatus(null);
    setUsernameError('');
    checkDirty({ username: cleaned });
  };

  // ── Save ─────────────────────────────────────────────────────────────────
  const handleSave = async () => {
    // 1. Validate display name
    const nameErrObj = validateDisplayName(editName);
    if (nameErrObj) {
      setNameError(t(nameErrObj.key, nameErrObj.fallback));
      setNameStatus('error');
      return;
    }

    // 2. Validate username format
    const uErrObj = validateUsernameFormat(editUsername);
    if (uErrObj) {
      setUsernameError(t(uErrObj.key, uErrObj.fallback));
      setUsernameStatus('invalid');
      return;
    }

    // 3. Block if taken or still loading
    if (usernameStatus === 'taken' || usernameStatus === 'checking') return;

    // 4. Goal check
    if (editGoals.length === 0) {
      toast.error(t('validation.select_one_goal', 'Please select at least one goal'));
      return;
    }

    setSaving(true);
    try {
      let avatarUrl = user?.avatar_url || user?.avatar || '';
      let avatarChoice = user?.avatar_choice || user?.starter_avatar_id;

      if (avatarChange) {
        setUploading(true);
        if (avatarChange.type === 'photo' && avatarChange.file) {
          const { file_url } = await base44.integrations.Core.UploadFile({ file: avatarChange.file });
          avatarUrl = file_url;
        } else if (avatarChange.type === 'starter' && avatarChange.avatarId) {
          const { getStarterAvatarFile: getFile } = await import('../components/profile/StarterAvatars');
          const f = await getFile(avatarChange.avatarId);
          const { file_url } = await base44.integrations.Core.UploadFile({ file: f });
          avatarUrl = file_url;
          avatarChoice = avatarChange.avatarId;
        }
        setUploading(false);
      }

      // GUARD: if avatarUrl is still a bare starter ID (old account), upload it now
      // so cascade always writes a real CDN URL (never a bare ID like "blaze")
      if (avatarUrl && !avatarUrl.startsWith('http') && !avatarUrl.startsWith('data:')) {
        const possibleId = avatarUrl.trim();
        try {
          setUploading(true);
          const { getStarterAvatarFile: getFile } = await import('../components/profile/StarterAvatars');
          const f = await getFile(possibleId);
          const { file_url } = await base44.integrations.Core.UploadFile({ file: f });
          avatarUrl = file_url;
          if (!avatarChoice) avatarChoice = possibleId;
        } catch (_) {
          avatarUrl = ''; // can't resolve — let cascade write empty, cards show initials
        } finally {
          setUploading(false);
        }
      }

      const newUsername = editUsername.trim().toLowerCase();
      const usernameChanged = newUsername !== (user?.username || '').toLowerCase();

      // If username changed, route through backend cooldown-enforced function FIRST
      if (usernameChanged) {
        const res = await base44.functions.invoke('changeUsername', { username: newUsername });
        if (res.data?.error === 'USERNAME_COOLDOWN') {
          toast.error(res.data.message || 'Username change on cooldown');
          setSaving(false);
          return;
        }
        if (res.data?.error) {
          toast.error(res.data.message || 'Failed to change username');
          setSaving(false);
          return;
        }
      }

      // Save all other profile fields (username excluded — already handled above)
      await base44.auth.updateMe({
        display_name: sanitizeDisplayName(editName),
        bio: editBio,
        dietary_preferences: editDietary,
        equipment: editEquipment,
        skill_level: editSkill,
        goals: editGoals,
        allergies: editAllergies,
        avatar: avatarUrl,
        avatar_url: avatarUrl,
        avatar_choice: avatarChoice,
        starter_avatar_id: avatarChoice,
      });

      // Cascade identity change to ALL denormalized entity fields.
      // MUST await before clearing cache + redirecting — otherwise the page
      // reloads and re-fetches stale DB data before cascade writes complete.
      const finalName = sanitizeDisplayName(editName);
      const finalAvatar = avatarUrl || '';
      await base44.functions.invoke('cascadeProfileUpdate', {
        display_name: finalName,
        avatar_url: finalAvatar,
      }).catch(() => {});
      // Cascade is done (or silently failed) — now safe to clear cache.
      // queryClient.clear() nukes ALL React Query caches so every feed/card
      // re-fetches fresh data (which now has the updated identity in DB).
      queryClient.clear();
      setSaveSuccess(true);
      setIsDirty(false);
      toast.success(t('editprofile.save_success', 'Profile saved successfully!'));
      setTimeout(() => window.location.replace(createPageUrl("Settings")), 800);
    } catch (err) {
      console.error('[EditProfile] save failed:', err);
      toast.error(t('error.failed_save', 'Failed to save. Please try again.'));
      setUploading(false);
    } finally {
      setSaving(false);
    }
  };

  const toggleDietary  = (item) => { const next = editDietary.includes(item) ? editDietary.filter(d => d !== item) : [...editDietary, item]; setEditDietary(next); checkDirty({ dietary: next }); };
  const toggleEquipment = (item) => { const next = editEquipment.includes(item) ? editEquipment.filter(e => e !== item) : [...editEquipment, item]; setEditEquipment(next); checkDirty({ equipment: next }); };

  const toggleAllergy = (value) => {
    const next = editAllergies.includes(value) ? editAllergies.filter(a => a !== value) : [...editAllergies, value];
    setEditAllergies(next);
    checkDirty({ allergies: next });
  };

  const toggleGoal = (goalValue) => {
    if (editGoals.includes(goalValue)) {
      const next = editGoals.filter(g => g !== goalValue);
      setEditGoals(next);
      checkDirty({ goals: next });
    } else {
      if (editGoals.length >= 2) { toast.error(t('validation.max_2_goals', 'You can choose up to 2 goals')); return; }
      const next = [...editGoals, goalValue];
      setEditGoals(next);
      checkDirty({ goals: next });
    }
  };

  const isUsernameOk = ['same', 'available', 'valid', null].includes(usernameStatus);
  const isNameOk = nameStatus !== 'error';
  const canSave = isNameOk && isUsernameOk && usernameStatus !== 'checking' && isDirty;

  return (
    <div className="min-h-screen bg-slate-50 page-bottom-safe">
      {/* Success Banner */}
      {saveSuccess && (
        <div className="fixed inset-x-0 top-0 z-[999] flex items-center justify-center pointer-events-none">
          <div className="mt-16 mx-5 flex items-center gap-3 px-5 py-3.5 rounded-2xl shadow-2xl pointer-events-auto"
            style={{ background: "linear-gradient(135deg,#059669,#10b981)", boxShadow: "0 8px 32px rgba(5,150,105,0.45)" }}>
            <CheckCircle2 className="w-5 h-5 text-white flex-shrink-0" />
            <span className="text-white font-bold text-sm">{t('editprofile.save_success', 'Profile saved successfully!')}</span>
          </div>
        </div>
      )}

      {/* Header */}
      <div className="sticky top-0 bg-white/95 backdrop-blur-lg border-b border-slate-100 z-10">
        <div className="flex items-center justify-between px-5 py-4">
          <button
            onClick={() => window.location.href = createPageUrl("Settings")}
            className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center"
          >
            <ArrowLeft className="w-5 h-5 text-slate-600" />
          </button>
          <h1 className="text-lg font-bold text-slate-900">{t('settings.edit_profile', 'Edit Profile')}</h1>
          <Button
            onClick={handleSave}
            disabled={saving || uploading || !canSave}
            size="sm"
            className="rounded-xl bg-indigo-600 hover:bg-indigo-700 text-white h-9 disabled:opacity-40"
          >
            {saving || uploading ? <Loader2 className="w-4 h-4 animate-spin" /> : t('action.save', 'Save')}
          </Button>
        </div>
      </div>

      <div className="px-5 py-6 space-y-6">
        {/* Avatar */}
        {user && (
          <div className="bg-white rounded-3xl border border-slate-100 p-5">
            <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider text-center mb-4">{t('editprofile.profile_avatar', 'Profile Avatar')}</p>
            <AvatarPickerSection
              user={user}
              onAvatarChange={(change) => { setAvatarChange(change); setIsDirty(true); }}
            />
          </div>
        )}

        {/* Display Name */}
        <div>
          <Label className="text-xs text-slate-600">{t('editprofile.display_name', 'Display Name')}</Label>
          <div className="relative mt-1">
            <Input
              value={editName}
              onChange={e => handleDisplayNameChange(e.target.value)}
              maxLength={14}
              className={cn(
                "h-11 rounded-xl pr-10",
                nameStatus === 'error' ? "border-rose-300 focus:border-rose-400" : nameStatus === 'valid' ? "border-emerald-300 focus:border-emerald-400" : ""
              )}
              placeholder={t('editprofile.name_placeholder', 'Your name')}
            />
            <div className="absolute right-3 top-1/2 -translate-y-1/2">
              <ValidationIcon status={nameStatus} />
            </div>
          </div>
          {nameError && <p className="text-xs text-rose-500 mt-1 font-medium">{nameError}</p>}
          <p className="text-xs text-slate-400 mt-1">{editName.trim().length}/14 {t('editprofile.characters', 'characters')}</p>
        </div>

        {/* Email — Read-only */}
        <div>
          <Label className="text-xs text-slate-600">{t('editprofile.email', 'Email')}</Label>
          <div className="relative mt-1">
            <Input
              value={user?.email || '—'}
              readOnly disabled
              className="h-11 rounded-xl pl-9 pr-10 bg-slate-100 text-slate-500 cursor-not-allowed border-slate-200"
            />
            <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          </div>
          <p className="text-xs text-slate-500 mt-1">{t('editprofile.email_readonly', "Your email can't be changed right now.")}</p>
        </div>

        {/* Username / Handle */}
        <div>
          <div className="flex items-center gap-2">
            <Label className="text-xs text-slate-600">{t('editprofile.username', 'Username')}</Label>
            {user?.username_verified && (
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-blue-50 border border-blue-200">
                <BadgeCheck className="w-3 h-3 text-blue-600" />
                <span className="text-[10px] font-semibold text-blue-600">{t('editprofile.username_verified', 'Verified')}</span>
              </div>
            )}
            {usernameCooldown && (
              <div className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-amber-50 border border-amber-200">
                <Lock className="w-3 h-3 text-amber-600" />
                <span className="text-[10px] font-semibold text-amber-600">{t('editprofile.username_cooldown', 'Cooldown')}</span>
              </div>
            )}
          </div>
          <div className="relative mt-1">
            <AtSign className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <Input
              value={editUsername}
              onChange={e => !usernameCooldown && handleUsernameChange(e.target.value)}
              readOnly={!!usernameCooldown}
              maxLength={14}
              className={cn(
                "h-11 rounded-xl pl-9 pr-10",
                usernameCooldown
                  ? "bg-slate-100 text-slate-500 cursor-not-allowed border-slate-200"
                  : usernameStatus === 'taken' || usernameStatus === 'invalid' || usernameStatus === 'error'
                  ? "border-rose-300 focus:border-rose-400"
                  : usernameStatus === 'available'
                  ? "border-emerald-300 focus:border-emerald-400"
                  : ""
              )}
              placeholder="your_handle"
            />
            <div className="absolute right-3 top-1/2 -translate-y-1/2">
              {usernameCooldown ? <Lock className="w-4 h-4 text-amber-400" /> : <ValidationIcon status={usernameStatus} />}
            </div>
          </div>
          {usernameCooldown ? (
            <p className="text-xs text-amber-600 mt-1 font-medium">
              ⏳ {t('editprofile.username_cooldown_msg', 'You can change your username again in')} {usernameCooldown.hours > 0 ? `${usernameCooldown.hours}h ` : ''}{usernameCooldown.minutes}m
            </p>
          ) : (
            <>
              {usernameError && <p className="text-xs text-rose-500 mt-1 font-medium">{usernameError}</p>}
              {usernameStatus === 'available' && !usernameError && <p className="text-xs text-emerald-600 mt-1 font-medium">{t('editprofile.username_available', '✓ Username available')}</p>}
              {usernameStatus === 'same' && <p className="text-xs text-slate-400 mt-1">{t('editprofile.username_current', 'Current username')}</p>}
            </>
          )}
          <p className="text-xs text-slate-400 mt-1">{editUsername.trim().length}/14 {t('editprofile.characters', 'characters')} · {t('editprofile.username_rules', 'Letters, numbers, _ and . only')}</p>
        </div>

        {/* Bio */}
        <div>
          <Label className="text-xs text-slate-600">{t('profile.bio', 'Bio')}</Label>
          <Textarea
            value={editBio}
            onChange={e => { setEditBio(e.target.value); checkDirty({ bio: e.target.value }); }}
            className="mt-1 rounded-xl min-h-[80px] resize-none"
            placeholder={t('profile.edit_bio', 'Tell us about yourself...')}
          />
        </div>

        {/* Dietary */}
        <div>
          <Label className="text-xs text-slate-600 mb-2 block">{t('editprofile.dietary', 'Dietary Preferences')}</Label>
          <div className="flex flex-wrap gap-1.5">
            {dietOptions.map(opt => (
              <DietaryChip key={opt.value} label={opt.label} value={opt.value} selected={editDietary.includes(opt.value)} onToggle={toggleDietary} size="sm" />
            ))}
          </div>
        </div>

        {/* Allergies */}
        <div>
          <Label className="text-xs text-slate-600 mb-1 block">{t('editprofile.allergies', 'Allergies')}</Label>
          <p className="text-[11px] text-slate-400 mb-2">{t('editprofile.allergies_desc', 'Select any allergies we should watch for in recipes')}</p>
          <div className="flex flex-wrap gap-1.5">
            {allergyOptions.map(opt => {
              const isSelected = editAllergies.includes(opt.value);
              const IconComp = typeof opt.icon === 'function' ? opt.icon : null;
              return (
                <button
                  key={opt.value}
                  onClick={() => toggleAllergy(opt.value)}
                  className={cn(
                    "flex items-center gap-1.5 px-2.5 py-1.5 rounded-full text-xs font-medium border transition-all",
                    isSelected
                      ? "bg-rose-50 text-rose-700 border-rose-300 shadow-sm"
                      : "bg-white text-slate-500 border-slate-200 hover:border-rose-200"
                  )}
                >
                  <span className="flex items-center" style={{ width: 16, height: 16 }}>
                    {IconComp ? <span style={{ transform: 'scale(0.57)', display: 'inline-flex' }}><IconComp /></span> : <span style={{ fontSize: 12 }}>{opt.icon}</span>}
                  </span>
                  {opt.label}
                  {isSelected && <span className="ml-0.5 text-rose-500 font-bold">✓</span>}
                </button>
              );
            })}
          </div>
          {editAllergies.length > 0 && (
            <p className="text-[11px] text-rose-500 font-medium mt-1.5">
              {editAllergies.length} {editAllergies.length === 1 ? t('editprofile.allergies_count_singular', 'allergy selected') : t('editprofile.allergies_count_plural', 'allergies selected')}
            </p>
          )}
        </div>

        {/* Equipment */}
        <div>
          <Label className="text-xs text-slate-600 mb-2 block">{t('editprofile.equipment', 'Equipment')}</Label>
          <div className="flex flex-wrap gap-1.5">
            {equipOptions.map(opt => (
              <button
                key={opt.value}
                onClick={() => toggleEquipment(opt.value)}
                className={cn(
                  "px-2.5 py-1 rounded-full text-[11px] font-medium border transition-all",
                  editEquipment.includes(opt.value) ? "bg-indigo-50 text-indigo-600 border-indigo-200" : "bg-white text-slate-500 border-slate-200"
                )}
              >{opt.label}</button>
            ))}
          </div>
        </div>

        {/* Skill Level */}
        <div>
          <Label className="text-xs text-slate-600">{t('editprofile.skill_level', 'Skill Level')}</Label>
          <Select value={editSkill} onValueChange={v => { setEditSkill(v); checkDirty({ skill: v }); }}>
            <SelectTrigger className="mt-1 h-10 rounded-xl"><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="beginner">{t('editprofile.beginner', 'Beginner')}</SelectItem>
              <SelectItem value="intermediate">{t('editprofile.intermediate', 'Intermediate')}</SelectItem>
              <SelectItem value="advanced">{t('editprofile.advanced', 'Advanced')}</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Goals */}
        <div>
          <Label className="text-xs text-slate-600 mb-3 block">{t('editprofile.goals', 'Goals (select 1–2)')}</Label>
          <div className="grid grid-cols-2 gap-2.5">
            {goalOptions.map(goal => {
              const isSelected = editGoals.includes(goal.value);
              const colorMap = {
                emerald: { bg: "bg-emerald-100", border: "border-emerald-300", text: "text-emerald-700" },
                orange:  { bg: "bg-orange-100",  border: "border-orange-300",  text: "text-orange-700" },
                blue:    { bg: "bg-blue-100",    border: "border-blue-300",    text: "text-blue-700" },
                yellow:  { bg: "bg-yellow-100",  border: "border-yellow-300",  text: "text-yellow-700" },
                rose:    { bg: "bg-rose-100",    border: "border-rose-300",    text: "text-rose-700" },
                purple:  { bg: "bg-purple-100",  border: "border-purple-300",  text: "text-purple-700" },
                red:     { bg: "bg-red-100",     border: "border-red-300",     text: "text-red-700" },
                pink:    { bg: "bg-pink-100",    border: "border-pink-300",    text: "text-pink-700" },
                indigo:  { bg: "bg-indigo-100",  border: "border-indigo-300",  text: "text-indigo-700" },
              };
              const colors = colorMap[goal.color] || colorMap.blue;
              return (
                <button
                  key={goal.value}
                  onClick={() => toggleGoal(goal.value)}
                  className={cn(
                    "p-3 rounded-2xl border-2 transition-all text-center relative",
                    isSelected ? `${colors.bg} ${colors.border} shadow-md` : "bg-white border-slate-200 hover:border-slate-300"
                  )}
                >
                  <div className="text-3xl mb-2">{goal.emoji}</div>
                  <p className={cn("text-xs font-bold line-clamp-2", isSelected ? colors.text : "text-slate-700")}>{goal.label}</p>
                  {isSelected && (
                    <div className="absolute -top-2 -right-2 w-6 h-6 rounded-full bg-green-500 flex items-center justify-center border-2 border-white shadow-lg">
                      <CheckCircle2 className="w-4 h-4 text-white" />
                    </div>
                  )}
                </button>
              );
            })}
          </div>
          <p className="text-xs text-slate-500 mt-2.5 font-medium">{editGoals.length} {t('editprofile.goals_count', '/ 2 selected')}</p>
        </div>
      </div>
    </div>
  );
}

/**
 * CircularCropModal — avatar cropper
 *
 * FRAME_R = 155 (large circle, nearly fills the preview square)
 * minScale = FRAME_D / CANVAS_SIZE so image short-side fills the circle exactly at default zoom
 * Export uses ctx.clip() before drawImage → perfectly circular PNG, transparent outside
 */
import React, { useState, useRef, useEffect, useCallback } from 'react';
import { X, Check, RotateCcw } from 'lucide-react';
import { motion } from 'framer-motion';

const FRAME_R     = 170;          // crop circle radius in preview px (fills square)
const FRAME_D     = FRAME_R * 2; // 310
const CANVAS_SIZE = 340;          // visible square canvas side
const OUTPUT_SIZE = 400;          // exported PNG logical size

export default function CircularCropModal({ imageFile, onSave, onClose }) {
  const [imgSrc,   setImgSrc]   = useState(null);
  const [nat,      setNat]      = useState({ w: 1, h: 1 });
  const [scale,    setScale]    = useState(1);
  const [minScale, setMinScale] = useState(1);
  const [offset,   setOffset]   = useState({ x: 0, y: 0 });
  const [dragging, setDragging] = useState(false);
  const [saving,   setSaving]   = useState(false);

  const live = useRef({ scale: 1, offset: { x: 0, y: 0 }, minScale: 1, dispW: CANVAS_SIZE, dispH: CANVAS_SIZE });
  useEffect(() => {
    const aspect = nat.w > 0 ? nat.w / nat.h : 1;
    const dispW  = aspect >= 1 ? CANVAS_SIZE * aspect : CANVAS_SIZE;
    const dispH  = aspect <  1 ? CANVAS_SIZE / aspect : CANVAS_SIZE;
    live.current = { scale, offset, minScale, dispW, dispH };
  });

  const dragOrigin   = useRef(null);
  const pinchDistRef = useRef(null);

  // ── Load image ──────────────────────────────────────────────────────────────
  useEffect(() => {
    if (!imageFile) return;
    const url = URL.createObjectURL(imageFile);
    setImgSrc(url);
    const img = new window.Image();
    img.onload = () => {
      const { naturalWidth: w, naturalHeight: h } = img;
      setNat({ w, h });
      // minScale: image short-side fills FRAME_D exactly at default zoom.
      // This means the image covers the circle but NOT necessarily the full canvas corners,
      // giving the user the ability to zoom out and see the full image.
      const ms = FRAME_D / CANVAS_SIZE;
      setMinScale(ms);
      setScale(ms);
      setOffset({ x: 0, y: 0 });
    };
    img.src = url;
    return () => URL.revokeObjectURL(url);
  }, [imageFile]);

  const aspect = nat.w > 0 ? nat.w / nat.h : 1;
  const dispW  = aspect >= 1 ? CANVAS_SIZE * aspect : CANVAS_SIZE;
  const dispH  = aspect <  1 ? CANVAS_SIZE / aspect : CANVAS_SIZE;

  // ── Clamp: image must always fully cover the crop circle ────────────────────
  const clamp = useCallback((ox, oy, sc, dw, dh) => {
    const sw   = dw * sc;
    const sh   = dh * sc;
    const maxX = Math.max(0, sw / 2 - FRAME_R);
    const maxY = Math.max(0, sh / 2 - FRAME_R);
    return {
      x: Math.max(-maxX, Math.min(maxX, ox)),
      y: Math.max(-maxY, Math.min(maxY, oy)),
    };
  }, []);

  // ── Pointer / touch / wheel events ──────────────────────────────────────────
  const onPointerDown = useCallback((e) => {
    if (e.touches?.length > 1) return;
    e.preventDefault();
    setDragging(true);
    const cx = e.touches ? e.touches[0].clientX : e.clientX;
    const cy = e.touches ? e.touches[0].clientY : e.clientY;
    dragOrigin.current = { cx, cy, ox: live.current.offset.x, oy: live.current.offset.y };
  }, []);

  const onPointerMove = useCallback((e) => {
    if (e.touches?.length === 2) {
      e.preventDefault();
      const t0   = e.touches[0], t1 = e.touches[1];
      const dist = Math.hypot(t0.clientX - t1.clientX, t0.clientY - t1.clientY);
      if (pinchDistRef.current !== null) {
        const { scale: sc, offset: o, minScale: ms, dispW: dw, dispH: dh } = live.current;
        const ratio = dist / pinchDistRef.current;
        const newSc = Math.max(ms, Math.min(ms * 10, sc * (1 + (ratio - 1) * 0.85)));
        const factor = newSc / sc;
        setScale(newSc);
        setOffset(clamp(o.x * factor, o.y * factor, newSc, dw, dh));
      }
      pinchDistRef.current = dist;
      return;
    }
    if (!dragOrigin.current) return;
    e.preventDefault();
    const cx = e.touches ? e.touches[0].clientX : e.clientX;
    const cy = e.touches ? e.touches[0].clientY : e.clientY;
    const { scale: sc, dispW: dw, dispH: dh } = live.current;
    setOffset(clamp(
      dragOrigin.current.ox + (cx - dragOrigin.current.cx),
      dragOrigin.current.oy + (cy - dragOrigin.current.cy),
      sc, dw, dh
    ));
  }, [clamp]);

  const onPointerUp = useCallback(() => {
    setDragging(false);
    pinchDistRef.current = null;
    dragOrigin.current   = null;
  }, []);

  const onWheel = useCallback((e) => {
    e.preventDefault();
    const { scale: sc, offset: o, minScale: ms, dispW: dw, dispH: dh } = live.current;
    const newSc = Math.max(ms, Math.min(ms * 10, sc * (e.deltaY < 0 ? 1.08 : 0.93)));
    const factor = newSc / sc;
    setScale(newSc);
    setOffset(clamp(o.x * factor, o.y * factor, newSc, dw, dh));
  }, [clamp]);

  const onSlider = useCallback((e) => {
    const newSc = Number(e.target.value);
    const { offset: o, scale: sc, dispW: dw, dispH: dh } = live.current;
    const factor = newSc / sc;
    setScale(newSc);
    setOffset(clamp(o.x * factor, o.y * factor, newSc, dw, dh));
  }, [clamp]);

  const handleReset = useCallback(() => {
    setScale(live.current.minScale);
    setOffset({ x: 0, y: 0 });
  }, []);

  // ── Export ───────────────────────────────────────────────────────────────────
  // The key: clip to circle FIRST, then drawImage.
  // Output canvas corners are never written → transparent PNG, no white sides.
  const handleSave = useCallback(async () => {
    if (!imgSrc || !nat.w || saving) return;
    setSaving(true);

    const { scale: sc, offset: o, dispW: dw, dispH: dh } = live.current;

    const ratio = OUTPUT_SIZE / CANVAS_SIZE;
    const outCX = OUTPUT_SIZE / 2;
    const outCY = OUTPUT_SIZE / 2;
    const drawW = dw * sc * ratio;
    const drawH = dh * sc * ratio;
    const drawX = outCX + o.x * ratio - drawW / 2;
    const drawY = outCY + o.y * ratio - drawH / 2;

    const dpr    = window.devicePixelRatio || 1;
    const canvas = document.createElement('canvas');
    canvas.width  = OUTPUT_SIZE * dpr;
    canvas.height = OUTPUT_SIZE * dpr;
    const ctx = canvas.getContext('2d');
    ctx.scale(dpr, dpr);
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = 'high';
    ctx.clearRect(0, 0, OUTPUT_SIZE, OUTPUT_SIZE);

    const img = new window.Image();
    img.onload = () => {
      // Clip to circle first — canvas corners stay transparent
      ctx.beginPath();
      ctx.arc(outCX, outCY, OUTPUT_SIZE / 2, 0, Math.PI * 2);
      ctx.clip();

      ctx.drawImage(img, drawX, drawY, drawW, drawH);

      canvas.toBlob(blob => {
        setSaving(false);
        if (blob) onSave(new File([blob], 'avatar.png', { type: 'image/png' }));
      }, 'image/png');
    };
    img.onerror = () => setSaving(false);
    img.src = imgSrc;
  }, [imgSrc, nat, saving, onSave]);

  // ── Render ───────────────────────────────────────────────────────────────────
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-[100] flex flex-col items-center justify-center"
      style={{ background: 'rgba(0,0,0,0.90)' }}
    >
      {imgSrc && (
        <div className="absolute inset-0 pointer-events-none" style={{
          backgroundImage: `url(${imgSrc})`,
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          filter: 'blur(24px) brightness(0.2)',
          transform: 'scale(1.1)',
        }} />
      )}

      <div className="relative z-10 flex flex-col items-center w-full max-w-xs px-5 gap-4">

        {/* Header */}
        <div className="flex items-center justify-between w-full">
          <button onClick={onClose}
            className="w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center transition-colors">
            <X className="w-5 h-5 text-white" />
          </button>
          <p className="text-white font-semibold text-sm">Adjust Photo</p>
          <button onClick={handleReset} title="Reset"
            className="w-10 h-10 rounded-full bg-white/10 hover:bg-white/20 flex items-center justify-center transition-colors">
            <RotateCcw className="w-4 h-4 text-white/80" />
          </button>
        </div>

        {/* Crop canvas */}
        <div
          style={{
            position:    'relative',
            width:       CANVAS_SIZE,
            height:      CANVAS_SIZE,
            overflow:    'hidden',
            flexShrink:  0,
            background:  '#000',
            cursor:      dragging ? 'grabbing' : 'grab',
            touchAction: 'none',
            userSelect:  'none',
            borderRadius: 0,
          }}
          onMouseDown={onPointerDown}
          onMouseMove={onPointerMove}
          onMouseUp={onPointerUp}
          onMouseLeave={onPointerUp}
          onTouchStart={onPointerDown}
          onTouchMove={onPointerMove}
          onTouchEnd={onPointerUp}
          onWheel={onWheel}
        >
          {imgSrc && nat.w > 0 && (
            <img
              src={imgSrc}
              draggable={false}
              alt=""
              style={{
                position:        'absolute',
                top:             '50%',
                left:            '50%',
                width:           dispW,
                height:          dispH,
                transform:       `translate(-50%, -50%) translate(${offset.x}px, ${offset.y}px) scale(${scale})`,
                transformOrigin: 'center center',
                willChange:      'transform',
                pointerEvents:   'none',
                userSelect:      'none',
                borderRadius:    0,
              }}
            />
          )}

          {/* SVG overlay: darken outside circle + white ring guide */}
          <svg
            width={CANVAS_SIZE} height={CANVAS_SIZE}
            style={{ position: 'absolute', inset: 0, pointerEvents: 'none' }}
          >
            <defs>
              <mask id="avatarCropMask">
                <rect width={CANVAS_SIZE} height={CANVAS_SIZE} fill="white" />
                <circle cx={CANVAS_SIZE / 2} cy={CANVAS_SIZE / 2} r={FRAME_R} fill="black" />
              </mask>
            </defs>
            <rect width={CANVAS_SIZE} height={CANVAS_SIZE} fill="rgba(0,0,0,0.58)" mask="url(#avatarCropMask)" />
            <circle cx={CANVAS_SIZE / 2} cy={CANVAS_SIZE / 2} r={FRAME_R}
              fill="none" stroke="rgba(255,255,255,0.8)" strokeWidth="2" />
          </svg>
        </div>

        <p className="text-white/35 text-xs text-center -mt-1">
          Drag · Pinch · Scroll to zoom · ↺ reset
        </p>

        {/* Zoom slider */}
        <div className="flex items-center gap-3 w-full">
          <span className="text-white/50 text-sm select-none">−</span>
          <input
            type="range"
            min={minScale}
            max={minScale * 10}
            step={minScale * 0.01}
            value={scale}
            onChange={onSlider}
            className="flex-1 h-1 cursor-pointer"
            style={{ accentColor: 'white' }}
          />
          <span className="text-white/50 text-sm select-none">+</span>
        </div>

        {/* Confirm */}
        <button
          onClick={handleSave}
          disabled={saving || !imgSrc}
          className="w-full rounded-2xl bg-white text-black font-bold text-sm flex items-center justify-center gap-2 disabled:opacity-50 transition-opacity"
          style={{ height: 50 }}
        >
          {saving
            ? <span className="w-5 h-5 border-2 border-black/30 border-t-black rounded-full animate-spin" />
            : <Check className="w-5 h-5" />}
          {saving ? 'Saving…' : 'Use Photo'}
        </button>
      </div>
    </motion.div>
  );
}

