  const { data: user } = useQuery({ queryKey: ['me-admin-notif'], queryFn: () => base44.auth.me() });
  const isOwner = user?.email === 'xenodekuu@gmail.com';

  const [liveQuery, setLiveQuery] = useState('');
  useEffect(() => {
    const timer = setTimeout(() => {
      setLiveQuery(searchQuery);
      setShowSearchDropdown(searchQuery.length >= 1);
    }, 150);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  const { data: searchResults = [], isLoading: searchLoading } = useQuery({
    queryKey: ['user-search-live', liveQuery],
    queryFn: async () => {
      if (!liveQuery || liveQuery.length < 1) return [];
      const res = await base44.functions.invoke('searchUsersAdvanced', { query: liveQuery, limit: 15 }).catch(() => ({ data: { results: [] } }));
      return res.data?.results || [];
    },
    enabled: !!liveQuery && liveQuery.length >= 1,
    staleTime: 3000,
  });

  // Auto-resolve destination when strategy type selected + user selected
  useEffect(() => {
    if (!selectedUser || !STRATEGY_TYPES.has(selectedType)) {
      setDestinationPreview(null);
      return;
    }
    let cancelled = false;
    setPreviewLoading(true);
    setDestinationPreview(null);

    base44.functions.invoke('adminSendPushNotification', {
      user_id: selectedUser.id,
      notification_type: selectedType,
      dry_run: true,
    }).then(res => {
      if (!cancelled) {
        setDestinationPreview(res.data);
        setPreviewLoading(false);
      }
    }).catch(err => {
      if (!cancelled) {
        setDestinationPreview({ resolved: false, reason: 'error', message: err.message });
        setPreviewLoading(false);
      }
    });

    return () => { cancelled = true; };
  }, [selectedUser?.id, selectedType]);

  // Send notification
  const sendMutation = useMutation({
    mutationFn: async () => {
      if (!selectedUser) throw new Error('No user selected');
      const res = await base44.functions.invoke('adminSendPushNotification', {
        user_id: selectedUser.id,
        notification_type: selectedType,
        send_mode: scheduledTime ? 'scheduled' : 'now',
        scheduled_time: scheduledTime || null,
        is_admin_override: overrideLimit,
        dry_run: false,
      });
      return res.data;
    },
    onSuccess: (data) => {
      if (data.scheduled) {
        setResult({ success: true, message: `Scheduled. Opens → ${data.deep_link || '/Home'}` });
      } else if (data.sent > 0) {
        setResult({ success: true, message: `Delivered to ${data.sent}/${data.total} device(s). Opens → ${data.deep_link || '/Home'}` });
      } else if (data.reason === 'no_content' || data.reason === 'cooldown_active') {
        setResult({ success: false, error: data.message });
      } else {
        setResult({ success: false, error: data.message || data.warning || 'Delivery failed' });
      }
      setTimeout(() => setResult(null), 10000);
    },
    onError: (err) => {
      setResult({ success: false, error: err.response?.data?.error || err.message });
    },
  });

  const { data: history = [] } = useQuery({
    queryKey: ['notification-history', selectedUser?.id],
    queryFn: async () => {
      const res = await base44.entities.NotificationHistory.filter({ user_id: selectedUser.id }, '-sent_at', 20);
      return res || [];
    },
    enabled: !!selectedUser,
  });

  if (!isOwner) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="text-center">
          <AlertTriangle className="w-12 h-12 text-red-500 mx-auto mb-3" />
          <p className="text-lg font-bold text-slate-900">Admin Only</p>
        </div>
      </div>
    );
  }

  const spec = NOTIFICATION_SPECS[selectedType];
  const isStrategy = STRATEGY_TYPES.has(selectedType);
  const canSend = selectedUser && (!isStrategy || destinationPreview?.resolved);

  const filteredTypes = Object.entries(NOTIFICATION_SPECS).filter(([, s]) =>
    categoryFilter === 'all' || s.category === categoryFilter
  );

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <div className="sticky top-0 bg-white border-b border-slate-200 z-10">
        <div className="flex items-center gap-3 p-4">
          <AdminBackButton />
          <div className="flex-1">
            <h1 className="text-lg font-bold text-slate-900">Notification Admin</h1>
            <p className="text-xs text-slate-500">Send targeted push notifications</p>
          </div>
          <button
            onClick={() => window.location.href = '/PushDiagnostics'}
            className="flex items-center gap-1.5 px-3 py-2 rounded-lg bg-amber-50 border border-amber-200 text-amber-800 text-xs font-bold"
            title="Push token diagnostics"
          >
            <Smartphone className="w-3.5 h-3.5" /> Diagnostics
          </button>
        </div>
      </div>

      <div className="max-w-2xl mx-auto p-4 space-y-5">
        {/* Result Banner */}
        {result && (
          <div className={`p-4 rounded-xl border flex items-start gap-3 ${result.success ? 'bg-green-50 border-green-200 text-green-700' : 'bg-red-50 border-red-200 text-red-700'}`}>
            {result.success ? <CheckCircle2 className="w-5 h-5 flex-shrink-0 mt-0.5" /> : <AlertTriangle className="w-5 h-5 flex-shrink-0 mt-0.5" />}
            <div>
              <p className="font-bold">{result.success ? 'Success' : 'Error'}</p>
              <p className="text-sm">{result.message || result.error}</p>
            </div>
          </div>
        )}

        {/* User Search */}
        <div className="bg-white rounded-xl p-4 border border-slate-200 relative z-30">
          <label className="block text-sm font-bold text-slate-900 mb-3">Send To</label>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              type="text" placeholder="Type name, email, or username..."
              value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => searchQuery.length >= 1 && setShowSearchDropdown(true)}
              autoComplete="off"
              className="w-full pl-10 pr-10 py-2.5 border-2 border-slate-200 rounded-xl text-sm focus:outline-none focus:border-blue-500 transition-all"
            />
            {searchQuery && !selectedUser && (
              <button onClick={() => { setSearchQuery(''); setShowSearchDropdown(false); }} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400">
                <X className="w-4 h-4" />
              </button>
            )}
          </div>

          {showSearchDropdown && searchQuery.length >= 1 && !selectedUser && (
            <div className="absolute top-[calc(100%+8px)] left-0 right-0 bg-white border-2 border-slate-200 rounded-xl shadow-2xl z-50 max-h-[360px] overflow-y-auto">
              {searchLoading ? (
                <div className="px-4 py-6 text-center"><div className="w-5 h-5 border-2 border-slate-300 border-t-blue-600 rounded-full animate-spin mx-auto" /></div>
              ) : searchResults.length > 0 ? (
                <div className="divide-y divide-slate-100">
                  {searchResults.map((u) => (
                    <button key={u.id} onClick={() => { setSelectedUser(u); setSearchQuery(''); setShowSearchDropdown(false); }}
                      className="w-full text-left p-3 hover:bg-blue-50 transition-colors">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-indigo-400 to-blue-500 flex items-center justify-center text-white font-bold text-sm">
                          {(u.display_name || u.email || '?').charAt(0).toUpperCase()}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="font-semibold text-slate-900 text-sm truncate">{u.display_name || '—'}</p>
                          <p className="text-xs text-slate-500 truncate">{u.username ? `@${u.username}` : u.email}</p>
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              ) : (
                <div className="px-4 py-6 text-center text-sm text-slate-500">No users found</div>
              )}
            </div>
          )}

          {selectedUser && (
            <div className="mt-3 p-3 rounded-xl bg-gradient-to-br from-indigo-50 to-blue-50 border-2 border-blue-300 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 rounded-full bg-gradient-to-br from-indigo-400 to-blue-500 flex items-center justify-center text-white font-bold text-lg">
                  {(selectedUser.display_name || selectedUser.email || '?').charAt(0).toUpperCase()}
                </div>
                <div>
                  <p className="font-bold text-slate-900 text-sm">{selectedUser.display_name || '—'}</p>
                  <p className="text-xs text-slate-600">{selectedUser.username ? `@${selectedUser.username}` : selectedUser.email}</p>
                </div>
              </div>
              <button onClick={() => { setSelectedUser(null); setSearchQuery(''); setDestinationPreview(null); }} className="p-2 rounded-lg hover:bg-white/60">
                <X className="w-5 h-5 text-slate-600" />
              </button>
            </div>
          )}
        </div>

        {/* Category Filter */}
        <div className="flex gap-2 overflow-x-auto hide-scrollbar -mx-4 px-4">
          {[['all', 'All'], ['strategy', '🎯 Strategy'], ['standard', '📋 Standard'], ['social', '💬 Social'], ['motivation', '💪 Motivation']].map(([key, label]) => (
            <button key={key} onClick={() => setCategoryFilter(key)}
              className={`px-3 py-1.5 rounded-full text-xs font-bold whitespace-nowrap border-2 transition-all ${categoryFilter === key ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-200'}`}>
              {label}
            </button>
          ))}
        </div>

        {/* Notification Type Grid */}
        <div className="bg-white rounded-xl p-4 border border-slate-200">
          <label className="block text-sm font-bold text-slate-900 mb-3">Notification Type</label>
          <div className="grid grid-cols-3 gap-2">
            {filteredTypes.map(([type, specItem]) => {
              const emoji = NOTIFICATION_TYPE_EMOJIS[type] || '📨';
              const isSelected = selectedType === type;
              const catColor = CATEGORY_COLORS[specItem.category] || '';
              return (
                <button key={type} onClick={() => setSelectedType(type)}
                  className={`flex flex-col items-center gap-1 p-2.5 rounded-xl border-2 transition-all ${isSelected ? 'bg-blue-50 border-blue-400 shadow-md shadow-blue-100' : `${catColor} hover:border-slate-300`}`}>
                  <span className="text-xl leading-none">{emoji}</span>
                  <span className={`text-[9px] font-bold text-center leading-tight ${isSelected ? 'text-blue-700' : 'text-slate-700'}`}>{type.replace(/_/g, ' ')}</span>
                  {specItem.category === 'strategy' && <span className="text-[7px] text-indigo-500 font-extrabold uppercase tracking-wider">targeted</span>}
                </button>
              );
            })}
          </div>
        </div>

        {/* Preview */}
        {spec && (
          <div className="bg-white rounded-xl p-4 border border-slate-200">
            <p className="text-xs font-bold text-slate-500 mb-2">NOTIFICATION PREVIEW</p>
            <div className="p-3 rounded-lg bg-slate-50">
              <p className="font-bold text-slate-900 text-sm">{spec.title}</p>
              <p className="text-xs text-slate-600 mt-1">{spec.description}</p>
            </div>
          </div>
        )}

        {/* Destination Preview (strategy types only) */}
        {isStrategy && selectedUser && (
          <div>
            <div className="flex items-center gap-2 mb-2">
              <Target className="w-4 h-4 text-indigo-500" />
              <p className="text-xs font-bold text-slate-700">DESTINATION TARGET</p>
            </div>
            <NotificationDestinationPreview preview={destinationPreview} isLoading={previewLoading} />
          </div>
        )}

        {/* Send Time */}
        <div className="bg-white rounded-xl p-4 border border-slate-200">
          <label className="block text-sm font-bold text-slate-900 mb-3">Send Time</label>
          <div className="flex gap-2 mb-3">
            <button onClick={() => setScheduledTime(null)}
              className={`flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg text-sm font-medium border-2 transition-all ${!scheduledTime ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-200 text-slate-700'}`}>
              <Zap className="w-4 h-4" /> Send Now
            </button>
            <button onClick={() => { const t = new Date(); t.setHours(t.getHours() + 1); setScheduledTime(t.toISOString()); }}
              className={`flex-1 flex items-center justify-center gap-2 px-3 py-2.5 rounded-lg text-sm font-medium border-2 transition-all ${scheduledTime ? 'bg-blue-600 border-blue-600 text-white' : 'bg-white border-slate-200 text-slate-700'}`}>
              <Clock className="w-4 h-4" /> Schedule
            </button>
          </div>
          {scheduledTime && (
            <input type="datetime-local" value={new Date(scheduledTime).toISOString().slice(0, 16)}
              onChange={(e) => setScheduledTime(new Date(e.target.value).toISOString())}
              className="w-full px-3 py-2.5 border border-slate-200 rounded-lg text-sm" />
          )}
        </div>

        {/* Override */}
        <label className="flex items-center gap-3 p-3 rounded-lg bg-yellow-50 border border-yellow-200 cursor-pointer">
          <input type="checkbox" checked={overrideLimit} onChange={(e) => setOverrideLimit(e.target.checked)} className="w-4 h-4" />
          <span className="text-sm font-medium text-yellow-800">Override daily limit & cooldowns</span>
        </label>

        {/* Send Button */}
        <button onClick={() => sendMutation.mutate()}
          disabled={!canSend || sendMutation.isPending}
          className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-blue-600 text-white rounded-lg font-bold hover:bg-blue-700 disabled:opacity-50">
          <Send className="w-4 h-4" />
          {sendMutation.isPending ? 'Sending...' : isStrategy && !destinationPreview?.resolved ? 'No content target' : 'Send Notification'}
        </button>

        {/* History */}
        {selectedUser && history.length > 0 && (
          <div className="bg-white rounded-xl p-4 border border-slate-200">
            <div className="flex items-center gap-2 mb-3">
              <History className="w-4 h-4 text-slate-600" />
              <h3 className="font-bold text-slate-900 text-sm">Recent History</h3>
            </div>
            <div className="space-y-2 max-h-72 overflow-y-auto">
              {history.slice(0, 15).map((h) => (
                <div key={h.id} className="p-2.5 rounded-lg bg-slate-50 text-xs">
                  <div className="flex items-center justify-between mb-1">
                    <span className="font-bold text-slate-900">{h.notification_type?.replace(/_/g, ' ')}</span>
                    <span className={`px-1.5 py-0.5 rounded-full text-[9px] font-bold ${h.delivery_status === 'delivered' ? 'bg-green-100 text-green-700' : h.delivery_status === 'no_tokens' ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'}`}>
                      {h.delivery_status || 'unknown'}
                    </span>
                  </div>
                  <p className="text-slate-600 truncate">{h.title}</p>
                  {h.deep_link && h.deep_link !== '/Home' && (
                    <p className="text-indigo-500 font-mono text-[10px] mt-1">→ {h.deep_link}</p>
                  )}
                  {h.send_reason && h.send_reason !== 'admin_manual' && (
                    <p className="text-slate-400 text-[10px] mt-0.5">Reason: {h.send_reason}</p>
                  )}
                  <p className="text-slate-400 mt-1">
                    {new Date(h.sent_at).toLocaleString()}
                    {h.was_opened && ' • Opened'}
                  </p>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

/**
 * AdminLiveDashboard — Real-time production analytics & observability page
 * STRICTLY admin-only (RequireAdmin + backend enforcement on every call)
 */
import React, { useState, useEffect, useCallback, useRef } from 'react';
import { base44 } from '@/api/base44Client';
import RequireAdmin from '../components/services/RequireAdmin';
import SummaryBar from '../components/admin/live-dashboard/SummaryBar';
import LiveFeed from '../components/admin/live-dashboard/LiveFeed';
import SignupsTable from '../components/admin/live-dashboard/SignupsTable';
import UsersTable from '../components/admin/live-dashboard/UsersTable';
import IntegrationCostsTable from '../components/admin/live-dashboard/IntegrationCostsTable';
import InsightsPanel from '../components/admin/live-dashboard/InsightsPanel';
import BankCreditsControlPanel from '../components/admin/BankCreditsControlPanel';
import LiveEventsPanel from '../components/admin/live-dashboard/LiveEventsPanel';
import { ArrowLeft, RefreshCw, Activity, UserPlus, Users, Cpu, BarChart2, Radio, Coins, Zap } from 'lucide-react';
import AdminBackButton from '../components/admin/AdminBackButton';
import { cn } from '@/lib/utils';
import { formatAdminTime } from '../utils/localTime';

const TABS = [
  { id: 'feed',     label: 'Live Feed', icon: Radio },
  { id: 'events',   label: 'Events',    icon: Zap },
  { id: 'signups',  label: 'Sign Ups',  icon: UserPlus },
  { id: 'users',    label: 'Users',     icon: Users },
  { id: 'costs',    label: 'Cost Log',  icon: Cpu },
  { id: 'insights', label: 'Insights',  icon: BarChart2 },
  { id: 'credits',  label: 'Bank Credits', icon: Coins },
];

// LiveFeed self-manages real-time via entity subscriptions + polling.
// Dashboard summary bar refreshes every 60s to avoid rate limit storms.
const LIVE_REFRESH_MS = 60000;

function AdminLiveDashboardContent() {
  const [activeTab, setActiveTab] = useState('feed');
  const [summary, setSummary] = useState(null);
  const [liveFeed, setLiveFeed] = useState([]);
  const [signups, setSignups] = useState([]);
  const [users, setUsers] = useState([]);
  const [costLogs, setCostLogs] = useState([]);
  const [costMeta, setCostMeta] = useState({ total_cost_usd: 0, by_category: {} });
  const [insights, setInsights] = useState(null);
  const [loading, setLoading] = useState({ overview: true, signups: false, users: false, costs: false, insights: false, feed: false });
  const [lastUpdated, setLastUpdated] = useState(null);
  const [isLive, setIsLive] = useState(true);
  const liveIntervalRef = useRef(null);

  const fetchSection = useCallback(async (section) => {
    const loadKey = section === 'overview' ? 'overview' : section === 'live_events' ? 'feed' : section === 'integration_costs' ? 'costs' : section;
    setLoading(prev => ({ ...prev, [loadKey]: true }));
    try {
      const res = await base44.functions.invoke('getAdminLiveDashboard', { section });
      const data = res.data;

      if (section === 'overview') {
        setSummary(data.summary);
        setLiveFeed(data.live_feed || []);
        setLastUpdated(new Date());
      } else if (section === 'live_events') {
        // Update feed AND patch summary cards + signups list
        setLiveFeed(data.events || []);
        if (data.summary_patch) {
          setSummary(prev => prev ? { ...prev, ...data.summary_patch } : data.summary_patch);
        }
        // Merge recent signups into the signups tab (prepend new ones)
        if (data.recent_signups?.length) {
          setSignups(prev => {
            const existingIds = new Set(prev.map(s => s.id));
            const fresh = data.recent_signups.filter(s => !existingIds.has(s.id));
            return fresh.length ? [...fresh, ...prev] : prev;
          });
        }
        setLastUpdated(new Date());
      } else if (section === 'signups') {
        setSignups(data.signups || []);
      } else if (section === 'users') {
        setUsers(data.users || []);
      } else if (section === 'integration_costs') {
        setCostLogs(data.logs || []);
        setCostMeta({ total_cost_usd: data.total_cost_usd || 0, by_category: data.by_category || {} });
      } else if (section === 'insights') {
        setInsights(data);
      }
    } catch (err) {
      console.error('[AdminDashboard]', section, err?.message);
    } finally {
      setLoading(prev => ({ ...prev, [loadKey]: false }));
    }
  }, []);

  // Initial load
  useEffect(() => {
    fetchSection('overview');
  }, []);

  // Auto-refresh: every 15s fetch live_events + re-fetch active tab data (users/signups) for real-time updates
  useEffect(() => {
    if (!isLive) { clearInterval(liveIntervalRef.current); return; }
    liveIntervalRef.current = setInterval(() => {
      fetchSection('live_events');
      // Also refresh users or signups tab if currently active (quota & gens update in real-time)
      if (activeTab === 'users') fetchSection('users');
      if (activeTab === 'signups') fetchSection('signups');
    }, LIVE_REFRESH_MS);
    return () => clearInterval(liveIntervalRef.current);
  }, [isLive, fetchSection, activeTab]);

  // Fetch tab data when tab changes (always fresh, no cache delays)
  useEffect(() => {
    const sectionMap = { signups: 'signups', users: 'users', costs: 'integration_costs', insights: 'insights' };
    const section = sectionMap[activeTab];
    if (section) fetchSection(section);
  }, [activeTab, fetchSection]);

  // Real-time: subscribe to User creates → update summary counts + signups list
  // (LiveFeed handles its own subscriptions independently)
  useEffect(() => {
    const unsub = base44.entities.User.subscribe(event => {
      if (event.type === 'create' && event.data) {
        const u = event.data;
        setSummary(prev => prev ? {
          ...prev,
          new_signups_today: (prev.new_signups_today || 0) + 1,
          total_users: (prev.total_users || 0) + 1,
          free_users: (prev.free_users || 0) + 1,
        } : prev);
        setSignups(prev => [{
          id: u.id, email: u.email,
          display_name: u.display_name || u.full_name || u.username || 'Unknown',
          full_name: u.full_name, username: u.username, avatar_url: u.avatar_url,
          created_date: u.created_date, onboarding_complete: !!u.onboarding_complete,
          plan: 'free', last_active: u.last_seen_at || u.updated_date,
        }, ...prev]);
      }
    });
    return unsub;
  }, []);

  const handleRefresh = () => {
    fetchSection('live_events');
    const sectionMap = { signups: 'signups', users: 'users', costs: 'integration_costs', insights: 'insights' };
    if (sectionMap[activeTab]) fetchSection(sectionMap[activeTab]);
  };

  return (
    <div style={{ background: '#0a0b0f', color: '#e2e8f0', minHeight: '100vh', display: 'flex', flexDirection: 'column', overflow: 'hidden', position: 'relative', zIndex: 1 }}>
      <style>{`
        /* Override Layout's main bg for admin dark theme */
        main { background-color: #0a0b0f !important; }
      `}</style>
      <style>{`
        .ald-hide-scrollbar::-webkit-scrollbar { display: none; }
        .ald-hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
        .ald-scrollable::-webkit-scrollbar { width: 6px; }
        .ald-scrollable::-webkit-scrollbar-track { background: rgba(255,255,255,0.03); }
        .ald-scrollable::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.12); border-radius: 3px; }
        .ald-scrollable::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }
        .ald-scrollable { scrollbar-width: thin; scrollbar-color: rgba(255,255,255,0.12) transparent; }
        .ald-tab-active { background: rgba(99,102,241,0.18); color: #818cf8; border-color: rgba(99,102,241,0.35); }
        .ald-tab { transition: all 0.15s ease; border: 1px solid transparent; }
        .ald-tab:hover:not(.ald-tab-active) { background: rgba(255,255,255,0.06); color: rgba(255,255,255,0.7); }
      `}</style>

      {/* ── STICKY HEADER ── */}
      <div style={{ background: 'rgba(10,11,15,0.97)', backdropFilter: 'blur(12px)', borderBottom: '1px solid rgba(255,255,255,0.07)', flexShrink: 0 }}>
        {/* Title row */}
        <div className="flex items-center gap-3 px-4 lg:px-6 py-3">
          <AdminBackButton dark />
          <div className="flex-1 min-w-0 flex items-center gap-3 flex-wrap">
            <h1 className="text-base font-black text-white tracking-tight whitespace-nowrap">Admin Live Dashboard</h1>
            <span className="text-[9px] font-black px-1.5 py-0.5 rounded-full bg-rose-900/60 text-rose-400 uppercase tracking-wider border border-rose-500/30 whitespace-nowrap">Owner Only</span>
            {isLive && (
