function Avatar({ name, avatarUrl, size = 9, loading = false }) {
  const [imgError, setImgError] = React.useState(false);
  // Reset error state whenever avatarUrl changes (e.g. user entity loads after URL-param stub)
  React.useEffect(() => { setImgError(false); }, [avatarUrl]);
  const sizes = { 7: 'w-7 h-7', 8: 'w-8 h-8', 9: 'w-9 h-9', 10: 'w-10 h-10' };
  const cls = sizes[size] || 'w-9 h-9';
  // Only attempt to render an img if avatarUrl is a non-empty string
  const hasValidUrl = typeof avatarUrl === 'string' && avatarUrl.trim().length > 0;
  const showImg = hasValidUrl && !imgError;
  // Derive letter from name — never show "?" or blank
  const letter = name?.trim()?.charAt(0)?.toUpperCase() || null;
  return (
    <div className={`${cls} rounded-full bg-gradient-to-br from-indigo-400 to-purple-400 flex items-center justify-center overflow-hidden flex-shrink-0`}>
      {loading ? (
        // Name not yet resolved — pulse skeleton, never empty circle
        <div className="w-full h-full bg-indigo-300/50 animate-pulse" />
      ) : showImg ? (
        <img src={avatarUrl} alt="" className="w-full h-full object-cover" onError={() => setImgError(true)} />
      ) : letter ? (
        <span className="text-xs font-bold text-white">{letter}</span>
      ) : (
        // Truly no name and no image — pulse skeleton
        <div className="w-full h-full bg-indigo-300/50 animate-pulse" />
      )}
    </div>
  );
}

function getConvPrefs() {
  try { return JSON.parse(localStorage.getItem('dm_conv_prefs') || '{}'); } catch { return {}; }
}
function setConvPrefsStore(p) { localStorage.setItem('dm_conv_prefs', JSON.stringify(p)); }

// Parse URL params at module scope so initial state is synchronous (no re-render needed)
function getInitialOtherUserFromUrl() {
  try {
    const p = new URLSearchParams(window.location.search);
    const uid = p.get("userId");
    const name = p.get("recipientName");
    const avatar = p.get("recipientAvatar");
    if (uid && name) {
      return {
        id: uid,
        display_name: decodeURIComponent(name),
        full_name: decodeURIComponent(name),
        avatar_url: avatar ? decodeURIComponent(avatar) : null,
      };
    }
  } catch {}
  return null;
}

export default function MessagesPage() {
  const [currentUser, setCurrentUser] = useState(null);
  // Initialize otherUserId synchronously from URL so we skip a render cycle
  const [otherUserId, setOtherUserId] = useState(() => {
    try { return new URLSearchParams(window.location.search).get("userId") || null; } catch { return null; }
  });
  // Initialize otherUser from URL params instantly — no waiting for useEffect
  const [otherUser, setOtherUser] = useState(getInitialOtherUserFromUrl);
  const [messageText, setMessageText] = useState("");
  const [sending, setSending] = useState(false);
  const [editingMsgId, setEditingMsgId] = useState(null);
  const [editMsgText, setEditMsgText] = useState('');
  const [nicknameEdit, setNicknameEdit] = useState(false);
  const [nicknameVal, setNicknameVal] = useState("");
  const [prefs, setPrefs] = useState(getConvPrefs());
  const [showGifPicker, setShowGifPicker] = useState(false);
  const [isBlocked, setIsBlocked] = useState(false);
  const [replyTo, setReplyTo] = useState(null); // { id, content, senderName }
  const [contextMenu, setContextMenu] = useState(null); // { msgId, x, y }
  const [menuReadyAt, setMenuReadyAt] = useState(0); // timestamp when menu appeared — blocks instant taps
  const [deleteConfirm, setDeleteConfirm] = useState(null); // { msgId, mode, label }
  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const [reactionsMap, setReactionsMap] = useState({}); // { messageId: { emoji: [user_ids] } }
  const [showReactionMenu, setShowReactionMenu] = useState(null); // { msgId, x, y }
  const [showReactionsList, setShowReactionsList] = useState(null); // messageId
  const [showActionPanel, setShowActionPanel] = useState(false);
  const [sendError, setSendError] = useState("");
  const [pendingImageFile, setPendingImageFile] = useState(null); // File object for image preview
  const [showMultiImageComposer, setShowMultiImageComposer] = useState(false);
  const sendTimestampsRef = useRef([]); // DM rate limiter: track last N send timestamps
  const bottomRef = useRef(null);
  const msgScrollRef = useRef(null);
  const longPressTimerRef = useRef(null);
  const didLongPressRef = useRef(false); // tracks if touchend should be suppressed
  const queryClient = useQueryClient();

  const conversationId = otherUserId && currentUser?.id
    ? [currentUser.id, otherUserId].sort().join("_")
    : null;

  const convPrefs = conversationId ? (prefs[conversationId] || {}) : {};
  // B3 FIX: Never show "..." or "." — hold loading skeleton until name is resolved.
  // URL params give us an instant cached name — use it immediately to avoid the skeleton.
  // Once otherUser entity loads, it overrides with the live canonical name.
  const resolvedOtherName = otherUser?.display_name || otherUser?.full_name || null;
  const displayName = convPrefs.nickname || resolvedOtherName || null;

  useEffect(() => {
    base44.auth.me().then(setCurrentUser).catch(() => {});
    const params = new URLSearchParams(window.location.search);
    const prefill = params.get("prefill");
    if (prefill) setMessageText(decodeURIComponent(prefill));
    // Auto-open create group flow if requested from ChatList long-press
    if (params.get("openCreateGroup") === "1") {
      setShowActionPanel(true);
      setTimeout(() => window.dispatchEvent(new CustomEvent('dm-panel-open-create-group')), 300);
    }
  }, []);

  // DM profile resolution — fires immediately on otherUserId, does NOT wait for currentUser.
  // Layer 1: URL params (instant, set in useState initializer above)
  // Layer 2: User entity query (authoritative — runs immediately, no currentUser dependency)
  // Layer 3: DirectConversation fallback (uses currentUser when available)
  useEffect(() => {
    if (!otherUserId) return;
    let cancelled = false;

    // IMMEDIATE: User.filter does not require currentUser — fire right away
    (async () => {
      let resolved = false;
      try {
        const users = await base44.entities.User.filter({ id: otherUserId });
        if (!cancelled && users[0]) {
          setOtherUser(users[0]);
          resolved = true;
        }
      } catch (err) {
        console.warn('[Messages] User.filter failed:', err?.message);
      }

      // Fallback to DirectConversation only if User query failed AND we have currentUser
      if (!resolved && !cancelled) {
        // Wait briefly for currentUser to be available (auth.me is fast, typically <200ms)
        const waitForAuth = () => new Promise(resolve => {
          let attempts = 0;
          const check = () => {
            // Access currentUser via ref-stable closure — read from state at check time
            const cu = currentUser;
            if (cu?.id || attempts > 8) { resolve(cu); return; }
            attempts++;
            setTimeout(check, 150);
          };
          check();
        });
        const cu = await waitForAuth();
        if (cancelled) return;
        if (cu?.id) {
          try {
            const convKey = [cu.id, otherUserId].sort().join('_');
            const convs = await base44.entities.DirectConversation.filter({ conversation_key: convKey });
            const c = convs[0];
            if (!cancelled && c) {
              const iAmA = c.participant_a_id === cu.id;
              const name = iAmA ? c.participant_b_name : c.participant_a_name;
              const avatar = iAmA ? c.participant_b_avatar : c.participant_a_avatar;
              if (name) {
                setOtherUser(prev => {
                  if (prev?.full_name || prev?.display_name) return prev;
                  return { id: otherUserId, display_name: name, full_name: name, avatar_url: avatar };
                });
                resolved = true;
              }
            }
          } catch {}
        }
      }

      // Last resort retry after 2s for transient network failures
      if (!resolved && !cancelled) {
        setTimeout(async () => {
          if (cancelled) return;
          try {
            const users = await base44.entities.User.filter({ id: otherUserId });
            if (!cancelled && users[0]) setOtherUser(users[0]);
          } catch {}
        }, 2000);
      }
    })();

    return () => { cancelled = true; };
  }, [otherUserId]);

  useEffect(() => {
    if (!otherUserId || !currentUser?.id) return;
    Promise.all([
      base44.entities.BlockedUser.filter({ blocker_id: currentUser.id, blocked_id: otherUserId }),
      base44.entities.BlockedUser.filter({ blocker_id: otherUserId, blocked_id: currentUser.id }),
    ]).then(([byMe, byThem]) => {
      const blocked = byMe.length > 0 || byThem.length > 0;
      const wasBlocked = isBlocked;
      setIsBlocked(blocked);
      // When block is newly detected, set a visibility cutoff so old messages hide
      if (blocked && !wasBlocked && conversationId) {
        localStorage.setItem(`dm_vis_start:${conversationId}`, new Date().toISOString());
        // Clear cached messages immediately
        queryClient.setQueryData(["messages", conversationId], []);
      }
    }).catch(() => {});
  }, [otherUserId, currentUser?.id]);

  // Track the visibility cutoff: after unblock, only show messages from after that point.
  // This uses a localStorage key per conversation so it survives page reloads.
  const getVisibilityStart = () => {
    try {
      const raw = localStorage.getItem(`dm_vis_start:${conversationId}`);
      return raw || null;
    } catch { return null; }
  };

  const { data: messages = [], refetch, isFetched: messagesFetched } = useQuery({
    queryKey: ["messages", conversationId],
    queryFn: async () => {
      // If blocked, return empty — no messages should be visible
      if (isBlocked) return [];
      const msgs = await base44.entities.Message.filter({ conversation_id: conversationId }, "-created_date", 60);
      const reversed = msgs.slice().reverse();
      // Apply visibility cutoff: after unblock, only show messages from after the cutoff
      const visStart = getVisibilityStart();
      if (visStart) {
        const cutoff = new Date(visStart).getTime();
        return reversed.filter(m => new Date(m.created_date).getTime() >= cutoff);
      }
      return reversed;
    },
    enabled: !!conversationId,
    staleTime: 30 * 1000,
    gcTime: 5 * 60 * 1000,
    refetchInterval: isBlocked ? false : 8000, // Don't poll if blocked
  });

  useEffect(() => {
    if (messages.length > 0) {
      const el = msgScrollRef.current;
      if (el) {
        const dist = el.scrollHeight - el.scrollTop - el.clientHeight;
        if (dist < 120) bottomRef.current?.scrollIntoView({ behavior: "smooth" });
      } else {
        bottomRef.current?.scrollIntoView({ behavior: "smooth" });
      }
    }
  }, [messages.length]);

  // Mark all unread messages as read when chat is opened
  // CRITICAL: Also invalidate unread-message-counts so the DM badge clears immediately
  useEffect(() => {
    if (!currentUser || !otherUserId) return;
    base44.entities.Message.filter({ recipient_id: currentUser.id, sender_id: otherUserId, is_read: false })
      .then(unreadMsgs => {
        if (unreadMsgs.length > 0) {
          Promise.all(unreadMsgs.map(m => base44.entities.Message.update(m.id, { is_read: true })));
          // Invalidate all badge-related queries so counts update immediately
          queryClient.invalidateQueries({ queryKey: ["unread-messages"] });
          queryClient.invalidateQueries({ queryKey: ["unread-message-counts"] });
        }
      });
  }, [otherUserId, currentUser?.id]);

  // Load reactions — deferred 1s so it never blocks initial message render.
  // Only loads reactions for the last 20 messages (reactions on old messages are rare).
  const msgIdsKey = messages.map(m => m.id).join(',');
  useEffect(() => {
    if (!messages.length) return;
    let cancelled = false;
    const timer = setTimeout(async () => {
      if (cancelled) return;
      try {
        const recentMsgIds = messages.slice(-20).map(m => m.id);
        const allRaw = await Promise.all(
          recentMsgIds.map(id => base44.entities.MessageReaction.filter({ message_id: id }).catch(() => []))
        );
        if (cancelled) return;
        const newMap = {};
        allRaw.forEach((reactions, idx) => {
          if (reactions.length > 0) {
            const grouped = {};
            reactions.forEach(r => {
              if (!grouped[r.emoji]) grouped[r.emoji] = [];
              grouped[r.emoji].push(r.user_id);
            });
            newMap[recentMsgIds[idx]] = grouped;
          }
        });
        setReactionsMap(newMap);
      } catch {}
    }, 1000);
    return () => { cancelled = true; clearTimeout(timer); };
  }, [msgIdsKey]);

  // Real-time reaction subscription — separate effect so cleanup works correctly
  useEffect(() => {
    if (!messages.length) return;
    const msgIds = new Set(messages.map(m => m.id));
    const unsub = base44.entities.MessageReaction.subscribe(event => {
      if (event.data?.message_id && msgIds.has(event.data.message_id)) {
        base44.entities.MessageReaction.filter({ message_id: event.data.message_id })
          .then(reactions => {
            const grouped = {};
            reactions.forEach(r => {
              if (!grouped[r.emoji]) grouped[r.emoji] = [];
              grouped[r.emoji].push(r.user_id);
            });
            setReactionsMap(prev => ({ ...prev, [event.data.message_id]: grouped }));
          }).catch(() => {});
      }
    });
    return () => unsub();
  }, [msgIdsKey]);

  // Auto-mark new messages as read when they arrive while chat is open
  useEffect(() => {
    if (messages.length > 0 && currentUser) {
      const unreadIds = messages.filter(m => m.recipient_id === currentUser.id && !m.is_read).map(m => m.id);
      if (unreadIds.length > 0) {
        Promise.all(unreadIds.map(id => base44.entities.Message.update(id, { is_read: true })));
        // Invalidate badge counts so unread DM badge clears immediately across app
        queryClient.invalidateQueries({ queryKey: ["unread-message-counts"] });
        queryClient.invalidateQueries({ queryKey: ["unread-messages"] });
      }
    }
  }, [messages, currentUser]);

  // DM RATE LIMITER: max 2 messages per second per conversation
  const checkSendRateLimit = () => {
    const now = Date.now();
    const timestamps = sendTimestampsRef.current;
    // Remove entries older than 1 second
    sendTimestampsRef.current = timestamps.filter(t => now - t < 1000);
    if (sendTimestampsRef.current.length >= 2) {
      return false; // rate limited
    }
    sendTimestampsRef.current.push(now);
    return true;
  };

  const handleSend = async () => {
    if (!messageText.trim() || !currentUser || !otherUserId || sending) return;
    if (!checkSendRateLimit()) {
      setSendError('Slow down! Max 2 messages per second.');
      setTimeout(() => setSendError(''), 2000);
      return;
    }
    if (isBlocked) {
      setSendError("You can't send messages to this user.");
      setTimeout(() => setSendError(""), 5000);
      return;
    }
    setSending(true);
    const body = messageText.trim();
    const capturedReplyTo = replyTo;
    // BLOCKER 5 FIX: Optimistic bubble appears instantly before any network call
    const optimisticId = `optimistic_${Date.now()}`;
    const optimisticMsg = {
      id: optimisticId,
      sender_id: currentUser.id,
      sender_name: currentUser.display_name || currentUser.full_name || '',
      sender_avatar: currentUser.avatar_url || '',
      recipient_id: otherUserId,
      conversation_id: conversationId,
      content: body,
      media_url: null,
      reply_to_id: capturedReplyTo?.id || null,
      is_read: false,
      is_edited: false,
      created_date: new Date().toISOString(),
    };
    queryClient.setQueryData(["messages", conversationId], (old = []) => [...old, optimisticMsg]);
    setTimeout(() => bottomRef.current?.scrollIntoView({ behavior: 'smooth' }), 30);
    // Clear input immediately
    setMessageText("");
    setReplyTo(null);
    try {
      await base44.functions.invoke('sendDirectMessage', {
        recipient_id: otherUserId,
        content: body,
        reply_to_id: capturedReplyTo?.id || null,
      });
      // Replace optimistic with real persisted messages
      refetch();
      queryClient.invalidateQueries({ queryKey: ["direct-convs-a"] });
      queryClient.invalidateQueries({ queryKey: ["direct-convs-b"] });
      // Fire mention notifications (non-blocking)
      base44.functions.invoke('sendMentionNotifications', {
        content: body,
        context_type: 'dm',
        context_id: conversationId,
      }).catch(() => {});
    } catch (err) {
      // Remove optimistic message and restore text so user doesn't lose it
      queryClient.setQueryData(["messages", conversationId], (old = []) =>
        old.filter(m => m.id !== optimisticId)
      );
      setMessageText(body);
      // Show user-facing error for block and other failures
      const status = err?.response?.status;
      const serverMsg = err?.response?.data?.error;
      if (status === 403) {
        setSendError(serverMsg || "You can't message this user.");
        setIsBlocked(true); // update UI state so composer hides
      } else {
        setSendError(serverMsg || "Failed to send message. Please try again.");
      }
      setTimeout(() => setSendError(""), 5000);
      console.error('[Messages] sendDirectMessage failed:', err?.message || err);
    } finally {
      setSending(false);
    }
  };

  const handleSendMedia = async (media) => {
    if (!currentUser || !otherUserId) return;
    if (isBlocked) {
      setSendError("You can't send messages to this user.");
      setTimeout(() => setSendError(""), 5000);
      return;
    }

    // Optimistic insert — message appears instantly before backend confirms
    const optimisticMsg = {
      id: `optimistic_${Date.now()}`,
      sender_id: currentUser.id,
      sender_name: currentUser.display_name || currentUser.full_name || '',
      sender_avatar: currentUser.avatar_url || '',
      recipient_id: otherUserId,
      conversation_id: conversationId,
      content: '',
      media_url: media.media_url,
      media_type: media.type || 'gif',
      is_media: true,
      is_read: false,
      created_date: new Date().toISOString(),
    };
    queryClient.setQueryData(["messages", conversationId], (old = []) => [...old, optimisticMsg]);
    // Scroll to bottom immediately
    setTimeout(() => bottomRef.current?.scrollIntoView({ behavior: 'smooth' }), 50);

    try {
      await base44.functions.invoke('sendDirectMessage', {
        recipient_id: otherUserId,
        content: '',
        media_url: media.media_url,
        media_type: media.type || 'gif',
        is_media: true,
      });
      // Refetch only AFTER backend confirms — removes optimistic msg, replaces with real persisted msg
      await refetch();
    } catch (err) {
      queryClient.setQueryData(["messages", conversationId], (old = []) =>
        old.filter(m => !String(m.id).startsWith('optimistic_'))
      );
      const status = err?.response?.status;
      if (status === 403) {
        setSendError("You can't send messages to this user.");
        setIsBlocked(true);
      } else {
        setSendError("Failed to send. Please try again.");
      }
      setTimeout(() => setSendError(""), 5000);
    } finally {
      queryClient.invalidateQueries({ queryKey: ["direct-convs-a"] });
      queryClient.invalidateQueries({ queryKey: ["direct-convs-b"] });
    }
  };

  const handleDeleteMsg = async (msgId, mode) => {
    setContextMenu(null);
    setDeleteConfirm(null);
    // Optimistic removal so date separators recompute immediately
    queryClient.setQueryData(["messages", conversationId], (old = []) =>
      old.map(m => {
        if (m.id !== msgId) return m;
        if (mode === 'for_me') return currentUser && m.sender_id === currentUser.id
          ? { ...m, deleted_for_sender: true }
          : { ...m, deleted_for_recipient: true };
        if (mode === 'for_all') return { ...m, deleted_for_sender: true, deleted_for_recipient: true };
        return m;
      })
    );
    await base44.functions.invoke('deleteDirectMessage', { message_id: msgId, mode });
    refetch();
    queryClient.invalidateQueries({ queryKey: ["all-messages"] });
  };

  const confirmDelete = (msgId, mode) => {
    const labels = {
      for_me: { title: 'Delete for you only?', body: 'This message will be removed from your view only.', btn: 'Delete for me' },
      for_all: { title: 'Delete for everyone?', body: 'This message will be permanently deleted for both sides.', btn: 'Delete for everyone' },
    };
    setDeleteConfirm({ msgId, mode, ...(labels[mode] || labels.for_me) });
    setContextMenu(null);
  };

  const handleEditMsgSave = async (msgId) => {
    if (!editMsgText.trim()) return;
    await base44.functions.invoke('editDirectMessage', { message_id: msgId, content: editMsgText.trim() });
    setEditingMsgId(null);
    setEditMsgText('');
    refetch();
  };

  const updatePref = (update) => {
    const current = getConvPrefs();
    const next = { ...current, [conversationId]: { ...(current[conversationId] || {}), ...update } };
    setConvPrefsStore(next);
    setPrefs(next);
  };

  // Long press logic for messages
  const startLongPress = (msgId, e) => {
    didLongPressRef.current = false;
    const touch = e.touches?.[0] || e;
    const x = touch.clientX || 0;
    const y = touch.clientY || 0;
    longPressTimerRef.current = setTimeout(() => {
      didLongPressRef.current = true;
      setContextMenu({ msgId, x, y });
      setMenuReadyAt(Date.now() + 350); // menu buttons not clickable for 350ms
    }, 500);
  };

  const cancelLongPress = (e) => {
    if (longPressTimerRef.current) clearTimeout(longPressTimerRef.current);
    // If long press fired, suppress the touchend from triggering any button
    if (didLongPressRef.current && e?.type === 'touchend') {
      e.preventDefault();
      e.stopPropagation();
      didLongPressRef.current = false;
    }
  };

  const isMenuReady = () => Date.now() >= menuReadyAt;

  // Build message lookup map for reply previews
  const msgMap = {};
  messages.forEach(m => { msgMap[m.id] = m; });

  // Group messages by date — ONLY include visible (non-deleted) messages so separators auto-disappear
  const groupedMessages = [];
  let lastDate = null;
  const visibleMessages = messages.filter(msg => {
    const isMineLocal = msg.sender_id === currentUser?.id;
    if (isMineLocal && msg.deleted_for_sender) return false;
    if (!isMineLocal && msg.deleted_for_recipient) return false;
    return true;
  });
  visibleMessages.forEach(msg => {
    const rawDate = msg.created_date || msg.created_at;
    const d = rawDate ? new Date(rawDate) : new Date();
    const dateKey = format(d, "yyyy-MM-dd");
    if (dateKey !== lastDate) {
      lastDate = dateKey;
      groupedMessages.push({ type: 'date', date: d, key: dateKey });
    }
    groupedMessages.push({ type: 'msg', msg, msgDate: d });
  });

  if (!otherUserId) {
    return <div className="h-screen bg-slate-50 flex items-center justify-center"><div className="w-8 h-8 border-2 border-slate-200 border-t-indigo-500 rounded-full animate-spin" /></div>;
  }

  const safeOtherUser = otherUser || { id: otherUserId, display_name: null, full_name: null, avatar_url: null };

  return (
    <div
      className="fixed inset-0 bg-slate-50 flex flex-col overflow-hidden"
      onClick={() => setContextMenu(null)}
    >
      {/* ── HEADER ── */}
      <div className="bg-white/95 backdrop-blur-lg border-b border-slate-100 z-10 flex-shrink-0">
        <div className="flex items-center gap-3 px-4 py-3">
          <Link to={createPageUrl("ChatList")}>
            <button className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center flex-shrink-0">
              <ArrowLeft className="w-5 h-5 text-slate-600" />
            </button>
          </Link>
          <button
            onClick={() => {
              if (safeOtherUser?.id) {
                const name = encodeURIComponent(resolvedOtherName || "");
                const avatar = encodeURIComponent(safeOtherUser.avatar_url || "");
                window.location.href = createPageUrl("UserProfile") + `?userId=${safeOtherUser.id}&recipientName=${name}&recipientAvatar=${avatar}`;
              }
            }}
            className="hover:opacity-80 transition-opacity flex-shrink-0"
          >
            <Avatar
              name={resolvedOtherName}
              avatarUrl={safeOtherUser.avatar_url}
              size={9}
              loading={false}
            />
          </button>
          <button
            onClick={() => {
              if (safeOtherUser?.id) {
                window.location.href = createPageUrl("UserProfile") + `?userId=${safeOtherUser.id}`;
              }
            }}
            className="flex-1 min-w-0 text-left hover:opacity-80 transition-opacity"
          >
            {displayName ? (
              <p className="text-base font-bold text-slate-900 truncate leading-tight">
                {displayName}
                {convPrefs.pinned && <span className="ml-1.5 text-xs text-amber-500">📌</span>}
              </p>
            ) : (
              /* Never show infinite skeleton — show "Chat" as temporary label until name resolves */
              <p className="text-base font-bold text-slate-400 truncate leading-tight">Chat</p>
            )}
            {convPrefs.nickname && resolvedOtherName && <p className="text-[11px] text-slate-400 truncate">{resolvedOtherName}</p>}
          </button>
          {/* Top-right action button — premium custom icon */}
          <button
            onClick={() => setShowActionPanel(true)}
            className="w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 transition-all active:scale-90"
            style={{ background: 'linear-gradient(135deg, #e0e7ff 0%, #ede9fe 100%)', border: '1px solid rgba(99,102,241,0.15)' }}
            data-icon-only
          >
            <Settings2 className="w-[18px] h-[18px] text-indigo-500" />
          </button>
        </div>
      </div>

      {/* ── MESSAGES ── */}
      <div
        ref={msgScrollRef}
        className="flex-1 overflow-y-auto overflow-x-hidden px-4 py-3 w-full relative"
        onClick={() => setContextMenu(null)}
        onScroll={(e) => {
          const el = e.currentTarget;
          setShowScrollBtn(el.scrollHeight - el.scrollTop - el.clientHeight > 80);
        }}
      >
        {/* C2 FIX: Never show empty-state until query has actually resolved.
            Before messagesFetched, show skeleton so no false "start a conversation" flash. */}
        {!messagesFetched ? (
          <div className="flex flex-col gap-3 p-2 pt-4">
            {[1,2,3,4].map(i => (
              <div key={i} className={`flex gap-2 ${i % 2 === 0 ? 'justify-end' : 'justify-start'}`}>
                {i % 2 !== 0 && <div className="w-7 h-7 rounded-full bg-slate-200 animate-pulse flex-shrink-0" />}
                <div className={`h-10 rounded-2xl animate-pulse bg-slate-200 ${i % 2 === 0 ? 'w-36' : 'w-52'}`} />
              </div>
            ))}
          </div>
        ) : messages.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full text-center">
            <div className="w-16 h-16 rounded-full bg-gradient-to-br from-indigo-100 to-purple-100 flex items-center justify-center mb-4">
              <svg width="28" height="28" viewBox="0 0 28 28" fill="none"><path d="M4 6C4 4.9 4.9 4 6 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H8l-4 4V6z" fill="#6366f1" fillOpacity=".18" stroke="#6366f1" strokeWidth="1.5" strokeLinejoin="round"/></svg>
            </div>
            <p className="text-sm font-semibold text-slate-700 mb-1">Start a conversation</p>
            <p className="text-xs text-slate-400">Say hi to {displayName}!</p>
          </div>
        ) : (
          <div className="space-y-0.5">
            {groupedMessages.map((item) => {
            if (item.type === 'date') {
            const label = isToday(item.date) ? 'Today' : isYesterday(item.date) ? 'Yesterday' : format(item.date, "MMMM d");
            return (
              <div key={item.key} className="flex items-center justify-center py-3">
                <span className="text-[11px] font-semibold text-slate-400 bg-slate-100 px-3 py-1 rounded-full">{label}</span>
              </div>
            );
            }

            const { msg, msgDate } = item;
            const isMine = msg.sender_id === currentUser?.id;
            if (isMine && msg.deleted_for_sender) return null;
            if (!isMine && msg.deleted_for_recipient) return null;

            const timeStr = msgDate ? format(msgDate, "h:mm a") : "";
            const isMedia = !!(msg.media_url);

            // Find original message if this is a reply
            const repliedMsg = msg.reply_to_id ? msgMap[msg.reply_to_id] : null;

            return (
            <SwipeableMessage
              key={msg.id}
              msg={msg}
              isMine={isMine}
              onSwipeReply={() => setReplyTo({ id: msg.id, content: msg.content, senderName: isMine ? 'You' : (safeOtherUser.display_name || 'Them') })}
            >
                  {!isMine && (
                    <Avatar name={safeOtherUser.display_name || safeOtherUser.full_name || msg.sender_name} avatarUrl={safeOtherUser.avatar_url || msg.sender_avatar} size={7} />
                  )}

                  <div className="relative min-w-[100px] max-w-[280px] sm:max-w-[400px]" onClick={e => { if (didLongPressRef.current) e.stopPropagation(); }}>
                    {editingMsgId === msg.id ? (
                      <div className="flex items-center gap-1 bg-white border border-indigo-200 rounded-2xl px-3 py-2 shadow-sm">
                        <input
                          autoFocus
                          value={editMsgText}
                          onChange={e => setEditMsgText(e.target.value)}
                          onKeyDown={e => { if (e.key === 'Enter') handleEditMsgSave(msg.id); if (e.key === 'Escape') setEditingMsgId(null); }}
                          className="flex-1 text-sm outline-none bg-transparent text-slate-900"
                        />
                        <button onClick={() => handleEditMsgSave(msg.id)} className="w-6 h-6 rounded-full bg-indigo-600 flex items-center justify-center flex-shrink-0">
                          <Check className="w-3 h-3 text-white" />
                        </button>
                        <button onClick={() => setEditingMsgId(null)} className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center flex-shrink-0">
                          <X className="w-3 h-3 text-slate-600" />
                        </button>
                      </div>
                    ) : (
                      <div
                        onTouchStart={(e) => startLongPress(msg.id, e)}
                        onTouchEnd={(e) => cancelLongPress(e)}
                        onTouchMove={(e) => { cancelLongPress(e); }}
                        onMouseDown={(e) => { if (e.button !== 0) return; startLongPress(msg.id, e); }}
                        onMouseUp={(e) => cancelLongPress(e)}
                        onMouseLeave={(e) => cancelLongPress(e)}
                        onContextMenu={(e) => { e.preventDefault(); e.stopPropagation(); }}
                      >
                        {/* Reply preview bubble */}
                        {repliedMsg && (
                          <div className={cn("mb-0.5 px-3 py-1.5 rounded-xl opacity-70 border-l-4 text-xs break-words max-w-[200px]", isMine ? "bg-indigo-500 text-indigo-100 border-indigo-300 ml-auto" : "bg-slate-200 text-slate-600 border-slate-400")}>
                            <p className="font-semibold text-[10px] mb-0.5">{repliedMsg.sender_id === currentUser?.id ? 'You' : safeOtherUser.display_name || 'Them'}</p>
                            <p className="line-clamp-1 break-words">{repliedMsg.content}</p>
                          </div>
                        )}

                        {/* Group share card — special rendering for [group_share:ID] messages */}
                        {msg.content?.startsWith('[group_share:') ? (() => {
                          const sharedGroupId = msg.content.match(/\[group_share:([^\]]+)\]/)?.[1];
                          if (!sharedGroupId) return null;
                          return (
                            <button
                              onClick={() => { window.location.href = createPageUrl('GroupDetail') + `?id=${sharedGroupId}`; }}
                              className={cn(
                                "rounded-2xl overflow-hidden border transition-all active:scale-98 text-left",
                                isMine ? "border-emerald-300 bg-emerald-50" : "border-slate-200 bg-white"
                              )}
                              style={{ minWidth: 200, maxWidth: 240 }}
                            >
                              <div className="p-3 flex items-center gap-2.5">
                                <div className="w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 text-lg"
                                  style={{ background: msg.meta_group_color ? `${msg.meta_group_color}22` : '#e0f2fe' }}>
                                  {msg.meta_group_emoji || <Users className="w-5 h-5 text-emerald-600" />}
                                </div>
                                <div className="flex-1 min-w-0">
                                  <p className="text-sm font-bold text-slate-900 truncate">{msg.meta_group_name || 'Group'}</p>
                                  <p className="text-[10px] text-emerald-600 font-semibold">Tap to open group →</p>
                                </div>
                              </div>
                              <div className="px-3 pb-2 flex items-center gap-1">
                                <span className="text-[9px] font-bold text-emerald-600 bg-emerald-100 px-1.5 py-0.5 rounded-full">Group</span>
                              </div>
                            </button>
                          );
                        })()
                        : /* Shop share card — for [shop_share:ID] messages */
                        msg.content?.startsWith('[shop_share:') ? (() => {
                          const sharedShopId = msg.content.match(/\[shop_share:([^\]]+)\]/)?.[1];
                          if (!sharedShopId) return null;
                          const sharerName = isMine ? 'You' : (safeOtherUser.display_name || 'Someone');
                          return (
                            <ShopShareCard
                              shopId={sharedShopId}
                              metaName={msg.meta_shop_name}
                              metaLogo={msg.meta_shop_logo}
                              metaColor={msg.meta_shop_color}
                              sharerName={sharerName}
                              isMine={isMine}
                            />
                          );
                        })()
                        : /* Profile share card — lazy-loads user data when meta fields missing */
                        msg.content?.startsWith('[profile_share:') ? (() => {
                          const sharedUserId = msg.content.match(/\[profile_share:([^\]]+)\]/)?.[1];
                          if (!sharedUserId) return null;
                          const sharerName = isMine ? 'You' : (safeOtherUser.display_name || 'Someone');
                          return (
                            <ProfileShareCard
                              sharedUserId={sharedUserId}
                              metaName={msg.meta_user_name}
                              metaAvatar={msg.meta_user_avatar}
                              sharerName={sharerName}
                              isMine={isMine}
                            />
                          );
                        })() : isMedia ? (
                          <div
                            className={cn("rounded-2xl overflow-hidden group relative", isMine ? "rounded-br-md" : "rounded-bl-md")}
                            style={{ maxWidth: 220 }}
                            onContextMenu={e => { e.preventDefault(); e.stopPropagation(); }}
                            onDragStart={e => e.preventDefault()}
                          >
                            <img
                              src={msg.media_url}
                              alt="media"
                              draggable={false}
                              className="w-full object-cover"
                              style={{ WebkitTouchCallout: 'none', pointerEvents: 'none', userSelect: 'none', WebkitUserSelect: 'none' }}
                              onContextMenu={e => { e.preventDefault(); e.stopPropagation(); }}
                              onTouchStart={e => e.stopPropagation()}
                            />
                            {/* Reaction button overlay */}
                            <button
                              onClick={(e) => {
                                const rect = e.currentTarget.getBoundingClientRect();
                                setShowReactionMenu({ msgId: msg.id, x: rect.left, y: rect.top });
                              }}
                              className="absolute top-1 right-1 w-7 h-7 rounded-full bg-white/90 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                              title="Add reaction"
                            >
                              <SmilePlus className="w-4 h-4 text-slate-600" />
                            </button>
                          </div>
                        ) : (
                          <div
                            className={cn(
                              "rounded-2xl px-4 py-2 select-none group relative",
                              isMine ? "bg-indigo-600 text-white rounded-br-sm" : "bg-white text-slate-900 border border-slate-200 rounded-bl-sm"
                            )}
                            style={{ boxShadow: "0 1px 3px rgba(0,0,0,0.06)" }}
                          >
                            <MentionText text={msg.content} className="text-sm leading-snug break-words" />
                            <p className={cn("text-[10px] mt-1 inline-block ml-1", isMine ? "text-indigo-200" : "text-slate-400")}>
                              {timeStr}{msg.is_edited ? ' · edited' : ''}
                            </p>
                            {/* Reaction button overlay */}
                            <button
                              onClick={(e) => {
                                const rect = e.currentTarget.getBoundingClientRect();
                                setShowReactionMenu({ msgId: msg.id, x: rect.right - 20, y: rect.top - 40 });
                              }}
                              className={cn("absolute -top-3 -right-3 w-7 h-7 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity", isMine ? "bg-indigo-700 hover:bg-indigo-800" : "bg-white border border-slate-200 hover:bg-slate-50")}
                              title="Add reaction"
                            >
                              <SmilePlus className={cn("w-4 h-4", isMine ? "text-white" : "text-slate-600")} />
                            </button>
                          </div>
                        ) /* end isMedia ternary */ }

                        {/* Reactions row */}
                        {reactionsMap[msg.id] && Object.keys(reactionsMap[msg.id]).length > 0 && (
                          <div className="flex gap-1 mt-1 flex-wrap">
                            {Object.entries(reactionsMap[msg.id]).map(([emoji, userIds]) => (
                              <button
                                key={emoji}
                                onClick={() => setShowReactionsList(msg.id)}
                                className={cn(
                                  "px-2 py-1 rounded-full text-sm font-medium transition-all active:scale-95",
                                  userIds.some(uid => uid === currentUser?.id)
                                    ? "bg-indigo-100 text-indigo-700 border border-indigo-300"
                                    : "bg-slate-100 text-slate-700 border border-slate-200 hover:bg-slate-150"
                                )}
                              >
                                {emoji} {userIds.length}
                              </button>
                            ))}
                          </div>
                        )}
                      </div>
                    )}

                    {/* Context Menu — appears ABOVE message on long press */}
                    <AnimatePresence>
                      {contextMenu?.msgId === msg.id && (
                        <>
                          <div className="fixed inset-0 z-40" onClick={() => setContextMenu(null)} />
                          <motion.div
                            initial={{ opacity: 0, scale: 0.88, y: 6 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.88 }}
                            transition={{ type: 'spring', stiffness: 450, damping: 30 }}
                            className="fixed z-50 overflow-hidden"
                            style={{
                              left: Math.max(8, Math.min((contextMenu?.x || 200) - 110, window.innerWidth - 240)),
                              top: Math.max(80, Math.min((contextMenu?.y || 200) - 260, window.innerHeight - 280)),
                              background: 'rgba(255,255,255,0.97)',
                              backdropFilter: 'blur(20px)',
                              borderRadius: 16,
                              boxShadow: '0 8px 40px rgba(0,0,0,0.18)',
                              border: '1px solid rgba(0,0,0,0.07)',
                              minWidth: 200,
                            }}
                            onClick={e => e.stopPropagation()}
                          >
                            {/* Quick emoji reaction row */}
                            <div data-emoji-safe className="flex items-center gap-1 px-3 pt-3 pb-2" onContextMenu={e => e.preventDefault()}>
                              {['❤️','😂','😮','😢','🔥','👍'].map(emoji => (
                                <button
                                  key={emoji}
                                  onPointerUp={() => {
                                    if (!isMenuReady()) return;
                                    const msgId = contextMenu.msgId;
                                    setContextMenu(null);
                                    // Optimistic update
                                    setReactionsMap(prev => {
                                      const cur = JSON.parse(JSON.stringify(prev[msgId] || {}));
                                      Object.keys(cur).forEach(e => {
                                        cur[e] = (cur[e] || []).filter(uid => uid !== currentUser?.id);
                                        if (cur[e].length === 0) delete cur[e];
                                      });
                                      const wasSet = (prev[msgId]?.[emoji] || []).includes(currentUser?.id);
                                      if (!wasSet) cur[emoji] = [...(cur[emoji] || []), currentUser?.id];
                                      return { ...prev, [msgId]: cur };
                                    });
                                    base44.functions.invoke('messageReactionToggle', { message_id: msgId, emoji })
                                      .then(() => base44.entities.MessageReaction.filter({ message_id: msgId })
                                        .then(reactions => {
                                          const grouped = {};
                                          reactions.forEach(r => { if (!grouped[r.emoji]) grouped[r.emoji] = []; grouped[r.emoji].push(r.user_id); });
                                          setReactionsMap(prev => ({ ...prev, [msgId]: grouped }));
                                        }).catch(() => {})).catch(() => {});
                                  }}
                                  className="w-9 h-9 rounded-full hover:bg-slate-100 active:scale-90 transition-all flex items-center justify-center text-xl"
                                >
                                  {emoji}
                                </button>
                              ))}
                              <button
                                onPointerUp={() => {
                                  if (!isMenuReady()) return;
                                  // Open full emoji picker sheet directly
                                  setShowReactionMenu({ msgId: msg.id, x: 100, y: 200, openFull: true });
                                  setContextMenu(null);
                                }}
                                className="w-9 h-9 rounded-full hover:bg-slate-100 flex items-center justify-center"
                              >
                                <SmilePlus className="w-4 h-4 text-slate-400" />
                              </button>
                            </div>
                            <div className="border-t border-slate-100" />
                            <button
                              onPointerUp={() => { if (!isMenuReady()) return; setReplyTo({ id: msg.id, content: msg.content, senderName: isMine ? 'You' : (safeOtherUser.display_name || 'Them') }); setContextMenu(null); }}
                              className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 active:bg-slate-100 transition-colors border-t border-slate-50"
                            >
                              <Reply className="w-4 h-4 text-indigo-500" />
                              Reply
                            </button>
                            {isMine && !isMedia && (
                              <button
                                onPointerUp={() => { if (!isMenuReady()) return; setEditMsgText(msg.content); setEditingMsgId(msg.id); setContextMenu(null); }}
                                className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 active:bg-slate-100 transition-colors border-t border-slate-50"
                              >
                                <Pencil className="w-4 h-4 text-slate-400" />
                                Edit message
                              </button>
                            )}
                            {!isMedia && (
                              <button
                                onPointerUp={() => { if (!isMenuReady()) return; navigator.clipboard?.writeText(msg.content).catch(() => {}); setContextMenu(null); }}
                                className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-700 active:bg-slate-100 transition-colors border-t border-slate-50"
                              >
                                <Copy className="w-4 h-4 text-slate-400" />
                                Copy text
                              </button>
                            )}
                            <button
                              onPointerUp={() => { if (!isMenuReady()) return; confirmDelete(msg.id, 'for_me'); }}
                              className="w-full flex items-center gap-3 px-4 py-3 text-sm text-slate-600 active:bg-slate-100 transition-colors border-t border-slate-50"
                            >
                              <Trash2 className="w-4 h-4 text-slate-400" />
                              Delete for me
                            </button>
                            {isMine && (
                              <button
                                onPointerUp={() => { if (!isMenuReady()) return; confirmDelete(msg.id, 'for_all'); }}
                                className="w-full flex items-center gap-3 px-4 py-3 text-sm text-rose-500 active:bg-rose-50 transition-colors border-t border-slate-50"
                              >
                                <Trash2 className="w-4 h-4" />
                                Delete for everyone
                              </button>
                            )}
                          </motion.div>
                        </>
                        )}
                        </AnimatePresence>
                        </div>
                        </SwipeableMessage>
                        );
                        })}
                        </div>
        )}
        <div ref={bottomRef} />
        <ScrollToBottomButton
          visible={showScrollBtn}
          onClick={() => bottomRef.current?.scrollIntoView({ behavior: 'smooth' })}
        />
      </div>

      {/* ── REPLY BANNER ── */}
