                if (!wasAlreadySet) cur[emoji] = [...(cur[emoji] || []), currentUser?.id];
                return { ...prev, [msgId]: cur };
              });
              setTimeout(() => {
                base44.entities.MessageReaction.filter({ message_id: msgId })
                  .then(reactions => {
                    const grouped = {};
                    reactions.forEach(r => { if (!grouped[r.emoji]) grouped[r.emoji] = []; grouped[r.emoji].push(r.user_id); });
                    setReactionsMap(prev => ({ ...prev, [msgId]: grouped }));
                  }).catch(() => {});
              }, 300);
            }}
            onClose={() => setShowReactionMenu(null)}
          />
        )}
      </AnimatePresence>

      {/* Reaction emoji quick-bar (non-full mode) */}
      <AnimatePresence>
        {showReactionMenu && !showReactionMenu.openFull && (
          <>
            {/* Backdrop */}
            <div className="fixed inset-0 z-[94]" onClick={() => setShowReactionMenu(null)} />
            <div
              className="fixed z-[95]"
              style={{
                left: Math.max(8, Math.min((showReactionMenu.x || 100) - 130, window.innerWidth - 280)),
                top: Math.max(80, (showReactionMenu.y || 200) - 60),
              }}
            >
              <MessageReactionsMenu
                messageId={showReactionMenu.msgId}
                openFull={false}
                onReactionAdded={(emoji) => {
                  const msgId = showReactionMenu.msgId;
                  // Optimistic update — remove user's previous, add new
                  setReactionsMap(prev => {
                    const cur = JSON.parse(JSON.stringify(prev[msgId] || {}));
                    // Remove this user from any existing emoji (switch logic)
                    Object.keys(cur).forEach(e => {
                      cur[e] = (cur[e] || []).filter(uid => uid !== currentUser?.id);
                      if (cur[e].length === 0) delete cur[e];
                    });
                    // Check if it was same emoji toggle (remove) — backend already handled it
                    // For optimistic UI, add the emoji with this user
                    const wasAlreadySet = Object.keys(prev[msgId] || {}).some(e => e === emoji && (prev[msgId][e] || []).includes(currentUser?.id));
                    if (!wasAlreadySet) {
                      cur[emoji] = [...(cur[emoji] || []), currentUser?.id];
                    }
                    return { ...prev, [msgId]: cur };
                  });
                  // Reconcile with backend truth — normalize to {emoji: [user_id strings]}
                  setTimeout(() => {
                    base44.entities.MessageReaction.filter({ message_id: msgId })
                      .then(reactions => {
                        const grouped = {};
                        reactions.forEach(r => {
                          if (!grouped[r.emoji]) grouped[r.emoji] = [];
                          grouped[r.emoji].push(r.user_id);
                        });
                        setReactionsMap(prev => ({ ...prev, [msgId]: grouped }));
                      }).catch(() => {});
                  }, 300);
                }}
                onClose={() => setShowReactionMenu(null)}
              />
            </div>
          </>
        )}
      </AnimatePresence>

