              <div className="flex gap-3">
                <button onClick={() => setDeleteConfirm(null)} className="flex-1 h-11 rounded-2xl bg-slate-100 text-slate-700 font-semibold text-sm">Cancel</button>
                <button onClick={() => handleDeleteMsg(deleteConfirm.msgId, deleteConfirm.mode)} className="flex-1 h-11 rounded-2xl bg-rose-500 text-white font-semibold text-sm">{deleteConfirm.btn}</button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* ── FULL-PAGE DM ACTION PANEL ── */}
      <DMActionPanel
        isOpen={showActionPanel}
        onClose={() => setShowActionPanel(false)}
        otherUserId={otherUserId}
        otherUserName={resolvedOtherName}
        otherUserAvatar={safeOtherUser.avatar_url}
        conversationId={conversationId}
        convPrefs={convPrefs}
        onUpdatePref={updatePref}
        currentUserId={currentUser?.id}
      />
    </div>
  );
}

