// Bubble is always 180px wide, ~44px tall. Container is 100% width — we use px offsets.
// Max left = containerWidth(320) - bubbleWidth(180) = 140px safe zone.
// We work in px so it never clips off-screen.
const BUBBLE_W = 180;
const CONTAINER_H = 180;
const BUBBLE_H = 48;

function getRandomPos(lastPos) {
  // Use a fixed safe container width of 300px (fits any mobile screen with padding)
  const maxLeft = 300 - BUBBLE_W; // 120px
  const maxTop  = CONTAINER_H - BUBBLE_H - 4; // ~128px
  let left, top;
  for (let i = 0; i < 30; i++) {
    left = Math.floor(Math.random() * maxLeft);
    top  = Math.floor(Math.random() * maxTop);
    // Must be meaningfully different from last position
    if (!lastPos || Math.abs(left - lastPos.left) > 40 || Math.abs(top - lastPos.top) > 30) break;
  }
  return { left, top };
}

function SingleBubble({ text, pos }) {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.55, y: 16 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.8, y: -8, filter: "blur(4px)" }}
      transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
      className="absolute"
      style={{ left: pos.left, top: pos.top, width: BUBBLE_W }}
    >
      <div
        style={{
          fontSize: "12.5px",
          lineHeight: 1.45,
          fontWeight: 600,
          color: "#fff",
          whiteSpace: "normal",
          wordBreak: "keep-all",
          overflowWrap: "break-word",
          padding: "9px 13px 10px",
          background: "linear-gradient(135deg, rgba(255,255,255,0.18) 0%, rgba(255,255,255,0.09) 100%)",
          backdropFilter: "blur(22px)",
          WebkitBackdropFilter: "blur(22px)",
          border: "1px solid rgba(255,255,255,0.28)",
          borderRadius: "16px 16px 16px 4px",
          boxShadow: "0 8px 32px rgba(0,0,0,0.45), inset 0 1px 0 rgba(255,255,255,0.15)",
          position: "relative",
        }}
      >
        {text}
        {/* tail */}
        <span style={{
          position: "absolute", bottom: -8, left: 12,
          width: 0, height: 0,
          borderLeft: "8px solid transparent",
          borderRight: "4px solid transparent",
          borderTop: "8px solid rgba(255,255,255,0.2)",
        }} />
      </div>
    </motion.div>
  );
}

function ScatteredBubbles() {
  const msgIdxRef = React.useRef(1);
  const lastPosRef = React.useRef({ left: 0, top: 0 });
  const [bubble, setBubble] = React.useState(() => {
    const pos = getRandomPos(null);
    lastPosRef.current = pos;
    return { text: BUBBLES[0].text, pos, id: 0 };
  });

  React.useEffect(() => {
    let timer;
    const cycle = () => {
      timer = setTimeout(() => {
        const nextText = BUBBLES[msgIdxRef.current % BUBBLES.length].text;
        msgIdxRef.current++;
        const nextPos = getRandomPos(lastPosRef.current);
        lastPosRef.current = nextPos;
        setBubble(prev => ({ text: nextText, pos: nextPos, id: prev.id + 1 }));
        cycle();
      }, 2000);
    };
    cycle();
    return () => clearTimeout(timer);
  }, []);

  return (
    <div className="relative w-full" style={{ height: CONTAINER_H }}>
      <AnimatePresence mode="wait">
        <SingleBubble key={bubble.id} text={bubble.text} pos={bubble.pos} />
      </AnimatePresence>
    </div>
  );
}



