const REASON_LABELS = {
  missing_features:   { label: "Missing features",      emoji: "🔧", color: "bg-blue-50 text-blue-700 border-blue-200" },
  too_expensive:      { label: "Too expensive",          emoji: "💸", color: "bg-yellow-50 text-yellow-700 border-yellow-200" },
  not_useful:         { label: "Not useful",             emoji: "🤷", color: "bg-slate-50 text-slate-700 border-slate-200" },
  switching_app:      { label: "Switching app",          emoji: "🔄", color: "bg-indigo-50 text-indigo-700 border-indigo-200" },
  privacy_concerns:   { label: "Privacy concerns",       emoji: "🔒", color: "bg-purple-50 text-purple-700 border-purple-200" },
  technical_issues:   { label: "Technical issues",       emoji: "⚠️", color: "bg-orange-50 text-orange-700 border-orange-200" },
  other:              { label: "Other",                  emoji: "💬", color: "bg-rose-50 text-rose-700 border-rose-200" },
};

function ReasonBadge({ reason }) {
  const info = REASON_LABELS[reason] || { label: reason, emoji: "❓", color: "bg-slate-50 text-slate-600 border-slate-200" };
  return (
    <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold border ${info.color}`}>
      <span>{info.emoji}</span>
      {info.label}
    </span>
  );
}

function formatDate(iso) {
  if (!iso) return "—";
  return new Date(iso).toLocaleDateString(undefined, { month: "short", day: "numeric", year: "numeric", hour: "2-digit", minute: "2-digit" });
}

export default function AdminChurnReportsPage() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [reports, setReports] = useState([]);
  const [reportsLoading, setReportsLoading] = useState(false);

  useEffect(() => {
    base44.auth.me()
      .then(u => { setUser(u); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  useEffect(() => {
    if (!user || user.role !== "admin") return;
    setReportsLoading(true);
    base44.entities.ChurnFeedback.list("-created_date", 200)
      .then(data => { setReports(data); setReportsLoading(false); })
      .catch(() => setReportsLoading(false));
  }, [user]);

  // ── Auth gate ──────────────────────────────────────────────────────────────
  if (loading) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-slate-400" />
      </div>
    );
  }

  if (!user || user.role !== "admin") {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
        <div className="w-16 h-16 rounded-2xl bg-rose-100 flex items-center justify-center mb-4">
          <ShieldAlert className="w-8 h-8 text-rose-500" />
        </div>
        <h2 className="text-lg font-bold text-slate-900 mb-2">Access Denied</h2>
        <p className="text-sm text-slate-500 mb-6 max-w-xs leading-relaxed">
          This page is restricted to administrators only. You cannot access this area.
        </p>
        <button
          onClick={() => window.location.href = createPageUrl("Home")}
          className="h-11 px-6 rounded-2xl bg-slate-900 text-white font-semibold text-sm"
        >
          Go Home
        </button>
      </div>
    );
  }

  // ── Stats ──────────────────────────────────────────────────────────────────
  const total = reports.length;
  const skipped = reports.filter(r => r.skipped).length;
  const answered = total - skipped;

  const reasonCounts = {};
  reports.filter(r => !r.skipped && r.reason).forEach(r => {
    reasonCounts[r.reason] = (reasonCounts[r.reason] || 0) + 1;
  });
  const topReasons = Object.entries(reasonCounts).sort((a, b) => b[1] - a[1]);

  return (
    <div className="min-h-screen bg-slate-900 text-white pb-16">
      {/* Header */}
      <div className="sticky top-0 z-10 bg-slate-900/95 backdrop-blur-xl border-b border-white/10 px-5 py-4 flex items-center gap-3">
        <button onClick={() => window.history.back()} className="w-10 h-10 rounded-full bg-white/10 flex items-center justify-center hover:bg-white/15">
          <ArrowLeft className="w-5 h-5" />
        </button>
        <div className="flex-1">
          <h1 className="text-lg font-bold">Churn Reports</h1>
          <p className="text-xs text-slate-400">Why users deleted their accounts</p>
        </div>
        <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-rose-500/20 text-rose-300 text-xs font-bold">
          <ShieldAlert className="w-3.5 h-3.5" /> Admin Only
        </div>
      </div>

      <div className="max-w-3xl mx-auto px-5 pt-6 space-y-6">

        {/* Stats cards */}
        <div className="grid grid-cols-3 gap-3">
          {[
            { label: "Total deletions", value: total, icon: Users, color: "text-white" },
            { label: "Gave feedback", value: answered, icon: Users, color: "text-emerald-400" },
            { label: "Skipped survey", value: skipped, icon: SkipForward, color: "text-slate-400" },
          ].map((s, i) => (
            <div key={i} className="bg-white/5 border border-white/10 rounded-2xl p-4 text-center">
              <p className={`text-3xl font-black ${s.color}`}>{s.value}</p>
              <p className="text-[11px] text-slate-400 mt-1">{s.label}</p>
            </div>
          ))}
        </div>

        {/* Top reasons chart */}
        {topReasons.length > 0 && (
          <div className="bg-white/5 border border-white/10 rounded-2xl p-5">
            <h2 className="text-sm font-bold text-slate-300 uppercase tracking-wider mb-4">Top Reasons</h2>
            <div className="space-y-3">
              {topReasons.map(([reason, count]) => {
                const info = REASON_LABELS[reason] || { label: reason, emoji: "❓" };
                const pct = answered > 0 ? Math.round((count / answered) * 100) : 0;
                return (
                  <div key={reason}>
                    <div className="flex items-center justify-between mb-1">
                      <span className="text-sm text-slate-200 flex items-center gap-2">
                        <span>{info.emoji}</span> {info.label}
                      </span>
                      <span className="text-xs font-bold text-slate-400">{count} ({pct}%)</span>
                    </div>
                    <div className="w-full h-2 bg-white/10 rounded-full overflow-hidden">
                      <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${pct}%` }}
                        transition={{ duration: 0.8, delay: 0.2 }}
                        className="h-full rounded-full bg-rose-500"
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Individual responses */}
        <div>
          <h2 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4">
            All Responses ({total})
          </h2>

          {reportsLoading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="w-7 h-7 animate-spin text-slate-400" />
            </div>
          ) : reports.length === 0 ? (
            <div className="text-center py-12 text-slate-500">
              <p className="text-sm">No churn reports yet.</p>
            </div>
          ) : (
            <div className="space-y-3">
              {reports.map((r, i) => (
                <motion.div
                  key={r.id}
                  initial={{ opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.02 }}
                  className="bg-white/5 border border-white/10 rounded-2xl p-4"
                >
                  <div className="flex items-start justify-between gap-3">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1 flex-wrap">
                        {r.skipped ? (
                          <span className="text-xs text-slate-500 font-semibold flex items-center gap-1">
                            <SkipForward className="w-3.5 h-3.5" /> Skipped survey
                          </span>
                        ) : (
                          <ReasonBadge reason={r.reason} />
                        )}
                      </div>
                      {r.note && (
                        <p className="text-sm text-slate-300 mt-2 leading-relaxed italic">"{r.note}"</p>
                      )}
                      {r.user_email && (
                        <p className="text-[11px] text-slate-500 mt-2 font-mono">{r.user_email}</p>
                      )}
                    </div>
                    <div className="text-[10px] text-slate-500 flex-shrink-0 text-right">
                      {formatDate(r.created_date)}
                    </div>
                  </div>
                </motion.div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
