/**
 * QuantityNormalizationEngine.js
 * 
 * CORE NORMALIZATION LAYER
 * Transforms raw pantry item data into a strict canonical quantity model.
 * 
 * Every ingredient is normalized into:
 * - canonical_base_amount (source of truth for math)
 * - canonical_base_unit (source of truth for conversion)
 * - primary_display_unit (user's preferred UI unit)
 * - allowed_display_units (strict allowed conversions)
 * - conversion_metadata (ingredient-specific density, package info)
 */

import {
  classifyIngredientType,
  normalizeToCanonical,
  getCanonicalUnit,
  getAllowedDisplayUnits,
} from './QuantityConversionEngine';

/**
 * Normalize a raw PantryItem into the canonical quantity model.
 * 
 * Input: PantryItem from DB (may have old field names or incomplete data)
 * Output: Fully normalized quantity model ready for modal/display
 * 
 * STRICT INVARIANT:
 * The output canonical_base_amount is immutable source of truth.
 * All UI derives from this value, never the other way around.
 */
export function normalizePantryItemQuantity(item) {
  if (!item) {
    return null;
  }

  // ────────────────────────────────────────────────────────────────────────
  // STEP 1: Resolve canonical base amount (SOURCE OF TRUTH)
  // ────────────────────────────────────────────────────────────────────────

  let canonical_base_amount;
  let canonical_base_unit;

  // PHASE 5 FIX: VALIDATE CANONICAL FIELDS STRICTLY
  // Do not trust canonical_base_amount if it's zero/invalid while legacy quantity is positive
  const hasValidCanonical = (
    item.canonical_base_amount != null &&
    typeof item.canonical_base_amount === 'number' &&
    Number.isFinite(item.canonical_base_amount) &&
    item.canonical_base_amount > 0 &&
    item.canonical_base_unit
  );

  if (hasValidCanonical) {
    // CRITICAL: Always normalize to gram/ml base — never store kg or L as canonical unit
    if (item.canonical_base_unit === 'kg') {
      canonical_base_amount = item.canonical_base_amount * 1000;
      canonical_base_unit = 'g';
    } else if (item.canonical_base_unit === 'L') {
      canonical_base_amount = item.canonical_base_amount * 1000;
      canonical_base_unit = 'ml';
    } else {
      canonical_base_amount = item.canonical_base_amount;
      canonical_base_unit = item.canonical_base_unit;
    }
  } else {
    // Legacy data: compute from raw quantity + unit
    const rawAmount = item.quantity ?? item.canonical_base_amount ?? 0;
    // Normalize lowercase 'l' → 'L' for consistent lookup
    const rawUnit = (item.unit ?? item.canonical_base_unit ?? 'g').replace(/^l$/, 'L');
    const ingredientType = classifyIngredientType(item.category, rawUnit);

    // Normalize raw to canonical
    canonical_base_amount = normalizeToCanonical(
      rawAmount,
      rawUnit,
      ingredientType,
      item.container_base_quantity && item.container_base_unit
        ? {
            containerQuantity: item.container_base_quantity,
            containerUnit: item.container_base_unit,
          }
        : null
    );

    canonical_base_unit = getCanonicalUnit(ingredientType);
  }

  // Guard: canonical must be non-negative and finite
  if (
    typeof canonical_base_amount !== 'number' ||
    !Number.isFinite(canonical_base_amount) ||
    canonical_base_amount < 0
  ) {
    console.error('[QuantityNormalization] Invalid canonical_base_amount:', {
      itemName: item.name,
      itemId: item.id,
      canonical_base_amount,
    });
    canonical_base_amount = 0;
  }

  // ────────────────────────────────────────────────────────────────────────
  // STEP 2: Resolve primary display unit (user's preferred unit)
  // ────────────────────────────────────────────────────────────────────────

  let primary_display_unit;

  if (item.primary_display_unit) {
    // Explicitly set
    primary_display_unit = item.primary_display_unit;
  } else if (item.unit) {
    // Fallback to original raw unit as primary
    primary_display_unit = item.unit;
  } else {
    // Ultimate fallback to canonical base unit
    primary_display_unit = canonical_base_unit;
  }

  // ────────────────────────────────────────────────────────────────────────
  // STEP 3: Resolve allowed display units
  // ────────────────────────────────────────────────────────────────────────

  let allowed_display_units;

  if (item.allowed_display_units && Array.isArray(item.allowed_display_units)) {
    // Explicitly configured
    allowed_display_units = item.allowed_display_units;
  } else {
    // Derive from ingredient type
    const ingredientType = classifyIngredientType(item.category, primary_display_unit);
    allowed_display_units = getAllowedDisplayUnits(ingredientType);
  }

  // Ensure primary_display_unit is in allowed_display_units
  if (!allowed_display_units.includes(primary_display_unit)) {
    console.warn('[QuantityNormalization] primary_display_unit not in allowed list:', {
      itemName: item.name,
      primary_display_unit,
      allowed_display_units,
    });
    // Fallback: prepend primary to allowed if missing
    allowed_display_units = [primary_display_unit, ...allowed_display_units];
  }

  // ────────────────────────────────────────────────────────────────────────
  // STEP 4: Resolve conversion metadata
  // ────────────────────────────────────────────────────────────────────────

  const conversion_metadata = item.conversion_metadata ?? {};

  // ────────────────────────────────────────────────────────────────────────
  // STEP 5: Build normalized quantity model
  // ────────────────────────────────────────────────────────────────────────

  const normalized = {
    // ─── Top-level fields required by modal ───
    id: item.id,
    name: item.name,
    category: item.category,
    quantity: item.quantity,
    unit: item.unit,
    container_base_quantity: item.container_base_quantity,
    container_base_unit: item.container_base_unit,
    initial_quantity: item.initial_quantity,

    // ─── Immutable canonical truth ───
    canonical_base_amount,
    canonical_base_unit,

    // ─── Display preferences ───
    primary_display_unit,
    allowed_display_units,

    // ─── Conversion metadata ───
    conversion_metadata,

    // ─── UI state (initialized, not source of truth) ───
    selected_display_unit: primary_display_unit,
    selected_amount_base: canonical_base_amount,
  };

  // Dev logging: verify normalization
  if (typeof localStorage !== 'undefined' && localStorage.getItem('__debug_mode') === 'true') {
    console.log('[normalizePantryItemQuantity]', {
      itemName: item.name,
      rawQuantity: item.quantity,
      rawUnit: item.unit,
      canonical_base_amount,
      canonical_base_unit,
      primary_display_unit,
      allowed_display_units,
    });
  }

  return normalized;
}

/**
 * Validate that a normalized quantity model is valid.
 * 
 * Checks all invariants.
 * Returns { valid: boolean, errors: string[] }
 */
export function validateNormalizedQuantity(normalized) {
  const errors = [];

  if (!normalized) {
    errors.push('Normalized quantity is null or undefined');
    return { valid: false, errors };
  }

  // Check canonical_base_amount
  if (
    typeof normalized.canonical_base_amount !== 'number' ||
    !Number.isFinite(normalized.canonical_base_amount) ||
    normalized.canonical_base_amount < 0
  ) {
    errors.push(
      `canonical_base_amount is invalid: ${normalized.canonical_base_amount}`
    );
  }

  // Check canonical_base_unit
  if (!normalized.canonical_base_unit) {
    errors.push('canonical_base_unit is missing or empty');
  }

  // Check primary_display_unit
  if (!normalized.primary_display_unit) {
    errors.push('primary_display_unit is missing or empty');
  }

  // Check allowed_display_units
  if (
    !Array.isArray(normalized.allowed_display_units) ||
    normalized.allowed_display_units.length === 0
  ) {
    errors.push('allowed_display_units is not a non-empty array');
  }

  // Check primary is in allowed
  if (
    normalized.allowed_display_units &&
    !normalized.allowed_display_units.includes(normalized.primary_display_unit)
  ) {
    errors.push(
      `primary_display_unit "${normalized.primary_display_unit}" not in allowed list`
    );
  }

  // Check selected_display_unit
  if (
    normalized.allowed_display_units &&
    !normalized.allowed_display_units.includes(normalized.selected_display_unit)
  ) {
    errors.push(
      `selected_display_unit "${normalized.selected_display_unit}" not in allowed list`
    );
  }

  // Check selected_amount_base
  if (
    typeof normalized.selected_amount_base !== 'number' ||
    !Number.isFinite(normalized.selected_amount_base) ||
    normalized.selected_amount_base < 0 ||
    normalized.selected_amount_base > normalized.canonical_base_amount
  ) {
    errors.push(
      `selected_amount_base is invalid or exceeds canonical max: ${normalized.selected_amount_base} > ${normalized.canonical_base_amount}`
    );
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

/**
 * Hard assertion: panic if normalized quantity is invalid.
 * Used before rendering critical UIs.
 */
export function assertNormalizedQuantity(normalized, contextName = '') {
  const validation = validateNormalizedQuantity(normalized);
  if (!validation.valid) {
    const errorMsg = `[QuantityNormalization] Invalid quantity${
      contextName ? ` in ${contextName}` : ''
    }: ${validation.errors.join('; ')}`;
    console.error(errorMsg, normalized);
    throw new Error(errorMsg);
  }
}

/**
 * Reset selected state to 100% of pantry item.
 * Used on modal open.
 */
export function resetSelectedToFull(normalized) {
  return {
    ...normalized,
    selected_display_unit: normalized.primary_display_unit,
    selected_amount_base: normalized.canonical_base_amount,
  };
}

