          </div>
          <div className="relative z-10 flex-shrink-0" onClick={e => e.stopPropagation()}>
            <Switch
              checked={effectiveAllowMissing}
              disabled={promptActive}
              onCheckedChange={(val) => {
                if (promptActive) return;
                setAllowMissing(val);
                if (val) { setAllowMissingSweeping(true); setTimeout(() => setAllowMissingSweeping(false), 1200); }
              }}
            />
          </div>
        </div>
        {promptActive && (
          <div className="px-3.5 pb-2.5 -mt-0.5">
            <div className="px-2.5 py-1.5 rounded-lg" style={{ background: 'rgba(99,102,241,0.06)', border: '1px solid rgba(99,102,241,0.10)' }}>
              <p className="text-[9px] text-indigo-500 font-medium leading-relaxed">
                ✦ {t('generate.allow_missing_auto_note', 'With an active refinement prompt, missing ingredients required for your request are automatically allowed.')}
              </p>
            </div>
          </div>
        )}
      </Card>

      {/* ═══════════════════════════════════════════════════════════
          ▌ OPTIONAL PROMPT
          ═══════════════════════════════════════════════════════════ */}
      <Card delay={0.16} className="!p-3">
        <Label icon={Sparkles} text={t('generate.refinement_label', 'Recipe refinement (optional)')} />
        <input
          type="text"
          placeholder={t('generate.refinement_placeholder', 'e.g., "spicy and crispy", "creamy grilled"')}
          value={optionalPrompt}
          onChange={(e) => { setOptionalPrompt(e.target.value.slice(0, 120)); if (optionalPromptError) setOptionalPromptError(""); }}
          maxLength={120}
          onFocus={(e) => setTimeout(() => e.target.scrollIntoView({ behavior: 'smooth', block: 'center' }), 300)}
          className="w-full h-11 px-3.5 rounded-xl text-[12px] text-slate-700 placeholder:text-slate-400 focus:outline-none transition-all"
          style={{ background: '#f8fafc', border: '1.5px solid rgba(99,102,241,0.12)' }}
        />
        <div className="flex items-center justify-between mt-1.5">
          <p className="text-[9px] text-slate-400 font-medium">{optionalPrompt.length}/120 — {t('generate.refinement_hint', 'Taste, texture, cooking style, macro targets')}</p>
        </div>
        {optionalPromptError && (
          <p data-prompt-error className="text-[11px] font-semibold mt-1" style={{ color: "#ef4444" }}>{optionalPromptError}</p>
        )}
      </Card>

      {/* ═══════════════════════════════════════════════════════════
          ▌ GENERATE CTA
          ═══════════════════════════════════════════════════════════ */}
      <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.18, duration: 0.35 }}
        className="pt-0.5 pb-1"
      >
        <motion.div className="relative overflow-hidden rounded-2xl" whileTap={{ scale: 0.97 }}>
          {selectedIngredients.size >= 2 && !generating && (
            <div className="absolute -inset-[1.5px] rounded-[18px] z-0 opacity-40" style={{
              background: 'linear-gradient(135deg, #4f46e5, #7c3aed, #ec4899, #4f46e5)',
              backgroundSize: '300% 300%',
              animation: 'gradientShift 4s ease infinite',
            }} />
          )}
          <button
            onClick={() => {
              if (isLocked) return;
              // SYNCHRONOUS local lock — disables the button on this very tap,
              // before any async work runs. Parent's single-flight guard still
              // handles credit safety; this is purely visual.
              setTapped(true);
              // Fire instant tactile feedback (premium subtle effect).
              tap.fire();
              handleGenerate();
            }}
            disabled={isLocked}
            className="relative w-full h-[52px] rounded-2xl text-white font-extrabold text-[14px] disabled:opacity-40 disabled:cursor-not-allowed flex items-center justify-center gap-2 overflow-hidden z-10 transition-transform"
            style={{
              background: (generating || tapped)
                ? "linear-gradient(135deg,#4f46e5,#7c3aed)"
                : "linear-gradient(135deg,#312e81 0%,#4338ca 30%,#6366f1 60%,#7c3aed 100%)",
              boxShadow: selectedIngredients.size >= 2
                ? "0 6px 28px rgba(67,56,202,0.45), inset 0 1px 0 rgba(255,255,255,0.12)"
                : "none",
              letterSpacing: '0.01em',
              transform: tapped && !generating ? 'scale(0.97)' : 'scale(1)',
            }}
          >
            {!generating && !tapped && selectedIngredients.size >= 2 && <span className="absolute inset-0 pm-shimmer pointer-events-none" />}
            <span className="absolute inset-x-0 top-0 h-px bg-white/15 pointer-events-none" />
            <GenerateButtonTapEffect active={tap.active} />
            <span className="relative z-10 flex items-center gap-2">
              {(generating || tapped) ? (
                <InlineProgressLabel isLoading={true} progress={genProgress?.progress ?? 0} label={t('generate.creating_label', 'Creating')} />
              ) : (
                <><ChefHat className="w-[18px] h-[18px] drop-shadow-sm" />{t('generate.title', 'Generate Recipe')}</>
              )}
            </span>
          </button>
        </motion.div>
        {selectedIngredients.size < 2 && !generating && (
          <p className="text-center text-[10px] text-slate-400 mt-2 font-medium">{t('generate.select_min', 'Select at least 2 ingredients to generate')}</p>
        )}
      </motion.div>
    </div>
  );
}

/**
 * RecipeValidationEngine
 * 
 * Validates generated recipes to ensure they follow strict ingredient discipline:
 * - No unauthorized main ingredients when allow_missing=false
 * - Missing ingredients properly marked when allow_missing=true
 * - Instructions match ingredients
 * - Servings are valid
 * 
 * This is the authoritative validation layer before showing recipes to users.
 */

const ALLOWED_BASICS = [
  'water', 'salt', 'pepper', 'oil', 'olive oil', 'vegetable oil', 'butter',
  'salt and pepper', 'cooking oil', 'seasoning'
];

const MAJOR_INGREDIENT_KEYWORDS = [
  'meat', 'beef', 'pork', 'chicken', 'fish', 'salmon', 'tuna', 'shrimp',
  'poultry', 'cheese', 'egg', 'eggs', 'milk', 'cream', 'yogurt',
  'tofu', 'tempeh', 'legume', 'beans', 'lentils', 'rice', 'pasta',
  'bread', 'flour', 'grain', 'vegetable', 'fruit'
];

function isAllowedBasic(ingredientName) {
  const lower = (ingredientName || '').toLowerCase().trim();
  return ALLOWED_BASICS.some(b => lower.includes(b) || b.includes(lower));
}

function isMajorIngredient(ingredientName) {
  const lower = (ingredientName || '').toLowerCase().trim();
  return MAJOR_INGREDIENT_KEYWORDS.some(kw => lower.includes(kw));
}

function classifyIngredient(name, isOptional, isMissing, allowedNames) {
  const lower = (name || '').toLowerCase().trim();
  const isInAllowed = allowedNames.some(allowed => 
    lower.includes(allowed.toLowerCase()) || allowed.toLowerCase().includes(lower)
  );

  return {
    name,
    isUserProvided: isInAllowed && !isMissing,
    isAllowedBasic: isAllowedBasic(name),
    isAiAdded: isMissing,
    isMajor: isMajorIngredient(name),
    isOptional
  };
}

/**
 * Validate recipe against ingredient rules
 * Returns { valid: boolean, issues: string[], fixed: recipe }
 */
export function validateGeneratedRecipe(recipe, userIngredientNames, allowMissing) {
  const issues = [];

  // Validate servings
  if (!recipe.servings || recipe.servings < 1 || recipe.servings > 20) {
    issues.push(`Invalid servings: ${recipe.servings}. Must be 1-20.`);
    recipe.servings = Math.max(1, Math.min(20, recipe.servings || 2));
  }

  // Validate ingredients against rules
  const allIngredients = [];
  for (const group of recipe.ingredients || []) {
    for (const item of group.items || []) {
      allIngredients.push(item);
    }
  }

  let hasUnauthorizedMainIngredient = false;

  for (const item of allIngredients) {
    const classification = classifyIngredient(item.name, item.optional, item.missing, userIngredientNames);

    // If allow_missing is OFF, check for major unauthorized ingredients
    if (!allowMissing && classification.isMajor && !classification.isUserProvided && !classification.isAllowedBasic) {
      hasUnauthorizedMainIngredient = true;
      issues.push(
        `Unauthorized main ingredient "${item.name}" added without permission. ` +
        `Enable "Allow missing ingredients" to add items outside your pantry.`
      );
    }

    // Validate amounts
    if (!item.amount || item.amount.trim() === '') {
      issues.push(`Ingredient "${item.name}" has no amount specified.`);
      item.amount = '1 unit';
    }
  }

  // Check for empty ingredient groups
  recipe.ingredients = (recipe.ingredients || [])
    .map(g => ({
      ...g,
      items: (g.items || []).filter(i => i.name && i.name.trim())
    }))
    .filter(g => g.items.length > 0);

  if (recipe.ingredients.length === 0) {
    issues.push('Recipe has no valid ingredients.');
  }

  // Check for empty instructions
  if (!recipe.steps || recipe.steps.length === 0) {
    issues.push('Recipe has no instructions.');
    recipe.steps = [{ step_number: 1, instruction: 'Prepare and cook.', timer_minutes: 0 }];
  } else {
    recipe.steps = recipe.steps
      .filter(s => s.instruction && s.instruction.trim())
      .map((s, i) => ({
        ...s,
        step_number: i + 1,
        timer_minutes: Math.max(0, s.timer_minutes || 0)
      }));
  }

  // Check title
  if (!recipe.title || recipe.title.trim() === '') {
    issues.push('Recipe has no title.');
    recipe.title = 'Generated Recipe';
  }

  return {
    valid: issues.length === 0,
    issues,
    fixed: recipe
  };
}

/**
 * Strict validation for allow_missing=false
 * Ensures NO major ingredients are added that aren't in the user's pantry
 */
export function validateStrictIngredientDiscipline(recipe, userIngredientNames) {
  const issues = [];

  for (const group of recipe.ingredients || []) {
    for (const item of group.items || []) {
      const classification = classifyIngredient(item.name, item.optional, item.missing, userIngredientNames);

      // Major ingredients MUST be user-provided or allowed basics
      if (classification.isMajor && !classification.isUserProvided && !classification.isAllowedBasic) {
        issues.push(`Unauthorized major ingredient: "${item.name}"`);
      }
    }
  }

  return { disciplineValid: issues.length === 0, issues };
}

/**
 * dishIntentResolver.js — Pre-generation dish understanding layer
 *
 * Resolves user input into a structured dish intent BEFORE recipe generation.
 * Runs synchronously (< 1ms) — no LLM, no API call, no blocking.
 *
 * Usage:
 *   const intent = resolveDishIntent(userInput, language, cuisineHint);
 *   // intent.canonicalDish, intent.confidence, intent.requestMode, ...
 */

import { fuzzyMatchDish, lookupDish, STRICTNESS } from './culturalDishLibrary';

// ── REQUEST MODE DETECTION ──────────────────────────────────────────────────
// Detects what the user wants: authentic, healthy adaptation, pantry-based, etc.

const MODE_PATTERNS = {
  authentic:    /\b(authentic|traditional|classic|original|real|proper|genuine|legit)\b/i,
  healthy:      /\b(healthy|health|light|low.?cal|diet|clean|lean|fit)\b/i,
  high_protein: /\b(high.?protein|protein.?rich|protein.?packed|extra.?protein|more.?protein)\b/i,
  low_carb:     /\b(low.?carb|keto|no.?carb|carb.?free)\b/i,
  gluten_free:  /\b(gluten.?free|no.?gluten|celiac)\b/i,
  vegan:        /\b(vegan|plant.?based)\b/i,
  vegetarian:   /\b(vegetarian|veggie|meatless|no.?meat)\b/i,
  quick:        /\b(quick|fast|easy|simple|15.?min|20.?min|30.?min|weeknight)\b/i,
  inspired:     /\b(inspired|style|fusion|twist|modern|updated|remix)\b/i,
};

function detectRequestMode(input) {
  const text = (input || '').toLowerCase();
  for (const [mode, pattern] of Object.entries(MODE_PATTERNS)) {
    if (pattern.test(text)) return mode;
  }
  return 'default'; // no specific mode detected — use dish's default strictness
}

// ── LANGUAGE DETECTION (lightweight) ────────────────────────────────────────
// Detects if input is in a non-Latin script

function detectInputLanguage(input) {
  if (!input) return 'en';
  // Hebrew
  if (/[\u0590-\u05FF]/.test(input)) return 'he';
  // Arabic
  if (/[\u0600-\u06FF]/.test(input)) return 'ar';
  // CJK
  if (/[\u4E00-\u9FFF]/.test(input)) return 'zh';
  // Japanese
  if (/[\u3040-\u309F\u30A0-\u30FF]/.test(input)) return 'ja';
  // Korean
  if (/[\uAC00-\uD7AF]/.test(input)) return 'ko';
  // Thai
  if (/[\u0E00-\u0E7F]/.test(input)) return 'th';
  // Hindi/Devanagari
  if (/[\u0900-\u097F]/.test(input)) return 'hi';
  // Cyrillic
  if (/[\u0400-\u04FF]/.test(input)) return 'ru';
  return 'en';
}

// ── STRIP MODE WORDS FROM INPUT ─────────────────────────────────────────────
// Remove modifier words to get the pure dish name for matching

function stripModeWords(input) {
  return (input || '')
    .replace(/\b(authentic|traditional|classic|original|real|proper|genuine|legit)\b/gi, '')
    .replace(/\b(healthy|health|light|low.?cal|diet|clean|lean|fit)\b/gi, '')
    .replace(/\b(high.?protein|protein.?rich|extra.?protein|more.?protein)\b/gi, '')
    .replace(/\b(low.?carb|keto|no.?carb)\b/gi, '')
    .replace(/\b(gluten.?free|no.?gluten)\b/gi, '')
    .replace(/\b(vegan|plant.?based|vegetarian|veggie|meatless)\b/gi, '')
    .replace(/\b(quick|fast|easy|simple|weeknight)\b/gi, '')
    .replace(/\b(inspired|style|fusion|twist|modern|updated|remix)\b/gi, '')
    .replace(/\b(recipe|make|cook|prepare|homemade|home.?made)\b/gi, '')
    .replace(/\s+/g, ' ')
    .trim();
}

// ── MAIN: resolveDishIntent ─────────────────────────────────────────────────
/**
 * Resolves user input into a structured dish intent.
 * 
 * @param {string} userInput - the user's free-text prompt or dish request
 * @param {string} [uiLanguage='en'] - current UI language
 * @param {string} [cuisineHint=null] - cuisine selected in the generator UI
 * @returns {object} DishIntent
 */
export function resolveDishIntent(userInput, uiLanguage = 'en', cuisineHint = null) {
  const startTime = performance.now();

  const inputLang = detectInputLanguage(userInput);
  const requestMode = detectRequestMode(userInput);
  const cleanedInput = stripModeWords(userInput);

  // Try to match the cleaned input against the canonical dish library
  const match = fuzzyMatchDish(cleanedInput);
  // Also try the raw input (in case stripping removed important words)
  const rawMatch = fuzzyMatchDish(userInput);

  // Pick the higher-confidence match
  const bestMatch = (!match && !rawMatch) ? null
    : (!match) ? rawMatch
    : (!rawMatch) ? match
    : (rawMatch.score > match.score) ? rawMatch : match;

  const resolutionTimeMs = performance.now() - startTime;

  // No canonical dish found — return ungrounded intent
  if (!bestMatch || bestMatch.score < 0.35) {
    const result = {
      canonicalDishId: null,
      canonicalDishName: null,
      confidence: 0,
      cuisineOrigin: cuisineHint || null,
      requestMode,
      mustIncludeMarkers: [],
      mustAvoidMarkers: [],
      imageGroundingTags: [],
      localizedDisplayName: null,
      culturalNotes: null,
      variantPolicy: 'flexible',
      isCanonicalDish: false,
      _trace: {
        userInput,
        inputLanguage: inputLang,
        cleanedInput,
        matchResult: 'none',
        resolutionTimeMs: Math.round(resolutionTimeMs * 100) / 100,
      },
    };

    if (typeof console !== 'undefined') {
      console.log('[DISH_RESOLUTION_TRACE]', JSON.stringify(result._trace));
    }
    return result;
  }

  const dish = bestMatch.dish;

  // Determine variant policy based on request mode + dish strictness
  let variantPolicy = 'grounded'; // default for known dishes
  if (requestMode === 'authentic' || requestMode === 'default') {
    variantPolicy = dish.strictness === STRICTNESS.STRICT ? 'strict' : 'grounded';
  } else if (['healthy', 'high_protein', 'low_carb', 'gluten_free', 'vegan', 'vegetarian'].includes(requestMode)) {
    variantPolicy = 'adapted'; // allow changes but keep dish recognizable
  } else if (requestMode === 'inspired') {
    variantPolicy = 'flexible';
  }

  const result = {
    canonicalDishId: dish.id,
    canonicalDishName: dish.name,
    confidence: bestMatch.score,
    cuisineOrigin: dish.cuisine || cuisineHint,
    requestMode,
    mustIncludeMarkers: variantPolicy === 'strict' ? dish.coreMarkers : 
                        variantPolicy === 'adapted' ? dish.coreMarkers.slice(0, 2) : // keep top 2 identity markers even for adaptations
                        [],
    mustAvoidMarkers: variantPolicy !== 'flexible' ? dish.invalidSubstitutions : [],
    imageGroundingTags: dish.imageVisualTags || [],
    localizedDisplayName: dish.name, // could be extended with locale-specific names
    culturalNotes: `${dish.name} is a ${dish.category} from ${dish.region}. ${dish.textureNotes || ''}`,
    variantPolicy,
    isCanonicalDish: true,
    // Full dish data for downstream use
    _dishData: dish,
    _trace: {
      userInput,
      inputLanguage: inputLang,
      cleanedInput,
      matchResult: bestMatch.matchedOn,
      matchScore: bestMatch.score,
      canonicalDish: dish.name,
      cuisine: dish.cuisine,
      requestMode,
      variantPolicy,
      resolutionTimeMs: Math.round(resolutionTimeMs * 100) / 100,
    },
  };

  if (typeof console !== 'undefined') {
    console.log('[DISH_RESOLUTION_TRACE]', JSON.stringify(result._trace));
  }

  return result;
}

/**
 * Build a grounding prompt section for the LLM from a resolved dish intent.
 * This is injected into the recipe generation prompt.
 * Returns empty string if no grounding is needed.
 */
export function buildDishGroundingPrompt(intent) {
  if (!intent?.isCanonicalDish || intent.confidence < 0.5) return '';

  const dish = intent._dishData;
  if (!dish) return '';

  const lines = [];

  lines.push(`\n\nIMPORTANT — CULTURAL DISH GROUNDING:`);
  lines.push(`The user is requesting "${dish.name}" — a well-known ${dish.category} from ${dish.region}.`);

  if (intent.variantPolicy === 'strict' || intent.variantPolicy === 'grounded') {
    lines.push(`This dish has a specific traditional identity. The recipe MUST be recognizable as ${dish.name}.`);

    if (dish.coreMarkers?.length > 0) {
      lines.push(`CORE IDENTITY MARKERS (must include): ${dish.coreMarkers.join(', ')}`);
    }
    if (dish.validIngredients?.length > 0) {
      lines.push(`EXPECTED INGREDIENTS: ${dish.validIngredients.join(', ')}`);
    }
    if (dish.invalidSubstitutions?.length > 0) {
      lines.push(`IDENTITY VIOLATIONS (avoid these): ${dish.invalidSubstitutions.join('; ')}`);
    }
    if (dish.cookingMethod) {
      lines.push(`COOKING METHOD: ${dish.cookingMethod}`);
    }
    if (dish.textureNotes) {
      lines.push(`EXPECTED RESULT: ${dish.textureNotes}`);
    }

    lines.push(`The recipe title MUST contain "${dish.name}" or a close variation.`);
    lines.push(`Do NOT create a different dish. Stay true to ${dish.name}'s traditional identity.`);
  } else if (intent.variantPolicy === 'adapted') {
    lines.push(`The user wants a ${intent.requestMode} version of ${dish.name}.`);
    lines.push(`The dish should still be RECOGNIZABLE as ${dish.name} — keep the core identity.`);
    if (dish.coreMarkers?.length > 0) {
      lines.push(`Preserve these identity elements where possible: ${dish.coreMarkers.slice(0, 2).join(', ')}`);
    }
    lines.push(`Adapt ingredients to be ${intent.requestMode} while maintaining the dish's character.`);
    lines.push(`The title should indicate both the dish name and the adaptation.`);
  }
  // 'flexible' mode gets no grounding — let the LLM freestyle

  return lines.join('\n');
}

/**
 * Build image grounding context from dish intent.
 * Used to improve image prompt accuracy for known dishes.
 */
export function buildImageGroundingFromIntent(intent) {
  if (!intent?.isCanonicalDish || intent.confidence < 0.5) return null;

  const dish = intent._dishData;
  if (!dish) return null;

  return {
    dishName: dish.name,
    visualTags: dish.imageVisualTags || [],
    servingStyle: dish.servingStyle || '',
    textureNotes: dish.textureNotes || '',
    category: dish.category,
    cuisine: dish.cuisine,
    region: dish.region,
  };
}

/**
 * RecipeGenerationTriggerEngine.js
 *
 * Centralized post-generation decision engine.
 * Evaluates a finalised recipe and returns the correct AI assist trigger.
 *
 * Trigger priority (highest first):
 *   CLARIFICATION     — hard structural conflict, ambiguous request
 *   MISSING_STRUCTURE — pantry technically sufficient but dish is underdeveloped
 *   NUTRITION_GOAL    — macro target not met
 *   ENHANCE           — recipe is valid but could be notably improved
 *   NONE              — recipe is strong, no intervention needed
 *
 * Usage:
 *   import { resolveRecipeGenerationTriggers } from './RecipeGenerationTriggerEngine';
 *   const trigger = resolveRecipeGenerationTriggers(recipe, pantryItems, userInputs, macroGoals);
 *   // trigger.type: 'ENHANCE' | 'MISSING_STRUCTURE' | 'NUTRITION_GOAL' | 'CLARIFICATION' | 'NONE'
 */

// ── CONSTANTS ─────────────────────────────────────────────────────────────
export const TRIGGER_TYPE = {
  NONE:              'NONE',
  ENHANCE:           'ENHANCE',
  MISSING_STRUCTURE: 'MISSING_STRUCTURE',
  NUTRITION_GOAL:    'NUTRITION_GOAL',
  CLARIFICATION:     'CLARIFICATION',
};

// Protein density lookup (g protein per 100g ingredient)
const PROTEIN_DENSITIES = {
  chicken: 31, turkey: 29, salmon: 25, tuna: 30,
  beef: 26, pork: 27, shrimp: 24, tofu: 8,
  egg: 13, 'greek yogurt': 10, 'cottage cheese': 11,
  lentils: 9, chickpeas: 9, beans: 8,
};

function lookupProteinDensity(name) {
  const n = name.toLowerCase();
  for (const [key, density] of Object.entries(PROTEIN_DENSITIES)) {
    if (n.includes(key)) return density;
  }
  return 0;
}

// ── SCORING HELPERS ───────────────────────────────────────────────────────

/**
 * Score: structural completeness of the recipe [0–100]
 * Checks: has protein, has fat/sauce, has vegetables/aromatics, has seasoning
 */
function scoreStructure(recipe) {
  const ingredients = (recipe.ingredients || []).flatMap(g => (g.items || []).filter(i => !i.optional && !i.missing));
  if (ingredients.length === 0) return 0;

  let score = 0;

  // Protein presence
  const hasProtein = ingredients.some(i => lookupProteinDensity(i.name) > 15);
  if (hasProtein) score += 30;

  // Fat / sauce presence
  const hasFat = ingredients.some(i => /oil|butter|cream|sauce|marinade|mayo|yogurt|tahini/.test(i.name.toLowerCase()));
  if (hasFat) score += 20;

  // Vegetable / aromatic presence
  const hasVeg = ingredients.some(i => /garlic|onion|pepper|tomato|carrot|celery|herb|lemon|lime|ginger|scallion|parsley|cilantro|basil/.test(i.name.toLowerCase()));
  if (hasVeg) score += 20;

  // Seasoning variety (beyond just salt/pepper)
  const hasSeasonings = ingredients.some(i => /paprika|cumin|oregano|thyme|rosemary|chili|coriander|turmeric|curry/.test(i.name.toLowerCase()));
  if (hasSeasonings) score += 15;

  // Ingredient count adequacy (less than 3 non-invisible = underdeveloped)
  const visible = ingredients.filter(i => !/^(salt|pepper|water|oil)$/i.test(i.name.toLowerCase()));
  if (visible.length >= 4) score += 15;
  else if (visible.length >= 3) score += 7;

  return Math.min(100, score);
}

/**
 * Score: flavor balance [0–100]
 * Checks: acid, fat, heat/spice, umami, sweetness
 */
function scoreFlavor(recipe) {
  const ingredients = (recipe.ingredients || []).flatMap(g => (g.items || []).filter(i => !i.optional && !i.missing).map(i => i.name.toLowerCase()));
  if (ingredients.length === 0) return 0;

  let score = 0;
  const text = ingredients.join(' ');

  if (/lemon|lime|vinegar|tomato|yogurt/.test(text)) score += 20; // acid
  if (/oil|butter|cream|tahini|mayo|avocado/.test(text)) score += 20; // fat
  if (/chili|pepper|paprika|sriracha|jalapeño|cayenne/.test(text)) score += 15; // heat
  if (/garlic|onion|soy|miso|parmesan|mushroom|tomato/.test(text)) score += 20; // umami
  if (/honey|maple|sugar|sweet/.test(text)) score += 10; // sweetness
  if (/herb|basil|parsley|cilantro|thyme|mint|dill/.test(text)) score += 15; // freshness

  return Math.min(100, score);
}

/**
 * Score: visual confidence (how likely the image will match the recipe) [0–100]
 */
function scoreVisualConfidence(recipe) {
  // If title clearly matches a dish family, visual confidence is high
  const title = (recipe.title || '').toLowerCase();
  const CLEAR_DISHES = ['wings', 'pasta', 'salad', 'burger', 'steak', 'curry', 'soup', 'stew', 'rice', 'salmon', 'chicken', 'tacos', 'pizza', 'bowl'];
  const isClear = CLEAR_DISHES.some(d => title.includes(d));
  if (isClear) return 85;

  // Check description + ingredients to determine if dish type can be inferred
  const desc = (recipe.description || '').toLowerCase();
  const hasDishWord = CLEAR_DISHES.some(d => desc.includes(d));
  if (hasDishWord) return 70;

  return 50; // ambiguous — still OK but prompt engine will handle it
}

/**
 * Score: nutrition goal match [0–100] — only relevant if macroGoals are set
 */
function scoreNutritionGoalMatch(recipe, macroGoals) {
  if (!macroGoals || Object.keys(macroGoals).length === 0) return 100; // no goal = always satisfied

  const totalServings = recipe.servings || 1;
  const totalProtein = recipe.nutrition_total_for_recipe?.protein
    ?? ((recipe.nutrition_per_serving?.protein || recipe.nutrition?.protein || 0) * totalServings);
  const totalCalories = recipe.nutrition_total_for_recipe?.calories
    ?? ((recipe.nutrition_per_serving?.calories || recipe.nutrition?.calories || 0) * totalServings);

  let score = 100;

  if (macroGoals.protein) {
    const target = typeof macroGoals.protein === 'object' ? macroGoals.protein.min : macroGoals.protein;
    if (target > 0) {
      const ratio = totalProtein / target;
      if (ratio >= 0.95) score = Math.min(score, 100);
      else if (ratio >= 0.85) score = Math.min(score, 70);
      else if (ratio >= 0.70) score = Math.min(score, 40);
      else score = Math.min(score, 10);
    }
  }

  if (macroGoals.calories) {
    const maxCal = macroGoals.calories;
    if (totalCalories > maxCal * 1.1) score = Math.min(score, 50);
  }

  return score;
}

/**
 * Score: pantry completeness relative to recipe [0–100]
 */
function scorePantryCompleteness(recipe, pantryItems) {
  if (!pantryItems || pantryItems.length === 0) return 50;

  const pantryNames = pantryItems.map(p => p.name.toLowerCase());
  const recipeIngredients = (recipe.ingredients || [])
    .flatMap(g => (g.items || []).filter(i => !i.optional && !i.missing).map(i => i.name.toLowerCase()));

  if (recipeIngredients.length === 0) return 50;

  const matchCount = recipeIngredients.filter(ri =>
    pantryNames.some(pn => pn.includes(ri.split(' ')[0]) || ri.includes(pn.split(' ')[0]))
  ).length;

  return Math.round((matchCount / recipeIngredients.length) * 100);
}

// ── MAIN: resolveRecipeGenerationTriggers ────────────────────────────────
/**
 * Evaluates a finalised recipe and returns the most appropriate trigger.
 *
 * @param {object} recipe         - finalised recipe object
 * @param {object[]} pantryItems  - user's pantry items
 * @param {object} userInputs     - { optionalPrompt, allowMissing, nutritionPref }
 * @param {object} macroGoals     - parsed macro goals { protein?, calories?, carbs?, fat? }
 * @returns {object} trigger
 *   {
 *     type: TRIGGER_TYPE,
 *     reason: string,       // primary human-readable reason
 *     details: string[],    // supporting details
 *     scores: object,       // raw scores for debugging
 *     priority: number,     // 0 = lowest, 4 = highest
 *   }
 */
export function resolveRecipeGenerationTriggers(recipe, pantryItems, userInputs = {}, macroGoals = {}) {
  const { optionalPrompt = '', allowMissing = false } = userInputs;
  const hasUserPrompt = optionalPrompt.trim().length > 0;

  // ── COMPUTE SCORES ──────────────────────────────────────────────────────
  const structureScore = scoreStructure(recipe);
  const flavorScore = scoreFlavor(recipe);
  const visualScore = scoreVisualConfidence(recipe);
  const nutritionScore = scoreNutritionGoalMatch(recipe, macroGoals);
  const pantryScore = scorePantryCompleteness(recipe, pantryItems);

  const scores = { structureScore, flavorScore, visualScore, nutritionScore, pantryScore };

  // ── TRIGGER D: CLARIFICATION (priority 4 — highest) ────────────────────
  // Structural conflict: recipe is actually incoherent or has no valid dish type
  const ingredientCount = (recipe.ingredients || []).flatMap(g => g.items || []).filter(i => !i.optional && !i.missing).length;
  if (ingredientCount < 2) {
    return {
      type: TRIGGER_TYPE.CLARIFICATION,
      reason: 'Recipe has too few ingredients to be a complete dish',
      details: ['Consider selecting more pantry items or enabling Allow Missing'],
      scores,
      priority: 4,
    };
  }

  // ── TRIGGER C: NUTRITION GOAL (priority 3) ──────────────────────────────
  if (Object.keys(macroGoals).length > 0 && nutritionScore < 70) {
    const totalServings = recipe.servings || 1;
    const actualProtein = recipe.nutrition_total_for_recipe?.protein
      ?? ((recipe.nutrition_per_serving?.protein || recipe.nutrition?.protein || 0) * totalServings);
    const targetProtein = macroGoals.protein
      ? (typeof macroGoals.protein === 'object' ? macroGoals.protein.min : macroGoals.protein)
      : null;

    return {
      type: TRIGGER_TYPE.NUTRITION_GOAL,
      reason: `Nutrition target not fully met`,
      details: [
        targetProtein ? `Protein: ~${Math.round(actualProtein)}g vs ${targetProtein}g target` : null,
        'Try selecting additional protein-rich ingredients',
      ].filter(Boolean),
      scores,
      priority: 3,
    };
  }

  // ── TRIGGER B: MISSING STRUCTURE (priority 2) ───────────────────────────
  // Recipe is technically valid but underdeveloped (weak pantry, minimal structure)
  // Only trigger if user did NOT provide a specific prompt (they already guided it)
  const isUnderdeveloped = structureScore < 55 && pantryScore < 70;
  const isMissingFlavor = flavorScore < 40 && structureScore < 65;

  if (!hasUserPrompt && (isUnderdeveloped || isMissingFlavor)) {
    const details = [];
    if (structureScore < 55) details.push('Recipe structure is minimal — consider adding a protein or sauce');
    if (flavorScore < 40) details.push('Flavor balance is weak — a herb, acid, or spice would help');
    if (pantryScore < 70) details.push('Few pantry items matched — more ingredients would improve the dish');

    return {
      type: TRIGGER_TYPE.MISSING_STRUCTURE,
      reason: 'This recipe needs a bit more to become a complete dish',
      details,
      scores,
      priority: 2,
    };
  }

  // ── TRIGGER A: ENHANCE (priority 1) ────────────────────────────────────
  // Recipe is valid but could be notably improved
  // Moderate structure + moderate improvement potential
  const couldEnhance = (structureScore >= 55 && structureScore < 78) || (flavorScore >= 40 && flavorScore < 65);

  if (!hasUserPrompt && couldEnhance) {
    return {
      type: TRIGGER_TYPE.ENHANCE,
      reason: 'This recipe could taste even better with a few additions',
      details: [
        flavorScore < 65 ? 'Adding herbs, acid, or spice would enhance the flavor profile' : null,
        structureScore < 78 ? 'A supporting ingredient would round out the dish' : null,
      ].filter(Boolean),
      scores,
      priority: 1,
    };
  }

  // ── TRIGGER E: NONE (recipe is strong) ─────────────────────────────────
  return {
    type: TRIGGER_TYPE.NONE,
    reason: 'Recipe looks great — no intervention needed',
    details: [],
    scores,
    priority: 0,
  };
}

/**
 * Utility: given a trigger type, returns UI metadata (title, icon hint, color)
 */
export function getTriggerUIConfig(triggerType) {
  const configs = {
    [TRIGGER_TYPE.ENHANCE]: {
      title: 'Want to make it even better?',
      subtitle: 'A few smart additions could elevate this dish',
      icon: 'sparkles',
      accent: 'indigo',
      ctaLabel: 'See suggestions',
      skipLabel: 'Keep as-is',
    },
    [TRIGGER_TYPE.MISSING_STRUCTURE]: {
      title: 'This dish needs a bit more',
      subtitle: 'Add a few key ingredients to complete the recipe',
      icon: 'chef',
      accent: 'amber',
      ctaLabel: 'Add ingredients',
      skipLabel: 'Use current recipe',
    },
    [TRIGGER_TYPE.NUTRITION_GOAL]: {
      title: 'Nutrition target not fully met',
      subtitle: 'We can help you get closer to your goal',
      icon: 'flame',
      accent: 'emerald',
      ctaLabel: 'Boost nutrition',
      skipLabel: 'Continue anyway',
    },
    [TRIGGER_TYPE.CLARIFICATION]: {
      title: 'This recipe needs more ingredients',
      subtitle: 'Select more pantry items or allow missing ingredients',
      icon: 'star',
      accent: 'violet',
      ctaLabel: 'Edit ingredients',
      skipLabel: 'Generate anyway',
    },
    [TRIGGER_TYPE.NONE]: null,
  };
  return configs[triggerType] || null;
}

/**
 * NutritionUpgradeModal — Suggests ingredients to reach nutrition targets
