import { motion, AnimatePresence } from 'framer-motion';
import { X, Plus, Check, Zap } from 'lucide-react';
import { getRipoAsset } from './RipoAssetMap';
import { RIPO_STATE } from '../character/RipoConstants';

export default function NutritionUpgradeModal({
  isOpen,
  goals,
  currentValues,
  suggestions,
  onAcceptSuggestions,
  onSkip,
}) {
  const [selectedIngredients, setSelectedIngredients] = useState(new Set());

  if (!isOpen) return null;

  const handleToggle = (ingName) => {
    const next = new Set(selectedIngredients);
    if (next.has(ingName)) next.delete(ingName);
    else next.add(ingName);
    setSelectedIngredients(next);
  };

  const handleAccept = () => {
    onAcceptSuggestions(Array.from(selectedIngredients));
    setSelectedIngredients(new Set());
  };

  const assetPath = getRipoAsset(RIPO_STATE.EXPLAINING);

  // Determine primary goal (protein/calories/etc)
  const goalLabel = goals?.protein_min
    ? `${goals.protein_min}g protein`
    : goals?.calories
      ? `${goals.calories} calories`
      : 'nutrition targets';

  const shortfall = goals?.protein_min ? Math.max(0, goals.protein_min - (currentValues?.protein || 0)) : null;

  return (
    <>
      <motion.div
        initial={{ opacity: 0, backdropFilter: 'blur(0px)' }}
        animate={{ opacity: 1, backdropFilter: 'blur(6px)' }}
        exit={{ opacity: 0, backdropFilter: 'blur(0px)' }}
        transition={{ duration: 0.3 }}
        className="fixed inset-0 z-[180] bg-black/40"
        onClick={onSkip}
      />

      <motion.div
        initial={{ opacity: 0, scale: 0.9, y: 30 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ type: 'spring', stiffness: 300, damping: 25 }}
        className="fixed inset-x-5 top-1/4 z-[190] bg-white rounded-3xl shadow-2xl max-w-sm mx-auto flex flex-col max-h-[80vh]"
      >
        {/* Header */}
        <div className="flex items-start justify-between p-4 border-b border-slate-200">
          <div>
            <h3 className="font-bold text-slate-900 flex items-center gap-2">
              <Zap className="w-5 h-5 text-amber-500" />
              Upgrade Recipe
            </h3>
            <p className="text-xs text-slate-500 mt-0.5">
              Add ingredients to reach {goalLabel}
            </p>
          </div>
          <button
            onClick={onSkip}
            className="w-8 h-8 rounded-lg bg-slate-100 hover:bg-slate-200 flex items-center justify-center text-slate-600 transition-colors flex-shrink-0"
          >
            <X className="w-4 h-4" />
          </button>
        </div>

        {/* Ripo character (EXPLAINING - normal state) - dedicated space */}
        <div className="flex items-center justify-center bg-gradient-to-b from-amber-50 to-white py-6 px-4 min-h-[140px]">
          {assetPath ? (
            <motion.img
              src={assetPath}
              alt="Ripo explaining"
              className="w-32 h-32 object-contain"
              style={{ imageRendering: 'crisp-edges' }}
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ delay: 0.1, type: 'spring', stiffness: 300 }}
            />
          ) : (
            <div className="text-6xl">👨‍🍳</div>
          )}
        </div>

        {/* Current vs Target */}
        {shortfall && (
          <div className="px-4 pb-3">
            <div className="bg-amber-50 border border-amber-200 rounded-xl p-3 text-xs">
              <div className="flex items-center justify-between mb-1">
                <span className="text-amber-900 font-semibold">Current:</span>
                <span className="text-amber-700">{Math.round(currentValues?.protein || 0)}g</span>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-amber-900 font-semibold">Target:</span>
                <span className="text-amber-700">{goals.protein_min}g</span>
              </div>
              <div className="w-full h-1.5 bg-amber-200 rounded-full mt-2 overflow-hidden">
                <div
                  className="h-full bg-amber-500 transition-all"
                  style={{ width: `${Math.min(100, ((currentValues?.protein || 0) / goals.protein_min) * 100)}%` }}
                />
              </div>
            </div>
          </div>
        )}

        {/* Suggestions */}
        <div className="px-4 pb-4 space-y-3 flex-1 overflow-y-auto">
          {!suggestions || suggestions.length === 0 ? (
            <p className="text-sm text-slate-500 text-center py-3">
              No suggestions available to reach target.
            </p>
          ) : (
            <>
              <p className="text-xs font-semibold text-slate-600 uppercase tracking-wide">
                Suggested additions
              </p>
              <div className="space-y-2">
                {suggestions.map((suggestion) => {
                  const isSelected = selectedIngredients.has(suggestion.name);
                  return (
                    <button
                      key={suggestion.name}
                      onClick={() => handleToggle(suggestion.name)}
                      className={`w-full flex items-start gap-3 px-3 py-2.5 rounded-xl border-2 transition-all text-left ${
                        isSelected
                          ? 'bg-amber-50 border-amber-300'
                          : 'bg-white border-slate-200 hover:border-amber-200'
                      }`}
                    >
                      <div
                        className={`w-5 h-5 rounded border-2 flex items-center justify-center flex-shrink-0 mt-0.5 transition-all ${
                          isSelected ? 'bg-amber-500 border-amber-500' : 'border-slate-300'
                        }`}
                      >
                        {isSelected && <Check className="w-3 h-3 text-white" />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-slate-900 capitalize">
                          {suggestion.name}
                        </p>
                        {suggestion.reason && (
                          <p className="text-xs text-slate-500 mt-0.5">
                            {suggestion.reason}
                          </p>
                        )}
                      </div>
                    </button>
                  );
                })}
              </div>

              <div className="flex gap-2 pt-3">
                <button
                  onClick={onSkip}
                  className="flex-1 h-10 rounded-xl bg-slate-100 text-slate-700 font-semibold text-sm hover:bg-slate-200 transition-colors"
                >
                  Skip
                </button>
                <button
                  onClick={handleAccept}
                  disabled={selectedIngredients.size === 0}
                  className="flex-1 h-10 rounded-xl bg-amber-600 text-white font-semibold text-sm hover:bg-amber-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all flex items-center justify-center gap-2"
                >
                  <Plus className="w-4 h-4" />
                  Add {selectedIngredients.size > 0 ? `(${selectedIngredients.size})` : ''}
                </button>
              </div>
            </>
          )}
        </div>
      </motion.div>
    </>
  );
}

/**
 * recipePostProcessor.js
 * 
 * Shared post-processing pipeline for generated recipes.
 * Used by BOTH pantry mode and freestyle mode to ensure consistent output.
 * 
 * This is the single source of truth for recipe normalization after LLM generation.
 */

import { normalizeIngredient } from '../recipe/ingredientNormalizer';
import { enforceCanonicalIngredients } from './CanonicalIngredientEnforcer';
import { ensureRecipeConsistency } from './RecipeConsistencyValidator';
import { priceRecipeIngredients } from '../recipe/IngredientPriceEngine';
import { capOptionalAddons, capUniversalSeasonings } from './PromptFidelityValidator';
import { buildMacroTargets, optimizeRecipe, enforceCalorieCap } from './MacroOptimizerEngine';
import { detectDishType } from './ChefRealismEngine';

/**
 * Normalize time values — LLM sometimes returns hours (1.5) or strings ("90").
 * Always returns integer minutes.
 */
function normTime(v) {
  if (v == null) return 0;
  const n = typeof v === 'string' ? parseFloat(v) : v;
  if (isNaN(n) || n < 0) return 0;
  if (n > 0 && n <= 12 && !Number.isInteger(n)) return Math.round(n * 60);
  return Math.round(n);
}

/**
 * Run the full post-processing pipeline on a raw LLM recipe.
 * Returns { recipe, pricedRecipe } with all normalizations applied.
 * 
 * @param {object} rawRecipe - Recipe object from LLM
 * @param {object} options - Processing options
 * @param {boolean} options.skipIngredientValidation - Skip strict ingredient filtering (freestyle mode)
 * @returns {object} { recipe: processed recipe, pricedRecipe: with pricing }
 */
export async function postProcessRecipe(rawRecipe, options = {}) {
  let recipe = { ...rawRecipe };

  // ── STEP 1: Canonical ingredient enforcement ──
  // Decompose composite ingredients (e.g. "Chickpea Patty") into base components
  {
    const cResult = enforceCanonicalIngredients(recipe);
    if (cResult.decomposed.length > 0) {
      console.log('[PostProcess:Canonical]', cResult.decomposed);
    }
    recipe = cResult.recipe;
  }

  // ── STEP 2: Normalize ingredient base_grams ──
  // Ensures NutritionPanel, PricingEngine, and MacroOptimizer all have data
  for (const group of (recipe.ingredients || [])) {
    for (const item of (group.items || [])) {
      if (item.name && !item.optional) {
        try {
          const normalized = normalizeIngredient(item);
          item.base_grams = normalized.base_grams;
        } catch {}
      }
    }
  }

  // ── STEP 3: Deterministic nutrition from actual ingredients ──
  try {
    const { lookupMacroDensity } = await import('./MacroOptimizerEngine');
    let totCal = 0, totProt = 0, totCarbs = 0, totFat = 0, totFiber = 0;
    let matchedCount = 0;
    for (const group of (recipe.ingredients || [])) {
      for (const item of (group.items || [])) {
        if (!item?.base_grams || item.base_grams <= 0 || item.optional) continue;
        const d = lookupMacroDensity(item.name);
        if (!d) continue;
        matchedCount++;
        const scale = item.base_grams / 100;
        totCal += (d.calories || 0) * scale;
        totProt += (d.protein || 0) * scale;
        totCarbs += (d.carbs || 0) * scale;
        totFat += (d.fat || 0) * scale;
        totFiber += (d.fiber || 0) * scale;
      }
    }
    if (matchedCount > 0) {
      const sv = recipe.servings || 1;
      recipe.nutrition_total_for_recipe = {
        calories: Math.round(totCal), protein: Math.round(totProt),
        carbs: Math.round(totCarbs), fat: Math.round(totFat), fiber: Math.round(totFiber),
      };
      recipe.nutrition_per_serving = {
        calories: Math.round(totCal / sv), protein: Math.round(totProt / sv),
        carbs: Math.round(totCarbs / sv), fat: Math.round(totFat / sv), fiber: Math.round(totFiber / sv),
      };
      recipe.nutrition = recipe.nutrition_per_serving;
    }
  } catch (e) {
    console.warn('[PostProcess] Deterministic nutrition failed:', e.message);
  }

  // ── STEP 4: Recipe consistency check ──
  {
    const consistency = ensureRecipeConsistency(recipe);
    if (consistency.violations.length > 0) {
      console.warn('[PostProcess:Consistency]', consistency.violations.map(v => `[${v.severity}] ${v.message}`));
    }
    recipe = consistency.recipe;
  }

  // ── STEP 5: Time normalization ──
  recipe.cook_time = normTime(recipe.cook_time);
  recipe.prep_time = normTime(recipe.prep_time);

  // ── STEP 5.5: Cap unrealistic optional add-on amounts ──
  capOptionalAddons(recipe);
  // ── STEP 5.6: Cap ALL seasoning/finishing amounts universally ──
  capUniversalSeasonings(recipe);

  // ── STEP 5.7: Macro optimization + strict calorie cap (when goals provided) ──
  // Freestyle path: applies when macroGoals are passed in options
  if (options.macroGoals) {
    const macroTargets = buildMacroTargets(options.macroGoals, []);
    if (macroTargets) {
      const dishType = detectDishType([], options.promptText || '', recipe.meal_type || 'dinner');
      const optimResult = optimizeRecipe(recipe, macroTargets, dishType);
      recipe = optimResult.recipe;
      if (macroTargets.calorie_max) {
        enforceCalorieCap(recipe, macroTargets.calorie_max);
      }
    }
  }

  // ── STEP 6: Pricing ──
  const pricedRecipe = priceRecipeIngredients(recipe);

  // ── STEP 7: Pricing floor enforcement — minimum $2.50/serving ──
  {
    const sv = pricedRecipe.servings || 1;
    const cps = pricedRecipe.cost_per_serving ?? 0;
    if (cps > 0 && cps < 2.50) {
      pricedRecipe.total_cost = parseFloat((2.50 * sv).toFixed(2));
      pricedRecipe.cost_per_serving = 2.50;
    }
  }

  return { recipe, pricedRecipe };
}

/**
 * generateIngredientIcons
 * Admin-only: generates realistic food photography icons for canonical ingredients
 * using AI image generation. Stores URLs back into CanonicalIngredient.emoji field.
 * 
 * Runs in small batches to avoid timeouts.
 * Call repeatedly with { offset, batch_size } to page through all ingredients.
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

// Build a detailed, realistic food photography prompt for each ingredient
function buildIconPrompt(displayName, category, subcategory) {
  const style = "professional food photography, overhead shot, isolated on pure white background, soft natural lighting, ultra-sharp focus, realistic colors, clean minimal composition, no text, no watermarks, no shadows, high resolution";

  const categoryHints = {
    vegetables: `fresh raw ${displayName}, vibrant color, perfect produce`,
    fruits: `fresh ripe ${displayName}, vibrant color, glistening surface`,
    herbs_spices: `${displayName}, scattered or in small pile, vivid close-up`,
    grains_cereals: `${displayName}, natural grain texture close-up`,
    legumes_beans: `${displayName}, dried or cooked beans scattered naturally`,
    nuts_seeds: `${displayName}, naturally scattered pile, golden warm tones`,
    dairy_eggs: `${displayName}, fresh dairy product`,
    meat_poultry: `raw ${displayName}, fresh cut, visible marbling or texture`,
    seafood: `fresh ${displayName}, glistening`,
    oils_fats: `${displayName} in small clear glass dish or drizzle`,
    sauces_condiments: `${displayName} in small ceramic bowl or spoon`,
    sweeteners: `${displayName} with natural texture`,
    baking: `${displayName}, baking ingredient close-up`,
    beverages: `${displayName} in clear glass`,
    canned_jarred: `${displayName}`,
    bread_wraps: `fresh baked ${displayName}`,
    pasta_noodles: `${displayName}, dried pasta`,
    frozen: `${displayName}`,
    packaged: `${displayName}`,
    other: `${displayName}`,
  };

  const hint = categoryHints[category] || displayName;
  return `${hint}, ${style}`;
}

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const body = await req.json().catch(() => ({}));
    const {
      offset = 0,
      batch_size = 5,           // small batch per call to avoid timeouts
      skip_existing = true,     // skip if already has a URL icon
      force_category = null,    // optionally only process a specific category
      dry_run = false,
    } = body;

    // Fetch the batch of ingredients to process
    const allIngredients = await base44.asServiceRole.entities.CanonicalIngredient.list('display_name', 2000, 0);

    let toProcess = allIngredients;

    if (force_category) {
      toProcess = toProcess.filter(i => i.category === force_category);
    }

    if (skip_existing) {
      toProcess = toProcess.filter(i => {
        const icon = i.emoji || '';
        // Skip if already has a URL (previously generated image)
        return !icon.startsWith('http');
      });
    }

    const batch = toProcess.slice(offset, offset + batch_size);
    const total_remaining = toProcess.length;

    if (batch.length === 0) {
      return Response.json({
        success: true,
        processed: 0,
        total_remaining: 0,
        message: 'All ingredients already have custom icons!',
      });
    }

    if (dry_run) {
      return Response.json({
        dry_run: true,
        would_process: batch.map(i => ({ id: i.id, name: i.display_name, category: i.category })),
        total_remaining,
        next_offset: offset + batch_size,
      });
    }

    const results = [];

    for (const ingredient of batch) {
      const prompt = buildIconPrompt(
        ingredient.display_name,
        ingredient.category,
        ingredient.subcategory
      );

      console.log(`[IconGen] Generating for: ${ingredient.display_name} (${ingredient.category})`);
      console.log(`[IconGen] Prompt: ${prompt}`);

      let imageUrl = null;
      let error = null;

      try {
        const imgRes = await base44.asServiceRole.integrations.Core.GenerateImage({ prompt });
        imageUrl = imgRes?.url || null;
      } catch (err) {
        error = err.message;
        console.error(`[IconGen] Failed for ${ingredient.display_name}:`, err.message);
      }

      if (imageUrl) {
        try {
          await base44.asServiceRole.entities.CanonicalIngredient.update(ingredient.id, {
            emoji: imageUrl,
          });
          results.push({ name: ingredient.display_name, status: 'success', url: imageUrl });
          console.log(`[IconGen] ✓ ${ingredient.display_name} -> ${imageUrl}`);
        } catch (updateErr) {
          results.push({ name: ingredient.display_name, status: 'update_failed', error: updateErr.message });
        }
      } else {
        results.push({ name: ingredient.display_name, status: 'image_failed', error });
      }
    }

    return Response.json({
      success: true,
      processed: batch.length,
      total_remaining: total_remaining - batch.length,
      next_offset: offset + batch_size,
      results,
      message: `Generated ${results.filter(r => r.status === 'success').length}/${batch.length} icons. Call again with offset=${offset + batch_size} to continue.`,
    });

  } catch (error) {
    console.error('[generateIngredientIcons] Error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

