- Any amount below 5g for a main ingredient
- Grams for eggs (use "2 eggs", "3 eggs")
- Liters for solid ingredients
- "slices" for liquid ingredients

AMOUNT FORMAT RULES:
- Liquids: use ml or cups (e.g., "200ml", "1 cup")
- Solids by weight: use grams (e.g., "300g")
- Countable items: use count + grams hint (e.g., "2 pieces (about 300g)", "3 cloves (about 9g)")
- Whole eggs: just count (e.g., "2 eggs", "3 eggs")`;

export function buildRecipePromptWithConstraints(userProfile, pantryItems, userInputs, constraintFrame) {
  // Inject constraint frame into userInputs if provided
  if (constraintFrame) {
    if (constraintFrame.required_grams?.protein_min && !userInputs.macro_goals?.protein) {
      userInputs = {
        ...userInputs,
        macro_goals: {
          ...userInputs.macro_goals,
          protein: constraintFrame.required_grams.protein_min,
        },
      };
    }
    if (constraintFrame.constraints_list?.length) {
      const extraInstructions = constraintFrame.constraints_list.join(". ");
      userInputs = {
        ...userInputs,
        optional_prompt: [userInputs.optional_prompt, extraInstructions].filter(Boolean).join(" | "),
      };
    }
  }
  return buildRecipePrompt(userProfile, pantryItems, userInputs);
}

export function buildRecipePrompt(userProfile, pantryItems, userInputs) {
  const restrictions = [];
  if (userProfile?.allergies?.length) {
    restrictions.push(`ALLERGEN PROHIBITION — NEVER include: ${userProfile.allergies.join(", ")}`);
  }
  if (userProfile?.dislikes?.length) {
    restrictions.push(`DISLIKED INGREDIENTS — NEVER include: ${userProfile.dislikes.join(", ")}`);
  }
  if (userProfile?.dietary_preferences?.length) {
    restrictions.push(`DIETARY RULES — MUST comply: ${userProfile.dietary_preferences.join(", ")}`);
  }

  // Hard cap at 12 selected ingredients
  const cappedIngredients = pantryItems.slice(0, 12);
  const targetServings = userInputs.servings || 2;

  // ── STRICT QUANTITY ENFORCEMENT: Build map of strict ingredient amounts ──
  const strictQuantityMap = userInputs.strict_quantities_map || {};
  const hasStrictQuantities = Object.keys(strictQuantityMap).length > 0;

  // Resolve macro goals early
  const macroGoals = userInputs.macro_goals || {};
  const extraProteinIngredients = userInputs.extra_protein_ingredients || [];
  const proteinGoalRaw = macroGoals.protein;
  const hasProteinGoal = !!proteinGoalRaw;
  const isAiAutoProtein = !!userInputs.ai_auto_protein;
  const hasApprovedExtras = extraProteinIngredients.length > 0;

  // Compute protein range (shared between ingredientRule and macroConstraintBlock)
  let proteinMin = 0, proteinMax = 0, proteinDisplay = '';
  if (hasProteinGoal) {
    if (typeof proteinGoalRaw === 'object') {
      proteinMin = proteinGoalRaw.min;
      proteinMax = proteinGoalRaw.max;
      proteinDisplay = `${proteinMin}–${proteinMax}g`;
    } else {
      proteinMin = Math.round(proteinGoalRaw * 0.95);
      proteinMax = Math.round(proteinGoalRaw * 1.05);
      proteinDisplay = `${proteinGoalRaw}g (range: ${proteinMin}–${proteinMax}g)`;
    }
  }

  // Build ingredient list: pantry items (with cap) + approved protein extras (no cap, required)
  const pantryLines = cappedIngredients.map(i => {
    const lowerName = i.name.toLowerCase();
    const strictEntry = strictQuantityMap[lowerName] || 
      Object.values(strictQuantityMap).find(e => 
        lowerName.includes(e.original_name?.toLowerCase() || '') || 
        (e.original_name?.toLowerCase() || '').includes(lowerName)
      );

    if (strictEntry) {
      // STRICT MODE: use EXACT amount, not pantry max
      return `- ${i.name} (STRICT EXACT AMOUNT: ${strictEntry.display_amount} ${strictEntry.display_unit} — use this EXACT decimal, NO ROUNDING, NOT ${Math.round(parseFloat(strictEntry.display_amount))} pieces)`;
    }

    const qty = i.quantity;
    const unit = i.unit || '';
    if (qty != null && qty > 0 && unit) {
      return `- ${i.name} (user has: ${qty}${unit} — MUST NOT exceed this total amount)`;
    }
    return `- ${i.name}`;
  });

  // Approved extras are added as required items alongside pantry items
  const extraLines = hasApprovedExtras
    ? extraProteinIngredients.map(name => {
        const proteinDensities = {
          'chicken': 0.31, 'turkey': 0.29, 'salmon': 0.25, 'tuna': 0.30,
          'lean beef': 0.26, 'egg': 0.13, 'greek yogurt': 0.10, 'shrimp': 0.24,
          'egg white': 0.11, 'cottage cheese': 0.11, 'tilapia': 0.26, 'cod': 0.23,
        };
        let density = 0.25; // default protein per gram
        for (const [key, val] of Object.entries(proteinDensities)) {
          if (name.toLowerCase().includes(key)) { density = val; break; }
        }
        // FIX: requiredGrams is for the TOTAL recipe (all servings), NOT per serving
        // Formula: totalProtein / density = total grams of this ingredient needed
        // We allocate ~80% of the gap to each enhancement ingredient (AI will balance)
        const requiredGrams = proteinMin ? Math.ceil((proteinMin * 0.8) / density) : 200;
        return `- ${name} ← USER-APPROVED PROTEIN BOOST (MANDATORY, NOT OPTIONAL: include ≥${requiredGrams}g TOTAL in the recipe across all servings to help reach total protein target of ${proteinMin}g, place in main group with optional=false, missing=false)`;
      })
    : [];

  const ingredientListBlock = [...pantryLines, ...extraLines].join("\n");

