  const aiAutoInstruction = isAiAutoProtein && !hasApprovedExtras && hasProteinGoal
    ? `\n⚡ AI-AUTO PROTEIN MODE: You MUST autonomously add high-protein ingredients (chicken breast, tuna, salmon, turkey breast, Greek yogurt, egg whites, etc.) to the MAIN group with optional=false, missing=false, calculated grams to reach ${proteinMin}–${proteinMax}g total protein. These are REQUIRED.`
    : '';

