    const gn = (group.group || '').toLowerCase();
    if (gn.includes('dressing') || gn.includes('finishing') || gn.includes('garnish') || gn.includes('plating') || gn.includes('decoration')) {
      for (const item of group.items || []) {
        if (item?.name) dressingItems.push(item.name);
      }
    }
