  // Extract visual enhancement keywords from user prompt
  const promptLower = (userPrompt || '').toLowerCase();
  const visualEnhancements = [];
  if (/healthy|clean eating|wholesome/.test(promptLower)) visualEnhancements.push('fresh wholesome healthy ingredients, vibrant colors');
  if (/avocado/.test(promptLower)) visualEnhancements.push('creamy avocado spread visible');
  if (/vegan|plant.based|no meat|meatless|vegetarian/.test(promptLower)) visualEnhancements.push('plant-based ingredients, colorful vegetables, NO meat patty visible');
  if (/spicy|hot/.test(promptLower)) visualEnhancements.push('chili garnish, vibrant red tones');
  if (/fresh|light/.test(promptLower)) visualEnhancements.push('light bright fresh presentation');
  if (/gourmet|elevated|fancy|special/.test(promptLower)) visualEnhancements.push('gourmet restaurant-level plating');

  // Dietary exclusions — prevent wrong visuals (uses the same parser as generation for full 18-language support)
  const dietaryExclusions = [];
  const imageDietaryResult = parseDietaryConstraints(userPrompt);
  if (imageDietaryResult.constraints.includes('vegetarian') || imageDietaryResult.constraints.includes('vegan')) {
    dietaryExclusions.push('NO meat patty, NO beef, NO raw meat in the image, NO chicken, NO fish');
  }
  if (imageDietaryResult.constraints.includes('dairy_free') || imageDietaryResult.constraints.includes('vegan')) {
    dietaryExclusions.push('NO cheese visible, NO cream, NO dairy');
  }
  if (imageDietaryResult.constraints.includes('egg_free')) {
    dietaryExclusions.push('NO visible eggs');
  }
  // Fallback: also check English patterns for edge cases not caught by parser
  if (dietaryExclusions.length === 0) {
    if (/no meat|without meat|meatless|vegetarian|vegan|plant.based/.test(promptLower)) {
      dietaryExclusions.push('NO meat patty, NO beef, NO raw meat in the image');
    }
    if (/no cheese|dairy.free|no dairy/.test(promptLower)) {
      dietaryExclusions.push('NO cheese visible');
    }
  }

  const subject = ingredientList ? `${title} made with ${ingredientList}` : title;
  const contextHint = [cuisine, mealType].filter(Boolean).join(', ');
  const diff = (recipe.difficulty || 'easy').toLowerCase();
  const finishingDesc = dressingItems.length > 0 ? `dressed with ${dressingItems.join(', ')}` : '';

  return [
    `Professional food photography of ${subject}`,
    contextHint ? `${contextHint} style` : '',
    'beautifully plated on a clean plate',
    finishingDesc,
    visualEnhancements.length > 0 ? visualEnhancements.join(', ') : '',
    diff === 'hard' ? 'restaurant-level plating with elegant finishing touches' : '',
    diff === 'medium' ? 'refined home plating with garnish details' : '',
    'soft natural light from the side',
    'shallow depth of field',
    'appetizing and realistic presentation',
    'high resolution, restaurant quality',
    'no text, no watermarks',
    dietaryExclusions.length > 0 ? dietaryExclusions.join(', ') : '',
    `ONLY show: ${ingredientList || title}${dressingItems.length ? ' with ' + dressingItems.join(', ') : ''}. Do NOT add ingredients not listed.`,
  ].filter(Boolean).join(', ');
}

