/**
 * generateRecipe — BACKEND-ONLY CREDIT PATH
 *
 * IMPORTANT: This function builds the prompt locally (zero cost) but ALL actual
 * LLM credit consumption MUST go through the backend `generateRecipeWithQuota`
 * function which enforces quota, idempotency, and credit tracking.
 *
 * This function is intentionally NOT exported as a direct credit-consuming path.
 * Call it only via the backend-gated wrapper `generateRecipeViaBackend` below,
 * or pass the built prompt directly to your backend function.
 *
 * Direct frontend InvokeLLM is REMOVED — backend is the sole credit authority.
 */
// Backwards-compatible alias — Generate.jsx imports this name
export const generateRecipe = generateRecipeViaBackend;

export function buildRecipeGenerationPrompt(userProfile, pantryItems, userInputs, constraintFrame = null) {
  return constraintFrame
    ? buildRecipePromptWithConstraints(userProfile, pantryItems, userInputs, constraintFrame)
    : buildRecipePrompt(userProfile, pantryItems, userInputs);
}

/**
 * generateRecipeViaBackend — the ONLY valid frontend recipe-generation entry point.
 *
 * Routes through `generateRecipeWithQuota` backend function which:
 *   1. Checks and enforces user quota (free/pro)
 *   2. Consumes Base44 InvokeLLM credits server-side
 *   3. Logs credit usage to IntegrationCostLog
 *   4. Returns idempotent result on replay
 *
 * No direct InvokeLLM call is made from the frontend.
 */
export async function generateRecipeViaBackend(userProfile, pantryItems, userInputs, constraintFrame = null, { clientRequestId } = {}) {
  const { base44 } = await import('@/api/base44Client');
  const { getClientTimezone } = await import('@/lib/clientTimezone');
  const prompt = buildRecipeGenerationPrompt(userProfile, pantryItems, userInputs, constraintFrame);
  const requestId = clientRequestId || crypto.randomUUID();
  const res = await base44.functions.invoke('generateRecipeWithQuota', {
    prompt,
    client_request_id: requestId,
    // CRITICAL: pass client tz so the backend writes Pro daily_count under the
    // SAME day_key that getAiQuotaAdvanced reads. Without this, writes go to UTC
    // and reads to local tz → quota appears reset to 25/25.
    client_timezone: getClientTimezone(),
    response_json_schema: {
      type: "object",
      properties: {
        title: { type: "string" },
        description: { type: "string" },
        cuisine: { type: "string" },
        meal_type: { type: "string" },
        cook_time: { type: "number" },
        prep_time: { type: "number" },
        difficulty: { type: "string" },
        servings: { type: "number" },
        ingredients: {
          type: "array",
          items: {
            type: "object",
            properties: {
              group: { type: "string" },
              items: {
                type: "array",
                items: {
                  type: "object",
                  properties: {
                    name: { type: "string" },
                    amount: { type: "string" },
                    optional: { type: "boolean" },
                    missing: { type: "boolean" }
                  }
                }
              }
            }
          }
        },
        steps: {
          type: "array",
          items: {
            type: "object",
            properties: {
              step_number: { type: "number" },
              instruction: { type: "string" },
              timer_minutes: { type: "number" },
              animation_key: { type: "string" }
            }
          }
        },
        tags: { type: "array", items: { type: "string" } },
        allergens: { type: "array", items: { type: "string" } },
        nutrition: {
          type: "object",
          properties: {
            calories: { type: "number" },
            protein: { type: "number" },
            carbs: { type: "number" },
            fat: { type: "number" },
            fiber: { type: "number" }
          }
        },
        substitutions: {
          type: "array",
          items: {
            type: "object",
            properties: {
              original: { type: "string" },
              substitute: { type: "string" }
            }
          }
        }
      }
    }
  });
  // The backend returns { success, recipe, event_id, generation_id, quota, credit_source }
  const data = res?.data;
  if (data?.idempotent_hit && data?.recipe) {
    // Idempotent replay — attach metadata
    data.recipe._eventId = data.event_id;
    data.recipe._generationId = data.generation_id;
    data.recipe._quota = data.quota;
    data.recipe._creditSource = data.credit_source;
    data.recipe._idempotentHit = true;
    return data.recipe;
  }
  if (!data?.recipe) {
    // Attach quota to error so frontend can update state even on failure
    const err = new Error(data?.error || 'Backend returned no recipe data');
    err.quota = data?.quota;
    err.code = data?.code;
    err.event_id = data?.event_id;
    throw err;
  }
  // Attach backend metadata to recipe for downstream use
  data.recipe._eventId = data.event_id;
  data.recipe._generationId = data.generation_id;
  data.recipe._quota = data.quota;
  data.recipe._creditSource = data.credit_source;
  return data.recipe;
}

// Simple personalization scoring
export function scoreRecipeForUser(recipe, userProfile, recentMealLogRecipeIds = [], pantryItemNames = []) {
  let score = 0;

  // Avoid recently eaten recipes
  if (recentMealLogRecipeIds.includes(recipe.id)) {
    score -= 50;
  }

  // Boost matching dietary preferences
  if (userProfile?.dietary_preferences && recipe.tags) {
    const matches = recipe.tags.filter(t => userProfile.dietary_preferences.includes(t));
    score += matches.length * 10;
  }

  // Boost recipes using pantry items
  if (recipe.ingredients && pantryItemNames.length > 0) {
    const allIngredients = recipe.ingredients.flatMap(g => g.items?.map(i => i.name?.toLowerCase()) || []);
    const pantryLower = pantryItemNames.map(n => n.toLowerCase());
    const matches = allIngredients.filter(i => pantryLower.some(p => i?.includes(p)));
    score += matches.length * 5;
  }

  // Penalize recipes with allergens
  if (userProfile?.allergies && recipe.allergens) {
    const hasAllergen = recipe.allergens.some(a => userProfile.allergies.includes(a));
    if (hasAllergen) score -= 100;
  }

  return score;
}

/**
 * getCommunityfeed v2 — RECENCY-FIRST community discovery feed.
 *
 * DISTINCT from Trending and Recommended:
 *   - Sorted primarily by recency (newest posts first)
 *   - Light engagement boost to surface active posts over dead ones
 *   - No personalization — community-wide discovery
 *   - Engagement boost is small (max 2x) so a new post can still appear above
 *     an old high-engagement post
 *
 * communityScore = recencyScore * (1 + smallEngagementBonus)
 *   recencyScore = exp(-ageDays / 4)    ← very sharp 4-day decay
 *   smallEngagementBonus = min((likes + saves*2 + comments*1.5) / 20, 1.0)
 *
 * This means:
 *   - A brand new post with 0 likes scores ~1.0 and beats a 5-day-old post with 10 likes
 *   - Trending shows those same 10-like posts first (momentum)
 *   - Recommended shows personalized recipes based on user goals
 *   → Three genuinely distinct orderings
 */
import { createClientFromRequest } from 'npm:@base44/sdk@0.8.21';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await req.json().catch(() => ({}));
    const { limit = 20, offset = 0, force_refresh = false, filters = {} } = body;

    const LOW_COST_MAX_PER_SERVING = 6;
    const COMMUNITY_DECAY_DAYS = 4; // Very sharp decay — community = freshness-first
    const sr = base44.asServiceRole;

    // Fetch data in parallel — include both Posts AND eligible Recipes (AI generated is part of community discovery)
    const [posts, recipes, allUsers, blockedByMe, blockedByOthers] = await Promise.all([
      sr.entities.Post.filter(
        { community_visible: true, type: 'community' },
        '-created_date',
        Math.max(limit * 4, 300)
      ).catch(() => sr.entities.Post.filter({ community_visible: true }, '-created_date', Math.max(limit * 4, 300)).catch(() => [])),
      sr.entities.Recipe.filter({ is_public: true }, '-created_date', Math.max(limit * 4, 300)).catch(() => []),
      sr.entities.User.filter({}, null, 5000).catch(() => []),
      sr.entities.BlockedUser.filter({ blocker_id: user.id }).catch(() => []),
      sr.entities.BlockedUser.filter({ blocked_id: user.id }).catch(() => []),
    ]);

    const blockedIds = new Set([
      ...blockedByMe.map(b => b.blocked_id),
      ...blockedByOthers.map(b => b.blocker_id),
    ]);

    const userMap = {};
    for (const u of allUsers) userMap[u.id] = u;

    let filteredPosts = posts.filter(p => {
      if (p.author_id && blockedIds.has(p.author_id)) return false;
      if (p.author_account_status && p.author_account_status !== 'active') return false;
      const author = userMap[p.author_id];
      if (author && author.account_status && author.account_status !== 'active') return false;
      // MODERATION: remove removed/appealed posts. 'active' and 'restored' are both visible.
      if (p.moderation_status === 'removed_by_moderation' || p.moderation_status === 'appealed' || p.moderation_status === 'deleted_by_owner') return false;
      // PRIVACY: must be community visible and not shop-only content
      if (p.community_visible !== true) return false;
      if (p.shop_visible === true && p.community_visible !== true) return false;
      return true;
    });

    // Convert eligible recipes to post-like objects for unified ranking
    // NOTE: community_visible is not required — missing/null = visible (only explicit false excluded)
    const recipeAsPosts = recipes.filter(r => {
      if (r.author_id && blockedIds.has(r.author_id)) return false;
      if (r.author_account_status && r.author_account_status !== 'active') return false;
      if (r.moderation_status === 'removed_by_moderation' || r.moderation_status === 'appealed') return false;
      if (r.community_visible === false) return false; // only exclude explicitly set to false
      return true;
    }).map(r => ({
      id: r.id,
      type: 'recipe',
      created_date: r.created_date,
      author_id: r.author_id,
      author_name: r.author_name,
      author_avatar: r.author_avatar,
      author_account_status: r.author_account_status,
      title: r.title,
      description: r.description,
      media_url: r.hero_image_url,
      like_count: r.likes_count || 0,
      save_count: r.saves_count || 0,
      comment_count: r.review_count || 0,
      moderation_status: r.moderation_status || 'active',
      community_visible: true,
      _recipe_source: r.source,
    }));

    filteredPosts = [...filteredPosts, ...recipeAsPosts];

    // Low-cost filter (unchanged from v1)
    if (filters.dietTags && filters.dietTags.includes('low-cost')) {
      const recipes = await sr.entities.Recipe.filter(
        { is_public: true, source: 'user' }, '-created_date', 500
      );
      const costMap = {};
      for (const r of recipes) {
        if (r.cost_per_serving != null && r.cost_per_serving > 0 && r.cost_per_serving <= LOW_COST_MAX_PER_SERVING) {
          costMap[r.id] = r.cost_per_serving;
        }
      }
      filteredPosts = filteredPosts.filter(p => costMap[p.id] != null || costMap[p.recipe_id] != null);
    }

    // COMMUNITY RANKING — recency-first with small engagement bonus
    // DISTINCT from Trending (velocity) and Recommended (personalized quality)
    const now = Date.now();
    const ranked = filteredPosts
      .map(post => {
        const ageDays = Math.max(
          (now - new Date(post.created_date || Date.now()).getTime()) / 86400000,
          0.01
        );

        // Very sharp recency decay — 4 days (Trending=7 days, Recommended=21 days)
        const recencyScore = Math.exp(-ageDays / COMMUNITY_DECAY_DAYS);

        const likes = post.like_count || post.likes_count || 0;
        const saves = post.save_count || post.saves_count || 0;
        const comments = post.comment_count || 0;

        // Small engagement bonus — capped at 1.0 so recency still dominates
        const engagementBonus = Math.min((likes + saves * 2 + comments * 1.5) / 20, 1.0);

        // Community score: recency drives ordering, engagement just prevents dead posts from surfacing
        let communityScore = recencyScore * (1 + engagementBonus);

        // REINSERTION WEIGHT — dampens restored posts during warmup. Never exceeds 1.0.
        // Uses ORIGINAL created_date for freshness (not restored_at) — anti-freshness-abuse.
        if (post.reinsertion_phase === 'warmup' && post.reinsertion_weight != null) {
          communityScore *= post.reinsertion_weight;
        }

        return { post, communityScore, _ageDays: ageDays };
      })
      .sort((a, b) => b.communityScore - a.communityScore)
      .map(item => item.post);

    const paginated = ranked.slice(offset, offset + limit);

    console.log(`[COMMUNITY_V2] user=${user.id} total=${filteredPosts.length} returning=${paginated.length} decay=${COMMUNITY_DECAY_DAYS}d`);

    // Enrich with viewer interaction state + LIVE author identity
    // CRITICAL: Query unified Like entity (target_type:'post') — NOT PostLike (old table).
    // toggleLikeUnified writes to Like entity only. PostLike is legacy and never updated.
    // Fetch all post likes for this user in ONE query to avoid N per-post queries.
    const postIds = paginated.map(p => p.id).filter(Boolean);
    const [allUserPostLikes, allUserPostSaves] = await Promise.all([
      postIds.length > 0
        ? sr.entities.Like.filter({ target_type: 'post', user_id: user.id }).catch(() => [])
        : Promise.resolve([]),
      postIds.length > 0
        ? sr.entities.PostSave.filter({ user_id: user.id }).catch(() => [])
        : Promise.resolve([]),
    ]);
    const likedPostIds = new Set(allUserPostLikes.map(l => l.target_id));
    const savedPostIds = new Set(allUserPostSaves.map(s => s.post_id));

    // Batch-fetch all PostRatings for this user in one query (avoids N×429-prone per-post queries)
    const allUserPostRatings = await sr.entities.PostRating.filter({ user_id: user.id }).catch(() => []);
    const ratingMap = {};
    for (const r of allUserPostRatings) {
      if (r.post_id) ratingMap[r.post_id] = r.stars;
    }

    const enrichedPosts = paginated.map((post) => {
      const author = userMap[post.author_id] || null;
      const resolvedName = author
        ? (author.display_name || author.full_name || author.username || post.author_name || '')
        : (post.author_name || '');
      const resolvedAvatar = author
        ? (author.avatar_url || author.avatar || post.author_avatar || '')
        : (post.author_avatar || '');
      const resolvedImage = post.media_url || post.hero_image_url || null;
      return {
        ...post,
        author_name: resolvedName,
        author_avatar: resolvedAvatar,
        media_url: resolvedImage,
        viewer_has_liked: likedPostIds.has(post.id),
        viewer_has_saved: savedPostIds.has(post.id),
        viewer_rating_value: ratingMap[post.id] ?? null,
      };
    });

    return Response.json({ posts: enrichedPosts, force_refresh, source: 'community_v2' });
  } catch (error) {
    console.error('[getCommunityfeed]', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

/**
 * getPricingObservability — PART 10: ANOMALY DETECTION & OBSERVABILITY
 * 
 * Provides production observability for the pricing system:
 * - Top unresolved ingredients (for catalog expansion)
 * - Anomaly rates (fallback-only, suspicious costs, coverage)
 * - Pricing health metrics
 * - Per-recipe pricing diagnostics
 */

import { createClientFromRequest } from 'npm:@base44/sdk@0.8.23';

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();
    if (!user || user.role !== 'admin') {
      return Response.json({ error: 'Admin access required' }, { status: 403 });
    }

    const { lookback_days, limit } = await req.json() || {};
    const days = lookback_days || 7;
    const limit_val = limit || 100;

    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - days);

    // Fetch all pricing summaries from last N days
    const summaries = await base44.asServiceRole.entities.RecipePricingSummary.filter(
      { computed_at: { $gte: cutoffDate.toISOString() } },
      '-computed_at',
      10000
    );

    // Aggregated metrics
    const totalRecipes = summaries.length;
    let fullCoverageCount = 0;
    let partialCoverageCount = 0;
    let unresolvedCount = 0;
    let totalUnresolvedIngredients = 0;
    const unresolvedTexts = {};
    const anomalyCounts = {};
    let totalFallbackCount = 0;

    for (const summary of summaries) {
      if (summary.pricing_status === 'full') fullCoverageCount++;
      else if (summary.pricing_status === 'partial') partialCoverageCount++;
      else unresolvedCount++;

      totalUnresolvedIngredients += summary.unresolved_ingredient_count || 0;
      totalFallbackCount += summary.fallback_pricing_count || 0;

      // Track unresolved ingredient texts
      for (const text of (summary.unresolved_ingredient_texts || [])) {
        unresolvedTexts[text] = (unresolvedTexts[text] || 0) + 1;
      }

      // Track anomalies
      for (const flag of (summary.anomaly_flags || [])) {
        anomalyCounts[flag] = (anomalyCounts[flag] || 0) + 1;
      }
    }

    // Sort unresolved by frequency
    const topUnresolved = Object.entries(unresolvedTexts)
      .sort(([, a], [, b]) => b - a)
      .slice(0, limit_val)
      .map(([text, count]) => ({ text, count }));

    // Coverage metrics
    const fullCoverageRatio = totalRecipes > 0 ? (fullCoverageCount / totalRecipes) : 0;
    const fallbackRatio = totalRecipes > 0 ? (totalFallbackCount / (totalRecipes * 5)) : 0; // Rough estimate: ~5 ingredients per recipe

    const healthMetrics = {
      total_recipes_priced: totalRecipes,
      full_coverage_count: fullCoverageCount,
      full_coverage_ratio: (fullCoverageRatio * 100).toFixed(1) + '%',
      partial_coverage_count: partialCoverageCount,
      partial_coverage_ratio: ((partialCoverageCount / totalRecipes) * 100).toFixed(1) + '%',
      unresolved_count: unresolvedCount,
      unresolved_ratio: ((unresolvedCount / totalRecipes) * 100).toFixed(1) + '%',
      total_unresolved_ingredients: totalUnresolvedIngredients,
      fallback_pricing_count: totalFallbackCount,
      fallback_ratio: (fallbackRatio * 100).toFixed(1) + '%',
    };

    return Response.json({
      lookback_days: days,
      generated_at: new Date().toISOString(),
      health: healthMetrics,
      top_unresolved_ingredients: topUnresolved,
      anomaly_distribution: anomalyCounts,
      action_items: generateActionItems(healthMetrics, topUnresolved, anomalyCounts),
    });
  } catch (error) {
    console.error('[getPricingObservability] error:', error.message);
    return Response.json({ error: error.message }, { status: 500 });
  }
});

function generateActionItems(health, topUnresolved, anomalies) {
  const items = [];

  // Check coverage health
  const fullCoverageNum = parseFloat(health.full_coverage_ratio);
  if (fullCoverageNum < 50) {
    items.push({
      severity: 'high',
      issue: 'Low pricing coverage',
      message: `Only ${fullCoverageNum}% of recipes have full pricing coverage`,
      action: 'Review and expand canonical ingredient database',
    });
  }

  // Check unresolved ingredients
  if (topUnresolved.length > 0) {
    items.push({
      severity: 'medium',
      issue: 'Top unresolved ingredients found',
      message: `${topUnresolved[0].text} appears ${topUnresolved[0].count} times`,
      action: 'Add these ingredients to CanonicalIngredient catalog',
      examples: topUnresolved.slice(0, 5).map(u => u.text),
    });
  }

  // Check fallback usage
  const fallbackNum = parseFloat(health.fallback_ratio);
  if (fallbackNum > 30) {
    items.push({
      severity: 'medium',
      issue: 'High fallback pricing usage',
      message: `${fallbackNum}% of pricing uses category benchmarks`,
      action: 'Add more ingredient-specific prices to CanonicalIngredient',
    });
  }

  // Check anomalies
  if (anomalies.all_unresolved_ingredients || anomalies.zero_priced_ingredients) {
    items.push({
      severity: 'high',
      issue: 'Zero-priced recipes detected',
      message: `${anomalies.zero_priced_ingredients || 0} recipes have no pricing`,
      action: 'Investigate and fix ingredient matching',
    });
  }

  return items;
}

