import React, { useState, useEffect, useRef } from "react";
import { X, Lock, Globe, Camera, ImageIcon, AlertTriangle, Loader2, Sparkles, Users, Upload } from "lucide-react";
import { cn } from "@/lib/utils";
import { base44 } from "@/api/base44Client";
import { useNavHider } from "@/components/hooks/useNavHider";
import { useLocalization } from "@/services/localization/LocalizationContext";
import { motion, AnimatePresence } from "framer-motion";
import { checkGroupNameSafety, checkPublicTextSafety } from "@/lib/contentSafety";

const COVER_COLORS = ["#6366f1", "#ec4899", "#f59e0b", "#10b981", "#3b82f6", "#8b5cf6", "#ef4444", "#06b6d4", "#f97316", "#14b8a6"];
const COVER_EMOJIS = ["🍳", "🥗", "🍕", "🌮", "🍜", "🥩", "🥦", "🍰", "🏋️", "💪", "🌍", "👥"];
const DEFAULT_RULES = "Be respectful to all members\nNo spam or self-promotion\nStay on topic\nNo medical claims\nReport issues to admins";

export default function CreateGroupModal({ isOpen, onClose, onSubmit, loading }) {
  const { t } = useLocalization();
  useNavHider(isOpen);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [privacy, setPrivacy] = useState("public");
  const [joinMode, setJoinMode] = useState("open");
  const [rulesText, setRulesText] = useState(DEFAULT_RULES);
  const [selectedColor, setSelectedColor] = useState(COVER_COLORS[0]);
  const [selectedEmoji, setSelectedEmoji] = useState(COVER_EMOJIS[0]);
  const [coverImageUrl, setCoverImageUrl] = useState(null);
  const [logoUrl, setLogoUrl] = useState(null);
  const [imageUploading, setImageUploading] = useState(false);
  const [logoUploading, setLogoUploading] = useState(false);
  const [moderationError, setModerationError] = useState(null);
  const [nameError, setNameError] = useState(null);
  const [descError, setDescError] = useState(null);
  const fileInputRef = useRef(null);
  const logoInputRef = useRef(null);

  useEffect(() => {
    if (isOpen) document.body.style.overflow = "hidden";
    return () => { document.body.style.overflow = ""; };
  }, [isOpen]);

  const handleUpload = async (file, type) => {
    setModerationError(null);
    if (type === 'banner') setImageUploading(true);
    else setLogoUploading(true);
    try {
      const { file_url } = await base44.integrations.Core.UploadFile({ file });
      const res = await base44.functions.invoke("moderateImage", { image_url: file_url });
      const mod = res.data;
      if (mod && mod.safe === false) {
        setModerationError(`Image flagged: ${mod.reason || 'policy violation'}. Try a different image.`);
      } else {
        if (type === 'banner') setCoverImageUrl(file_url);
        else setLogoUrl(file_url);
      }
    } catch {
      setModerationError("Failed to process image. Please try again.");
    }
    if (type === 'banner') setImageUploading(false);
    else setLogoUploading(false);
  };

  const isValid = name.trim().length >= 2 && !nameError && !descError && (privacy !== "private" || rulesText.trim().length >= 5);

  const handleNameChange = (val) => {
    setName(val);
    setNameError(null);
    const check = checkGroupNameSafety(val);
    if (!check.safe) {
      setNameError('This name contains inappropriate content. Please choose a different name.');
    }
  };

  const handleDescriptionChange = (val) => {
    setDescription(val.slice(0, 160));
    setDescError(null);
    const check = checkPublicTextSafety(val);
    if (!check.safe) {
      setDescError('Description contains inappropriate content. Please rewrite it.');
    }
  };

  const handleSubmit = () => {
    if (!isValid || loading) return;
    const check = checkGroupNameSafety(name);
    if (!check.safe) {
      setNameError('This name contains inappropriate content. Please choose a different name.');
      return;
    }
    const descCheck = checkPublicTextSafety(description);
    if (!descCheck.safe) {
      setDescError('Description contains inappropriate content. Please rewrite it.');
      return;
    }
    const rulesCheck = checkPublicTextSafety(rulesText);
    if (!rulesCheck.safe) {
      setDescError('Rules contain inappropriate content. Please rewrite them.');
      return;
    }
    onSubmit({
      name: name.trim(),
      description: description.trim(),
      privacy,
      join_mode: joinMode,
      rules_text: rulesText.trim(),
      icon_key: selectedEmoji,
      color_key: selectedColor,
      cover_color: selectedColor,
      cover_emoji: selectedEmoji,
      cover_image_url: coverImageUrl || null,
      logo_url: logoUrl || null,
    });
  };

  if (!isOpen) return null;

