          <div className="flex items-center gap-2.5">
            <div className="w-8 h-8 rounded-xl flex items-center justify-center"
              style={{ background: 'linear-gradient(135deg, #6366f1, #8b5cf6)' }}>
              <Users className="w-4 h-4 text-white" />
            </div>
            <h2 className="font-bold text-slate-900 text-base">{t('creategroup.title', 'Create Group')}</h2>
          </div>
          <button onClick={onClose} className="w-9 h-9 flex items-center justify-center rounded-xl hover:bg-slate-100 transition-colors">
            <X className="w-4 h-4 text-slate-400" />
          </button>
        </div>

        {/* ── SCROLLABLE BODY ──────────────────────────────── */}
        <div className="overflow-y-auto flex-1 px-5 py-5 space-y-6" style={{ overscrollBehavior: "contain" }}>

          {/* ── LIVE PREVIEW CARD ──────────────────────────── */}
          <div className="rounded-2xl overflow-hidden" style={{ boxShadow: '0 2px 16px rgba(0,0,0,0.08)' }}>
            <div className="h-20 relative" style={{
              background: coverImageUrl ? undefined : `linear-gradient(135deg, ${selectedColor}dd, ${selectedColor}88)`,
            }}>
              {coverImageUrl && <img src={coverImageUrl} alt="" className="w-full h-full object-cover" />}
              <div className="absolute inset-0" style={{ background: 'linear-gradient(to bottom, transparent 40%, rgba(0,0,0,0.15) 100%)' }} />
            </div>
            <div className="px-3 pb-3 pt-2 bg-white relative">
              <div className="absolute -top-5 left-3">
                <div className="w-10 h-10 rounded-xl overflow-hidden flex items-center justify-center"
                  style={{ background: logoUrl ? '#f8fafc' : `${selectedColor}22`, border: '2.5px solid #fff', boxShadow: '0 2px 8px rgba(0,0,0,0.1)' }}>
                  {logoUrl ? <img src={logoUrl} alt="" className="w-full h-full object-cover" /> : <span className="text-sm">{selectedEmoji}</span>}
                </div>
              </div>
              <div className="h-3" />
