                    <X className="w-3 h-3 text-white" />
                  </button>
                </div>
              ) : (
                <button onClick={() => logoInputRef.current?.click()} disabled={logoUploading}
                  className="w-full aspect-square rounded-2xl border-2 border-dashed border-slate-200 flex flex-col items-center justify-center gap-1.5 hover:border-indigo-300 hover:bg-indigo-50/50 transition-all">
                  {logoUploading ? <Loader2 className="w-5 h-5 animate-spin text-slate-400" /> : (
                    <>
