            </div>

            {/* Banner */}
            <div>
              <p className="text-[10px] font-bold text-slate-500 uppercase tracking-wider mb-2">Banner</p>
              <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={(e) => { const f = e.target.files?.[0]; if (f) handleUpload(f, 'banner'); }} />
              {coverImageUrl ? (
                <div className="relative w-full aspect-square rounded-2xl overflow-hidden" style={{ border: '2px solid #e0e7ff' }}>
                  <img src={coverImageUrl} alt="" className="w-full h-full object-cover" />
                  <button onClick={() => setCoverImageUrl(null)}
                    className="absolute top-1.5 right-1.5 w-6 h-6 rounded-full bg-black/50 flex items-center justify-center">
                    <X className="w-3 h-3 text-white" />
                  </button>
