                {t('creategroup.create_btn', 'Create Group')}
              </>
            )}
          </motion.button>
        </div>
      </motion.div>
    </div>
  );
}

/**
 * CreatorSearchResult — Beautiful YouTube-style top creator/shop result card.
 * Shown above recipe results when search strongly matches a user or shop.
 */
import React, { useState, useRef } from "react";
import { base44 } from "@/api/base44Client";
import { createPageUrl } from "../../utils";
import { ShoppingBag, User, UserCheck, UserPlus, ExternalLink } from "lucide-react";
import { cn } from "@/lib/utils";
import { motion } from "framer-motion";

export default function CreatorSearchResult({ profile, shop, currentUserId, onDismiss }) {
  const [following, setFollowing] = useState(profile?.is_followed || false);
  const [followLoading, setFollowLoading] = useState(false);
  const inFlightRef = useRef(false);

  if (!profile && !shop) return null;

  // display_name is canonical — full_name is fallback only
  const displayName = (profile?.display_name || profile?.full_name || "").trim() || shop?.shop_name || "Chef";
  const username = profile?.username || "";
  const avatar = profile?.avatar_url || shop?.logo_image_url;
  const bio = profile?.bio || shop?.tagline || shop?.bio_long?.slice(0, 100) || "";
  const followerCount = profile?.follower_count || shop?.follower_count || 0;

  const handleFollow = async (e) => {
    e.stopPropagation();
    if (!profile?.id || followLoading || inFlightRef.current) return;
    inFlightRef.current = true;
    setFollowLoading(true);
    try {
      const res = await base44.functions.invoke("toggleFollowState", { target_user_id: profile.id });
      // Use authoritative response status, not just toggle
      const newStatus = res.data?.viewer_follow_status;
      setFollowing(newStatus === 'following');
    } catch { }
    setFollowLoading(false);
    setTimeout(() => { inFlightRef.current = false; }, 400);
  };

  const goToProfile = () => {
    if (profile?.id) window.location.href = createPageUrl("UserProfile") + `?userId=${profile.id}`;
  };
  const goToShop = () => {
    if (shop?.id) window.location.href = createPageUrl("Shop") + `?id=${shop.id}`;
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: -8 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -8 }}
      className="mx-5 mb-4 rounded-3xl overflow-hidden shadow-lg border border-orange-100"
      style={{ background: "linear-gradient(145deg, #fff7ed 0%, #ffffff 60%, #fef3c7 100%)" }}
    >
      {/* Top gradient accent */}
      <div className="h-1.5 w-full" style={{ background: "linear-gradient(90deg, #f97316, #ef4444, #f59e0b)" }} />

      <div className="p-4">
        {/* Label */}
        <div className="flex items-center justify-between mb-3">
          <span className="text-[10px] font-black uppercase tracking-widest text-orange-500">Top Creator Match</span>
          {onDismiss && (
            <button onClick={onDismiss} className="text-slate-300 hover:text-slate-400 transition-colors">
              <span className="text-xs">✕</span>
            </button>
          )}
        </div>

        {/* Profile row — full tappable area */}
        <button className="flex items-center gap-3 w-full text-left" onClick={goToProfile} style={{ cursor: profile?.id ? "pointer" : "default", background: 'none', border: 'none', padding: 0 }}>
          {/* Avatar */}
          <div className="relative flex-shrink-0">
            {avatar ? (
              <img src={avatar} alt={displayName} className="w-16 h-16 rounded-2xl object-cover border-2 border-white shadow-md" />
            ) : (
              <div className="w-16 h-16 rounded-2xl border-2 border-white shadow-md flex items-center justify-center text-2xl font-bold text-white"
                style={{ background: "linear-gradient(135deg, #f97316, #ef4444)" }}>
                {displayName[0]?.toUpperCase() || "?"}
              </div>
            )}
            {shop && (
              <div className="absolute -bottom-1 -right-1 w-6 h-6 rounded-lg flex items-center justify-center shadow-sm border border-white"
                style={{ background: "linear-gradient(135deg, #f97316, #ef4444)" }}>
                <ShoppingBag className="w-3 h-3 text-white" />
              </div>
            )}
          </div>

          {/* Info */}
          <div className="flex-1 min-w-0">
            <p className="font-bold text-slate-900 text-base leading-tight truncate">{displayName}</p>
            {username && <p className="text-xs text-slate-400 mt-0.5">@{username}</p>}
            {shop?.shop_name && (
              <p className="text-xs text-orange-600 font-semibold mt-0.5 flex items-center gap-1">
                <ShoppingBag className="w-3 h-3" />
                {shop.shop_name}
              </p>
            )}
            {followerCount > 0 && (
              <p className="text-[11px] text-slate-400 mt-0.5">{followerCount.toLocaleString()} followers</p>
            )}
          </div>
        </button>

        {/* Bio */}
        {bio && (
          <p className="text-xs text-slate-500 mt-3 leading-relaxed line-clamp-2">{bio}</p>
        )}

        {/* Actions */}
        <div className="flex gap-2 mt-4">
          {/* Follow button */}
          {profile?.id && profile.id !== currentUserId && (
            <button
              onClick={handleFollow}
              disabled={followLoading}
              className={cn(
                "flex-1 h-10 rounded-2xl text-xs font-bold flex items-center justify-center gap-1.5 transition-all",
                following
                  ? "bg-slate-100 text-slate-600 border border-slate-200"
                  : "text-white shadow-md shadow-orange-100"
              )}
              style={!following ? { background: "linear-gradient(135deg, #f97316, #ef4444)" } : {}}
            >
              {following ? <UserCheck className="w-3.5 h-3.5" /> : <UserPlus className="w-3.5 h-3.5" />}
              {following ? "Following" : "Follow"}
            </button>
          )}

          {/* View Shop */}
          {shop?.id && (
            <button
              onClick={goToShop}
              className="flex-1 h-10 rounded-2xl text-xs font-bold text-orange-600 bg-orange-50 border border-orange-200 hover:bg-orange-100 flex items-center justify-center gap-1.5 transition-all"
            >
              <ShoppingBag className="w-3.5 h-3.5" />
              View Shop
            </button>
          )}

          {/* View Profile */}
          {profile?.id && (
            <button
              onClick={goToProfile}
              className="h-10 w-10 rounded-2xl flex items-center justify-center bg-slate-100 border border-slate-200 text-slate-500 hover:bg-slate-200 transition-all flex-shrink-0"
            >
              <User className="w-4 h-4" />
            </button>
          )}
        </div>
      </div>
    </motion.div>
  );
}

