/**
 * PostCommentsSheet — bottom sheet for post comments.
 * Uses backend functions (service role) so reads/writes always work.
 */
import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Send, Loader2, MoreVertical, Pencil, Trash2, Check } from 'lucide-react';
import { base44 } from '@/api/base44Client';
import { cn } from '@/lib/utils';
import MentionInput from '../mentions/MentionInput';
import { useLocalization } from '@/services/localization/LocalizationContext';
import { useBottomNavLock } from '@/lib/bottomNavManager';

export default function PostCommentsSheet({ postId, onClose }) {
  const { t } = useLocalization();
  const [comments, setComments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [text, setText] = useState('');
  const [sending, setSending] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);
  const [menuOpen, setMenuOpen] = useState(null); // comment id
  const [editingId, setEditingId] = useState(null);
  const [editText, setEditText] = useState('');
  const bottomRef = useRef(null);

  // Lock bottom nav while comments sheet is mounted
  useBottomNavLock(true);

  const timeAgo = (iso) => {
    const diff = (Date.now() - new Date(iso).getTime()) / 1000;
    if (diff < 60) return t('time.just_now', 'just now');
    if (diff < 3600) return `${Math.floor(diff / 60)}${t('time.m_ago', 'm ago')}`;
    if (diff < 86400) return `${Math.floor(diff / 3600)}${t('time.h_ago', 'h ago')}`;
    return `${Math.floor(diff / 86400)}${t('time.d_ago', 'd ago')}`;
  };

  useEffect(() => {
    document.body.style.overflow = 'hidden';
    base44.auth.me().then(setCurrentUser).catch(() => {});
    return () => { document.body.style.overflow = ''; };
  }, []);



  // Android hardware back closes this sheet
  useEffect(() => {
    const handleBack = (e) => { e.preventDefault(); onClose(); };
    window.addEventListener('popstate', handleBack);
    return () => window.removeEventListener('popstate', handleBack);
  }, [onClose]);

  useEffect(() => {
    if (!postId) return;
    setLoading(true);
    base44.functions.invoke('getPostComments', { post_id: postId })
      .then(res => setComments(res.data?.comments || []))
      .catch(() => setComments([]))
      .finally(() => setLoading(false));
  }, [postId]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [comments.length]);

  const handleDelete = async (commentId) => {
    setMenuOpen(null);
    try {
      await base44.functions.invoke('deletePostComment', { comment_id: commentId });
      setComments(prev => prev.filter(c => c.id !== commentId));
    } catch (e) { console.error('Delete failed:', e); }
  };

  const handleEditSave = async (commentId) => {
    if (!editText.trim()) return;
    try {
      const res = await base44.functions.invoke('editPostComment', { comment_id: commentId, body: editText.trim() });
      if (res.data?.comment) {
        setComments(prev => prev.map(c => c.id === commentId ? { ...c, body: editText.trim(), is_edited: true } : c));
      }
    } catch (e) { console.error('Edit failed:', e); }
    setEditingId(null);
    setEditText('');
  };

  const handleSend = async () => {
    if (!text.trim() || sending) return;
    setSending(true);
    const body = text.trim();
    setText('');
    try {
      const res = await base44.functions.invoke('createPostComment', { post_id: postId, body });
      if (res.data?.comment) {
        setComments(prev => [...prev, res.data.comment]);
      }
      // Fire mention notifications (non-blocking)
      base44.functions.invoke('sendMentionNotifications', {
        content: body,
        context_type: 'comment',
        context_id: postId,
      }).catch(() => {});
    } catch (e) {
      console.error('Comment failed:', e);
      setText(body);
    } finally {
      setSending(false);
    }
  };

  return (
    <>
      <motion.div
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        className="fixed inset-0 z-[80] bg-black/50"
        onClick={onClose}
      />
      <motion.div
        initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }}
        transition={{ type: 'spring', damping: 30, stiffness: 300 }}
        className="fixed inset-x-0 bottom-0 z-[81] bg-white rounded-t-3xl flex flex-col"
        style={{ maxHeight: '85vh', overscrollBehavior: 'contain', paddingBottom: 'env(safe-area-inset-bottom, 0px)' }}
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-5 pt-4 pb-3 border-b border-slate-100 flex-shrink-0">
          <h3 className="text-base font-bold text-slate-900">{t('comments.title','Comments')} {comments.length > 0 ? `(${comments.length})` : ''}</h3>
          <button onClick={onClose} className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center">
            <X className="w-4 h-4 text-slate-500" />
          </button>
        </div>

        {/* Comments list */}
        <div className="flex-1 overflow-y-auto px-5 py-3 space-y-4" style={{ overscrollBehavior: 'contain' }}>
          {loading ? (
            <div className="flex justify-center py-8">
              <Loader2 className="w-6 h-6 text-slate-300 animate-spin" />
            </div>
          ) : comments.length === 0 ? (
            <div className="text-center py-10 text-slate-400 text-sm">{t('comments.empty','No comments yet. Be the first!')}</div>
          ) : (
            comments.map(c => (
              <div key={c.id} className="flex gap-3 relative">
                <div className="w-8 h-8 rounded-full bg-gradient-to-br from-indigo-400 to-purple-500 flex items-center justify-center text-white text-xs font-bold flex-shrink-0 overflow-hidden">
                  {c.author_avatar ? (
                    <img src={c.author_avatar} alt="" className="w-full h-full object-cover" />
                  ) : (
                    (c.author_name || 'U')[0].toUpperCase()
                  )}
                </div>
                <div className="flex-1">
                  <div className="flex items-baseline gap-2">
                    <span className="text-xs font-bold text-slate-800">{c.author_name || t('common.user','User')}</span>
                    <span className="text-[10px] text-slate-400">{timeAgo(c.created_date)}</span>
                    {c.is_edited && <span className="text-[9px] text-slate-400 italic">{t('common.edited','edited')}</span>}
                  </div>
                  {editingId === c.id ? (
                    <div className="flex items-center gap-1 mt-1">
                      <input
                        autoFocus
                        value={editText}
                        onChange={e => setEditText(e.target.value)}
                        onKeyDown={e => { if (e.key === 'Enter') handleEditSave(c.id); if (e.key === 'Escape') setEditingId(null); }}
                        className="flex-1 text-sm bg-slate-100 rounded-xl px-3 py-1 outline-none"
                      />
                      <button onClick={() => handleEditSave(c.id)} className="w-6 h-6 rounded-full bg-indigo-600 flex items-center justify-center flex-shrink-0">
                        <Check className="w-3 h-3 text-white" />
                      </button>
                      <button onClick={() => setEditingId(null)} className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center flex-shrink-0">
                        <X className="w-3 h-3 text-slate-500" />
                      </button>
                    </div>
                  ) : (
                    <p className="text-sm text-slate-700 mt-0.5 leading-relaxed">{c.body}</p>
                  )}
                </div>
                {currentUser?.id === c.author_id && (
                  <div className="relative flex-shrink-0">
                    <button onClick={() => setMenuOpen(menuOpen === c.id ? null : c.id)} className="w-6 h-6 flex items-center justify-center text-slate-300 hover:text-slate-500">
                      <MoreVertical className="w-3.5 h-3.5" />
                    </button>
                    <AnimatePresence>
                      {menuOpen === c.id && (
                        <motion.div
                          initial={{ opacity: 0, scale: 0.9, y: -4 }}
                          animate={{ opacity: 1, scale: 1, y: 0 }}
                          exit={{ opacity: 0, scale: 0.9, y: -4 }}
                          className="absolute right-0 top-7 z-10 bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden w-36"
                        >
                          <button onClick={() => { setEditText(c.body); setEditingId(c.id); setMenuOpen(null); }} className="w-full flex items-center gap-2 px-3 py-2.5 text-sm text-slate-700 hover:bg-slate-50">
                                          <Pencil className="w-3.5 h-3.5 text-slate-400" /> {t('action.edit','Edit')}
                                        </button>
                                        <button onClick={() => handleDelete(c.id)} className="w-full flex items-center gap-2 px-3 py-2.5 text-sm text-rose-500 hover:bg-rose-50 border-t border-slate-50">
                                          <Trash2 className="w-3.5 h-3.5" /> {t('action.delete','Delete')}
                                        </button>
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </div>
                )}
              </div>
            ))
          )}
          <div ref={bottomRef} className="pb-2" />
        </div>

        {/* Composer */}
        <div className="border-t border-slate-100 px-4 py-3 flex items-end gap-2 flex-shrink-0">
          <div className="flex-1 bg-slate-100 rounded-2xl px-3 py-2.5">
            <MentionInput
              value={text}
              onChange={setText}
              onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
              placeholder={t('comments.placeholder','Add a comment... (@ to mention)')}
              rows={1}
              className="w-full bg-transparent text-sm text-slate-900 resize-none outline-none max-h-20"
            />
          </div>
          <button
            onClick={handleSend}
            disabled={!text.trim() || sending}
            className="w-10 h-10 rounded-2xl flex items-center justify-center flex-shrink-0 disabled:opacity-40 transition-all"
            style={{ background: text.trim() ? 'linear-gradient(135deg,#6366f1,#8b5cf6)' : '#f1f5f9' }}
          >
            {sending ? <Loader2 className="w-4 h-4 text-white animate-spin" /> : <Send className={cn("w-4 h-4", text.trim() ? "text-white" : "text-slate-400")} />}
          </button>
        </div>
      </motion.div>
    </>
  );
}

import React, { useState } from "react";
import { resolveAvatarUrl } from "../../utils/avatarResolver";
import { useAuthorIdentity } from "../recipe/useAuthorIdentity";
import { motion } from "framer-motion";
import { Heart, Bookmark, Clock, ChefHat, MoreVertical, Play } from "lucide-react";
import { createPageUrl } from "../../utils";
import { base44 } from "@/api/base44Client";
import { detectAllergens } from "./AllergenDetector";
import { cn } from "@/lib/utils";
import IconBadge from "../ui-custom/IconBadge";
import TagPill from "../ui-custom/TagPill";
import { useLikeUnified } from "@/components/hooks/useLikeUnified";

/**
 * PremiumRecipeCard: locked, production-ready component
 * - Strict proportions: 16:9 image, consistent padding
 * - Tag overflow handled with +N pill (never wraps)
 * - Action buttons with proper hit targets
 * - Responsive across all screen sizes
 * - No random layout shifts
 */
export default function PremiumRecipeCard({
  recipe,
  currentUser = null,
  likedIds = new Set(),
  savedIds = new Set(),
  userAllergens = [],
  onLike,
  onSave,
  onOpenMenu,
  onClick,
}) {
  const { displayName: authorName, avatarUrl: authorAvatar } = useAuthorIdentity(recipe, currentUser);
  const [imageError, setImageError] = useState(false);
  const { allergen_tags } = detectAllergens(recipe.ingredients || []);
  const hasWarning = userAllergens.length > 0 && allergen_tags.some(a => userAllergens.includes(a));
  const totalTime = (recipe.cook_time || 0) + (recipe.prep_time || 0);

  // Unified like store — shares the same global key as RecipeCard + RecipeDetail
  const { viewer_has_liked: isLiked, like_count: likesCount, disabled: likeBlocked, toggleLike } = useLikeUnified(
    'recipe',
    recipe.id,
    likedIds.has(recipe.id),
    recipe.likes_count ?? 0
  );

  // Tag logic: show max 2, rest in +N
  const visibleTags = recipe.tags?.slice(0, 2) || [];
  const hiddenTagCount = Math.max(0, (recipe.tags?.length || 0) - 2);

  const mapTagColor = (tag) => {
    const colorMap = {
      vegan: "vegan",
      vegetarian: "vegetarian",
      "gluten-free": "gluten-free",
      "dairy-free": "dairy-free",
      keto: "keto",
      "high-protein": "high-protein",
      "low-carb": "low-carb",
    };
    return colorMap[tag] || "slate";
  };

  const handleNavigateToAuthor = (e) => {
    e.stopPropagation();
    if (recipe.created_by) {
      base44.entities.User.filter({ email: recipe.created_by }).then(users => {
        if (users.length > 0) {
          window.location.href = createPageUrl("UserProfile") + `?userId=${users[0].id}`;
        }
      });
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      onClick={onClick}
      className="bg-white rounded-3xl overflow-hidden shadow-sm border border-slate-100 cursor-pointer hover:shadow-md active:scale-[0.98] transition-all flex flex-col h-full"
    >
      {/* Image Container — 16:9 aspect ratio, strict */}
      <div className="relative w-full bg-slate-200 overflow-hidden" style={{ aspectRatio: "16/9" }}>
        {!imageError && (
          <img
            src={recipe.hero_image_url || "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=800&h=450&fit=crop"}
            alt={recipe.title}
            className="w-full h-full object-cover"
            onError={() => setImageError(true)}
          />
        )}
        {imageError && (
          <div className="w-full h-full bg-gradient-to-br from-slate-300 to-slate-400 flex items-center justify-center">
            <ChefHat className="w-8 h-8 text-slate-500 opacity-50" />
          </div>
        )}

        {/* Overlay gradient */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/30 via-transparent to-transparent" />

        {/* Top-left menu button */}
        {onOpenMenu && (
          <motion.button
            whileTap={{ scale: 0.9 }}
            onClick={(e) => {
              e.stopPropagation();
              onOpenMenu(recipe);
            }}
            className="absolute top-3 left-3 z-10"
          >
            <IconBadge icon={MoreVertical} color="white" size="md" />
          </motion.button>
        )}

        {/* Top-right save button */}
        {onSave && (
          <motion.button
            whileTap={{ scale: 0.9 }}
            onClick={(e) => {
              e.stopPropagation();
              onSave(recipe);
            }}
            className="absolute top-3 right-3 z-10"
          >
            <div className={cn(
              "w-8 h-8 rounded-lg flex items-center justify-center shadow-md",
              savedIds.has(recipe.id) ? "bg-amber-500 text-white" : "bg-white/90 text-slate-600"
            )}>
              <Bookmark className={cn("w-4 h-4", savedIds.has(recipe.id) && "fill-current")} strokeWidth={2} />
            </div>
          </motion.button>
        )}

        {/* Allergen warning (if needed) */}
        {hasWarning && (
          <div className="absolute top-3 right-16 bg-rose-500 text-white text-[10px] font-bold px-2.5 py-1 rounded-full shadow-md flex items-center gap-1">
            <span>⚠</span>Allergen
          </div>
        )}

        {/* Bottom-left badges: time + difficulty */}
        <div className="absolute bottom-3 left-3 flex gap-2 flex-wrap">
          {totalTime > 0 && (
            <div className="flex items-center gap-1.5 bg-blue-600/90 backdrop-blur-sm text-white text-[10px] font-bold px-2.5 py-1.5 rounded-xl">
              <Clock className="w-3.5 h-3.5" strokeWidth={2} />
              {totalTime}m
            </div>
          )}
          {recipe.difficulty && (
            <div
              className="text-[10px] font-bold px-2.5 py-1.5 rounded-xl backdrop-blur-sm text-white"
              style={{
                background:
                  recipe.difficulty === "easy"
                    ? "rgba(16, 185, 129, 0.9)"
                    : recipe.difficulty === "medium"
                    ? "rgba(245, 158, 11, 0.9)"
                    : "rgba(239, 68, 68, 0.9)",
              }}
            >
              {recipe.difficulty.charAt(0).toUpperCase() + recipe.difficulty.slice(1)}
            </div>
          )}
        </div>
      </div>

      {/* Content Section */}
      <div className="flex flex-col flex-1 p-4 gap-3">
        {/* Tags Row — strict single line with +N overflow */}
        {(visibleTags.length > 0 || hiddenTagCount > 0) && (
          <div className="flex items-center gap-1.5 flex-wrap min-h-[20px] max-h-[24px] overflow-hidden">
            {visibleTags.map(t => (
              <TagPill key={t} label={t} color={mapTagColor(t)} size="xs" />
            ))}
            {hiddenTagCount > 0 && (
              <TagPill label={`+${hiddenTagCount}`} color="slate_dark" size="xs" />
            )}
          </div>
        )}

        {/* Title — max 2 lines */}
        <h3 className="text-sm font-bold text-slate-900 line-clamp-2 leading-tight">
          {recipe.title}
        </h3>

        {/* Cooked Count */}
        {recipe.cooked_count_unique_users > 0 && (
          <div className="text-[10px] text-slate-500 font-medium">
            ✓ Cooked by {recipe.cooked_count_unique_users}
          </div>
        )}

        {/* Nutrition Info — TOTAL recipe calories/protein */}
        {(() => {
          const s = Math.max(1, recipe.servings || 1);
          const t = recipe.nutrition_total_for_recipe;
          const ps = recipe.nutrition_per_serving;
          const leg = recipe.nutrition;
          const cal = t?.calories > 0 ? Math.round(t.calories)
            : ps?.calories > 0 ? Math.round(ps.calories * s)
            : leg?.calories > 0 ? Math.round(leg.calories) : 0;
          const prot = t?.calories > 0 ? Math.round(t.protein ?? t.protein_g ?? 0)
            : ps?.calories > 0 ? Math.round((ps.protein ?? ps.protein_g ?? 0) * s)
            : leg?.calories > 0 ? Math.round(leg.protein ?? leg.protein_g ?? 0) : 0;
          if (!cal) return null;
          return (
            <div className="text-[10px] text-slate-500 font-medium space-y-0.5">
              <div>🔥 {cal} cal</div>
              {prot > 0 && <div>⚡ {prot}g protein</div>}
            </div>
          );
        })()}

        {/* Author Section */}
        <div className="mt-auto pt-3 border-t border-slate-100">
          <motion.button
            whileTap={{ scale: 0.98 }}
            onClick={handleNavigateToAuthor}
            className="flex items-center gap-2.5 w-full group"
          >
            <div className="w-7 h-7 rounded-full bg-gradient-to-br from-violet-400 to-pink-400 flex items-center justify-center flex-shrink-0 border border-violet-300 shadow-sm overflow-hidden">
              {authorAvatar ? (
                <img src={authorAvatar} alt="" className="w-full h-full object-cover" />
              ) : (
                <span className="text-xs font-bold text-white">
                  {(authorName || "C").charAt(0).toUpperCase()}
                </span>
              )}
            </div>
            <span className="text-[11px] text-slate-600 font-medium truncate group-hover:text-indigo-600 transition-colors">
              {authorName || "Unknown Chef"}
            </span>
          </motion.button>
        </div>

        {/* Action Buttons */}
        <div className="flex items-center gap-2 mt-3 pt-3 border-t border-slate-100 min-h-[44px]">
          {/* Like Button — unified store, same key as RecipeCard + RecipeDetail */}
          <motion.button
            whileTap={likeBlocked ? {} : { scale: 0.95 }}
            disabled={likeBlocked}
            onClick={async (e) => {
              e.stopPropagation();
              if (likeBlocked) return;
              await toggleLike(e);
              onLike?.(recipe);
            }}
            className={cn(
              "flex items-center gap-1.5 px-3 py-2.5 rounded-xl font-semibold text-[11px] transition-all",
              isLiked
                ? "bg-rose-100 text-rose-600"
                : "bg-slate-100 text-slate-600 hover:bg-slate-150",
              likeBlocked && "opacity-60"
            )}
          >
            <Heart className={cn("w-3.5 h-3.5", isLiked && "fill-current")} strokeWidth={2} />
            <span className="tabular-nums">{likesCount}</span>
          </motion.button>

          {/* Cook Button — Primary gradient */}
          {recipe.id && (
            <motion.a
              whileTap={{ scale: 0.95 }}
              href={createPageUrl("CookMode") + `?id=${recipe.id}`}
              onClick={(e) => e.stopPropagation()}
              className="flex-1 h-11 rounded-xl flex items-center justify-center gap-2 font-bold text-white text-[11px] shadow-md hover:shadow-lg active:scale-95 transition-all"
              style={{
                background: "linear-gradient(135deg, #6366f1 0%, #8b5cf6 50%, #a855f7 100%)",
              }}
            >
              <Play className="w-4 h-4 fill-current" strokeWidth={2} />
              Cook
            </motion.a>
          )}

          {/* View Button — Secondary */}
          {recipe.id && (
            <motion.a
              whileTap={{ scale: 0.95 }}
              href={createPageUrl("RecipeDetail") + `?id=${recipe.id}`}
              onClick={(e) => e.stopPropagation()}
              className="h-11 px-3.5 rounded-xl bg-slate-100 text-slate-700 font-semibold text-[11px] hover:bg-slate-200 transition-all"
            >
              View
            </motion.a>
          )}
        </div>
      </div>
    </motion.div>
  );
}

import React, { useState, useEffect } from "react";
import ReactDOM from "react-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Edit, Trash2, AlertTriangle, Eye, Flag, X } from "lucide-react";
import { cn } from "@/lib/utils";
import { useLocalization } from "@/services/localization/LocalizationContext";
import { useBottomNavLock } from "@/lib/bottomNavManager";

export default function CardMenuSheet({ isOpen, onClose, isOwner, recipeName, onEdit, onDelete, onReport, onNotInterested }) {
  const { t } = useLocalization();
  const [confirmDelete, setConfirmDelete] = useState(false);

  // Android back button closes this sheet
  useEffect(() => {
    if (!isOpen) return;
    const handleBack = (e) => { e.preventDefault(); onClose?.(); };
    window.addEventListener('popstate', handleBack);
    return () => window.removeEventListener('popstate', handleBack);
  }, [isOpen, onClose]);

  // Lock bottom nav while sheet is open via reference-counted manager
  useBottomNavLock(!!isOpen);

  // Belt-and-suspenders: also directly hide the nav element via inline styles
  // This catches edge cases where the CSS class approach has specificity issues
  useEffect(() => {
    if (!isOpen) return;
    const nav = document.querySelector('[data-bottom-nav]');
    if (nav) {
      nav.style.display = 'none';
      nav.style.visibility = 'hidden';
      nav.style.pointerEvents = 'none';
    }
    return () => {
      if (nav) {
        nav.style.display = '';
        nav.style.visibility = '';
        nav.style.pointerEvents = '';
      }
    };
  }, [isOpen]);

  const handleDelete = () => {
    onDelete?.();
    onClose?.();
  };

  const handleReport = () => {
    onReport?.();
    onClose?.();
  };

  const handleNotInterested = () => {
    onNotInterested?.();
    onClose?.();
  };

  // Render via portal into overlay-portal so PullToRefresh overlay detection works
  // and body scroll/touch locks engage correctly.
  const portalTarget = typeof document !== 'undefined'
    ? (document.getElementById('overlay-portal') || document.body)
    : null;

  if (!portalTarget) return null;

  return ReactDOM.createPortal(
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black/40 backdrop-blur-sm"
            style={{ zIndex: 9995 }}
          />

          {/* Bottom sheet */}
          <motion.div
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 40 }}
            transition={{ type: "spring", damping: 25, stiffness: 300 }}
            className="fixed inset-x-0 bottom-0 bg-white rounded-t-3xl shadow-2xl"
            style={{ zIndex: 9996 }}
          >
            {/* Handle bar */}
            <div className="flex justify-center pt-3 pb-2">
              <div className="w-10 h-1 rounded-full bg-slate-200" />
            </div>

            {/* Content */}
            <div className="px-5 pb-6 max-h-[70vh] overflow-y-auto" style={{ overscrollBehavior: 'contain', paddingBottom: 'max(24px, env(safe-area-inset-bottom, 24px))' }}>
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-bold text-slate-900 truncate">{recipeName}</h3>
                <button onClick={onClose} aria-label="Close menu" className="w-11 h-11 flex items-center justify-center hover:bg-slate-100 rounded-xl transition-colors">
                  <X className="w-4 h-4 text-slate-500" />
                </button>
              </div>

              {!confirmDelete ? (
                <div className="space-y-2">
                  {isOwner ? (
                    <>
                      <motion.button
                        whileTap={{ scale: 0.98 }}
                        onClick={() => { onEdit?.(); onClose?.(); }}
                        className="w-full flex items-center gap-3 px-4 py-3.5 rounded-xl hover:bg-slate-50 transition-colors text-slate-900 font-medium"
                      >
                        <Edit className="w-5 h-5 text-indigo-600" />
                        <span>{t('action.edit', 'Edit Recipe')}</span>
                      </motion.button>

                      <motion.button
                        whileTap={{ scale: 0.98 }}
                        onClick={() => setConfirmDelete(true)}
                        className="w-full flex items-center gap-3 px-4 py-3.5 rounded-xl hover:bg-red-50 transition-colors text-red-600 font-medium"
                      >
                        <Trash2 className="w-5 h-5" />
                        <span>{t('action.delete', 'Delete Recipe')}</span>
                      </motion.button>
                    </>
                  ) : (
                    <>
                      <motion.button
                        whileTap={{ scale: 0.98 }}
                        onClick={handleNotInterested}
                        className="w-full flex items-center gap-3 px-4 py-3.5 rounded-xl hover:bg-slate-50 transition-colors text-slate-900 font-medium"
                      >
                        <Eye className="w-5 h-5 text-slate-500" />
                        <span>{t('action.not_interested', 'Not Interested')}</span>
                      </motion.button>

                      <motion.button
                        whileTap={{ scale: 0.98 }}
                        onClick={handleReport}
                        className="w-full flex items-center gap-3 px-4 py-3.5 rounded-xl hover:bg-red-50 transition-colors text-red-600 font-medium"
                      >
                        <Flag className="w-5 h-5" />
                        <span>{t('report.title', 'Report Recipe')}</span>
                      </motion.button>
                    </>
                  )}
                </div>
              ) : (
                <motion.div
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  className="py-4"
                >
                  <div className="flex items-start gap-3 p-4 bg-red-50 rounded-xl mb-4 border border-red-200">
                    <AlertTriangle className="w-5 h-5 text-red-600 flex-shrink-0 mt-0.5" />
                    <div>
                      <p className="text-sm font-semibold text-red-900 mb-1">{t('action.delete_confirm_title', 'Delete Recipe?')}</p>
                      <p className="text-xs text-red-700">{t('action.delete_confirm_body', 'This action cannot be undone. All comments and likes will be lost.')}</p>
                    </div>
                  </div>

                  <div className="flex gap-2">
                    <motion.button
                      whileTap={{ scale: 0.98 }}
                      onClick={() => setConfirmDelete(false)}
                      className="flex-1 h-11 rounded-xl bg-slate-100 text-slate-900 font-semibold hover:bg-slate-200 transition-colors"
                      >
                       {t('report.cancel', 'Cancel')}
                      </motion.button>
                      <motion.button
                       whileTap={{ scale: 0.98 }}
                       onClick={handleDelete}
                       className="flex-1 h-11 rounded-xl bg-red-600 text-white font-semibold hover:bg-red-700 transition-colors"
                      >
                       {t('action.delete', 'Delete')}
                    </motion.button>
                  </div>
                </motion.div>
              )}
            </div>

            {/* Safe area for iPhones */}
            <div style={{ height: 'env(safe-area-inset-bottom, 0px)' }} />
          </motion.div>
        </>
      )}
    </AnimatePresence>,
    portalTarget
  );
}

import React, { useState, useEffect } from 'react';
import { resolveAvatarUrl } from '../../utils/avatarResolver';
import { Heart, MessageCircle, Bookmark, Share2, ImageIcon, Globe, ShoppingCart, Check as CheckIcon } from 'lucide-react';
import { base44 } from '@/api/base44Client';
import { cn } from '@/lib/utils';
import { createPageUrl } from '../../utils';
import { navigateToPost } from '../../lib/postNavigation';
import { AnimatePresence } from 'framer-motion';
import PostCommentsSheet from './PostCommentsSheet';
import { useLikeUnified } from '../hooks/useLikeUnified';
import { useSaveUnified } from '../hooks/useSaveUnified';
import { usePostContent } from '@/components/localization/useRecipeContent';
import { useLocalization } from '@/services/localization/LocalizationContext';

const DIFFICULTY_STYLES = {
  easy: { bg: "#dcfce7", text: "#166534", labelKey: "recipe.easy", labelFallback: "Easy" },
  medium: { bg: "#fef3c7", text: "#92400e", labelKey: "recipe.medium", labelFallback: "Medium" },
  hard: { bg: "#fee2e2", text: "#991b1b", labelKey: "recipe.hard", labelFallback: "Hard" },
};

export default function PostCard({ post, onLike, onSave }) {
  // HARDENED: Use 'recipe' target_type with recipe_id (or post.id as fallback).
  // The community feed enriches viewer_has_liked by querying Like { target_type: 'recipe' }.
  // PostCard MUST use the same target_type/id so the global store key matches VipRecipeCard
  // and feed enrichment. Using 'post' would create a separate store key and a separate
  // Like entity record that feed enrichment never reads → heart desync.
  const likeTargetId = post.recipe_id || post.id;
  const { viewer_has_liked: liked, like_count: likeCount, disabled: liking, toggleLike } = useLikeUnified(
    'recipe',
    likeTargetId,
    post.viewer_has_liked === true,
    post.like_count || 0
  );
  // Use unified save store — persists across surfaces, no stale local state
  const { viewer_has_saved: saved, disabled: saveBlocked, toggleSave } = useSaveUnified(
    post.id,
    post.viewer_has_saved === true,
    post.save_count || post.saves_count || 0
  );
  const [commentCount, setCommentCount] = useState(post.comment_count || 0);
  const [showComments, setShowComments] = useState(false);
  const [cartState, setCartState] = useState("idle"); // idle | adding | added
  const postContent = usePostContent(post);
  const { resolvedLang, t } = useLocalization();

  // Show "Original language" badge when user's UI language differs from post language
  // Posts are ALWAYS shown in original language — no fake translation implied.
  // Badge appears only when the app lang is not English (posts default to EN)
  // OR when the post has a known non-English original.
  const showOriginalLangBadge = resolvedLang && resolvedLang !== 'en' && postContent?.language_used === 'en';

  // Track impression only when visible (IntersectionObserver) to avoid firing for off-screen items
  useEffect(() => {
    let timer;
    const el = document.getElementById(`post-card-${post.id}`);
    if (!el) return;
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting) {
        timer = setTimeout(() => {
          base44.functions.invoke('trackPostEvent', { post_id: post.id, event_type: 'impression' }).catch(() => {});
        }, 1000);
        observer.disconnect();
      }
    }, { threshold: 0.5 });
    observer.observe(el);
    return () => { observer.disconnect(); clearTimeout(timer); };
  }, [post.id]);

  const handleLike = (e) => {
    e.stopPropagation();
    if (liking) return;
    toggleLike(e).then(() => {
      onLike?.(post.id, liked);
    });
  };

  const handleSave = async (e) => {
    e.stopPropagation();
    if (saveBlocked) return;
    await toggleSave(e);
    onSave?.(post.id, !saved);
  };

  const handleOpen = () => {
    base44.functions.invoke('trackPostEvent', { post_id: post.id, event_type: 'open' }).catch(() => {});
    if (post.recipe_id) {
      navigateToPost({
        recipeId: post.recipe_id,
        postId: post.id,
        moderationStatus: post.moderation_status,
        viewerId: null, // PostCard doesn't receive viewer — safety net in RecipeDetail handles it
        ownerId: post.author_id,
      });
    }
  };

  const handleAddToGroceries = async (e) => {
    e.stopPropagation();
    if (cartState !== "idle") return;
    // Need ingredients — resolve from recipe_id
    const recipeId = post.recipe_id;
    if (!recipeId) return;
    setCartState("adding");
    try {
      // Fetch recipe to get ingredients with pricing
      const recipes = await base44.entities.Recipe.filter({ id: recipeId }).catch(() => []);
      const recipe = recipes[0];
      if (!recipe?.ingredients?.length) { setCartState("idle"); return; }
      const allItems = recipe.ingredients.flatMap(g => (g.items || []).filter(i => !i.optional));
      const existing = await base44.entities.ShoppingList.filter({ recipe_id: recipeId }).catch(() => []);
      const existingNames = new Set(existing.map(e => e.name?.toLowerCase()));
      const toAdd = allItems.filter(i => !existingNames.has(i.name?.toLowerCase()));
      if (toAdd.length > 0) {
        await base44.entities.ShoppingList.bulkCreate(
          toAdd.map(i => ({
            name: i.name,
            amount: i.amount || "",
            recipe_id: recipeId,
            recipe_title: recipe.title || post.title,
            is_bought: false,
            cost: i.ingredient_cost || null,
          }))
        );
      }
      setCartState("added");
      setTimeout(() => setCartState("idle"), 2500);
    } catch {
      setCartState("idle");
    }
  };

  const handleAuthorClick = (e) => {
    e.stopPropagation();
    if (post.author_id) {
      window.location.href = createPageUrl('UserProfile') + `?userId=${post.author_id}`;
    }
  };

  const handleCommentClick = (e) => {
    e.stopPropagation();
    setShowComments(true);
  };

  return (
    <>
      <div
        id={`post-card-${post.id}`}
        className="bg-white rounded-2xl shadow-sm hover:shadow-md transition-shadow overflow-hidden cursor-pointer border border-slate-100"
        onClick={handleOpen}
      >
        {/* Header */}
        <div className="p-3.5 border-b border-slate-100 flex items-center gap-3">
          {/* Hero icon square */}
          <div 
            className="w-12 h-12 rounded-xl flex-shrink-0 flex items-center justify-center overflow-hidden border border-slate-200"
            style={{
              background: post.media_url 
                ? `url(${post.media_url}) center / cover` 
                : "linear-gradient(135deg, #e0e7ff, #f3e8ff)",
              boxShadow: "0 2px 8px rgba(0,0,0,0.08)"
            }}
          >
            {!post.media_url && (
              <ImageIcon className="w-5 h-5 text-slate-300" />
            )}
          </div>

          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-0.5">
              <button onClick={handleAuthorClick} className="w-7 h-7 rounded-full bg-gradient-to-br from-indigo-400 to-purple-400 flex-shrink-0 overflow-hidden">
                {resolveAvatarUrl(post.author_avatar) ? (
                  <img src={resolveAvatarUrl(post.author_avatar)} alt="" className="w-full h-full object-cover" />
                ) : (
                  <span className="w-full h-full flex items-center justify-center text-white text-xs font-bold">
                    {(post.author_name?.trim() || '?')[0].toUpperCase()}
                  </span>
                )}
              </button>
              <button onClick={handleAuthorClick} className="text-sm font-semibold text-slate-900 hover:text-indigo-600 transition-colors text-left truncate">
                {post.author_name || t('common.unknown','Unknown')}
              </button>
            </div>
            <p className="text-xs text-slate-500">{post.created_date || post.created_at ? new Date(post.created_date || post.created_at).toLocaleDateString() : ''}</p>
          </div>
        </div>

        {/* Media — full size below header */}
        {post.media_url && (
          <div
            className="w-full h-64 bg-slate-100 overflow-hidden"
            onContextMenu={e => e.preventDefault()}
          >
            <img
              src={post.media_url}
              alt={post.title}
              draggable={false}
              className="w-full h-full object-cover"
              loading="lazy"
              style={{ WebkitTouchCallout: 'none', pointerEvents: 'none' }}
            />
          </div>
        )}

        {/* Content */}
        <div className="p-4">
          <h3 className="font-semibold text-slate-900 mb-2 line-clamp-2">{postContent?.title || post.title}</h3>
          <p className="text-sm text-slate-600 line-clamp-3">{postContent?.body || post.body}</p>

          <div className="flex gap-2 mt-3 flex-wrap items-center">
            {post.difficulty && (
              <span className="text-xs font-bold px-2 py-1 rounded-full"
                style={{ background: DIFFICULTY_STYLES[post.difficulty]?.bg, color: DIFFICULTY_STYLES[post.difficulty]?.text }}>
                {DIFFICULTY_STYLES[post.difficulty] ? t(DIFFICULTY_STYLES[post.difficulty].labelKey, DIFFICULTY_STYLES[post.difficulty].labelFallback) : post.difficulty}
              </span>
            )}
            {post.tags?.slice(0, 2).map(tag => (
              <span key={tag} className="text-xs bg-slate-100 text-slate-600 px-2 py-1 rounded-full">#{tag}</span>
            ))}
            {showOriginalLangBadge && (
              <span className="flex items-center gap-1 text-[10px] text-slate-400 bg-slate-50 border border-slate-200 px-2 py-0.5 rounded-full">
                <Globe className="w-2.5 h-2.5" />
                {t('post.original_lang','Original')}
              </span>
            )}
          </div>
        </div>

        {/* Actions */}
        <div className="p-4 border-t border-slate-100 flex items-center justify-between gap-1">
          <button
            aria-label={liked ? "Unlike post" : "Like post"}
            onClick={handleLike}
            disabled={liking}
            className={cn(
              'flex items-center gap-2 text-sm font-medium rounded-lg px-3 py-2 transition-colors min-h-[44px]',
              liked ? 'text-rose-600 bg-rose-50' : 'text-slate-600 hover:bg-slate-50'
            )}
          >
            <Heart className={cn('w-4 h-4', liked && 'fill-current')} />
            {likeCount}
          </button>

          <button
            aria-label="View comments"
            onClick={handleCommentClick}
            className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:bg-slate-50 rounded-lg px-3 py-2 transition-colors min-h-[44px]"
          >
            <MessageCircle className="w-4 h-4" />
            {commentCount}
          </button>

          <button
            aria-label={saved ? "Unsave post" : "Save post"}
            onClick={handleSave}
            disabled={saveBlocked}
            className={cn(
              'flex items-center gap-2 text-sm font-medium rounded-lg px-3 py-2 transition-colors min-h-[44px]',
              saved ? 'text-amber-600 bg-amber-50' : 'text-slate-600 hover:bg-slate-50'
            )}
          >
            <Bookmark className={cn('w-4 h-4', saved && 'fill-current')} />
          </button>

          {/* Grocery cart — add all ingredients to shopping list */}
          {post.recipe_id && (
            <button
              aria-label={t('shopping.add_ingredients','Add ingredients to shopping list')}
              onClick={handleAddToGroceries}
              className={cn(
                'flex items-center justify-center w-10 h-10 rounded-lg transition-colors',
                cartState === "added" ? 'text-emerald-600 bg-emerald-50' : 'text-emerald-500 hover:bg-emerald-50'
              )}
            >
              {cartState === "adding" ? (
                <span className="w-4 h-4 rounded-full border-2 border-emerald-400 border-t-transparent animate-spin" />
              ) : cartState === "added" ? (
                <CheckIcon className="w-4 h-4" strokeWidth={3} />
              ) : (
                <ShoppingCart className="w-4 h-4" />
              )}
            </button>
          )}

          <button
            aria-label="Share post"
            onClick={(e) => {
              e.stopPropagation();
              const shareUrl = post.recipe_id
                ? `https://reciplyai.app/r/${post.recipe_id}`
                : `https://reciplyai.app/r/${post.id}`;
              if (navigator.share) {
                navigator.share({ title: post.title, url: shareUrl }).catch(() => {});
              } else {
                navigator.clipboard?.writeText(shareUrl).catch(() => {});
              }
            }}
            className="flex items-center gap-2 text-sm font-medium text-slate-600 hover:bg-slate-50 rounded-lg px-3 py-2 transition-colors min-h-[44px]">
            <Share2 className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Comments Sheet */}
      <AnimatePresence>
        {showComments && (
          <PostCommentsSheet
            postId={post.id}
            onClose={() => setShowComments(false)}
          />
        )}
      </AnimatePresence>
    </>
  );
}

/**
 * AllergenDetector — deterministic allergen mapping.
 * Input: ingredient groups (recipe.ingredients)
 * Output: { allergen_tags: string[], allergen_sources: Record<string, string[]>, confidence: "exact"|"estimated" }
 *
 * KEY NAMES are intentionally kept consistent:
 * shellfish, fish, gluten, dairy, eggs, nuts, peanuts, soy, sesame
 * These MUST match what is stored in user.allergies and UserPreference.allergens_list.
 *
 * STRICT RULES:
 * - fish ≠ shellfish (salmon is fish, squid is shellfish)
 * - Every keyword uses word-boundary matching to prevent false positives
 */

// Canonical allergen → ingredient keyword mapping.
// Keys MUST match what is stored in user.allergies / UserPreference.allergens_list.
