function normalizeText(str) {
  return str.toLowerCase().replace(/[^a-z0-9 ]/g, " ").trim();
}

/**
 * Word-boundary match: prevents "bass" matching "bassil", "egg" matching "vegetable", etc.
 * Multi-word phrases (e.g. "soy sauce") use direct inclusion.
 */
function matchesKeyword(ingredientName, keyword) {
  if (keyword.includes(' ')) {
    return ingredientName.includes(keyword);
  }
  const re = new RegExp(`(^|[^a-z0-9])${keyword}([^a-z0-9]|$)`);
  return re.test(ingredientName);
}

/**
 * Detect ALL allergens present in a recipe (regardless of user settings).
 * Returns allergen_tags = list of allergen keys present in recipe.
 * This is used for DISPLAY ONLY (soft info chips).
 */
export function detectAllergens(ingredientGroups) {
  if (!ingredientGroups || ingredientGroups.length === 0) {
    return { allergen_tags: [], allergen_sources: {}, confidence: "exact" };
  }

  const allIngredientNames = [];
  for (const group of ingredientGroups) {
    for (const item of (group.items || [])) {
      if (item.name) allIngredientNames.push(normalizeText(item.name));
    }
  }

  const detectedAllergens = {};

  for (const [allergen, keywords] of Object.entries(ALLERGEN_MAP)) {
    const sources = [];
    for (const ingredientName of allIngredientNames) {
      for (const kw of keywords) {
        if (matchesKeyword(ingredientName, kw)) {
          if (!sources.includes(ingredientName)) sources.push(ingredientName);
          break;
        }
      }
    }
    if (sources.length > 0) {
      detectedAllergens[allergen] = sources;
    }
  }

  return {
    allergen_tags: Object.keys(detectedAllergens),
    allergen_sources: detectedAllergens,
    confidence: "exact",
  };
}

/**
 * Returns only the allergens that are BOTH in the recipe AND in the user's allergy list.
 * This is the STRICT intersection used for HARD alerts.
 * Returns empty array if no match → no alert.
 */
export function getAllergenIntersection(recipeTags, userAllergenList) {
  if (!recipeTags?.length || !userAllergenList?.length) return [];
  const userSet = new Set(userAllergenList.map(a => a.toLowerCase().trim()));
  return recipeTags.filter(tag => userSet.has(tag.toLowerCase().trim()));
}

