/**
 * useCurrentUser — Single source of truth for current user data across ALL pages.
 * 
 * Reads from AuthContext (already resolved by Layout's auth gate).
 * Pages MUST NOT call base44.auth.me() independently — that causes:
 * - duplicate network requests
 * - race conditions with stale user state
 * - queries firing before auth is resolved
 * 
 * Returns { user, userId, userEmail, isReady, isLoading }
 */
import { useAuth } from '@/lib/AuthContext';

export function useCurrentUser() {
  const { user, isLoadingAuth, authSettled } = useAuth();

  return {
    user: user || null,
    userId: user?.id || null,
    userEmail: user?.email || null,
    isReady: !!user?.id,
    isLoading: !authSettled || isLoadingAuth,
  };
}

/**
 * useAuthoritativeQuota — Single source of truth for generation quota.
 *
 * ARCHITECTURE:
 * - Backend is the ONLY authority (getAiQuotaAdvanced + getRecipeGenerationEntitlement)
 * - No local reconstruction of remaining/used/reset
 * - No stale cache can override fresh backend data
 * - Immediate revalidation after every generation spend
 * - Reconnect/refresh/reopen always hits backend first
 * - EntitlementContext localStorage cache is NEVER used for quota numbers
 * - placeholderData is FORBIDDEN — shows skeleton until backend responds
 *
 * All quota UI components MUST read from this hook, never from local state.
 */
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { base44 } from '@/api/base44Client';
import { useCallback, useRef } from 'react';
import { useEntitlementContext } from '@/components/services/EntitlementContext';

const ENTITLEMENT_STALE_TIME = 30_000;
const CLIENT_TZ = typeof Intl !== 'undefined' ? Intl.DateTimeFormat().resolvedOptions().timeZone : 'UTC';

export function useAuthoritativeQuota(userId) {
  const queryClient = useQueryClient();
  const { isPro, ready: entReady } = useEntitlementContext();
  const lastSpendRef = useRef(0);

  // Primary quota source — getAiQuotaAdvanced
  // RATE LIMIT FIX: Allow 60s stale + 5min gc so app open / tab switch don't
  // re-fetch immediately. After a spend, invalidateAfterSpend() forces fresh fetch.
  // placeholderData keeps last-known quota visible during background refetch.
  const {
    data: quota,
    isLoading: quotaLoading,
    isFetched: quotaFetched,
    refetch: refetchQuota,
  } = useQuery({
    queryKey: ['authoritative-quota', userId],
    queryFn: async () => {
      const res = await base44.functions.invoke('getAiQuotaAdvanced', { client_timezone: CLIENT_TZ });
      return res.data;
    },
    enabled: !!userId,
    staleTime: 60_000,
    gcTime: 5 * 60 * 1000,
    refetchOnWindowFocus: true,
    refetchOnMount: true,
    refetchOnReconnect: true,
    retry: 3,
    retryDelay: (attempt) => Math.min(2000 * Math.pow(2, attempt), 10000),
    placeholderData: (prev) => prev,
  });

  // Pro entitlement details (daily limit, cooldown, etc.)
  const {
    data: proEntitlement,
    isLoading: proLoading,
    refetch: refetchPro,
  } = useQuery({
    queryKey: ['authoritative-pro-entitlement', userId],
    queryFn: async () => {
      const res = await base44.functions.invoke('getRecipeGenerationEntitlement', { client_timezone: CLIENT_TZ });
      return res.data;
    },
    enabled: !!userId && isPro === true,
    staleTime: ENTITLEMENT_STALE_TIME,
    gcTime: 5 * 60 * 1000,
    refetchOnWindowFocus: true,
    retry: 2,
  });

  // Force-refresh both after a generation spend
  // CRITICAL: removeQueries + immediate refetch ensures NO stale data survives.
  // The UI will show loading skeleton between remove and refetch completion.
  const invalidateAfterSpend = useCallback(async () => {
    lastSpendRef.current = Date.now();
    // 1. Remove ALL cached quota data — ensures no stale read
    queryClient.removeQueries({ queryKey: ['authoritative-quota'] });
    queryClient.removeQueries({ queryKey: ['authoritative-pro-entitlement'] });
    // 2. Small delay to ensure removal is processed
    await new Promise(r => setTimeout(r, 100));
    // 3. Fetch fresh from backend — UI shows skeleton until this resolves
    await Promise.allSettled([
      refetchQuota(),
      isPro ? refetchPro() : Promise.resolve(),
    ]);
  }, [queryClient, refetchQuota, refetchPro, isPro]);

  // Listen for quota:stale events (e.g. from EntitlementProvider visibility change)
  // This is handled via refetchOnWindowFocus above — no manual listener needed

  // STRICT: isLoading = true until backend has responded at least once.
  // Never false while quotaFetched is false — prevents showing stale zero state.
  const isLoading = !quotaFetched || quotaLoading;
  // SECOND GUARD: if we just spent and cache was cleared, also treat as loading
  const isPostSpendLoading = lastSpendRef.current > 0 && !quota && !quotaFetched;

  return {
    quota: quota ?? null,
    proEntitlement: proEntitlement ?? null,
    isLoading: isLoading || isPostSpendLoading,
    isPro: quota?.is_premium === true || isPro === true,
    invalidateAfterSpend,
    refetch: async () => {
      queryClient.removeQueries({ queryKey: ['authoritative-quota'] });
      await Promise.allSettled([refetchQuota(), refetchPro()]);
    },
  };
}

