        </motion.p>
      </div>

      {/* ── Intro animation overlay ── */}
      {showIntro && (
        <AppIntroAnimation
          key={`intro-${introKey}`}
          onDone={() => setShowIntro(false)}
        />
      )}

      {/* ── Success animation overlay ── */}
      <PostSuccessAnimation
        key={`success-${successKey}`}
        visible={showSuccess}
        type={successType}
        onDone={() => setShowSuccess(false)}
      />

      {/* ── Streak celebration overlay — REAL sequence ── */}
      <StreakCelebrationSequence
        key={`streak-${streakPopupKey}`}
        isVisible={showStreakPopup}
        streakDay={streakPopupDay}
        onDismiss={() => setShowStreakPopup(false)}
      />
    </div>
  );
}

