function AdminGroupDetailContent() {
  const urlParams = new URLSearchParams(window.location.search);
  const groupId = urlParams.get('groupId');
  const [acting, setActing] = useState(null);

  const { data: group, isLoading, refetch } = useQuery({
    queryKey: ['admin-group', groupId],
    queryFn: async () => {
      const groups = await base44.asServiceRole.entities.Group.filter({ id: groupId }, '-created_date', 1);
      return groups[0] || null;
    },
    enabled: !!groupId,
  });

  const { data: members } = useQuery({
    queryKey: ['admin-group-members', groupId],
    queryFn: async () => {
      const mems = await base44.asServiceRole.entities.GroupMember.filter({ group_id: groupId }, '-joined_at', 50);
      return mems || [];
    },
    enabled: !!groupId,
  });

  const { data: posts } = useQuery({
    queryKey: ['admin-group-posts', groupId],
    queryFn: async () => {
      const grpPosts = await base44.asServiceRole.entities.GroupPost.filter({ group_id: groupId }, '-created_date', 10);
      return grpPosts || [];
    },
    enabled: !!groupId,
  });

  const runAction = async (action) => {
    setActing(action);
    try {
      const res = await base44.functions.invoke('adminModerationEnhanced', {
        action,
        target_id: groupId,
        target_type: 'group',
      });
      if (res.data?.ok) {
        toast.success(`${action.replace(/_/g, ' ')}`);
        refetch();
      } else {
        toast.error(res.data?.error || 'Action failed');
      }
    } catch (err) {
      toast.error(err?.response?.data?.error || 'Action failed');
    } finally {
      setActing(null);
    }
  };

  if (!groupId) return <div className="text-center py-16"><p>Group not found</p></div>;

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <div className="sticky top-0 bg-white/95 backdrop-blur-lg border-b border-slate-100 z-10">
        <div className="flex items-center gap-3 px-4 py-4">
          <button onClick={() => window.history.back()}
            className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center">
            <ArrowLeft className="w-5 h-5 text-slate-700" />
          </button>
          <div>
            <h1 className="text-lg font-bold text-slate-900">Group Details</h1>
            <p className="text-xs text-slate-500">Admin View</p>
          </div>
        </div>
      </div>

      <div className="px-4 py-4 space-y-4">
        {isLoading ? (
          <div className="h-32 bg-white rounded-2xl animate-pulse" />
        ) : group ? (
          <>
            {/* Group info card */}
            <div className="bg-white rounded-2xl border border-slate-200 p-5 space-y-4">
              <div>
                <p className="text-base font-bold text-slate-900">{group.name}</p>
                {group.description && <p className="text-sm text-slate-600 mt-1">{group.description}</p>}
              </div>

              <div className="bg-slate-50 rounded-xl p-3 space-y-1.5 text-[11px]">
                <div className="flex gap-3"><span className="text-slate-400 w-24">Group ID</span><span className="font-mono text-slate-700">{group.id}</span></div>
                <div className="flex gap-3"><span className="text-slate-400 w-24">Members</span><span className="text-slate-700">{members?.length || 0}</span></div>
                <div className="flex gap-3"><span className="text-slate-400 w-24">Posts</span><span className="text-slate-700">{posts?.length || 0}</span></div>
                <div className="flex gap-3"><span className="text-slate-400 w-24">Created</span><span className="text-slate-700">{group.created_date ? format(new Date(group.created_date), 'MMM d, yyyy') : '—'}</span></div>
              </div>

              {/* Quick actions */}
              <div className="pt-3 border-t border-slate-100">
                <button onClick={() => runAction('delete_group')}
                  disabled={acting === 'delete_group'}
                  className="flex items-center gap-1.5 h-9 px-3 rounded-xl font-semibold text-xs bg-rose-100 text-rose-700 hover:bg-rose-200 disabled:opacity-50">
                  {acting === 'delete_group' ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Trash2 className="w-3.5 h-3.5" />}
                  Delete Group
                </button>
              </div>
            </div>

            {/* Members */}
            {members && members.length > 0 && (
              <div className="bg-white rounded-2xl border border-slate-200 p-5">
                <div className="flex items-center gap-2 mb-3">
                  <Users className="w-4 h-4 text-slate-600" />
                  <p className="text-sm font-bold text-slate-900">Members ({members.length})</p>
                </div>
                <div className="space-y-2">
                  {members.slice(0, 10).map(member => (
                    <div key={member.id} className="flex items-center justify-between p-3 rounded-lg bg-slate-50 text-sm">
                      <span className="text-slate-900 font-semibold truncate">{member.user_id}</span>
                      <span className="text-[10px] font-semibold px-2 py-0.5 rounded-full bg-slate-200 text-slate-700">{member.role}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Posts */}
            {posts && posts.length > 0 && (
              <div className="bg-white rounded-2xl border border-slate-200 p-5">
                <p className="text-sm font-bold text-slate-900 mb-3">Posts ({posts.length})</p>
                <div className="space-y-2">
                  {posts.slice(0, 5).map(post => (
                    <div key={post.id} className="flex items-center justify-between p-3 rounded-lg bg-slate-50 text-sm">
                      <span className="text-slate-900 font-semibold truncate">{post.title || 'Untitled'}</span>
                      <span className="text-[10px] text-slate-500">{post.created_date ? format(new Date(post.created_date), 'MMM d') : ''}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </>
        ) : (
          <div className="text-center py-16"><p className="text-slate-600">Group not found</p></div>
        )}
      </div>
    </div>
  );
}

export default function AdminGroupDetailPage() {
