// Extract recipe ID from URL — resilient to multiple formats and timing
// Checks: ?id=X, hash params, pathname segments
function extractRecipeId() {
  // Primary: query param ?id=X
  const params = new URLSearchParams(window.location.search);
  const fromQuery = params.get('id');
  if (fromQuery) return fromQuery;
  // Fallback: hash-based ?id=X (e.g. after redirect)
  if (window.location.hash.includes('id=')) {
    const hashParams = new URLSearchParams(window.location.hash.split('?')[1] || '');
    const fromHash = hashParams.get('id');
    if (fromHash) return fromHash;
  }
  return null;
}

export default function RecipeDetailPage() {
  const queryClient = useQueryClient();
  const { t, resolvedLang } = useLocalization();
  // CENTRALIZED: user from AuthContext — no independent auth.me() call
  const { user } = useCurrentUser();
  // Initialize recipeId synchronously from URL — resilient extraction
  const [recipeId, setRecipeId] = useState(extractRecipeId);
  const mountTimeRef = useRef(Date.now());
  const [returnTo, setReturnTo] = useState(() => new URLSearchParams(window.location.search).get("return_to") || null);

  // HARDENING: If recipeId was null on mount (URL not yet ready), re-extract after a tick.
  // This handles race conditions where the component mounts before the URL is fully committed.
  useEffect(() => {
    if (recipeId) return;
    // Re-check immediately (microtask) and after short delays
    const checks = [0, 50, 150, 500];
    const timers = checks.map(delay =>
      setTimeout(() => {
        const id = extractRecipeId();
        if (id) setRecipeId(id);
      }, delay)
    );
    return () => timers.forEach(clearTimeout);
  }, [recipeId]);
  const [showMealLoggingModal, setShowMealLoggingModal] = useState(false);
  const [showInsufficientModal, setShowInsufficientModal] = useState(false);
  const [insufficientItems, setInsufficientItems] = useState([]);
  const [pendingLoggingData, setPendingLoggingData] = useState(null);
  const [loggingInFlight, setLoggingInFlight] = useState(false);
  const [displayServings, setDisplayServings] = useState(null); // null = use recipe default
  const [showPerServing, setShowPerServing] = useState(false);
  const [debugLog, setDebugLog] = useState("");
  const [userPrefs, setUserPrefs] = useState(null);
  // savedState is ONLY used for AI-generated recipes (recipe.is_saved field).
  // Normal recipes use useSaveUnified (global store, synced with cards).
  const [savedStateAI, setSavedStateAI] = useState(null); // null = loading, true/false = known
  const [savingInFlightAI, setSavingInFlightAI] = useState(false);
  const [cookedCount, setCookedCount] = useState(0);
  // Allergen warning state
  const [allergenWarningDismissed, setAllergenWarningDismissed] = useState(false);
  const [showAllergenWarning, setShowAllergenWarning] = useState(false);
  const [detectedAllergenInfo, setDetectedAllergenInfo] = useState({ allergens: [], triggeringIngredients: [] });
  // Bulk grocery state — tracks which ingredient names are in the "all added" set
  // This is the PERSISTENT state. It drives forceAdded prop on each IngredientShoppingButton.
  // ingredientButtonRefs: array of stable { current: null } objects, one per ingredient slot.
  // getIngredientRef(i) creates the slot on demand so it's always a stable ref object.
  const ingredientButtonRefs = useRef([]);
  const getIngredientRef = useCallback((index) => {
    if (!ingredientButtonRefs.current[index]) {
      ingredientButtonRefs.current[index] = { current: null };
    }
    return ingredientButtonRefs.current[index];
  }, []);
  const [addedIngredientCount, setAddedIngredientCount] = useState(0);
  const [showShareSheet, setShowShareSheet] = useState(false);
  const [showMealCelebration, setShowMealCelebration] = useState(false);
  const [celebrationData, setCelebrationData] = useState(null);

  // Load user preferences when user resolves (no independent auth.me())
  useEffect(() => {
    if (!user?.id) return;
    base44.entities.UserPreference.filter({ owner_id: user.id }).then(prefs => {
      setUserPrefs(prefs[0] || { allergens_enabled: false, allergens_list: [] });
    }).catch(() => setUserPrefs({ allergens_enabled: false, allergens_list: [] }));
  }, [user?.id]);

  const { data: recipe, isLoading, isFetched: recipeFetched, isError: recipeError, error: recipeQueryError, failureCount: recipeFailureCount } = useQuery({
    queryKey: ["recipe", recipeId],
    queryFn: async () => {
      const results = await base44.entities.Recipe.filter({ id: recipeId });
      if (results.length === 0) {
        const err = new Error('recipe_empty_result');
        err.isEmptyResult = true;
        throw err;
      }
      return results[0];
    },
    // HARDENED: retry empty results up to 5x with generous backoff.
    // Cold starts, replication lag, and transient 429s all get retried.
    retry: (failureCount, error) => {
      if (error?.isEmptyResult) return failureCount < 5;
      const status = error?.response?.status || error?.status;
      if (status === 429) return failureCount < 5;
      if (status >= 400 && status < 500) return false;
      return failureCount < 4;
    },
    retryDelay: (attempt) => Math.min(2000 * Math.pow(1.5, attempt), 10000),
    enabled: !!recipeId, // only fetch when we have an ID
  });

  // Hide bottom nav for AI-generated recipes
  useBottomNavLock(recipe?.source === 'generated');

  // Count total ingredients across all groups
  const totalIngredientCount = useMemo(() => {
    if (!recipe) return 0;
    return (recipe.ingredients || []).reduce((sum, g) => sum + (g.items?.length || 0), 0);
  }, [recipe?.id, recipe?.ingredients]);

  const allAdded = totalIngredientCount > 0 && addedIngredientCount >= totalIngredientCount;

  const handleIngredientStateChange = useCallback((_name, added) => {
    setAddedIngredientCount(prev => Math.max(0, prev + (added ? 1 : -1)));
  }, []);



  // ── RECIPE-LEVEL MODERATION GUARD ────────────────────────────────────────────
  // If the Recipe entity itself has moderation_status = removed_by_moderation,
  // block normal detail rendering REGARDLESS of the linked Post state.
  // This is the source-of-truth guard for direct recipe links.
  const recipeIsModRemoved = recipe && recipe.moderation_status === 'removed_by_moderation';

  // Block check — deferred, non-blocking for first render
  const { data: isAuthorBlocked } = useQuery({
    queryKey: ["recipe-block-check", recipe?.author_id, user?.id],
    queryFn: async () => {
      if (!recipe?.author_id || !user?.id || recipe.author_id === user.id) return false;
      const [byMe, byThem] = await Promise.all([
        base44.entities.BlockedUser.filter({ blocker_id: user.id, blocked_id: recipe.author_id }).catch(() => []),
        base44.entities.BlockedUser.filter({ blocker_id: recipe.author_id, blocked_id: user.id }).catch(() => []),
      ]);
      return byMe.length > 0 || byThem.length > 0;
    },
    enabled: !!recipe?.author_id && !!user?.id,
    staleTime: 5 * 60 * 1000, // cache for 5min — don't refetch on every open
  });

  const { data: reviews = [], isFetched: reviewsFetched } = useQuery({
    queryKey: ["reviews", recipeId],
    queryFn: () => base44.entities.RecipeReview.filter({ recipe_id: recipeId }, "-created_date", 20),
    enabled: !!recipeId,
    // Stability fix: keep already-loaded reviews visible during background refetches.
    // Without placeholderData, any re-render (e.g. after follow toggle) briefly returned [] and
    // dropped review_count/userHasReviewed → users saw count "reset" mid-interaction.
    placeholderData: (prev) => prev,
    staleTime: 60 * 1000,
    refetchOnMount: true,
    refetchOnWindowFocus: false,
    gcTime: 30 * 60 * 1000,
  });

  // Derived: whether the current user already has a review on this recipe.
  // Recomputes whenever the reviews array changes (e.g. after delete + refetch).
  const userHasReviewed = React.useMemo(() => {
    if (!user?.id || !reviewsFetched) return false;
    return reviews.some(r => r.author_id === user.id || r.created_by === user.email);
  }, [user?.id, user?.email, reviews, reviewsFetched, reviews.length]);

  // Auto-cleanup: if user has 2+ reviews, delete all but the newest
  React.useEffect(() => {
    if (!user?.id || !reviewsFetched || reviews.length < 2) return;
    const mine = reviews
      .filter(r => r.author_id === user.id || r.created_by === user.email)
      .sort((a, b) => new Date(b.created_date) - new Date(a.created_date));
    if (mine.length < 2) return;
    // Delete all but the first (newest)
    const toDelete = mine.slice(1);
    toDelete.forEach(r => {
      base44.functions.invoke('manageReview', { action: 'delete', review_id: r.id }).catch(() => {});
    });
    // Refresh reviews after cleanup
    setTimeout(() => {
      queryClient.invalidateQueries({ queryKey: ["reviews", recipeId] });
      queryClient.invalidateQueries({ queryKey: ["recipe", recipeId] });
    }, 1000);
  }, [user?.id, reviewsFetched, reviews.length]);



  // Fetch viewer's like status for this recipe — seeds the unified store correctly.
  // Only needed when opening RecipeDetail directly (store may be virgin/version=0).
  // If user came from a feed card that already seeded the store (version>0), this is a no-op
  // because useLikeUnified ignores seeds after user interaction.
  const { data: viewerLikeData } = useQuery({
    queryKey: ['viewer-recipe-like', recipeId, user?.id],
    queryFn: async () => {
      if (!recipeId || !user?.id) return { liked: false };
      // CRITICAL: Query the Like entity (unified system), NOT RecipeLike (old system).
      // toggleLikeUnified writes to Like. RecipeLike is the old table — never touched by unified path.
      const likes = await base44.entities.Like.filter({ target_type: 'recipe', target_id: recipeId, user_id: user.id });
      return { liked: likes.length > 0 };
    },
    enabled: !!recipeId && !!user?.id,
    staleTime: 0,
    refetchOnMount: 'always',
    retry: (failureCount, error) => {
      const status = error?.response?.status || error?.status;
      if (status === 429) return failureCount < 5;
      if (status >= 400 && status < 500) return false;
      return failureCount < 3;
    },
    retryDelay: (attempt) => Math.min(1500 * Math.pow(1.5, attempt), 10000),
  });

  // Normal saved recipes system — query used to seed the unified save store
  const { data: normalRecipeSaves = [], isFetched: normalSavesFetched } = useQuery({
    queryKey: ["normal-recipe-saves-check", user?.email],
    queryFn: () => base44.entities.RecipeSave.filter({ created_by: user.email }),
    enabled: !!user?.email,
    staleTime: 60 * 1000,
  });

  // URL-based shop/category context (fastest, no extra queries needed)
  const [urlShopId, setUrlShopId] = useState(null);
  const [urlCategoryId, setUrlCategoryId] = useState(null);
  const [urlShopName, setUrlShopName] = useState(null);
  const [urlCategoryName, setUrlCategoryName] = useState(null);

  useEffect(() => {
    const p = new URLSearchParams(window.location.search);
    setUrlShopId(p.get('from_shop') || null);
    setUrlCategoryId(p.get('from_category') || null);
    setUrlShopName(p.get('shop_name') ? decodeURIComponent(p.get('shop_name')) : null);
    setUrlCategoryName(p.get('category_name') ? decodeURIComponent(p.get('category_name')) : null);
  }, []);

  // Fetch shop context — prefer URL param, fallback to recipe.shop_id
  const resolvedShopId = urlShopId || (recipe?.shop_id ?? null);
  const { data: shopContext } = useQuery({
    queryKey: ["shop-context", resolvedShopId],
    queryFn: async () => {
      if (!resolvedShopId) return null;
      const shops = await base44.entities.Shop.filter({ id: resolvedShopId });
      return shops[0] || null;
    },
    enabled: !!resolvedShopId,
  });

  // Fetch category context — prefer URL params
  const categoryContext = urlCategoryId ? {
    id: urlCategoryId,
    name: urlCategoryName || 'Category',
  } : null;

  const { data: authorUser, isLoading: authorUserLoading } = useQuery({
    queryKey: ["author-user", recipe?.author_id],
    queryFn: async () => {
      if (!recipe?.author_id) return null;
      try {
        const results = await base44.entities.User.filter({ id: recipe.author_id });
        return results[0] || null;
      } catch (err) {
        console.error("Failed to fetch author user:", err);
        return null;
      }
    },
    enabled: !!recipe?.author_id,
    staleTime: 10 * 60 * 1000, // 10 min cache
    retry: (failureCount, error) => {
      const status = error?.response?.status || error?.status;
      if (status === 429) return failureCount < 2;
      if (status >= 400 && status < 500) return false;
      return failureCount < 1;
    },
    retryDelay: (attempt) => Math.min(2000 * Math.pow(1.5, attempt), 5000),
  });

  // Determine initial saved state for seeding
  const isSavedNormal = normalRecipeSaves.some(s => s.recipe_id === recipeId);

  // Unified save store for normal (non-generated) recipes — syncs with all cards
  const { viewer_has_saved: unifiedSaved, disabled: unifiedSaveDisabled, toggleSave: unifiedToggleSave } = useSaveUnified(
    recipe?.source !== 'generated' ? recipeId : null,
    isSavedNormal,
    recipe?.saves_count ?? 0
  );

  // AI-generated recipes: use recipe.is_saved (separate system)
  useEffect(() => {
    if (!recipe || recipe.source !== 'generated') return;
    setSavedStateAI(recipe.is_saved === true);
  }, [recipe?.id, recipe?.is_saved]);

  // Resolved saved state: unified for normal, AI state for generated
  const savedState = recipe?.source === 'generated' ? savedStateAI : unifiedSaved;
  const savingInFlight = recipe?.source === 'generated' ? savingInFlightAI : unifiedSaveDisabled;

  // Fetch cooked count — deferred 1s so it doesn't block first paint
  useEffect(() => {
    if (!recipeId) return;
    const t = setTimeout(() => {
      base44.functions.invoke('getRecipeCookedCount', { recipe_id: recipeId })
        .then(res => setCookedCount(res.data.cooked_count || 0))
        .catch(() => setCookedCount(0));
    }, 1000);
    return () => clearTimeout(t);
  }, [recipeId]);

  // COST OPTIMIZATION: Use cached pricing read path instead of always recomputing
  // Deferred 2s to not block first paint — only triggers when recipe is missing pricing
  useEffect(() => {
    if (!recipe?.id) return;
    if (recipe.total_cost > 0) return; // already has pricing, skip fetch
    const t = setTimeout(() => {
      base44.functions.invoke('getRecipePricingSafe', { recipe_id: recipe.id })
        .then(() => {
          // Re-fetch recipe to ensure pricing is current
          queryClient.invalidateQueries({ queryKey: ['recipe', recipe.id] });
        })
        .catch(() => {});
    }, 2000);
    return () => clearTimeout(t);
  }, [recipe?.id]);

  // Allergen detection — run when recipe + user prefs are loaded
  // Uses canonical AllergenDetector for consistency (no inline ALLERGEN_KEYWORDS).
  useEffect(() => {
    if (!recipe || !user || allergenWarningDismissed) return;

    const userAllergies = (user?.allergies && Array.isArray(user.allergies))
      ? user.allergies.map(a => a.toLowerCase().trim())
      : [];

    const allIngredients = (recipe.ingredients || []).flatMap(g => g.items || []);
    if (!allIngredients.length) return;

    // Canonical detection — same map used everywhere
    const { allergen_tags } = detectAllergens(recipe.ingredients || []);

    // HARD ALERT: ONLY if user is allergic to the detected allergen
    const hardAllergens = userAllergies.length > 0
      ? allergen_tags.filter(tag => userAllergies.includes(tag))
      : [];

    // SOFT INFO: allergens present but user is NOT allergic
    const softAllergens = allergen_tags.filter(tag => !userAllergies.includes(tag));

    console.debug('[RecipeDetail][Allergen]', {
      recipeAllergens: allergen_tags,
      userAllergies,
      hardAllergens,
      softAllergens,
      alertType: hardAllergens.length > 0 ? 'HARD' : softAllergens.length > 0 ? 'SOFT' : 'NONE',
    });

    if (hardAllergens.length > 0) {
      const normalize = s => s.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').trim();
      const matchKw = (name, kw) => kw.includes(' ') ? name.includes(kw) : new RegExp(`(^|[^a-z0-9])${kw}([^a-z0-9]|$)`).test(name);
      const triggeringIngredients = [];
      for (const allergen of hardAllergens) {
        const keywords = ALLERGEN_MAP[allergen] || [];
        for (const ingredient of allIngredients) {
          const ingName = normalize(ingredient.name || '');
          if (keywords.some(kw => matchKw(ingName, kw)) && !triggeringIngredients.some(ti => ti.name === ingredient.name)) {
            triggeringIngredients.push(ingredient);
          }
        }
      }
      setDetectedAllergenInfo({ allergens: hardAllergens, triggeringIngredients, softAllergens });
      setShowAllergenWarning(true);
    } else {
      // No hard alert — only store soft info for inline display
      setDetectedAllergenInfo({ allergens: [], triggeringIngredients: [], softAllergens });
    }
  }, [recipe?.id, user?.id, allergenWarningDismissed]);

  const [likeBurst, setLikeBurst] = useState(false);
  // useLikeUnified shares the SAME store key ("recipe:<recipeId>") as RecipeCard via
  // useRecipeLikeController — so card and detail are always in sync, no duplicate stores.
  // CRITICAL: ONLY call useLikeUnified AFTER recipe is fully loaded (recipeFetched=true).
  // Never seed with 0 when loading — defer hook call until recipe resolves with authoritative count.
  // This ensures first visible count is always correct from DB, not a placeholder.
  // Seed like count from recipe immediately for instant display.
  // Viewer liked status resolves async — show count first, liked state catches up.
  const viewerLikeResolved = viewerLikeData !== undefined;
  const seedCount = recipeFetched && recipe ? (recipe?.likes_count ?? 0) : LOADING_SENTINEL;
  const seedLiked = viewerLikeResolved ? (viewerLikeData?.liked ?? false) : false;
  const {
    viewer_has_liked: isLiked,
    like_count: likesCount,
    disabled: likeBlocked,
    toggleLike,
  } = useLikeUnified(
    'recipe',
    recipeId,
    seedLiked,
    seedCount
  );

  const handleLike = async (e) => {
    if (likeBlocked) return;
    setLikeBurst(true);
    setTimeout(() => setLikeBurst(false), 500);
    await toggleLike(e);
  };

  const handleSave = async () => {
    if (recipe?.source === 'generated') {
      // AI-generated recipe: toggle recipe.is_saved (separate AI save system)
      if (savingInFlightAI) return;
      setSavingInFlightAI(true);
      try {
        const newSavedState = !savedStateAI;
        await base44.entities.Recipe.update(recipeId, { is_saved: newSavedState });
        setSavedStateAI(newSavedState);
        queryClient.invalidateQueries({ queryKey: ["generated-recipes"] });
      } catch (err) {
        console.error('Save toggle error:', err);
      } finally {
        setSavingInFlightAI(false);
      }
    } else {
      // Normal recipe: use unified save store (same as cards — fully synced)
      if (unifiedSaveDisabled) return;
      await unifiedToggleSave();
      // Invalidate caches so other surfaces stay in sync
      queryClient.invalidateQueries({ queryKey: ["normal-recipe-saves-check"] });
      queryClient.invalidateQueries({ queryKey: ["normal-recipe-saves-full"] });
      queryClient.invalidateQueries({ queryKey: ["saved-recipes"] });
      queryClient.invalidateQueries({ queryKey: ["user-engagement"] });
    }
  };

  const handleMealLoggingConfirm = async (loggingData) => {
    if (!recipe) return;
    setShowMealLoggingModal(false);
    setLoggingInFlight(true);

    const mealLogData = {
      recipe_id: recipe.id,
      recipe_title: recipe.title,
      recipe_image: recipe.hero_image_url,
      recipe_servings: recipe.servings || 1,
      servings_eaten: loggingData.servings_eaten,
      eaten_at: new Date().toISOString(),
      nutrition_snapshot_per_serving: loggingData.nutrition_snapshot_per_serving,
      nutrition_snapshot_logged_total: loggingData.nutrition_snapshot_logged_total,
      calories_snapshot: loggingData.nutrition_snapshot_per_serving?.calories || 0,
      protein_snapshot: loggingData.nutrition_snapshot_per_serving?.protein || 0,
      carbs_snapshot: loggingData.nutrition_snapshot_per_serving?.carbs || 0,
      fat_snapshot: loggingData.nutrition_snapshot_per_serving?.fat || 0,
    };

    // Run simulation first (read-only, non-blocking on failure)
    let simResult = null;
    try {
      const simRes = await base44.functions.invoke('simulatePantryDeduction', {
        recipe_ingredients: recipe?.ingredients || [],
        recipe_servings: recipe?.servings || 1,
        servings_eaten: loggingData.servings_eaten,
      });
      simResult = simRes.data;
    } catch (simErr) {
      console.warn('[RecipeDetail] simulation failed, proceeding without check:', simErr.message);
    }

    // If simulation found problems, show warning modal
    if (simResult?.has_problems && simResult.problematic?.length > 0) {
      setPendingLoggingData({ mealLogData, loggingData });
      setInsufficientItems(simResult.problematic);
      setLoggingInFlight(false);
      setShowInsufficientModal(true);
      return;
    }

    // All sufficient — log directly
    await executeLog(mealLogData, loggingData, []);
  };

  const executeLog = async (mealLogData, loggingData, skipIds) => {
    setLoggingInFlight(true);
    try {
      const res = await base44.functions.invoke('logMealAndUpdateInventory', {
        meal_log_data: mealLogData,
        ingredient_deductions: [],
        recipe_ingredients: recipe?.ingredients || [],
        recipe_servings: recipe?.servings || 1,
        servings_eaten: loggingData?.servings_eaten ?? mealLogData.servings_eaten,
        pantry_item_ids_to_skip: skipIds || [],
      });
      console.log("[MEAL] Created:", res.data?.meal_log_id);
      // Invalidate all Home page caches
      queryClient.invalidateQueries({ queryKey: ["recent-meals"] });
      queryClient.invalidateQueries({ queryKey: ["pantry-items", user?.email] });
      queryClient.invalidateQueries({ queryKey: ["pantry-items"] });
      // Force re-fetch of meal logs via useLiveSync (refreshes Recent Meals immediately)
      queryClient.invalidateQueries({ queryKey: ["meal-logs-sync"] });
      // Bust stats cache so nutrition shows updated
      bustStatsCache(user?.id);
      setShowInsufficientModal(false);
      // Record streak action — queue celebration in localStorage for Home page
      try {
        const sRes = await base44.functions.invoke('updateStreakAction', { action_type: 'log_meal' });
        if (sRes.data?.streak?.is_new_day_increment && sRes.data.streak.current_streak_days > 0) {
          setPendingStreakCelebration(sRes.data.streak.current_streak_days);
        }
      } catch (e) {
        console.warn('[RecipeDetail] streak update failed:', e?.message);
      }

      // ALWAYS show meal logged celebration first, then navigate to Home
      // (streak celebration will fire on Home from localStorage if earned)
      setCelebrationData({
        recipeName: recipe?.title || '',
        recipeImage: recipe?.hero_image_url || '',
        servingsEaten: loggingData?.servings_eaten ?? mealLogData.servings_eaten ?? 1,
        calories: mealLogData.calories_snapshot || 0,
        protein: mealLogData.protein_snapshot || 0,
      });
      setShowMealCelebration(true);
    } finally {
      setLoggingInFlight(false);
    }
  };

  const handleInsufficientContinue = async (skippedIds) => {
    if (!pendingLoggingData) return;
    const { mealLogData, loggingData } = pendingLoggingData;
    setPendingLoggingData(null);
    await executeLog(mealLogData, loggingData, skippedIds);
  };

  const handleInsufficientEditIngredient = (pantryItemId) => {
    window.location.href = createPageUrl("Pantry") + `?editItemId=${pantryItemId}&return_to=${encodeURIComponent(window.location.href)}`;
  };

  // Use recipe.servings as the default display amount
  const selectedServings = displayServings ?? (recipe?.servings || 1);
  const setSelectedServings = setDisplayServings;
  // Note: showPerServing state is declared above in useState

  // Debug logging for dev mode
  useEffect(() => {
    if (!recipe?.ingredients) return;
    const isDev = typeof localStorage !== "undefined" && localStorage.getItem("__debug_mode") === "true";
    if (!isDev) return;
    const result = computeNutrition(recipe.ingredients, recipe.servings || 1, selectedServings);
    console.log("[NUTRITION_ENGINE]", result.debug_log);
    setDebugLog(result.debug_log);
  }, [recipe?.ingredients, selectedServings, recipe?.servings]);

  // ── REMOVED POST ROUTING GUARD ──────────────────────────────────────────
  // Only fetch the linked Post when this Recipe is confirmed moderation-removed.
  // IMPORTANT: 'active' and 'restored' recipes skip this entirely — no redirect.
  const recipeIsConfirmedRemoved = !!recipe && (
    recipe.moderation_status === 'removed_by_moderation' ||
    recipe.moderation_status === 'appealed'
  );

  const { data: linkedPost } = useQuery({
    queryKey: ['recipe-post-link', recipeId],
    queryFn: async () => {
      if (!recipeId) return null;
      const posts = await base44.entities.Post.filter({ recipe_id: recipeId });
      return posts[0] || null;
    },
    enabled: !!recipeId && recipeIsConfirmedRemoved,
    staleTime: 0,
  });

  // Only treat post as removed if BOTH recipe AND post are in removed state.
  // This prevents stale linkedPost data from triggering a redirect after restore.
  const postIsRemoved = recipeIsConfirmedRemoved && linkedPost &&
    (linkedPost.moderation_status === 'removed_by_moderation' ||
     linkedPost.moderation_status === 'appealed');

  // Handle removed post routing once we have both user and linkedPost data
  const hasRedirectedRef = useRef(false);
  useEffect(() => {
    if (!postIsRemoved || !user || !linkedPost) return;
    if (hasRedirectedRef.current) return;
    if (linkedPost.author_id === user.id) {
      hasRedirectedRef.current = true;
      window.location.replace(createPageUrl('RemovedPostDetail') + `?id=${linkedPost.id}`);
    }
  }, [postIsRemoved, user?.id, linkedPost?.id]);

  // Auto-translate the recipe metadata based on user's display language setting
  // Steps are resolved separately via steps_translations to support all 18 languages uniformly
  const { translatedRecipe: displayRecipe, isTranslating: translatingRecipe } = useRecipeTranslation(recipe || null);
  const activeRecipe = displayRecipe || recipe;

  // Pull-to-refresh handler for RecipeDetail — only for non-AI recipes
  const handleRecipeDetailRefresh = useCallback(async () => {
    const keys = [
      ["recipe", recipeId],
      ["reviews", recipeId],
      ["viewer-recipe-like", recipeId, user?.id],
      ["normal-recipe-saves-check", user?.email],
    ];
    keys.forEach(k => queryClient.invalidateQueries({ queryKey: k }));
    await Promise.all(keys.map(k => queryClient.refetchQueries({ queryKey: k })));
  }, [queryClient, recipeId, user?.id, user?.email]);

  // HARDENED: No recipe ID in URL.
  // Never show "not found" immediately — the ID extraction may still be running.
  // Show skeleton for the first 2 seconds, then show the no-ID screen.
  const timeSinceMount = Date.now() - mountTimeRef.current;
  if (!recipeId) {
    if (timeSinceMount < 2000) {
      // Still within grace period — show skeleton, not error
      return (
        <div className="min-h-screen bg-white">
          <div className="relative h-72 bg-gradient-to-br from-slate-200 to-slate-300 animate-pulse">
            <div className="absolute top-4 left-4 w-10 h-10 rounded-full bg-white/30" />
          </div>
          <div className="px-5 -mt-8 relative z-10">
            <div className="bg-white rounded-3xl p-5 shadow-lg space-y-4">
              <div className="h-6 bg-slate-100 rounded-xl w-3/4 animate-pulse" />
              <div className="h-4 bg-slate-100 rounded-xl w-full animate-pulse" />
              <div className="h-4 bg-slate-100 rounded-xl w-2/3 animate-pulse" />
            </div>
          </div>
        </div>
      );
    }
    // Past grace period with no recipeId — show not-found
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
        <div className="w-16 h-16 rounded-3xl bg-slate-100 flex items-center justify-center mb-4">
          <ChefHat className="w-8 h-8 text-slate-400" />
        </div>
        <h2 className="text-lg font-bold text-slate-800 mb-2">Recipe Not Found</h2>
        <p className="text-sm text-slate-500 mb-6">No recipe ID was provided.</p>
        <button onClick={() => window.location.href = createPageUrl("Home")} className="px-5 h-11 rounded-2xl bg-indigo-600 text-white text-sm font-semibold">Go Home</button>
      </div>
    );
  }

  // HARDENED: Show skeleton whenever recipe data isn't confirmed yet.
  // NEVER show not-found while loading, retrying, or within grace period.
  // recipe===undefined = not resolved. recipe===null = impossible (queryFn throws).
  // recipeError with isEmptyResult within 15s of mount = still retrying, show skeleton.
  const isWithinGracePeriod = (Date.now() - mountTimeRef.current) < 15000;
  const isStillRetrying = recipeError && recipeQueryError?.isEmptyResult && isWithinGracePeriod;
  if (isLoading || !recipeFetched || recipe === undefined || isStillRetrying) {
    return (
      <div className="min-h-screen bg-white">
        {/* Hero skeleton */}
        <div className="relative h-72 bg-gradient-to-br from-slate-200 to-slate-300 animate-pulse">
          <div className="absolute top-4 left-4 w-10 h-10 rounded-full bg-white/30" />
          <div className="absolute bottom-0 left-0 right-0 h-24 bg-gradient-to-t from-white/20 to-transparent" />
        </div>
        {/* Content skeleton */}
        <div className="px-5 -mt-8 relative z-10">
          <div className="bg-white rounded-3xl p-5 shadow-lg space-y-4">
            <div className="h-6 bg-slate-100 rounded-xl w-3/4 animate-pulse" />
            <div className="h-4 bg-slate-100 rounded-xl w-full animate-pulse" />
            <div className="h-4 bg-slate-100 rounded-xl w-2/3 animate-pulse" />
            <div className="flex gap-3 pt-2">
              <div className="h-8 bg-slate-100 rounded-full w-24 animate-pulse" />
              <div className="h-8 bg-slate-100 rounded-full w-20 animate-pulse" />
            </div>
            <div className="h-px bg-slate-100 w-full" />
            <div className="flex gap-2">
              {[1,2,3].map(i => <div key={i} className="h-10 bg-slate-100 rounded-xl flex-1 animate-pulse" />)}
            </div>
          </div>
          <div className="mt-4 bg-white rounded-3xl p-5 shadow-sm space-y-3">
            <div className="h-5 bg-slate-100 rounded-xl w-1/2 animate-pulse" />
            {[1,2,3,4].map(i => <div key={i} className="h-12 bg-slate-50 rounded-xl animate-pulse" />)}
          </div>
        </div>
      </div>
    );
  }

  // HARDENED: Error / not-found — only show after grace period AND all retries exhausted.
  // For empty-result errors, always offer retry (never just "not found" dead-end).
  if (recipeError) {
    const isNotFound = recipeQueryError?.isEmptyResult;
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
        <button onClick={() => window.history.back()} className="absolute top-5 left-5 w-10 h-10 rounded-full bg-white border border-slate-200 flex items-center justify-center shadow-sm">
          <ArrowLeft className="w-5 h-5 text-slate-600" />
        </button>
        <div className="w-16 h-16 rounded-3xl bg-slate-100 flex items-center justify-center mb-4">
          <ChefHat className="w-8 h-8 text-slate-400" />
        </div>
        {isNotFound ? (
          <>
            <h2 className="text-lg font-bold text-slate-800 mb-2">{t('recipe.not_found','Recipe Not Found')}</h2>
            <p className="text-sm text-slate-500 mb-6 max-w-xs">{t('recipe.not_found_desc','This recipe may have been deleted or moved.')}</p>
          </>
        ) : (
          <>
            <h2 className="text-lg font-bold text-slate-800 mb-2">{t('recipe.load_error','Couldn\'t load recipe')}</h2>
            <p className="text-sm text-slate-500 mb-6">{t('recipe.load_error_desc','Something went wrong. Please try again.')}</p>
          </>
        )}
        <div className="flex gap-3">
          <button
            onClick={() => {
              // Force fresh fetch — invalidate cache and retry
              queryClient.removeQueries({ queryKey: ['recipe', recipeId] });
              window.location.reload();
            }}
            className="px-5 h-11 rounded-2xl bg-slate-100 text-slate-700 text-sm font-semibold"
          >
            {t('action.retry','Retry')}
          </button>
          <button onClick={() => window.location.href = createPageUrl("Home")} className="px-5 h-11 rounded-2xl bg-indigo-600 text-white text-sm font-semibold">{t('action.go_home','Go Home')}</button>
        </div>
      </div>
    );
  }

  // NOTE: recipe===null guard removed — queryFn now throws on empty results so recipe is never null.

  // ── RECIPE MODERATION GUARD (direct recipe link / safety net) ───────────
  // Recipe is confirmed removed. Determine destination NOW — don't wait for
  // linkedPost if we can avoid it. The useEffect above handles the redirect
  // once linkedPost resolves. Here we just show a minimal spinner (not a
  // blank page) while waiting, or show unavailable for non-owners immediately.
  if (recipeIsModRemoved && user) {
    const isOwner = recipe.author_id === user.id || recipe.created_by === user.email;
    if (isOwner) {
      if (linkedPost?.id) {
        // linkedPost loaded — redirect now
        window.location.replace(createPageUrl('RemovedPostDetail') + `?id=${linkedPost.id}`);
      }
      // Still waiting for linkedPost — show minimal spinner (not blank page)
      return (
        <div className="min-h-screen bg-slate-50 flex items-center justify-center">
          <div className="w-8 h-8 border-2 border-slate-200 border-t-indigo-500 rounded-full animate-spin" />
        </div>
      );
    }
    // Non-owner — show unavailable immediately (no need to wait for linkedPost)
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
        <button onClick={() => window.history.back()} className="absolute top-5 left-5 w-10 h-10 rounded-full bg-white border border-slate-200 flex items-center justify-center shadow-sm">
          <ArrowLeft className="w-5 h-5 text-slate-600" />
        </button>
        <div className="w-16 h-16 rounded-3xl bg-slate-100 flex items-center justify-center mb-4">
          <Lock className="w-8 h-8 text-slate-400" />
        </div>
        <h2 className="text-lg font-bold text-slate-800 mb-2">{t('recipe.content_unavailable','Content Unavailable')}</h2>
        <p className="text-sm text-slate-500 mb-6 max-w-xs leading-relaxed">{t('recipe.no_longer_available','This recipe is no longer available.')}</p>
        <button onClick={() => window.history.back()} className="px-6 h-11 rounded-2xl bg-indigo-600 text-white text-sm font-semibold">{t('action.go_back','Go Back')}</button>
      </div>
    );
  }

  // Non-owner trying to view a removed post → show unavailable
  if (postIsRemoved && user && linkedPost?.author_id !== user.id) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
        <button onClick={() => window.history.back()} className="absolute top-5 left-5 w-10 h-10 rounded-full bg-white border border-slate-200 flex items-center justify-center shadow-sm">
          <ArrowLeft className="w-5 h-5 text-slate-600" />
        </button>
        <div className="w-16 h-16 rounded-3xl bg-slate-100 flex items-center justify-center mb-4">
          <Lock className="w-8 h-8 text-slate-400" />
        </div>
        <h2 className="text-lg font-bold text-slate-800 mb-2">{t('recipe.content_unavailable','Content Unavailable')}</h2>
        <p className="text-sm text-slate-500 mb-6 max-w-xs leading-relaxed">
          {t('recipe.no_longer_available','This recipe is no longer available.')}
        </p>
        <button onClick={() => window.history.back()} className="px-6 h-11 rounded-2xl bg-indigo-600 text-white text-sm font-semibold">
          {t('action.go_back','Go Back')}
        </button>
      </div>
    );
  }

  // Blocked author — show gate instead of recipe content
  if (isAuthorBlocked) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-8 text-center">
        <button onClick={() => window.history.back()} className="absolute top-5 left-5 w-10 h-10 rounded-full bg-white border border-slate-200 flex items-center justify-center shadow-sm">
          <ArrowLeft className="w-5 h-5 text-slate-600" />
        </button>
        <div className="w-16 h-16 rounded-3xl bg-slate-200 flex items-center justify-center mb-4">
          <Lock className="w-8 h-8 text-slate-500" />
        </div>
        <h2 className="text-lg font-bold text-slate-800 mb-2">{t('recipe.user_blocked','This user is blocked')}</h2>
        <p className="text-sm text-slate-500 mb-6 max-w-xs leading-relaxed">
          {t('recipe.user_blocked_desc',"You've blocked this creator (or they've blocked you). Unblock them to view their recipes.")}
        </p>
        <button
          onClick={() => window.history.back()}
          className="px-6 h-11 rounded-2xl bg-indigo-600 text-white text-sm font-semibold"
        >
          {t('action.go_back','Go Back')}
        </button>
      </div>
    );
  }

  const totalTime = (recipe.cook_time || 0) + (recipe.prep_time || 0);

  const isAIRecipe = recipe?.source === 'generated';

  return (
    <PullToRefresh onRefresh={isAIRecipe ? (() => Promise.resolve()) : handleRecipeDetailRefresh}>
    <div className="min-h-screen bg-white" style={{ paddingBottom: 'calc(env(safe-area-inset-bottom, 0px) + 120px)' }}>
      {/* Hero Image */}
      <div className="relative h-72">
        <RecipeHeroImage
          src={recipe.hero_image_url}
          alt={recipe.title}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-black/20" />

        {/* Top Bar */}
        <div className="absolute top-0 left-0 right-0 flex items-center justify-between p-4">
          <button
            aria-label="Go back"
            onClick={() => {
              window.location.replace(returnTo || createPageUrl("Home"));
            }}
            className="w-10 h-10 rounded-full bg-white/80 backdrop-blur-md flex items-center justify-center"
          >
            <ArrowLeft className="w-5 h-5 text-slate-700" />
          </button>
          <div className="flex gap-2">
            {/* Share Button — only for non-AI recipes */}
            {recipe?.source !== 'generated' && (
              <ReciplyShareIcon
                size={18}
                className="text-white"
                onClick={() => setShowShareSheet(true)}
                style={{ background: 'rgba(255,255,255,0.25)', backdropFilter: 'blur(8px)', borderRadius: 9999, width: 40, height: 40 }}
              />
            )}
            {/* Save button — only for non-AI recipes in top bar */}
            {recipe?.source !== 'generated' && (
              <button
                aria-label={savedState ? "Unsave recipe" : "Save recipe"}
                onClick={handleSave}
                disabled={savingInFlight}
                className={cn(
                  "flex items-center gap-1.5 px-3 h-10 rounded-full backdrop-blur-md disabled:opacity-60 transition-all",
                  savedState ? "bg-amber-500 text-white" : "bg-white/80 text-slate-600"
                )}
              >
                <Bookmark className={cn("w-4 h-4", savedState && "fill-current")} />
                <span className="text-xs font-semibold">{savedState ? t('recipe.saved','Saved') : t('recipe.save','Save')}</span>
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Content */}
      <div className="px-5 -mt-8 relative z-10">
        <div className="bg-white rounded-3xl p-5 shadow-lg">
          {/* Privacy badge + Tags */}
          <div className="flex items-center gap-2 flex-wrap mb-3">
            <PrivacyBadge isPublic={recipe.is_public} visibility={recipe.visibility} moderationStatus={recipe.moderation_status} source={recipe.source} size="sm" />
            {recipe.tags?.length > 0 && (
              <div className="flex flex-wrap gap-1.5">
                {recipe.tags.map(tag => (
                  <span key={tag} className="text-[10px] font-medium bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded-full">{tag}</span>
                ))}
              </div>
            )}
          </div>

          <div className="flex items-start gap-2">
            <h1 className="text-2xl font-bold text-slate-900 tracking-tight flex-1">{activeRecipe.title}</h1>
            {translatingRecipe && <span className="mt-1 text-[10px] text-indigo-400 font-medium shrink-0 animate-pulse">✦ Translating…</span>}
          </div>
          {activeRecipe.description && <p className="text-sm text-slate-500 mt-1.5 leading-relaxed break-words whitespace-pre-wrap min-w-0">{activeRecipe.description}</p>}

          {/* Like & Rating Row */}
          <div className="flex items-center gap-4 mt-3 pt-3 border-t border-slate-100">
            {recipe.source === 'generated' ? (
              /* AI recipe: no like, beautiful not-rateable badge */
              <motion.div
                initial={{ opacity: 0, scale: 0.92 }}
                animate={{ opacity: 1, scale: 1 }}
                transition={{ duration: 0.4, ease: 'easeOut' }}
                className="relative flex items-center gap-2 px-4 py-1.5 rounded-full overflow-hidden"
                style={{
                  background: 'linear-gradient(135deg, #f0f4ff 0%, #e8f4fd 50%, #f0f0ff 100%)',
                  border: '1px solid rgba(148,163,250,0.3)',
                }}
              >
                {/* Shimmer sweep */}
                <motion.div
                  className="absolute inset-0 pointer-events-none"
                  style={{
                    background: 'linear-gradient(105deg, transparent 35%, rgba(255,255,255,0.55) 50%, transparent 65%)',
                    backgroundSize: '200% 100%',
                  }}
                  animate={{ backgroundPosition: ['-100% center', '200% center'] }}
                  transition={{ duration: 2.8, repeat: Infinity, ease: 'linear', repeatDelay: 1.5 }}
                />
                <motion.div
                  animate={{ rotate: [0, 10, -10, 0] }}
                  transition={{ duration: 3, repeat: Infinity, ease: 'easeInOut', repeatDelay: 2 }}
                >
                  <Sparkles className="w-3.5 h-3.5 text-indigo-400" />
                </motion.div>
                <span className="text-xs font-semibold text-indigo-400 relative z-10">{t('recipe.ai_not_rateable','AI · Not rateable')}</span>
              </motion.div>
            ) : (
              <>
                <button
                  onClick={handleLike}
                  disabled={likeBlocked}
                  className="relative flex items-center gap-2 px-3 py-1.5 rounded-full bg-gradient-to-r from-rose-50 to-pink-50 hover:from-rose-100 hover:to-pink-100 transition-all overflow-hidden disabled:opacity-70 disabled:cursor-not-allowed"
                >
                  <AnimatePresence>
                    {likeBurst && !likeBlocked && (
                      <motion.span
                        key="burst"
                        className="absolute inset-0 flex items-center justify-center pointer-events-none text-xl"
                        initial={{ scale: 0.5, opacity: 1 }}
                        animate={{ scale: 2.5, opacity: 0 }}
                        exit={{}}
                        transition={{ duration: 0.45 }}
                      >❤️</motion.span>
                    )}
                  </AnimatePresence>
                  <Heart className={cn("w-4 h-4", isLiked ? "fill-rose-500 text-rose-500" : "text-rose-400")} />
                  {/* Show count immediately from recipe data — viewer liked state resolves async */}
                  {recipeFetched
                    ? <span className="text-sm font-semibold text-slate-700">{likesCount ?? 0}</span>
                    : <span className="w-6 h-4 bg-slate-100 rounded animate-pulse inline-block" />
                  }
                </button>

                <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-gradient-to-r from-amber-50 to-yellow-50">
                  {(recipe.avg_rating > 0) ? (
                    <>
                      <Star className="w-4 h-4 text-amber-500 fill-amber-500" />
                      <span className="text-sm font-semibold text-slate-700">{recipe.avg_rating.toFixed(1)}</span>
                      <span className="text-xs text-slate-400">({recipe.review_count || 0})</span>
                    </>
                  ) : (
                    <>
                      <Star className="w-4 h-4 text-slate-200 fill-slate-200" />
                      <span className="text-xs text-slate-400">{t('recipe.not_rated_short','Not rated')}</span>
                    </>
                  )}
                </div>
              </>
            )}
          </div>

          {/* Author badge — unified for generated + community */}
          <div className="mt-3 pt-3 border-t border-slate-100">
            {(() => {
              if (recipe.source === "generated") {
                return (
                  <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-indigo-50 border border-indigo-100">
                    <Sparkles className="w-3.5 h-3.5 text-indigo-600" />
                    <span className="text-xs font-semibold text-indigo-600">{t('recipe.generated_by_ai','Generated by Reciply AI')}</span>
                  </div>
                );
              }
              // Suppress only if author is explicitly non-active
              const authorIsActive = !recipe.author_account_status || recipe.author_account_status === 'active';
              if (!authorIsActive) {
                return (
                  <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-slate-50 border border-slate-100">
                    <span className="text-xs text-slate-400 font-medium">{t('recipe.author_unavailable','Author unavailable')}</span>
                  </div>
                );
              }
              // Show badge if we have author_name (don't wait for authorUser to load)
              if (recipe.author_name && recipe.author_id) {
                return (
                   <RecipeByBadge
                     authorName={recipe.author_name}
                     authorAvatar={recipe.author_avatar}
                     authorId={recipe.author_id}
                     authorHasShop={authorUser?.has_shop}
                     shopId={recipe.shop_id}
                     shopLogo={shopContext?.logo_image_url}
                     shopName={shopContext?.shop_name || recipe.shop_name}
                     shopLogoFromRecipe={recipe.shop_logo_url}
                   />
                 );
              }
              // Loading state — author_id exists but name not yet available
              if (recipe.author_id && authorUserLoading) {
                return <div className="h-8 w-40 bg-slate-100 rounded-full animate-pulse" />;
              }
              return null;
            })()}
          </div>

          {/* Shop context — subtle metadata, non-clickable */}
          {shopContext && (
            <div className="mt-3 pt-3 border-t border-slate-100">
              <p className="text-[11px] text-slate-400 leading-relaxed">
                <span className="font-medium text-slate-500">{t('recipe.from_shop','From shop')}:</span> {shopContext.shop_name}
                {categoryContext && (
                <> &middot; <span className="font-medium text-slate-500">{t('recipe.category','Category')}:</span> {categoryContext.name}</>
                )}
              </p>
            </div>
          )}

          {/* Pricing row — deterministic, backend-authoritative */}
          <div className="mt-3 pt-3 border-t border-slate-100">
            <RecipeCostRow recipe={recipe} displayServings={selectedServings} />
          </div>

          {/* Allergen chips — hard alert tags (user is allergic) shown in red, soft info in neutral */}
          {(() => {
            const { allergen_tags } = detectAllergens(recipe.ingredients || []);
            if (!allergen_tags.length) return null;
            // User allergies from user.allergies (canonical source)
            const userAllergyList = (user?.allergies && Array.isArray(user.allergies))
              ? user.allergies.map(a => a.toLowerCase().trim())
              : [];
            const hardTags = allergen_tags.filter(t => userAllergyList.includes(t));
            const softTags = allergen_tags.filter(t => !userAllergyList.includes(t));
            return (
              <div className="mt-3 pt-3 border-t border-slate-100 space-y-2">
                {/* Hard alert chips — user is allergic */}
                {hardTags.length > 0 && (
                  <AllergenChips allergenTags={hardTags} userAllergens={userAllergyList} />
                )}
                {/* Soft info chips — allergens present but not user's */}
                {softTags.length > 0 && (
                  <div className="flex flex-wrap gap-1.5 items-center">
                    <span className="text-[10px] text-slate-400 font-medium">{t('recipe.contains','Contains')}:</span>
                    {softTags.map(tag => (
                      <span key={tag} className="flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-medium bg-slate-50 border border-slate-200 text-slate-500">
                        <span>{{"shellfish":"🦐","fish":"🐟","gluten":"🌾","dairy":"🥛","eggs":"🥚","nuts":"🌰","peanuts":"🥜","soy":"🌱","sesame":"⚪"}[tag] || "⚠"}</span>
                        {t(`allergen.${tag}`, {"shellfish":"Shellfish","fish":"Fish","gluten":"Gluten","dairy":"Dairy","eggs":"Eggs","nuts":"Tree Nuts","peanuts":"Peanuts","soy":"Soy","sesame":"Sesame"}[tag] || tag)}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            );
          })()}

          {/* Dev Debug Panel */}
          {typeof localStorage !== "undefined" && localStorage.getItem("__debug_mode") === "true" && (
            <div className="mt-4 p-3 bg-slate-900 rounded-xl border border-slate-700 max-h-64 overflow-y-auto">
              <div className="flex items-center gap-2 mb-2">
                <Bug className="w-3.5 h-3.5 text-amber-400" />
                <span className="text-xs font-bold text-amber-400">NUTRITION DEBUG</span>
              </div>
              <pre className="text-[9px] text-slate-300 font-mono whitespace-pre-wrap break-all leading-tight">
                {debugLog || "(calculating...)"}
              </pre>
            </div>
          )}

          {/* Stats Row — premium single-line prep / cook / difficulty pills with custom icons + patterns */}
          <div className="mt-4 py-3 border-t border-slate-100">
            <RecipeStatsRow
              prepTime={recipe.prep_time || 0}
              cookTime={recipe.cook_time || 0}
              totalTime={totalTime}
              difficulty={recipe.difficulty}
              source={recipe.source}
            />
          </div>

          {/* Servings — dedicated prominent row */}
          <div className="flex items-center gap-3 py-3 border-t border-slate-100 overflow-visible">
            <div className="flex items-center gap-2 flex-1">
              <div className="w-8 h-8 rounded-xl bg-indigo-50 flex items-center justify-center flex-shrink-0">
                <Users className="w-4 h-4 text-indigo-600" />
              </div>
              <div>
                <p className="text-xs text-slate-400 font-medium leading-none">{t('recipe.servings', 'Servings')}</p>
                <p className="text-sm font-bold text-slate-900 leading-tight">{selectedServings} {selectedServings === 1 ? t('recipe.serving_singular', 'serving') : t('recipe.servings_plural', 'servings')}</p>
              </div>
            </div>
            <ServingsChip
              value={selectedServings}
              defaultServings={recipe.servings || 1}
              onChange={setSelectedServings}
            />
          </div>


        </div>

        {/* Debug Panel */}
        <PricingDebugPanel
          recipe={recipe}
          selectedServings={selectedServings}
          defaultServings={recipe.servings || 1}
        />

        {/* Ingredients */}
        <div className="mt-6">
          <div className="flex items-center justify-between mb-4 gap-3">
            <h2 className="text-lg font-bold text-slate-900">{t('recipe.ingredients', 'Ingredients')} ({t('recipe.servings', 'Servings').toLowerCase()}: {selectedServings})</h2>
            <AddAllToGroceryButton
              ingredientButtonRefs={ingredientButtonRefs.current.filter(Boolean)}
              allAdded={allAdded}
            />
          </div>
           <div className="space-y-3">
             {activeRecipe.ingredients?.map((group, gIdx) => (
               <div key={gIdx}>
                 {group.group && <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wide mt-4 mb-2">{group.group}</h3>}
                 <div className="space-y-2">
                   {(group.items || []).map((item, iIdx) => {
                     const scaleFactor = selectedServings / (recipe.servings || 1);
                     const refIndex = (activeRecipe.ingredients || []).slice(0, gIdx).reduce((sum, g) => sum + (g.items?.length || 0), 0) + iIdx;
                     return (
                       <div key={`${gIdx}-${iIdx}`} className="flex items-center gap-2 border-b border-slate-100 last:border-b-0 py-0.5">
                         <div className="flex-1 min-w-0">
                           {recipe?.source === 'generated' ? (
                             <AIIngredientRow
                               item={item}
                               scaledAmount={scaleAIIngredientAmount(item, scaleFactor)}
                               scaledCost={item.ingredient_cost ? item.ingredient_cost * scaleFactor : null}
                             >
                               <IngredientShoppingButton
                                 ref={getIngredientRef(refIndex)}
                                 item={item}
                                 recipe={recipe}
                                 cost={item.ingredient_cost ? item.ingredient_cost * scaleFactor : null}
                                 onStateChange={handleIngredientStateChange}
                               />
                             </AIIngredientRow>
                           ) : (
                             <IngredientRow
                               amount={item.amount}
                               unit={item.unit || ''}
                               name={item.name}
                               optional={item.optional}
                               cost={item.ingredient_cost || null}
                               scale={scaleFactor}
                             />
                           )}
                         </div>
                         {recipe?.source !== 'generated' && (
                           <IngredientShoppingButton
                             ref={getIngredientRef(refIndex)}
                             item={item}
                             recipe={recipe}
                             cost={item.ingredient_cost ? item.ingredient_cost * scaleFactor : null}
                             scaleFactor={scaleFactor}
                             onStateChange={handleIngredientStateChange}
                           />
                         )}
                       </div>
                     );
                   })}
                 </div>
               </div>
             ))}
           </div>
         </div>

         {/* Nutrition */}
         <div className="mt-6">
           <NutritionPanel
             ingredientGroups={recipe.ingredients}
             defaultServings={recipe.servings || 1}
             adjustedServings={selectedServings}
             showPerServing={showPerServing}
             onToggleViewMode={() => setShowPerServing(v => !v)}
             storedNutritionTotal={recipe.nutrition_total_for_recipe}
             storedNutritionPerServing={recipe.nutrition_per_serving}
           />
         </div>

         {/* Cook Mode button — positioned after nutrition, before instructions */}
         <div className="mt-6 mb-2">
           <button
             onClick={() => {
               const url = createPageUrl("CookMode") + `?id=${recipe.id}&return_to=${encodeURIComponent(createPageUrl("RecipeDetail") + `?id=${recipe.id}${returnTo ? `&return_to=${encodeURIComponent(returnTo)}` : ''}`)}`;
               window.location.href = url;
             }}
             className="w-full flex items-center justify-center gap-1.5 px-4 py-3 rounded-2xl text-white text-sm font-bold shadow-lg active:scale-95 transition-all"
             style={{ background: "linear-gradient(135deg,#6366f1,#8b5cf6)" }}>
             <Play className="w-4 h-4 fill-white" />
             {t('recipe.cook_now', 'Cook Now')}
             </button>
         </div>

         {/* Action Buttons — Log Meal + Review — placed prominently after Cook Now */}
         <ActionButtons 
           recipeId={recipe.id}
           onCookClick={() => setShowMealLoggingModal(true)}
           isLoading={false}
           isGenerated={recipe.source === 'generated'}
           isOwner={!!(user && (recipe.author_id === user.id || recipe.created_by === user.email))}
           userHasReviewed={userHasReviewed}
           reviewCheckLoading={!user || !reviewsFetched}
         />

             {/* Steps */}
             <div className="mt-6">
               <h2 className="text-lg font-bold text-slate-900 mb-4">{t('recipe.instructions', 'Instructions')}</h2>
               <div className="space-y-3">
               {(getLocalizedSteps(activeRecipe, resolvedLang).length > 0
               ? getLocalizedSteps(activeRecipe, resolvedLang)
               : (recipe?.steps || [])
             ).map((step) => (
               <InstructionStep
                 key={step.step_number}
                 stepNumber={step.step_number}
                 instruction={step.instruction}
                 timerMinutes={step.timer_minutes || 0}
               />
             ))}
           </div>
         </div>

         {/* Substitutions */}
         {activeRecipe.substitutions?.length > 0 && (
           <div className="mt-6">
             <h2 className="text-lg font-bold text-slate-900 mb-3">{t('recipe.substitutions', 'Substitutions')}</h2>
             <div className="space-y-2">
               {activeRecipe.substitutions.map((sub, i) => (
                 <div key={i} className="flex items-center gap-3 p-3 rounded-xl bg-amber-50">
                   <span className="text-sm text-slate-600">{sub.original}</span>
                   <span className="text-xs text-slate-400">→</span>
                   <span className="text-sm font-medium text-amber-700">{sub.substitute}</span>
                 </div>
               ))}
             </div>
           </div>
         )}

        {/* Cooked Count + Action Buttons */}
        {cookedCount > 0 && (
          <div className="flex items-center gap-1 px-3 py-1.5 rounded-full bg-emerald-50 w-fit mt-6 mb-2">
            <CheckCircle2 className="w-4 h-4 text-emerald-600" />
            <span className="text-sm font-semibold text-emerald-700">{cookedCount} {t('recipe.cooked_it','cooked it')}</span>
          </div>
        )}

        {/* Save / Unsave for AI-generated recipes — placed near Log Meal */}
        {recipe?.source === 'generated' && (
          <div className="mt-4 mb-2">
            <style>{`
              .ai-save-btn {
                transition: background 0.22s ease, color 0.22s ease, box-shadow 0.22s ease;
              }
            `}</style>
            <button
              onClick={handleSave}
              disabled={savingInFlightAI || savedStateAI === null}
              className="ai-save-btn w-full h-12 rounded-2xl font-bold text-sm flex items-center justify-center gap-2 disabled:opacity-60"
              style={savedStateAI ? {
                background: "linear-gradient(135deg,#a16207,#ca8a04)",
                color: "#fff8e1",
                boxShadow: "0 3px 14px rgba(161,98,7,0.35)",
              } : {
                background: "linear-gradient(135deg,#C8960C 0%,#F7C948 45%,#D4A017 80%,#B8860B 100%)",
                color: "#3d1f00",
                boxShadow: "0 4px 18px rgba(212,160,23,0.45)",
              }}
            >
              {savingInFlightAI ? (
                <span className="w-4 h-4 border-2 border-current/40 border-t-current rounded-full animate-spin" />
              ) : savedStateAI ? (
                <><CheckCircle2 className="w-4 h-4" /><span>{t('recipe.saved_to_generated', 'Saved to Generated')}</span></>
              ) : (
                <><Save className="w-4 h-4" /><span>{t('recipe.save_recipe', 'Save Recipe')}</span></>
              )}
            </button>
          </div>
        )}

        {/* Meal Logging Modal */}
        <MealLoggingModal
          isOpen={showMealLoggingModal}
          recipe={recipe}
          onConfirm={handleMealLoggingConfirm}
          onCancel={() => setShowMealLoggingModal(false)}
        />

        {/* Insufficient Ingredients Modal */}
        <InsufficientIngredientsModal
          isOpen={showInsufficientModal}
          problematicItems={insufficientItems}
          onContinue={handleInsufficientContinue}
          onCancel={() => { setShowInsufficientModal(false); setPendingLoggingData(null); setLoggingInFlight(false); }}
          onEditIngredient={handleInsufficientEditIngredient}
        />

        {/* Allergen Warning Modal — shown on post open when user has matching allergies */}
        {/* AllergenWarningModal — HARD ALERT ONLY (user is allergic to detected ingredient) */}
        <AllergenWarningModal
          isOpen={showAllergenWarning && detectedAllergenInfo.allergens?.length > 0}
          allergens={detectedAllergenInfo.allergens || []}
          ingredients={detectedAllergenInfo.triggeringIngredients || []}
          recipeName={recipe?.title}
          onProceed={() => {
            setShowAllergenWarning(false);
            setAllergenWarningDismissed(true);
          }}
          onCancel={() => {
            setShowAllergenWarning(false);
            window.history.back();
          }}
        />

        {/* Meal Logged Celebration — Strava-style full screen */}
        <MealLoggedCelebration
          isVisible={showMealCelebration}
          recipeName={celebrationData?.recipeName || ''}
          recipeImage={celebrationData?.recipeImage || ''}
          servingsEaten={celebrationData?.servingsEaten || 1}
          calories={celebrationData?.calories || 0}
          protein={celebrationData?.protein || 0}
          onComplete={() => {
            setShowMealCelebration(false);
            window.location.href = createPageUrl("Home");
          }}
        />

        {/* Unified Recipe Share Sheet */}
        <AnimatePresence>
          {showShareSheet && (
            <ReciplyShareSheet
              isOpen={showShareSheet}
              onClose={() => setShowShareSheet(false)}
              type="recipe"
              preview={{
                name: recipe?.title,
                image: recipe?.hero_image_url,
                authorName: recipe?.author_name,
              }}
              shareUrl={buildRecipeShareUrl(recipeId)}
              shareTitle={`${recipe?.title || 'Recipe'} — Reciply`}
              shareText={buildRecipeShareMessage(recipe?.title || 'this recipe', recipeId)}
              recipeId={recipeId}
              recipeName={recipe?.title}
              onSendToContacts={async (recipientIds) => {
                const content = buildRecipeShareMessage(recipe?.title || 'this recipe', recipeId);
                await Promise.all(
                  recipientIds.map(rid =>
                    base44.functions.invoke('sendDirectMessage', { recipient_id: rid, content })
                  )
                );
              }}
            />
          )}
        </AnimatePresence>

        {/* Reviews Section — hidden for AI-generated recipes */}
          {recipe?.source !== 'generated' && reviews.length > 0 && (
            <div className="mt-8">
              <h2 className="text-lg font-bold text-slate-900 mb-3">
                {t('recipe.reviews', 'Reviews')} <span className="text-slate-400 font-normal">({recipe.review_count || reviews.length})</span>
              </h2>
            <div className="space-y-3">
              {reviews.map(review => (
                <ReviewCard
                  key={review.id}
                  review={review}
                  isOwn={!!(user && (review.author_id === user.id || review.created_by === user.email))}
                  recipeId={recipeId}
                  onDeleted={() => {
                    // Force immediate refetch so userHasReviewed updates instantly
                    queryClient.invalidateQueries({ queryKey: ["reviews", recipeId] });
                    queryClient.invalidateQueries({ queryKey: ["recipe", recipeId] });
                    queryClient.refetchQueries({ queryKey: ["reviews", recipeId] });
                  }}
                />
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
    </PullToRefresh>
  );
}

import React, { useState, useEffect, useCallback, useMemo, useRef } from "react";
import { base44 } from "@/api/base44Client";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { ArrowLeft, Plus, Search, X, Lightbulb, MessageCircle } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import FeedbackCardCompact from "../components/feedback/FeedbackCardCompact";
import CreateFeedbackSheet from "../components/feedback/CreateFeedbackSheet";
import EditFeedbackSheet from "../components/feedback/EditFeedbackSheet";
import FeedbackDetailSheet from "../components/feedback/FeedbackDetailSheet";
import { useCurrentUser } from "@/hooks/useCurrentUser";

const SORT_OPTIONS = [
  { key: "newest", label: "Newest" },
  { key: "most_voted", label: "Most Voted" },
  { key: "most_discussed", label: "Most Discussed" },
];

const FILTER_OPTIONS = [
  { key: "all", label: "All" },
  { key: "open", label: "Open" },
  { key: "planned", label: "Planned" },
  { key: "in_progress", label: "In Progress" },
  { key: "completed", label: "Completed" },
];

export default function FeedbackBoard() {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { user, userId, isReady } = useCurrentUser();

  const [search, setSearch] = useState("");
  const [sort, setSort] = useState("newest");
  const [filter, setFilter] = useState("all");
  const [showCreate, setShowCreate] = useState(false);
  const [selectedPost, setSelectedPost] = useState(null);
  const [editingPost, setEditingPost] = useState(null);
  const [deletingPost, setDeletingPost] = useState(null);
  const isAdmin = user?.role === "admin";

  // Optimistic vote state — tracks local overrides so UI is instant
  const [optimisticVotes, setOptimisticVotes] = useState({});
  // Lock to prevent double-tap races
  const voteInFlightRef = useRef(new Set());

  const { data: posts = [], isLoading } = useQuery({
    queryKey: ["feedback-posts"],
    queryFn: () => base44.entities.FeedbackPost.list("-created_date", 200),
    enabled: isReady,
    staleTime: 30_000,
  });

  const { data: userVotes = [] } = useQuery({
    queryKey: ["feedback-votes", userId],
    queryFn: () => base44.entities.FeedbackVote.filter({ user_id: userId }),
    enabled: !!userId,
    staleTime: 30_000,
  });

  // Server vote set — combined with optimistic overrides for display
  const serverVotedIds = useMemo(() => new Set(userVotes.map(v => v.feedback_id)), [userVotes]);

  // Resolved vote state: server truth + optimistic overrides
  const hasVoted = useCallback((feedbackId) => {
    if (feedbackId in optimisticVotes) return optimisticVotes[feedbackId];
    return serverVotedIds.has(feedbackId);
  }, [serverVotedIds, optimisticVotes]);

  // Resolved vote count: server count + optimistic delta
  const getVoteCount = useCallback((post) => {
    const base = post.vote_count || 0;
    if (!(post.id in optimisticVotes)) return base;
    const serverHad = serverVotedIds.has(post.id);
    const optimistic = optimisticVotes[post.id];
    if (serverHad && !optimistic) return base - 1;
    if (!serverHad && optimistic) return base + 1;
    return base;
  }, [serverVotedIds, optimisticVotes]);

  // Optimistic vote toggle — instant UI, background sync
  const handleVote = useCallback(async (feedbackId) => {
    if (!userId) return;
    if (voteInFlightRef.current.has(feedbackId)) return;
    voteInFlightRef.current.add(feedbackId);

    const currentlyVoted = hasVoted(feedbackId);
    // Optimistic flip
    setOptimisticVotes(prev => ({ ...prev, [feedbackId]: !currentlyVoted }));

    try {
      if (currentlyVoted) {
        // Remove vote
        const existing = userVotes.find(v => v.feedback_id === feedbackId);
        if (existing) {
          await base44.entities.FeedbackVote.delete(existing.id);
        }
        const post = posts.find(p => p.id === feedbackId);
        if (post) {
          await base44.entities.FeedbackPost.update(feedbackId, {
            vote_count: Math.max(0, (post.vote_count || 0) - 1),
          });
        }
      } else {
        // Add vote
        await base44.entities.FeedbackVote.create({ feedback_id: feedbackId, user_id: userId });
        const post = posts.find(p => p.id === feedbackId);
        if (post) {
          await base44.entities.FeedbackPost.update(feedbackId, {
            vote_count: (post.vote_count || 0) + 1,
          });
        }
      }
      // Sync server state
      queryClient.invalidateQueries({ queryKey: ["feedback-posts"] });
      queryClient.invalidateQueries({ queryKey: ["feedback-votes", userId] });
    } catch (err) {
      console.error('[FeedbackBoard] vote failed:', err);
      // Revert optimistic on failure
      setOptimisticVotes(prev => {
        const next = { ...prev };
        delete next[feedbackId];
        return next;
      });
    } finally {
      voteInFlightRef.current.delete(feedbackId);
    }
  }, [userId, userVotes, posts, queryClient, hasVoted]);

  // Clear optimistic overrides when server data arrives
  useEffect(() => {
    setOptimisticVotes({});
  }, [userVotes, posts]);

  const refreshAll = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: ["feedback-posts"] });
    queryClient.invalidateQueries({ queryKey: ["feedback-votes", userId] });
  }, [queryClient, userId]);

  const handleDeletePost = useCallback(async (post) => {
    if (!post) return;
    await base44.entities.FeedbackPost.delete(post.id);
    setDeletingPost(null);
    setSelectedPost(null);
    refreshAll();
  }, [refreshAll]);

  const displayPosts = useMemo(() => {
    let filtered = posts;
    if (filter !== "all") filtered = filtered.filter(p => p.status === filter);
    if (search.trim()) {
      const q = search.toLowerCase();
      filtered = filtered.filter(p =>
        (p.title || "").toLowerCase().includes(q) ||
        (p.description || "").toLowerCase().includes(q)
      );
    }
    if (sort === "most_voted") filtered = [...filtered].sort((a, b) => getVoteCount(b) - getVoteCount(a));
    else if (sort === "most_discussed") filtered = [...filtered].sort((a, b) => (b.comment_count || 0) - (a.comment_count || 0));
    return filtered;
  }, [posts, filter, search, sort, getVoteCount]);

  useEffect(() => {
    if (selectedPost) {
      const fresh = posts.find(p => p.id === selectedPost.id);
      if (fresh) setSelectedPost(fresh);
    }
  }, [posts]);

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <div className="relative overflow-hidden px-5 pt-8 pb-6"
        style={{ background: "linear-gradient(135deg, #312e81 0%, #4f46e5 50%, #7c3aed 100%)" }}>
        <div className="absolute rounded-full" style={{ top: -40, right: -20, width: 200, height: 200, background: "rgba(255,255,255,0.06)", borderRadius: "50%" }} />
        <div className="absolute rounded-full" style={{ bottom: -30, left: -30, width: 160, height: 160, background: "rgba(255,255,255,0.04)", borderRadius: "50%" }} />
        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-4">
            <button onClick={() => navigate(-1)} className="w-9 h-9 rounded-full bg-white/15 flex items-center justify-center">
              <ArrowLeft className="w-4.5 h-4.5 text-white" />
            </button>
            <div className="flex-1">
              <h1 className="text-xl font-bold text-white tracking-tight">Feedback Board</h1>
              <p className="text-xs text-indigo-200">Share ideas & vote on what matters</p>
            </div>
            <div className="flex items-center gap-2 text-indigo-200">
              <Lightbulb className="w-4 h-4" />
              <span className="text-xs font-semibold">{posts.length} ideas</span>
            </div>
          </div>
          <div className="relative">
            <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 w-4 h-4 text-white/50" />
            <input
              type="text" value={search} onChange={e => setSearch(e.target.value)}
              placeholder="Search feedback..."
              className="w-full h-10 pl-10 pr-9 rounded-xl bg-white/15 backdrop-blur-sm text-white placeholder-white/50 text-sm outline-none focus:ring-2 focus:ring-white/30"
            />
            {search && (
              <button onClick={() => setSearch("")} className="absolute right-3 top-1/2 -translate-y-1/2">
                <X className="w-4 h-4 text-white/50" />
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="px-5 pt-4 pb-2 space-y-2.5">
        <div className="flex gap-2 overflow-x-auto hide-scrollbar -mx-5 px-5">
          {SORT_OPTIONS.map(s => (
            <button key={s.key} onClick={() => setSort(s.key)}
              className={`px-3.5 py-2 rounded-xl text-xs font-semibold whitespace-nowrap transition-all ${
                sort === s.key ? "bg-indigo-600 text-white shadow-md shadow-indigo-200" : "bg-white text-slate-500 border border-slate-200"
              }`}>{s.label}</button>
          ))}
        </div>
        <div className="flex gap-2 overflow-x-auto hide-scrollbar -mx-5 px-5">
          {FILTER_OPTIONS.map(f => (
            <button key={f.key} onClick={() => setFilter(f.key)}
              className={`px-3 py-1.5 rounded-lg text-[11px] font-semibold whitespace-nowrap transition-all ${
                filter === f.key ? "bg-slate-800 text-white" : "bg-slate-100 text-slate-400"
              }`}>{f.label}</button>
          ))}
        </div>
      </div>

      <div className="px-5 pb-32">
        {isLoading ? (
          <div className="flex justify-center py-16">
            <div className="w-8 h-8 border-2 border-indigo-200 border-t-indigo-600 rounded-full animate-spin" />
          </div>
        ) : displayPosts.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 gap-3">
            <div className="w-16 h-16 rounded-2xl bg-indigo-50 flex items-center justify-center">
              <MessageCircle className="w-7 h-7 text-indigo-400" />
            </div>
            <p className="text-sm font-semibold text-slate-600">No feedback yet</p>
            <p className="text-xs text-slate-400 text-center max-w-[240px]">Be the first to share an idea!</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-3 mt-3">
            {displayPosts.map(post => (
              <FeedbackCardCompact
                key={post.id}
                post={{ ...post, vote_count: getVoteCount(post) }}
                hasVoted={hasVoted(post.id)}
                onVote={handleVote}
                onClick={() => setSelectedPost(post)}
                onAuthorClick={(authorId) => navigate(`/UserProfile?id=${authorId}`)}
                currentUserId={userId}
                isAdmin={isAdmin}
                onEdit={(p) => setEditingPost(p)}
                onDelete={(p) => setDeletingPost(p)}
              />
            ))}
          </div>
        )}
      </div>

      <motion.button
        onClick={() => setShowCreate(true)} whileTap={{ scale: 0.9 }}
        className="fixed bottom-24 right-5 w-14 h-14 rounded-2xl flex items-center justify-center shadow-xl z-30"
        style={{ background: "linear-gradient(135deg, #6366f1, #8b5cf6)", boxShadow: "0 8px 28px rgba(99,102,241,0.45)" }}
      >
        <Plus className="w-6 h-6 text-white" />
      </motion.button>

      {user && <CreateFeedbackSheet isOpen={showCreate} onClose={() => setShowCreate(false)} user={user} onCreated={refreshAll} />}

      {user && <EditFeedbackSheet isOpen={!!editingPost} onClose={() => setEditingPost(null)} post={editingPost} onUpdated={refreshAll} />}

      {user && (
        <FeedbackDetailSheet
          post={selectedPost ? { ...selectedPost, vote_count: getVoteCount(selectedPost) } : null}
          isOpen={!!selectedPost}
          onClose={() => setSelectedPost(null)}
          user={user}
          hasVoted={selectedPost ? hasVoted(selectedPost.id) : false}
          onVote={handleVote}
          onUpdated={refreshAll}
          onEdit={(p) => { setSelectedPost(null); setEditingPost(p); }}
          onDelete={(p) => { setSelectedPost(null); setDeletingPost(p); }}
        />
      )}

      {/* Delete confirmation modal */}
      {deletingPost && (
        <div className="fixed inset-0 z-[90] bg-black/60 backdrop-blur-sm flex items-center justify-center p-5">
          <div className="bg-white rounded-3xl p-6 max-w-sm w-full shadow-2xl" onClick={e => e.stopPropagation()}>
            <div className="w-12 h-12 rounded-2xl bg-red-100 flex items-center justify-center mx-auto mb-4">
              <span className="text-2xl">🗑️</span>
            </div>
            <h3 className="text-lg font-bold text-slate-900 text-center mb-2">Delete feedback?</h3>
            <p className="text-sm text-slate-500 text-center mb-6">This will permanently remove this post and all its votes and comments.</p>
            <div className="flex gap-3">
              <button onClick={() => setDeletingPost(null)} className="flex-1 h-11 rounded-2xl bg-slate-100 text-slate-700 font-semibold text-sm">Cancel</button>
              <button onClick={() => handleDeletePost(deletingPost)} className="flex-1 h-11 rounded-2xl bg-red-500 text-white font-semibold text-sm">Delete</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/**
 * RipoStatesUpload — Admin page for uploading Ripo character state assets
 * Individual upload zones for THINKING, THINKING_ALT, EXPLAINING, EXPLAINING_ALT states
 */
import React, { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { createPageUrl } from '../utils';
import { ArrowLeft, Loader2, CheckCircle2 } from 'lucide-react';
import RipoStateUploadZone from '../components/onboarding/RipoStateUploadZone';
import { toast } from 'sonner';

const STATE_SLOTS = [
  { key: 'ripo_thinking', name: 'Thinking', description: 'Used during initial recipe generation phase' },
  { key: 'ripo_thinking_alt', name: 'Thinking Alt', description: 'Alternate thinking state for variation' },
  { key: 'ripo_explaining', name: 'Explaining', description: 'Recipe ready, explaining the dish' },
  { key: 'ripo_explaining_alt', name: 'Explaining Alt', description: 'Alternate explaining state' },
];

export default function RipoStatesUploadPage() {
  const [user, setUser] = useState(null);
  const [assets, setAssets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploadingMap, setUploadingMap] = useState({});

  useEffect(() => {
    base44.auth.me().then(u => {
      setUser(u);
      if (u?.role !== 'admin') {
        window.location.replace(createPageUrl('Home'));
        return;
      }
      loadAssets();
    }).catch(() => window.location.replace(createPageUrl('Home')));
  }, []);

  const loadAssets = async () => {
    setLoading(true);
    try {
      const allAssets = await base44.entities.RipoAsset.filter({ category: 'states' });
      setAssets(allAssets);
    } catch (err) {
      console.error('Failed to load assets:', err);
      toast.error('Failed to load assets');
    } finally {
      setLoading(false);
    }
  };

  const handleUpload = async (assetKey, file) => {
    if (!file) {
      toast.error('Please select a file');
      return;
    }

    setUploadingMap(prev => ({ ...prev, [assetKey]: true }));
    try {
      const { file_url } = await base44.integrations.Core.UploadFile({ file });
      const existing = assets.find(a => a.key === assetKey);

      if (existing) {
        await base44.entities.RipoAsset.update(existing.id, {
          file_url,
          is_active: true,
        });
      } else {
        const slot = STATE_SLOTS.find(s => s.key === assetKey);
        await base44.entities.RipoAsset.create({
          key: assetKey,
          name: slot?.name || assetKey,
          asset_type: 'image',
          category: 'states',
          file_url,
          is_active: true,
          notes: slot?.description || '',
        });
      }

      await loadAssets();
      toast.success(`${assetKey} uploaded!`);
    } catch (err) {
      console.error('Upload error:', err);
      toast.error(`Failed to upload ${assetKey}`);
    } finally {
      setUploadingMap(prev => ({ ...prev, [assetKey]: false }));
    }
  };

  if (loading || !user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-900">
        <Loader2 className="w-8 h-8 animate-spin text-slate-400" />
      </div>
    );
  }

  const completedCount = STATE_SLOTS.filter(s =>
    assets.some(a => a.key === s.key && a.file_url)
  ).length;

  return (
    <div className="min-h-screen bg-slate-900 text-white pb-16">
      {/* Header */}
      <div className="sticky top-0 z-10 bg-slate-900/95 backdrop-blur-xl border-b border-white/10 px-5 py-4 flex items-center gap-3">
        <button
          onClick={() => window.history.back()}
          className="w-10 h-10 rounded-full bg-white/10 flex items-center justify-center hover:bg-white/15 transition-colors"
        >
          <ArrowLeft className="w-5 h-5" />
        </button>
        <div className="flex-1">
          <h1 className="text-lg font-bold">Ripo Character States</h1>
          <p className="text-xs text-slate-400">{completedCount}/{STATE_SLOTS.length} assets uploaded</p>
        </div>
      </div>

      {/* Upload zones */}
      <div className="max-w-2xl mx-auto px-5 pt-8">
        <div className="space-y-6">
          {STATE_SLOTS.map(slot => {
            const existing = assets.find(a => a.key === slot.key);
            const isUploading = uploadingMap[slot.key] || false;

            return (
              <RipoStateUploadZone
                key={slot.key}
                assetKey={slot.key}
                assetName={slot.name}
                currentFile={existing?.file_url ? new File([], slot.key) : null}
                onFileSelect={() => {}} // Handled internally by zone
                onUpload={async (file) => await handleUpload(slot.key, file)}
                uploading={isUploading}
                uploadSuccess={!!existing?.file_url}
                uploadError={null}
              />
            );
          })}
        </div>

        {/* Completion message */}
        {completedCount === STATE_SLOTS.length && (
          <div className="mt-8 p-6 rounded-2xl bg-emerald-500/10 border border-emerald-500/25 text-center">
            <div className="flex items-center justify-center gap-2 mb-2">
              <CheckCircle2 className="w-6 h-6 text-emerald-400" />
              <h3 className="text-lg font-bold text-emerald-300">All states uploaded!</h3>
            </div>
            <p className="text-sm text-emerald-200/70">
              Your Ripo character is ready for generation animations.
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

