function SavedTab({ userId, userEmail }) {
  const queryClient = useQueryClient();
  const { t } = useLocalization();
  // Optimistic removal: track locally-unsaved IDs so card disappears instantly
  const [localUnsavedIds, setLocalUnsavedIds] = React.useState(new Set());

  // ENGAGEMENT FIX: Fetch viewer's liked recipe IDs so SavedTab cards show correct liked state.
  // Uses the same unified Like entity that toggleLikeUnified writes to.
  const { data: savedTabLikes = [] } = useQuery({
    queryKey: ["user-likes-unified", userId],
    queryFn: () => base44.entities.Like.filter({ user_id: userId, target_type: 'recipe' }),
    enabled: !!userId,
    staleTime: 30 * 1000,
  });
  const savedTabLikedIds = React.useMemo(() => new Set(savedTabLikes.map(l => l.target_id)), [savedTabLikes]);

  // Subscribe to RecipeSave entity changes to re-fetch when saves change on other surfaces
  React.useEffect(() => {
    if (!userId) return;
    const unsub = base44.entities.RecipeSave.subscribe(() => {
      queryClient.invalidateQueries({ queryKey: ["normal-recipe-saves-full", userId] });
    });
    return () => unsub();
  }, [userId, queryClient]);

  const { data, isLoading, isFetched, isRefetching } = useQuery({
    queryKey: ["normal-recipe-saves-full", userId],
    queryFn: async () => {
      const saves = await base44.entities.RecipeSave.filter({ created_by: userEmail }, "-created_date", 50).catch(() => []);

      if (!saves.length) return { saves: [], recipes: [] };

      const recipeIds = saves.map(s => s.recipe_id).filter(Boolean);
      const results = await Promise.all(
        recipeIds.map(id => base44.entities.Recipe.filter({ id }).then(r => r[0] || null).catch(() => null))
      );

      const recipeMap = {};
      results.forEach(r => { if (r?.id) recipeMap[r.id] = r; });

      // Build display list: skip removed/moderated, null, and inaccessible recipes
      // Each item is individually guarded so one bad save never crashes the whole list
      const validRecipes = saves
        .map(s => {
          try { return recipeMap[s.recipe_id] || null; } catch { return null; }
        })
        .filter(r => {
          if (!r || !r.id) return false;
          // Skip moderation-removed content
          if (r.moderation_status === 'removed_by_moderation' || r.moderation_status === 'appealed') return false;
          // Only skip if EXPLICITLY suspended/deleted — NOT paused/restored (stale denormalized value)
          // author_account_status can be stale on Recipe entity after account restore — be conservative
          if (r.author_account_status && ['suspended', 'deleted', 'pending_deletion'].includes(r.author_account_status)) return false;
          return true;
        });

      return { saves, recipes: validRecipes };
    },
    enabled: !!userId,
    // Instant refetch on invalidation — saves must appear immediately after user action
    staleTime: 0,
    placeholderData: (prev) => prev, // keep previous data visible while refetching
  });

  const handleUnsave = React.useCallback(async (recipeId) => {
    // Optimistic: hide immediately
    setLocalUnsavedIds(prev => new Set([...prev, recipeId]));
    try {
      await base44.functions.invoke('toggleRecipeSave', { recipe_id: recipeId });
    } catch (_) {
      // Revert on error
      setLocalUnsavedIds(prev => { const next = new Set(prev); next.delete(recipeId); return next; });
    }
    // Invalidate with and without userId to catch all call sites
    queryClient.invalidateQueries({ queryKey: ["normal-recipe-saves-full"] });
    queryClient.invalidateQueries({ queryKey: ["normal-recipe-saves-check"] });
    queryClient.invalidateQueries({ queryKey: ["saved-recipes"] });
  }, [queryClient, userId]);

  // Reset local unsaved IDs when data re-fetches (so stale ids don't persist)
  React.useEffect(() => {
    if (isFetched) setLocalUnsavedIds(new Set());
  }, [isFetched, data?.saves?.length]);

  // C1 FIX: Show skeleton only on true first-load (no data at all, not background refetch).
  // placeholderData keeps previous visible during refetch — only block on virgin load.
  if (!isFetched && !data) {
    return <div className="flex flex-col gap-3">{[1,2,3].map(i => <div key={i} className="h-44 bg-slate-100 rounded-2xl animate-pulse" />)}</div>;
  }

  const saves = data?.saves || [];
  const savedRecipes = (data?.recipes || []).filter(r => r?.id && !localUnsavedIds.has(r.id));

  // Only show empty state AFTER confirmed isFetched AND no saves at all
  if (isFetched && saves.length === 0) {
    return <EmptyState icon={Bookmark} title={t('profile.no_saved_title','No saved recipes')} description={t('profile.no_saved_desc','Save community and shop recipes to see them here')} />;
  }

  // If saves exist but we're still resolving — show skeleton, never blank
  if (saves.length > 0 && savedRecipes.length === 0 && isLoading) {
    return <div className="flex flex-col gap-3">{[1,2,3].map(i => <div key={i} className="h-44 bg-slate-100 rounded-2xl animate-pulse" />)}</div>;
  }

  // A2 FIX: Only show "unavailable" when confirmed: fetched, data resolved, saves exist, all recipes filtered.
  // NEVER show this during a background refetch — keep last good content instead.
  if (isFetched && !isLoading && !isRefetching && saves.length > 0 && savedRecipes.length === 0) {
    return <EmptyState icon={Bookmark} title={t('profile.saved_unavailable_title','Saved recipes unavailable')} description={t('profile.saved_unavailable_desc','The recipes you saved are no longer available in the community')} />;
  }

  return (
    <div className="flex flex-col gap-3">
      {savedRecipes.map(r => (
        <VipRecipeCard
          key={r.id}
          recipe={r}
          showLike
          showSave
          isLiked={savedTabLikedIds.has(r.id)}
          isSaved={!localUnsavedIds.has(r.id)}
          showCook
          onSave={() => handleUnsave(r.id)}
          onClick={() => window.location.href = createPageUrl("RecipeDetail") + `?id=${r.id}`}
        />
      ))}
    </div>
  );
}

