import React, { useState, useMemo, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, Globe, DollarSign, Search, Check, ChevronRight, X, AlertCircle, Lock, Sparkles } from "lucide-react";
