import { getDeviceLanguage, SUPPORTED_LANGUAGES } from "@/services/localization/languages.js";
import { detectCurrencyFromLocale, SUPPORTED_CURRENCIES } from "@/services/localization/currencies.js";
import { useLocalization } from "@/services/localization/LocalizationContext";
import { cn } from "@/lib/utils";

const CONTENT_LANGUAGE_MODES = [
  { id: "appLanguage",  label: "Use App Language",    description: "Translates recipes to match your app language", icon: "🔗" },
  { id: "original",     label: "Original Language",   description: "Always show recipes in their original language", icon: "📖" },
  { id: "autoTranslate",label: "Auto Translate",      description: "Automatically translate all content to your app language", icon: "✨" },
  { id: "custom",       label: "Specific Language",   description: "Translate content to a specific language you choose", icon: "🌍" },
];

function getFlagEmoji(regionCode) {
  if (!regionCode || regionCode.length !== 2) return "🌐";
  try {
    return regionCode.toUpperCase().split("").map(c => String.fromCodePoint(0x1F1E6 - 65 + c.charCodeAt(0))).join("");
  } catch { return "🌐"; }
}

// ── Picker Sheet ──────────────────────────────────────────────────────────────

function PickerSheet({ title, items, selectedKey, onSelect, onClose, searchable }) {
  const [query, setQuery] = useState("");
  const filtered = useMemo(() => {
    if (!query.trim()) return items;
    const q = query.toLowerCase();
    return items.filter(item =>
      item.label.toLowerCase().includes(q) ||
      item.subLabel?.toLowerCase().includes(q) ||
      item.key.toLowerCase().includes(q)
    );
  }, [items, query]);

  return (
    <motion.div
      initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
      className="fixed inset-0 z-[80] bg-black/60 backdrop-blur-sm flex items-end"
      onClick={onClose}
    >
      <motion.div
        initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
        transition={{ type: "spring", damping: 30, stiffness: 280 }}
        onClick={e => e.stopPropagation()}
        className="bg-white w-full rounded-t-3xl flex flex-col"
        style={{ maxHeight: "85vh", paddingBottom: "env(safe-area-inset-bottom, 16px)" }}
      >
        <div className="flex justify-center pt-3 pb-1"><div className="w-10 h-1 rounded-full bg-slate-200" /></div>
        <div className="flex items-center justify-between px-5 pb-3 pt-1">
          <h3 className="text-lg font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center">
            <X className="w-4 h-4 text-slate-500" />
          </button>
        </div>
        {searchable && (
          <div className="px-5 pb-3">
            <div className="flex items-center gap-2 px-3 py-2.5 rounded-2xl bg-slate-100">
              <Search className="w-4 h-4 text-slate-400 flex-shrink-0" />
              <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Search..."
                className="flex-1 bg-transparent text-sm text-slate-900 outline-none placeholder:text-slate-400" autoFocus />
              {query && <button onClick={() => setQuery("")}><X className="w-3.5 h-3.5 text-slate-400" /></button>}
            </div>
          </div>
        )}
        <div className="flex-1 overflow-y-auto px-4 pb-2">
          {filtered.length === 0
            ? <div className="py-10 text-center text-slate-400 text-sm">No results</div>
            : <div className="space-y-1">
                {filtered.map(item => (
                  <button key={item.key}
                    onClick={() => { onSelect(item.key); onClose(); }}
                    className={cn("w-full flex items-center gap-3 px-3 py-3 rounded-2xl transition-colors text-left",
                      selectedKey === item.key ? "bg-indigo-50" : "hover:bg-slate-50")}
                  >
                    {item.emoji && <span className="text-xl flex-shrink-0">{item.emoji}</span>}
                    <div className="flex-1 min-w-0">
                      <p className={cn("text-sm font-semibold truncate", selectedKey === item.key ? "text-indigo-700" : "text-slate-900")}>{item.label}</p>
                      {item.subLabel && <p className="text-xs text-slate-500 truncate">{item.subLabel}</p>}
                    </div>
                    {selectedKey === item.key && <Check className="w-4 h-4 text-indigo-600 flex-shrink-0" />}
                  </button>
                ))}
              </div>
          }
        </div>
      </motion.div>
    </motion.div>
  );
}

