export default function DisplayLanguageSettingsPage() {
  // Hydration state
  const [hydrationState, setHydrationState] = useState("loading"); // "loading" | "hydrated" | "error"

  // SAVED state (from backend — source of truth)
  const [savedPrefs, setSavedPrefs] = useState(null);

  // DRAFT state (local only, not committed until Save)
  const [draft, setDraft] = useState(null);

  // UI state
  const [isSaving, setIsSaving] = useState(false);
  const [saveError, setSaveError] = useState(null);
  const [picker, setPicker] = useState(null);
  const [showLeaveConfirm, setShowLeaveConfirm] = useState(false);

  // LocalizationContext: apply prefs after save
  const { setUiLanguage, setContentLanguageMode, setCurrency, resolvedLang, resolvedCurrency, t } = useLocalization();

  // Derive display prefs (draft takes priority over saved)
  const displayPrefs = draft || savedPrefs || {
    app_language: null,
    content_language_mode: "appLanguage",
    content_language_custom: null,
    currency_code: null,
  };

  const hasChanges = draft !== null;

  // ── Hydrate from backend on mount ───────────────────────────────────────────
  useEffect(() => {
    let cancelled = false;
    const hydrate = async () => {
      try {
        const user = await base44.auth.me();
        if (cancelled) return;
        // Use locale_preferences from user profile
        const loaded = user?.locale_preferences ? { ...user.locale_preferences } : {
          app_language: null,
          content_language_mode: "appLanguage",
          content_language_custom: null,
          currency_code: null,
        };
        setSavedPrefs(loaded);
        setHydrationState("hydrated");
      } catch (err) {
        if (!cancelled) {
          console.error("[DisplayLanguageSettings] hydration failed:", err.message);
          setHydrationState("error");
        }
      }
    };
    hydrate();
    return () => { cancelled = true; };
  }, []);

  // ── Navigation guard: confirm leaving with unsaved changes ──────────────────
  useEffect(() => {
    if (!hasChanges) return;
    const handleBeforeUnload = (e) => { e.preventDefault(); e.returnValue = ""; };
    window.addEventListener("beforeunload", handleBeforeUnload);
    return () => window.removeEventListener("beforeunload", handleBeforeUnload);
  }, [hasChanges]);

  // ── Draft helpers ────────────────────────────────────────────────────────────
  const setDraftPref = (key, value) => {
    setSaveError(null);
    setDraft(prev => ({ ...(prev || savedPrefs || {}), [key]: value }));
  };

  const handleDiscard = () => {
    setDraft(null);
    setSaveError(null);
  };

  // ── Save to backend ──────────────────────────────────────────────────────────
  const handleSave = async () => {
    if (!hasChanges || isSaving) return;
    setIsSaving(true);
    setSaveError(null);
    try {
      const toSave = { ...draft };
      await base44.auth.updateMe({ locale_preferences: toSave });

      // Commit saved state
      setSavedPrefs(toSave);
      setDraft(null);

      // Apply to live localization context immediately (always, even if null = reset to auto)
      setUiLanguage(toSave.app_language || null);
      setContentLanguageMode(toSave.content_language_mode || "appLanguage", toSave.content_language_custom || null);
      setCurrency(toSave.currency_code || null);

      // Show inline success briefly
      setSaveError(null);
    } catch (err) {
      console.error("[DisplayLanguageSettings] save failed:", err.message);
      setSaveError(err.message || "Failed to save. Please try again.");
    } finally {
      setIsSaving(false);
    }
  };

  // ── Back navigation ──────────────────────────────────────────────────────────
  const handleBack = () => {
    if (hasChanges) {
      setShowLeaveConfirm(true);
    } else {
      window.history.back();
    }
  };

  // ── Content Mode Selection ───────────────────────────────────────────────────
  const handleContentModeSelect = (modeId) => {
    setDraftPref("content_language_mode", modeId);
    if (modeId !== "custom") setDraftPref("content_language_custom", null);
    if (modeId === "custom") setTimeout(() => setPicker("customLang"), 200);
  };

  // ── Build picker items ───────────────────────────────────────────────────────
  const languageItems = useMemo(() =>
    Object.entries(SUPPORTED_LANGUAGES).map(([code, info]) => ({
      key: code, label: info.nativeName, subLabel: info.name, emoji: getFlagEmoji(info.region),
    })), []);

  const currencyItems = useMemo(() =>
    Object.entries(SUPPORTED_CURRENCIES).map(([code, info]) => ({
      key: code, label: `${info.symbol} ${info.name}`, subLabel: code, emoji: null,
    })), []);

  const contentLangItems = useMemo(() =>
    Object.entries(SUPPORTED_LANGUAGES).map(([code, info]) => ({
      key: code, label: info.nativeName, subLabel: info.name, emoji: getFlagEmoji(info.region),
    })), []);

  const currentModeName = CONTENT_LANGUAGE_MODES.find(m => m.id === displayPrefs.content_language_mode)?.label || "Original Language";
  const currentCustomLang = displayPrefs.content_language_custom ? SUPPORTED_LANGUAGES[displayPrefs.content_language_custom]?.nativeName : null;
  const currencyInfo = SUPPORTED_CURRENCIES[displayPrefs.currency_code];
  const langInfo = SUPPORTED_LANGUAGES[displayPrefs.app_language];
  // Auto-detected fallbacks for display
  const autoLangInfo = SUPPORTED_LANGUAGES[resolvedLang];
  const autoCurrencyInfo = SUPPORTED_CURRENCIES[resolvedCurrency];

  // ── Loading / error states ────────────────────────────────────────────────────
  if (hydrationState === "loading") {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="flex flex-col items-center gap-3">
          <div className="w-8 h-8 rounded-full border-2 border-indigo-200 border-t-indigo-600 animate-spin" />
          <p className="text-sm text-slate-500">{t('displaylang.loading', 'Loading your preferences...')}</p>
        </div>
      </div>
    );
  }

  if (hydrationState === "error") {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6">
        <div className="bg-white rounded-2xl p-6 max-w-sm text-center shadow-sm border border-slate-100">
          <div className="w-12 h-12 rounded-full bg-rose-100 flex items-center justify-center mx-auto mb-3">
            <AlertCircle className="w-6 h-6 text-rose-600" />
          </div>
          <p className="font-semibold text-slate-900 mb-1">{t('displaylang.error_title', 'Failed to load preferences')}</p>
          <p className="text-xs text-slate-500 mb-4">{t('displaylang.error_body', 'Your settings could not be loaded from the server.')}</p>
          <button onClick={() => window.location.reload()}
            className="w-full h-10 rounded-lg bg-indigo-600 text-white font-semibold text-sm hover:bg-indigo-700 transition-colors">
            {t('displaylang.retry', 'Retry')}
          </button>
        </div>
      </div>
    );
  }

  // ── Main render ───────────────────────────────────────────────────────────────
  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <div className="bg-white border-b border-slate-100 sticky top-0 z-20">
        <div className="flex items-center gap-3 px-4 py-4">
          <button onClick={handleBack} className="w-9 h-9 rounded-xl bg-slate-100 flex items-center justify-center">
            <ArrowLeft className="w-4 h-4 text-slate-700" />
          </button>
          <div className="flex-1 min-w-0">
            <h1 className="text-base font-bold text-slate-900">{t('displaylang.title', 'Display & Language')}</h1>
            {hasChanges && (
              <p className="text-xs text-amber-500 font-semibold">{t('displaylang.unsaved', 'Unsaved changes')}</p>
            )}
          </div>
        </div>
      </div>

      {/* Content */}
      <div className={cn("px-4 pt-5 space-y-5", hasChanges ? "pb-32" : "pb-10")}>
        <p className="text-sm text-slate-500 px-1">
          {t('displaylang.subtitle', 'Customize how the app looks and speaks to you')}
        </p>

        {/* App Language */}
        <div>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider px-1 mb-2">{t('displaylang.app_lang_section', 'App Language')}</p>
          <div className="rounded-2xl overflow-hidden shadow-sm">
            <SettingsRow
              icon={Globe} iconColor="text-indigo-600" iconBg="bg-indigo-50"
              title={t('displaylang.app_lang_title', 'App Language')} subtitle={t('displaylang.app_lang_subtitle', 'Language used across the app interface')}
              value={langInfo?.nativeName || (autoLangInfo ? `Auto: ${autoLangInfo.nativeName}` : t('displaylang.app_lang_auto', 'Auto-detect'))}
              onClick={() => setPicker("language")}
            />
          </div>
        </div>

        {/* Posts Translation — Premium Locked Coming Soon */}
        <ComingSoonPostsTranslation t={t} />

        {/* Currency */}
        <div>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider px-1 mb-2">{t('displaylang.currency_section', 'Currency')}</p>
          <div className="rounded-2xl overflow-hidden shadow-sm">
            <SettingsRow
              icon={DollarSign} iconColor="text-emerald-600" iconBg="bg-emerald-50"
              title={t('displaylang.currency_title', 'Currency')} subtitle={t('displaylang.currency_subtitle', 'Currency used for prices across the app')}
              value={currencyInfo ? `${currencyInfo.symbol} ${displayPrefs.currency_code}` : (autoCurrencyInfo ? `Auto: ${autoCurrencyInfo.symbol} ${resolvedCurrency}` : t('displaylang.currency_auto', 'Auto-detect'))}
              onClick={() => setPicker("currency")}
            />
          </div>
        </div>

        <p className="text-xs text-slate-400 text-center px-1">
          {t('displaylang.auto_detect_note', 'Auto-detected from your device if not set')}
        </p>
      </div>

      {/* Sticky Save Bar — only visible when there are unsaved changes */}
      <AnimatePresence>
        {hasChanges && (
          <motion.div
            initial={{ y: 100, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: 100, opacity: 0 }}
            transition={{ type: "spring", damping: 28, stiffness: 300 }}
            className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-4 py-4 z-30"
            style={{ paddingBottom: "calc(env(safe-area-inset-bottom, 0px) + 16px)" }}
          >
            <div className="max-w-lg mx-auto flex gap-3">
              <button
                onClick={handleDiscard} disabled={isSaving}
                className="flex-1 h-11 rounded-2xl bg-slate-100 text-slate-700 font-semibold text-sm hover:bg-slate-200 disabled:opacity-50 transition-colors"
              >
                {t('displaylang.discard_btn', 'Discard')}
              </button>
              <button
                onClick={handleSave} disabled={isSaving}
                className="flex-1 h-11 rounded-2xl bg-indigo-600 text-white font-semibold text-sm hover:bg-indigo-700 disabled:opacity-50 transition-colors flex items-center justify-center gap-2"
              >
                {isSaving ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    {t('displaylang.saving', 'Saving...')}
                  </>
                ) : (
                  <>
                    <Check className="w-4 h-4" />
                    {t('displaylang.save_btn', 'Save Changes')}
                  </>
                )}
              </button>
            </div>
            {saveError && (
              <div className="mt-2 p-3 rounded-lg bg-rose-50 border border-rose-200 flex items-start gap-2">
                <AlertCircle className="w-4 h-4 text-rose-500 flex-shrink-0 mt-0.5" />
                <div>
                  <p className="text-xs text-rose-700 font-medium">{saveError}</p>
                  <button onClick={handleSave} className="text-xs text-rose-600 font-semibold mt-1 hover:underline">
                    {t('displaylang.try_again', 'Try again')}
                  </button>
                </div>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Picker Sheets */}
      <AnimatePresence>
        {picker === "language" && (
          <PickerSheet
            title={t('displaylang.app_lang_title', 'App Language')}
            items={languageItems}
            selectedKey={displayPrefs.app_language}
            onSelect={(lang) => setDraftPref("app_language", lang)}
            onClose={() => setPicker(null)}
            searchable
          />
        )}

        {picker === "contentMode" && (
          <motion.div
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[80] bg-black/60 backdrop-blur-sm flex items-end"
            onClick={() => setPicker(null)}
          >
            <motion.div
              initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
              transition={{ type: "spring", damping: 30, stiffness: 280 }}
              onClick={e => e.stopPropagation()}
              className="bg-white w-full rounded-t-3xl"
              style={{ paddingBottom: "env(safe-area-inset-bottom, 16px)" }}
            >
              <div className="flex justify-center pt-3 pb-1"><div className="w-10 h-1 rounded-full bg-slate-200" /></div>
              <div className="flex items-center justify-between px-5 pb-4 pt-2">
                <h3 className="text-lg font-bold text-slate-900">{t('displaylang.content_mode_picker_title', 'Recipe & Post Language')}</h3>
                <button onClick={() => setPicker(null)} className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center">
                  <X className="w-4 h-4 text-slate-500" />
                </button>
              </div>
              <div className="px-4 pb-5 space-y-2">
                {CONTENT_LANGUAGE_MODES.map(mode => (
                  <button key={mode.id}
                    onClick={() => { handleContentModeSelect(mode.id); if (mode.id !== "custom") setPicker(null); }}
                    className={cn(
                      "w-full flex items-center gap-3 p-4 rounded-2xl transition-colors text-left",
                      displayPrefs.content_language_mode === mode.id
                        ? "bg-indigo-50 border-2 border-indigo-200"
                        : "bg-slate-50 border-2 border-transparent hover:bg-slate-100"
                    )}
                  >
                    <span className="text-2xl">{mode.icon}</span>
                    <div className="flex-1">
                      <p className={cn("text-sm font-bold",
                        displayPrefs.content_language_mode === mode.id ? "text-indigo-700" : "text-slate-900")}>
                        {mode.label}
                      </p>
                      <p className="text-xs text-slate-500 mt-0.5">{mode.description}</p>
                      {mode.id === "custom" && displayPrefs.content_language_mode === "custom" && displayPrefs.content_language_custom && (
                        <p className="text-xs text-indigo-500 mt-0.5 font-medium">
                          {SUPPORTED_LANGUAGES[displayPrefs.content_language_custom]?.nativeName}
                        </p>
                      )}
                    </div>
                    {displayPrefs.content_language_mode === mode.id && (
                      <Check className="w-4 h-4 text-indigo-600 flex-shrink-0" />
                    )}
                  </button>
                ))}
              </div>
            </motion.div>
          </motion.div>
        )}

        {picker === "currency" && (
          <PickerSheet
            title={t('displaylang.currency_title', 'Currency')}
            items={currencyItems}
            selectedKey={displayPrefs.currency_code}
            onSelect={(code) => setDraftPref("currency_code", code)}
            onClose={() => setPicker(null)}
            searchable
          />
        )}

        {picker === "customLang" && (
          <PickerSheet
            title={t('displaylang.select_content_lang', 'Select Content Language')}
            items={contentLangItems}
            selectedKey={displayPrefs.content_language_custom}
            onSelect={(lang) => setDraftPref("content_language_custom", lang)}
            onClose={() => setPicker(null)}
            searchable
          />
        )}
      </AnimatePresence>

      {/* Leave without saving confirm */}
      <AnimatePresence>
        {showLeaveConfirm && (
          <motion.div
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[90] bg-black/60 backdrop-blur-sm flex items-center justify-center p-5"
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="bg-white rounded-3xl p-6 max-w-sm w-full"
            >
              <h3 className="text-lg font-bold text-slate-900 mb-2">{t('displaylang.discard_title', 'Discard changes?')}</h3>
              <p className="text-sm text-slate-600 mb-6">
                {t('displaylang.discard_body', 'You have unsaved changes. Are you sure you want to leave without saving?')}
              </p>
              <div className="flex gap-3">
                <button
                  onClick={() => setShowLeaveConfirm(false)}
                  className="flex-1 h-11 rounded-2xl bg-slate-100 text-slate-700 font-semibold text-sm"
                >
                  {t('displaylang.keep_editing', 'Keep Editing')}
                </button>
                <button
                  onClick={() => { setShowLeaveConfirm(false); handleDiscard(); window.history.back(); }}
                  className="flex-1 h-11 rounded-2xl bg-rose-500 text-white font-semibold text-sm"
                >
                  {t('displaylang.discard_leave', 'Discard & Leave')}
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

