export default function FriendGroupsPage() {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { t } = useLocalization();
  const [search, setSearch] = useState("");
  const [leaveTarget, setLeaveTarget] = useState(null); // { groupId, groupName }

  // CENTRALIZED: use AuthContext — never call auth.me() independently
  const { user } = useCurrentUser();

  // Fetch friends_chat groups — NO placeholderData to prevent ghost groups after leave/delete.
  // staleTime is short so returning to this page always shows fresh server state.
  const { data: groups = [], isLoading, refetch } = useQuery({
    queryKey: ["friend-groups-page", user?.id],
    queryFn: async () => {
      if (!user?.id) return [];
      const memberships = await base44.entities.GroupMember.filter({ user_id: user.id, status: "active" });
      if (!memberships.length) return [];
      const results = await Promise.all(
        memberships.map(async (m) => {
          const gs = await base44.entities.Group.filter({ id: m.group_id, group_type: "friends_chat" }).catch(() => []);
          const g = gs[0];
          if (!g) return null;
          return { ...g, myRole: m.role };
        })
      );
      return results.filter(Boolean).sort((a, b) => new Date(b.updated_date || b.created_date) - new Date(a.updated_date || a.created_date));
    },
    enabled: !!user?.id,
    staleTime: 15 * 1000,
    refetchOnMount: 'always',
  });

  const filtered = groups.filter((g) =>
    !search || g.name?.toLowerCase().includes(search.toLowerCase())
  );

  const handleLeaveClick = (groupId, groupName) => {
    setLeaveTarget({ groupId, groupName });
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <div className="sticky top-0 z-10 bg-white/95 backdrop-blur-lg border-b border-slate-100">
        <div className="flex items-center gap-3 px-4 py-3">
          <button
            onClick={() => navigate(-1)}
            className="w-9 h-9 rounded-xl bg-slate-100 flex items-center justify-center"
          >
            <ChevronLeft className="w-5 h-5 text-slate-600" />
          </button>
          <div className="flex-1">
            <h1 className="text-lg font-bold text-slate-900">{t("friendgroups.title", "Friend Groups")}</h1>
            <p className="text-[10px] text-slate-400">{t("friendgroups.subtitle", "Private group chats with friends")}</p>
          </div>
          <button
            onClick={() => {
              // Navigate to ChatList with create-group intent
              navigate(createPageUrl("ChatList"));
            }}
            className="w-9 h-9 rounded-xl flex items-center justify-center"
            style={{ background: "linear-gradient(135deg, #8b5cf6, #6366f1)" }}
          >
            <Plus className="w-5 h-5 text-white" />
          </button>
        </div>

        {/* Search */}
        {groups.length > 3 && (
          <div className="px-4 pb-3">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
              <input
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                placeholder={t("friendgroups.search", "Search friend groups...")}
                className="w-full h-10 pl-9 pr-3 rounded-xl border border-slate-200 bg-white text-sm focus:outline-none focus:ring-2 focus:ring-purple-400/30"
              />
            </div>
          </div>
        )}
      </div>

      {/* Content */}
      <div className="px-4 pt-4 pb-32">
        {isLoading ? (
          <div className="space-y-3">
            {[1, 2, 3].map((i) => (
              <div key={i} className="h-20 bg-white rounded-2xl animate-pulse" />
            ))}
          </div>
        ) : filtered.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-center">
            <div
              className="w-20 h-20 rounded-3xl flex items-center justify-center mb-4"
              style={{ background: "linear-gradient(135deg, #f5f3ff, #ede9fe)", border: "1px solid rgba(139,92,246,0.15)" }}
            >
              <MessageCircle className="w-9 h-9 text-purple-400" />
            </div>
            <h3 className="text-base font-bold text-slate-900 mb-1">
              {search ? t("friendgroups.no_results", "No groups found") : t("friendgroups.empty_title", "No friend groups yet")}
            </h3>
            <p className="text-sm text-slate-500 max-w-[240px]">
              {search
                ? t("friendgroups.no_results_desc", "Try a different search")
                : t("friendgroups.empty_desc", "Create a group chat from any DM conversation to get started")}
            </p>
            {!search && (
              <button
