                animate={{ opacity: 1, y: 0 }}
                className="bg-white rounded-2xl border border-slate-100 overflow-hidden"
                style={{ boxShadow: "0 1px 6px rgba(0,0,0,0.04)" }}
              >
                <button
                  onClick={() => navigate(createPageUrl("FriendsGroupChat") + `?id=${group.id}`)}
