                    className="flex-1 py-2 text-[11px] font-semibold text-purple-600 hover:bg-purple-50/50 transition-colors"
                  >
                    {t("friendgroups.open_chat", "Open Chat")}
                  </button>
                  <div className="w-px bg-slate-50" />
                  <button
                    onClick={() => navigate(createPageUrl("FriendsGroupSettings") + `?id=${group.id}`)}
                    className="flex-1 py-2 text-[11px] font-semibold text-slate-500 hover:text-indigo-600 hover:bg-indigo-50/50 transition-colors"
                  >
                    <Settings className="w-3 h-3 inline mr-1" />
                    {t("friendgroups.settings", "Settings")}
