function MacroPill({ label, value, unit, color }) {
  if (!value) return null;
  return (
    <div className={`flex flex-col items-center px-3 py-2 rounded-xl ${color}`}>
      <span className="text-xs font-bold">{Math.round(value)}{unit}</span>
      <span className="text-[10px] opacity-70 mt-0.5">{label}</span>
    </div>
  );
}

