// Tiny helper: acquires/releases a bottom-nav hide lock while `active` is true
// Uses useLayoutEffect via useBottomNavLock so the nav is hidden before paint
function BottomNavOverlayLock({ active }) {
  useBottomNavLock(active);
  return null;
}

// Constants moved to PantryModeForm component

export default function GeneratePage() {
  const queryClient = useQueryClient();
  // CENTRALIZED: user from AuthContext — never call auth.me() here
  const { user: authContextUser } = useCurrentUser();
  const [user, setUser] = useState(null);
  const [mealType, setMealType] = useState("dinner");
  const [cuisine, setCuisine] = useState("mediterranean");
  const [maxCookTime, setMaxCookTime] = useState(30);
  const [servings, setServings] = useState(2);
  const [difficulty, setDifficulty] = useState("easy");
  const [nutritionPref, setNutritionPref] = useState([]);
  const [allowMissing, setAllowMissing] = useState(false);
  const [selectedIngredients, setSelectedIngredients] = useState(new Set());
  const [generating, setGenerating] = useState(false);
  const [generatedRecipe, setGeneratedRecipe] = useState(null);
  const [saving, setSaving] = useState(false);
  const [showIngredientSelector, setShowIngredientSelector] = useState(false);
  const [showTimePicker, setShowTimePicker] = useState(false);
  const [expiredModalItems, setExpiredModalItems] = useState(null);
  const [lastPickedServing, setLastPickedServing] = useState(null);
  const [lastPickedNutrition, setLastPickedNutrition] = useState(null);
  const [allowMissingSweeping, setAllowMissingSweeping] = useState(false);
  const [displayServings, setDisplayServings] = useState(null);
  const [removeIngredient, setRemoveIngredient] = useState(null);
  const [ingredientUsageMap, setIngredientUsageMap] = useState({}); // { [pantry_item_id]: usageData }
  const [showEatConfirm, setShowEatConfirm] = useState(false);
  const [showMealLog, setShowMealLog] = useState(false);
  const [savedRecipeForEat, setSavedRecipeForEat] = useState(null);
  const [showInsufficientModal, setShowInsufficientModal] = useState(false);
  const [insufficientItems, setInsufficientItems] = useState([]);
  const [pendingGenerateLogData, setPendingGenerateLogData] = useState(null);
  const [isSaved, setIsSaved] = useState(false);
  const [showLeaveGuard, setShowLeaveGuard] = useState(false);
  const [pendingLeaveAction, setPendingLeaveAction] = useState(null);
  const [showFreeLimitModal, setShowFreeLimitModal] = useState(false);
  const [quota, setQuota] = useState(null);
  // CRITICAL: Start as false — the explicit fetchQuota() call sets true→false.
  // Starting as true caused a stuck skeleton if fetchQuota failed silently on first mount.
  const [quotaLoading, setQuotaLoading] = useState(false);
  const [optionalPrompt, setOptionalPrompt] = useState("");
  const [optionalPromptError, setOptionalPromptError] = useState("");
  const [constraintWarning, setConstraintWarning] = useState(null);
  const [showSaveConfirm, setShowSaveConfirm] = useState(false);
  const [macroNegotiation, setMacroNegotiation] = useState(null);
  const [suggestionsReview, setSuggestionsReview] = useState(null);
  const [pendingRecipeForSuggestions, setPendingRecipeForSuggestions] = useState(null);
  const [parsedProteinConstraint, setParsedProteinConstraint] = useState(null);
  const [userBypassedConstraint, setUserBypassedConstraint] = useState(false);
  const [enhanceRecipe, setEnhanceRecipe] = useState(null); // { reason, dishType, suggestions, ingredientList }
  const [enhancementCheckPending, setEnhancementCheckPending] = useState(false);
  const [allergenWarning, setAllergenWarning] = useState(null); // { allergens: string[], pendingRecipe: object }
  const generationStartRef = useRef(null);
  // Integer retry counter — 0 on fresh generation, increments per internal retry.
  // Capped at MAX_FIDELITY_RETRIES (=2) so we get at most 3 total attempts per user click.
  const generationRetryRef = useRef(0);
  // ── FAILURE HANDLING REFS (used by failureClassifier integration) ──
  // autoRetryUsedRef: did we already burn our one silent auto-retry for transient errors?
  //   Reset on a successful generation, on user-initiated fresh attempts, and on dismiss.
  // consecutiveFailureRef: counts consecutive user-visible failures across a session.
  //   When >=2, we surface a fallback CTA ("Try a simpler recipe").
  const autoRetryUsedRef = useRef(false);
  const consecutiveFailureRef = useRef(0);
  const [showFallbackCta, setShowFallbackCta] = useState(false);
  const nutritionBoostShownRef = useRef(false);
  const allergenModalShownRef = useRef(false);
  const enhanceModalShownRef = useRef(false);
  const macroNegotiationShownRef = useRef(false);
  const [isMealLogged, setIsMealLogged] = useState(false);
  const [showMealCelebration, setShowMealCelebration] = useState(false);
  const [celebrationData, setCelebrationData] = useState(null);
  const [processingMealLog, setProcessingMealLog] = useState(false);
  const [generationError, setGenerationError] = useState(null); // error message shown inside Ripo overlay
  const [genMode, setGenMode] = useState("pantry"); // "pantry" | "freestyle"
  const [freeMode, setFreeMode] = useState(false); // ignore dietary prefs in freestyle
  const [showCooldownPopup, setShowCooldownPopup] = useState(false);
  const [cooldownSeconds, setCooldownSeconds] = useState(0);
  const { constraintFallback, preGenerate, postGenerate, reset: resetConstraints } = useConstraintSolver();
  // ── SINGLE-FLIGHT GUARD: prevents spam-tap from creating multiple distinct
  // client_request_ids → which would each charge a separate credit. The guard's
  // ref-based lock flips synchronously on first tap, before any await/state work.
  const generateGuard = useGenerateClickGuard();
  const hasActiveOverlay = showCooldownPopup || showIngredientSelector || showTimePicker || showEatConfirm || showMealLog || showInsufficientModal || showLeaveGuard || showFreeLimitModal || showSaveConfirm || !!macroNegotiation || !!enhanceRecipe || !!allergenWarning || !!suggestionsReview || !!expiredModalItems || !!constraintWarning || generating || !!generatedRecipe;
  useQuotaStaleListener(() => fetchQuota());

  // Disable browser scroll restoration so it never restores mid-page position
  useEffect(() => {
    if ('scrollRestoration' in window.history) {
      window.history.scrollRestoration = 'manual';
    }
  }, []);

  // Scroll to top whenever a new recipe result appears (generation or regeneration)
  // SAFETY BELT: Whenever a recipe lands in state, FORCE-CLEAR the loading + error
  // state in the same effect. This prevents the "stuck loading" P0 bug where the
  // generating flag stays true after the recipe is set (closure / batching edge case).
  useEffect(() => {
    if (generatedRecipe) {
      // 1. Force-clear any lingering loading/error state — single source of truth.
      setGenerating(false);
      setGenerationError(null);
      generationStartRef.current = null;
      // 2. Scroll to top so user sees the result immediately.
      requestAnimationFrame(() => {
        const mainEl = document.querySelector('main');
        if (mainEl) mainEl.scrollTop = 0;
        window.scrollTo({ top: 0, left: 0, behavior: 'instant' });
        document.documentElement.scrollTop = 0;
        document.body.scrollTop = 0;
      });
    }
  }, [generatedRecipe]);

  // Register / clear the global navigation guard whenever dirty state changes
  useEffect(() => {
    const isDirty = !!generatedRecipe && !isSaved && !isMealLogged;
    if (isDirty) {
      navigationGuard.register(() => false); // always block — Layout will show modal
    } else {
      navigationGuard.clear();
    }
    return () => navigationGuard.clear(); // cleanup on unmount
  }, [generatedRecipe, isSaved, isMealLogged]);

  // Server-authoritative entitlements — null until loaded (never assume plan)
  const { isPro, generationLimit, isLoading: entLoading, ready: entReady } = useEntitlementsAdvanced();
  const { t, resolvedLang } = useLocalization();

  // NOTE: quotaLoading is controlled exclusively by fetchQuota().
  // Do NOT set quotaLoading=false from entReady — that creates a flash where
  // quotaLoading=false but quota=null, causing QuotaAreaDisplay to render
  // a broken card before fetchQuota completes.

  // Fetch authoritative quota on mount.
  // CRITICAL: Do NOT clear ent_v2 here — that destroys the global EntitlementProvider
  // cache and causes a flash where isPro=null, which breaks the quota UI.
  // EntitlementProvider handles its own revalidation on mount and foreground.
  // Sync user from AuthContext — no independent auth.me() call
  useEffect(() => {
    if (authContextUser?.id) setUser(authContextUser);
  }, [authContextUser?.id]);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const ingredients = params.get("ingredients");
    if (ingredients) {
      setSelectedIngredients(new Set(ingredients.split(",").filter(Boolean)));
    }
    // Fetch immediately — no artificial delay. fetchQuota itself handles auth settling.
    fetchQuota();
  }, []);

  // Safety: if quotaLoading stays true for >15s, force it off (prevents infinite skeleton)
  useEffect(() => {
    if (!quotaLoading) return;
    const safety = setTimeout(() => {
      console.warn('[Quota] Safety timeout — forcing quotaLoading=false after 15s');
      setQuotaLoading(false);
      if (!quota) setQuotaError(true);
    }, 15000);
    return () => clearTimeout(safety);
  }, [quotaLoading]);

  // Re-fetch quota when auth resolves (cold-start: initial mount fetch may run before user cookie is set)
  const quotaFetchedForUserRef = useRef(null);
  useEffect(() => {
    if (!authContextUser?.id) return;
    if (quotaFetchedForUserRef.current === authContextUser.id) return;
    quotaFetchedForUserRef.current = authContextUser.id;
    if (!quota && !quotaLoading) {
      fetchQuota();
    }
  }, [authContextUser?.id]);

  // NOTE: No stale fallback refs — quota state is always from the latest successful fetch.
  // If a fetch fails, we keep whatever is already in React state (which was from the previous success).

  // Device timezone from canonical single source of truth
  const clientTimezone = getClientTimezone();

  const [quotaError, setQuotaError] = useState(false);

  // SINGLE SOURCE OF TRUTH: getAiQuotaAdvanced returns is_premium + all free/pro_* fields.
  // No parallel getRecipeGenerationEntitlement fetch — that duplication caused desync races.
  const fetchQuota = async () => {
    setQuotaLoading(true);
    setQuotaError(false);
    try {
      const res = await base44.functions.invoke('getAiQuotaAdvanced', { client_timezone: clientTimezone });
      if (res?.data && !res.data.error) {
        setQuota(res.data);
        setQuotaError(false);
      } else {
        setQuotaError(true);
      }
    } catch (e) {
      console.warn('[Generate] quota fetch failed:', e.message);
      setQuotaError(true);
    } finally {
      setQuotaLoading(false);
    }
  };

  // Merge a server-provided quota snapshot into local state.
  // Never overwrites real data with null/undefined — backend is the only writer.
  const applyServerQuota = (serverQuota) => {
    if (!serverQuota || typeof serverQuota !== 'object') return;
    setQuota(serverQuota);
  };

  const handleUseBankedCredit = async () => {
    const res = await base44.functions.invoke('consumeBankedCredit', {
      client_timezone: clientTimezone,
    });
    if (res.data?.success && res.data?.quota) {
      setQuota(res.data.quota);
    }
  };

  const { data: pantryItems = [] } = useQuery({
    queryKey: ["pantry-items", user?.email],
    queryFn: () => base44.entities.PantryItem.filter({ created_by: user.email }, "-created_date", 200),
    enabled: !!user?.email,
  });

  // Restore recipe after returning from CookMode (restore_cook=1)
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    if (params.get("restore_cook") === "1") {
      try {
        const stored = sessionStorage.getItem("cookModeReturnRecipe");
        if (stored) {
          const recipe = JSON.parse(stored);
          setGeneratedRecipe(recipe);
          sessionStorage.removeItem("cookModeReturnRecipe");
        }
      } catch (e) {}
      // Clean URL
      const url = new URL(window.location.href);
      url.searchParams.delete("restore_cook");
      window.history.replaceState({}, "", url.toString());
    }
  }, []);

  // Apply regenerate payload + restore history preview (restore_preview=1)
  useRegeneratePayload({ pantryItems, setSelectedIngredients, setIngredientUsageMap, setGeneratedRecipe, setIsSaved });

  // Auto-select pantry items from URL
  useEffect(() => {
    if (pantryItems.length > 0 && selectedIngredients.size > 0) {
      const ids = new Set();
      pantryItems.forEach(p => {
        if (selectedIngredients.has(p.name)) ids.add(p.id);
      });
      if (ids.size > 0) setSelectedIngredients(ids);
    }
  }, [pantryItems]);

  const toggleIngredient = (id) => {
    const next = new Set(selectedIngredients);
    if (next.has(id)) next.delete(id); else next.add(id);
    setSelectedIngredients(next);
  };

  const toggleNutrition = (value) => {
    if (nutritionPref.includes(value)) {
      setNutritionPref(nutritionPref.filter(n => n !== value));
    } else if (nutritionPref.length < 2) {
      setNutritionPref([...nutritionPref, value]);
    }
  };

  // Smooth progress for generate button — faster, more continuous
  const genProgress = useSmoothProgress({ isLoading: generating, mode: 'smart' });

  const doGenerate = async (extraProteinIngredients = [], generationMode = "WITHOUT_EXTRAS", excludeAllergensList = [], forcePromptOverride = null) => {
    // Self-contained single-flight: ensure the guard is held while doGenerate runs.
    // If entered through a modal-resume path (MacroNegotiationModal, EnhanceRecipeModal,
    // ExpiredIngredientModal, AllergenWarningModal, IngredientConstraintWarning, etc.)
    // the outer guard was already released. tryAcquire returns true here and finally
    // releases it. If called from handleGenerate / onRetryGeneration which already
    // hold the lock, tryAcquire returns false (no-op) and finally still releases.
    generateGuard.tryAcquire();
    // Track start time — if we're resuming after a modal pause, keep the existing start ref
    if (!generationStartRef.current) {
      generationStartRef.current = Date.now();
      nutritionBoostShownRef.current = false;
      allergenModalShownRef.current = false;
      enhanceModalShownRef.current = false;
      macroNegotiationShownRef.current = false;
    }
    // Set all state in one synchronous batch so React renders the overlay in a single pass
    setGenerating(true);
    setGeneratedRecipe(null);
    setGenerationError(null);
    // NOTE: generationRetryRef is NOT reset here — it's managed by the catch/retry logic
    // Yield one frame to let the overlay mount & paint before starting heavy async work
    await new Promise(r => requestAnimationFrame(r));
    try {

    // CONSTRAINT SOLVER: PRE-GENERATION
    const macroGoalsFromPrompt = parseMacroGoals(optionalPrompt.trim()) || {};
    const { parsedIntent, activeTargets, constraintFrame } = preGenerate({
      promptText: optionalPrompt.trim(), servings,
      selectedPantryItems: pantryItems.filter(p => selectedIngredients.has(p.id)),
      extraMacroGoals: macroGoalsFromPrompt,
    });
    const selected = pantryItems.filter(p => selectedIngredients.has(p.id));
    const promptText = (forcePromptOverride ?? optionalPrompt).trim();
    const hasExtras = extraProteinIngredients.length > 0 || generationMode === "AI_CHOSEN_EXTRAS";
    const effectiveAllowMissing = promptText.length > 0 || hasExtras ? true : allowMissing;

     // ── PARSE RICH USER REQUEST (taste, texture, cooking style, etc.) ──
     const { parseDietaryConstraints } = await import('../components/generate/RichUserRequestParser');
     const richPreferences = promptText ? parseRichUserRequest(promptText) : null;
     const preferenceInstructions = richPreferences ? preferencesToPromptInstructions(richPreferences) : "";
     // ── PARSE STRUCTURED GOALS (budget, include/exclude, semantic intent) ──
     const goalInstructions = goalsToPromptInstructions(macroGoalsFromPrompt);
     const enrichedPrompt = [promptText, preferenceInstructions, goalInstructions].filter(Boolean).join(" ");

     // Parse macro goals from prompt
     const macroGoals = parseMacroGoals(promptText);

    // ── Parse ALL request goals (not just macros) ──
    const requestGoals = parseRequestGoals(promptText);
    if (macroGoals?.protein) requestGoals.protein = macroGoals.protein;
    if (macroGoals?.calories) requestGoals.calories = macroGoals.calories;
    if (macroGoals?.carbs) requestGoals.carbs = macroGoals.carbs;
    if (macroGoals?.fat) requestGoals.fat = macroGoals.fat;
    const adaptationConfig = buildAdaptationConfig(
      requestGoals,
      extraProteinIngredients,
      generationMode
    );

    // Resolve extras based on generation mode
    const resolvedExtras = extraProteinIngredients;
    const isAiAutoMode = generationMode === "AI_CHOSEN_EXTRAS";

    // Build strict quantity map for AI enforcement
    // The map contains strict amounts that the AI must respect
    const strictQuantityMap = buildStrictQuantityMap(ingredientUsageMap, selectedIngredients, selected);
    console.log('[Generate] Strict quantity map built:', strictQuantityMap);

    // Merge: explicit parseMacroGoals() numbers + intent targets from TaskIntentClassifier
    // This is where qualitative intents ("high protein", "low carb") get numeric values injected
    const mergedMacroGoals = {
      ...(macroGoals || {}),
      ...(activeTargets?.protein && !(macroGoals||{}).protein ? { protein: activeTargets.protein } : {}),
      ...(activeTargets?.calories && !(macroGoals||{}).calories ? { calories: activeTargets.calories } : {}),
      ...(activeTargets?.carbs && !(macroGoals||{}).carbs ? { carbs: activeTargets.carbs } : {}),
      ...(activeTargets?.fat && !(macroGoals||{}).fat ? { fat: activeTargets.fat } : {}),
    };
    // If user said "per serving", convert to total for the optimizer (which works in totals)
    if (mergedMacroGoals.calories && mergedMacroGoals.calories_per_serving) {
      mergedMacroGoals.calories = mergedMacroGoals.calories * servings;
      console.log(`[Generate] Calorie target is per-serving → scaled to total: ${mergedMacroGoals.calories} for ${servings} servings`);
    }
    // Nutrition targets require allow_missing=true so AI can freely source proteins
    const hasNutritionTarget = !!(mergedMacroGoals.protein || mergedMacroGoals.calories);
    const finalAllowMissing = effectiveAllowMissing || hasNutritionTarget;

    // CREDIT-FIRST: generateRecipe now atomically consumes credit before LLM call.
    // client_request_id is sourced from the single-flight guard so:
    //  • Spam-tap during a single attempt → all rejected synchronously (guard.tryAcquire returns false).
    //  • Internal retries (e.g. fidelity re-run) → reuse the same id, backend dedups.
    //  • Only a brand-new user-initiated attempt rotates the id.
    const clientRequestId = generateGuard.getOrCreateRequestId();
    let result = await generateRecipe(user || {}, selected, {
      meal_type: mealType,
      cuisine,
      max_cook_time: maxCookTime,
      servings,
      difficulty,
      nutrition_preference: nutritionPref.length > 0 ? nutritionPref.join(", ") : "balanced",
      allow_missing: finalAllowMissing,
      optional_prompt: enrichedPrompt || null,
      macro_goals: mergedMacroGoals,
      extra_protein_ingredients: resolvedExtras,
      ai_auto_protein: isAiAutoMode,
      strict_quantities_map: strictQuantityMap,
      _display_language: resolvedLang || 'en',
    }, constraintFrame, { clientRequestId });

    // Extract credit metadata returned by backend (attached to recipe object)
    const backendEventId = result._eventId || null;
    const backendQuota = result._quota || null;
    // AUTHORITATIVE: backend is the single source of truth. Never mutate.
    // Backend's quotaAfter is computed POST-spend atomically, so it is always correct.
    if (backendQuota) setQuota(backendQuota);
    // Clean internal metadata before recipe processing
    delete result._eventId; delete result._generationId; delete result._quota; delete result._creditSource; delete result._idempotentHit;

    // Validate recipe against strict ingredient rules
    // Include approved extra protein ingredients so validator doesn't strip them
    const userIngredientNames = [
     ...selected.map(p => p.name),
     ...resolvedExtras,
    ];
    const validation = validateGeneratedRecipe(result, userIngredientNames, effectiveAllowMissing);

    if (!validation.valid) {
      console.warn('[Recipe Validation] Issues found:', validation.issues);
      Object.assign(result, validation.fixed);
    }

    // ── CANONICAL INGREDIENT ENFORCEMENT ──────────────────────────────────
    // Decompose composite/processed ingredient names (e.g. "Chickpea Patty")
    // into real canonical components BEFORE other validators strip them.
    {
      const canonicalResult = enforceCanonicalIngredients(result);
      if (canonicalResult.decomposed.length > 0) {
        console.log('[CanonicalEnforcer] Decomposed composites:', canonicalResult.decomposed);
      }
      result = canonicalResult.recipe;
    }
    // ── END CANONICAL ENFORCEMENT ──────────────────────────────────────────

    // ── AUTHORITATIVE INGREDIENT ENFORCEMENT ───────────────────────────────
    // Strip ANY ingredient not explicitly authorized by the user.
    // This is the single definitive filter replacing multiple partial checks.
    const ingredientValidation = validateGeneratedIngredients(
      result,
      selected,
      resolvedExtras,
      effectiveAllowMissing
    );
    if (!ingredientValidation.valid) {
      console.warn('[IngredientValidator] Stripped unauthorized ingredients:', ingredientValidation.violations.map(v => v.ingredient));
    }
    result = ingredientValidation.cleaned_recipe;
    // ── END INGREDIENT ENFORCEMENT ─────────────────────────────────────────

    // ── POST-PROCESS: AI Recipe Intelligence Layer + MARK ENHANCEMENT INGREDIENTS ──
    // Validates quantities, checks taste balance, marks AI-added and enhancement-selected ingredients, tracks variation
    const userSelectedNames = selected.map(p => p.name);
    const enhancedSelectedNames = [...userSelectedNames, ...resolvedExtras]; // Mark both pantry + selected enhancement extras
    result = AIRecipeIntelligenceLayer.postProcessRecipe(result, enhancedSelectedNames);

    // Mark enhancement-selected ingredients with a flag for UI visibility
    if (resolvedExtras.length > 0) {
      for (const group of (result.ingredients || [])) {
        for (const item of (group.items || [])) {
          if (resolvedExtras.some(extra => item.name.toLowerCase().includes(extra.toLowerCase()))) {
            item._enhanced_selection = true; // Mark for UI differentiation
          }
        }
      }
    }

    // ── CHEF REALISM ENGINE: detect dish type + rebalance portions ───────────
    const detectedDishType = detectDishType(selected, promptText, mealType);
    const proteinTargetForRealism = macroGoals?.protein
      ? (typeof macroGoals.protein === 'object' ? macroGoals.protein.min : macroGoals.protein)
      : null;
    result = rebalanceIngredients(result, detectedDishType, proteinTargetForRealism);
    const realismValidation = validateRealism(result, detectedDishType, proteinTargetForRealism);
    if (realismValidation.issues.length > 0) {
      console.warn('[ChefRealism] Validation issues:', realismValidation.issues);
    }
    if (realismValidation.warnings.length > 0) {
      console.info('[ChefRealism] Warnings:', realismValidation.warnings);
    }
    // ── END CHEF REALISM ───────────────────────────────────────────────────

    // ── MACRO OPTIMIZER: adjust ingredient amounts to hit numeric targets ───
    // Pass merged goals (including per-serving → total calorie scaling done above)
    const macroTargets = buildMacroTargets(mergedMacroGoals, nutritionPref);
    if (macroTargets) {
      const optimResult = optimizeRecipe(result, macroTargets, detectedDishType);
      result = optimResult.recipe;
      if (optimResult.report.length > 0) {
        console.log('[MacroOptimizer] Adjustments:', optimResult.report);
      }
      // FINAL AGGRESSIVE CALORIE CAP ENFORCEMENT — guarantees per-serving compliance
      if (macroTargets.calorie_max) {
        enforceCalorieCap(result, macroTargets.calorie_max);
      }
    }
    // ── END MACRO OPTIMIZER ────────────────────────────────────────────────

    // ── PANTRY CLAMPING: Enforce user-selected usage caps (from ingredientUsageMap) ──
    // CRITICAL: Uses canonical_base_amount (source of truth) instead of legacy quantity/unit.
    // If user selected a usage % via the slider, that becomes the hard max — NOT the full pantry amount.
    const { lookupMacroDensity: _lookupDensity, parseAmountToGrams: _parseAmt } = await import('../components/generate/MacroOptimizerEngine');
    const { isLeanProteinSource: _isLean } = await import('../components/generate/ProteinConstraintSolver');
    const hasHardProteinTarget = !!(macroGoals?.protein);

    const selectedWithAmounts = pantryItems.filter(p => selectedIngredients.has(p.id));
    const pantryAmountMap = {}; // name (lowercase) → { maxGrams, display }
    for (const p of selectedWithAmounts) {
      // Use canonical_base_amount as authoritative source (always in g/ml/pieces)
      let maxG = null;
      const canonical = parseFloat(p.canonical_base_amount);
      const canonicalUnit = p.canonical_base_unit || p.unit || 'g';

      if (!isNaN(canonical) && canonical > 0) {
        // Canonical is already in base units (g for solids, ml for liquids, pieces for discrete)
        maxG = canonical;
      } else {
        // Fallback to legacy fields
        const qty = parseFloat(p.quantity);
        if (isNaN(qty) || qty <= 0) continue;
        if (p.unit === 'g') maxG = qty;
        else if (p.unit === 'kg') maxG = qty * 1000;
        else if (p.unit === 'ml') maxG = qty;
        else if (p.unit === 'L') maxG = qty * 1000;
        else if (p.unit === 'tbsp') maxG = qty * 15;
        else if (p.unit === 'tsp') maxG = qty * 5;
        else maxG = qty; // best effort
      }
      if (maxG === null || maxG <= 0) continue;

      // CRITICAL: If user selected a usage cap via the slider, use that instead of full pantry
      const usageEntry = ingredientUsageMap[p.id];
      if (usageEntry?.use_cap_amount != null && usageEntry.use_cap_amount > 0) {
        maxG = usageEntry.use_cap_amount; // This is in canonical base units
        console.log(`[Generate] Pantry cap for "${p.name}": user selected ${maxG}${canonicalUnit} (${usageEntry.use_percent}% of pantry)`);
      }

      pantryAmountMap[p.name.toLowerCase()] = { maxGrams: maxG, display: `${Math.round(maxG)}${canonicalUnit}`, name: p.name };
    }

    for (const group of (result.ingredients || [])) {
      for (const item of (group.items || [])) {
        if (!item?.name || !item?.amount || item.optional || item.missing) continue;
        const nameLower = item.name.toLowerCase();
        const pantryEntry = Object.entries(pantryAmountMap).find(([k]) =>
          nameLower.includes(k) || k.includes(nameLower)
        );
        if (!pantryEntry) continue;
        const [, { maxGrams, display }] = pantryEntry;

        // Parse recipe amount — handle both "300g" and "300 g" and plain numbers
        const amtStr = String(item.amount).trim();
        let recipeGrams = null;
        const gramsMatch = amtStr.match(/^([\d.]+)\s*g$/i);
        if (gramsMatch) {
          recipeGrams = parseFloat(gramsMatch[1]);
        } else if (/^\d+(\.\d+)?$/.test(amtStr) && (item.unit === 'g' || !item.unit)) {
          recipeGrams = parseFloat(amtStr);
        }

        if (recipeGrams !== null && recipeGrams > maxGrams) {
          // Skip clamping lean proteins when a hard protein target is in play
          if (hasHardProteinTarget) {
            const density = _lookupDensity(item.name);
            if (density && _isLean(item.name, density)) {
              console.log(`[Generate] Pantry clamp SKIPPED for lean protein "${item.name}": target-driven scaling (${recipeGrams}g > ${maxGrams}g pantry limit)`);
              continue;
            }
          }
          item.amount = `${Math.round(maxGrams)}g`;
          item.base_grams = maxGrams;
          console.warn(`[Generate] Clamped "${item.name}": AI said ${recipeGrams}g but user cap is ${display}`);
        }
      }
    }
    // ── FLOUR MINIMUM CLAMP: enforce 50g minimum for all flour/grain ingredients ──
    for (const group of (result.ingredients || [])) {
      for (const item of (group.items || [])) {
        clampFlourMinimum(item);
      }
    }
    // ── PROTEIN CONSTRAINT SOLVER ──────────────────────────────────────────────
    // Runs AFTER pantry clamping. Hard-enforces protein min/max by scaling/injecting
    // lean protein sources. This is the final authoritative guarantee.
    // Use mergedMacroGoals so intent-derived targets (e.g. "high protein") are also enforced.
    const _effectiveProteinGoal = mergedMacroGoals?.protein || macroGoals?.protein;
    if (_effectiveProteinGoal) {
      const isRange = typeof _effectiveProteinGoal === 'object';
      // For single-number targets, apply ±5% tolerance for tighter fulfillment
      const pMin = isRange ? _effectiveProteinGoal.min : Math.round(_effectiveProteinGoal * 0.95);
      const pMax = isRange ? _effectiveProteinGoal.max : Math.round(_effectiveProteinGoal * 1.10);
      // Always allow injection when a hard protein target is set — the pantry clamp
      // above already guards actual stock limits. Without this, the solver gives up
      // on achieving the target when allow_missing=false even though we can inject.
      const solverAllowMissing = true;
      const solverResult = solveProteinConstraint(result, pMin, pMax, detectedDishType, solverAllowMissing);
      result = solverResult.recipe;

      if (!solverResult.success && solverResult.failure) {
        // Soft-warn: still show the best result but log the failure
        console.warn('[ProteinConstraintSolver] Could not satisfy constraint:', solverResult.failure);
      }
    }
    // ── END PROTEIN CONSTRAINT SOLVER ─────────────────────────────────────────

    // ── CULINARY ROLE GUARD ────────────────────────────────────────────────────
    // Final enforcement: caps cheese/secondary-protein amounts that previous
    // engines may have inflated. PRIMARY_PROTEIN is never touched here.
    {
      const _pg = mergedMacroGoals?.protein || macroGoals?.protein;
      const pTarget = _pg ? (typeof _pg === 'object' ? _pg.min : _pg) : null;
      const { recipe: guardedRecipe } = enforceCulinaryRoles(result, detectedDishType, pTarget);
      result = guardedRecipe;
    }
    // ── END CULINARY ROLE GUARD ────────────────────────────────────────────────

    // ── STRICT QUANTITY ENFORCEMENT: Post-generation guarantee ──────────────
    result = enforceStrictQuantities(result, strictQuantityMap);
    // ────────────────────────────────────────────────────────────────────────

    // Normalize ingredients for deterministic nutrition calculation (no backend call)
    const normalizedIngredients = [];
    for (const group of (result.ingredients || [])) {
      for (const item of (group.items || [])) {
        if (item.name && !item.optional) {
          try {
            const normalized = normalizeIngredient(item);
            // Write base_grams BACK onto the item so NutritionPanel/NutritionEngine can use it
            item.base_grams = normalized.base_grams;
            normalizedIngredients.push({
              name: normalized.name,
              grams: normalized.base_grams,
              grams_confidence: normalized.grams_confidence,
            });
          } catch (normErr) {
            console.error(`[Generate] Normalization failed for "${item.name}": ${normErr.message}`);
          }
        }
      }
    }

    // ── DETERMINISTIC NUTRITION: ALWAYS recalculate from actual ingredients ──
    // This is the source of truth. AI-generated nutrition values are NEVER trusted
    // because the AI can fabricate macros (e.g. 19g protein from only vegetables).
    // The optimizer may have already computed values but we always override here
    // to ensure ingredients are the single source of truth.
    try {
      const { lookupMacroDensity: _lookupDensity } = await import('../components/generate/MacroOptimizerEngine');
      let totCal = 0, totProt = 0, totCarbs = 0, totFat = 0, totFiber = 0;
      let matchedCount = 0;
      for (const ni of normalizedIngredients) {
        if (!ni.grams || ni.grams <= 0) continue;
        const d = _lookupDensity(ni.name);
        if (!d) continue;
        matchedCount++;
        const scale = ni.grams / 100;
        totCal   += (d.calories || 0) * scale;
        totProt  += (d.protein  || 0) * scale;
        totCarbs += (d.carbs    || 0) * scale;
        totFat   += (d.fat      || 0) * scale;
        totFiber += (d.fiber    || 0) * scale;
      }
      const sv = result.servings || 1;
      // Only override if we matched at least 1 ingredient — prevents blanking valid values
      if (matchedCount > 0) {
        const total = { calories: Math.round(totCal), protein: Math.round(totProt), carbs: Math.round(totCarbs), fat: Math.round(totFat), fiber: Math.round(totFiber) };
        const perServing = { calories: Math.round(totCal/sv), protein: Math.round(totProt/sv), carbs: Math.round(totCarbs/sv), fat: Math.round(totFat/sv), fiber: Math.round(totFiber/sv) };
        result.nutrition_total_for_recipe = total;
        result.nutrition_per_serving = perServing;
        result.nutrition = perServing;
        console.log(`[Generate] Deterministic nutrition from ${matchedCount}/${normalizedIngredients.length} ingredients:`, perServing);
      } else {
        // Zero matches — keep whatever optimizer/AI set (better than nothing)
        console.warn('[Generate] No MACRO_DB matches for ingredients — keeping existing nutrition values');
      }
    } catch (e) {
      console.warn('[Generate] Deterministic nutrition failed:', e.message);
    }

    // ── RECIPE CONSISTENCY CHECK ──
    {
      const consistency = ensureRecipeConsistency(result);
      if (consistency.violations.length > 0) console.warn('[RecipeConsistency]', consistency.violations.map(v => `[${v.severity}] ${v.message}`));
      result = consistency.recipe;
    }

    // ── QUANTITY SANITY CAPS (pre-normalization) ──
    capUniversalSeasonings(result);

    // ── MANDATORY FINAL NORMALIZATION (single guaranteed entry point) ─────
    // Runs enforceFinalConstraints, validates, retries once if violations
    // remain, recomputes nutrition, re-prices, stamps _normalized_v marker.
    const _chickenBefore = _findChicken(result);
    const _normRes = runFinalNormalization(result, { userPrompt: promptText, macroGoals: mergedMacroGoals, reprice: true });
    _logChickenDiff('Pantry', _chickenBefore, _findChicken(result), result.servings || 1);
    if (!_normRes.ok) console.warn('[Generate:Pantry] Normalization violations after retry:', _normRes.violations.slice(0, 8));

    // IMAGE in parallel; INTEGRITY pass on already-priced result.
    const _imagePromise = generateRecipeImageSafe(buildRecipeImagePrompt(result, null, null, enrichedPrompt || promptText));
    let pricedResult = result;
    const { runFinalIntegrityPass: _fip } = await import('../components/generate/recipeFinalIntegrity');
    _fip(pricedResult);
    pricedResult.hero_image_url = await _imagePromise;
    if (!pricedResult.hero_image_url) {
      console.error('[Generate] Image generation failed — refunding.');
      await refundAndSync(backendEventId, 'image_generation_failed', setQuota);
      generationStartRef.current = null;
      generationRetryRef.current = 0;
      setGenerating(false);
      setGenerationError(t('generate.error_image_failed', 'The image service is temporarily unavailable. Please try again.'));
      return;
    }

    // ── PRICING FLOOR ENFORCEMENT: minimum $2.50/serving ──────────────────
    {
      const servings = pricedResult.servings || 1;
      const MIN_COST_PER_SERVING = 2.50;
      const cps = pricedResult.cost_per_serving ?? 0;
      if (cps > 0 && cps < MIN_COST_PER_SERVING) {
        const correctedTotal = MIN_COST_PER_SERVING * servings;
        console.warn(`[PricingFloor] Cost/serving $${cps.toFixed(2)} below $${MIN_COST_PER_SERVING} floor — corrected to $${correctedTotal.toFixed(2)} total`);
        pricedResult.total_cost = parseFloat(correctedTotal.toFixed(2));
        pricedResult.cost_per_serving = MIN_COST_PER_SERVING;
      }
    }

    // PROMPT FIDELITY: HARD requested-protein preservation.
    // SINGLE ATTEMPT per user click — no recursive setTimeout. If the LLM returns a
    // wrong-protein recipe, refund and fail cleanly. User can tap Retry manually;
    // on the retry, we feed a reinforced prompt (below) so the next attempt is stronger.
    // This guarantees: (1) no self-restart, (2) never surface a broken recipe, (3) no lost credit.
    { const fp = (forcePromptOverride ?? optionalPrompt).trim();
      const fidelity = validatePromptFidelity(pricedResult, fp, servings);
      pricedResult = fidelity.recipe;
      if (!fidelity.valid) {
        const missing = fidelity.issues.filter(i => i.severity === 'critical' && i.requested).map(i => i.requested);
        if (missing.length) {
          console.error('[Generate] Fidelity FAILED — refunding, showing error:', fidelity.issues);
          const firstRun = !forcePromptOverride && (generationRetryRef.current || 0) === 0;
          await refundAndSync(backendEventId, 'protein_mismatch', setQuota);
          generationStartRef.current = null;
          if (firstRun) {
            // Stash a reinforced prompt so the user's next Retry tap uses it automatically.
            const { buildProteinReinforcedPrompt } = await import('../components/generate/proteinReinforcementBuilder');
            generationRetryRef.current = 1;
            window.__reciply_reinforced_prompt = buildProteinReinforcedPrompt(optionalPrompt.trim(), missing);
          } else {
            generationRetryRef.current = 0;
            window.__reciply_reinforced_prompt = null;
          }
          setGenerating(false);
          setGenerationError(t('generate.error_protein_missing', 'Could not generate a {protein} recipe. Please try again.', { protein: missing.join(', ') }));
          return;
        }
      }
    }

    // ── CONSTRAINT SOLVER: POST-GENERATION VALIDATION ────────────────────────
    {
      const freshUser = user || authContextUser || null;
      const postResult = postGenerate({
        recipe: pricedResult,
        activeTargets,
        parsedIntent,
        userAllergens: Array.isArray(freshUser?.allergies) ? freshUser.allergies : [],
        excludeAllergensList,
      });
      // Apply pricing reconciliation from postGenerate
      pricedResult = postResult.reconciledRecipe;

      if (!postResult.valid && postResult.shouldRetry) {
        // NO automatic re-entry. Refund + fail clean. User taps Retry manually.
        console.warn('[Generate] Constraint retry suggested — refunding and surfacing error instead of self-restarting.');
        await refundAndSync(backendEventId, 'constraint_retry_requested', setQuota);
        generationStartRef.current = null;
        setGenerating(false);
        setGenerationError(t('generate.error_generation_failed', 'Recipe generation failed. Please try again.'));
        return;
      }

      if (!postResult.valid && !postResult.shouldRetry && postResult.fallback) {
        // All attempts exhausted — fallback card shown via useConstraintSolver state.
        // Refund because we're not surfacing a result.
        await refundAndSync(backendEventId, 'constraint_fallback', setQuota);
        generationStartRef.current = null;
        setGenerating(false);
        return;
      }
    }
    // ── END POST-GENERATION VALIDATION ───────────────────────────────────────

    // Credit was already consumed atomically inside generateRecipeWithQuota (CREDIT-FIRST architecture).
    // backendEventId was extracted earlier from the recipe metadata.
    const eventId = backendEventId;

    // ── HARD CONSTRAINT VALIDATION (AUTHORITATIVE) ──────────────────────────
    // This MUST pass before showing result, otherwise return conflict state
    let hardConstraintConfig = {};
    const _finalProtein = mergedMacroGoals?.protein || macroGoals?.protein;
    if (_finalProtein) {
      const isRange = typeof _finalProtein === 'object';
      hardConstraintConfig.protein_min = isRange ? _finalProtein.min : _finalProtein;
      hardConstraintConfig.protein_max = isRange ? _finalProtein.max : null;
    }
    const _finalCalories = mergedMacroGoals?.calories || macroGoals?.calories;
    if (_finalCalories) {
      hardConstraintConfig.calorie_max = _finalCalories;
    }
    // Budget from recipe
    if (pricedResult.total_cost !== undefined) {
      // Only enforce budget if it was explicitly requested
      // (implied by presence in constraints)
    }

    const constraintValidation = validateHardConstraints(pricedResult, hardConstraintConfig);
    if (!constraintValidation.valid && !nutritionBoostShownRef.current && !macroNegotiationShownRef.current) {
      console.error('[Generate] HARD CONSTRAINTS VIOLATED:', constraintValidation);
      nutritionBoostShownRef.current = true;
      macroNegotiationShownRef.current = true;
      setGenerating(false);
      setMacroNegotiation({
        goals: hardConstraintConfig,
        currentMax: constraintValidation.failed[0]?.actual || null,
        hardConstraintViolation: true,
        constraintValidationFailure: true,
        validationReport: constraintValidation,
        adjustmentSuggestions: constraintValidation.adjustmentSuggestions,
      });
      return;
    }

    // Constraints passed — log success
    if (constraintValidation.passed.length > 0) {
      console.log('[Generate] All hard constraints satisfied:', constraintValidation.passed);
    }

    const adaptValidation = validateAdaptationResult(pricedResult, adaptationConfig);
    if (!adaptValidation.valid) console.warn('[Generate] Adaptation soft-fail:', adaptValidation.failedConstraints);
    if (adaptValidation.warnings.length > 0) console.warn('[Generate] Adaptation warnings:', adaptValidation.warnings);

    setIsSaved(false); // reset saved state on new generation

    // ── VALIDATE RECIPE AGAINST HARD PROTEIN CONSTRAINT ──
    if (parsedProteinConstraint && parsedProteinConstraint.is_hard_constraint) {
      const constraintValidation = validateRecipeAgainstConstraint(
        pricedResult,
        parsedProteinConstraint,
        userBypassedConstraint
      );

      if (!constraintValidation.valid && !constraintValidation.bypassApplied && !nutritionBoostShownRef.current && !macroNegotiationShownRef.current) {
        logConstraintViolation(pricedResult, parsedProteinConstraint, constraintValidation);
        console.error(`[Generate] HARD CONSTRAINT VIOLATION: ${constraintValidation.reason}`);
        nutritionBoostShownRef.current = true;
        macroNegotiationShownRef.current = true;
        setGenerating(false);
        setMacroNegotiation({
          goals: parsedProteinConstraint,
          currentMax: constraintValidation.report?.recipe_protein_grams,
          hardConstraintViolation: true,
          constraintValidationFailure: true,
          validationReport: constraintValidation.report,
        });
        return;
      }

      // If bypass applied, log it
      if (constraintValidation.bypassApplied) {
        console.info(`[Generate] Constraint bypass applied - showing below-target recipe (${Math.round(constraintValidation.report?.recipe_protein_grams)}g vs ${parsedProteinConstraint.min_grams}g)`);
      }
    }

    // ── CHECK FOR AI-SUGGESTED INGREDIENTS ──
    // If user had a prompt and AI added "Suggested additions" group, show review modal
    if (optionalPrompt.trim() && pricedResult.ingredients) {
      const suggestionsGroup = pricedResult.ingredients.find(g => 
        g.group?.toLowerCase().includes('suggested')
      );
      if (suggestionsGroup?.items?.length > 0) {
        // Extract suggested items for review
        const suggestions = suggestionsGroup.items.map(item => ({
          name: item.name,
          amount: item.amount,
          reason: `Needed to fulfill: ${optionalPrompt}`
        }));
        setSuggestionsReview({
          prompt: optionalPrompt,
          suggestions
        });
        setPendingRecipeForSuggestions({
          ...pricedResult,
          _eventId: eventId,
          _suggestedGroupIdx: pricedResult.ingredients.indexOf(suggestionsGroup)
        });
        generationStartRef.current = null; // suggestions review is terminal, reset timer
        setGenerating(false);
        return;
      }
    }

    // ── POST-GEN ALLERGEN CHECK (single source of truth, fires exactly once per generation) ──
    // Skip allergen check entirely if user already chose to regenerate without these allergens
    const allIngredientItems = (pricedResult.ingredients || []).flatMap(g => g.items || []);
    if (allIngredientItems.length > 0 && excludeAllergensList.length === 0) {
      // Use AuthContext user — always fresh, no independent fetch needed
      const freshUserForAllergen = user || authContextUser || null;
      const userAllergens = Array.isArray(freshUserForAllergen?.allergies) ? freshUserForAllergen.allergies : [];
      if (userAllergens.length > 0) {
        // Exact word-boundary allergen matching — prevents false positives like "soy sauce" → eggs
        const ALLERGEN_KEYWORDS_POSTGEN = {
          gluten:    ['flour', 'bread', 'pasta', 'wheat', 'noodle', 'spaghetti', 'penne', 'tortilla', 'ramen', 'barley', 'oats', 'breadcrumb', 'couscous'],
          dairy:     ['milk', 'cheese', 'butter', 'cream', 'yogurt', 'mozzarella', 'parmesan', 'cheddar', 'feta', 'ricotta', 'ghee', 'whey'],
          eggs:      ['egg', 'eggs', 'egg white', 'egg yolk', 'mayonnaise'],
          nuts:      ['walnut', 'almond', 'cashew', 'pecan', 'pistachio', 'hazelnut', 'macadamia', 'pine nut'],
          peanuts:   ['peanut', 'peanut butter', 'groundnut'],
          soy:       ['tofu', 'tempeh', 'edamame', 'miso', 'soy sauce', 'tamari', 'soybean', 'soy milk'],
          shellfish: ['shrimp', 'prawn', 'crab', 'lobster', 'scallop', 'mussel', 'clam', 'oyster', 'squid'],
          fish:      ['salmon', 'tuna', 'cod', 'tilapia', 'halibut', 'anchovy', 'sardine', 'mackerel', 'trout', 'bass', 'snapper'],
          sesame:    ['sesame', 'tahini', 'sesame oil', 'sesame seed'],
        };
        // Word-boundary match to prevent substring false positives
        const matchesAllergenKeyword = (ingredientName, keyword) => {
          if (keyword.includes(' ')) return ingredientName.includes(keyword);
          return new RegExp(`(^|[^a-z])${keyword}([^a-z]|$)`).test(ingredientName);
        };
        let matchedAllergens = [];
        // Check declared recipe allergens first (exact set membership only)
        if (pricedResult.allergens?.length > 0) {
          const recipeAllergenSet = new Set(pricedResult.allergens.map(a => a.toLowerCase()));
          matchedAllergens = userAllergens.filter(a => recipeAllergenSet.has(a.toLowerCase()));
        }
        // Also scan ingredient names against keywords using word-boundary matching
        if (matchedAllergens.length === 0) {
          const allIngredientNames = allIngredientItems.map(i => (i.name || '').toLowerCase());
          matchedAllergens = userAllergens.filter(allergen => {
            const keywords = ALLERGEN_KEYWORDS_POSTGEN[allergen.toLowerCase()] || [allergen.toLowerCase()];
            return allIngredientNames.some(n => keywords.some(k => matchesAllergenKeyword(n, k)));
          });
        }
        // Only show modal if we found real matches and haven't shown it yet this generation
        if (matchedAllergens.length > 0 && !allergenModalShownRef.current) {
          allergenModalShownRef.current = true;
          generationStartRef.current = null;
          setGenerating(false);
          setAllergenWarning({ allergens: matchedAllergens, pendingRecipe: { ...pricedResult, _eventId: eventId } });
          return;
        }
      }
    }

    // ── CLIENT-SIDE TIME NORMALIZATION (defense-in-depth) ──────────────────
    // Backend also normalizes, but this catches any edge case with cached data
    const _normTime = (v) => {
      if (v == null) return 0;
      const n = typeof v === 'string' ? parseFloat(v) : v;
      if (isNaN(n) || n < 0) return 0;
      if (n > 0 && n <= 12 && !Number.isInteger(n)) return Math.round(n * 60);
      return Math.round(n);
    };
    pricedResult.cook_time = _normTime(pricedResult.cook_time);
    pricedResult.prep_time = _normTime(pricedResult.prep_time);

    // ── STORE DIETARY CONSTRAINTS ON RECIPE (for switch filtering + image) ──
    const _dietaryResult = parseDietaryConstraints(promptText);
    if (_dietaryResult.constraints.length > 0) {
