      cost_per_serving: generatedRecipe.cost_per_serving ?? null,
      has_unknown_pricing: generatedRecipe.has_unknown_pricing ?? false,
    };
    const saved = await base44.entities.Recipe.create(recipeData);
    if (!saved?.id) {
      console.error('[Generate] handleSave: Recipe.create returned no ID');
      setSaving(false);
      return;
    }
    if (_eventId) {
      base44.functions.invoke('markGenerationSavedAdvanced', {
        event_id: _eventId,
        saved_recipe_id: saved.id,
        recipe_image_url: generatedRecipe.hero_image_url || null,
      }).catch(() => {});
    }
    // ATOMIC: Update any ShoppingList items that reference the temp __gen ID to the canonical saved Recipe ID
    try {
      const tempGenId = `__gen_${_eventId || 'temp'}`;
      const groceryItems = await base44.entities.ShoppingList.filter({ owner_id: user?.id, recipe_id: tempGenId }).catch(() => []);
      if (groceryItems.length > 0) {
        await Promise.all(groceryItems.map(item =>
          base44.entities.ShoppingList.update(item.id, { recipe_id: saved.id, recipe_title: saved.title || recipeData.title })
        ));
        console.log(`[Generate] Atomically updated ${groceryItems.length} grocery items from ${tempGenId} to ${saved.id}`);
      }
    } catch (groceryErr) {
      console.warn('[Generate] Grocery ID update failed (non-blocking):', groceryErr.message);
    }
    // NOTE: Recipe save does NOT advance streak — only meal logging does.
    // Generate deterministic Hebrew translations for the saved recipe (ZERO CREDITS)
    base44.functions.invoke('generateHebrewContentForRecipe', {
      recipe_id: saved.id,
      recipe_data: recipeData,
    }).catch(() => {}); // non-blocking fire-and-forget
    const savedRecipeWithId = { ...recipeData, id: saved.id };
    trackEvent('save_recipe', { recipe_id: saved.id, recipe_title: saved.title }, 'Generate');

    // STEP 1: Optimistically inject the new recipe into BOTH Profile and Home caches immediately
    // so both pages show it without waiting for a refetch
    const insertIntoCache = (queryKey) => {
      queryClient.setQueryData(queryKey, (old) => {
        if (!old) return [savedRecipeWithId];
        // Avoid duplicates — prepend only if not already in cache
        const exists = old.some(r => r.id === saved.id);
        return exists ? old : [savedRecipeWithId, ...old];
      });
    };
    insertIntoCache(["generated-recipes", user?.id]); // Both Profile + Home use this same key

    // STEP 2: Refetch immediately so both Profile + Home have fresh server data
    queryClient.refetchQueries({ queryKey: ["generated-recipes"], exact: false });

    setSaving(false);
    setIsSaved(true);
    setSavedRecipeForEat(savedRecipeWithId);
  };

  // Log Meal — opens meal logging without requiring save first
  const handleLogMealRequest = () => {
    // ALWAYS use the latest generatedRecipe for nutrition — it's the authoritative source
    // after ingredient switches. savedRecipeForEat may have stale nutrition from before switches.
    const { _eventId, ...recipeWithoutMeta } = generatedRecipe || {};
    const recipeForLog = {
      ...(savedRecipeForEat || {}),                // preserve id from save if available
      ...recipeWithoutMeta,                         // override with LATEST nutrition + ingredients
      id: savedRecipeForEat?.id || recipeWithoutMeta.id || null,
      _eventId: _eventId || savedRecipeForEat?._eventId,
    };
    setSavedRecipeForEat(recipeForLog);
    setShowMealLog(true);
  };

  const handleMealLogConfirm = async (loggingData) => {
    if (!savedRecipeForEat) return;
    setShowMealLog(false);
    setProcessingMealLog(true);

    // If recipe has an event ID and hasn't been saved yet, use logMealFromGenerated
    const eventId = savedRecipeForEat._eventId || generatedRecipe?._eventId;
    const isUnsavedGenerated = eventId && !isSaved;

    if (isUnsavedGenerated) {
      await logGeneratedMeal({
        eventId,
        loggingData,
        savedRecipeForEat,
        queryClient,
        user,
        setPendingStreakCelebration,
        setIsMealLogged,
        setCelebrationData,
        setShowMealCelebration,
        setProcessingMealLog,
      });
      return;
    }

    const mealLogData = {
      recipe_id: savedRecipeForEat.id || "",
      recipe_title: savedRecipeForEat.title,
      recipe_image: savedRecipeForEat.hero_image_url,
      recipe_servings: savedRecipeForEat.servings || 1,
      servings_eaten: loggingData.servings_eaten,
      eaten_at: new Date().toISOString(),
      nutrition_snapshot_per_serving: loggingData.nutrition_snapshot_per_serving || {},
      nutrition_snapshot_logged_total: loggingData.nutrition_snapshot_logged_total || {},
      calories_snapshot: loggingData.nutrition_snapshot_per_serving?.calories || 0,
      protein_snapshot: loggingData.nutrition_snapshot_per_serving?.protein || 0,
      carbs_snapshot: loggingData.nutrition_snapshot_per_serving?.carbs || 0,
      fat_snapshot: loggingData.nutrition_snapshot_per_serving?.fat || 0,
    };

    const deductions = Object.values(ingredientUsageMap).map(u => ({
      pantry_item_id: u.ingredient_id,
      ingredient_name: u.pantry_item?.name || u.ingredient_id,
      deduct_amount: u.use_cap_amount
        ? Math.round(u.use_cap_amount * (loggingData.servings_eaten / (savedRecipeForEat.servings || 1)) * 100) / 100
        : 0,
    })).filter(d => d.deduct_amount > 0);

    // Run simulation only if there are deductions
    let simResult = null;
    if (deductions.length > 0) {
      try {
        const simRes = await base44.functions.invoke('simulatePantryDeduction', {
          ingredient_deductions: deductions,
          recipe_servings: savedRecipeForEat.servings || 1,
          servings_eaten: loggingData.servings_eaten,
        });
        simResult = simRes.data;
      } catch (simErr) {
        console.warn('[Generate] simulation failed, proceeding without check:', simErr.message);
      }
    }

    if (simResult?.has_problems && simResult.problematic?.length > 0) {
      setPendingGenerateLogData({ mealLogData, deductions, loggingData });
      setInsufficientItems(simResult.problematic);
      setShowInsufficientModal(true);
      return;
    }

    await executeGenerateLog(mealLogData, deductions, []);
  };



  const executeGenerateLog = async (mealLogData, deductions, skipIds) => {
    await logSavedRecipeMeal({
      mealLogData,
      deductions,
      skipIds,
      queryClient,
      user,
      setPendingStreakCelebration,
      setIsMealLogged,
      setShowInsufficientModal,
      setShowEatConfirm,
      setCelebrationData,
      setShowMealCelebration,
      setProcessingMealLog,
    });
  };

  const handleGenerateInsufficientContinue = async (skippedIds) => { if (!pendingGenerateLogData) return; const { mealLogData, deductions } = pendingGenerateLogData; setPendingGenerateLogData(null); await executeGenerateLog(mealLogData, deductions, skippedIds); };
  const handleGenerateInsufficientEdit = (pantryItemId) => { window.location.href = createPageUrl("Pantry") + `?editItemId=${pantryItemId}&return_to=${encodeURIComponent(window.location.href)}`; };

  return (
    <div className={generatedRecipe ? "pb-0 min-h-screen" : "pb-4 min-h-screen"} style={{
      background: generatedRecipe ? "#f8fafc" : "linear-gradient(135deg, #f8fafc 0%, #f1f5f9 25%, #e2e8f0 50%, #f1f5f9 75%, #f8fafc 100%)",
      backgroundSize: generatedRecipe ? undefined : "400% 400%",
      animation: generatedRecipe ? undefined : "gradientShift 15s ease infinite"
    }}>
      <GeneratePageStyles />

      {/* Hide bottom nav via centralized manager while any overlay is active */}
      <BottomNavOverlayLock active={hasActiveOverlay} />
      {/* HARD CSS override: guarantee nav is hidden during generation + recipe view.
          The ref-counted lock system can be cleared by Layout's route-change cleanup
          when TabContainer switches tabs, so this inline <style> is the bulletproof fallback. */}
      {(generating || generatedRecipe) && (
        <style>{`[data-bottom-nav] { display: none !important; visibility: hidden !important; pointer-events: none !important; opacity: 0 !important; }`}</style>
      )}



      {/* Cooldown Tracker Popup */}
      <CooldownTrackerPopup
        isOpen={showCooldownPopup}
        onClose={() => setShowCooldownPopup(false)}
        onGenerateNow={() => { setShowCooldownPopup(false); handleGenerate(); }}
        initialSeconds={cooldownSeconds}
        onQuotaRefresh={fetchQuota}
      />

      <GeneratePageModals
        showSaveConfirm={showSaveConfirm} setShowSaveConfirm={setShowSaveConfirm} handleSave={handleSave}
        expiredModalItems={expiredModalItems} setExpiredModalItems={setExpiredModalItems} doGenerate={doGenerate}
        macroNegotiation={macroNegotiation} setMacroNegotiation={setMacroNegotiation} mealType={mealType} cuisine={cuisine}
        setUserBypassedConstraint={setUserBypassedConstraint}
        enhanceRecipe={enhanceRecipe} setEnhanceRecipe={setEnhanceRecipe}
        generatedRecipe={generatedRecipe} setGeneratedRecipe={setGeneratedRecipe} setPendingRecipeForSuggestions={setPendingRecipeForSuggestions}
        constraintWarning={constraintWarning} setConstraintWarning={setConstraintWarning} setEnhancementCheckPending={setEnhancementCheckPending}
        showEatConfirm={showEatConfirm} setShowEatConfirm={setShowEatConfirm} savedRecipeForEat={savedRecipeForEat} setShowMealLog={setShowMealLog}
        showMealLog={showMealLog} handleMealLogConfirm={handleMealLogConfirm}
        showInsufficientModal={showInsufficientModal} setShowInsufficientModal={setShowInsufficientModal} insufficientItems={insufficientItems}
        handleGenerateInsufficientContinue={handleGenerateInsufficientContinue} handleGenerateInsufficientEdit={handleGenerateInsufficientEdit}
        setPendingGenerateLogData={setPendingGenerateLogData}
        suggestionsReview={suggestionsReview} setSuggestionsReview={setSuggestionsReview}
        handleSuggestionsAccept={handleSuggestionsAccept} handleSuggestionsReject={handleSuggestionsReject}
        allergenWarning={allergenWarning} setAllergenWarning={setAllergenWarning} allergenModalShownRef={allergenModalShownRef}
        generating={generating} generationStartRef={generationStartRef}
        generationError={generationError}
        onRetryGeneration={() => {
          // Single-flight: ignore the tap if a request is already in-flight.
          if (generateGuard.isInFlight()) return;
          setGenerationError(null);
          generationStartRef.current = null;
          // RETRY POLICY:
          //  • Reinforced retry (post-fidelity-failure fix-up): KEEP the request id.
          //    Backend's idempotency cache will return the cached failed event;
          //    no second credit is consumed. Frontend re-runs validators / prompt.
          //  • Plain retry: ROTATE the request id so the user explicitly opts into
          //    a fresh paid attempt.
          const reinforced = typeof window !== 'undefined' ? window.__reciply_reinforced_prompt : null;
          if (!reinforced) generateGuard.rotateRequestId();
          if (genMode === 'freestyle') {
            const usePrompt = reinforced || optionalPrompt.trim();
            window.__reciply_reinforced_prompt = null;
            // handleFreestyleGenerate acquires the guard itself.
            handleFreestyleGenerate({ prompt: usePrompt, servings, freeMode });
          } else {
            // doGenerate is normally entered through handleGenerate (which holds the
            // guard). Here we acquire directly; doGenerate's finally releases it.
            if (!generateGuard.tryAcquire()) return;
            if (reinforced) {
              window.__reciply_reinforced_prompt = null;
              doGenerate([], 'WITHOUT_EXTRAS', [], reinforced);
            } else {
              doGenerate();
            }
          }
        }}
        onDismissGenerationError={() => {
          setGenerationError(null);
          window.__reciply_reinforced_prompt = null;
          generationRetryRef.current = 0;
          autoRetryUsedRef.current = false;
          consecutiveFailureRef.current = 0;
          setShowFallbackCta(false);
          // Dismissing an error = abandon this attempt. Rotate the id so the
          // next Generate tap starts a brand-new backend request.
          generateGuard.rotateRequestId();
        }}
        // FALLBACK CTA — surfaces only after >=2 consecutive failures.
        // Resets advanced filters to safe defaults and triggers a fresh attempt.
        onGenerationFallback={showFallbackCta ? () => {
          // Reset advanced/strict inputs that commonly cause failures.
          setOptionalPrompt("");
          setOptionalPromptError("");
          setNutritionPref([]);
          setIngredientUsageMap({});
          setMaxCookTime(45);
          setServings(2);
          setDifficulty("easy");
          setAllowMissing(true);
          // Reset failure tracking + start a brand-new attempt with a fresh requestId.
          setGenerationError(null);
          setShowFallbackCta(false);
          consecutiveFailureRef.current = 0;
          autoRetryUsedRef.current = false;
          generationRetryRef.current = 0;
          window.__reciply_reinforced_prompt = null;
          generateGuard.rotateRequestId();
          // Defer one tick so state settles before doGenerate reads it.
          Promise.resolve().then(() => {
            if (!generateGuard.tryAcquire()) return;
            if (genMode === 'freestyle') {
              handleFreestyleGenerate({ prompt: '', servings: 2, freeMode: true });
            } else {
              doGenerate([], 'WITHOUT_EXTRAS');
            }
          });
        } : null}
        generationFallbackLabel={t('generate.fallback_simpler', 'Try a simpler recipe')}
      />

      {/* Premium Header Section — always renders immediately, never blank.
          Reserve space with min-height to prevent layout shift while quota loads. */}
      <GeneratePageHeader
        t={t}
        quota={quota}
        quotaLoading={quotaLoading}
        isPro={isPro}
        fetchQuota={fetchQuota}
        onUseBanked={handleUseBankedCredit}
      />

      {/* Free Limit Modal — shows banked credit option if available */}
      <FreeLimitModal
        isOpen={showFreeLimitModal}
        quota={quota}
        t={t}
        resolvedLang={resolvedLang}
        onClose={() => setShowFreeLimitModal(false)}
        onUseBanked={handleUseBankedCredit}
      />

      {/* Leave Guard Modal */}
      <LeaveGuardModal
        isOpen={showLeaveGuard}
        t={t}
        onStay={() => { setShowLeaveGuard(false); setPendingLeaveAction(null); }}
        onLeave={() => {
          setShowLeaveGuard(false);
          if (pendingLeaveAction) pendingLeaveAction();
          setPendingLeaveAction(null);
        }}
      />

      {/* Constraint Fallback Card */}
      {constraintFallback && !generatedRecipe && !generating && (
        <ConstraintFallbackCard
          fallback={constraintFallback}
          onReset={() => { resetConstraints(); setOptionalPrompt(""); }}
        />
      )}

      {generatedRecipe ? (
         /* RESULT */
         <GeneratedRecipeView
           generatedRecipe={generatedRecipe}
           displayServings={displayServings}
           setDisplayServings={setDisplayServings}
           removeIngredient={removeIngredient}
           setRemoveIngredient={setRemoveIngredient}
           setGeneratedRecipe={setGeneratedRecipe}
           pantryItems={pantryItems}
           user={user}
           saving={saving}
           isSaved={isSaved}
           isLoggingMeal={showMealLog}
           onSaveRequest={async () => {
             if (saving) return;
             if (!isSaved) {
               setShowSaveConfirm(true);
             } else if (savedRecipeForEat?.id) {
               setSaving(true);
               try {
                 await base44.entities.Recipe.update(savedRecipeForEat.id, { is_saved: false });
                 setIsSaved(false);
                 queryClient.invalidateQueries({ queryKey: ["generated-recipes"] });
               } catch (e) { console.error('[Generate] Unsave failed', e.message); }
               finally { setSaving(false); }
             }
           }}
           onLogMeal={handleLogMealRequest}
           quota={quota}
           onFreeLimitReached={() => {
             fetchQuota().then(() => setShowFreeLimitModal(true));
           }}
           onLeaveAttempt={(action) => {
             if (isSaved || isMealLogged) { action(); return; }
             setPendingLeaveAction(() => action);
             setShowLeaveGuard(true);
           }}
         />
       ) : null}

       {/* FORM — Always visible while generating (don't hide during generation) */}
       {!generatedRecipe && (
         <div className="mt-2 space-y-0">
          <div className="px-4 mt-1"><CinematicModeSwitcher mode={genMode} onChange={setGenMode} /></div>
          {genMode === "freestyle" && <FreestyleMode user={user} freeMode={freeMode} onFreeModeChange={setFreeMode} generating={generating} disabled={generating} onGenerate={handleFreestyleGenerate} difficulty={difficulty} onDifficultyChange={setDifficulty} />}
          {genMode === "pantry" && (
           <PantryModeForm
             pantryItems={pantryItems}
             selectedIngredients={selectedIngredients}
             toggleIngredient={toggleIngredient}
             setShowIngredientSelector={setShowIngredientSelector}
             difficulty={difficulty}
             setDifficulty={setDifficulty}
             mealType={mealType}
             setMealType={setMealType}
             cuisine={cuisine}
             setCuisine={setCuisine}
             maxCookTime={maxCookTime}
             setMaxCookTime={setMaxCookTime}
             setShowTimePicker={setShowTimePicker}
             servings={servings}
             setServings={setServings}
             lastPickedServing={lastPickedServing}
             setLastPickedServing={setLastPickedServing}
             nutritionPref={nutritionPref}
             toggleNutrition={toggleNutrition}
             lastPickedNutrition={lastPickedNutrition}
             setLastPickedNutrition={setLastPickedNutrition}
             allowMissing={allowMissing}
             setAllowMissing={setAllowMissing}
             allowMissingSweeping={allowMissingSweeping}
             setAllowMissingSweeping={setAllowMissingSweeping}
             optionalPrompt={optionalPrompt}
             setOptionalPrompt={setOptionalPrompt}
             optionalPromptError={optionalPromptError}
             setOptionalPromptError={setOptionalPromptError}
             generating={generating}
             handleGenerate={handleGenerate}
             genProgress={genProgress}
             quotaDisabled={!quotaLoading && !entLoading && !isPro && quota && !quota.is_premium && !quota.owner_override && ((quota.remaining ?? 0) <= 0) && !generating}
           />
          )}
        </div>
      )}
      {/* Ingredient Selector Modal */}
      <IngredientSelector
        isOpen={showIngredientSelector}
        onClose={() => setShowIngredientSelector(false)}
        pantryItems={pantryItems}
        selectedIds={selectedIngredients}
        onSelect={toggleIngredient}
        usageMap={ingredientUsageMap}
        onUsageConfirm={(usageData) => {
          setIngredientUsageMap(prev => ({ ...prev, [usageData.ingredient_id]: usageData }));
        }}
      />

      {/* Custom Time Picker */}
      <CustomTimePicker
        isOpen={showTimePicker}
        onClose={() => setShowTimePicker(false)}
        onSelect={(minutes) => setMaxCookTime(minutes)}
        maxMinutes={250}
      />

      {/* Processing meal log overlay — blocks ALL interaction until celebration starts */}
      <MealLogProcessingOverlay visible={processingMealLog && !showMealCelebration} />

      {/* Meal Logged Celebration — Strava-style full screen */}
      <MealLoggedCelebration
        isVisible={showMealCelebration}
        recipeName={celebrationData?.recipeName || ''}
        recipeImage={celebrationData?.recipeImage || ''}
        servingsEaten={celebrationData?.servingsEaten || 1}
        calories={celebrationData?.calories || 0}
        protein={celebrationData?.protein || 0}
        onComplete={() => {
          setShowMealCelebration(false);
          window.location.href = createPageUrl("Home");
        }}
      />
    </div>
  );
}

/**
 * DescriptionClamp — Consistent 2-line ellipsis truncation across all recipe cards
 */
export function clampDescription(text, maxLength = 140) {
  if (!text) return null;
  const trimmed = text.trim();
  if (trimmed.length <= maxLength) return trimmed;
  // Truncate + add ellipsis
  let clamped = trimmed.slice(0, maxLength - 2);
  // Try to cut at word boundary
  const lastSpace = clamped.lastIndexOf(' ');
  if (lastSpace > maxLength * 0.7) {
    clamped = trimmed.slice(0, lastSpace);
  }
  return clamped + '..';
}

export function DescriptionText({ text, className = "" }) {
  const clamped = clampDescription(text);
  return (
    <p className={`line-clamp-2 ${className}`} style={{ lineHeight: 1.4 }}>
      {clamped || <span style={{ opacity: 0.4 }}>No description</span>}
    </p>
  );
}

