  const [saveStatus, setSaveStatus] = useState(null); // null | 'success' | 'error'

  const [marketingEnabled, setMarketingEnabled] = useState(false);
  const [bypassForApp, setBypassForApp] = useState(true);

  useEffect(() => {
    const init = async () => {
      try {
        const u = await base44.auth.me();
        setUser(u);
        if (u?.role !== 'admin') {
          setLoading(false);
          return;
        }
        // Load current config
        const res = await base44.functions.invoke('getAppConfig', {});
        const cfg = res.data?.config || {};
        setMarketingEnabled(cfg.marketing_landing_enabled === true);
        setBypassForApp(cfg.marketing_bypass_for_app !== false); // default true
      } catch (e) {
        console.error('[AdminLandingConfig] init error:', e);
      } finally {
        setLoading(false);
      }
    };
    init();
  }, []);

  const handleSave = async () => {
    setSaving(true);
    setSaveStatus(null);
