/**
 * ServingsSelector — mobile-safe, no overflow.
 *
 * Props:
 *   value         (number)   current servings
 *   defaultServings (number) recipe's base servings (for display reference)
 *   onChange      (fn)       called with new servings number
 */
import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

// Format a number as a clean fraction label
function fmtServings(n) {
  if (n === 0.25) return "¼";
  if (n === 0.5)  return "½";
  if (n === 0.75) return "¾";
  if (n === 1.5)  return "1½";
  if (n === 2.5)  return "2½";
  if (Number.isInteger(n)) return String(n);
  return String(Math.round(n * 100) / 100);
}

const QUICK_PICKS = [0.5, 1, 1.5, 2, 3, 4];

export default function ServingsSelector({ value, defaultServings, onChange }) {
  const [showCustom, setShowCustom] = useState(false);
  const [inputVal, setInputVal] = useState("");

  const isQuick = QUICK_PICKS.some(q => Math.abs(q - value) < 0.01);
  const isCustomActive = !isQuick;

  const handleQuick = (s) => {
    setShowCustom(false);
    onChange(s);
  };

  const handleCustomToggle = () => {
    setInputVal(String(value));
    setShowCustom(v => !v);
  };

  const clamp = (n) => Math.min(50, Math.max(0.25, n));

  const applyInput = () => {
    const n = parseFloat(inputVal);
    if (!isNaN(n) && n > 0) onChange(clamp(Math.round(n * 4) / 4));
  };

  const step = (delta) => {
    const next = clamp(Math.round((value + delta) * 4) / 4);
    onChange(next);
    setInputVal(String(next));
  };

  return (
    <div className="w-full">
      {/* Quick picks: 4 per row grid so it never overflows */}
      <div className="grid grid-cols-4 gap-2 w-full" style={{ gridTemplateColumns: "repeat(4, minmax(0, 1fr))" }}>
        {QUICK_PICKS.map(q => (
          <motion.button
            key={q}
            whileTap={{ scale: 0.96 }}
            onClick={() => handleQuick(q)}
            className={cn(
              "h-9 rounded-xl text-sm font-semibold border transition-all",
              Math.abs(q - value) < 0.01 && !showCustom
                ? "bg-indigo-600 text-white border-indigo-600 shadow-sm"
                : "bg-white text-slate-700 border-slate-200 hover:border-slate-300"
            )}
          >
            {fmtServings(q)}
          </motion.button>
        ))}
        {/* Custom pill spans remaining cols (2 cols in row 2) */}
        <motion.button
          whileTap={{ scale: 0.96 }}
          onClick={handleCustomToggle}
          className={cn(
            "h-9 col-span-2 rounded-xl text-sm font-semibold border transition-all",
            (showCustom || isCustomActive)
              ? "bg-slate-900 text-white border-slate-900"
              : "bg-white text-slate-700 border-slate-200 hover:border-slate-300"
          )}
        >
          {isCustomActive && !showCustom ? `${fmtServings(value)} ✎` : "Custom"}
        </motion.button>
      </div>

      {/* Custom inline stepper — no absolute, fully contained */}
      <AnimatePresence initial={false}>
        {showCustom && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.18, ease: "easeInOut" }}
            className="overflow-hidden"
          >
            <div className="flex items-center gap-2 mt-2 w-full">
              <button
                onClick={() => step(-0.25)}
                className="w-10 h-10 rounded-xl border border-slate-200 bg-white flex items-center justify-center text-slate-700 font-bold text-lg hover:bg-slate-50 active:bg-slate-100 transition-colors flex-shrink-0"
              >−</button>
              <input
                type="number"
                min="0.25"
                max="50"
                step="0.25"
                value={inputVal}
                onChange={e => setInputVal(e.target.value)}
                onBlur={applyInput}
                onKeyDown={e => e.key === "Enter" && applyInput()}
                className="flex-1 h-10 rounded-xl border border-slate-200 bg-white text-center text-sm font-bold text-slate-900 focus:border-indigo-400 focus:outline-none min-w-0"
              />
              <button
                onClick={() => step(0.25)}
                className="w-10 h-10 rounded-xl border border-slate-200 bg-white flex items-center justify-center text-slate-700 font-bold text-lg hover:bg-slate-50 active:bg-slate-100 transition-colors flex-shrink-0"
              >+</button>
              <button
                onClick={() => { applyInput(); setShowCustom(false); }}
                className="px-3 h-10 rounded-xl bg-indigo-600 text-white text-xs font-semibold hover:bg-indigo-700 active:bg-indigo-800 transition-colors flex-shrink-0"
              >Set</button>
            </div>
            <p className="text-[11px] text-slate-400 mt-1.5 pl-0.5">0.25 – 50 servings</p>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

