  // ── Toggle helpers ──────────────────────────────────────────────────
  const toggleDiet = (value) => {
    setError("");
    if (value === "none") {
      setDietary(prev => prev.includes("none") ? [] : ["none"]);
      return;
    }
    setDietary(prev => {
      const filtered = prev.filter(d => d !== "none");
      return filtered.includes(value) ? filtered.filter(d => d !== value) : [...filtered, value];
    });
  };

  const toggleAllergy = (value) => {
    setError("");
    if (value === "none") {
      setAllergies(prev => prev.includes("none") ? [] : ["none"]);
      return;
    }
    setAllergies(prev => {
      const filtered = prev.filter(a => a !== "none");
      return filtered.includes(value) ? filtered.filter(a => a !== value) : [...filtered, value];
    });
  };

  const toggleEquipment = (value) => {
    setError("");
    setEquipment(prev =>
      prev.includes(value) ? prev.filter(e => e !== value) : [...prev, value]
    );
  };

  const toggleGoal = (value) => {
    setError("");
    setGoals(prev => {
      if (prev.includes(value)) return prev.filter(g => g !== value);
      if (prev.length >= 2) return prev;
      return [...prev, value];
    });
  };

  // ── Navigation ──────────────────────────────────────────────────────
  const handleNext = async () => {
    setError("");

    if (step === 1 && dietary.length === 0) {
      setError("Please select at least one diet option");
      return;
    }
    if (step === 3 && equipment.length === 0) {
      setError("Please select at least one equipment option");
      return;
    }
    if (step === 4 && !skillLevel) {
      setError("Please select your cooking level");
      return;
    }
    if (step === 5 && goals.length === 0) {
      setError("Please select at least one goal");
      return;
    }
    if (step === 6 && !avatarChoice) {
      setError("Please choose your avatar to continue");
      return;
    }
    // Step 6 (avatar) — save and show review interstitial
    if (step === 6) {
      handleComplete();
      return;
    }
    // Step 7 (review interstitial) handles its own continue — skip in handleNext
    if (step === 7) {
      return;
    }

    setStep(s => s + 1);
  };

  const handleComplete = async () => {
    setIsSaving(true);
    setError("");
    try {
      const chosenAvatar = avatarChoice || "blaze";

      // Generate display_name + username for this new user (fire before avatar upload)
      const currentUser = await base44.auth.me().catch(() => null);
      const identityUpdates = {};
      if (!currentUser?.username || currentUser.username.trim().length < 2 ||
          !currentUser?.display_name || currentUser.display_name.trim().length < 2) {
        const idRes = await base44.functions.invoke('generateUsername', {
          mode: 'generate',
          full_name: currentUser?.full_name || '',
          email: currentUser?.email || '',
        }).catch(() => null);
        if (idRes?.data?.ok) {
          if (!currentUser?.username || currentUser.username.trim().length < 2) {
            identityUpdates.username = idRes.data.username;
          }
          if (!currentUser?.display_name || currentUser.display_name.trim().length < 2) {
            identityUpdates.display_name = idRes.data.display_name;
          }
        }
      }

      // Upload the chosen starter avatar as the user's actual profile picture
      let avatarUrl = null;
      try {
        const file = await getStarterAvatarFile(chosenAvatar);
        const { file_url } = await base44.integrations.Core.UploadFile({ file });
        avatarUrl = file_url;
      } catch (_) {
        // Non-fatal — proceed without avatar upload
      }

      await base44.auth.updateMe({
        dietary_preferences: dietary,
        allergies: allergies.filter(a => a !== "none"),
        equipment,
        skill_level: skillLevel || "beginner",
        goals,
        avatar_choice: chosenAvatar,
        onboarding_complete: true,
        ...(avatarUrl ? { avatar: avatarUrl, avatar_url: avatarUrl } : {}),
        ...identityUpdates,
      });
      setIsSaving(false);
      // Build audience profile from onboarding data (fire-and-forget, non-blocking)
      base44.functions.invoke('buildAudienceProfile', {}).catch(() => {});
      // Data saved → show review interstitial as final step
      setStep(7);
    } catch (err) {
      setError(err.message || "Failed to save. Please try again.");
      setIsSaving(false);
    }
  };

  const handleFinishOnboarding = () => {
    // ProFunnel: Route through RipoIntro → Trust → Paywall before Home
    window.location.replace(createPageUrl("RipoIntro"));
  };

  const currentAssetKey = STEP_ANIMATION_KEYS[step];

  // ── Loading ─────────────────────────────────────────────────────────
  if (!ssoCheckDone) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center">
        <div className="w-8 h-8 rounded-full border-2 border-indigo-200 border-t-indigo-600 animate-spin" />
      </div>
    );
  }



  // ── Main onboarding flow ────────────────────────────────────────────
  return (
    <>
      <Toaster position="bottom-center" />
      <div
        className="min-h-screen flex flex-col"
        style={{ background: "linear-gradient(160deg, #f8f9ff 0%, #fff 40%, #f5f3ff 100%)" }}
      >
        {/* Ripo animation — hidden on review interstitial (step 6) */}
        {currentAssetKey && (
          <div className="flex-shrink-0 flex items-center justify-center pt-6 pb-2">
            <OnboardingAnimationFrame
              assetKey={currentAssetKey}
              stepIndex={step}
            />
          </div>
        )}

        {/* Step content — scrollable, fits as much as possible */}
        <div className={cn("flex-1 flex items-center justify-center px-5 overflow-y-auto", "pb-32")}>
          <div className="w-full max-w-xs">
            <AnimatePresence mode="wait">
              {step === 0 && <StepWelcome key="s0" />}
              {step === 1 && (
                <StepDiet key="s1" selected={dietary} onToggle={toggleDiet} error={error} />
              )}
              {step === 2 && (
                <StepAllergies key="s2" selected={allergies} onToggle={toggleAllergy} error={error} />
              )}
              {step === 3 && (
                <StepEquipment key="s3" selected={equipment} onToggle={toggleEquipment} error={error} />
              )}
              {step === 4 && (
                <StepCookingSkill
                  key="s4"
                  selected={skillLevel}
                  onSelect={(v) => { setSkillLevel(v); setError(""); }}
                  error={error}
                />
              )}
              {step === 5 && (
                <StepGoals key="s5" selected={goals} onToggle={toggleGoal} error={error} />
              )}
              {step === 6 && (
                <StepAvatarChoice
                  key="s6"
                  selected={avatarChoice}
                  onSelect={(v) => { setAvatarChoice(v); setError(""); }}
                  error={error}
                />
              )}
              {step === 7 && (
                <StepAppReview
                  key="s7_review"
                  onContinue={handleFinishOnboarding}
                />
              )}
            </AnimatePresence>
          </div>
        </div>

        {/* Fixed bottom bar — polished, no emojis */}
        <div
          className="fixed bottom-0 left-0 right-0 border-t border-slate-100 px-5 pt-3"
          style={{
            paddingBottom: "max(16px, env(safe-area-inset-bottom))",
            background: "linear-gradient(to top, #ffffff 60%, rgba(255,255,255,0.98) 80%, rgba(255,255,255,0.92) 100%)",
            backdropFilter: "blur(16px)",
            zIndex: 50,
          }}
        >
          {/* Hide progress + buttons on the review interstitial (step 7) */}
          {step === 7 ? null : (
            <>
              <div className="mb-3">
                <OnboardingProgressBar current={step} total={TOTAL_STEPS - 1} />
              </div>
              <div className="flex gap-2">
                {step > 0 && (
                  <button
                    onClick={() => { setStep(s => s - 1); setError(""); }}
                    className="h-11 px-4 rounded-xl border border-slate-200 bg-white text-slate-700 font-semibold text-sm flex-shrink-0 transition-all active:scale-[0.96] hover:bg-slate-50"
                  >
                    Back
                  </button>
                )}
                <OnboardingButton
                  label={isSaving ? "Setting up…" : BUTTON_LABELS[step]}
                  onClick={handleNext}
                  disabled={isSaving}
                  variant={step === 6 ? "final" : "primary"}
                />
              </div>
            </>
          )}
        </div>
      </div>
    </>
  );
}

/**
 * StreakProof — standalone page that renders the streak celebration popup
 * immediately on mount, with a 30-second auto-dismiss so screenshots can capture it.
 * Also triggers a real updateStreakAction to prove backend is wired.
 * Admin-only dev proof page — never linked in production nav.
 */
import React, { useState, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import StreakCelebrationSequence from '../components/streak/StreakCelebrationSequence';
import StreakBreakPopup from '../components/streak/StreakBreakPopup';
import { createPageUrl } from '../utils';

export default function StreakProofPage() {
  const [step, setStep] = useState('priming'); // priming | show_celebration | show_break | done
  const [streakDay, setStreakDay] = useState(4);
  const [backendResult, setBackendResult] = useState(null);
  const [log, setLog] = useState([]);

  const addLog = (msg) => setLog(prev => [...prev, `${new Date().toISOString().slice(11, 23)} ${msg}`]);

  useEffect(() => {
    const run = async () => {
      // Step 1: prime state to yesterday via debugStreakSimulate set_only
      addLog('Step 1: priming streak state to yesterday (set_only)...');
      try {
        const primeRes = await base44.functions.invoke('debugStreakSimulate', {
          days_since_last_action: 1,
          set_only: true,
        });
        addLog(`Prime OK: last_action=${primeRes.data?.primed?.last_streak_action_date_local} streak=${primeRes.data?.primed?.current_streak_days}`);
      } catch (e) {
        addLog(`Prime FAILED: ${e.message} — continuing anyway`);
      }

      // Clear session dedup so celebration fires fresh
      for (let i = sessionStorage.length - 1; i >= 0; i--) {
        const k = sessionStorage.key(i);
        if (k?.startsWith('streak_popup_shown_day_')) {
          sessionStorage.removeItem(k);
          addLog(`Cleared dedup key: ${k}`);
        }
      }

      // Step 2: call real updateStreakAction — exactly what recordAction() calls
      addLog('Step 2: calling updateStreakAction(generate)...');
      try {
        const actionRes = await base44.functions.invoke('updateStreakAction', {
          action_type: 'generate',
        });
        const s = actionRes.data?.streak;
        setBackendResult(s);
        addLog(`Backend OK: streak=${s?.current_streak_days} is_new_day_increment=${s?.is_new_day_increment} status=${s?.streak_status}`);

        if (s?.is_new_day_increment && s?.current_streak_days > 0) {
          setStreakDay(s.current_streak_days);
          addLog(`→ 🎉 is_new_day_increment=true for day ${s.current_streak_days} — SHOWING CELEBRATION POPUP`);
          setStep('show_celebration');
        } else {
          addLog(`→ No increment (same day or already actioned). Showing popup anyway for visual proof with day=${streakDay}`);
          setStep('show_celebration');
        }
      } catch (e) {
        addLog(`updateStreakAction FAILED: ${e.message}`);
        addLog('→ Showing popup for visual proof regardless');
        setStep('show_celebration');
      }
    };

    run();
  }, []);

  return (
    <div className="min-h-screen bg-slate-900 p-6 pb-20">
      <div className="max-w-sm mx-auto">
        <h1 className="text-white font-bold text-lg mb-2">🔥 Streak Celebration Proof</h1>
        <p className="text-slate-400 text-xs mb-4">Admin dev proof — not in production nav</p>

        {/* Backend result */}
        {backendResult && (
          <div className="bg-green-900/40 border border-green-600/40 rounded-xl p-3 mb-3">
            <p className="text-green-400 text-xs font-bold mb-1">✅ Backend confirmed:</p>
            <pre className="text-green-300 text-[10px] font-mono whitespace-pre-wrap">
              {JSON.stringify(backendResult, null, 2)}
            </pre>
          </div>
        )}

        {/* Log */}
        <div className="bg-black/60 rounded-xl p-3 space-y-0.5 mb-4">
          {log.map((l, i) => (
            <p key={i} className="text-[10px] font-mono text-slate-300">{l}</p>
          ))}
          {log.length === 0 && <p className="text-slate-500 text-xs">Running...</p>}
        </div>

        <button
          onClick={() => window.location.href = createPageUrl('Home')}
          className="w-full h-10 rounded-2xl bg-indigo-600 text-white text-sm font-semibold"
        >
          ← Back to Home
        </button>
      </div>

      {/* THE ACTUAL CELEBRATION POPUP — renders on top of everything */}
      <StreakCelebrationSequence
        isVisible={step === 'show_celebration'}
        streakDay={streakDay}
        onDismiss={() => {
          addLog('Popup dismissed — showing BREAK popup next for proof');
          setStep('show_break');
        }}
      />

      {/* BREAK POPUP PROOF — shows after celebration dismisses */}
      <StreakBreakPopup
        isVisible={step === 'show_break'}
        onDismiss={() => {
          addLog('Break popup dismissed — proof complete');
          setStep('done');
        }}
      />

      {step === 'done' && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80">
          <div className="bg-white rounded-3xl p-8 max-w-sm w-full mx-4 text-center">
            <div className="text-5xl mb-4">✅</div>
            <h2 className="text-xl font-black text-slate-900 mb-2">Proof Complete</h2>
            <p className="text-sm text-slate-500 mb-4">Both popups rendered and dismissed correctly.</p>
            <button onClick={() => window.location.href = createPageUrl('Home')} className="w-full h-11 rounded-2xl bg-indigo-600 text-white font-bold">
              Return to Home
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useMemo, useEffect } from "react";
import { base44 } from "@/api/base44Client";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { ArrowLeft, ShoppingCart, Trash2, Check, ChevronDown, ChevronUp, Eye } from "lucide-react";
import { createPageUrl } from "../utils";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";
import { useLocalization } from "@/services/localization/LocalizationContext";
import { translateIngredientName } from "@/services/localization/ingredientTranslations";
import { formatGroceryAmount } from "@/services/localization/groceryPhraseFormatter";

export default function ShoppingListPage() {
  const { t, formatPrice, resolvedLang } = useLocalization();
  const queryClient = useQueryClient();
  const [collapsedRecipes, setCollapsedRecipes] = useState(new Set());
  const [currentUser, setCurrentUser] = useState(null);
  const [resolvedGenIds, setResolvedGenIds] = useState({});

  useEffect(() => {
    base44.auth.me().then(u => setCurrentUser(u)).catch(() => {});
  }, []);

  const userId = currentUser?.id;
  const userEmail = currentUser?.email;

  const { data: items = [], isLoading } = useQuery({
    queryKey: ["shopping-list", userId],
    queryFn: async () => {
      // PRIVACY: Filter by owner_id first (indexed), fall back to created_by for legacy items
      const [byOwner, byCreator] = await Promise.all([
        userId ? base44.entities.ShoppingList.filter({ owner_id: userId }, "-created_date", 200) : [],
        userEmail ? base44.entities.ShoppingList.filter({ created_by: userEmail }, "-created_date", 200) : [],
      ]);
      // Merge and deduplicate by ID
      const seen = new Set();
      const merged = [];
      for (const item of [...byOwner, ...byCreator]) {
        if (!seen.has(item.id)) { seen.add(item.id); merged.push(item); }
      }
      return merged;
    },
    enabled: !!userId || !!userEmail,
    staleTime: 30 * 1000,
  });

  const toggleBoughtMutation = useMutation({
    mutationFn: ({ id, is_bought }) => base44.entities.ShoppingList.update(id, { is_bought }),
    onMutate: async ({ id, is_bought }) => {
      await queryClient.cancelQueries({ queryKey: ["shopping-list", userId] });
      queryClient.setQueryData(["shopping-list", userId], (old = []) =>
        old.map(item => item.id === id ? { ...item, is_bought } : item)
      );
    },
    onSettled: () => queryClient.invalidateQueries({ queryKey: ["shopping-list"] }),
  });

  const deleteItemMutation = useMutation({
    mutationFn: (id) => base44.entities.ShoppingList.delete(id),
    onMutate: async (id) => {
      await queryClient.cancelQueries({ queryKey: ["shopping-list", userId] });
      queryClient.setQueryData(["shopping-list", userId], (old = []) => old.filter(i => i.id !== id));
    },
    onSettled: () => queryClient.invalidateQueries({ queryKey: ["shopping-list"] }),
  });

  const clearBoughtMutation = useMutation({
    mutationFn: async () => {
      const bought = items.filter(i => i.is_bought);
      await Promise.all(bought.map(i => base44.entities.ShoppingList.delete(i.id)));
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["shopping-list"] }),
  });

  const clearAllMutation = useMutation({
    mutationFn: async () => {
      await Promise.all(items.map(i => base44.entities.ShoppingList.delete(i.id)));
    },
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ["shopping-list"] }),
  });

  const grouped = React.useMemo(() => {
    const map = {};
    for (const item of items) {
      const key = item.recipe_id || "__manual__";
      const label = item.recipe_title || t('shopping.other', 'Other');
      if (!map[key]) map[key] = { recipe_id: key, recipe_title: label, items: [] };
      map[key].items.push(item);
    }
    return Object.values(map);
  }, [items]);

  const boughtCount = items.filter(i => i.is_bought).length;
  const totalCount = items.length;

  const toggleCollapse = (key) => {
    setCollapsedRecipes(prev => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key); else next.add(key);
      return next;
    });
  };

  // Resolve __gen recipe IDs to real Recipe entities by matching title + author_id
  useEffect(() => {
    if (!userId || !items.length) return;
    const genGroups = grouped.filter(g => g.recipe_id?.startsWith('__gen'));
    if (!genGroups.length) return;
    const toResolve = genGroups.filter(g => !(g.recipe_id in resolvedGenIds));
    if (!toResolve.length) return;
    (async () => {
      const newResolved = {};
      for (const group of toResolve) {
        try {
          const recipes = await base44.entities.Recipe.filter(
            { title: group.recipe_title, source: 'generated', author_id: userId },
            '-created_date', 1
          );
          newResolved[group.recipe_id] = recipes[0]?.id || null;
        } catch {
          newResolved[group.recipe_id] = null;
        }
      }
      setResolvedGenIds(prev => ({ ...prev, ...newResolved }));
    })();
  }, [grouped, userId]);

  const fmtCost = (val) => {
    if (!val || val <= 0) return null;
    if (formatPrice) return formatPrice(val);
    return `$${Number(val).toFixed(2)}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-28">
      {/* Header */}
      <div className="sticky top-0 z-10 bg-white border-b border-slate-100 shadow-sm">
        <div className="flex items-center gap-3 px-5 py-4">
          <Link to={createPageUrl("Pantry")}>
            <button className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center">
              <ArrowLeft className="w-5 h-5 text-slate-600" />
            </button>
          </Link>
          <div className="flex-1">
            <h1 className="text-xl font-bold text-slate-900">{t('shopping.title', 'Shopping List')}</h1>
            {totalCount > 0 && (
              <p className="text-xs text-slate-400">{boughtCount}/{totalCount} {t('shopping.bought', 'bought')}</p>
            )}
          </div>
          {boughtCount > 0 && (
            <button
              onClick={() => clearBoughtMutation.mutate()}
              className="text-xs text-rose-500 font-semibold px-3 py-1.5 rounded-xl bg-rose-50"
            >
              {t('shopping.clear_bought', 'Clear bought')}
            </button>
          )}
        </div>
        {totalCount > 0 && (
          <div className="h-1 bg-slate-100 mx-5 mb-3 rounded-full overflow-hidden">
            <motion.div
              className="h-full bg-emerald-500 rounded-full"
              animate={{ width: `${(boughtCount / totalCount) * 100}%` }}
              transition={{ duration: 0.3 }}
            />
          </div>
        )}
      </div>

      <div className="px-5 py-4 space-y-4">
        {isLoading ? (
          <div className="space-y-3">
            {[1, 2, 3, 4].map(i => (
              <div key={i} className="h-14 bg-white rounded-2xl animate-pulse" />
            ))}
          </div>
        ) : totalCount === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-center">
            <div className="w-20 h-20 rounded-full bg-indigo-50 flex items-center justify-center mb-4">
              <ShoppingCart className="w-10 h-10 text-indigo-300" />
            </div>
            <h3 className="text-lg font-bold text-slate-700 mb-1">{t('shopping.empty_title', 'Your list is empty')}</h3>
            <p className="text-sm text-slate-400 mb-6 max-w-xs">
              {t('shopping.empty_desc', 'Tap the 🛒 button next to any ingredient to add it here.')}
            </p>
            <Link to={createPageUrl("Home")}>
              <button className="px-6 py-2.5 rounded-2xl bg-indigo-600 text-white font-semibold text-sm">
                {t('shopping.go_recipes', 'Go to My Recipes')}
              </button>
            </Link>
          </div>
        ) : (
          <>
            {grouped.map((group) => {
              const isCollapsed = collapsedRecipes.has(group.recipe_id);
              const allBought = group.items.every(i => i.is_bought);
              const groupCost = group.items.reduce((sum, i) => sum + (i.cost || 0), 0);
              return (
                <div key={group.recipe_id} className="bg-white rounded-2xl overflow-hidden shadow-sm border border-slate-100">
                  {/* Group header */}
                  <div className="flex items-center gap-1 px-4 py-3 border-b border-slate-50">
                    <button
                      onClick={() => toggleCollapse(group.recipe_id)}
                      className="flex-1 flex items-center gap-2 min-w-0 text-left"
                    >
                      <div className={cn("w-2 h-2 rounded-full flex-shrink-0", allBought ? "bg-emerald-400" : "bg-indigo-400")} />
                      <span className="text-sm font-bold text-slate-800 truncate flex-1">{group.recipe_title}</span>
                      <span className="text-xs text-slate-400 flex-shrink-0">
                        ({group.items.filter(i => i.is_bought).length}/{group.items.length})
                      </span>
                      {groupCost > 0 && (
                        <span className="text-[11px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full flex-shrink-0">
                          {fmtCost(groupCost)}
                        </span>
                      )}
                      {isCollapsed
                        ? <ChevronDown className="w-4 h-4 text-slate-400 flex-shrink-0" />
                        : <ChevronUp className="w-4 h-4 text-slate-400 flex-shrink-0" />
                      }
                    </button>
                    {/* Eye icon to view recipe — resolve __gen IDs */}
                    {group.recipe_id && group.recipe_id !== "__manual__" && (() => {
                      const isGen = group.recipe_id.startsWith('__gen');
                      const realId = isGen ? resolvedGenIds[group.recipe_id] : group.recipe_id;
                      if (isGen && realId === null) return null;
                      if (isGen && realId === undefined) return (
                        <div className="w-8 h-8 rounded-full flex items-center justify-center bg-slate-100 flex-shrink-0 ml-1">
                          <div className="w-2 h-2 rounded-full bg-slate-300 animate-pulse" />
                        </div>
                      );
                      return (
                        <button
                          onClick={(e) => {
                            e.stopPropagation();
                            window.location.href = createPageUrl("RecipeDetail") + `?id=${realId}`;
                          }}
