                    )}
                  </AnimatePresence>
                </div>
              );
            })}

            <button
              onClick={() => clearAllMutation.mutate()}
              className="w-full py-3 rounded-2xl border-2 border-dashed border-rose-200 text-rose-400 text-sm font-semibold hover:bg-rose-50 transition-colors"
            >
