            </button>
          </>
        )}
      </div>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { base44 } from '@/api/base44Client';
import { createPageUrl } from '../utils';
import { Loader2 } from 'lucide-react';
import { motion } from 'framer-motion';

/**
 * Paused.jsx — Full-screen hard-lock UI for paused accounts
 * No navigation, no access to app features.
 * Shows pause date + resume/logout buttons only.
 */
export default function PausedPage() {
  const [user, setUser] = useState(null);
  const [resuming, setResuming] = useState(false);
  const [resumeError, setResumeError] = useState('');
  const prefersReducedMotion = useMemo(() => {
    if (typeof window === 'undefined') return false;
    return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  }, []);

  useEffect(() => {
    base44.auth.me()
      .then(u => {
        if (!u) {
          // Not authenticated, redirect to login
          window.location.href = createPageUrl('AuthCallback');
          return;
        }
        // If not paused, redirect to home
        if (u.account_status !== 'paused' || !u.paused_until) {
          window.location.href = createPageUrl('Home');
          return;
        }
        setUser(u);
      })
      .catch(() => {
        // Auth failed, redirect to login
        window.location.href = createPageUrl('AuthCallback');
      });
  }, []);

  const handleResume = async () => {
    setResuming(true);
    setResumeError('');
    try {
      const res = await base44.functions.invoke('resumeAccount', {});
      if (res?.data?.success || res?.data?.already_active) {
        // Force hard reload to pick up fresh auth state
        window.location.href = createPageUrl('Home');
      } else {
        setResumeError(res?.data?.reason || 'Failed to resume account.');
        setResuming(false);
      }
    } catch (err) {
      setResumeError(err.response?.data?.reason || err.message || 'Failed to resume. Please try again.');
      setResuming(false);
    }
  };

  const handleLogOut = () => {
    localStorage.clear();
    sessionStorage.clear();
    base44.auth.logout(createPageUrl('AuthCallback'));
  };

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="w-8 h-8 rounded-full border-2 border-indigo-200 border-t-indigo-600 animate-spin" />
      </div>
    );
  }

  const pausedUntil = user.paused_until ? new Date(user.paused_until) : null;
  const pauseDateStr = pausedUntil
    ? pausedUntil.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })
    : 'Paused';

  return (
    <div
      className="min-h-screen flex flex-col items-center justify-center p-6"
      style={{
        background: 'linear-gradient(160deg, #0f172a 0%, #1e1b4b 60%, #0f172a 100%)',
      }}
    >
      <style>{`
        @keyframes pauseIconFloat {
          0%, 100% { transform: translateY(0) scale(1); opacity: 0.9; }
          50% { transform: translateY(-8px) scale(1.03); opacity: 1; }
        }
        @keyframes pauseGlow {
          0%, 100% { box-shadow: 0 0 18px rgba(99,179,237,0.35), 0 4px 20px rgba(59,130,246,0.25); }
          50% { box-shadow: 0 0 28px rgba(147,210,255,0.55), 0 4px 28px rgba(59,130,246,0.45); }
        }
        @keyframes goldShimmer {
          0% { background-position: 200% center; }
          100% { background-position: -200% center; }
        }
        @keyframes iceGlow {
          0%, 100% { box-shadow: 0 0 18px rgba(99,179,237,0.35), 0 4px 20px rgba(59,130,246,0.25); }
          50% { box-shadow: 0 0 28px rgba(147,210,255,0.55), 0 4px 28px rgba(59,130,246,0.45); }
        }
      `}</style>

      <div className="w-full max-w-xs text-center">
        {/* Pause Icon with glow */}
        <motion.div
          className="w-20 h-20 rounded-full mx-auto mb-6 flex items-center justify-center flex-shrink-0"
          style={{
            background: 'linear-gradient(135deg, #1e3a5f 0%, #1e40af 100%)',
            animation: !prefersReducedMotion ? 'pauseGlow 3s ease-in-out infinite' : 'none',
          }}
          initial={!prefersReducedMotion ? { scale: 0.9, opacity: 0 } : false}
          animate={!prefersReducedMotion ? { scale: 1, opacity: 1 } : false}
          transition={!prefersReducedMotion ? { duration: 0.6 } : {}}
        >
          <div
            style={{
              animation: !prefersReducedMotion ? 'pauseIconFloat 2.5s ease-in-out infinite' : 'none',
            }}
          >
            <svg className="w-10 h-10 text-sky-300" fill="currentColor" viewBox="0 0 24 24">
              <path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z" />
            </svg>
          </div>
        </motion.div>

        {/* Title */}
        <motion.h1
          className="text-3xl font-bold text-white mb-2 tracking-tight"
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.1 }}
        >
          Account Paused
        </motion.h1>

        {/* Subtitle */}
        <motion.p
          className="text-sm text-slate-400 mb-1"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.5, delay: 0.2 }}
        >
          Your account is paused until
        </motion.p>

        {/* Date */}
        <motion.p
          className="text-xl font-semibold text-sky-300 mb-6"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.5, delay: 0.3 }}
        >
          {pauseDateStr}
        </motion.p>

        {/* Message Box */}
        <motion.div
          className="rounded-2xl p-4 mb-6 text-left"
          style={{
            background: 'rgba(255,255,255,0.04)',
            border: '1px solid rgba(255,255,255,0.08)',
