          <p className="text-sm text-slate-300 leading-relaxed">
            Your profile is hidden and app access is restricted until the pause ends. You can resume anytime or wait for auto-reactivation.
          </p>
        </motion.div>

        {/* Subscription Disclaimer */}
        <motion.div
          className="rounded-2xl p-4 mb-8 text-left"
          style={{
            background: 'rgba(255,255,255,0.04)',
