              target="_blank"
              rel="noopener noreferrer"
              className="text-sky-300 hover:text-sky-200 font-semibold underline transition-colors"
            >
              Google Play
            </a>
            .
          </p>
        </motion.div>

        {/* Error Alert */}
        {resumeError && (
          <motion.div
            className="rounded-2xl p-3 mb-4 text-left"
            style={{
              background: 'rgba(239,68,68,0.15)',
              border: '1px solid rgba(239,68,68,0.3)',
            }}
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
          >
            <p className="text-xs text-rose-300">{resumeError}</p>
          </motion.div>
        )}

        {/* Buttons */}
        <motion.div
          className="flex flex-col gap-3 w-full"
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.5, delay: 0.6 }}
        >
          {/* Resume Button (Gold) */}
          <button
            onClick={handleResume}
            disabled={resuming}
            className="relative w-full h-12 rounded-2xl text-sm font-semibold tracking-wide disabled:opacity-60 overflow-hidden transition-all duration-300 hover:scale-[1.02] active:scale-[0.98]"
            style={{
              background: 'linear-gradient(135deg, #f6d365 0%, #fda085 40%, #f7c948 70%, #ffe066 100%)',
              color: '#7a4a00',
              boxShadow: '0 4px 20px rgba(247, 195, 30, 0.45), inset 0 1px 0 rgba(255,255,255,0.4)',
              border: '1px solid rgba(255, 210, 80, 0.6)',
            }}
          >
            <span className="relative z-10 flex items-center justify-center gap-2">
              {resuming ? (
                <>
                  <span className="w-4 h-4 border-2 border-yellow-700/40 border-t-yellow-800 rounded-full animate-spin" />
