import React, { useState } from "react";
import { base44 } from "@/api/base44Client";
import { useQuery, useQueryClient } from "@tanstack/react-query";
import { ArrowLeft, AlertTriangle, CheckCircle2, RefreshCw, Filter, Trash2 } from "lucide-react";
import AdminBackButton from "../components/admin/AdminBackButton";
import { cn } from "@/lib/utils";
import { format } from "date-fns";

const CATEGORY_COLORS = {
  rate_limit: "bg-amber-100 text-amber-700",
  auth_failure: "bg-red-100 text-red-700",
  network_error: "bg-orange-100 text-orange-700",
  query_timeout: "bg-yellow-100 text-yellow-700",
  null_reference: "bg-purple-100 text-purple-700",
  feed_failure: "bg-blue-100 text-blue-700",
  media_upload_failure: "bg-pink-100 text-pink-700",
  permission_mismatch: "bg-rose-100 text-rose-700",
  data_integrity: "bg-indigo-100 text-indigo-700",
  unknown: "bg-slate-100 text-slate-600",
};

const SEVERITY_COLORS = {
  critical: "bg-red-500 text-white",
  error: "bg-red-100 text-red-700",
  warning: "bg-amber-100 text-amber-700",
  info: "bg-blue-100 text-blue-600",
};

export default function AdminErrorLog() {
  const [filter, setFilter] = useState("all");
  const [surfaceFilter, setSurfaceFilter] = useState("all");
  const [expandedId, setExpandedId] = useState(null);
  const queryClient = useQueryClient();

  const { data: errors = [], isLoading, refetch } = useQuery({
    queryKey: ["admin-error-logs", filter, surfaceFilter],
    queryFn: async () => {
      const q = {};
      if (filter !== "all") q.error_category = filter;
      if (surfaceFilter !== "all") q.page_surface = surfaceFilter;
      return base44.entities.BackendErrorLog.filter(q, "-created_date", 100);
    },
    staleTime: 30_000,
  });

  const unresolvedCount = errors.filter(e => !e.resolved).length;
  const categories = [...new Set(errors.map(e => e.error_category).filter(Boolean))];
  const surfaces = [...new Set(errors.map(e => e.page_surface).filter(Boolean))];

  const handleResolve = async (id) => {
    await base44.entities.BackendErrorLog.update(id, { resolved: true, resolution_note: "Marked resolved by admin" });
    refetch();
  };

  const handleDelete = async (id) => {
    await base44.entities.BackendErrorLog.delete(id);
    refetch();
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <div className="sticky top-0 bg-white/95 backdrop-blur-lg border-b border-slate-100 z-10">
        <div className="flex items-center gap-3 px-5 py-4">
          <AdminBackButton />
          <div className="flex-1">
            <h1 className="text-lg font-bold text-slate-900">Backend Error Log</h1>
            <p className="text-xs text-slate-500">{unresolvedCount} unresolved · {errors.length} total</p>
          </div>
          <button onClick={() => refetch()} className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center" data-icon-only>
            <RefreshCw className="w-4 h-4 text-slate-600" />
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="px-5 py-3 flex gap-2 overflow-x-auto hide-scrollbar">
        <select
          value={filter}
          onChange={e => setFilter(e.target.value)}
          className="h-9 px-3 rounded-xl bg-white border border-slate-200 text-xs font-medium text-slate-700"
        >
          <option value="all">All Categories</option>
          {categories.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
        <select
          value={surfaceFilter}
          onChange={e => setSurfaceFilter(e.target.value)}
          className="h-9 px-3 rounded-xl bg-white border border-slate-200 text-xs font-medium text-slate-700"
        >
          <option value="all">All Surfaces</option>
          {surfaces.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
      </div>

      {/* Error List */}
      <div className="px-5 space-y-2">
        {isLoading ? (
          <div className="flex justify-center py-12">
            <div className="w-8 h-8 border-2 border-slate-200 border-t-indigo-500 rounded-full animate-spin" />
          </div>
        ) : errors.length === 0 ? (
          <div className="text-center py-16">
            <CheckCircle2 className="w-12 h-12 text-emerald-400 mx-auto mb-3" />
            <p className="text-sm font-semibold text-slate-700">No errors found</p>
            <p className="text-xs text-slate-400 mt-1">All clear!</p>
          </div>
        ) : errors.map(err => (
          <div
            key={err.id}
            className={cn("bg-white rounded-2xl border overflow-hidden transition-all", err.resolved ? "border-emerald-200 opacity-60" : "border-slate-200")}
          >
            <button
              onClick={() => setExpandedId(expandedId === err.id ? null : err.id)}
              className="w-full text-left p-4"
            >
              <div className="flex items-start gap-3">
                <div className={cn("w-2 h-2 rounded-full mt-1.5 flex-shrink-0", err.severity === 'critical' ? "bg-red-500" : err.severity === 'warning' ? "bg-amber-400" : "bg-red-400")} />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap mb-1">
                    <span className="text-xs font-bold text-slate-900">{err.function_name}</span>
                    <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full", CATEGORY_COLORS[err.error_category] || CATEGORY_COLORS.unknown)}>
                      {err.error_category}
                    </span>
                    {err.page_surface && (
                      <span className="text-[10px] font-medium px-2 py-0.5 rounded-full bg-indigo-50 text-indigo-600">{err.page_surface}</span>
                    )}
                    {err.resolved && (
                      <span className="text-[10px] font-bold px-2 py-0.5 rounded-full bg-emerald-100 text-emerald-700">✓ Resolved</span>
                    )}
                  </div>
                  <p className="text-xs text-slate-600 line-clamp-2">{err.error_message}</p>
                  <p className="text-[10px] text-slate-400 mt-1">
                    {err.timestamp ? format(new Date(err.timestamp), "MMM d, HH:mm:ss") : "Unknown time"}
                    {err.user_id && <span> · User: {err.user_id.substring(0, 8)}…</span>}
                    {err.retry_count > 0 && <span> · {err.retry_count} retries</span>}
                    {err.fallback_used && <span> · Fallback {err.fallback_succeeded ? "✓" : "✗"}</span>}
                  </p>
                </div>
              </div>
            </button>

            {/* Expanded Detail */}
            {expandedId === err.id && (
              <div className="px-4 pb-4 border-t border-slate-100 pt-3 space-y-3">
                {err.normalized_reason && (
                  <div>
                    <p className="text-[10px] font-bold text-slate-500 uppercase mb-1">Reason</p>
                    <p className="text-xs text-slate-700">{err.normalized_reason}</p>
                  </div>
                )}
                {err.stack_trace && (
                  <div>
                    <p className="text-[10px] font-bold text-slate-500 uppercase mb-1">Stack</p>
                    <pre className="text-[10px] text-slate-600 bg-slate-50 rounded-xl p-2 overflow-x-auto max-h-40 whitespace-pre-wrap">{err.stack_trace}</pre>
                  </div>
                )}
                {err.request_context && (
                  <div>
                    <p className="text-[10px] font-bold text-slate-500 uppercase mb-1">Context</p>
                    <pre className="text-[10px] text-slate-600 bg-slate-50 rounded-xl p-2 overflow-x-auto max-h-24 whitespace-pre-wrap">{err.request_context}</pre>
                  </div>
                )}
                <div className="flex gap-2 pt-2">
                  {!err.resolved && (
                    <button onClick={() => handleResolve(err.id)} className="flex items-center gap-1.5 px-3 py-2 rounded-xl bg-emerald-50 text-emerald-700 text-xs font-semibold">
                      <CheckCircle2 className="w-3.5 h-3.5" /> Mark Resolved
                    </button>
                  )}
                  <button onClick={() => handleDelete(err.id)} className="flex items-center gap-1.5 px-3 py-2 rounded-xl bg-rose-50 text-rose-600 text-xs font-semibold">
                    <Trash2 className="w-3.5 h-3.5" /> Delete
                  </button>
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

/**
 * RequestProof — QA page to verify message requests flow
 * Shows: pending requests, inbox visibility, before/after accept
 */
import React, { useState } from 'react';
import { base44 } from '@/api/base44Client';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { Link } from 'react-router-dom';
import { ArrowLeft, RefreshCw, Check } from 'lucide-react';

export default function RequestProof() {
  const qc = useQueryClient();
  const [accepting, setAccepting] = useState(null);
  const [autoRefresh, setAutoRefresh] = useState(true);

  const { data: currentUser } = useQuery({
    queryKey: ['current-user'],
    queryFn: () => base44.auth.me(),
  });

  const { data: allConvs, refetch: refetchConvs } = useQuery({
    queryKey: ['all-convs-proof', currentUser?.id],
    queryFn: async () => {
      if (!currentUser?.id) return [];
      const [convsA, convsB] = await Promise.all([
        base44.entities.DirectConversation.filter({ participant_a_id: currentUser.id }),
        base44.entities.DirectConversation.filter({ participant_b_id: currentUser.id }),
      ]);
      const seen = new Set();
      return [...convsA, ...convsB].filter(c => { if (seen.has(c.id)) return false; seen.add(c.id); return true; });
    },
    enabled: !!currentUser?.id,
    staleTime: 0,
    refetchInterval: autoRefresh ? 2000 : false,
  });

  const handleAccept = async (convId) => {
    setAccepting(convId);
    try {
      await base44.functions.invoke('acceptDirectConversation', { conversation_id: convId });
      qc.invalidateQueries({ queryKey: ['all-convs-proof'] });
      qc.invalidateQueries({ queryKey: ['direct-convs-a'] });
      qc.invalidateQueries({ queryKey: ['direct-convs-b'] });
    } catch (e) {
      alert('Accept failed: ' + (e?.message || 'unknown error'));
    } finally {
      setAccepting(null);
    }
  };

  const pendingRequests = allConvs?.filter(c => c.is_request && c.request_recipient_id === currentUser?.id) || [];
  const inboxConvs = allConvs?.filter(c => !c.is_request || c.request_recipient_id !== currentUser?.id) || [];

  return (
    <div className="min-h-screen bg-slate-50 p-6">
