/**
 * AdminModeration — Admin-only moderation dashboard.
 * Protected by RequireAdmin (checks user.role === 'admin' via server).
 * Handles deep-links from report emails: ?report_id=... &ctx=target|reporter
 * 
 * FIX: UserProfile uses ?userId= not ?id=
 * FIX: Status updates now go through adminModerateAction backend (server-side admin check)
 * FIX: Added Remove Content + Suspend User actions that propagate globally
 */
import React, { useState, useEffect, useMemo } from 'react';
import { base44 } from '@/api/base44Client';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { createPageUrl } from '../utils';
import RequireAdmin from '../components/services/RequireAdmin';
import { ArrowLeft, Flag, Eye, User, CheckCircle2, Clock, XCircle, Trash2, ShieldOff, ShieldCheck, Loader2 } from 'lucide-react';
import AdminBackButton from '../components/admin/AdminBackButton';
import { format } from 'date-fns';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

const STATUS_COLORS = {
  open:      'bg-rose-100 text-rose-700',
  in_review: 'bg-amber-100 text-amber-700',
  resolved:  'bg-green-100 text-green-700',
  dismissed: 'bg-slate-100 text-slate-600',
};

const CTX_LABELS = {
  target:   'Email action: View Target',
  reporter: 'Email action: View Reporter',
};

// Build the correct content URL for the target
function buildTargetUrl(report) {
  switch (report.target_type) {
    case 'post':
    case 'recipe':   return createPageUrl('RecipeDetail') + `?id=${report.target_id}`;
    case 'user':     return createPageUrl('UserProfile')  + `?userId=${report.target_id}`; // FIX: userId not id
    case 'group':    return createPageUrl('GroupDetail')  + `?id=${report.target_id}`;
    case 'shop':     return createPageUrl('Shop')         + `?id=${report.target_id}`;
    case 'comment':  return createPageUrl('Community');
    case 'message':  return createPageUrl('ChatList');
    default:         return createPageUrl('Home');
  }
}

// Build reporter profile URL (always userId param)
function buildReporterUrl(report) {
  return createPageUrl('UserProfile') + `?userId=${report.reporter_user_id}`;
}

function ReportCard({ report, isSelected, onClick }) {
  return (
    <button
      onClick={onClick}
      className={cn(
        'w-full text-left p-4 rounded-2xl border transition-all',
        isSelected ? 'border-indigo-300 bg-indigo-50' : 'border-slate-200 bg-white hover:bg-slate-50'
      )}
    >
      <div className="flex items-start justify-between gap-2 mb-1">
        <span className={cn('text-[10px] font-bold px-2 py-0.5 rounded-full uppercase', STATUS_COLORS[report.status] || STATUS_COLORS.open)}>
          {report.status}
        </span>
        <span className="text-[10px] font-semibold text-slate-500 capitalize flex-shrink-0">{report.target_type}</span>
      </div>
      <p className="text-sm font-semibold text-slate-800 truncate">{report.reason}</p>
      {report.details && <p className="text-xs text-slate-500 truncate mt-0.5">{report.details}</p>}
      <p className="text-[10px] text-slate-400 mt-1">
        {report.created_date ? format(new Date(report.created_date), 'MMM d, yyyy') : ''}
      </p>
    </button>
  );
}

function ReportDetail({ report, ctx, onDone }) {
  const [acting, setActing] = useState(null); // which action is in-flight
  const queryClient = useQueryClient();

  const runAction = async (action, extra = {}) => {
    setActing(action);
    try {
      const res = await base44.functions.invoke('adminModerateAction', {
        action,
        report_id: report.id,
        target_type: report.target_type,
        target_id: report.target_id,
        reporter_user_id: report.reporter_user_id,
        ...extra,
      });
      if (res.data?.ok) {
        toast.success(`Action applied: ${action.replace(/_/g, ' ')}`);
        queryClient.invalidateQueries({ queryKey: ['admin-reports'] });
        queryClient.invalidateQueries({ queryKey: ['admin-report-deep'] });
        onDone();
      } else {
        toast.error(res.data?.error || 'Action failed');
      }
    } catch (err) {
      toast.error(err?.response?.data?.error || err.message || 'Action failed');
    } finally {
      setActing(null);
    }
  };

  const targetUrl   = buildTargetUrl(report);
  const reporterUrl = buildReporterUrl(report);
  const isUserTarget = report.target_type === 'user';

  return (
    <div className="bg-white rounded-2xl border border-slate-200 p-5 space-y-4 mb-4">
      {ctx && (
        <div className="bg-amber-50 border border-amber-200 rounded-xl px-3 py-2">
          <p className="text-xs font-semibold text-amber-700">{CTX_LABELS[ctx] || ''}</p>
        </div>
      )}

      <div className="flex items-center justify-between">
        <h3 className="text-base font-bold text-slate-900">Report detail</h3>
        <span className={cn('text-xs font-bold px-2.5 py-1 rounded-full uppercase', STATUS_COLORS[report.status] || STATUS_COLORS.open)}>
          {report.status}
        </span>
      </div>

      {/* Report metadata */}
      <div className="bg-slate-50 rounded-xl p-3 space-y-1.5 text-[11px]">
        <Row label="Report ID"   value={report.id}              mono />
        <Row label="Target type" value={report.target_type}     />
        <Row label="Target ID"   value={report.target_id}       mono />
        <Row label="Reporter ID" value={report.reporter_user_id} mono />
        <Row label="Reason"      value={report.reason}          />
        {report.details && <Row label="Details" value={report.details} />}
        <Row label="Submitted"   value={report.created_date ? format(new Date(report.created_date), 'MMM d, yyyy HH:mm') : '—'} />
      </div>

      {/* Quick-view links — open in same tab so admin is authenticated */}
      <div className="flex gap-2 flex-wrap pt-1">
        <a href={targetUrl}
          className="flex items-center gap-1.5 text-xs font-semibold px-3 py-2 rounded-xl bg-indigo-50 text-indigo-700 hover:bg-indigo-100 transition-colors">
          <Eye className="w-3.5 h-3.5" /> View Target
        </a>
        <a href={reporterUrl}
          className="flex items-center gap-1.5 text-xs font-semibold px-3 py-2 rounded-xl bg-slate-100 text-slate-700 hover:bg-slate-200 transition-colors">
          <User className="w-3.5 h-3.5" /> View Reporter
        </a>
      </div>

      {/* Moderation actions */}
      <div className="pt-2 border-t border-slate-100 space-y-2">
        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Moderation Actions</p>

        {/* Content/User actions */}
        <div className="flex gap-2 flex-wrap">
          {(report.target_type === 'post' || report.target_type === 'recipe' || report.target_type === 'comment') && (
            <ActionButton
              label="Remove Content"
              icon={Trash2}
              color="bg-rose-100 text-rose-700 hover:bg-rose-200"
              loading={acting === 'remove_content'}
              onClick={() => runAction('remove_content')}
            />
          )}
          {isUserTarget && (
            <ActionButton
              label="Suspend User"
              icon={ShieldOff}
              color="bg-rose-100 text-rose-700 hover:bg-rose-200"
              loading={acting === 'suspend_user'}
              onClick={() => runAction('suspend_user', { target_id: report.target_id })}
            />
          )}
          {isUserTarget && (
            <ActionButton
              label="Unsuspend User"
              icon={ShieldCheck}
              color="bg-emerald-100 text-emerald-700 hover:bg-emerald-200"
              loading={acting === 'unsuspend_user'}
              onClick={() => runAction('unsuspend_user', { target_id: report.target_id })}
            />
          )}
        </div>

        {/* Status-change actions */}
        <div className="flex gap-2 flex-wrap">
          {report.status === 'open' && (
            <ActionButton
              label="Mark In Review"
              icon={Clock}
              color="bg-amber-100 text-amber-700 hover:bg-amber-200"
              loading={acting === 'mark_in_review'}
              onClick={() => runAction('mark_in_review')}
            />
          )}
          {(report.status === 'open' || report.status === 'in_review') && (
            <ActionButton
              label="Resolve"
              icon={CheckCircle2}
              color="bg-green-100 text-green-700 hover:bg-green-200"
              loading={acting === 'resolve_report'}
              onClick={() => runAction('resolve_report')}
            />
          )}
          {(report.status === 'open' || report.status === 'in_review') && (
            <ActionButton
              label="Dismiss"
              icon={XCircle}
              color="bg-slate-100 text-slate-600 hover:bg-slate-200"
              loading={acting === 'dismiss_report'}
              onClick={() => runAction('dismiss_report')}
            />
          )}
        </div>
      </div>
    </div>
  );
}

function Row({ label, value, mono }) {
  return (
    <div className="flex gap-3 items-start">
      <span className="text-slate-400 w-24 flex-shrink-0 pt-0.5">{label}</span>
      <span className={cn('text-slate-700 break-all flex-1', mono && 'font-mono')}>{value}</span>
    </div>
  );
}

function ActionButton({ label, icon: Icon, color, loading, onClick }) {
  return (
    <button
      onClick={onClick}
      disabled={loading}
      className={cn('flex items-center gap-1.5 h-9 px-3 rounded-xl font-semibold text-xs transition-colors disabled:opacity-50', color)}
    >
      {loading ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Icon className="w-3.5 h-3.5" />}
      {label}
    </button>
  );
}

function AdminModerationContent() {
  const urlParams = new URLSearchParams(window.location.search);
  const reportIdParam = urlParams.get('report_id');
  const ctxParam = urlParams.get('ctx'); // 'target' | 'reporter' | null

  const [statusFilter, setStatusFilter] = useState('open');
  const [selectedReportId, setSelectedReportId] = useState(reportIdParam || null);

  // Use the admin-gated backend function instead of direct entity access
  const { data: reportsData, isLoading, refetch } = useQuery({
    queryKey: ['admin-reports', statusFilter],
    queryFn: async () => {
      const res = await base44.functions.invoke('adminGetReports', { status: statusFilter, limit: 100 });
      return res.data?.reports || [];
    },
    staleTime: 0,
  });

  const { data: deepLinkedData } = useQuery({
    queryKey: ['admin-report-deep', reportIdParam],
    queryFn: async () => {
      const res = await base44.functions.invoke('adminGetReports', { report_id: reportIdParam });
      return res.data?.reports || [];
    },
    enabled: !!reportIdParam,
    staleTime: 0,
  });

  const reports = reportsData || [];
  const allReports = useMemo(() => {
    if (!reportIdParam) return reports;
    const deep = (deepLinkedData || [])[0];
    if (!deep) return reports;
    return reports.some(r => r.id === deep.id) ? reports : [deep, ...reports];
  }, [reports, deepLinkedData, reportIdParam]);

  const selectedReport = allReports.find(r => r.id === selectedReportId) || null;

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {/* Header */}
      <div className="sticky top-0 bg-white/95 backdrop-blur-lg border-b border-slate-100 z-10">
        <div className="flex items-center gap-3 px-4 py-4">
          <AdminBackButton />
          <div>
            <h1 className="text-lg font-bold text-slate-900 flex items-center gap-2">
              Moderation Panel
              <span className="text-[10px] font-bold px-2 py-0.5 rounded-full bg-rose-100 text-rose-700 uppercase">Admin Only</span>
            </h1>
            <p className="text-xs text-slate-500">{allReports.length} {statusFilter.replace('_', ' ')} report{allReports.length !== 1 ? 's' : ''}</p>
          </div>
        </div>
      </div>

      <div className="px-4 py-4">
        {/* Status filter tabs */}
        <div className="flex gap-2 overflow-x-auto hide-scrollbar mb-4 pb-1">
          {['open', 'in_review', 'resolved', 'dismissed'].map(s => (
            <button key={s} onClick={() => setStatusFilter(s)}
              className={cn(
                'flex-shrink-0 px-4 py-2 rounded-full text-xs font-semibold capitalize transition-colors',
                statusFilter === s ? 'bg-slate-900 text-white' : 'bg-white border border-slate-200 text-slate-600 hover:bg-slate-50'
              )}>
              {s.replace('_', ' ')}
            </button>
          ))}
        </div>

        {/* Selected report detail */}
        {selectedReport && (
          <ReportDetail
            report={selectedReport}
            ctx={ctxParam}
            onDone={() => { refetch(); setSelectedReportId(null); }}
          />
        )}

        {/* Report list */}
        {isLoading ? (
          <div className="space-y-3">
            {[1, 2, 3].map(i => <div key={i} className="h-20 bg-white rounded-2xl border border-slate-200 animate-pulse" />)}
          </div>
        ) : allReports.length === 0 ? (
          <div className="text-center py-16">
            <Flag className="w-10 h-10 text-slate-300 mx-auto mb-3" />
            <p className="text-sm font-semibold text-slate-700">No {statusFilter.replace('_', ' ')} reports</p>
          </div>
        ) : (
          <div className="space-y-2">
            {allReports.map(report => (
              <ReportCard
                key={report.id}
                report={report}
                isSelected={selectedReportId === report.id}
                onClick={() => setSelectedReportId(selectedReportId === report.id ? null : report.id)}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default function AdminModerationPage() {
  return (
    <RequireAdmin>
      <AdminModerationContent />
    </RequireAdmin>
  );
}

