// --- Animated online counter ---
function OnlineCount({ count }) {
  const [display, setDisplay] = React.useState(count);
  const [animKey, setAnimKey] = React.useState(0);

  React.useEffect(() => {
    if (count !== display) {
      setDisplay(count);
      setAnimKey(k => k + 1);
    }
  }, [count]);

  const isOnline = display > 0;

  return (
    <div className={cn(
      "flex items-center gap-1.5 px-3 py-1.5 rounded-full transition-colors duration-500",
      isOnline ? "bg-green-50" : "bg-slate-100"
    )}>
      <motion.div
        animate={{ scale: isOnline ? [1, 1.3, 1] : 1 }}
        transition={{ duration: 0.4 }}
      >
        <Activity className={cn("w-3.5 h-3.5 transition-colors duration-500", isOnline ? "text-green-500" : "text-slate-400")} />
      </motion.div>
      <AnimatePresence mode="popLayout" initial={false}>
        <motion.span
          key={animKey}
          initial={{ opacity: 0, y: -8 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: 8 }}
          transition={{ duration: 0.25, ease: 'easeOut' }}
          className={cn("text-xs font-bold tabular-nums transition-colors duration-500", isOnline ? "text-green-600" : "text-slate-500")}
        >
          {display}
        </motion.span>
      </AnimatePresence>
    </div>
  );
}

