// --- Message Bubble (double-tap heart, long-press context menu, swipe timestamps) ---
function ChatBubble({ msg, isMe, onReply, allMessages, showAvatar = true, showName = true, showTimestamps = false, onDeleted, onEdited, onEditStart, blockedUserIds = new Set(), reactions = {}, onReaction, onReplyJump, highlightId, onOpenReactionsList, onNonMemberAction = null, t = (k, fallback) => fallback }) {
  const [heartAnim, setHeartAnim] = useState(false);
  const [contextMenu, setContextMenu] = useState(null);
  const longPressRef = React.useRef(null);
  const lastTapRef = React.useRef(0);
  const doubleTapCooldownRef = React.useRef(false); // prevent rapid-fire double taps
  const swipeStartRef = React.useRef(null);
  const [swipeOffset, setSwipeOffset] = useState(0);
  const isSwiping = React.useRef(false);

  const [showBlocked, setShowBlocked] = useState(false);
  const time = msg.created_at ? new Date(msg.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';
  const repliedMsg = msg.reply_to_id ? allMessages.find(m => m.id === msg.reply_to_id) : null;
  const isBlocked = !isMe && blockedUserIds.has(msg.sender_id);

  // Reactions — use parent reactionsMap (already optimistic from GroupDetailContent)
  const msgReactions = reactions[msg.id] || {};
  const reactionEntries = Object.entries(msgReactions);
  const isHighlighted = highlightId === msg.id;

  // Discord-style blocked message treatment
  if (isBlocked && !showBlocked) {
    return (
      <div className={cn("flex gap-1.5 mb-0.5 items-center", isMe ? "justify-end" : "justify-start")}>
        {!isMe && <div className="w-7" />}
        <div className="flex items-center gap-2 px-3 py-1.5 rounded-2xl bg-slate-100 border border-slate-200">
          <span className="text-xs text-slate-400 italic">{t('group.blocked_user','Blocked user')}</span>
          <button onClick={() => setShowBlocked(true)} className="text-[10px] text-indigo-500 font-semibold hover:underline">
            {t('group.see_message','See message')}
          </button>
        </div>
      </div>
    );
  }

  // ---- DOUBLE TAP = heart (instant, idempotent) ----
  const handleTap = (e) => {
    if (contextMenu) { setContextMenu(null); return; }
    const now = Date.now();
    if (now - lastTapRef.current < 350) {
      lastTapRef.current = 0;
      if (onNonMemberAction) { onNonMemberAction(); return; }
      // Prevent rapid-fire double taps
      if (doubleTapCooldownRef.current) return;
      doubleTapCooldownRef.current = true;
      setTimeout(() => { doubleTapCooldownRef.current = false; }, 500);

      // Instant heart animation (visual feedback at 0ms)
      setHeartAnim(true);
      setTimeout(() => setHeartAnim(false), 900);
      // Delegate to parent optimistic handler
      if (onReaction) onReaction(msg.id, '❤️');
    } else {
      lastTapRef.current = now;
    }
  };

  // ---- LONG PRESS = context menu ----
  const handleTouchStart = (e) => {
    const touch = e.touches[0];
    swipeStartRef.current = { x: touch.clientX, y: touch.clientY, time: Date.now() };
    isSwiping.current = false;

    longPressRef.current = setTimeout(() => {
      if (!isSwiping.current) {
        setContextMenu({ x: touch.clientX, y: touch.clientY });
      }
    }, 480);
  };

  const handleTouchMove = (e) => {
    if (!swipeStartRef.current) return;
    const dx = e.touches[0].clientX - swipeStartRef.current.x;
    const dy = e.touches[0].clientY - swipeStartRef.current.y;

    // Cancel long press if moved significantly
    if (Math.abs(dx) > 8 || Math.abs(dy) > 8) {
      clearTimeout(longPressRef.current);
    }
    // Horizontal swipe gesture for timestamp reveal
    if (Math.abs(dx) > Math.abs(dy) * 1.4 && Math.abs(dx) > 12) {
      isSwiping.current = true;
      const clamped = isMe
        ? Math.max(-72, Math.min(0, dx))
        : Math.max(0, Math.min(72, dx));
      setSwipeOffset(clamped);
    }
  };

  const handleTouchEnd = () => {
    clearTimeout(longPressRef.current);
    if (isSwiping.current) {
      setSwipeOffset(0);
    }
    isSwiping.current = false;
    swipeStartRef.current = null;
  };

  // Cleanup on unmount
  // eslint-disable-next-line react-hooks/rules-of-hooks
  React.useEffect(() => {
    return () => clearTimeout(longPressRef.current);
  }, []);

  // Swipe progress (0–1) for timestamp fade
  const swipeProgress = Math.abs(swipeOffset) / 72;

  return (
    <>
      <motion.div
        initial={{ opacity: 0, y: 6 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.15 }}
        className={cn("flex gap-1.5 mb-0.5 relative select-none", isMe ? "justify-end" : "justify-start")}
      >
        {/* Avatar column — top-aligned so it never floats to bottom beside tall media */}
        {!isMe && (
          <div className="flex flex-col justify-start flex-shrink-0 pt-0.5">
            {showAvatar ? (
              <UserProfileNavigator userId={msg.sender_id}>
                <AvatarWithFallback
                  avatarUrl={msg.sender_avatar_url}
                  name={msg.sender_name}
                  userId={msg.sender_id}
                />
              </UserProfileNavigator>
            ) : <div className="w-7" />}
          </div>
        )}

        <div
          className={cn("flex flex-col max-w-[75%]", isMe ? "items-end" : "items-start")}
          style={{
            transform: `translateX(${swipeOffset}px)`,
            transition: isSwiping.current ? 'none' : 'transform 0.28s cubic-bezier(0.25,0.46,0.45,0.94)',
          }}
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          onClick={handleTap}
        >
          {/* Sender name */}
          {!isMe && showName && (
            <UserProfileNavigator userId={msg.sender_id}>
              <button className="text-[11px] font-semibold text-slate-500 px-0.5 mb-0.5 hover:text-indigo-600 transition-colors">
                {msg.sender_name}
              </button>
            </UserProfileNavigator>
          )}

          {/* Reply preview — click to jump to original message */}
          {repliedMsg && (
            <button
              onClick={(e) => { e.stopPropagation(); if (onReplyJump) onReplyJump(repliedMsg.id); }}
              className={cn(
                "text-[10px] px-2.5 py-1.5 rounded-xl mb-1 border-l-2 max-w-[200px] text-left active:opacity-70 transition-opacity",
                isMe ? "bg-purple-100 border-purple-400 text-purple-700" : "bg-slate-100 border-indigo-300 text-slate-600"
              )}
            >
              <span className="font-bold block text-indigo-500">{repliedMsg.sender_name}</span>
              <span className="truncate block opacity-80">
                {repliedMsg.type === 'gif' ? '🎞 GIF' : repliedMsg.type === 'sticker' ? '🎨 Sticker' : repliedMsg.text || '...'}
              </span>
            </button>
          )}

          {/* The bubble itself — no overflow-hidden so reactions below are never clipped */}
          <div className="relative">
            {/* Highlight pulse for reply-jump target */}
            <AnimatePresence>
              {isHighlighted && (
                <motion.div
                  key="highlight"
                  initial={{ opacity: 0.7 }}
                  animate={{ opacity: [0.7, 0.4, 0] }}
                  transition={{ duration: 1.2, ease: 'easeOut' }}
                  className="absolute -inset-1 rounded-2xl pointer-events-none z-0"
                  style={{ background: 'rgba(99,102,241,0.25)', borderRadius: 18 }}
                />
              )}
            </AnimatePresence>

            <div
              className={cn(
                "text-sm leading-relaxed text-left relative z-10",
                isMe
                  ? "px-4 py-2.5 rounded-2xl rounded-br-md shadow-sm"
                  : "px-4 py-2.5 rounded-2xl rounded-bl-md bg-white border border-slate-100 shadow-sm text-slate-900",
                msg._failed && "opacity-60"
              )}
              style={isMe ? {
                background: 'linear-gradient(135deg, #7c3aed 0%, #6d28d9 50%, #5b21b6 100%)',
                color: 'white',
                boxShadow: '0 2px 12px rgba(109,40,217,0.3)',
              } : {}}
            >
              {msg.type === 'gif' ? (
                <div
                  onContextMenu={e => e.preventDefault()}
                  onDragStart={e => e.preventDefault()}
                  style={{ userSelect: 'none', WebkitUserSelect: 'none', WebkitTouchCallout: 'none' }}
                >
                  <img
                    src={msg.media_url}
                    alt="gif"
                    draggable={false}
                    className="rounded-xl max-w-[200px] max-h-[180px] object-cover"
                    style={{ pointerEvents: 'none', WebkitTouchCallout: 'none' }}
                    onError={e => { e.target.alt = 'GIF'; }}
                  />
                </div>
              ) : msg.type === 'sticker' ? (
                <div
                  onContextMenu={e => e.preventDefault()}
                  onDragStart={e => e.preventDefault()}
                  style={{ userSelect: 'none', WebkitUserSelect: 'none', WebkitTouchCallout: 'none' }}
                >
                  <img
                    src={msg.media_url}
                    alt="sticker"
                    draggable={false}
                    className="w-20 h-20 object-contain"
                    style={{ pointerEvents: 'none', WebkitTouchCallout: 'none' }}
                  />
                </div>
              ) : (
                // SYSTEM 4: Render @mentions as blue clickable links
                <MentionText text={msg.text} />
              )}
              {msg._failed && <span className="text-[10px] block mt-1 text-red-400">⚠ {t('group.failed_to_send','Failed to send')}</span>}
              {msg._status === 'pending' && !msg._failed && isMe && (
                <span className="text-[10px] block mt-0.5 opacity-40">{t('group.sending','sending…')}</span>
              )}
              {msg.is_edited && !msg._optimistic && (
                <span className="text-[9px] block mt-0.5 opacity-50 italic">{t('group.edited','edited')}</span>
              )}
            </div>

            {/* Double-tap heart burst */}
            <AnimatePresence>
              {heartAnim && (
                <motion.div
                  key="heart"
                  initial={{ scale: 0, opacity: 1, y: 0 }}
                  animate={{ scale: 1.6, opacity: 0, y: -28 }}
                  exit={{ opacity: 0 }}
                  transition={{ duration: 0.72, ease: [0.25, 0.46, 0.45, 0.94] }}
                  className="absolute inset-0 flex items-center justify-center pointer-events-none z-20"
                >
                  <span className="text-2xl drop-shadow-md">❤️</span>
                </motion.div>
              )}
            </AnimatePresence>
          </div>

          {/* Reactions — always visible below bubble, never resets, uses optimistic state */}
          {reactionEntries.length > 0 && (() => {
            const sorted = [...reactionEntries].sort((a, b) => (b[1].count || 1) - (a[1].count || 1));
            const topThree = sorted.slice(0, 3);
            const totalCount = reactionEntries.reduce((sum, [, d]) => sum + (d.count || 1), 0);
            // iReacted: check for both real userId and legacy '__me__' sentinel
            const iReacted = reactionEntries.some(([, d]) =>
              d.user_ids?.includes('__me__') || (msg._viewerUserId && d.user_ids?.includes(msg._viewerUserId))
            );

            return (
              <div className={cn("flex mt-1", isMe ? "justify-end" : "justify-start")}>
                <button
                  onClick={(e) => { e.stopPropagation(); if (onOpenReactionsList) onOpenReactionsList(msg.id); }}
                  className="flex items-center active:scale-95 transition-transform will-change-transform"
                  style={{
                    background: iReacted ? 'rgba(99,102,241,0.12)' : 'rgba(255,255,255,0.92)',
                    border: iReacted ? '1px solid rgba(99,102,241,0.3)' : '1px solid rgba(15,23,42,0.1)',
                    borderRadius: 999,
                    padding: '3px 8px 3px 4px',
                    boxShadow: '0 1px 6px rgba(0,0,0,0.10)',
                  }}
                >
                  <div className="flex items-center" style={{ marginRight: 4 }}>
                    {topThree.map(([emoji], i) => (
                      <div
                        key={emoji}
                        className="w-5 h-5 rounded-full flex items-center justify-center text-xs flex-shrink-0"
                        style={{
                          background: 'rgba(241,245,249,1)',
                          border: '1.5px solid rgba(255,255,255,0.9)',
                          marginLeft: i === 0 ? 0 : 2,
                          zIndex: topThree.length - i,
                          position: 'relative',
                          lineHeight: 1,
                        }}
                      >
                        {emoji}
                      </div>
                    ))}
                  </div>
                  <span className="text-xs font-bold tabular-nums" style={{ color: iReacted ? '#4f46e5' : '#475569' }}>
                    {totalCount > 1 ? totalCount : ''}
                  </span>
                </button>
              </div>
            );
          })()}
        </div>

        {/* Swipe-reveal timestamp — appears on left side for my messages, right for others */}
        <AnimatePresence>
          {(showTimestamps || swipeProgress > 0.15) && (
            <motion.span
              initial={{ opacity: 0 }}
              animate={{ opacity: showTimestamps ? 0.85 : swipeProgress }}
              exit={{ opacity: 0 }}
              transition={{ duration: 0.2 }}
              className={cn(
                "self-end mb-1 text-[10px] text-slate-400 whitespace-nowrap pointer-events-none flex-shrink-0",
                isMe ? "order-first mr-1" : "ml-1"
              )}
            >
              {time}
            </motion.span>
          )}
        </AnimatePresence>
      </motion.div>

      {/* Context menu overlay */}
      <AnimatePresence>
        {contextMenu && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 z-[190]"
              style={{ background: 'rgba(0,0,0,0.18)' }}
              onClick={() => setContextMenu(null)}
            />
            <MessageContextMenu
              msg={msg}
              isMe={isMe}
              position={contextMenu}
              onReply={onReply}
              onDismiss={() => setContextMenu(null)}
              onDeleted={onDeleted}
              onEdited={onEdited}
              onEditStart={onEditStart}
              onReaction={onReaction}
            />
          </>
        )}
      </AnimatePresence>
    </>
  );
}

