// Shows public user-authored recipes AND saved AI-generated recipes.
function RecipePicker({ onSelect, onClose, userId, t = (k, fallback) => fallback }) {
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!userId) return;
    // Include both: public user recipes + saved AI-generated recipes
    Promise.all([
      base44.entities.Recipe.filter({ author_id: userId, source: 'user', is_public: true }, '-created_date', 30).catch(() => []),
      base44.entities.Recipe.filter({ author_id: userId, source: 'generated', is_saved: true }, '-created_date', 20).catch(() => []),
    ]).then(([manual, generated]) => {
      const seen = new Set();
      const merged = [...manual, ...generated].filter(r => {
        if (seen.has(r.id)) return false;
        seen.add(r.id);
        return true;
      });
      setRecipes(merged);
    }).catch(() => setRecipes([]))
      .finally(() => setLoading(false));
  }, [userId]);

  if (loading) {
    return (
      <div className="space-y-2">
        {[1,2,3].map(i => <div key={i} className="h-16 rounded-2xl bg-slate-100 animate-pulse" />)}
      </div>
    );
  }

  if (recipes.length === 0) {
    return (
      <div className="text-center py-6">
        <ChefHat className="w-10 h-10 text-slate-300 mx-auto mb-2" />
        <p className="text-sm font-semibold text-slate-700 mb-1">{t('group.no_recipes_yet','No recipes yet')}</p>
        <p className="text-xs text-slate-400 mb-4">{t('group.no_recipes_desc','Publish a community recipe or save a generated recipe to share it in a group.')}</p>
        <button
          onClick={() => window.location.href = createPageUrl('PublishRecipe')}
          className="px-4 py-2 rounded-xl text-white text-sm font-bold"
          style={{ background: 'linear-gradient(135deg,#f97316,#ef4444)' }}
        >
          {t('group.upload_recipe','Upload a Recipe')}
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-2 max-h-56 overflow-y-auto">
      {recipes.map(r => (
        <button key={r.id} onClick={() => onSelect(r)}
          className="w-full flex items-center gap-3 p-3 rounded-2xl bg-slate-50 hover:bg-slate-100 transition-colors text-left">
          {r.hero_image_url && (
            <img src={r.hero_image_url} alt="" className="w-10 h-10 rounded-xl object-cover flex-shrink-0" />
          )}
          <span className="text-sm font-semibold text-slate-800 truncate">{r.title}</span>
        </button>
      ))}
    </div>
  );
}

