  const [showScrollBtn, setShowScrollBtn] = useState(false);
  const chatScrollRef = React.useRef(null); // ref for the messages scroll container

  // Edit mode: { msg } when user is editing a message
  const [editingMsg, setEditingMsg] = useState(null);
  // Reactions: { [messageId]: { [emoji]: { count, user_ids: string[] } } }
  // Canonical local state — patched optimistically, reconciled from backend in background
  const [reactionsMap, setReactionsMap] = useState({});
  // Reply-jump highlight: messageId to briefly highlight
  const [highlightMsgId, setHighlightMsgId] = useState(null);
  // Message DOM refs for reply-jump scroll
  const messageRefsMap = React.useRef({}); // { [msgId]: DOMElement }
  const [joinLoading, setJoinLoading] = useState(false);
  const [joinSuccess, setJoinSuccess] = useState(false);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);
  const lastSentRef = useRef({ text: '', timestamp: 0 }); // dedupe tracker
  const sendCooldownRef = useRef(false); // brief cooldown after any send

  // Hide bottom nav while in group detail (immersive) — MUST be before any conditional renders
  useEffect(() => {
    const nav = document.querySelector('[data-bottom-nav]');
    if (nav) nav.style.display = 'none';
    return () => { if (nav) nav.style.display = ''; };
  }, []);

  // Presence heartbeat while viewing group — immediately and every 30s
  useEffect(() => {
    if (!groupId || !user?.id) return;

    const sendHeartbeat = async () => {
      try {
        await base44.functions.invoke('updatePresence', { group_id: groupId });
      } catch (err) {
        console.warn('[GroupDetail] heartbeat failed', err.message);
      }
    };

    // Send immediately on mount — user appears online immediately
    sendHeartbeat();

    // Then every 60s during active session — reduced to avoid rate limiting
    const interval = setInterval(sendHeartbeat, 60000);

    // Stop on visibility change
    const handleVisibilityChange = () => {
      if (document.hidden) {
        clearInterval(interval);
      } else {
        sendHeartbeat();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      clearInterval(interval);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [groupId, user?.id]);

  // Load blocked users for Discord-style message treatment
  useEffect(() => {
    base44.auth.me().then(u => {
      if (!u?.id) return;
      base44.entities.BlockedUser.filter({ blocker_id: u.id }).then(list => {
        setBlockedUserIds(new Set(list.map(b => b.blocked_id)));
      }).catch(() => {});
    }).catch(() => {});
  }, []);

  useEffect(() => {
    console.log('[GroupDetail] mount');
    setUserLoading(true);
    base44.auth.me().then(u => {
      console.log('[GroupDetail] auth resolved', { userId: u?.id });
      setUser(u);
      setIsPro(!!u?.is_pro);
    }).catch(err => {
      console.error('[GroupDetail] auth failed', err.message);
    }).finally(() => {
      setUserLoading(false);
    });
  }, []);

  // Load members with presence — used by both initial load and sheet open.
  // CRITICAL: on error, ALWAYS preserve existing members list — never drop to 0.
  const loadMembers = useCallback(async ({ silent = false } = {}) => {
    if (!groupId) return;
    if (!silent) setMembersLoading(true);
    try {
      const result = await base44.functions.invoke('getGroupMembers', { group_id: groupId });
      const memberList = result.data?.members;
      if (Array.isArray(memberList) && memberList.length > 0) {
        const sorted = [...memberList].sort((a, b) => {
          const aOnline = a.is_online ? 1 : 0;
          const bOnline = b.is_online ? 1 : 0;
          if (aOnline !== bOnline) return bOnline - aOnline;
          const aTime = new Date(a.last_seen_at || 0).getTime();
          const bTime = new Date(b.last_seen_at || 0).getTime();
          return bTime - aTime;
        });
        setMembers(sorted);
      } else if (Array.isArray(memberList) && memberList.length === 0 && members.length === 0) {
        // Only set empty if we've never loaded anything — don't wipe a populated list
        setMembers([]);
      }
      // If memberList is undefined/null, keep previous state — don't wipe to []
    } catch {
      // On network error, ALWAYS preserve last known state — never reset to []
    } finally {
      if (!silent) setMembersLoading(false);
    }
  }, [groupId, members.length]);

  // VIEWER-SCOPED: key is stable per groupId+userId pair.
  // CRITICAL: we use a STABLE key per user so React Query's cache persists across unmount/remount.
  // placeholderData ensures the cached result is served immediately on remount — no skeleton flash.
  // enabled waits for user to resolve so we never fetch membership as 'anon'.
  const { data: groupDetail, isLoading: groupLoading, error: groupError, refetch: refetchGroup } = useQuery({
    queryKey: ['group-detail', groupId, user?.id],
    queryFn: async () => {
      if (!groupId) {
        const err = new Error('No group ID provided');
        err.code = 'NO_GROUP_ID';
        throw err;
      }
      const r = await base44.functions.invoke('getGroupDetail', { group_id: groupId });
      const d = r?.data;
      if (!d?.group) {
        const err = new Error(d?.error || 'Group not found');
        err.code = d?.code || 'NOT_FOUND';
        throw err;
      }
      return d;
    },
    // Only fetch once user is resolved — avoids 'anon' membership fetch
    enabled: !!groupId && !userLoading && !!user?.id,
    retry: (failureCount, error) => {
      const noRetry = ['NOT_FOUND', 'NO_GROUP_ID', 'FORBIDDEN'];
      if (noRetry.includes(error?.code)) return false;
      return failureCount < 2;
    },
    retryDelay: () => 500,
    // 5-minute stale time: membership cached in React Query persists across unmount/remount.
    // On route return, cache is served instantly (placeholderData), re-fetch runs in background.
    staleTime: 5 * 60 * 1000,
    // CRITICAL: serve cached data immediately on remount — membership never flips to null on return
    placeholderData: (prev) => prev,
  });

  // Defensive destructuring with safe defaults — MUST come before any effect that uses viewerIsMember
  const group = groupDetail?.group ?? null;
  // CRITICAL: membership is UNKNOWN (null) while loading — never default to false (non-member)
  // groupDetail exists if we have placeholder OR fresh data — only null means truly loading
  const membershipResolved = !!groupDetail;

  // STALE PROTECTION: derive membership from cache — React Query placeholderData means the cache
  // from the previous visit is served instantly on remount, so viewerIsMember is correct immediately.
  // We never default to false — null means "still loading" which shows a skeleton/pulse, not a gate.
  const viewerIsMember = membershipResolved ? (groupDetail?.viewer_is_member ?? false) : null;
  const viewerRole = groupDetail?.viewer_role ?? 'none';
  const viewerIsBanned = groupDetail?.viewer_is_banned ?? false;

  // Load members immediately on page open (so online count is correct from first render)
  useEffect(() => {
  if (!groupId || !user?.id || groupLoading) return;

  // Send heartbeat first so current user is already counted as online on first loadMembers
  base44.functions.invoke('updatePresence', { group_id: groupId }).catch(() => {});

  // Immediate load — then retry once after 5s
  loadMembers();
  const retryTimer = setTimeout(() => loadMembers({ silent: true }), 5000);

  // Poll every 30s — reduced from 10s to avoid rate limiting
  const interval = setInterval(() => loadMembers({ silent: true }), 30000);
  return () => {
    clearTimeout(retryTimer);
    clearInterval(interval);
  };
  }, [groupId, user?.id, groupLoading]);

  // STABILITY: track whether we've ever successfully loaded content — once true, never flash empty
  const messagesEverLoadedRef = React.useRef(false);
  const postsEverLoadedRef = React.useRef(false);

  const { data: messagesData, isLoading: messagesLoading, isFetched: messagesFetched } = useQuery({
    queryKey: ['group-messages', groupId],
    queryFn: async () => {
      try {
        const r = await base44.functions.invoke('groupChatGet', { group_id: groupId });
        const msgs = r?.data?.messages ?? [];
        if (msgs.length > 0) messagesEverLoadedRef.current = true;
        return msgs;
      } catch (err) {
        console.error('[GroupDetail] messages fetch failed', err.message);
        // Return undefined so react-query keeps the previous cache value intact
        return undefined;
      }
    },
    refetchInterval: 25000,
    enabled: !!groupId && membershipResolved && !!user?.id,
    staleTime: 20000,
    // CRITICAL: Keep previous data on every refetch — never flash empty during revalidation
    placeholderData: (prev) => prev,
  });

  const { data: posts, isLoading: postsLoading, isFetched: postsFetched, refetch: refetchPosts } = useQuery({
    queryKey: ['group-posts', groupId],
    queryFn: async () => {
      try {
        const result = await base44.entities.GroupPost.filter({ group_id: groupId }, '-created_date');
        if (!result) return undefined;
        // SYSTEM 5: Filter out removed/moderated posts — never show shells or default images
        const visible = result.filter(p =>
          p.moderation_status !== 'removed_by_moderation' &&
          p.moderation_status !== 'appealed' &&
          p.moderation_status !== 'pending_removal'
        );
        if (visible.length > 0) postsEverLoadedRef.current = true;
        return visible;
      } catch (err) {
        console.error('[GroupDetail] posts fetch failed', err.message);
        return undefined;
      }
    },
    refetchInterval: 30000,
    enabled: !!groupId && membershipResolved,
    staleTime: 20000,
    placeholderData: (prev) => prev,
  });

  // Fetch which posts the current viewer has liked — seeds correct initial liked state per card
  const { data: viewerPostLikes = [] } = useQuery({
    queryKey: ['group-post-likes-viewer', groupId, user?.id],
    queryFn: async () => {
      if (!user?.id) return [];
      try {
        return await base44.entities.GroupPostLike.filter({ user_id: user.id });
      } catch {
        return [];
      }
    },
    enabled: !!groupId && !!user?.id,
    staleTime: 60 * 1000,
  });
  const viewerLikedPostIds = new Set(viewerPostLikes.map(l => l.group_post_id));

  // Defensive array handling — safe defaults, never undefined
  const messagesArray = Array.isArray(messagesData) ? messagesData : [];
  const postsArray = Array.isArray(posts) ? posts : [];
  // Update "ever loaded" refs on each render (handles case where data comes from placeholderData)
  if (messagesArray.length > 0) messagesEverLoadedRef.current = true;
  if (postsArray.length > 0) postsEverLoadedRef.current = true;

  // CANONICAL RECONCILIATION: Only remove an optimistic message when we have explicit confirmation:
  // 1. The backend echoed back the _optimisticId on the returned message (primary/deterministic)
  // 2. The optimistic was explicitly cleared by the send success handler (setOptimisticMessages filter)
  // We do NOT use content-matching as a fallback — it is too aggressive and causes messages to
  // disappear when a user sends the same text twice, or when a refetch returns before the
  // optimistic is cleared by the success handler.
  const serverOptimisticIds = new Set(
    messagesArray.map(m => m?._optimisticId).filter(Boolean)
  );
  const pendingOptimistic = optimisticMessages.filter(m => {
    // Always keep failed optimistics so user sees the error state
    if (m._failed === true) return true;
    // Remove only if server explicitly echoed this optimisticId back
    if (m._optimisticId && serverOptimisticIds.has(m._optimisticId)) return false;
    // Otherwise keep — the send handler will clear it after the background refetch
    return true;
  });
  const allMessages = [...messagesArray, ...pendingOptimistic];

  // (reconciliation + render logs removed — were firing on every 3s poll cycle)

  // Auto-scroll: instant on first load, smooth for new messages
  const isInitialLoadRef = React.useRef(true);
  const prevLengthRef = React.useRef(0);

  useEffect(() => {
    if (isInitialLoadRef.current && allMessages.length > 0) {
      // Instant scroll to bottom on first load — no "second of no messages"
      isInitialLoadRef.current = false;
      prevLengthRef.current = allMessages.length;
      setTimeout(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'instant' });
      }, 0);
      return;
    }
    if (allMessages.length > prevLengthRef.current) {
      // Only auto-scroll if already near bottom
      const el = chatScrollRef.current;
      if (el) {
        const distFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;
        if (distFromBottom < 120) {
          messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
        }
      } else {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
      }
    }
    prevLengthRef.current = allMessages.length;
  }, [allMessages.length]);

  // ─── REACTIONS: OPTIMISTIC LOCAL STATE ────────────────────────────────────
  // Never wipe local state — only merge. Backend poll is reconciliation only.
  const reactionsDebounceRef = React.useRef(null);
  const reactionToggleTimeRef = React.useRef({});
  const lastOptimisticWriteRef = React.useRef(0);

  const fetchReactionsSilent = React.useCallback(async () => {
    if (!groupId) return;
    try {
      const res = await base44.functions.invoke('getGroupMessageReactions', { group_id: groupId });
      if (res?.data?.reactions) {
        const serverMap = res.data.reactions;
        const timeSinceWrite = Date.now() - lastOptimisticWriteRef.current;
        setReactionsMap(prev => {
          // PROTECTION: If optimistic write happened <3s ago, skip server overwrite
          if (timeSinceWrite < 3000) return prev;
          const merged = {};
          Object.entries(serverMap).forEach(([k, v]) => { merged[k] = v; });
          Object.entries(prev).forEach(([k, v]) => { if (!(k in serverMap)) merged[k] = v; });
          return merged;
        });
      }
    } catch {
      // Silent fail — existing optimistic state preserved
    }
  }, [groupId]);

  useEffect(() => {
    if (!groupId) return;
    fetchReactionsSilent();
    const interval = setInterval(fetchReactionsSilent, 30000);
    const debouncedSync = () => {
      clearTimeout(reactionsDebounceRef.current);
      reactionsDebounceRef.current = setTimeout(fetchReactionsSilent, 2500);
    };
    const unsubReactions = base44.entities.MessageReaction.subscribe(debouncedSync);
    return () => {
      clearInterval(interval);
      clearTimeout(reactionsDebounceRef.current);
      unsubReactions();
    };
  }, [groupId, fetchReactionsSilent]);

  // Optimistic reaction toggle — instant UI (0ms), backend async, rollback only on error
  const handleOptimisticReaction = React.useCallback((messageId, emoji) => {
    if (!messageId || !emoji || !user?.id) return;
    const key = `${messageId}:${emoji}`;
    const now = Date.now();
    if ((reactionToggleTimeRef.current[key] || 0) > now - 400) return; // 400ms debounce
    reactionToggleTimeRef.current[key] = now;
    lastOptimisticWriteRef.current = now;

    const myId = user.id;

    // INSTANT local update — no await, no spinner
    setReactionsMap(prev => {
      const msgReactions = { ...(prev[messageId] || {}) };
      const existing = msgReactions[emoji];
      const alreadyReacted = existing?.user_ids?.includes(myId) || existing?.user_ids?.includes('__me__');
      if (alreadyReacted) {
        const newIds = (existing.user_ids || []).filter(id => id !== myId && id !== '__me__');
        const newCount = Math.max(0, (existing.count || 1) - 1);
        if (newCount === 0) {
          delete msgReactions[emoji];
        } else {
          msgReactions[emoji] = { ...existing, count: newCount, user_ids: newIds };
        }
      } else {
        msgReactions[emoji] = {
          count: (existing?.count || 0) + 1,
          user_ids: [...(existing?.user_ids || []), myId],
        };
      }
      return { ...prev, [messageId]: msgReactions };
    });

    // Backend async — deferred reconciliation after protection window
    base44.functions.invoke('messageReactionToggle', { message_id: messageId, emoji })
      .then(() => setTimeout(fetchReactionsSilent, 3500))
      .catch(() => setTimeout(fetchReactionsSilent, 3500));
  }, [user?.id, fetchReactionsSilent]);

  // Reply jump: scroll to message and highlight it
  const handleReplyJump = React.useCallback((targetMsgId) => {
    const el = messageRefsMap.current[targetMsgId];
    if (el) {
      el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      setHighlightMsgId(targetMsgId);
      setTimeout(() => setHighlightMsgId(null), 1400);
    }
  }, []);

  // Handle edit save — called when user submits while in edit mode
  const handleEditSave = async () => {
    if (!editingMsg || !messageText.trim() || messageSending) return;
    setMessageSending(true);
    const newText = messageText.trim();
    try {
      // Optimistic update
      queryClient.setQueryData(['group-messages', groupId], (old) =>
        Array.isArray(old) ? old.map(m => m.id === editingMsg.id ? { ...m, text: newText, is_edited: true } : m) : old
      );
      setMessageText('');
      setEditingMsg(null);
      await base44.functions.invoke('editGroupMessage', { message_id: editingMsg.id, text: newText });
    } catch (e) {
      console.warn('[GroupDetail] edit save failed', e.message);
    } finally {
      setMessageSending(false);
    }
  };

  const handleSendMessage = async (e) => {
    e?.preventDefault();
    // If in edit mode, save the edit instead
    if (editingMsg) {
      handleEditSave();
      return;
    }
    // CRITICAL: Do not allow send before user auth is fully resolved
    if (!user?.id) {
      console.warn('[GroupDetail] handleSendMessage: user not yet resolved, aborting');
      return;
    }
    if (viewerIsMember === false) {
      setShowNonMemberModal(true);
      return;
    }
    const text = messageText.trim();
    if (!text || messageSending) return;

    // Client-side cooldown — blocks spam Enter/send icon presses
    if (sendCooldownRef.current) return;

    // Client-side duplicate detection: same text within 3 seconds
    const now = Date.now();
    if (
      lastSentRef.current.text === text &&
      now - lastSentRef.current.timestamp < 3000
    ) return;

    // Paused users cannot send messages
    if (user?.account_status === 'paused') {
      setShowPauseGate(true);
      return;
    }

    const optimisticId = `opt_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    const sentAtTimestamp = new Date().toISOString();

    const optimistic = {
      id: optimisticId, // Use optimisticId as the client ID
      text,
      type: 'text',
      sender_id: user?.id,
      sender_name: user?.full_name || 'You',
      sender_avatar_url: user?.avatar_url || '',
      created_at: sentAtTimestamp,
      reply_to_id: replyingTo?.id || null,
      group_id: groupId,
      _optimistic: true,
      _optimisticId: optimisticId, // Marker for reconciliation with server message
      _status: 'pending',
    };

    setOptimisticMessages(prev => [...prev, optimistic]);
    setMessageText('');
    setReplyingTo(null);
    setMessageError('');
    setMessageSending(true);

    // Engage cooldown + record this send for deduplication
    sendCooldownRef.current = true;
    lastSentRef.current = { text, timestamp: Date.now() };
    setTimeout(() => { sendCooldownRef.current = false; }, 50);

    try {
      const res = await base44.functions.invoke('groupMessageSend', {
        group_id: groupId, type: 'text', text,
        reply_to_id: replyingTo?.id || null,
        _optimisticId: optimisticId, // Pass marker so backend can return it
      });
      const d = res?.data;

      if (!d?.ok) {
        // Real error from server
        const errorMessages = {
          CONTENT_NOT_ALLOWED: t('group.err.content_not_allowed','Message blocked — please edit your content.'),
          NOT_GROUP_MEMBER: t('group.err.not_member','You are not a member of this group.'),
          AUTH_REQUIRED: t('group.err.auth_required','Please log in again.'),
          INTERNAL_SERVER_ERROR: t('group.err.server_error_body','Something went wrong on our end. Please try again later.'),
        };
        const msg = errorMessages[d?.error_code] || d?.error || t('group.err.failed_send','Failed to send.');
        setOptimisticMessages(prev => prev.map(m => m._optimisticId === optimisticId ? { ...m, _failed: true, _status: 'failed' } : m));
        setMessageError(msg);
        setTimeout(() => setMessageError(''), 5000);
      } else {
        // Success (including duplicate=true case — message accepted or already exists)
        setOptimisticMessages(prev => prev.map(m => m._optimisticId === optimisticId ? { ...m, _status: 'sent' } : m));
        // Refetch in background — always remove the optimistic regardless of refetch outcome
        base44.functions.invoke('groupChatGet', { group_id: groupId }).then(refreshRes => {
          const freshMessages = refreshRes?.data?.messages ?? [];
          queryClient.setQueryData(['group-messages', groupId], freshMessages);
        }).catch(refetchErr => {
          console.warn('[GroupDetail] background refetch failed (message was sent ok)', refetchErr.message);
          queryClient.invalidateQueries({ queryKey: ['group-messages', groupId] });
        }).finally(() => {
          // ALWAYS remove the optimistic after send success — even if refetch fails
          setOptimisticMessages(prev => prev.filter(m => m._optimisticId !== optimisticId));
        });
      }
    } catch (err) {
      const serverData = err.response?.data;
      const errorCode = serverData?.error_code;
      const errMap = {
        CONTENT_NOT_ALLOWED: t('group.err.content_not_allowed','Message blocked — please edit your content.'),
        NOT_GROUP_MEMBER: t('group.err.not_member','You are not a member of this group.'),
        AUTH_REQUIRED: t('group.err.auth_required','Please log in again.'),
        INTERNAL_SERVER_ERROR: t('group.err.server_error_body','Something went wrong on our end. Please try again later.'),
      };
      const msg = errMap[errorCode] || serverData?.error || err.message || t('group.err.failed_send','Failed to send.');
      setOptimisticMessages(prev => prev.map(m => m._optimisticId === optimisticId ? { ...m, _failed: true, _status: 'failed' } : m));
      setMessageError(msg);
      setTimeout(() => setMessageError(''), 5000);
    } finally {
      setMessageSending(false);
    }
  };

  const handleSendMedia = async (media) => {
    setShowGifPicker(false);
    if (!viewerIsMember || !user) return;

    const optimisticId = `opt_media_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    const optimistic = {
      id: optimisticId,
      media_url: media.media_url,
      media_width: media.media_width,
      media_height: media.media_height,
      type: media.type, // 'gif' or 'sticker'
      sender_id: user.id,
      sender_name: user.full_name || 'You',
      sender_avatar_url: user.avatar_url || '',
      created_at: new Date().toISOString(),
      _optimistic: true,
      _optimisticId: optimisticId, // Marker for reconciliation
      _status: 'pending',
    };
    setOptimisticMessages(prev => [...prev, optimistic]);

    try {
      const res = await base44.functions.invoke('groupMessageSend', {
        group_id: groupId,
        type: media.type,
        media_url: media.media_url,
        media_width: media.media_width,
        media_height: media.media_height,
        _optimisticId: optimisticId, // Pass marker so backend can return it
      });
      const d = res?.data;
      if (!d?.ok && d?.error_code) {
        setOptimisticMessages(prev => prev.map(m => m._optimisticId === optimisticId ? { ...m, _failed: true, _status: 'failed' } : m));
        return;
      }

      // Success — refetch in background, always remove optimistic
       setOptimisticMessages(prev => prev.map(m => m._optimisticId === optimisticId ? { ...m, _status: 'sent' } : m));
       base44.functions.invoke('groupChatGet', { group_id: groupId }).then(refreshRes => {
         const freshMessages = refreshRes?.data?.messages ?? [];
         queryClient.setQueryData(['group-messages', groupId], freshMessages);
       }).catch(() => {
         queryClient.invalidateQueries({ queryKey: ['group-messages', groupId] });
       }).finally(() => {
         setOptimisticMessages(prev => prev.filter(m => m._optimisticId !== optimisticId));
       });
    } catch (err) {
      setOptimisticMessages(prev => prev.map(m => m._optimisticId === optimisticId ? { ...m, _failed: true, _status: 'failed' } : m));
    }
  };

  const handleJoin = async () => {
    setJoinLoading(true);
    try {
      const response = await base44.functions.invoke('groupJoin', { group_id: groupId });
      setJoinSuccess(true);
      // Refetch group detail (viewer-scoped) so viewer_is_member updates immediately
      refetchGroup();
      // Invalidate viewer-scoped group lists and memberships so Community tab reflects join
      queryClient.invalidateQueries({ queryKey: ['group-memberships', user?.id] });
      queryClient.invalidateQueries({ queryKey: ['groups', user?.id] });
      queryClient.invalidateQueries({ queryKey: ['group-messages', groupId] });
      queryClient.invalidateQueries({ queryKey: ['group-posts', groupId] });
      // Reload members + reactions immediately after joining
      loadMembers();
      fetchReactionsSilent();
      // Close modal after success animation
      setTimeout(() => {
        setShowNonMemberModal(false);
        setJoinSuccess(false);
        setJoinLoading(false);
      }, 1800);
    } catch (err) {
      console.error('[GroupDetail] join failed', err.message);
      setMessageError(t('community.failed_join_group','Failed to join group. Please try again.'));
      setJoinLoading(false);
    }
  };

  const handleCreatePost = async () => {
    if (viewerIsMember === false) {
      setShowNonMemberModal(true);
      return;
    }
    if (!selectedRecipe) { setPostError(t('group.select_recipe_error','Please select a recipe to share.')); return; }

    // Paused users cannot post
    if (user?.account_status === 'paused') {
      setShowPauseGate(true);
      return;
    }

    setPostSending(true);
    setPostError('');
    try {
      const res = await base44.functions.invoke('groupPostCreate', {
        group_id: groupId,
        content: postCaption,
        recipe_id: selectedRecipe.id,
        media_url: selectedRecipe.hero_image_url || null,
      });
      const d = res.data;
      if (d?.error_code === 'NOT_PRO') { setPostError(t('group.err.not_pro','Posting requires Reciply Pro.')); return; }
      if (d?.error_code === 'COOLDOWN') { const mins = Math.ceil((d.remaining_seconds || 0) / 60); setPostError(t('group.err.cooldown_active',`Cooldown active. Wait ${mins} min.`)); return; }
      if (d?.error_code === 'CONTENT_NOT_ALLOWED') { setPostError(t('group.err.content_not_allowed','Please edit your message — some content was flagged.')); return; }
      setPostCaption('');
      setSelectedRecipe(null);
      setShowPostComposer(false);
      queryClient.invalidateQueries({ queryKey: ['group-posts', groupId] });
    } catch {
      setPostError(t('group.err.failed_post','Failed to post. Please try again.'));
    } finally {
      setPostSending(false);
    }
  };

  // Navigate to the next unread mention in the chat
  const handleGoToNextMention = React.useCallback(() => {
    if (mentionPopup?.message_id) {
      const elem = document.getElementById(`message-${mentionPopup.message_id}`);
      if (elem) {
        elem.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
    }
    setMentionPopup(null);
  }, [mentionPopup]);

  // --- Early guards ---
  // Show skeleton ONLY when: user auth is loading, OR group query has NO data at all yet.
  // With placeholderData, returning members will have groupDetail immediately — no skeleton.
  // viewerIsMember===null only when there's truly no data (first ever visit or cold load).
  const isBootstrapping = userLoading || (!!groupId && !!user?.id && !groupDetail && groupLoading);

  if (!groupId) {
    console.log('[GroupDetail] no groupId in URL');
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center gap-4 p-6">
        <div className="w-16 h-16 rounded-2xl bg-blue-100 flex items-center justify-center mb-2">
          <Users className="w-8 h-8 text-blue-600" />
        </div>
        <h1 className="text-lg font-bold text-slate-900">{t('group.not_found','Group not found')}</h1>
        <p className="text-sm text-slate-500 text-center max-w-sm">{t('group.invalid_link','Invalid or missing group link')}</p>
        <button
          onClick={() => window.history.length > 1 ? navigate(-1) : window.location.href = createPageUrl('Home')}
          className="h-11 px-6 rounded-2xl bg-indigo-600 hover:bg-indigo-700 text-white font-semibold text-sm transition-colors flex items-center gap-2"
        >
          <ArrowLeft className="w-4 h-4" /> {t('action.go_back','Go Back')}
        </button>
      </div>
    );
  }

  if (isBootstrapping) {
    return <GroupSkeleton />;
  }

  // Banned user — show blocked state
  if (viewerIsBanned) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center gap-4">
        <div className="w-16 h-16 rounded-2xl bg-rose-100 flex items-center justify-center">
          <UserX className="w-8 h-8 text-rose-500" />
        </div>
        <h2 className="text-lg font-bold text-slate-900">{t('group.banned_title',"You've been banned")}</h2>
        <p className="text-sm text-slate-500 max-w-xs">{t('group.banned_desc','You no longer have access to this group.')}</p>
        <button onClick={() => window.history.back()} className="h-11 px-6 rounded-2xl bg-slate-100 text-slate-700 font-semibold text-sm">{t('action.go_back','Go Back')}</button>
      </div>
    );
  }

  // Only show error when:
  // 1. Bootstrap is complete (not in flight)
  // 2. NO group data after successful resolve
  // 3. Actual error code (not transient loading state)
  // NEVER show error during initial fetch or stale retries
  if (!isBootstrapping && !group && groupError && groupError.code) {
    const errorCode = groupError?.code;
    console.error('[GroupDetail] Load failed', { groupId, code: errorCode, message: groupError?.message });

    const errorConfig = {
      NO_GROUP_ID:           { title: t('group.err.invalid_link','Invalid link'),            body: t('group.err.invalid_link_body','Invalid or missing group link.'),                          retry: false },
      NOT_FOUND:             { title: t('group.err.not_found','Group not found'),         body: t('group.err.not_found_body','This group does not exist or has been deleted.'),          retry: false },
      FORBIDDEN:             { title: t('group.err.access_denied','Access denied'),           body: t('group.err.access_denied_body',"You don't have permission to view this group."),           retry: false },
      INTERNAL_SERVER_ERROR: { title: t('group.err.server_error','Server error'),            body: t('group.err.server_error_body','Something went wrong on our end. Please try again later.'), retry: true  },
    };
    const cfg = errorConfig[errorCode] || { title: t('group.err.load_failed',"Couldn't load group"), body: t('group.err.load_failed_body','Please try again or check your connection.'), retry: true };

    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center gap-4 p-6">
        <div className="w-16 h-16 rounded-2xl bg-slate-100 flex items-center justify-center mb-2">
          <Users className="w-8 h-8 text-slate-400" />
        </div>
        <h1 className="text-lg font-bold text-slate-900">{cfg.title}</h1>
        <p className="text-sm text-slate-500 text-center max-w-sm">{cfg.body}</p>
        <div className="flex gap-3 mt-4 w-full max-w-xs">
          {cfg.retry && (
            <button
              onClick={() => refetchGroup()}
              className="flex-1 h-11 rounded-2xl border border-slate-200 hover:border-slate-300 text-slate-700 font-semibold text-sm flex items-center justify-center gap-2"
            >
              <RefreshCw className="w-4 h-4" /> {t('action.retry','Retry')}
            </button>
          )}
          <button
            onClick={() => window.history.length > 1 ? navigate(-1) : window.location.href = createPageUrl('Home')}
            className="flex-1 h-11 rounded-2xl bg-indigo-600 hover:bg-indigo-700 text-white font-semibold text-sm flex items-center justify-center gap-2"
          >
            <ArrowLeft className="w-4 h-4" /> {t('action.back','Back')}
          </button>
        </div>
      </div>
    );
  }

  // Paused user: show gate modal
  if (user?.account_status === 'paused' && showPauseGate) {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center p-6 z-50">
        <div className="flex flex-col items-center gap-4 max-w-sm text-center rounded-3xl p-8" style={{ background: 'rgba(59,130,246,0.08)' }}>
          <div className="w-16 h-16 rounded-2xl bg-blue-100 flex items-center justify-center">
            <Clock className="w-8 h-8 text-blue-600" />
          </div>
          <h3 className="text-lg font-bold text-slate-900">{t('group.paused_title','Your account is paused')}</h3>
          <p className="text-sm text-slate-600">{t('group.paused_desc','You can preview this group but cannot interact while paused. Reactivate your account to participate.')}</p>
          <button
            onClick={() => window.location.href = createPageUrl('DangerZone')}
            className="w-full h-11 rounded-2xl bg-blue-600 hover:bg-blue-700 text-white font-semibold text-sm transition-colors"
          >
            {t('group.reactivate_account','Reactivate Account')}
          </button>
          <button
            onClick={() => setShowPauseGate(false)}
            className="w-full h-10 rounded-2xl bg-slate-100 hover:bg-slate-200 text-slate-700 font-medium text-sm transition-colors"
          >
            {t('group.continue_browsing','Continue Browsing')}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="fixed inset-0 bg-slate-50 flex flex-col overflow-hidden" style={{ zIndex: 10, paddingTop: 'env(safe-area-inset-top, 0px)', paddingBottom: 'env(safe-area-inset-bottom, 0px)', paddingLeft: 'env(safe-area-inset-left, 0px)', paddingRight: 'env(safe-area-inset-right, 0px)' }}>
      {/* Fixed header — no scroll */}
      <div className="sticky top-0 z-40 bg-white border-b border-slate-100 shadow-sm flex-shrink-0">
        <div className="flex items-center px-4 py-3 gap-2 min-h-16">
          <button 
            onClick={() => {
              if (window.history.length > 1) {
                navigate(-1);
              } else {
                window.location.href = createPageUrl('Home');
              }
            }}
            className="w-9 h-9 rounded-full bg-slate-100 flex items-center justify-center flex-shrink-0 hover:bg-slate-200 transition-colors"
          >
            <ArrowLeft className="w-4 h-4 text-slate-700" />
          </button>
          <button
            onClick={() => { if (group?.group_type === 'friends_chat') window.location.href = createPageUrl('FriendsGroupSettings') + `?id=${groupId}`; else window.location.href = createPageUrl('GroupHub') + `?id=${groupId}`; }}
            className="flex items-center gap-2 flex-1 min-w-0 text-left group"
          >
            <div className="w-9 h-9 rounded-xl flex items-center justify-center text-base flex-shrink-0 transition-opacity group-hover:opacity-70 overflow-hidden" style={{ background: (group?.logo_url || group?.cover_image_url) ? '#f8fafc' : group?.cover_color ? `${group.cover_color}22` : 'linear-gradient(135deg,#6366f1,#8b5cf6)' }}>
              {group?.logo_url ? <img src={group.logo_url} alt="" className="w-full h-full object-cover" /> : group?.cover_image_url ? <img src={group.cover_image_url} alt="" className="w-full h-full object-cover" /> : group?.cover_emoji ? <span>{group.cover_emoji}</span> : <Users className="w-5 h-5 text-white" />}
            </div>
            <div className="min-w-0">
              <h1 className="text-sm font-bold text-slate-900 truncate transition-opacity group-hover:opacity-70">{group?.name || 'Group'}</h1>
              <p className="text-[10px] text-slate-400">{group?.group_type === 'friends_chat' ? '💬 Friends · ' : ''}{group?.member_count || 0} {t('community.members','members')}</p>
            </div>
          </button>
          <ReciplyShareIcon size={16} className="text-indigo-600" onClick={() => setShowGroupShareSheet(true)} />
          <MentionPingBadgeHeader count={pingCount} onClick={handleGoToNextMention} />
          <button
            onClick={() => {
              setShowMemberList(true);
            }}
            className="flex items-center gap-1.5 flex-shrink-0"
          >
            <div className={`flex items-center gap-1 px-2.5 py-1.5 rounded-full ${members.filter(m => m.is_online).length > 0 ? 'bg-green-50' : 'bg-slate-100'}`}>
              <Users className={`w-4 h-4 ${members.filter(m => m.is_online).length > 0 ? 'text-green-600' : 'text-slate-500'}`} />
              <span className={`text-[10px] font-bold ${members.filter(m => m.is_online).length > 0 ? 'text-green-700' : 'text-slate-600'}`}>{group?.member_count || 0}</span>
            </div>
            <OnlineCount count={members.filter(m => m.is_online).length} />
          </button>
        </div>
        {/* Tabs — compact */}
        <div className="flex px-4 gap-1 border-t border-slate-100 bg-slate-50">
          {[{key:'chat', labelKey:'group.tab_chat', fallback:'Chat'},{key:'posts', labelKey:'group.tab_posts', fallback:'Posts'}].map(tabDef => (
            <button key={tabDef.key} onClick={() => setTab(tabDef.key)}
              className={cn("flex-1 py-2 text-xs font-semibold capitalize relative transition-colors", tab === tabDef.key ? "text-indigo-600" : "text-slate-400")}
            >
              {t(tabDef.labelKey, tabDef.fallback)}
              {tab === tabDef.key && <motion.div layoutId="tab-indicator" className="absolute bottom-0 left-2 right-2 h-0.5 bg-indigo-600 rounded-full" />}
            </button>
          ))}
        </div>
      </div>

      {/* Content — flex-1 takes all remaining height, only this scrolls */}
      <AnimatePresence mode="wait">
        {tab === 'chat' ? (
          <motion.div key="chat" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="flex-1 flex flex-col min-h-0 overflow-hidden">
            {/* Messages — scrollable only; horizontal swipe on right half reveals timestamps */}
            <div
              ref={chatScrollRef}
              className="flex-1 overflow-y-auto overscroll-contain px-4 py-4 min-h-0 relative"
              onScroll={(e) => {
                const el = e.currentTarget;
                const distFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;
                setShowScrollBtn(distFromBottom > 80);
              }}
              onTouchStart={(e) => {
                const touch = e.touches[0];
                swipePanStartRef.current = { x: touch.clientX, y: touch.clientY };
              }}
              onTouchMove={(e) => {
                if (!swipePanStartRef.current) return;
                const dx = e.touches[0].clientX - swipePanStartRef.current.x;
                const dy = e.touches[0].clientY - swipePanStartRef.current.y;
                if (Math.abs(dx) > Math.abs(dy) * 1.2 && dx > 24) {
                  if (!showTimestampsRef.current) {
                    showTimestampsRef.current = true;
                    setShowTimestamps(true);
                  }
                }
              }}
              onTouchEnd={() => {
                swipePanStartRef.current = null;
                if (showTimestampsRef.current) {
                  setTimeout(() => { showTimestampsRef.current = false; setShowTimestamps(false); }, 1800);
                }
              }}
            >
              {/* SKELETON: show while loading OR before first fetch completes — never show empty state prematurely */}
              {(messagesLoading || !messagesFetched || !membershipResolved) && allMessages.length === 0 ? (
                <div className="space-y-4 pt-2">
                  {[1,2,3,4,5].map(i => (
                    <div key={i} className={`flex gap-2 ${i % 2 === 0 ? 'justify-end' : 'justify-start'}`}>
                      {i % 2 !== 0 && <div className="w-7 h-7 rounded-full bg-slate-200 animate-pulse flex-shrink-0" />}
                      <div className={`h-10 rounded-2xl animate-pulse bg-slate-200 ${i % 2 === 0 ? 'w-36' : 'w-52'}`} />
                    </div>
                  ))}
                </div>
              ) : allMessages.length === 0 && messagesFetched && !messagesLoading && !messagesEverLoadedRef.current ? (
                <div className="flex flex-col items-center justify-center h-full gap-3 pb-8">
                  <div className="w-14 h-14 rounded-2xl bg-slate-100 flex items-center justify-center">
                    <MessageCircle className="w-7 h-7 text-slate-300" />
                  </div>
                  <p className="text-sm font-semibold text-slate-500">{t('group.no_messages','No messages yet')}</p>
                  <p className="text-xs text-slate-400">{t('group.say_hello','Say hello to the group!')}</p>
                </div>
              ) : (
                <>
                  {Array.isArray(allMessages) && allMessages.map((msg, idx) => {
                    if (!msg || typeof msg !== 'object' || !msg.id) {
                      console.warn('[GroupDetail] invalid message object', msg);
                      return null;
                    }
                    const isMe = msg.sender_id === user?.id;
                    const prevMsg = allMessages[idx - 1];
                    const nextMsg = allMessages[idx + 1];
                    const isLastInRun = !nextMsg || nextMsg.sender_id !== msg.sender_id;
                    const isFirstInRun = !prevMsg || prevMsg.sender_id !== msg.sender_id;
                    return (
                      <div
                        key={msg.id}
                        id={`message-${msg.id}`}
                        ref={el => { if (el) messageRefsMap.current[msg.id] = el; else delete messageRefsMap.current[msg.id]; }}
                      >
                        <ChatBubble
                          msg={msg}
                          isMe={isMe}
                          onReply={setReplyingTo}
                          allMessages={allMessages}
                          showAvatar={!isMe && isLastInRun}
                          showName={!isMe && isFirstInRun}
                          showTimestamps={showTimestamps}
                          blockedUserIds={blockedUserIds}
                          reactions={reactionsMap}
                          onReaction={handleOptimisticReaction}
                          onReplyJump={handleReplyJump}
                          highlightId={highlightMsgId}
                          onOpenReactionsList={setShowReactionsList}
                          t={t}
                          onNonMemberAction={viewerIsMember === false ? () => setShowNonMemberModal(true) : null}
                          onEditStart={(msg) => {
                           setEditingMsg(msg);
                           setMessageText(msg.text || '');
                           setTimeout(() => inputRef.current?.focus(), 50);
                          }}
                          onDeleted={(id) => {
                            setOptimisticMessages(prev => prev.filter(m => m.id !== id));
                            queryClient.setQueryData(['group-messages', groupId], (old) => (Array.isArray(old) ? old.filter(m => m.id !== id) : old));
                          }}
                          onEdited={(id, newText) => {
                            queryClient.setQueryData(['group-messages', groupId], (old) => (Array.isArray(old) ? old.map(m => m.id === id ? { ...m, text: newText, is_edited: true } : m) : old));
                          }}
                        />
                      </div>
                    );
                  })}
                  <div ref={messagesEndRef} />
                </>
              )}

              {/* Mention popup — floats inside scroll area */}
              <MentionPopupNotification
                mention={mentionPopup}
                onDismiss={() => setMentionPopup(null)}
                onScrollTo={handleGoToNextMention}
              />
              {/* Scroll to bottom button */}
              <ScrollToBottomButton
                visible={showScrollBtn}
                onClick={() => messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })}
              />
            </div>

            {messageError && <div className="px-4 py-1 bg-red-50 text-red-500 text-xs text-center">{messageError}</div>}

            {/* Reply preview bar */}
            <AnimatePresence>
              {replyingTo && (
                <motion.div
                  initial={{ y: 12, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  exit={{ y: 12, opacity: 0 }}
                  transition={{ type: 'spring', stiffness: 380, damping: 28 }}
                  className="flex-shrink-0 mx-3 mb-1 rounded-2xl overflow-hidden"
                  style={{ background: 'rgba(99,102,241,0.07)', border: '1px solid rgba(99,102,241,0.18)' }}
                >
                  <div className="flex items-center gap-2.5 px-3 py-2">
                    <div className="w-1 self-stretch rounded-full bg-indigo-400 flex-shrink-0" />
                    <Reply className="w-3.5 h-3.5 text-indigo-400 flex-shrink-0" />
                    <div className="flex-1 min-w-0">
                      <span className="text-[11px] font-bold text-indigo-500 block leading-tight">{replyingTo.sender_name}</span>
                      <p className="text-[11px] text-slate-500 truncate leading-tight mt-0.5">
                        {replyingTo.type === 'gif' ? '🎞 GIF' : replyingTo.type === 'sticker' ? '🎨 Sticker' : replyingTo.text || '...'}
                      </p>
                    </div>
                    <button onClick={() => setReplyingTo(null)} className="w-6 h-6 rounded-full bg-slate-200/80 flex items-center justify-center flex-shrink-0 hover:bg-slate-300 transition-colors">
                      <X className="w-3.5 h-3.5 text-slate-500" />
                    </button>
                  </div>
                </motion.div>
              )}
            </AnimatePresence>

            {/* Composer — pinned at bottom */}
            <div className="relative bg-white border-t border-slate-100 px-3 py-3 flex-shrink-0 z-30">
              {viewerIsMember === null ? (
                <div className="w-full h-11 rounded-2xl bg-slate-100 animate-pulse" />
              ) : viewerIsMember === false ? (
                <button onClick={() => setShowNonMemberModal(true)} className="w-full h-11 rounded-2xl bg-slate-100 text-slate-400 text-sm font-medium flex items-center justify-center gap-2">
                  <Users className="w-4 h-4" /> {t('group.join_to_send','Join to send messages')}
                </button>
              ) : (
                <>
                  <AnimatePresence>
                    {editingMsg && (
                      <motion.div initial={{ y: 8, opacity: 0 }} animate={{ y: 0, opacity: 1 }} exit={{ y: 8, opacity: 0 }}
                        className="flex items-center justify-between mb-2 px-1">
                        <div className="flex items-center gap-1.5">
                          <div className="w-1 h-4 bg-indigo-400 rounded-full" />
                          <span className="text-[11px] font-semibold text-indigo-600">{t('group.editing_message','Editing message')}</span>
                        </div>
                        <button onClick={() => { setEditingMsg(null); setMessageText(''); }}
                          className="w-5 h-5 rounded-full bg-slate-200 flex items-center justify-center hover:bg-slate-300 transition-colors">
                          <X className="w-3 h-3 text-slate-500" />
                        </button>
                      </motion.div>
                    )}
                  </AnimatePresence>

                  <form onSubmit={handleSendMessage} className="flex items-end gap-2">
                    {!editingMsg && (
                      <button type="button" onClick={() => setShowGifPicker(true)}
                        className="w-10 h-10 rounded-2xl bg-slate-100 flex items-center justify-center flex-shrink-0 text-slate-500 hover:bg-slate-200 transition-colors">
                        <Smile className="w-5 h-5" />
                      </button>
                    )}
                    <div className={cn("flex-1 rounded-2xl px-3 py-2.5", editingMsg ? "bg-indigo-50 border border-indigo-200" : "bg-slate-100")}>
                      <MentionInput
                        value={messageText}
                        onChange={(v) => { setMessageText(v); if (messageError) setMessageError(''); }}
                        onKeyDown={(e) => {
                          if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); e.stopPropagation(); handleSendMessage(); }
                          if (e.key === 'Escape' && editingMsg) { setEditingMsg(null); setMessageText(''); }
                        }}
                        placeholder={editingMsg ? t('group.edit_message_placeholder','Edit message...') : t('group.message_placeholder','Message... (@ to mention)')}
                        disabled={messageSending}
                        rows={1}
                        className="w-full bg-transparent text-sm text-slate-900 resize-none outline-none border-none max-h-24"
                        context="group"
                        groupId={groupId}
                      />
                    </div>
                    <button type="submit" disabled={!messageText.trim() || messageSending}
                      className="w-10 h-10 rounded-2xl flex items-center justify-center flex-shrink-0 transition-all disabled:opacity-40"
                      style={{ background: messageText.trim() ? (editingMsg ? 'linear-gradient(135deg,#6366f1,#4f46e5)' : 'linear-gradient(135deg, #6366f1, #8b5cf6)') : '#f1f5f9' }}>
                      {messageSending ? <Loader2 className="w-4 h-4 text-white animate-spin" /> : <Send className={cn("w-4 h-4", messageText.trim() ? "text-white" : "text-slate-400")} />}
                    </button>
                  </form>
                </>
              )}
            </div>
          </motion.div>
        ) : (
          <motion.div key="posts" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }} className="flex-1 flex flex-col min-h-0 overflow-hidden">
            <div className="flex-1 overflow-y-auto overscroll-contain px-4 py-4 min-h-0">
              {(postsLoading || !postsFetched) && postsArray.length === 0 ? (
                <div className="space-y-3">
                  {[1,2,3].map(i => (
                    <div key={i} className="h-44 rounded-3xl bg-slate-100 animate-pulse" />
                  ))}
                </div>
              ) : postsArray.length === 0 && postsFetched && !postsLoading && !postsEverLoadedRef.current ? (
                <div className="flex flex-col items-center justify-center py-16 gap-3">
                  <div className="w-14 h-14 rounded-2xl bg-slate-100 flex items-center justify-center">
                    <ChefHat className="w-7 h-7 text-slate-300" />
                  </div>
                  <p className="text-sm font-semibold text-slate-500">{t('group.no_posts','No posts yet')}</p>
                  <p className="text-xs text-slate-400 text-center max-w-[200px]">{t('group.no_posts_desc','Be the first to share a recipe with the group!')}</p>
                </div>
              ) : (
                Array.isArray(postsArray) && (
                  <div className="space-y-3">
                    {postsArray.map(post => {
                      if (!post || typeof post !== 'object' || !post.id) {
                        console.warn('[GroupDetail] invalid post object', post);
                        return null;
                      }
                      return (
                        <GroupPostCard key={post.id} post={post} currentUserId={user?.id}
                         viewerHasLiked={viewerLikedPostIds.has(post.id)}
                         onClick={() => { console.log('post clicked', post.id); }}
                         onComment={(p) => { setSelectedCommentPost(p); setShowComments(true); }}
                         t={t}
                         onNonMemberAction={viewerIsMember === false ? () => setShowNonMemberModal(true) : null} />
                      );
                    })}
                  </div>
                )
               )}
            </div>
            <div className="bg-white border-t border-slate-100 px-4 py-3 flex-shrink-0">
              {viewerIsMember === null ? (
                <div className="w-full h-12 rounded-2xl bg-slate-100 animate-pulse" />
              ) : viewerIsMember === false ? (
                <button onClick={() => setShowNonMemberModal(true)}
                  className="w-full h-12 rounded-2xl bg-indigo-50 text-indigo-600 font-bold text-sm flex items-center justify-center gap-2">
                  <Users className="w-4 h-4" /> {t('group.join_to_post','Join to post')}
                </button>
              ) : isPro ? (
                <button onClick={() => setShowPostComposer(true)}
                  className="w-full h-12 rounded-2xl text-white font-bold text-sm flex items-center justify-center gap-2"
                  style={{ background: 'linear-gradient(135deg, #f97316, #ef4444)' }}>
                  <Plus className="w-5 h-5" /> {t('group.share_post','Share a Post')}
                </button>
              ) : user?.account_status === 'paused' ? (
                <button onClick={() => setShowPauseGate(true)}
                  className="w-full h-12 rounded-2xl bg-blue-50 border-2 border-blue-200 text-blue-800 font-bold text-sm flex items-center justify-center gap-2">
                  <Clock className="w-4 h-4 text-blue-500" /> {t('group.paused_reactivate','Account paused — Reactivate to post')}
                </button>
              ) : (
                <button onClick={() => window.location.href = createPageUrl('SubscriptionOffer') + '?from=GroupDetail&blocked=group_post'}
                  className="w-full h-12 rounded-2xl bg-amber-50 border-2 border-amber-200 text-amber-800 font-bold text-sm flex items-center justify-center gap-2">
                  <Crown className="w-4 h-4 text-amber-500" /> {t('group.pro_required_post','Pro required to post — Upgrade ✦')}
                </button>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {showGroupShareSheet && <ReciplyShareSheet isOpen onClose={() => setShowGroupShareSheet(false)} type="group" preview={{ name: group?.name, emoji: group?.cover_emoji, color: group?.cover_color, memberCount: group?.member_count }} shareUrl={`${window.location.origin}${createPageUrl('GroupDetail')}?id=${groupId}`} shareTitle={`${group?.name || 'Group'} on Reciply`} shareText={`Join ${group?.name || 'this group'} on Reciply!`} onSendToContacts={async (rids) => { const content = `[group_share:${groupId}]`; await Promise.all(rids.map(r => base44.functions.invoke('sendDirectMessage', { recipient_id: r, content, meta_type: 'group_share', meta_group_id: groupId, meta_group_name: group?.name || '', meta_group_emoji: group?.cover_emoji || '' }))); }} />}
      <AnimatePresence>{showGifPicker && <GifStickerPicker onSelect={handleSendMedia} onClose={() => setShowGifPicker(false)} />}</AnimatePresence>

      {/* Member List Drawer — Mobile sheet with drag UX */}
      <MembersSheet
        groupId={groupId}
        currentUserId={user?.id}
        isOpen={showMemberList}
        onOpenChange={setShowMemberList}
        initialMembers={members}
      />

      {/* Post Composer Sheet */}
      <AnimatePresence>
        {showPostComposer && (
          <>
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
              className="fixed inset-0 z-40 bg-black/50 pointer-events-auto" onClick={() => { setShowPostComposer(false); setSelectedRecipe(null); setShowRecipePicker(false); }} />
            <motion.div initial={{ y: '100%' }} animate={{ y: 0 }} exit={{ y: '100%' }}
              transition={{ type: 'spring', damping: 30, stiffness: 300 }}
              className="fixed inset-x-0 bottom-0 z-50 bg-white rounded-t-3xl p-5 max-h-[85vh] overflow-y-auto">
              <div className="w-10 h-1 bg-slate-200 rounded-full mx-auto mb-4" />
              <h3 className="text-lg font-bold text-slate-900 mb-3">{t('group.share_with_group','Share with the group')}</h3>

              <div className="mb-3">
                <div className="flex items-center justify-between mb-2">
                  <span className="text-sm font-semibold text-slate-700">{t('group.recipe_label','Recipe')} <span className="text-rose-500">*</span></span>
                  {selectedRecipe && (
                    <button onClick={() => setSelectedRecipe(null)} className="text-xs text-slate-400 hover:text-slate-600">{t('action.change','Change')}</button>
                  )}
                </div>

                {selectedRecipe ? (
                  <div className="flex items-center gap-3 p-3 rounded-2xl bg-orange-50 border border-orange-100">
                    {selectedRecipe.hero_image_url && (
                      <img src={selectedRecipe.hero_image_url} alt="" className="w-10 h-10 rounded-xl object-cover flex-shrink-0" />
                    )}
                    <span className="text-sm font-semibold text-orange-700 truncate">{selectedRecipe.title}</span>
                    <button onClick={() => setSelectedRecipe(null)} className="ml-auto w-5 h-5 rounded-full bg-orange-200 flex items-center justify-center flex-shrink-0">
                      <X className="w-3 h-3 text-orange-600" />
                    </button>
                  </div>
                ) : (
                  <>
                    {!showRecipePicker ? (
                      <button onClick={() => setShowRecipePicker(true)}
                        className="w-full h-12 rounded-2xl border-2 border-dashed border-slate-200 text-slate-500 text-sm font-medium flex items-center justify-center gap-2 hover:border-orange-300 hover:text-orange-500 transition-colors">
                        <ChefHat className="w-4 h-4" /> {t('group.select_recipe','Select a recipe')}
                      </button>
                    ) : (
                      <RecipePicker userId={user?.id} onSelect={(r) => { setSelectedRecipe(r); setShowRecipePicker(false); }} onClose={() => setShowRecipePicker(false)} t={t} />
                    )}
                  </>
                )}
              </div>

              <textarea
                value={postCaption}
                onChange={e => setPostCaption(e.target.value)}
                placeholder={t('group.caption_placeholder','Add a caption (optional)...')}
                rows={2}
                className="w-full bg-slate-50 rounded-2xl px-4 py-3 text-sm text-slate-900 resize-none outline-none border border-slate-100 focus:border-indigo-200"
              />

              {postError && (
                <div className="mt-2 flex items-center gap-2 text-red-500 text-xs bg-red-50 px-3 py-2 rounded-xl">
                  <AlertCircle className="w-3.5 h-3.5 flex-shrink-0" />{postError}
                </div>
              )}

              <div className="flex gap-3 mt-4">
                <Button variant="outline" onClick={() => { setShowPostComposer(false); setPostError(''); setSelectedRecipe(null); setShowRecipePicker(false); }} className="flex-1 rounded-2xl">{t('action.cancel','Cancel')}</Button>
                <button onClick={handleCreatePost} disabled={postSending || !selectedRecipe}
                  className="flex-1 h-10 rounded-2xl text-white font-bold text-sm flex items-center justify-center gap-2 disabled:opacity-50"
                  style={{ background: 'linear-gradient(135deg, #f97316, #ef4444)' }}>
                  {postSending ? <><Loader2 className="w-4 h-4 animate-spin" /> {t('group.posting','Posting...')}</> : t('group.post','Post')}
                </button>
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>

      {/* Comments Sheet */}
      <GroupPostCommentsSheet
        isOpen={showComments}
        post={selectedCommentPost}
        onClose={() => { setShowComments(false); setSelectedCommentPost(null); }}
        currentUser={user}
        viewerIsMember={viewerIsMember}
        onNonMemberAction={() => { setShowComments(false); setSelectedCommentPost(null); setShowNonMemberModal(true); }}
      />

      {/* Message Reactions Menu */}
      {showReactionsMenu && (
        <div className="fixed inset-0 z-50 pointer-events-auto" onClick={() => setShowReactionsMenu(null)}>
          <MessageReactionsMenu messageId={showReactionsMenu} onClose={() => setShowReactionsMenu(null)} />
        </div>
      )}

      {/* Reactions List Bottom Sheet — passes snapshot for instant open */}
      <AnimatePresence>
        {showReactionsList && (
          <MessageReactionsList
            messageId={showReactionsList}
            initialReactions={reactionsMap[showReactionsList] || null}
            onClose={() => setShowReactionsList(null)}
          />
        )}
      </AnimatePresence>

      {/* Non-Member Action Gate Modal */}
      <AnimatePresence>
        {showNonMemberModal && (
          <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-5">
            <motion.div
              initial={{ opacity: 0, scale: 0.88, y: 24 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.88, y: 24 }}
              transition={{ type: 'spring', stiffness: 420, damping: 30 }}
              className="bg-white rounded-3xl p-7 max-w-sm w-full shadow-2xl text-center overflow-hidden"
            >
              <AnimatePresence mode="wait">
                {joinSuccess ? (
                  <motion.div
                    key="success"
                    initial={{ opacity: 0, scale: 0.6 }}
                    animate={{ opacity: 1, scale: 1 }}
                    transition={{ type: 'spring', stiffness: 400, damping: 22 }}
                    className="flex flex-col items-center py-2"
                  >
                    <motion.div
                      initial={{ scale: 0 }}
                      animate={{ scale: [0, 1.35, 1] }}
                      transition={{ duration: 0.55, times: [0, 0.65, 1] }}
                      className="w-20 h-20 rounded-full bg-green-100 flex items-center justify-center mb-4 relative"
                    >
                      <CheckCircle2 className="w-10 h-10 text-green-500" />
                      <motion.div
                        initial={{ scale: 1, opacity: 0.6 }}
                        animate={{ scale: 2.2, opacity: 0 }}
                        transition={{ duration: 0.7 }}
                        className="absolute inset-0 rounded-full border-2 border-green-400"
                      />
                    </motion.div>
                    <motion.h3
                      initial={{ opacity: 0, y: 8 }}
                      animate={{ opacity: 1, y: 0 }}
                      transition={{ delay: 0.2 }}
                      className="text-xl font-black text-slate-900 mb-1"
                    >{t('group.welcome_aboard','Welcome aboard! 🎉')}</motion.h3>
                    <motion.p
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      transition={{ delay: 0.35 }}
                      className="text-sm text-slate-500"
                    >{t('group.joined_success',"You've joined the group")}</motion.p>
                  </motion.div>
                ) : (
                  <motion.div key="prompt" initial={{ opacity: 1 }} exit={{ opacity: 0, scale: 0.95 }}>
                    <motion.div
                      animate={{ scale: [1, 1.08, 1] }}
                      transition={{ duration: 1.8, repeat: Infinity, ease: "easeInOut" }}
                      className="w-16 h-16 rounded-2xl bg-gradient-to-br from-indigo-100 to-purple-100 flex items-center justify-center mx-auto mb-4"
                    >
                      <Users className="w-8 h-8 text-indigo-600" />
                    </motion.div>
                    <h3 className="text-xl font-black text-slate-900 mb-2">{t('group.join_to_participate','Join to participate')}</h3>
                    <p className="text-sm text-slate-500 mb-7 leading-relaxed">{t('group.join_desc','Chat, post recipes, and interact with everyone in this group.')}</p>
                    <div className="flex gap-3">
                      <button
                        onClick={() => setShowNonMemberModal(false)}
                        className="flex-1 h-12 rounded-2xl bg-slate-100 text-slate-700 font-semibold text-sm hover:bg-slate-200 transition-colors"
                      >{t('action.close','Close')}</button>
                      <motion.button
                        onClick={handleJoin}
                        disabled={joinLoading}
                        whileHover={{ scale: 1.03 }}
                        whileTap={{ scale: 0.96 }}
                        className="flex-1 h-12 rounded-2xl text-white font-bold text-sm flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 disabled:opacity-70"
                        style={{ background: 'linear-gradient(135deg, #6366f1, #8b5cf6)' }}
                      >
                        {joinLoading ? (
                          <><Loader2 className="w-4 h-4 animate-spin" /> {t('group.joining','Joining...')}</>
                        ) : t('group.join_now','Join Now ✦')}
                      </motion.button>
                    </div>
                  </motion.div>
                )}
              </AnimatePresence>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}

