/* AUTHORITATIVE theme token override — unlayered so it always wins over any @layer base conflict
   (e.g. index.css re-defines --primary as near-black; this restores Reciply indigo) */
:root {
  --background: 0 0% 100%;
  --foreground: 222.2 84% 4.9%;
  --card: 0 0% 100%;
  --card-foreground: 222.2 84% 4.9%;
  --popover: 0 0% 100%;
