}

/* Prevent horizontal overflow / side-drag on web */
html {
  height: 100%;
  /* Android wrapper: use real viewport height, not broken 100vh */
  height: calc(var(--app-vh, 1vh) * 100);
  overflow: hidden;
  /* Allow Android system gestures (back swipe etc.) */
  overscroll-behavior-x: none;
}

body {
  height: 100%;
  overflow: hidden;
  max-width: 100vw;
  /* Prevent pull-to-refresh on body (handled per-component) */
  overscroll-behavior-y: none;
  /* SYSTEM 3: Use slate-50 as the universal app chrome background.
     This eliminates white gaps at top/bottom safe-area insets and between
     the bottom nav and the system navigation bar. */
  background-color: #f8fafc !important;
}

#root {
  height: 100%;
  display: flex;
  flex-direction: column;
}

/* ── ANDROID WRAPPER: respect native nav-bar inset ────────────────────────
   The native Android shell pushes real per-edge inset values via the CSS
   variables --saw-inset-top / --saw-inset-bottom (declared in index.css).
   We MUST honor --saw-inset-bottom here so the bottom nav and content are
   not cropped behind the Android system navigation bar (gesture pill /
   3-button bar).

   Top inset stays 0 because the native shell positions the WebView BELOW
   the status bar already. Bottom inset is needed because Android's gesture
   nav bar floats over the WebView. */
html[data-android-wrapper] {
  --safe-area-top: 0px;
  --safe-area-bottom: var(--saw-inset-bottom, 0px);
}

/* Android wrapper: top can be flat (handled by native shell), bottom MUST
   respect the inset so nothing is cropped behind the system nav bar. */
html[data-android-wrapper] .safe-top { padding-top: 0 !important; }
html[data-android-wrapper] .safe-bottom { padding-bottom: var(--saw-inset-bottom, 0px) !important; }
html[data-android-wrapper] .pb-safe { padding-bottom: var(--saw-inset-bottom, 0px) !important; }
html[data-android-wrapper] .mb-safe { margin-bottom: var(--saw-inset-bottom, 0px) !important; }

/* ── Safe area CSS variables (used by nav + modals) ── */
:root {
  --safe-area-top: env(safe-area-inset-top, 0px);
  --safe-area-bottom: env(safe-area-inset-bottom, 0px);
  --safe-area-left: env(safe-area-inset-left, 0px);
  --safe-area-right: env(safe-area-inset-right, 0px);
}

/* ── Protected media surfaces: suppress browser context menu ── */
.no-callout {
  -webkit-touch-callout: none;
  -webkit-user-select: none;
  user-select: none;
  pointer-events: auto;
}
.no-callout img,
.no-callout video {
  -webkit-touch-callout: none;
  -webkit-user-drag: none;
  user-select: none;
  pointer-events: none;
}

/* ── Non-selectable UI text (labels, badges, nav items) ── */
.no-select {
  -webkit-user-select: none;
  user-select: none;
}

/* ── CRITICAL: inputs/textareas MUST always allow selection (Android) ── */
input, textarea, [contenteditable] {
  -webkit-user-select: text !important;
  user-select: text !important;
}

/* ── Safe area bottom spacing helper ── */
.pb-safe {
  padding-bottom: env(safe-area-inset-bottom, 0px);
}
.mb-safe {
  margin-bottom: env(safe-area-inset-bottom, 0px);
}

/* Hide scrollbar utility */
.hide-scrollbar::-webkit-scrollbar { display: none; }
.hide-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

/* Bottom nav lock — hides nav even before the nav element mounts */
body.bottom-nav-locked [data-bottom-nav] {
  display: none !important;
  visibility: hidden !important;
  pointer-events: none !important;
  opacity: 0 !important;
}

/* ── Bottom-nav clearance: accounts for nav height (~72px) + iOS safe-area-inset-bottom ──
   Use .page-bottom-safe on the root div of any settings/sub-page that sits below the bottom nav.
   Never use a raw pb-20 that ignores safe area. Desktop: ~80px (no safe area). Mobile iOS: ~114px. */
.page-bottom-safe {
  padding-bottom: calc(env(safe-area-inset-bottom, 0px) + 5rem);
}

/* ── Smooth momentum scrolling on mobile (iOS/Android WebView) ── */
.overflow-y-auto,
.overflow-auto,
[class*="overflow-y-auto"] {
  -webkit-overflow-scrolling: touch;
  overscroll-behavior: contain;
}

/* ── Bottom sheets and modals: contain overscroll ── */
[role="dialog"],
[data-sheet],
.modal-scroll {
  overscroll-behavior: contain;
  -webkit-overflow-scrolling: touch;
}

/* ── Global avatar enforcement — all rounded-full containers clip children ── */
.rounded-full {
  border-radius: 9999px !important;
  overflow: hidden;
}
.rounded-full img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center;
  border-radius: 0;
  display: block;
  padding: 0;
  margin: 0;
}

/* ── BIDI / RTL TEXT UTILITIES (layout stays LTR, text isolated per-element) ── */

/* Force LTR isolation — use on English tokens, numbers, dates inside RTL text */
.bidi-ltr {
  direction: ltr !important;
  unicode-bidi: isolate !important;
  display: inline;
}

/* Force RTL isolation — use on RTL fragments inside LTR containers */
.bidi-rtl {
  direction: rtl !important;
  unicode-bidi: isolate !important;
  display: inline;
}

/* Bidi-safe stat/number — prevents fractions/counts from flipping */
.bidi-stat-value {
  direction: ltr !important;
  unicode-bidi: isolate !important;
  display: inline;
  font-variant-numeric: tabular-nums;
}

/* Bidi-safe badge/chip — stays LTR centered inside RTL parent */
.bidi-badge {
  direction: ltr !important;
  unicode-bidi: isolate !important;
  display: inline-flex !important;
  align-items: center;
  justify-content: center;
  white-space: nowrap;
}

/* Bidi-safe date/time tokens */
.bidi-date {
  direction: ltr !important;
  unicode-bidi: isolate !important;
  display: inline;
  white-space: nowrap;
}

/* RTL text block — text aligns right without flipping layout */
.rtl-text {
  direction: rtl;
  text-align: right;
  unicode-bidi: isolate;
}

/* Smooth animations */
* { -webkit-tap-highlight-color: transparent; }

/* SAFETY NET: Ensure main scrollable area is NEVER transparent/black.
   Prevents flash between overlay fade-out and recipe view paint. */
main {
  background-color: #f8fafc !important;
}

/* EMOJI LONG-PRESS PREVENTION: block browser context menu, download popup on emoji rows */
[data-emoji-safe],
[data-emoji-safe] * {
  -webkit-touch-callout: none !important;
  -webkit-user-select: none !important;
  user-select: none !important;
  -webkit-user-drag: none !important;
}
[data-emoji-safe] button {
  touch-action: manipulation;
}

/* ── Respect reduced motion preference ── */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* ── Prevent overscroll bounce inside bottom sheets / modals ── */
.fixed.inset-0 {
  overscroll-behavior: contain;
}

/* ── Bottom nav: prevent text selection on nav tap targets only ── */
nav[aria-label="Main navigation"] a,
nav[aria-label="Main navigation"] button {
  -webkit-user-select: none;
  user-select: none;
}

/* ── Minimum tap target sizes for accessibility (Google Play compliance) ── */
nav a {
  min-height: 48px;
  min-width: 48px;
}

/* ── All interactive controls: minimum 44px touch target (Google Play requirement) ── */
button:not([data-no-min-height]):not([data-icon-only]):not(.inline-btn),
[role="button"]:not([data-no-min-height]):not([data-icon-only]) {
  min-height: 44px;
}

/* Inline/icon-only buttons are exempt — must explicitly opt-out */
button.inline-btn,
button[data-icon-only] {
  min-height: unset;
}

/* ── Select / dropdown triggers: enforce 48px height ── */
[data-radix-select-trigger],
[role="combobox"] {
  min-height: 48px !important;
}

/* ── Modal/dialog open → bottom nav hidden via JS (see AppSheet + layout) ── */
/* Additional CSS guard: when a dialog or sheet is open, ensure content below bottom nav has enough padding ── */
.main-content-area {
  padding-bottom: calc(env(safe-area-inset-bottom, 0px) + 72px);
}

/* ── Safe area: ensure content never reaches system chrome ── */
.safe-top {
  padding-top: env(safe-area-inset-top, 0px);
}
.safe-bottom {
  padding-bottom: env(safe-area-inset-bottom, 0px);
}
.safe-left {
  padding-left: env(safe-area-inset-left, 0px);
}
.safe-right {
  padding-right: env(safe-area-inset-right, 0px);
}

/* ── Native-like button press feedback ── */
button:not(:disabled):active,
[role="button"]:not(:disabled):active {
  transform: scale(0.97);
  transition: transform 0.1s ease;
}

/* Prevent override on elements that define their own active styles */
button.no-press-feedback:active {
  transform: none;
}

@keyframes shimmer {
  0% { 
    background-position: -200% center;
  }
  100% { 
    background-position: 200% center;
  }
}

@layer utilities {
  .animate-shimmer {
    animation: shimmer 2s infinite;
    background-size: 200% 100%;
  }
}

