const LayoutWrapper = ({ children, currentPageName, hideBottomNav = false }) => Layout ?
  <Layout currentPageName={currentPageName} hideBottomNav={hideBottomNav}>
    <PageTransitionWrapper pageKey={currentPageName}>{children}</PageTransitionWrapper>
  </Layout>
  : <PageTransitionWrapper pageKey={currentPageName}>{children}</PageTransitionWrapper>;

// The 5 main bottom-nav tabs rendered simultaneously for keep-alive state preservation
const TAB_ROUTES = [
  { path: "/Home", pageName: "Home", Page: Home },
  { path: "/Pantry", pageName: "Pantry", Page: Pantry },
  { path: "/Generate", pageName: "Generate", Page: Generate },
  { path: "/Community", pageName: "Community", Page: Community },
  { path: "/Profile", pageName: "Profile", Page: Profile },
];
const TAB_PATH_SET = new Set(["/Home", "/Pantry", "/Generate", "/Community", "/Profile"]);

const TabRouteWrapper = ({ currentPageName }) => (
  <LayoutWrapper currentPageName={currentPageName}>
    <TabContainer tabs={TAB_ROUTES} />
  </LayoutWrapper>
);

// Derive a stable animation key: tab routes all share the same key so AnimatePresence
// does NOT re-animate when switching between tabs (TabContainer handles that internally).
// Non-tab routes each get their own unique key so they animate in/out correctly.
const TAB_KEY = "tab-shell";
function getRouteAnimKey(pathname) {
  if (pathname === '/' || pathname === '/welcome') return 'welcome';
  if (TAB_PATH_SET.has(pathname)) return TAB_KEY;
  return pathname;
}

const PUBLIC_PATHS = new Set(["/", "/welcome", "/marketing", "/terms", "/privacy", "/support", "/legal/terms", "/legal/privacy", "/AuthCallback"]);
const ADMIN_PATH_PREFIXES = ["/Admin", "/CostAudit", "/PricingAudit", "/IngredientIconAudit", "/AnimationLibrary", "/RipoAssets", "/OnboardingAnimationUpload", "/RipoStatesUpload", "/EmailAssetManager", "/PushDiagnostics", "/AdminSeedDemo", "/AdminAuthDiagnostics"];
// Note: /AdminHub is covered by the /Admin prefix above.

// Cache key for landing config so we don't re-fetch on every render
// Uses sessionStorage so it resets on new tab/fresh load — never stale across sessions
const LANDING_CONFIG_CACHE_KEY = '__reciply_landing_cfg__';

function getCachedLandingConfig() {
  try {
    const raw = sessionStorage.getItem(LANDING_CONFIG_CACHE_KEY);
    if (!raw) return null;
    const { value, ts } = JSON.parse(raw);
    // Cache valid for 60 seconds — short enough to reflect real saves quickly
    if (Date.now() - ts < 60_000) return value;
    sessionStorage.removeItem(LANDING_CONFIG_CACHE_KEY);
    return null;
  } catch { return null; }
}

function setCachedLandingConfig(value) {
  try {
    sessionStorage.setItem(LANDING_CONFIG_CACHE_KEY, JSON.stringify({ value, ts: Date.now() }));
  } catch {}
}

const AuthenticatedApp = () => {
  const location = useLocation();
  const animKey = getRouteAnimKey(location.pathname);
  const isLegalPage = isRedirectExemptPublicRoute(location.pathname);

  const isNativeApp = isAppEnvironment();
  const isAdminPath = ADMIN_PATH_PREFIXES.some(p => location.pathname.startsWith(p));
  const isPublicPath = PUBLIC_PATHS.has(location.pathname) || location.pathname.startsWith('/legal/');

  // Web guard state — null = loading, true = marketing enabled, false = disabled
  const [marketingEnabled, setMarketingEnabled] = useState(() => {
    // Native app: never show marketing — skip fetch entirely
    if (isNativeApp) return false;
    // Public/admin paths: never need the guard — skip fetch
    if (isPublicPath || isAdminPath) return false;
    // Check session cache first for instant decision (no flash)
    const cached = getCachedLandingConfig();
    if (cached !== null) return cached;
    // Unknown — must fetch
    return null;
  });

  useEffect(() => {
    // Only fetch if we're on a non-public, non-admin, web path and don't have a cached answer
    if (isNativeApp || isPublicPath || isAdminPath || marketingEnabled !== null) return;

    base44.functions.invoke('getAppConfig', {})
      .then(res => {
        const enabled = res.data?.config?.marketing_landing_enabled === true;
        setCachedLandingConfig(enabled);
        setMarketingEnabled(enabled);
      })
      .catch(() => {
        // On error: default to NOT showing marketing (show app flow)
        setCachedLandingConfig(false);
        setMarketingEnabled(false);
      });
  }, [location.pathname]);

  // Still loading config — show slate-50 background (matches app chrome) with premium loader
  // CRITICAL: Never flash white then switch — use exact app background color
  if (marketingEnabled === null) {
    return (
      <div style={{ position: 'fixed', inset: 0, background: '#f8fafc', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <LoadingSpinner />
      </div>
    );
  }

  // CENTRAL WEB GUARD: Only redirect to marketing if config says so
  // Native app, admin paths, public paths, and legal pages always bypass this
  if (!isPublicPath && !isAdminPath && !isNativeApp && !isLegalPage && marketingEnabled === true) {
    window.location.replace("/marketing");
    return null;
  }

  // Render the main app
  return (
    <AnimatePresence mode="sync" initial={false}>
    <Routes location={location} key={animKey}>
      {/* Public pre-auth landing — MUST be first, no Layout wrapper, no auth */}
      <Route path="/" element={<Welcome />} />
      <Route path="/welcome" element={<Welcome />} />
      {/* AuthCallback — MUST be unwrapped (no Layout) and listed BEFORE the
          pagesConfig loop, otherwise the loop's LayoutWrapper would mount
          Layout.jsx which adds bootstrap delays + auth gating that block
          token capture and polling in the Android WebView. */}
      <Route path="/AuthCallback" element={<AuthCallbackPage />} />
      {/* External legal pages — also handled at top-level App, but kept here as fallback */}
      <Route path="/legal/terms" element={<Suspense fallback={<PageLoadingFallback />}><TermsExternal /></Suspense>} />
      <Route path="/legal/privacy" element={<Suspense fallback={<PageLoadingFallback />}><PrivacyExternal /></Suspense>} />
      <Route path="/legal/support" element={<Suspense fallback={<PageLoadingFallback />}><SupportExternal /></Suspense>} />
      {/* Marketing + public legal pages — always accessible */}
      <Route path="/marketing" element={<Suspense fallback={<PageLoadingFallback />}><MarketingLanding /></Suspense>} />
      <Route path="/terms" element={<LayoutWrapper currentPageName="TermsOfService" hideBottomNav={true}><Suspense fallback={<PageLoadingFallback />}><TermsOfServicePage /></Suspense></LayoutWrapper>} />
      <Route path="/privacy" element={<LayoutWrapper currentPageName="PrivacyPolicy" hideBottomNav={true}><Suspense fallback={<PageLoadingFallback />}><PrivacyPolicyPage /></Suspense></LayoutWrapper>} />
      <Route path="/support" element={<LayoutWrapper currentPageName="Support" hideBottomNav={true}><Suspense fallback={<PageLoadingFallback />}><SupportPage /></Suspense></LayoutWrapper>} />
      {/* APP-ONLY ROUTES — WebGuard blocks all of these in a web browser */}
      {/* Tab pages — all rendered simultaneously via TabContainer for keep-alive.
          A single LayoutWrapper wraps the whole TabContainer so layout/auth runs once.
          All tab routes share the same animKey so the shell is NEVER unmounted during
          tab switches — only TabContainer's visibility toggling fires. */}
      {["/Home", "/Pantry", "/Generate", "/Community", "/Profile"].map((tabPath) => (
        <Route
          key={tabPath}
          path={tabPath}
          element={<TabRouteWrapper currentPageName={tabPath.slice(1)} />}
        />
      ))}
      {Object.entries(Pages)
        .filter(([path]) => !TAB_PATH_SET.has(`/${path}`) && path !== "Home" && path !== "Pantry" && path !== "Generate" && path !== "Community" && path !== "Profile")
