function AppWithAuth() {
  const [appReady, setAppReady] = useState(false);

  useEffect(() => {
    const onReady = () => setAppReady(true);
    window.addEventListener('reciply-bootstrap-complete', onReady);
    const t = setTimeout(() => setAppReady(true), 8000);
    // Kick off critical asset warming in PARALLEL with auth — hydrates from
    // localStorage instantly and prefetches Ripo video blobs + images so
    // Welcome / Onboarding / CookMode never wait for them.
    console.log('[Boot] auth + assets parallel start');
    import('@/lib/assetPreloader').then(({ warmCriticalAssets }) => {
      warmCriticalAssets();
    }).catch(() => {});
    return () => {
      window.removeEventListener('reciply-bootstrap-complete', onReady);
      clearTimeout(t);
    };
  }, []);

  return (
    <AuthProvider>
      <LocalizationProvider>
        <QueryClientProvider client={queryClientInstance}>
          <OverlayProvider>
            <AppSplash ready={appReady}>
              <AuthenticatedApp />
            </AppSplash>
          </OverlayProvider>
        </QueryClientProvider>
        <Toaster />
      </LocalizationProvider>
    </AuthProvider>
  );
}

