function ResumeAccountButton({ onResumed, disabled: externalDisabled }) {
  const [loading, setLoading] = React.useState(false);
  const [error, setError] = React.useState("");

  const handleResume = async () => {
    setLoading(true);
    setError("");
    try {
      const response = await base44.functions.invoke("resumeAccount", {});
      const data = response.data;
      if (data?.success || data?.already_active) {
        // Re-fetch fresh user state from server, then let parent update UI
        onResumed();
      } else {
        // NOT_PAUSED means we're already active — treat as success
        if (data?.error_type === "NOT_PAUSED") {
          onResumed();
          return;
        }
        setError(data?.reason || "Failed to resume account.");
        setLoading(false);
      }
    } catch (err) {
      setError(err.response?.data?.reason || err.message || "Failed to resume. Please try again.");
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col items-center gap-2 w-full">
      <button
        onClick={handleResume}
        disabled={loading || externalDisabled}
        className="relative w-full h-12 rounded-2xl text-sm font-semibold tracking-wide disabled:opacity-60 overflow-hidden transition-all duration-300 hover:scale-[1.02] active:scale-[0.98] shadow-lg hover:shadow-yellow-400/40"
        style={{
          background: "linear-gradient(135deg, #f6d365 0%, #fda085 40%, #f7c948 70%, #ffe066 100%)",
          color: "#7a4a00",
          boxShadow: "0 4px 20px rgba(247, 195, 30, 0.45), inset 0 1px 0 rgba(255,255,255,0.4)",
          border: "1px solid rgba(255, 210, 80, 0.6)",
        }}
      >
        <span className="relative z-10 flex items-center justify-center gap-2">
          {loading ? (
            <>
              <span className="w-4 h-4 border-2 border-yellow-700/40 border-t-yellow-800 rounded-full animate-spin" />
              Resuming...
            </>
          ) : (
            <>✦ Resume Account</>
          )}
        </span>
        {/* shimmer overlay */}
        <span className="absolute inset-0 pointer-events-none" style={{
          background: "linear-gradient(105deg, transparent 40%, rgba(255,255,255,0.35) 50%, transparent 60%)",
          backgroundSize: "200% 100%",
          animation: "goldShimmer 2.4s infinite",
        }} />
      </button>
      {error && <p className="text-xs text-rose-500 font-medium">{error}</p>}
    </div>
  );
}

function NavTabItem({ tab, unreadMessages, onGuardedNav }) {
  const Icon = tab.icon;
  const { t } = useLocalization();
  const displayName = tab.nameKey ? t(tab.nameKey, tab.name) : tab.name;
  // Always derive active state from committed router pathname — single source of truth.
  // This prevents stale highlight when AnimatePresence or prop lag causes currentPageName
  // to lag behind the actual committed route.
  const { pathname } = useLocation();
  const isActive = pathname === `/${tab.page}`;
  const showBadge = tab.page === "Profile" && unreadMessages > 0;
  const [tapped, setTapped] = React.useState(false);

  const handleClick = (e) => {
    if (isActive) return;
    const allowed = navigationGuard.check();
    if (!allowed) {
      e.preventDefault();
      onGuardedNav(createPageUrl(tab.page));
      return;
    }
    if (tab.pulse) {
      setTapped(true);
      setTimeout(() => setTapped(false), 320);
    }
  };

  return (
    <Link
      to={createPageUrl(tab.page)}
      onClick={handleClick}
      aria-label={tab.name}
      aria-current={isActive ? "page" : undefined}
      className={cn(
        "relative rounded-2xl transition-all duration-300 min-w-[62px] group",
        isActive ? "" : "text-slate-400 hover:text-slate-600"
      )}
      style={{
        ...(isActive ? { color: tab.color } : {}),
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        gap: '3px',
        height: '64px',
        lineHeight: 1,
        paddingLeft: '12px',
        paddingRight: '12px',
      }}
    >
      {isActive && !tab.pulse && (
        <>
          <div className="absolute inset-0 rounded-2xl" style={{ background: `${tab.color}12` }} />
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-12 h-12 rounded-full opacity-20"
            style={{ background: `radial-gradient(circle, ${tab.color}80 0%, transparent 70%)` }} />
        </>
      )}
      {tab.pulse ? (
        <>
          <div
            className={cn(
              "relative p-2 rounded-xl transition-all duration-200",
              tapped ? "gold-tap-anim" : "gold-pulse-anim"
            )}
            style={{
              background: isActive
                ? "linear-gradient(135deg, #FFE8A3 0%, #F7C948 45%, #D4A017 100%)"
                : "linear-gradient(135deg, #FFF8DC 0%, #F7C948 50%, #C8960C 100%)",
              boxShadow: isActive
                ? "0 2px 14px rgba(247,201,72,0.55), inset 0 1px 0 rgba(255,255,255,0.4)"
                : "0 1px 8px rgba(212,160,23,0.35)",
              borderRadius: "12px",
            }}
          >
            <Icon className="w-5 h-5 stroke-[2.5px]" style={{ color: "#7a4800", fill: isActive ? "#7a4800" : "none" }} />
            {tapped && (
              <div className="absolute inset-0 rounded-xl pointer-events-none" style={{
                background: "radial-gradient(circle, rgba(247,201,72,0.7) 0%, transparent 70%)",
                animation: "tabGlowBurst 0.4s ease-out forwards"
              }} />
            )}
          </div>
          <span className="relative font-bold" style={{
            color: "#7a4800",
            display: 'block',
            fontSize: '12.5px',
            lineHeight: 1.1,
            marginTop: '2px',
            textAlign: 'center',
            whiteSpace: 'nowrap',
            overflow: 'visible',
          }}>{displayName}</span>
        </>
      ) : (
        <>
          <div className={cn("relative p-2 rounded-xl transition-all duration-300", isActive && "bg-white shadow-sm")}>
                <div className="relative">
                  <Icon className={cn("w-5 h-5 transition-all", isActive && "stroke-[2.5px]")} style={{ fill: "none" }} />
                  {isActive && (
                    <div className="absolute inset-0 nav-icon-fill">
                      <Icon className="w-5 h-5 stroke-[2.5px]" style={{ fill: tab.color }} />
                    </div>
                  )}
                </div>
                {showBadge && (
                  <div className="absolute -top-0.5 -right-0.5 w-5 h-5 rounded-full bg-rose-500 flex items-center justify-center text-white text-[10px] font-bold shadow-lg">
                    {unreadMessages > 99 ? '99+' : unreadMessages}
