                )}
              </div>
              <span className={cn("relative transition-all", isActive ? "font-bold" : "font-medium")} style={{
                  display: 'block',
                  fontSize: '12.5px',
                  lineHeight: 1.1,
                  marginTop: '2px',
                  textAlign: 'center',
                  whiteSpace: 'nowrap',
                  overflow: 'visible',
                }}>{displayName}</span>
        </>
      )}
    </Link>
  );
}

// This is the new LayoutContent component, extracted from the original Layout component.
function LayoutContent({ children, currentPageName, hideBottomNav = false }) {
  const queryClient = useLayoutQueryClient();
  // ── ANDROID WRAPPER DETECTION (suppresses redundant safe-area spacers) ──
  const isAndroidWrapper = typeof document !== 'undefined' && document.documentElement.hasAttribute('data-android-wrapper');
  // ── CENTRALIZED AUTH: single source of truth from AuthContext ──────────
  const { user: authUser, isAuthenticated, authSettled, isLoadingAuth } = useAuth();
  const [user, setUser] = React.useState(null);
  const [prevUserId, setPrevUserId] = React.useState(null);
  const [unreadCount, setUnreadCount] = React.useState(0);
  // DM badge — single source of truth, shared with Profile page
  const unreadMessages = useUnreadDMCount(user?.id ?? null);
  const [showModerationModal, setShowModerationModal] = React.useState(false);
  const [moderationData, setModerationData] = React.useState(null);
  const [ownershipPopup, setOwnershipPopup] = React.useState(null);
  const [authBootstrapState, setAuthBootstrapState] = React.useState('bootstrapping');
  const showNotificationRef = React.useRef(null);

  // Sync user from AuthContext as the authoritative source
  React.useEffect(() => {
    if (authUser?.id) {
      setUser(authUser);
      setAuthBootstrapState('authenticated');
    } else if (authSettled && !authUser) {
      setAuthBootstrapState('unauthenticated');
    }
  }, [authUser?.id, authSettled]);

  // These hooks need to be called unconditionally (React rules of hooks)
  const proVerification = useProVerification();
  const { popup: rewardPopup, dismiss: dismissRewardPopup } = useRewardPopups(user?.id);
  const { showNotification } = useNotificationBanner();
  const { resolvedLang, isRTL } = useLocalization();
  const [authChecked, setAuthChecked] = React.useState(false);
  const [authTimeout, setAuthTimeout] = React.useState(false);
  const [showNavGuardModal, setShowNavGuardModal] = React.useState(false);
  const [pendingNavUrl, setPendingNavUrl] = React.useState(null);
  const bootstrapPageRef = React.useRef(currentPageName);
  const bootstrapRanRef = React.useRef(false);
  const appBackgroundRef = React.useRef(false);
  const reloadAttemptedRef = React.useRef(false);
  const backgroundedAtRef = React.useRef(null);
  const softReauthRef = React.useRef(false);

  // Clear ALL nav locks on every route change so stale hidden state never survives navigation
  // CRITICAL: Must fire BEFORE rendering nav so locks don't persist
  React.useLayoutEffect(() => {
    clearAllNavLocks();
  }, [currentPageName]);

  // Mount-only hard reset: ensure no stale lock survives a full page reload.
  // The [currentPageName] effect below handles route-change clearing.
  React.useLayoutEffect(() => {
    clearAllNavLocks();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  React.useEffect(() => { showNotificationRef.current = showNotification; }, [showNotification]);

  // Set HTML lang attribute for accessibility + screen readers
  React.useEffect(() => {
    if (resolvedLang && typeof document !== 'undefined') {
      document.documentElement.lang = resolvedLang;
      document.documentElement.dir = 'ltr';
    }
  }, [resolvedLang]);

  // Android back button: close nav guard modal if open, or let default back proceed
