          `}</style>
          <div className="max-w-lg mx-auto px-3" style={{
            position: 'absolute',
            left: 0,
            right: 0,
            top: 0,
            height: '76px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-around',
            boxSizing: 'border-box',
            transform: 'translateY(6px)',
          }}>
            {tabs.map((tab) => (
              <NavTabItem
                key={tab.page}
                tab={tab}
                unreadMessages={unreadMessages}
                onGuardedNav={(url) => { setPendingNavUrl(url); setShowNavGuardModal(true); }}
              />
            ))}
          </div>
          {/* safe-area-inset-bottom is now handled via paddingBottom on the nav itself */}
        </nav>
      )}

      {/* Ownership Transfer Popup */}
      <OwnershipTransferPopup
        isOpen={!!ownershipPopup}
        groupName={ownershipPopup?.groupName}
        groupId={ownershipPopup?.groupId}
        onDismiss={() => setOwnershipPopup(null)}
      />

      {/* Global Reward Popup */}
      <RewardPopup
        visible={!!rewardPopup}
        type={rewardPopup?.type}
        data={rewardPopup?.data || {}}
        onDismiss={dismissRewardPopup}
      />

      {/* Moderation Modal */}
      <ModerationModal
        isOpen={showModerationModal}
        action={moderationData?.action}
        reason={moderationData?.reason}
        timeoutUntil={moderationData?.timeoutUntil}
        onDismiss={async () => {
          if (moderationData?.action === 'timeout') {
            // Persist acknowledgment before closing popup
            try {
              await base44.functions.invoke('acknowledgeTimeout', {});
            } catch (e) {
              console.warn('[Layout] acknowledgeTimeout failed:', e?.message);
            }
            setShowModerationModal(false);
            window.location.href = createPageUrl("TimeoutPage");
          } else if (moderationData?.action === 'banned') {
            setShowModerationModal(false);
            window.location.href = createPageUrl("BannedPage");
          } else if (moderationData?.action === 'unbanned') {
            setShowModerationModal(false);
            window.location.href = createPageUrl("Home");
          } else {
            setShowModerationModal(false);
          }
        }}
      />

      {/* Global leave-guard modal — shown when navigationGuard.check() returns false */}
      {showNavGuardModal && (
        <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-5">
          <div className="bg-white rounded-3xl p-6 max-w-sm w-full shadow-2xl">
            <h3 className="text-lg font-bold text-slate-900 mb-2">Leave without saving?</h3>
            <p className="text-sm text-slate-500 mb-6">
              If you leave now, this recipe will <span className="font-bold text-rose-600">NOT be saved</span> and will not appear in your History.
            </p>
            <div className="flex gap-3">
              <button
                onClick={() => { setShowNavGuardModal(false); setPendingNavUrl(null); }}
                className="flex-1 h-11 rounded-2xl bg-slate-100 text-slate-700 font-semibold text-sm"
              >Stay</button>
              <button
                onClick={() => {
                  const url = pendingNavUrl;
                  navigationGuard.clear();
                  setShowNavGuardModal(false);
                  setPendingNavUrl(null);
                  if (url) window.location.href = url;
                }}
                className="flex-1 h-11 rounded-2xl bg-rose-500 text-white font-semibold text-sm"
              >Leave</button>
            </div>
          </div>
        </div>
      )}
      </div>
    </>
  );
}

