/* ── ANDROID WRAPPER SAFE-AREA INSETS ─────────────────────────────────────
   The native Android shell injects per-edge inset values via CSS variables:
     --saw-inset-top, --saw-inset-bottom, --saw-inset-left, --saw-inset-right
   These update automatically on rotation, keyboard show/hide, etc.

   On regular browsers / web preview these vars are unset, so we fall back to
   env(safe-area-inset-*) and finally to 0px. This gives true cross-platform
   notch/status-bar padding without any JS.

   Usage in components:  padding-top: var(--safe-area-top);
*/
:root {
  /* Hard-floor safe-area insets with sensible fallbacks.
     Android WebViews and TWAs often return 0 from env(), which causes the
     status bar to overlap the header and the gesture bar to overlap the
     bottom nav. We enforce a minimum of 24px top and 24px bottom so content
     is ALWAYS visible regardless of platform. Real notches (iOS, Android
     with display cutouts) report >24px and naturally win via max(). */
  --safe-area-top:    max(env(safe-area-inset-top, 24px),    var(--saw-inset-top, 0px), 24px);
  --safe-area-bottom: max(env(safe-area-inset-bottom, 24px), var(--saw-inset-bottom, 0px), 24px);
  --safe-area-left:   max(env(safe-area-inset-left, 0px),    var(--saw-inset-left, 0px), 0px);
  --safe-area-right:  max(env(safe-area-inset-right, 0px),   var(--saw-inset-right, 0px), 0px);

  /* Short aliases per spec */
  --safe-top:    var(--safe-area-top);
  --safe-bottom: var(--safe-area-bottom);
}

/* Inside the Android wrapper, the native shell already positions the WebView
   BELOW the status bar, so we trust --saw-inset-top exactly (no floor).
   For the bottom we floor at 34px because gesture-nav devices can report 0
   while still rendering a translucent gesture pill over the WebView. */
html[data-android-wrapper="true"] {
  --safe-area-top:    var(--saw-inset-top, 0px);
  --safe-area-bottom: max(var(--saw-inset-bottom, 0px), 34px);
  --safe-area-left:   var(--saw-inset-left, 0px);
  --safe-area-right:  var(--saw-inset-right, 0px);
}

/* ── TEXT-ONLY RTL SUPPORT (No layout flipping) ─────────────────────── */
/* App layout stays LTR always. RTL languages only adapt text content direction. */

/* Text direction for input/textarea only (content, not layout) */
:lang(he) input, :lang(ar) input,
