/* ── BIDI ISOLATION UTILITIES ────────────────────────────────────────── */

/* Force element to LTR — use on English tokens, numbers, dates, badges inside RTL text */
.bidi-ltr {
  direction: ltr !important;
  unicode-bidi: isolate !important;
  display: inline;
}

/* Force element to RTL — use on RTL text inside LTR block */
.bidi-rtl {
  direction: rtl !important;
  unicode-bidi: isolate !important;
  display: inline;
}

/* Bidi-safe block container — layout stays LTR but text aligns RTL */
.bidi-rtl-block {
  direction: rtl;
