import { useEffect } from 'react';
import { Outlet } from 'react-router-dom';
import { useAuth } from '@/lib/AuthContext';
import UserNotRegisteredError from '@/components/UserNotRegisteredError';

const DefaultFallback = () => (
  <div className="fixed inset-0 flex items-center justify-center">
    <div className="w-8 h-8 border-4 border-slate-200 border-t-slate-800 rounded-full animate-spin"></div>
  </div>
);

export default function ProtectedRoute({ fallback = <DefaultFallback />, unauthenticatedElement }) {
  const { isAuthenticated, isLoadingAuth, authChecked, authError, checkUserAuth } = useAuth();

  useEffect(() => {
    if (!authChecked && !isLoadingAuth) {
      checkUserAuth();
    }
  }, [authChecked, isLoadingAuth, checkUserAuth]);

  if (isLoadingAuth || !authChecked) {
    return fallback;
  }

  if (authError) {
    if (authError.type === 'user_not_registered') {
      return <UserNotRegisteredError />;
    }
    return unauthenticatedElement;
  }

  if (!isAuthenticated) {
    return unauthenticatedElement;
  }

  return <Outlet />;
}

/**
 * SafeNavigationLink — Navigate to entity detail pages safely
 * Falls back to a page if entity not found or route is invalid
 */
import React from 'react';
import { Link } from 'react-router-dom';
import { createPageUrl } from '../utils';
import { toast } from 'sonner';

export default function SafeNavigationLink({
  entityName,
  entityId,
  fallbackPage,
  fallbackId,
  children,
  className = '',
  onClick,
}) {
  const handleClick = async (e) => {
    // Allow normal link behavior
    if (onClick) {
      onClick(e);
    }
  };

  // Always use the entity link first, with fallback available
  const targetUrl = createPageUrl(`${entityName}Detail`, { id: entityId });
  const fallbackUrl = fallbackId ? createPageUrl(fallbackPage, { id: fallbackId }) : createPageUrl(fallbackPage);

  return (
    <Link
      to={targetUrl}
      className={className}
      onClick={handleClick}
      onError={() => {
        toast.error('Invalid route');
        // Redirect to fallback
        window.location.href = fallbackUrl;
      }}
    >
      {children}
    </Link>
  );
}

