 * Server-authoritative computation of tier level based on total_ratings_received
 * SINGLE SOURCE OF TRUTH — NO CLIENT-SIDE TIER COMPUTATION
 */

export const RATING_TIERS = [
  {
    threshold: 0,
    tier_key: "starter_chef",
    tier_name: "Starter Chef",
    icon_key: "chef_hat_outline",
    color_key: "slate",
