    tier_name: "Trusted Cook",
    icon_key: "silver_star_medal",
    color_key: "silver",
    description: "Recipes people trust"
  },
  {
    threshold: 500,
    tier_key: "community_favorite",
    tier_name: "Community Favorite",
    icon_key: "gold_heart_medal",
    color_key: "gold",
    description: "A fan favorite"
  },
  {
    threshold: 1000,
    tier_key: "pro_creator",
    tier_name: "Pro Creator",
    icon_key: "gold_crown_sparkle",
    color_key: "gold",
    description: "Professional reputation"
  },
  {
    threshold: 5000,
    tier_key: "elite_chef",
    tier_name: "Elite Chef",
    icon_key: "platinum_crown",
    color_key: "platinum",
    description: "Elite status achieved"
  },
  {
    threshold: 10000,
    tier_key: "legend",
    tier_name: "Legend",
    icon_key: "diamond_crown",
    color_key: "diamond",
    description: "A true legend"
  },
  {
    threshold: 50000,
    tier_key: "mythic",
    tier_name: "Mythic Chef",
    icon_key: "royal_crown_aura",
    color_key: "mythic",
    description: "Transcendent culinary creator"
  }
];

/**
 * Compute tier from total ratings received
 * Returns the highest tier the user qualifies for
 */
export function computeRatingTier(totalRatingsReceived) {
  for (let i = RATING_TIERS.length - 1; i >= 0; i--) {
    if (totalRatingsReceived >= RATING_TIERS[i].threshold) {
      const tier = RATING_TIERS[i];
      const nextTier = i < RATING_TIERS.length - 1 ? RATING_TIERS[i + 1] : null;
      return {
        ...tier,
        next_threshold: nextTier?.threshold || null,
        progress_to_next: nextTier ? Math.min(100, Math.round((totalRatingsReceived / nextTier.threshold) * 100)) : 100,
        current_progress: totalRatingsReceived
      };
    }
  }
  return RATING_TIERS[0];
}

/**
 * Get tier by tier_key
 */
export function getTierByKey(tierKey) {
  return RATING_TIERS.find(t => t.tier_key === tierKey) || RATING_TIERS[0];
}

import React, { useMemo } from 'react';
