/**
 * InlineProgressLabel — Small progress indicator to embed in buttons
 * 
 * Shows: "Sending (34%)" or "Generating (62%)" with optional tiny progress bar
 * No reduced motion animation needed (small scale)
 */
export default function InlineProgressLabel({
  isLoading,
  progress = 0,
  label = 'Processing',
  variant = 'compact', // 'compact' (text only) or 'bar' (with progress bar)
}) {
  const prefersReducedMotion = useMemo(() => {
    if (typeof window === 'undefined') return false;
    return window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  }, []);

  if (!isLoading) return null;

  if (variant === 'bar') {
    return (
      <div className="flex items-center gap-1.5">
        <div className="w-12 h-1.5 bg-white/20 rounded-full overflow-hidden">
          <div
            className="h-full bg-white rounded-full transition-all duration-300"
            style={{ width: `${Math.min(progress, 100)}%` }}
          />
        </div>
        <span className="text-xs font-semibold text-white min-w-[28px]">{progress}%</span>
      </div>
    );
  }

  // Compact: text only
  return (
    <div className="flex items-center gap-1">
      {!prefersReducedMotion && <Loader2 className="w-3.5 h-3.5 text-white animate-spin" />}
      <span className="text-sm font-semibold text-white">{label} ({progress}%)</span>
    </div>
  );
}

