  return null;
}

import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';

/**
 * SmartProgressIndicator — feels alive throughout the entire duration.
 * Uses smart progress model: fast early, moderate middle, slower/shimmer near completion.
 */
export default function SmartProgressIndicator({ isLoading, progress = 0 }) {
  const [displayProgress, setDisplayProgress] = useState(0);
  const [shimmerActive, setShimmerActive] = useState(false);

  useEffect(() => {
    if (!isLoading) {
      setDisplayProgress(100);
      return;
    }

    // Smart progress model:
    // 0-30%: fast (ramp in 1 second)
    // 30-70%: moderate (ramp in 3 seconds)
    // 70-95%: slow (ramp in 4 seconds)
    // 95+%: shimmer/pulse (stays alive visually)

    const interval = setInterval(() => {
      setDisplayProgress(prev => {
        if (prev >= 95) {
          // Activate shimmer near end to show continuous activity
          setShimmerActive(true);
          return prev;
        }

        // Increment based on current level
        if (prev < 30) return Math.min(prev + 8, 30);
        if (prev < 70) return Math.min(prev + 2, 70);
        return Math.min(prev + 0.8, 95);
      });
    }, 200);

    return () => clearInterval(interval);
  }, [isLoading]);

  return (
    <div className="w-full h-1 rounded-full overflow-hidden bg-white/30 relative">
      <motion.div
        animate={{ width: `${displayProgress}%` }}
        transition={{ duration: 0.3, ease: 'easeOut' }}
        className="h-full bg-white rounded-full relative overflow-hidden"
      >
        {shimmerActive && (
          <motion.div
            animate={{
              x: ['−100%', '100%'],
            }}
            transition={{
              duration: 1.5,
              repeat: Infinity,
              ease: 'easeInOut',
            }}
            className="absolute inset-0"
            style={{
              background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.4), transparent)',
              backgroundSize: '200% 100%',
            }}
          />
        )}
      </motion.div>
    </div>
  );
}

