            disabled={isLoading_accept || isLoading_decline}
            whileTap={{ scale: 0.95 }}
            className="flex-1 h-8 rounded-lg bg-black/20 hover:bg-black/30 text-white text-xs font-semibold flex items-center justify-center gap-1 disabled:opacity-50 backdrop-blur-sm border border-white/20 transition-all"
