import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Heart, Bookmark, Star, UserPlus, Mail, Bell } from 'lucide-react';
import { base44 } from '@/api/base44Client';
import UserProfileNavigator from '../profile/UserProfileNavigator';

const NOTIFICATION_TYPES = [
  { id: 'likes', label: 'Likes', icon: Heart, color: 'text-red-500' },
  { id: 'saves', label: 'Saves', icon: Bookmark, color: 'text-amber-500' },
  { id: 'ratings', label: 'Ratings', icon: Star, color: 'text-yellow-500' },
  { id: 'follows', label: 'Follows', icon: UserPlus, color: 'text-green-500' },
  { id: 'requests', label: 'Requests', icon: Mail, color: 'text-blue-500' },
  { id: 'updates', label: 'Updates', icon: Bell, color: 'text-indigo-500' },
];

export default function NotificationsScreenV2({ currentUserId }) {
  const [notifications, setNotifications] = useState([]);
  const [selectedType, setSelectedType] = useState('likes');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadNotifications();
  }, [selectedType]);

  const loadNotifications = async () => {
    setLoading(true);
    try {
      // Fetch all notifications for current user
      const notifs = await base44.entities.Notification.filter(
        { recipient_id: currentUserId },
        '-created_at',
        100
      ) || [];

      // Filter by type
      const filtered = notifs.filter(n => n.notification_type === selectedType);
      setNotifications(filtered);

      // Mark as read
      const unreadIds = filtered.filter(n => !n.is_read).map(n => n.id);
      for (const id of unreadIds) {
        await base44.entities.Notification.update(id, { is_read: true });
      }
    } catch (err) {
      console.error('[NotificationsScreenV2]', err.message);
    } finally {
      setLoading(false);
    }
  };

  const getTypeConfig = (type) => {
    return NOTIFICATION_TYPES.find(t => t.id === type);
  };

  const config = getTypeConfig(selectedType);
  const TypeIcon = config?.icon || Bell;

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <div className="bg-white border-b border-slate-100 p-4">
        <h1 className="text-2xl font-bold text-slate-900 mb-4">Notifications</h1>

        {/* Type chips */}
        <div className="flex gap-2 overflow-x-auto hide-scrollbar">
          {NOTIFICATION_TYPES.map(type => (
            <button
              key={type.id}
              onClick={() => setSelectedType(type.id)}
              className={`px-3 py-1.5 rounded-full text-sm font-medium whitespace-nowrap transition-all flex items-center gap-1.5 ${
                selectedType === type.id
                  ? 'bg-indigo-600 text-white'
                  : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
              }`}
            >
              <type.icon className="w-4 h-4" />
              {type.label}
            </button>
          ))}
        </div>
      </div>

      {/* Content */}
      <div className="p-4">
        {loading ? (
          <div className="space-y-3">
            {[1, 2, 3].map(i => (
              <div key={i} className="h-16 rounded-2xl bg-white animate-pulse" />
            ))}
          </div>
        ) : notifications.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 text-center">
            <TypeIcon className="w-12 h-12 text-slate-300 mb-3" />
            <p className="text-slate-500 text-sm">No {config?.label.toLowerCase()} yet</p>
          </div>
        ) : (
          <div className="space-y-2">
            <AnimatePresence mode="popLayout">
              {notifications.map(notif => (
                <NotificationItem
                  key={notif.id}
                  notification={notif}
                  typeConfig={config}
                />
              ))}
            </AnimatePresence>
          </div>
        )}
      </div>
    </div>
  );
}

function NotificationItem({ notification, typeConfig }) {
  const TypeIcon = typeConfig?.icon || Bell;
  const relativeTime = getRelativeTime(new Date(notification.created_at));

  return (
    <motion.div
      layout
      initial={{ opacity: 0, x: -20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: 20 }}
      className="bg-white rounded-2xl p-4 flex gap-3 items-center hover:bg-slate-50 transition-colors"
    >
      {/* Actor Avatar */}
      <UserProfileNavigator userId={notification.actor_id}>
        <div className="w-12 h-12 rounded-full bg-gradient-to-br from-indigo-400 to-purple-500 flex items-center justify-center text-white text-sm font-bold flex-shrink-0 cursor-pointer">
          {notification.actor_avatar_url ? (
            <img
              src={notification.actor_avatar_url}
              alt=""
              className="w-full h-full object-cover rounded-full"
            />
          ) : (
            (notification.actor_name || 'U')[0].toUpperCase()
          )}
        </div>
      </UserProfileNavigator>

      {/* Content */}
      <div className="flex-1 min-w-0">
        <p className="text-sm text-slate-900 font-medium">
          {notification.message || 'New notification'}
        </p>
        <p className="text-xs text-slate-500 mt-0.5">{relativeTime}</p>
      </div>

      {/* Type Icon Badge */}
      <div className={`w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center flex-shrink-0 ${typeConfig?.color}`}>
        <TypeIcon className="w-4 h-4" />
      </div>

      {/* CTA Button (for requests) */}
      {notification.notification_type === 'requests' && notification.action_type === 'follow_request' && (
        <button
          onClick={() => handleAcceptRequest(notification.id)}
          className="px-3 py-1.5 rounded-lg bg-indigo-600 text-white text-xs font-semibold hover:bg-indigo-700"
        >
          Accept
        </button>
      )}
    </motion.div>
  );
}

function getRelativeTime(date) {
  const now = new Date();
  const diffMs = now - date;
  const diffMins = Math.floor(diffMs / (1000 * 60));

  if (diffMins < 1) return 'Just now';
  if (diffMins < 60) return `${diffMins}m ago`;

  const diffHours = Math.floor(diffMins / 60);
  if (diffHours < 24) return `${diffHours}h ago`;

  const diffDays = Math.floor(diffHours / 24);
  return `${diffDays}d ago`;
}

async function handleAcceptRequest(notificationId) {
  try {
    // Accept the request (e.g., follow, group join)
    await base44.entities.Notification.update(notificationId, {
      is_read: true,
      is_accepted: true,
    });
  } catch (err) {
    console.error('[handleAcceptRequest]', err.message);
  }
}

