function getRelativeTime(date) {
  const now = new Date();
  const diffMins = Math.floor((now - date) / (1000 * 60));

  if (diffMins < 1) return 'Just now';
  if (diffMins < 60) return `${diffMins}m ago`;

  const diffHours = Math.floor(diffMins / 60);
  if (diffHours < 24) return `${diffHours}h ago`;

  return `${Math.floor(diffHours / 24)}d ago`;
}

import React, { useEffect, useState, useRef } from 'react';
import { createContext, useContext } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageCircle } from 'lucide-react';
import { createPageUrl } from '../../utils';

const NotificationContext = createContext();

export function NotificationProvider({ children }) {
  const [banner, setBanner] = useState(null);
  const timerRef = useRef(null);

  const showNotification = (notification) => {
    // Issue 5: Suppress DM banners when user is already in ChatList or same DM thread
    if (notification.type === 'dm') {
      const path = window.location.pathname;
      if (path === '/ChatList') return;
      if (path === '/Messages') {
        const params = new URLSearchParams(window.location.search);
        const activeSender = params.get('userId');
        if (activeSender && activeSender === notification.sender_id) return;
      }
    }
    if (timerRef.current) clearTimeout(timerRef.current);
    setBanner(notification);
    timerRef.current = setTimeout(() => setBanner(null), 4000);
  };

  return (
    <NotificationContext.Provider value={{ showNotification }}>
      {children}
      <AnimatePresence>
        {banner && <NotificationBannerDisplay key={banner.from_name + banner.message} notification={banner} onDismiss={() => setBanner(null)} />}
      </AnimatePresence>
    </NotificationContext.Provider>
  );
}

export function useNotificationBanner() {
  const context = useContext(NotificationContext);
  if (!context) throw new Error('useNotificationBanner must be used within NotificationProvider');
  return context;
}

function NotificationBannerDisplay({ notification, onDismiss }) {
  const isDM = notification.type === 'dm';

  const handleTap = () => {
    onDismiss();
    if (isDM && notification.sender_id) {
      window.location.href = createPageUrl("Messages") + `?userId=${notification.sender_id}`;
    }
  };

  return (
    <motion.div
      initial={{ y: -80, opacity: 0 }}
      animate={{ y: 0, opacity: 1 }}
      exit={{ y: -80, opacity: 0 }}
      transition={{ type: 'spring', damping: 28, stiffness: 320 }}
      className="fixed top-4 left-4 right-4 z-[200] max-w-sm mx-auto"
      onClick={handleTap}
    >
      <div
        className="flex items-center gap-3 px-4 py-3 rounded-2xl cursor-pointer active:scale-[0.98] transition-transform"
        style={{
          background: isDM ? 'linear-gradient(135deg, #f0f4ff 0%, #fff 100%)' : '#fff',
          boxShadow: '0 8px 32px rgba(0,0,0,0.12), 0 1px 4px rgba(0,0,0,0.06)',
          border: isDM ? '1px solid rgba(99,102,241,0.18)' : '1px solid rgba(0,0,0,0.06)',
        }}
      >
        {/* Avatar */}
        {notification.avatar ? (
          <img src={notification.avatar} alt="" className="w-10 h-10 rounded-full object-cover flex-shrink-0 border-2 border-white shadow-sm" />
        ) : (
          <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${isDM ? 'bg-gradient-to-br from-indigo-500 to-purple-500' : 'bg-gradient-to-br from-indigo-400 to-purple-500'}`}>
            {isDM
              ? <MessageCircle className="w-5 h-5 text-white" />
              : <span className="text-white text-sm font-bold">{(notification.from_name || notification.title || '?')[0].toUpperCase()}</span>
            }
          </div>
        )}

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-1.5 mb-0.5">
            {isDM && (
              <span className="text-[10px] font-bold text-indigo-500 bg-indigo-50 px-1.5 py-0.5 rounded-full uppercase tracking-wide">DM</span>
            )}
            <p className="text-sm font-bold text-slate-900 truncate">
              {notification.from_name || notification.title}
            </p>
          </div>
          {notification.message && (
            <p className="text-xs text-slate-500 truncate">{notification.message}</p>
          )}
        </div>

        <div className={`w-2 h-2 rounded-full flex-shrink-0 ${isDM ? 'bg-indigo-500' : 'bg-indigo-400'}`} />
      </div>
    </motion.div>
  );
}

