export default function EntryNotificationPopup({
  isOpen,
  likesCount     = 0,
  followersCount = 0,
  reviewsCount   = 0,
  mentionsCount  = 0,
  onDismiss,
  onNavigate,
}) {
  const { t } = useLocalization();
  const [visible, setVisible] = useState(false);
  const [sweepKey, setSweepKey] = useState(0);
  const holdRef = useRef(null);
  const exitRef = useRef(null);

  const triggerExit = (cb) => {
    clearTimeout(holdRef.current);
    setVisible(false);
    exitRef.current = setTimeout(cb, EXIT_MS + 50);
  };

  useEffect(() => {
    if (!isOpen) {
      clearTimeout(holdRef.current);
      clearTimeout(exitRef.current);
      setVisible(false);
      return;
    }
    setVisible(true);
    setSweepKey(k => k + 1);
    clearTimeout(holdRef.current);
    holdRef.current = setTimeout(
      () => triggerExit(() => onDismiss?.()),
      ENTRY_MS + HOLD_MS
    );
    return () => { clearTimeout(holdRef.current); clearTimeout(exitRef.current); };
  }, [isOpen]); // eslint-disable-line

  const rows = [
    likesCount     > 0 && { type: 'likes',     count: likesCount     },
    followersCount > 0 && { type: 'followers', count: followersCount },
    reviewsCount   > 0 && { type: 'reviews',   count: reviewsCount   },
    mentionsCount  > 0 && { type: 'mentions',  count: mentionsCount  },
  ].filter(Boolean);

  if (rows.length === 0) return null;

  return (
    <AnimatePresence>
      {visible && (
        <motion.div
          key="entry-notif"
          initial={{ opacity: 0, y: 18, scale: 0.93 }}
          animate={{ opacity: 1, y: 0,  scale: 1    }}
          exit={{    opacity: 0, y: -8,  scale: 0.96 }}
          transition={{ duration: ENTRY_MS / 1000, ease: [0.22, 1, 0.36, 1] }}
          drag="y"
          dragConstraints={{ top: 0, bottom: 80 }}
          dragElastic={{ top: 0, bottom: 0.16 }}
          onDragEnd={(_, info) => { if (info.offset.y > 24) triggerExit(() => onDismiss?.()); }}
          onClick={() => triggerExit(() => { onDismiss?.(); onNavigate?.(); })}
          style={{
            position: 'fixed',
            zIndex: 120,
            bottom: 'calc(env(safe-area-inset-bottom, 0px) + 82px)',
            right: 14,
            width: 'min(220px, calc(100vw - 22px))',
            cursor: 'pointer',
            userSelect: 'none',
          }}
        >
          {/* Subtle glow behind card */}
          <div style={{
            position: 'absolute',
            inset: 0,
            borderRadius: 18,
            background: 'radial-gradient(ellipse at 50% 130%, rgba(225,29,72,0.14) 0%, transparent 68%)',
            filter: 'blur(10px)',
            transform: 'scale(1.1) translateY(8px)',
            pointerEvents: 'none',
          }} />

          {/* Card shell */}
          <div style={{
            position: 'relative',
            borderRadius: 18,
            overflow: 'hidden',
            background: '#ffffff',
            border: '1px solid rgba(225,29,72,0.10)',
            boxShadow: '0 8px 30px rgba(0,0,0,0.11), 0 2px 6px rgba(0,0,0,0.05)',
          }}>

            {/* Top accent bar */}
            <div style={{
              height: 2.5,
              background: 'linear-gradient(90deg, #e11d48 0%, #f43f5e 45%, #fb7185 75%, #fda4af 100%)',
            }} />

            {/* One-time shimmer on entry */}
            <motion.div
              key={sweepKey}
              initial={{ x: '-110%' }}
              animate={{ x: '220%' }}
              transition={{ delay: (ENTRY_MS / 1000) * 0.4, duration: 0.65, ease: 'easeOut' }}
              style={{
                position: 'absolute',
                top: 0, bottom: 0, width: '45%',
                background: 'linear-gradient(105deg, transparent 15%, rgba(255,255,255,0.5) 50%, transparent 85%)',
                pointerEvents: 'none',
                zIndex: 1,
              }}
            />

            {/* Content */}
            <div style={{ padding: '8px 10px 9px 11px', position: 'relative', zIndex: 2 }}>

              {/* Header: label + close */}
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 7 }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
                  <motion.div
                    animate={{ scale: [1, 1.35, 1], opacity: [1, 0.55, 1] }}
                    transition={{ duration: 1.8, repeat: Infinity, ease: 'easeInOut' }}
                    style={{ width: 5, height: 5, borderRadius: '50%', background: '#e11d48', flexShrink: 0 }}
                  />
                  <span style={{
                    fontSize: 8,
                    fontWeight: 700,
                    textTransform: 'uppercase',
                    letterSpacing: '0.12em',
                    color: '#9ca3af',
                  }}>
                    {t('notif.while_away', 'While you were away')}
                  </span>
                </div>

                <button
                  data-no-min-height
                  onClick={e => { e.stopPropagation(); triggerExit(() => onDismiss?.()); }}
                  style={{
                    width: 16, height: 16,
                    borderRadius: '50%',
                    background: 'rgba(156,163,175,0.12)',
                    border: 'none',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    cursor: 'pointer',
                    flexShrink: 0,
                    padding: 0,
                    fontSize: 9,
                    color: '#9ca3af',
                    fontWeight: 700,
                    lineHeight: 1,
                    minHeight: 'unset',
