              </div>

              {/* Rows — compact, icon-first */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                {rows.map((row, i) => (
                  <NotifRow key={row.type} type={row.type} count={row.count} rowIndex={i} />
