export default function ModerationNotificationCard({
  notification,
  onClick,
  onAvatarClick,
}) {
  const { t } = useLocalization();
  // Resolve action type — check both moderation_action (legacy account actions)
  // and payload_json.action_type (post moderation events)
  const tryParsePayload = (str) => { try { return str ? JSON.parse(str) : {}; } catch { return {}; } };
  const payload = tryParsePayload(notification.payload_json);
  const actionType = notification.moderation_action || payload?.action_type || 'content_removed';

  const config = MODERATION_CONFIG[actionType] || MODERATION_CONFIG.content_removed;
  const Icon = config.icon;

  const getDurationText = () => {
    if (actionType === 'timeout' && notification.duration_days) {
      const days = Math.floor(notification.duration_days);
      const hours = Math.round((notification.duration_days - days) * 24);
      if (days > 0 && hours > 0) return `${days}d ${hours}h`;
      if (days > 0) return `${days} day${days > 1 ? 's' : ''}`;
      if (hours > 0) return `${hours} hour${hours > 1 ? 's' : ''}`;
      return "Timeout";
    }
    return null;
  };

  const durationText = getDurationText();

  // Subtitle: dynamic for timeout, static from config for others
  // Resolve title and subtitle via t() when keys exist, otherwise use legacy static fields
  const title = config.titleKey
    ? t(config.titleKey, config.titleFallback || config.title)
    : config.title;

  const subtitle = actionType === 'timeout'
    ? `${t('notifications.timed_out_for', 'Timed out for')} ${durationText}`
    : config.subtitleKey
    ? t(config.subtitleKey, config.subtitleFallback || config.subtitle)
    : config.subtitle;

  return (
    <motion.button
      onClick={onClick}
      initial={{ opacity: 0, x: 50, scale: 0.95 }}
      animate={{ opacity: 1, x: 0, scale: 1 }}
      exit={{ opacity: 0, x: 50, scale: 0.95 }}
      whileHover={{ scale: 1.02 }}
      whileTap={{ scale: 0.98 }}
      className={cn(
        "w-full text-left bg-gradient-to-br p-4 rounded-xl shadow-lg hover:shadow-xl transition-all relative overflow-hidden",
        config.gradient
