/**
 * PriceDisplay — Global canonical price display component.
 *
 * This is THE SINGLE component to use for ALL price rendering in the app.
 * It handles:
 * - Currency conversion from USD to user's selected currency
 * - Symbol formatting (₪, $, €, etc.)
 * - Zero/null/undefined graceful handling
 * - Compact/regular formatting
 *
 * Usage:
 *   <PriceDisplay usdAmount={recipe.total_cost} />
 *   <PriceDisplay usdAmount={recipe.cost_per_serving} label="per serving" />
 *   <PriceDisplay usdAmount={ingredient.price} variant="inline" />
 */
import React from 'react';
import { useLocalization } from '@/services/localization/LocalizationContext';

export default function PriceDisplay({
  usdAmount,
  label,
  className = '',
  variant = 'default',   // 'default' | 'inline' | 'large' | 'badge' | 'small'
  hideIfZero = true,     // hides if 0 or null
  fallback = null,       // what to show if no price (null = nothing)
}) {
  const { formatPrice } = useLocalization();

  const amount = Number(usdAmount);
  const isEmpty = usdAmount == null || isNaN(amount) || (hideIfZero && amount === 0);

  if (isEmpty) {
    return fallback ? <span className={className}>{fallback}</span> : null;
  }

  const formatted = formatPrice(amount);

  if (!formatted) {
    return fallback ? <span className={className}>{fallback}</span> : null;
  }

  if (variant === 'inline') {
    return (
      <span className={`font-semibold ${className}`}>
        {formatted}
        {label && <span className="font-normal text-slate-400 ml-1 text-xs">{label}</span>}
      </span>
    );
  }

  if (variant === 'large') {
    return (
      <span className={`text-xl font-bold ${className}`}>
        {formatted}
        {label && <span className="text-sm font-normal text-slate-400 ml-1">{label}</span>}
      </span>
    );
  }

  if (variant === 'badge') {
    return (
      <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold bg-amber-50 text-amber-700 border border-amber-200 ${className}`}>
        {formatted}
        {label && <span className="opacity-70">{label}</span>}
      </span>
    );
  }

  if (variant === 'small') {
    return (
      <span className={`text-xs font-medium ${className}`}>
        {formatted}
        {label && <span className="text-slate-400 ml-0.5">{label}</span>}
      </span>
    );
  }

  // default
  return (
    <span className={`font-medium ${className}`}>
      {formatted}
      {label && <span className="text-slate-400 ml-1 text-xs">{label}</span>}
    </span>
  );
}

/**
 * ResponsivePrice — Adaptive currency display component.
 * 
 * Automatically resizes font, padding, and container to prevent
 * overflow when currency strings are long (e.g. IDR, VND, KRW).
 */

import React, { useRef, useState, useLayoutEffect, useMemo } from "react";
import { useLocalization } from "@/services/localization/LocalizationContext";
import { cn } from "@/lib/utils";

// Length thresholds for automatic font/size adaptation
const LENGTH_THRESHOLDS = [
  { maxLen: 6,  fontSize: "text-sm",  px: "px-3",   py: "py-1",   minW: "" },
  { maxLen: 8,  fontSize: "text-sm",  px: "px-2.5", py: "py-1",   minW: "" },
  { maxLen: 11, fontSize: "text-xs",  px: "px-2",   py: "py-0.5", minW: "" },
  { maxLen: 14, fontSize: "text-xs",  px: "px-1.5", py: "py-0.5", minW: "" },
  { maxLen: 999, fontSize: "text-[10px]", px: "px-1", py: "py-0.5", minW: "" },
];

function getSizeConfig(text) {
  const len = (text || "").length;
  return LENGTH_THRESHOLDS.find(t => len <= t.maxLen) || LENGTH_THRESHOLDS[LENGTH_THRESHOLDS.length - 1];
}

// Pill / badge variant (used in recipe cards, post cards, ingredient lists)
export function PriceTag({ usdAmount, className, variant = "pill" }) {
  const { formatPrice } = useLocalization();

  if (usdAmount == null || isNaN(Number(usdAmount)) || Number(usdAmount) <= 0) {
    return null;
  }

  const formatted = formatPrice(Number(usdAmount));
  if (!formatted) return null;

  const config = getSizeConfig(formatted);

  if (variant === "plain") {
    return (
      <span className={cn("font-bold tabular-nums whitespace-nowrap", config.fontSize, className)}>
        {formatted}
      </span>
    );
  }

  if (variant === "pill") {
    return (
      <span
        className={cn(
          "inline-flex items-center justify-center font-bold rounded-full whitespace-nowrap tabular-nums",
          "bg-emerald-50 text-emerald-700 border border-emerald-200",
          config.fontSize, config.px, config.py, className
        )}
        title={formatted}
      >
        {formatted}
      </span>
    );
  }

  if (variant === "badge") {
    return (
      <span
        className={cn(
          "inline-flex items-center justify-center font-bold rounded-xl whitespace-nowrap tabular-nums",
          "bg-white/90 text-slate-800 shadow-sm",
          config.fontSize, config.px, config.py, className
        )}
        title={formatted}
      >
        {formatted}
      </span>
    );
  }

  if (variant === "dark") {
    return (
      <span
        className={cn(
          "inline-flex items-center justify-center font-bold rounded-xl whitespace-nowrap tabular-nums",
          "bg-slate-900 text-white",
          config.fontSize, config.px, config.py, className
        )}
        title={formatted}
      >
        {formatted}
      </span>
    );
  }

  return (
    <span className={cn("font-bold tabular-nums whitespace-nowrap", config.fontSize, className)}>
      {formatted}
    </span>
  );
}

// Per serving display
export function PricePerServing({ usdAmount, servings = 1, className }) {
  const { formatPrice, t } = useLocalization();

  if (usdAmount == null || isNaN(Number(usdAmount)) || Number(usdAmount) <= 0) {
    return null;
  }

  const perServing = Number(usdAmount) / Math.max(1, servings);
  const formatted = formatPrice(perServing);
  if (!formatted) return null;

  const config = getSizeConfig(formatted);

  return (
    <span className={cn("tabular-nums whitespace-nowrap text-slate-500", config.fontSize, className)}>
      <span className="font-semibold text-slate-700">{formatted}</span>
      <span className="ml-1 font-normal">{t("common.pricePerServing", "per serving")}</span>
    </span>
  );
}

// Full price row with total + per serving
export function PriceRow({ totalUsd, servings, className }) {
  const { formatPrice, t } = useLocalization();

  if (!totalUsd || isNaN(Number(totalUsd)) || Number(totalUsd) <= 0) return null;

  const formattedTotal = formatPrice(Number(totalUsd));
