// Inline text price — for sentences/descriptions
export function InlinePrice({ usdAmount, className }) {
  const { formatPrice } = useLocalization();
  if (usdAmount == null || isNaN(Number(usdAmount))) return null;
  const formatted = formatPrice(Number(usdAmount));
  if (!formatted) return null;
  return <span className={cn("font-semibold tabular-nums whitespace-nowrap", className)}>{formatted}</span>;
}

export default PriceTag;

/**
 * MentionText — Renders text with @mention tokens as blue clickable profile links.
 *
 * SYSTEM 4: All surfaces that display user-generated text (group chat bubbles,
 * post captions, DM messages) should use this component instead of a plain <p> or <span>.
 *
 * Usage:
 *   <MentionText text={message.content} className="text-sm text-slate-900" />
 *
 * How it works:
 * - Splits text on @word boundaries using a regex.
 * - For each @handle token, renders a clickable blue span.
 * - Clicking a mention navigates to UserProfile search by username.
 * - Non-mention text is rendered as plain text nodes.
 *
 * NOTE: This renderer works with the text as-is (no server-side user_id resolution needed).
 * The profile page accepts ?username= as a lookup param alongside ?userId=.
 * If the username resolves to a real user, the profile page shows them.
 * If not, it shows the not-found state (no fake fallback).
 */
import React from 'react';
import { createPageUrl } from '../../utils';

// Non-global regex for split — produces alternating [plain, @mention, plain, @mention, ...]
const MENTION_SPLIT_REGEX = /(@[\w\u0080-\uFFFF]+)/;
// Non-global test regex — stateless, safe to call repeatedly
const MENTION_TEST_REGEX = /^@[\w\u0080-\uFFFF]+$/;

function MentionToken({ handle, mentionStyle }) {
  const username = handle.slice(1); // strip leading @

  const handleClick = (e) => {
    e.stopPropagation();
    e.preventDefault();
    // Navigate to user profile by username lookup — UserProfile resolves ?username= to userId
    window.location.href = createPageUrl('UserProfile') + `?username=${encodeURIComponent(username)}`;
  };

  return (
    <span
      role="button"
      tabIndex={0}
      onClick={handleClick}
      onKeyDown={(e) => { if (e.key === 'Enter') handleClick(e); }}
      className="font-semibold cursor-pointer inline"
      style={{ color: '#6366f1', ...mentionStyle }}
    >
      {handle}
    </span>
  );
}

export default function MentionText({ text, className = '', style = {}, mentionStyle = {} }) {
  if (!text) return null;

  // Split on @mention tokens — non-global regex gives stable alternating array
  const parts = text.split(MENTION_SPLIT_REGEX);

  return (
    <span className={className} style={style} dir="auto">
      {parts.map((part, i) =>
        MENTION_TEST_REGEX.test(part)
          ? <MentionToken key={i} handle={part} mentionStyle={mentionStyle} />
          : part
      )}
    </span>
  );
}

/**
 * MentionInput — reusable textarea/input with live @mention suggestions.
 *
 * SYSTEM 4 FIX:
 * - Accepts context props for scoped search eligibility:
 *     context: 'group' | 'dm' | 'post' | 'global'
 *     groupId: string (required when context='group')
 *     participantUserId: string (required when context='dm')
 * - Mention tokens are stored as @handle in the text string.
 * - onMentionNotify(mentionedUserIds[]) is called with all tagged user IDs.
 * - insertMention stores both the handle AND the user ID for later notification.
 *
 * Props:
 *   value, onChange(newValue), placeholder, rows, className, style,
 *   onMentionNotify(mentionedUserIds[])
 *   inputType: "textarea" | "input"
 *   onKeyDown
 *   context: 'group' | 'dm' | 'post' | 'global' (default: 'global')
 *   groupId: string (for group context)
 *   participantUserId: string (for dm context)
 */
import React, { useState, useRef, useCallback, useEffect } from 'react';
import { base44 } from '@/api/base44Client';
import { motion, AnimatePresence } from 'framer-motion';

function Avatar({ name, avatarUrl }) {
  return (
    <div className="w-7 h-7 rounded-full bg-gradient-to-br from-indigo-400 to-purple-400 flex-shrink-0 overflow-hidden flex items-center justify-center">
      {avatarUrl ? (
        <img src={avatarUrl} alt="" className="w-full h-full object-cover" />
      ) : (
        <span className="text-[10px] font-bold text-white">{name?.charAt(0)?.toUpperCase() || '?'}</span>
      )}
    </div>
  );
}

export default function MentionInput({
  value = '',
  onChange,
  placeholder = 'Write something...',
  rows = 3,
  className = '',
  style = {},
  onMentionNotify,
  inputType = 'textarea',
  onKeyDown,
  disabled = false,
  // SYSTEM 4: Context props for scoped mention eligibility
  context = 'global',
  groupId,
  participantUserId,
}) {
  const [suggestions, setSuggestions] = useState([]);
  const [mentionQuery, setMentionQuery] = useState(null);
  const [mentionStart, setMentionStart] = useState(-1);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [selectedIdx, setSelectedIdx] = useState(0);
  const inputRef = useRef(null);
  const dropdownRef = useRef(null);
  const searchTimeout = useRef(null);
  // Map: handle → userId for all inserted mentions this session
  const mentionedMap = useRef(new Map());

  const detectMention = useCallback((text, cursorPos) => {
    const slice = text.slice(0, cursorPos);
    const atIdx = slice.lastIndexOf('@');
    if (atIdx === -1) return null;
    const query = slice.slice(atIdx + 1);
    if (query.includes(' ') || query.includes('\n')) return null;
    return { query, atIdx };
  }, []);

  const handleChange = useCallback((e) => {
    const newVal = e.target.value;
    onChange(newVal);

    const cursor = e.target.selectionStart ?? newVal.length;
    const mention = detectMention(newVal, cursor);

    if (mention !== null) {
      setMentionQuery(mention.query);
      setMentionStart(mention.atIdx);
      setSelectedIdx(0);

      clearTimeout(searchTimeout.current);
      setLoadingSuggestions(true);

      searchTimeout.current = setTimeout(async () => {
        try {
          const res = await base44.functions.invoke('searchUsersForMention', {
            query: mention.query || '',
            context,
            group_id: groupId,
            participant_user_id: participantUserId,
          });
          setSuggestions(res.data?.users || []);
        } catch {
          setSuggestions([]);
        } finally {
          setLoadingSuggestions(false);
        }
      }, mention.query.length === 0 ? 0 : 150);
    } else {
      closeSuggestions();
    }
  }, [onChange, detectMention, context, groupId, participantUserId]);

  const closeSuggestions = () => {
    setSuggestions([]);
    setMentionQuery(null);
    setMentionStart(-1);
    setLoadingSuggestions(false);
    clearTimeout(searchTimeout.current);
  };

  const insertMention = useCallback((user) => {
    const handle = user.username || user.display_name?.replace(/\s+/g, '') || '';
    if (!handle) return;

    const before = value.slice(0, mentionStart);
    const after = value.slice(mentionStart + 1 + (mentionQuery?.length || 0));
    const newVal = `${before}@${handle} ${after}`;
    onChange(newVal);

    // Store mapping: handle → userId (for ping/notification)
    mentionedMap.current.set(handle, user.id);
    onMentionNotify?.([...mentionedMap.current.values()]);

    closeSuggestions();

    setTimeout(() => {
      if (inputRef.current) {
        const pos = before.length + handle.length + 2;
        inputRef.current.focus();
        inputRef.current.setSelectionRange(pos, pos);
      }
    }, 10);
  }, [value, mentionStart, mentionQuery, onChange, onMentionNotify]);

  const handleKeyDown = useCallback((e) => {
    if (suggestions.length > 0) {
      if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIdx(i => Math.min(i + 1, suggestions.length - 1)); return; }
      if (e.key === 'ArrowUp')   { e.preventDefault(); setSelectedIdx(i => Math.max(i - 1, 0)); return; }
      if (e.key === 'Enter' || e.key === 'Tab') { e.preventDefault(); insertMention(suggestions[selectedIdx]); return; }
      if (e.key === 'Escape') { closeSuggestions(); return; }
    }
    onKeyDown?.(e);
  }, [suggestions, selectedIdx, insertMention, onKeyDown]);

  useEffect(() => {
    const handler = (e) => {
      const inInput = inputRef.current?.contains(e.target);
      const inDropdown = dropdownRef.current?.contains(e.target);
      if (!inInput && !inDropdown) closeSuggestions();
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const showDropdown = mentionQuery !== null && (suggestions.length > 0 || loadingSuggestions);

  const inputProps = {
    ref: inputRef,
    value,
    onChange: handleChange,
    onKeyDown: handleKeyDown,
    placeholder,
    disabled,
    className,
    style,
  };

  return (
    <div className="relative w-full">
      {inputType === 'textarea' ? (
        <textarea {...inputProps} rows={rows} />
      ) : (
        <input {...inputProps} type="text" />
      )}

      <AnimatePresence>
        {showDropdown && (
          <motion.div
            ref={dropdownRef}
            initial={{ opacity: 0, y: -6, scale: 0.97 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -6, scale: 0.97 }}
            transition={{ duration: 0.13 }}
            className="absolute left-0 right-0 bottom-full mb-1 z-[200] bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden"
            style={{ maxHeight: 220 }}
          >
            <div className="overflow-y-auto" style={{ maxHeight: 220 }}>
              {loadingSuggestions && suggestions.length === 0 ? (
                <div className="px-4 py-3 text-xs text-slate-400">Searching…</div>
              ) : suggestions.length === 0 ? (
                <div className="px-4 py-3 text-xs text-slate-400">No users found</div>
              ) : (
                suggestions.map((user, idx) => (
                  <button
                    key={user.id}
                    type="button"
                    onMouseDown={(e) => { e.preventDefault(); insertMention(user); }}
                    className={`w-full flex items-center gap-3 px-3 py-2.5 text-left transition-colors ${idx === selectedIdx ? 'bg-indigo-50' : 'hover:bg-slate-50'}`}
                  >
                    <Avatar name={user.display_name} avatarUrl={user.avatar_url} />
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-semibold text-slate-900 truncate">{user.display_name}</p>
                      {user.username && (
                        <p className="text-[11px] text-slate-400 truncate">@{user.username}</p>
                      )}
                    </div>
                  </button>
                ))
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

