export default function ReputationPanelFixed({ isOpen, onClose, totalRatingsReceived = 0 }) {
  // Hide bottom nav while reputation modal is open
  useBottomNavLock(isOpen);

  useEffect(() => {
    if (isOpen) {
      const scrollY = window.scrollY;
      document.body.style.position = "fixed";
      document.body.style.top = `-${scrollY}px`;
      document.body.style.width = "100%";
    } else {
      const top = document.body.style.top;
      document.body.style.position = "";
      document.body.style.top = "";
      document.body.style.width = "";
      if (top) {
        window.scrollTo(0, -parseInt(top));
      }
    }
    return () => {
      const top = document.body.style.top;
      document.body.style.position = "";
      document.body.style.top = "";
      document.body.style.width = "";
      if (top && isOpen) {
        window.scrollTo(0, -parseInt(top));
      }
    };
  }, [isOpen]);

  // Find current tier (highest threshold user qualifies for)
  let currentTierIndex = 0;
  for (let i = TIERS.length - 1; i >= 0; i--) {
    if (totalRatingsReceived >= TIERS[i].threshold) {
      currentTierIndex = i;
      break;
    }
  }
  const currentTier = TIERS[currentTierIndex];

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className="fixed inset-0 z-[98] bg-black/40 backdrop-blur-sm"
        onClick={onClose}
      />

