/**
 * PRICING DEBUG PANEL — dev-only overlay
 * Allows instant testing of pricing calculations
 */
import React, { useState } from "react";
import { base44 } from "@/api/base44Client";
import { Bug, RotateCcw } from "lucide-react";

export default function PricingDebugPanel({ recipe, selectedServings, defaultServings }) {
  const [isOpen, setIsOpen] = useState(false);
  const [isRecomputing, setIsRecomputing] = useState(false);

  if (typeof localStorage === "undefined" || localStorage.getItem("__debug_mode") !== "true") {
    return null;
  }

  const scaleFactor = selectedServings / (defaultServings || 1);
  const scaledTotal = (recipe.total_cost || 0) * scaleFactor;
  const scaledPerServing = scaledTotal / selectedServings;

  const unknownCount = recipe.ingredients?.reduce((acc, group) => {
    return acc + (group.items || []).filter(item => !item.ingredient_cost || item.ingredient_cost <= 0).length;
  }, 0) || 0;

  const pricedCount = recipe.ingredients?.reduce((acc, group) => {
    return acc + (group.items || []).filter(item => item.ingredient_cost && item.ingredient_cost > 0).length;
  }, 0) || 0;

  const handleRecompute = async () => {
    setIsRecomputing(true);
    try {
      await base44.functions.invoke("estimateRecipePricing", { recipe_id: recipe.id });
      window.location.reload();
    } catch (err) {
      console.error("Recompute failed:", err);
    } finally {
      setIsRecomputing(false);
    }
  };

  return (
    <div className="fixed bottom-28 right-4 z-40">
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          className="w-10 h-10 rounded-full bg-amber-500 text-white flex items-center justify-center shadow-lg hover:bg-amber-600 transition-colors"
          title="Pricing Debug"
        >
          <Bug className="w-5 h-5" />
        </button>
      )}

      {isOpen && (
        <div className="bg-slate-900 text-white rounded-xl p-4 shadow-xl max-w-xs space-y-2 text-sm">
          <div className="flex items-center justify-between mb-2">
            <span className="font-bold">Pricing Debug</span>
            <button onClick={() => setIsOpen(false)} className="text-white/50 hover:text-white">✕</button>
          </div>

          <div className="bg-slate-800 rounded p-2 space-y-1 text-xs">
            <div><span className="text-slate-400">Servings:</span> {selectedServings} (scale: {scaleFactor.toFixed(2)}x)</div>
            <div><span className="text-slate-400">Priced ingredients:</span> {pricedCount}</div>
            <div><span className="text-slate-400">Unknown ingredients:</span> {unknownCount}</div>
            <div><span className="text-slate-400">Total cost:</span> ${scaledTotal.toFixed(2)}</div>
            <div><span className="text-slate-400">Per serving:</span> ${scaledPerServing.toFixed(2)}</div>
            <div><span className="text-slate-400">Has unknown:</span> {recipe.has_unknown_pricing ? "yes" : "no"}</div>
          </div>

          <button
            onClick={handleRecompute}
            disabled={isRecomputing}
            className="w-full mt-2 px-3 py-1.5 rounded bg-orange-500 hover:bg-orange-600 disabled:opacity-50 text-xs font-semibold flex items-center justify-center gap-1"
          >
            <RotateCcw className="w-3 h-3" />
            Recompute
          </button>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { base44 } from "@/api/base44Client";
import { ChevronDown, ChevronUp, Copy, Trash2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import RevenueCatDebugPanel from "./RevenueCatDebugPanel";

// Global diagnostics store
export const DiagnosticsStore = {
  calls: [],
  lastError: null,
  mealLogs: [],

  addCall: (name, payload, response, error = null) => {
    const call = {
      name,
      payload,
      response,
      error,
      timestamp: new Date().toISOString(),
    };
    DiagnosticsStore.calls.unshift(call);
    if (DiagnosticsStore.calls.length > 20) DiagnosticsStore.calls.pop();
    if (error) DiagnosticsStore.lastError = error;
  },

  setMealLogs: (logs) => {
    DiagnosticsStore.mealLogs = logs;
  },

  clear: () => {
    DiagnosticsStore.calls = [];
    DiagnosticsStore.lastError = null;
  },
};

function ViewportDebugInfo() {
  const [info, setInfo] = React.useState({});
  React.useEffect(() => {
    const update = () => {
      const root = document.getElementById('root');
      const main = document.querySelector('main');
      const nav = document.querySelector('[data-bottom-nav]');
      const cs = getComputedStyle(document.documentElement);
      setInfo({
        innerH: window.innerHeight,
        visualH: window.visualViewport?.height || 'N/A',
        appVh: cs.getPropertyValue('--app-vh') || 'N/A',
        rootH: root?.offsetHeight || 'N/A',
        mainH: main?.offsetHeight || 'N/A',
        navH: nav?.offsetHeight || 'hidden',
        saTop: cs.getPropertyValue('--safe-area-top') || getComputedStyle(root).paddingTop || '0',
        saBot: cs.getPropertyValue('--safe-area-bottom') || '0',
        android: document.documentElement.hasAttribute('data-android-wrapper') ? 'YES' : 'no',
        native: document.documentElement.hasAttribute('data-native-app') ? 'YES' : 'no',
      });
    };
    update();
    const id = setInterval(update, 2000);
    return () => clearInterval(id);
  }, []);
  return (
    <div className="text-slate-300 space-y-0.5">
      <p>innerHeight: <span className="text-emerald-300">{info.innerH}px</span></p>
      <p>visualViewport: <span className="text-emerald-300">{typeof info.visualH === 'number' ? `${Math.round(info.visualH)}px` : info.visualH}</span></p>
      <p>--app-vh: <span className="text-emerald-300">{info.appVh}</span></p>
      <p>root height: <span className="text-emerald-300">{info.rootH}px</span></p>
      <p>main height: <span className="text-emerald-300">{info.mainH}px</span></p>
      <p>nav height: <span className="text-emerald-300">{info.navH}{typeof info.navH === 'number' ? 'px' : ''}</span></p>
      <p>safe-area-top: <span className="text-amber-300">{info.saTop}</span></p>
      <p>safe-area-bot: <span className="text-amber-300">{info.saBot}</span></p>
      <p>android-wrapper: <span className={info.android === 'YES' ? 'text-green-400' : 'text-slate-500'}>{info.android}</span></p>
      <p>native-app: <span className={info.native === 'YES' ? 'text-green-400' : 'text-slate-500'}>{info.native}</span></p>
    </div>
  );
}

