                </p>
              </div>
            )}
          </div>
        </motion.div>
      </motion.div>
    </AnimatePresence>
  );
}

/**
 * reportAdminLinks.js — Centralised admin/moderation URL builder
 * All email quick-action links are admin-gated (RequireAdmin enforces role check).
 * FIX: UserProfile uses ?userId= (not ?id=)
 */

export function buildReportAdminUrls({ appUrl, targetType, targetId, reporterId, reportId }) {
  const base = (appUrl || 'https://reciplyai.app').replace(/\/$/, '');

  // Content-specific deep link for "Open Target"
  const targetRouteMap = {
    post:    `/RecipeDetail?id=${targetId}`,
    recipe:  `/RecipeDetail?id=${targetId}`,
    user:    `/UserProfile?userId=${targetId}`,   // FIX: userId not id
    group:   `/GroupDetail?id=${targetId}`,
    shop:    `/Shop?id=${targetId}`,
    comment: `/Community`,
    message: `/ChatList`,
  };
  const targetPath = targetRouteMap[targetType] || '/Home';

  return {
    // Opens the specific report detail in the admin panel
    openReport:   `${base}/AdminModeration?report_id=${reportId}`,
    // Opens the reported content (deep-linked via the admin panel for auth enforcement)
    openTarget:   `${base}/AdminModeration?report_id=${reportId}&ctx=target`,
    // Opens reporter context in admin panel
    openReporter: `${base}/AdminModeration?report_id=${reportId}&ctx=reporter`,
    // Admin moderation dashboard root
    adminPanel:   `${base}/AdminModeration`,
    // Direct content link (for admin reference in email body, not buttons)
    directTargetUrl: `${base}${targetPath}`,
    // Direct reporter profile (for admin reference in email body)
    directReporterUrl: `${base}/UserProfile?userId=${reporterId}`,
  };
}

