function PanelAvatar({ name, avatarUrl, size = 16 }) {
  const [err, setErr] = useState(false);
  useEffect(() => setErr(false), [avatarUrl]);
  const hasImg = typeof avatarUrl === "string" && avatarUrl.trim().length > 0 && !err;
  const letter = name?.trim()?.charAt(0)?.toUpperCase() || "?";
  const cls = size === 16 ? "w-16 h-16" : size === 10 ? "w-10 h-10" : "w-8 h-8";
  return (
    <div className={`${cls} rounded-full bg-gradient-to-br from-indigo-400 to-purple-500 flex items-center justify-center overflow-hidden flex-shrink-0`}>
      {hasImg ? <img src={avatarUrl} alt="" className="w-full h-full object-cover" onError={() => setErr(true)} /> : <span className="text-white font-bold" style={{ fontSize: size === 16 ? 24 : size === 10 ? 14 : 11 }}>{letter}</span>}
    </div>
  );
}

function ActionRow({ icon: Icon, label, sublabel, onClick, color, loading, toggle, toggled, danger }) {
  const iconBg = danger ? "bg-rose-50" : color === "amber" ? "bg-amber-50" : color === "emerald" ? "bg-emerald-50" : "bg-slate-50";
  const iconColor = danger ? "text-rose-500" : color === "amber" ? "text-amber-600" : color === "emerald" ? "text-emerald-600" : "text-slate-600";
  return (
    <button onClick={onClick} disabled={loading} className="flex items-center gap-3 w-full px-5 py-3 active:bg-slate-50 transition-colors disabled:opacity-50">
      <div className={cn("w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0", iconBg)}>
        {loading ? <Loader2 className="w-4 h-4 animate-spin text-slate-400" /> : <Icon className={cn("w-4 h-4", iconColor)} />}
      </div>
      <div className="flex-1 min-w-0 text-left">
        <p className={cn("text-sm font-semibold", danger ? "text-rose-600" : "text-slate-800")}>{label}</p>
        {sublabel && <p className="text-[11px] text-slate-400 truncate">{sublabel}</p>}
      </div>
      {toggle !== undefined && (
        <div className={cn("w-10 h-6 rounded-full transition-colors flex items-center px-0.5", toggled ? "bg-indigo-500" : "bg-slate-200")}>
          <div className={cn("w-5 h-5 rounded-full bg-white shadow transition-transform", toggled ? "translate-x-4" : "translate-x-0")} />
        </div>
      )}
      {!toggle && !loading && <ChevronRight className="w-4 h-4 text-slate-300 flex-shrink-0" />}
    </button>
  );
}

const REPORT_REASONS = (t) => [
  { key: "spam", label: t("report.spam", "Spam") },
  { key: "harassment", label: t("report.harassment", "Harassment") },
  { key: "inappropriate", label: t("report.inappropriate", "Inappropriate content") },
  { key: "other", label: t("report.other", "Other") },
];

export default function DMActionPanel({
  isOpen,
  onClose,
  otherUserId,
  otherUserName,
  otherUserAvatar,
  conversationId,
  convPrefs = {},
  onUpdatePref,
  currentUserId,
}) {
  const { t } = useLocalization();
  const [view, setView] = useState("main"); // main | nickname | report | createGroup
  const [nicknameVal, setNicknameVal] = useState(convPrefs.nickname || "");
  const [reportReason, setReportReason] = useState("");
  const [reportDetails, setReportDetails] = useState("");
  const [reportSending, setReportSending] = useState(false);
  const [blockLoading, setBlockLoading] = useState(false);
  const [isBlocked, setIsBlocked] = useState(false);
  const [showBlockConfirm, setShowBlockConfirm] = useState(false);
  const [showClearConfirm, setShowClearConfirm] = useState(false);

  // Create group state
  const [groupSearch, setGroupSearch] = useState("");
  const [groupSelected, setGroupSelected] = useState([]);
  const [groupName, setGroupName] = useState("");
  const [groupCreating, setGroupCreating] = useState(false);
  const [eligibleUsers, setEligibleUsers] = useState([]); // followers only
  const [eligibleLoading, setEligibleLoading] = useState(false);

  // Reset view on open
  useEffect(() => {
    if (isOpen) {
      setView("main");
      setNicknameVal(convPrefs.nickname || "");
      setReportReason("");
      setReportDetails("");
      setShowBlockConfirm(false);
      setShowClearConfirm(false);
      setGroupSearch("");
      setGroupSelected([otherUserId]); // pre-select the DM partner
      setGroupName("");
    }
  }, [isOpen]);

  // Listen for auto-open create group event (from ChatList long-press → Messages URL param)
  useEffect(() => {
    const handler = () => { if (isOpen) setView("createGroup"); };
    window.addEventListener('dm-panel-open-create-group', handler);
    return () => window.removeEventListener('dm-panel-open-create-group', handler);
  }, [isOpen]);

  // Check block status
  useEffect(() => {
    if (!isOpen || !currentUserId || !otherUserId) return;
    base44.entities.BlockedUser.filter({ blocker_id: currentUserId, blocked_id: otherUserId })
      .then((r) => setIsBlocked(r.length > 0))
      .catch(() => {});
  }, [isOpen, currentUserId, otherUserId]);

  // Fetch eligible users = FOLLOWERS ONLY
  useEffect(() => {
    if (view !== "createGroup" || !currentUserId) return;
    setEligibleLoading(true);
    setGroupSearch("");
    let cancelled = false;
    (async () => {
      try {
        const res = await base44.functions.invoke('getGroupEligibleUsers', {});
        if (cancelled) return;
        setEligibleUsers(res.data?.users || []);
      } catch (err) {
        console.warn('[DMActionPanel] eligible fetch failed:', err);
        if (!cancelled) setEligibleUsers([]);
      } finally {
        if (!cancelled) setEligibleLoading(false);
      }
    })();
    return () => { cancelled = true; };
  }, [view, currentUserId]);

  const isPinned = !!convPrefs.pinned;
  const isMuted = !!convPrefs.muted;

  const handleBlock = async () => {
    setBlockLoading(true);
    setShowBlockConfirm(false);
    try {
      if (isBlocked) {
        await base44.functions.invoke("unblockUser", { blocked_id: otherUserId });
        setIsBlocked(false);
        toast.success(t("chat.user_unblocked", "User unblocked"));
      } else {
        await base44.functions.invoke("blockUser", { target_user_id: otherUserId });
        setIsBlocked(true);
        toast.success(t("chat.user_blocked", "User blocked"));
      }
    } catch (err) {
      toast.error(err?.message || "Failed");
    } finally {
      setBlockLoading(false);
    }
  };

  const handleReport = async () => {
    if (!reportReason.trim()) return;
    setReportSending(true);
    try {
      await base44.functions.invoke("createReport", {
        target_type: "user",
        target_id: otherUserId,
        reason: reportReason.trim(),
        details: reportDetails.trim() ? `${reportDetails.trim()} | DM conversation: ${conversationId}` : `DM conversation: ${conversationId}`,
      });
      toast.success(t("report.submitted", "Report submitted. Our team will review it."));
      setView("main");
      setReportReason("");
      setReportDetails("");
    } catch {
      toast.error(t("error.something_went_wrong", "Something went wrong"));
    } finally {
      setReportSending(false);
    }
  };

  const handleClearChat = async () => {
    setShowClearConfirm(false);
    // Clear chat = hide all messages for current user only, keep conversation visible
    // Set a visibility cutoff so all existing messages are hidden for this user
    if (conversationId) {
      localStorage.setItem(`dm_vis_start:${conversationId}`, new Date().toISOString());
    }
    onClose();
    // Force messages to re-filter with the new cutoff
    window.location.reload();
  };

  const handleCreateGroup = async () => {
    if (groupSelected.length < 2 || !groupName.trim()) return;
    setGroupCreating(true);
    try {
      const res = await base44.functions.invoke("createGroupFromDM", {
        name: groupName.trim(),
        member_ids: groupSelected,
      });
      toast.success(t("chat.group_created", "Group created!"));
      onClose();
      // Invalidate friend group caches so the new group appears immediately in lists
      try {
        const { queryClientInstance } = await import('@/lib/query-client');
        queryClientInstance.invalidateQueries({ queryKey: ["friend-groups-page"] });
        queryClientInstance.invalidateQueries({ queryKey: ["friends-chat-groups"] });
        queryClientInstance.invalidateQueries({ queryKey: ["direct-convs-a"] });
        queryClientInstance.invalidateQueries({ queryKey: ["direct-convs-b"] });
      } catch {}
      const gid = res.data?.group_id;
      if (gid) {
        // CRITICAL: Route to FriendsGroupChat — NOT GroupDetail (generic community page)
        window.location.href = createPageUrl("FriendsGroupChat") + `?id=${gid}`;
      }
    } catch (err) {
      toast.error(err?.response?.data?.error || err?.message || "Failed to create group");
    } finally {
      setGroupCreating(false);
    }
  };

  // Display list: filter followers locally by search query
  const displayUsers = groupSearch.trim().length >= 2
    ? eligibleUsers.filter(u => {
        const q = groupSearch.trim().toLowerCase();
        return (u.display_name || '').toLowerCase().includes(q) || (u.username || '').toLowerCase().includes(q);
      })
    : eligibleUsers;
  const displayLoading = eligibleLoading;

  const toggleGroupMember = (uid) => {
    setGroupSelected((prev) => (prev.includes(uid) ? prev.filter((id) => id !== uid) : [...prev, uid]));
  };

  return (
    <>
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0, y: "100%" }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: "100%" }}
          transition={{ type: "spring", stiffness: 300, damping: 30 }}
          className="fixed inset-0 z-[100] bg-white flex flex-col"
          style={{ paddingTop: "env(safe-area-inset-top, 0px)" }}
        >
          {/* ── HEADER ── */}
          <div className="flex items-center justify-between px-5 py-4 border-b border-slate-100 flex-shrink-0">
            <h2 className="text-base font-bold text-slate-900">
              {view === "main" && t("chat.chat_settings", "Chat Settings")}
              {view === "nickname" && t("chat.set_nickname", "Set Nickname")}
              {view === "report" && t("report.report_user", "Report User")}
              {view === "createGroup" && t("chat.create_friends_group", "Create Friends Group")}
            </h2>
            <button
              onClick={() => { if (view === "main") onClose(); else setView("main"); }}
              className="w-9 h-9 rounded-full bg-slate-100 flex items-center justify-center"
              data-icon-only
            >
              <X className="w-4 h-4 text-slate-600" />
            </button>
          </div>

          {/* ── CONTENT ── */}
          <div className="flex-1 overflow-y-auto">
            <AnimatePresence mode="wait">
              {/* ══════════ MAIN VIEW ══════════ */}
              {view === "main" && (
                <motion.div key="main" initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: 20 }} transition={{ duration: 0.15 }}>
                  {/* Profile summary */}
                  <div className="flex flex-col items-center pt-6 pb-5 px-5">
                    <PanelAvatar name={otherUserName} avatarUrl={otherUserAvatar} size={16} />
                    <p className="text-lg font-bold text-slate-900 mt-3">{otherUserName || t("chat.user", "User")}</p>
                    {convPrefs.nickname && otherUserName && (
                      <p className="text-xs text-slate-400 mt-0.5">
                        {t("chat.nickname_label", "Nickname")}: {convPrefs.nickname}
                      </p>
                    )}
                    <button
                      onClick={() => { onClose(); window.location.href = createPageUrl("UserProfile") + `?userId=${otherUserId}`; }}
                      className="mt-3 px-4 py-2 rounded-full bg-indigo-50 text-indigo-600 text-xs font-semibold active:scale-95 transition-all"
                    >
                      {t("chat.view_profile", "View profile")}
                    </button>
                  </div>

                  <div className="h-2 bg-slate-50" />

                  {/* Quick toggles */}
                  <div className="py-1">
                    <ActionRow
                      icon={isPinned ? PinOff : Pin}
                      label={isPinned ? t("chat.unpin", "Unpin chat") : t("chat.pin", "Pin to top")}
                      color="amber"
                      onClick={() => { onUpdatePref?.({ pinned: !isPinned }); }}
                    />
                    <ActionRow
                      icon={isMuted ? Bell : BellOff}
                      label={isMuted ? t("chat.unmute", "Unmute notifications") : t("chat.mute", "Mute notifications")}
                      color={isMuted ? "emerald" : undefined}
                      toggle
                      toggled={isMuted}
                      onClick={() => { onUpdatePref?.({ muted: !isMuted }); }}
                    />
                    <ActionRow
                      icon={Pencil}
                      label={convPrefs.nickname ? t("chat.edit_nickname", "Edit nickname") : t("chat.set_nickname", "Set nickname")}
                      sublabel={convPrefs.nickname || null}
                      onClick={() => setView("nickname")}
                    />
                  </div>

