    </motion.div>
  );
}

/**
 * MultiImageComposer — Select up to 5 images from gallery, edit each separately
 * (caption, rotation, send mode per image), then send all.
 * Opens native gallery picker immediately on mount.
 */
import React, { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, Plus, Send, Eye, EyeOff, RotateCw, Loader2, Type } from "lucide-react";
import { cn } from "@/lib/utils";
import { base44 } from "@/api/base44Client";
import { compressAndUpload } from "@/lib/imageCompressor";

const MAX_IMAGES = 5;

export default function MultiImageComposer({ onSendImages, onClose }) {
  // Each image: { file, previewUrl, rotation, mode, caption }
  const [images, setImages] = useState([]);
  const [activeIdx, setActiveIdx] = useState(0);
  const [sending, setSending] = useState(false);
  const [showCaption, setShowCaption] = useState(false);
  const [pickerOpened, setPickerOpened] = useState(false);
  const fileInputRef = useRef(null);

  // Open gallery picker immediately on mount (only once)
  useEffect(() => {
    if (pickerOpened) return;
    // Check if there are pending images from the Messages page file input
    const pending = window.__pendingMultiImages;
    if (pending && pending.length > 0) {
      window.__pendingMultiImages = null;
      addFiles(pending);
      setPickerOpened(true);
    } else {
      // Small delay so the component mounts first, then trigger native picker
      const t = setTimeout(() => {
        fileInputRef.current?.click();
        setPickerOpened(true);
      }, 100);
      return () => clearTimeout(t);
    }
  }, []);

  const addFiles = (files) => {
    const arr = Array.isArray(files) ? files : Array.from(files);
    const newImages = [];
    const currentCount = images.length;
    for (const file of arr) {
      if (currentCount + newImages.length >= MAX_IMAGES) break;
      if (!file.type?.startsWith("image/")) continue;
      newImages.push({
        file,
        previewUrl: URL.createObjectURL(file),
        rotation: 0,
        mode: "permanent",
        caption: "",
      });
    }
    if (newImages.length > 0) {
      setImages(prev => {
        const next = [...prev, ...newImages];
        setActiveIdx(prev.length); // focus first new image
        return next;
      });
    }
  };

  const removeImage = (idx) => {
    setImages(prev => {
      URL.revokeObjectURL(prev[idx].previewUrl);
      const next = prev.filter((_, i) => i !== idx);
      return next;
    });
    setActiveIdx(prev => Math.min(prev, Math.max(0, images.length - 2)));
  };

  const updateImage = (idx, updates) => {
    setImages(prev => prev.map((img, i) => i === idx ? { ...img, ...updates } : img));
  };

  const rotateActive = () => {
    updateImage(activeIdx, { rotation: ((images[activeIdx]?.rotation || 0) + 90) % 360 });
  };

  const handleSend = async () => {
    if (sending || images.length === 0) return;
    setSending(true);
    try {
      const uploads = await Promise.all(
        images.map(async (img) => {
          let fileToUpload = img.file;
          if (img.rotation !== 0) {
            fileToUpload = await processRotation(img.file, img.previewUrl, img.rotation);
          }
          const { file_url } = await compressAndUpload(fileToUpload, 'chat_image');
          return { file_url, mode: img.mode, caption: img.caption?.trim() || "" };
        })
      );
      await onSendImages(uploads);
    } catch (err) {
      console.error("[MultiImageComposer] send failed:", err);
    } finally {
      setSending(false);
    }
  };

  // If user cancels the gallery picker without selecting anything, close
  const handleFileInputChange = (e) => {
    if (e.target.files?.length) {
      addFiles(e.target.files);
    } else if (images.length === 0) {
      // No images selected and no existing — close
      onClose();
    }
    e.target.value = "";
  };

  // Close if user picked nothing on first open
  const handleFileInputCancel = () => {
    if (images.length === 0) {
      // Small delay because cancel fires before change on some browsers
      setTimeout(() => {
        if (images.length === 0) onClose();
      }, 300);
    }
  };

  const active = images[activeIdx] || null;

  // If no images yet, show minimal UI with the hidden file input
  if (images.length === 0 && pickerOpened) {
    return (
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className="fixed inset-0 z-[120] bg-black flex items-center justify-center"
      >
        <input
          ref={fileInputRef}
          type="file"
          accept="image/*"
          multiple
          className="hidden"
          onChange={handleFileInputChange}
          onCancel={handleFileInputCancel}
        />
        <div className="text-white/40 text-sm font-medium">Select images from gallery...</div>
      </motion.div>
    );
  }

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-[120] bg-black flex flex-col"
      style={{ paddingTop: "env(safe-area-inset-top, 0px)" }}
    >
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        multiple
        className="hidden"
        onChange={handleFileInputChange}
        onCancel={handleFileInputCancel}
      />

      {/* Top bar */}
      <div className="flex items-center justify-between px-4 py-3 flex-shrink-0">
        <button onClick={onClose} className="w-10 h-10 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center" data-icon-only>
          <X className="w-5 h-5 text-white" />
        </button>
        <span className="text-white/60 text-xs font-bold">{images.length}/{MAX_IMAGES} images</span>
        <div className="flex items-center gap-2">
          <button onClick={rotateActive} disabled={!active} className="w-10 h-10 rounded-full bg-white/10 backdrop-blur-md flex items-center justify-center disabled:opacity-30" data-icon-only>
            <RotateCw className="w-4 h-4 text-white" />
          </button>
          <button
            onClick={() => setShowCaption(prev => !prev)}
            disabled={!active}
            className={cn(
              "w-10 h-10 rounded-full backdrop-blur-md flex items-center justify-center disabled:opacity-30",
              showCaption ? "bg-indigo-500" : "bg-white/10"
            )}
            data-icon-only
          >
            <Type className="w-4 h-4 text-white" />
          </button>
        </div>
      </div>

      {/* Main preview */}
      <div className="flex-1 flex items-center justify-center overflow-hidden px-4 relative">
        {active && (
          <motion.img
            key={activeIdx}
            src={active.previewUrl}
            alt="Preview"
            className="max-w-full max-h-full object-contain rounded-2xl"
            style={{ transform: `rotate(${active.rotation}deg)` }}
            animate={{ rotate: active.rotation }}
            transition={{ type: "spring", stiffness: 300, damping: 30 }}
            draggable={false}
          />
        )}
      </div>

      {/* Caption input for active image */}
      <AnimatePresence>
        {showCaption && active && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="px-4 overflow-hidden flex-shrink-0"
          >
            <input
              autoFocus
              value={active.caption || ""}
              onChange={(e) => updateImage(activeIdx, { caption: e.target.value })}
              placeholder="Add a caption for this image..."
              className="w-full h-11 px-4 rounded-2xl bg-white/10 backdrop-blur-md text-white text-sm placeholder:text-white/40 outline-none border border-white/15"
            />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Thumbnail strip */}
      <div className="flex items-center gap-2 px-4 py-3 overflow-x-auto hide-scrollbar flex-shrink-0">
        {images.map((img, idx) => (
          <div key={idx} className="relative flex-shrink-0">
            <button
              onClick={() => setActiveIdx(idx)}
              className={cn(
                "w-14 h-14 rounded-xl overflow-hidden border-2 transition-all",
                idx === activeIdx ? "border-indigo-400 scale-105" : "border-white/20"
              )}
            >
              <img src={img.previewUrl} alt="" className="w-full h-full object-cover" style={{ transform: `rotate(${img.rotation}deg)` }} />
            </button>
            <button
              onClick={() => removeImage(idx)}
              className="absolute -top-1.5 -right-1.5 w-5 h-5 rounded-full bg-rose-500 flex items-center justify-center"
              data-icon-only
            >
              <X className="w-3 h-3 text-white" />
            </button>
            {/* Per-image mode badge */}
            {img.mode === "one_time" && (
              <div className="absolute bottom-0.5 left-0.5 w-4 h-4 rounded-full bg-amber-500 flex items-center justify-center">
                <EyeOff className="w-2.5 h-2.5 text-white" />
              </div>
            )}
            {img.caption && (
              <div className="absolute bottom-0.5 right-0.5 w-4 h-4 rounded-full bg-indigo-500 flex items-center justify-center">
                <Type className="w-2.5 h-2.5 text-white" />
              </div>
            )}
          </div>
        ))}
        {images.length < MAX_IMAGES && (
          <button
            onClick={() => fileInputRef.current?.click()}
            className="w-14 h-14 rounded-xl border-2 border-dashed border-white/20 flex items-center justify-center flex-shrink-0"
          >
            <Plus className="w-5 h-5 text-white/40" />
          </button>
        )}
      </div>

      {/* Per-image send mode */}
      <div className="px-4 pt-2 pb-4 flex-shrink-0" style={{ paddingBottom: "max(16px, env(safe-area-inset-bottom))" }}>
        {active && (
          <div className="flex items-center justify-center gap-2 mb-3">
            <button
              onClick={() => updateImage(activeIdx, { mode: "permanent" })}
              className={cn(
                "flex items-center gap-2 px-4 py-2.5 rounded-2xl text-xs font-bold transition-all",
                active.mode === "permanent" ? "bg-white text-slate-900 shadow-lg" : "bg-white/10 text-white/60"
              )}
            >
              <Eye className="w-3.5 h-3.5" /> Keep in chat
            </button>
            <button
              onClick={() => updateImage(activeIdx, { mode: "one_time" })}
              className={cn(
                "flex items-center gap-2 px-4 py-2.5 rounded-2xl text-xs font-bold transition-all",
                active.mode === "one_time" ? "bg-white text-slate-900 shadow-lg" : "bg-white/10 text-white/60"
              )}
            >
              <EyeOff className="w-3.5 h-3.5" /> View once
            </button>
          </div>
        )}

        <motion.button
          whileTap={{ scale: 0.95 }}
          onClick={handleSend}
          disabled={sending || images.length === 0}
          className="w-full h-14 rounded-2xl bg-indigo-600 text-white font-bold text-sm flex items-center justify-center gap-2 disabled:opacity-50 shadow-lg shadow-indigo-500/30"
        >
          {sending ? (
            <><Loader2 className="w-5 h-5 animate-spin" /> Sending {images.length} image{images.length > 1 ? 's' : ''}...</>
          ) : (
            <><Send className="w-5 h-5" /> Send {images.length} image{images.length > 1 ? 's' : ''}</>
          )}
        </motion.button>
      </div>
    </motion.div>
  );
}

async function processRotation(file, previewUrl, rotation) {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement("canvas");
      const ctx = canvas.getContext("2d");
      const swap = rotation === 90 || rotation === 270;
      canvas.width = swap ? img.height : img.width;
      canvas.height = swap ? img.width : img.height;
      ctx.translate(canvas.width / 2, canvas.height / 2);
      ctx.rotate((rotation * Math.PI) / 180);
      ctx.drawImage(img, -img.width / 2, -img.height / 2);
      canvas.toBlob((blob) => {
        resolve(new File([blob], file.name || "image.jpg", { type: "image/jpeg" }));
      }, "image/jpeg", 0.92);
    };
    img.src = previewUrl;
  });
}

import React, { useState } from 'react';
