export default function ChatComposer({ groupId, onMessageSent, disabled = false }) {
  const [text, setText] = useState('');
  const [sending, setSending] = useState(false);
  const [showGifPicker, setShowGifPicker] = useState(false);
  const [showStickerPicker, setShowStickerPicker] = useState(false);
  const [error, setError] = useState('');

  const handleSendText = async () => {
    if (!text.trim()) return;

    setSending(true);
    setError('');
    const body = text.trim();
    try {
      const res = await base44.functions.invoke('groupMessageSend', {
        group_id: groupId,
        type: 'text',
        text: body,
      });

      if (res.data?.success) {
        setText('');
        onMessageSent?.(res.data.message);
        // Fire mention notifications (non-blocking)
        base44.functions.invoke('sendMentionNotifications', {
          content: body,
          context_type: 'group_message',
          context_id: groupId,
        }).catch(() => {});
      } else {
        setError(res.data?.error || 'Failed to send');
      }
    } catch (err) {
      setError(err.message || 'Failed to send');
    } finally {
      setSending(false);
    }
  };

  const handleMediaSelect = async (media) => {
    setSending(true);
    setError('');
    try {
      const res = await base44.functions.invoke('groupMessageSend', {
        group_id: groupId,
        type: media.type,
        media_url: media.media_url,
        media_width: media.media_width,
        media_height: media.media_height,
      });

      if (res.data?.success) {
        onMessageSent?.(res.data.message);
      } else {
        setError(res.data?.error || 'Failed to send');
      }
    } catch (err) {
      setError(err.message || 'Failed to send');
    } finally {
      setSending(false);
    }
  };

  return (
    <div className="bg-white border-t border-slate-100 p-4 space-y-2">
      {error && (
        <div className="text-xs text-red-500 bg-red-50 px-3 py-2 rounded-lg">
          {error}
        </div>
      )}

      <div className="flex gap-2 items-end">
        {/* Text Input with mention support */}
        <MentionInput
          value={text}
          onChange={setText}
          onKeyDown={(e) => {
            if (e.key === 'Enter' && !e.shiftKey) {
              e.preventDefault();
              handleSendText();
            }
          }}
          placeholder="Type a message... (@ to mention)"
          rows={1}
          disabled={disabled || sending}
          className="flex-1 px-4 py-2.5 rounded-2xl bg-slate-100 text-sm resize-none outline-none disabled:opacity-50 focus:bg-slate-200"
