import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Search, Loader2 } from 'lucide-react';
import { base44 } from '@/api/base44Client';

// ── Search-term block list (frontend guard — never hits API) ─────────────────
const BLOCKED_SEARCH_TERMS = [
  'sex','sexual','sexuality','sexxx',
  'porn','porno','pornography',
  'xxx','xxxx',
  'dick','dik','d i c k',
  'cock','coc','c o c k',
  'pussy','pussyy','pussies',
  'penis','peniss',
  'vagina','vag',
  'boobs','boob','tits','tit','titties',
  'asshole','butthole',
  'cum','cumshot',
  'blowjob','blow job','handjob','hand job',
  'nude','nudity','nudist','naked',
  'nsfw',
  'hentai','ecchi','rule34','rule 34',
  'fetish','fetishes',
  'erotic','erotica',
  'lingerie','topless','undress',
  'explicit','obscene',
  '18+','adult content',
];

function normalizeQuery(q) {
  return q.toLowerCase().replace(/\s+/g, ' ').trim();
}

function isBlockedQuery(q) {
  const norm = normalizeQuery(q);
  const compact = norm.replace(/\s/g, '');
  for (const term of BLOCKED_SEARCH_TERMS) {
    const t = term.toLowerCase().replace(/\s+/g, ' ').trim();
    const tc = t.replace(/\s/g, '');
    if (norm.includes(t) || compact.includes(tc)) return true;
  }
  return false;
}

// Multi-layer NSFW filter for returned GIF objects (defense-in-depth)
const NSFW_KEYWORDS = [
  'sex','nude','nudity','boobs','18+','hentai','ecchi','nsfw',
  'lingerie','naked','panties','topless','porn','erotic',
  'cleavage','oral','blow job','xxx','adult','sexual','intimate','undress','thong',
  'exposure','shaft','cock','dick','penetr','vulva','vagina','pussy',
];

function isSafeGif(gif) {
  if (!gif) return false;
  if (gif.rating) {
    const rating = gif.rating.toLowerCase();
    if (rating !== 'g' && rating !== 'pg') return false;
  }
  const title = (gif.title || '').toLowerCase();
  if (NSFW_KEYWORDS.some(kw => title.includes(kw))) return false;
  const desc = (gif.description || '').toLowerCase();
  if (NSFW_KEYWORDS.some(kw => desc.includes(kw))) return false;
  return true;
}

const GIF_PAGE_SIZE = 24;

// --- GIF Tab ---
// Separated default-feed state from search state to prevent stale-cursor corruption.
// Uses a request-ID counter to cancel any stale concurrent fetches.
// Detect platform once
function detectPlatform() {
  const ua = navigator.userAgent || '';
  if (/android/i.test(ua)) return 'android';
  return 'web';
}

function GifTab({ onSelect }) {
  const [query, setQuery] = useState('');
  const [blocked, setBlocked] = useState(false);
  const [apiType] = useState(() => detectPlatform()); // auto-detect, no toggle needed

  // Default (trending) feed state
  const [defaultGifs, setDefaultGifs] = useState([]);
  const [defaultOffset, setDefaultOffset] = useState(0);
  const [defaultHasMore, setDefaultHasMore] = useState(true);
  const [defaultLoading, setDefaultLoading] = useState(true);
  const [defaultLoadingMore, setDefaultLoadingMore] = useState(false);
  const [defaultError, setDefaultError] = useState('');

  // Search feed state
  const [searchGifs, setSearchGifs] = useState([]);
  const [searchOffset, setSearchOffset] = useState(0);
  const [searchHasMore, setSearchHasMore] = useState(true);
  const [searchLoading, setSearchLoading] = useState(false);
  const [searchLoadingMore, setSearchLoadingMore] = useState(false);
  const [searchError, setSearchError] = useState('');
  const [activeSearchQuery, setActiveSearchQuery] = useState('');

  const scrollRef = useRef(null);
  const seenDefaultIds = useRef(new Set());
  const seenSearchIds = useRef(new Set());
