  const reqIdRef = useRef(0);

  const isSearchMode = query.trim().length > 0 && !blocked;

  // Unified display state based on mode
  const gifs = isSearchMode ? searchGifs : defaultGifs;
  const loading = isSearchMode ? searchLoading : defaultLoading;
  const loadingMore = isSearchMode ? searchLoadingMore : defaultLoadingMore;
  const error = isSearchMode ? searchError : defaultError;
  const hasMore = isSearchMode ? searchHasMore : defaultHasMore;

  const fetchDefault = useCallback(async (off, append = false) => {
    const myId = ++reqIdRef.current;
    if (off === 0) {
      setDefaultLoading(true);
      seenDefaultIds.current.clear();
    } else {
      setDefaultLoadingMore(true);
    }
    setDefaultError('');
    try {
      const res = await base44.functions.invoke('searchGiphy', { query: '', limit: GIF_PAGE_SIZE, offset: off, apiType });
      if (reqIdRef.current !== myId) return; // stale — discard
      const data = res.data;
      const fresh = (data?.gifs || []).filter(isSafeGif).filter(g => {
        if (seenDefaultIds.current.has(g.id)) return false;
        seenDefaultIds.current.add(g.id);
        return true;
      });
      setDefaultGifs(prev => append ? [...prev, ...fresh] : fresh);
      setDefaultHasMore((data?.gifs?.length || 0) >= GIF_PAGE_SIZE);
    } catch {
      if (reqIdRef.current !== myId) return;
      setDefaultError('Could not load GIFs. Tap to retry.');
    } finally {
      if (reqIdRef.current === myId) {
        setDefaultLoading(false);
        setDefaultLoadingMore(false);
      }
    }
  }, [apiType]);

  const fetchSearch = useCallback(async (q, off, append = false) => {
    const myId = ++reqIdRef.current;
    if (off === 0) {
      setSearchLoading(true);
      seenSearchIds.current.clear();
    } else {
      setSearchLoadingMore(true);
    }
    setSearchError('');
    try {
      const res = await base44.functions.invoke('searchGiphy', { query: q, limit: GIF_PAGE_SIZE, offset: off, apiType });
      if (reqIdRef.current !== myId) return;
      const data = res.data;
      const fresh = (data?.gifs || []).filter(isSafeGif).filter(g => {
        if (seenSearchIds.current.has(g.id)) return false;
        seenSearchIds.current.add(g.id);
        return true;
      });
      setSearchGifs(prev => append ? [...prev, ...fresh] : fresh);
      setSearchHasMore((data?.gifs?.length || 0) >= GIF_PAGE_SIZE);
    } catch {
      if (reqIdRef.current !== myId) return;
      setSearchError('Could not load GIFs. Tap to retry.');
    } finally {
      if (reqIdRef.current === myId) {
        setSearchLoading(false);
        setSearchLoadingMore(false);
      }
    }
  }, [apiType]);

  // Load default feed once on mount
  useEffect(() => {
    fetchDefault(0, false);
  }, [fetchDefault]);

  // Debounced search — only fires for non-empty queries; clearing restores default feed
  useEffect(() => {
    const q = query.trim();
    if (!q) {
      setBlocked(false);
      // Clear stale search state so next search starts fresh
      setSearchGifs([]);
      setSearchOffset(0);
      setSearchHasMore(true);
      setSearchError('');
      return;
    }
    if (isBlockedQuery(q)) {
      setBlocked(true);
      return;
    }
    setBlocked(false);
    const t = setTimeout(() => {
      setSearchOffset(0);
      setSearchHasMore(true);
      setActiveSearchQuery(q);
      fetchSearch(q, 0, false);
    }, 400);
    return () => clearTimeout(t);
  }, [query, fetchSearch]);

  // Scroll-based infinite pagination — separated per mode
  const handleScroll = useCallback(() => {
    const el = scrollRef.current;
    if (!el || loading || loadingMore || !hasMore) return;
    const nearBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 120;
    if (!nearBottom) return;
    if (isSearchMode) {
      const nextOff = searchOffset + GIF_PAGE_SIZE;
      setSearchOffset(nextOff);
      fetchSearch(activeSearchQuery, nextOff, true);
    } else {
      const nextOff = defaultOffset + GIF_PAGE_SIZE;
      setDefaultOffset(nextOff);
      fetchDefault(nextOff, true);
    }
  }, [loading, loadingMore, hasMore, isSearchMode, searchOffset, defaultOffset, activeSearchQuery, fetchSearch, fetchDefault]);

  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    el.addEventListener('scroll', handleScroll, { passive: true });
    return () => el.removeEventListener('scroll', handleScroll);
  }, [handleScroll]);

  const handleRetry = () => {
    if (isSearchMode) {
      fetchSearch(activeSearchQuery, 0, false);
    } else {
      fetchDefault(0, false);
    }
  };

  return (
    <div className="flex flex-col h-full">
      <div className="px-4 pb-3 space-y-2">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
          <input
            type="text"
            placeholder="Search GIFs..."
            value={query}
            onChange={e => setQuery(e.target.value)}
            className="w-full pl-9 pr-4 py-2 rounded-xl bg-slate-100 text-sm outline-none focus:bg-slate-200"
          />
        </div>

      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 pb-6 min-h-0">
        {blocked ? (
          <div className="flex flex-col items-center justify-center py-10">
            <p className="text-sm font-semibold text-rose-500">This search term is not allowed.</p>
          </div>
        ) : loading ? (
          <div className="grid grid-cols-2 gap-2">
            {[1,2,3,4,5,6].map(i => (
              <div key={i} className="h-24 rounded-xl bg-slate-100 animate-pulse" />
            ))}
          </div>
        ) : error ? (
          <div className="flex flex-col items-center justify-center py-10 gap-3">
            <p className="text-sm text-slate-400">{error}</p>
            <button
              onClick={handleRetry}
              className="px-4 py-2 rounded-xl bg-indigo-50 text-indigo-600 text-sm font-semibold active:scale-95 transition-transform"
            >
              Tap to retry
            </button>
          </div>
        ) : gifs.length === 0 ? (
          <p className="text-center text-slate-400 text-sm py-8">No GIFs found</p>
        ) : (
          <>
            <div className="grid grid-cols-2 gap-2">
              {gifs.map(gif => (
                <button
                  key={gif.id}
                  onClick={() => onSelect({
                    type: 'gif',
                    media_url: gif.media_url,
                    media_width: gif.media_width,
                    media_height: gif.media_height,
                  })}
                  onContextMenu={e => e.preventDefault()}
                  className="rounded-xl overflow-hidden hover:opacity-80 transition-opacity bg-slate-100"
                  style={{ WebkitTouchCallout: 'none', userSelect: 'none', WebkitUserSelect: 'none' }}
                >
                  <img
                    src={gif.preview_url || gif.media_url}
                    alt={gif.title || 'gif'}
                    draggable={false}
                    className="w-full h-24 object-cover"
                    style={{ WebkitTouchCallout: 'none', pointerEvents: 'none' }}
                    onError={e => { e.target.style.display = 'none'; }}
                  />
                </button>
              ))}
            </div>
            {loadingMore && (
              <div className="flex justify-center py-4">
                <Loader2 className="w-5 h-5 animate-spin text-slate-400" />
              </div>
            )}
            {!hasMore && gifs.length > 0 && (
              <p className="text-center text-slate-300 text-xs py-4">All GIFs loaded</p>
            )}
          </>
        )}
      </div>
    </div>
  );
}

