function StickerTab({ onSelect }) {
  const [packs, setPacks] = useState([]);
  const [stickers, setStickers] = useState([]);
  const [selectedPack, setSelectedPack] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      try {
        const [packList, stickerList] = await Promise.all([
          base44.entities.StickerPack.list('-created_date', 50),
          base44.entities.Sticker.list('order', 200),
        ]);
        setPacks(packList || []);
        setStickers(stickerList || []);
      } catch {
        setPacks([]);
        setStickers([]);
      } finally {
        setLoading(false);
      }
    };
    load();
  }, []);

  const filtered = selectedPack
    ? stickers.filter(s => s.pack_id === selectedPack)
    : stickers;

  return (
    <div className="flex flex-col h-full">
      {packs.length > 0 && (
        <div className="px-4 pb-3 flex gap-2 overflow-x-auto hide-scrollbar">
          <button
            onClick={() => setSelectedPack(null)}
