export default function MessageContextMenu({
  msg,
  isMe,
  position,
  onReply,
  onDismiss,
  onDeleted,
  onEdited,
  onEditStart, // NEW: fires to start edit mode in composer
  onReaction,  // NEW: fires optimistic reaction update in parent
}) {
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  // Handle reaction — optimistic update via callback, then backend
  const handleReaction = async (emoji) => {
    onDismiss();
    // Optimistic update immediately
    if (onReaction) onReaction(msg.id, emoji);
    try {
      await base44.functions.invoke('messageReactionToggle', { message_id: msg.id, emoji });
    } catch (e) {
      console.warn('[MessageContextMenu] reaction failed', e.message);
    }
  };

  const handleCopy = () => {
    if (msg.text) navigator.clipboard?.writeText(msg.text).catch(() => {});
    onDismiss();
  };

  const handleReply = () => {
    onReply(msg);
    onDismiss();
  };

  // Edit: delegate to composer via onEditStart
  const handleEditClick = () => {
    onDismiss();
    if (onEditStart) onEditStart(msg);
  };

  // Delete for me — hides from current user's view
  const handleDeleteForMe = async () => {
    setShowDeleteModal(false);
    onDismiss();
    try {
      // Optimistic remove immediately
      if (onDeleted) onDeleted(msg.id);
      await base44.functions.invoke('deleteGroupMessage', { message_id: msg.id, scope: 'me' });
    } catch (e) {
      console.warn('[MessageContextMenu] delete-for-me failed', e.message);
    }
  };

  // Delete for everyone — removes for all
  const handleDeleteForEveryone = async () => {
    setShowDeleteModal(false);
    onDismiss();
    try {
      // Optimistic remove immediately
      if (onDeleted) onDeleted(msg.id);
      await base44.functions.invoke('deleteGroupMessage', { message_id: msg.id, scope: 'everyone' });
    } catch (e) {
      console.warn('[MessageContextMenu] delete-for-everyone failed', e.message);
    }
  };

  // Viewport-aware positioning
  const MENU_WIDTH = 220;
  const MENU_EST_HEIGHT = 170;
  const vw = typeof window !== 'undefined' ? window.innerWidth : 400;
  const vh = typeof window !== 'undefined' ? window.innerHeight : 800;

  const touchX = position?.x || vw / 2;
  const touchY = position?.y || vh / 2;

  const rawLeft = isMe
    ? Math.max(8, touchX - MENU_WIDTH + 16)
    : Math.min(vw - MENU_WIDTH - 8, touchX - 16);

  const spaceAbove = touchY - MENU_EST_HEIGHT - 16;
  const rawTop = spaceAbove >= 60
    ? Math.max(60, spaceAbove)
    : Math.min(vh - MENU_EST_HEIGHT - 24, touchY + 16);

  return (
    <>
      <motion.div
        initial={{ scale: 0.78, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.78, opacity: 0 }}
        transition={{ type: 'spring', stiffness: 440, damping: 28 }}
        style={{
          position: 'fixed',
          left: rawLeft,
          top: rawTop,
          width: MENU_WIDTH,
          zIndex: 200,
          transformOrigin: isMe ? 'bottom right' : 'bottom left',
        }}
        className="rounded-2xl overflow-hidden"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Glass background */}
        <div
          className="absolute inset-0 rounded-2xl border border-white/30"
          style={{
            background: 'rgba(255,255,255,0.93)',
            backdropFilter: 'blur(28px)',
            WebkitBackdropFilter: 'blur(28px)',
            boxShadow: '0 8px 40px rgba(0,0,0,0.18), 0 1px 0 rgba(255,255,255,0.6) inset',
          }}
        />

        {/* Quick reactions row + full picker button */}
        <div className="relative flex items-center justify-between px-2 py-2.5 border-b border-slate-100/70">
          {QUICK_REACTIONS.map((emoji, i) => (
            <motion.button
              key={emoji}
              initial={{ scale: 0, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ delay: i * 0.028, type: 'spring', stiffness: 420, damping: 20 }}
              whileTap={{ scale: 1.5 }}
              onClick={() => handleReaction(emoji)}
              className="text-[20px] leading-none p-0.5"
            >
              {emoji}
            </motion.button>
          ))}
          <motion.button
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ delay: QUICK_REACTIONS.length * 0.028, type: 'spring', stiffness: 420, damping: 20 }}
            whileTap={{ scale: 1.2 }}
            onClick={() => setShowEmojiPicker(true)}
            className="w-7 h-7 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 hover:bg-slate-200 transition-colors"
          >
            <Plus className="w-3.5 h-3.5" />
          </motion.button>
        </div>

        {/* Actions */}
        <div className="relative py-1">
          <button
            onClick={handleReply}
            className="w-full flex items-center gap-3 px-4 py-2.5 text-[13px] font-medium text-slate-700 hover:bg-slate-50/80 active:bg-slate-100 transition-colors"
          >
            <Reply className="w-3.5 h-3.5 text-slate-400" />
            Reply
          </button>

          {msg.type === 'text' && msg.text && (
            <button
              onClick={handleCopy}
              className="w-full flex items-center gap-3 px-4 py-2.5 text-[13px] font-medium text-slate-700 hover:bg-slate-50/80 active:bg-slate-100 transition-colors"
            >
              <Copy className="w-3.5 h-3.5 text-slate-400" />
              Copy text
