          )}

          {isMe && msg.type === 'text' && (
            <button
              onClick={handleEditClick}
              className="w-full flex items-center gap-3 px-4 py-2.5 text-[13px] font-medium text-slate-700 hover:bg-slate-50/80 active:bg-slate-100 transition-colors"
            >
              <Pencil className="w-3.5 h-3.5 text-slate-400" />
              Edit
            </button>
          )}

          {isMe && (
            <button
