import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import ChatBubble from './ChatBubble';

const TIME_GAP_THRESHOLD_MS = 3 * 60 * 1000; // 3 minutes

function groupMessages(messages, currentUserId) {
  if (!messages || messages.length === 0) return [];

  const groups = [];
  let currentGroup = [messages[0]];

  for (let i = 1; i < messages.length; i++) {
    const prev = messages[i - 1];
    const curr = messages[i];

    const sameSender = prev.sender_id === curr.sender_id;
    const timeDiff = new Date(curr.created_at) - new Date(prev.created_at);
    const withinTimeGap = timeDiff <= TIME_GAP_THRESHOLD_MS;

    if (sameSender && withinTimeGap) {
      currentGroup.push(curr);
    } else {
      groups.push(currentGroup);
      currentGroup = [curr];
    }
  }

  if (currentGroup.length > 0) {
    groups.push(currentGroup);
  }

  return groups;
}

export default function ChatMessageList({ messages, currentUserId }) {
  const [scrollDeltaX, setScrollDeltaX] = useState(0);
  const [showTimestamps, setShowTimestamps] = useState(false);
  const containerRef = useRef(null);
  const startXRef = useRef(0);
  const timeoutRef = useRef(null);

  const handleMouseDown = (e) => {
    startXRef.current = e.clientX;
  };

  const handleMouseMove = (e) => {
    if (startXRef.current === 0) return;

    const deltaX = e.clientX - startXRef.current;
    const absX = Math.abs(deltaX);
    const opacity = Math.min(absX / 60, 1); // Show timestamps based on drag distance

    setScrollDeltaX(deltaX);
    setShowTimestamps(absX > 5); // Threshold to activate

    // Clear timeout on active drag
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
  };

  const handleMouseUp = () => {
    startXRef.current = 0;
    // Fade out timestamps after 1.2s
    if (showTimestamps) {
      timeoutRef.current = setTimeout(() => {
        setShowTimestamps(false);
        setScrollDeltaX(0);
      }, 1200);
    }
  };

  useEffect(() => {
    if (!containerRef.current) return;

    const el = containerRef.current;
    el.addEventListener('mousedown', handleMouseDown);
    document.addEventListener('mousemove', handleMouseMove);
    document.addEventListener('mouseup', handleMouseUp);

    return () => {
      el.removeEventListener('mousedown', handleMouseDown);
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
    };
  }, [showTimestamps]);

  const groups = groupMessages(messages, currentUserId);

  return (
    <div
      ref={containerRef}
      className="flex-1 overflow-y-auto px-4 py-4 space-y-4 select-none"
      style={{ userSelect: 'none' }}
    >
      <AnimatePresence mode="popLayout">
        {groups.map((group, groupIdx) => {
          const isCurrentUser = group[0].sender_id === currentUserId;

          return (
            <motion.div
              key={`group-${groupIdx}`}
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className={`flex flex-col ${
                isCurrentUser ? 'items-end' : 'items-start'
              } gap-1`}
            >
              {group.map((msg, idx) => (
                <ChatBubble
                  key={msg.id}
                  message={msg}
                  isCurrentUser={isCurrentUser}
                  showUsername={!isCurrentUser}
                  showTimestamp={showTimestamps}
                  messageGroupIndex={idx}
                />
              ))}
            </motion.div>
          );
        })}
      </AnimatePresence>

      {messages.length === 0 && (
        <div className="flex items-center justify-center h-32 text-slate-400 text-sm">
          No messages yet. Start a conversation!
        </div>
      )}
    </div>
  );
}

