const dietaryColors = {
  vegan: "bg-emerald-50 text-emerald-700",
  vegetarian: "bg-lime-50 text-lime-700",
  "gluten-free": "bg-purple-50 text-purple-700",
  "dairy-free": "bg-sky-50 text-sky-700",
  keto: "bg-orange-50 text-orange-700",
  "high-protein": "bg-red-50 text-red-700",
  "low-carb": "bg-indigo-50 text-indigo-700",
};

function getNutrition(recipe) {
  const n = recipe.nutrition_per_serving;
  if (n?.calories > 0 || n?.protein > 0) return n;
  // fallback: divide total by servings
  const t = recipe.nutrition_total_for_recipe;
  const s = recipe.servings || 1;
  if (t?.calories > 0) {
    return { calories: Math.round(t.calories / s), protein: Math.round((t.protein || 0) / s) };
  }
  // legacy field
  const l = recipe.nutrition;
  if (l?.calories > 0) return l;
  return null;
}

export default function RecipeCardPremium({
  recipe,
  showCreator = false,
  showSave = false,
  showLike = false,
  showCook = true,
  isLiked = false,
  isSaved = false,
  onLike,
  onSave,
  onClick,
}) {
  const [savedOptimistic, setSavedOptimistic] = useState(null);
  const [likedOptimistic, setLikedOptimistic] = useState(null);
  const [likeCountOffset, setLikeCountOffset] = useState(0);
  const [savingInFlight, setSavingInFlight] = useState(false);
  const [likingInFlight, setLikingInFlight] = useState(false);

  const currentlySaved = savedOptimistic !== null ? savedOptimistic : isSaved;
  const currentlyLiked = likedOptimistic !== null ? likedOptimistic : isLiked;
  const displayLikes = (recipe.likes_count || 0) + likeCountOffset;

  const totalTime = (recipe.cook_time || 0) + (recipe.prep_time || 0);
  const nut = getNutrition(recipe);

  const handleSave = async (e) => {
    e.stopPropagation();
    if (savingInFlight) return;
    setSavingInFlight(true);
    setSavedOptimistic(!currentlySaved);
    try {
      await base44.functions.invoke('togglePostSaveState', { post_id: recipe.id });
      onSave?.(recipe);
    } catch {
      setSavedOptimistic(currentlySaved);
    } finally {
      setSavingInFlight(false);
    }
  };

  const handleLike = async (e) => {
    e.stopPropagation();
    if (likingInFlight) return;
    setLikingInFlight(true);
    const newLiked = !currentlyLiked;
    setLikedOptimistic(newLiked);
    setLikeCountOffset(prev => prev + (newLiked ? 1 : -1));
    try {
      await base44.functions.invoke('toggleRecipeLikeWithNotif', { recipe_id: recipe.id });
      onLike?.(recipe);
    } catch {
      setLikedOptimistic(currentlyLiked);
      setLikeCountOffset(prev => prev + (newLiked ? -1 : 1));
    } finally {
      setLikingInFlight(false);
    }
  };

  const handleNavigate = () => {
    if (onClick) { onClick(); return; }
    window.location.href = createPageUrl("RecipeDetail") + `?id=${recipe.id}`;
  };

  const difficultyColor = {
    easy: "#10b981",
    medium: "#f59e0b",
    hard: "#ef4444",
  }[recipe.difficulty] || "#6366f1";

  return (
    <motion.div
      whileTap={{ scale: 0.97 }}
      transition={{ type: "spring", stiffness: 400, damping: 28 }}
      onClick={handleNavigate}
      className="bg-white rounded-3xl overflow-hidden shadow-sm border border-slate-100/80 cursor-pointer flex flex-col hover:shadow-md transition-shadow duration-300"
    >
      {/* Image — 4:3 ratio */}
      <div className="relative w-full overflow-hidden bg-slate-100" style={{ paddingBottom: "75%" }}>
        <img
          src={recipe.hero_image_url || "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=500&h=375&fit=crop"}
          alt={recipe.title}
          className="absolute inset-0 w-full h-full object-cover"
          loading="lazy"
        />
        {/* Gradient overlay — bottom only */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/55 via-black/5 to-transparent" />

        {/* TOP-RIGHT: Save button */}
        {showSave && (
          <motion.button
            whileTap={{ scale: 0.82 }}
            onClick={handleSave}
            className={cn(
              "absolute top-2.5 right-2.5 w-8 h-8 rounded-xl flex items-center justify-center shadow-lg border transition-all",
              currentlySaved
                ? "bg-amber-400 border-amber-300 text-white"
                : "bg-white/90 border-white/60 text-slate-600"
            )}
          >
            <Bookmark className={cn("w-3.5 h-3.5", currentlySaved && "fill-current")} />
          </motion.button>
        )}

        {/* TOP-LEFT: Rating */}
        {recipe.avg_rating > 0 && (
          <div className="absolute top-2.5 left-2.5 flex items-center gap-0.5 bg-white/90 text-slate-800 text-[9px] font-bold px-1.5 py-0.5 rounded-lg shadow">
            <Star className="w-2.5 h-2.5 text-amber-500 fill-amber-500" />
            {recipe.avg_rating.toFixed(1)}
          </div>
        )}

        {/* BOTTOM: Time + Difficulty badges */}
        <div className="absolute bottom-2.5 left-2.5 right-2.5 flex items-end justify-between z-10">
          <div className="flex gap-1.5">
            {totalTime > 0 && (
              <div className="flex items-center gap-1 bg-blue-500 text-white text-[9px] font-bold px-2 py-0.5 rounded-lg shadow-md">
                <Clock className="w-2.5 h-2.5" />
                {totalTime}m
              </div>
            )}
            {recipe.difficulty && (
              <div
                className="text-[9px] font-bold px-2 py-0.5 rounded-lg text-white shadow-md capitalize"
                style={{ backgroundColor: difficultyColor }}
              >
                {recipe.difficulty}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Content — tight */}
      <div className="flex flex-col p-3 gap-1.5 flex-1">
        {/* Tags (max 2) */}
        {recipe.tags?.length > 0 && (
          <div className="flex gap-1 flex-wrap">
            {recipe.tags.slice(0, 2).map(t => (
              <span key={t} className={cn(
                "text-[8px] px-1.5 py-0.5 rounded-md font-semibold capitalize",
                dietaryColors[t] || "bg-slate-50 text-slate-500"
