        )}

        {/* Title */}
        <h3 className="font-bold text-[12.5px] text-slate-900 leading-tight line-clamp-2">
          {recipe.title}
        </h3>

        {/* Macros row — always show if available */}
        {nut && (nut.calories > 0 || nut.protein > 0) && (
          <div className="flex items-center gap-1.5 text-[9px] font-semibold text-slate-500">
