            <button
              onClick={(e) => {
                e.stopPropagation();
                if (recipe.author_id) window.location.href = createPageUrl("UserProfile") + `?userId=${recipe.author_id}`;
              }}
              className="flex items-center gap-1.5 min-w-0 flex-1 hover:opacity-70 transition-opacity"
            >
              <div className="w-5 h-5 rounded-full bg-gradient-to-br from-violet-400 to-pink-400 flex items-center justify-center flex-shrink-0 overflow-hidden">
                {recipe.author_avatar ? (
                  <img src={recipe.author_avatar} alt="" className="w-full h-full object-cover" />
                ) : (
                  <User className="w-2.5 h-2.5 text-white" />
                )}
              </div>
              <span className="text-[9px] text-slate-500 font-medium truncate">{recipe.author_name}</span>
            </button>
          ) : <div className="flex-1" />}

          <div className="flex items-center gap-1 flex-shrink-0">
            {/* Like */}
            {showLike && (
              <motion.button
                whileTap={{ scale: 0.85 }}
                onClick={handleLike}
                className={cn(
                  "flex items-center gap-0.5 px-2 py-1 rounded-lg text-[9px] font-bold transition-all",
                  currentlyLiked ? "bg-rose-100 text-rose-600" : "bg-slate-100 text-slate-500"
                )}
              >
                <Heart className={cn("w-2.5 h-2.5", currentlyLiked && "fill-current")} />
                {displayLikes}
              </motion.button>
            )}

            {/* Cook button */}
            {showCook && recipe.id && (
              <motion.a
                whileTap={{ scale: 0.88 }}
                href={createPageUrl("CookMode") + `?id=${recipe.id}`}
