export default function ReviewCard({ review, isOwn = false, recipeId, onDeleted }) {
  const [expanded, setExpanded] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [deleting, setDeleting] = useState(false);
  const menuRef = useRef(null);
  const { t } = useLocalization();

  // Close menu on outside click
  useEffect(() => {
    if (!menuOpen) return;
    const handler = (e) => { if (menuRef.current && !menuRef.current.contains(e.target)) setMenuOpen(false); };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [menuOpen]);

  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [editText, setEditText] = useState(review.review_text || '');
  const [editSaving, setEditSaving] = useState(false);

  const handleDelete = async () => {
    setShowDeleteConfirm(false);
    setDeleting(true);
    try {
      const res = await base44.functions.invoke('manageReview', {
        action: 'delete',
        review_id: review.id,
      });
      if (res.data?.error) {
        toast.error(res.data.error);
        return;
      }
      toast.success(t('review.deleted', 'Review deleted.'));
      onDeleted?.();
    } catch (err) {
      toast.error(err?.message || t('error.failed_delete', 'Failed to delete review.'));
    } finally {
      setDeleting(false);
    }
  };

  const handleEditSave = async () => {
    if (!editText.trim() || editText.trim().length < 5) return;
    setEditSaving(true);
    try {
      const res = await base44.functions.invoke('manageReview', {
        action: 'edit',
        review_id: review.id,
        review_text: editText,
      });
      if (res.data?.error) {
        toast.error(res.data.error);
        return;
