/**
 * UserAvatar — Deterministic fallback avatar.
 * Shows image if available, else circle with initials/gradient.
 * Handles: uploaded URLs, default Reciply character avatar IDs (e.g. "blaze"), initials fallback.
 * Used consistently across: Notifications, Feed, Comments, Followers, etc.
 */
import React, { useState } from "react";
import { resolveAvatarUrl } from "../../utils/avatarResolver";

export default function UserAvatar({ avatarUrl, username, displayName, email, size = "md" }) {
  const [imgErr, setImgErr] = useState(false);
  const sizeMap = {
    xs: "w-6 h-6 text-[10px]",
    sm: "w-8 h-8 text-xs",
    md: "w-10 h-10 text-sm",
    lg: "w-16 h-16 text-lg",
  };
  const sizeClass = sizeMap[size] || sizeMap.md;

  // Derive initial with priority: displayName > username > email > safe placeholder
  const deriveName = () => {
    const candidates = [displayName, username, email];
    for (const c of candidates) {
      const t = (c || "").trim();
      if (t.length > 0) return t.charAt(0).toUpperCase();
    }
    return "R";
  };

  const initial = deriveName();

  // Deterministic gradient based on initial
  const getGradient = () => {
    const charCode = initial.charCodeAt(0);
    const gradients = [
      "from-indigo-400 to-purple-500",
      "from-blue-400 to-cyan-500",
      "from-pink-400 to-rose-500",
      "from-green-400 to-emerald-500",
      "from-amber-400 to-orange-500",
      "from-red-400 to-pink-500",
    ];
    return gradients[charCode % gradients.length];
  };

  // Resolve the image source via shared canonical resolver:
  // 1. https/data URL → as-is
  // 2. starter avatar ID (e.g. "blaze") → inline SVG data URL
  // 3. empty/invalid → null → show initials fallback
  const resolvedUrl = resolveAvatarUrl(avatarUrl);
  const showImage = !!resolvedUrl && !imgErr;

  return (
    <div className={`${sizeClass} rounded-full overflow-hidden flex items-center justify-center flex-shrink-0 bg-gradient-to-br ${getGradient()}`} style={{ padding: 0 }}>
      {showImage ? (
        <img src={resolvedUrl} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover', objectPosition: 'center', display: 'block', borderRadius: 0 }} onError={() => setImgErr(true)} />
      ) : (
        <span className="font-bold text-white leading-none select-none">{initial}</span>
      )}
    </div>
  );
}

