/**
 * PullToRefreshContainer
 * 
 * Window-scroll-aware pull-to-refresh for full-page content.
 * 
 * - Only activates when window.scrollY === 0
 * - Uses framer-motion for smooth indicator animation
 * - Does NOT wrap in overflow-auto (uses window scroll, not container scroll)
 * - Prevents accidental trigger during normal scroll
 * 
 * Usage:
 *   <PullToRefreshContainer onRefresh={async () => { ... }}>
 *     <PageContent />
 *   </PullToRefreshContainer>
 */
import React, { useState, useRef, useCallback, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { RotateCw } from "lucide-react";

const PULL_THRESHOLD = 72;
const MAX_PULL = 110;

export default function PullToRefreshContainer({ onRefresh, children }) {
  const [pullY, setPullY] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const startYRef = useRef(null);
  const pullingRef = useRef(false);

  const handleTouchStart = useCallback((e) => {
    // Only initiate pull when at top of page
    if (window.scrollY === 0) {
      startYRef.current = e.touches[0].clientY;
      pullingRef.current = true;
    }
  }, []);

  const handleTouchMove = useCallback((e) => {
    if (!pullingRef.current || isRefreshing || startYRef.current === null) return;
    const delta = e.touches[0].clientY - startYRef.current;
    if (delta <= 0) {
      pullingRef.current = false;
      return;
    }
    // Dampen pull after threshold
    const damped = delta > PULL_THRESHOLD
      ? PULL_THRESHOLD + (delta - PULL_THRESHOLD) * 0.25
      : delta;
    setPullY(Math.min(damped, MAX_PULL));
  }, [isRefreshing]);

  const handleTouchEnd = useCallback(async () => {
    if (!pullingRef.current) return;
    pullingRef.current = false;

    if (pullY >= PULL_THRESHOLD) {
      setIsRefreshing(true);
      setPullY(0);
      try {
        await onRefresh?.();
      } finally {
        setIsRefreshing(false);
      }
    } else {
      setPullY(0);
    }
    startYRef.current = null;
  }, [pullY, onRefresh]);

  useEffect(() => {
    document.addEventListener("touchstart", handleTouchStart, { passive: true });
    document.addEventListener("touchmove", handleTouchMove, { passive: true });
    document.addEventListener("touchend", handleTouchEnd);
    return () => {
      document.removeEventListener("touchstart", handleTouchStart);
      document.removeEventListener("touchmove", handleTouchMove);
      document.removeEventListener("touchend", handleTouchEnd);
    };
  }, [handleTouchStart, handleTouchMove, handleTouchEnd]);

  const pullProgress = Math.min(pullY / PULL_THRESHOLD, 1);
  const showIndicator = pullY > 8 || isRefreshing;

  return (
    <div className="relative">
      {/* Pull indicator — positioned above content */}
      <AnimatePresence>
        {showIndicator && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ duration: 0.15 }}
            className="fixed top-0 left-0 right-0 z-[44] flex justify-center pointer-events-none"
            style={{ paddingTop: "env(safe-area-inset-top, 8px)" }}
          >
            <div className="flex items-center gap-2 bg-white/90 backdrop-blur-sm px-4 py-2 rounded-full shadow-md border border-slate-100 mt-2">
              <motion.div
                animate={{
                  rotate: isRefreshing ? 360 : pullProgress * 270,
                  scale: isRefreshing ? 1 : 0.8 + pullProgress * 0.2,
                }}
                transition={isRefreshing ? { duration: 0.6, repeat: Infinity, ease: "linear" } : { duration: 0.1 }}
              >
                <RotateCw className="w-4 h-4 text-indigo-600" />
              </motion.div>
              <span className="text-xs font-medium text-indigo-600">
                {isRefreshing ? "Refreshing..." : pullY >= PULL_THRESHOLD ? "Release to refresh" : "Pull to refresh"}
              </span>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Content — shift down during pull */}
      <motion.div
        style={{ y: pullY > 0 ? pullY * 0.4 : 0 }}
        transition={{ type: "spring", damping: 30, stiffness: 300 }}
      >
        {children}
      </motion.div>
    </div>
  );
}

