/**
 * ResponsiveSelectSheet — Mobile-safe selector wrapper
 * 
 * For problematic dropdowns on mobile, this provides a bottom sheet interface
 * on mobile while keeping dropdown behavior on desktop if needed.
 * 
 * Prevents clipping, z-index issues, and ensures mobile-friendly tap targets.
 */
import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '@/lib/utils';

/**
 * @param {object} props
 * @param {array} props.options - array of {label, value}
 * @param {string} props.value - currently selected value
 * @param {function} props.onChange - callback when selection changes
 * @param {string} [props.placeholder] - placeholder text
 * @param {function} [props.renderTrigger] - custom trigger button (default: simple button with selected label)
 * @param {boolean} [props.searchable] - enable search (default: false)
 * @param {string} [props.className] - additional classes
 */
export default function ResponsiveSelectSheet({
  options,
  value,
  onChange,
  placeholder = 'Select...',
  renderTrigger,
  searchable = false,
  className = '',
}) {
  const [isOpen, setIsOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const selectedOption = options.find(opt => opt.value === value);
  const filteredOptions = searchable
    ? options.filter(opt => opt.label.toLowerCase().includes(searchTerm.toLowerCase()))
    : options;

  const handleSelect = (selectedValue) => {
    onChange(selectedValue);
    setIsOpen(false);
    setSearchTerm('');
  };

  return (
    <div className={cn('relative', className)}>
      {/* Trigger button */}
      {renderTrigger ? (
        renderTrigger(selectedOption, () => setIsOpen(true))
      ) : (
        <button
          type="button"
          onClick={() => setIsOpen(true)}
          className="w-full px-3 py-2 border border-slate-200 rounded-lg bg-white text-left text-sm text-slate-900 hover:border-slate-300 transition-colors"
        >
          {selectedOption?.label || placeholder}
        </button>
      )}

      {/* Mobile bottom sheet — always visible on mobile to prevent clipping */}
      <AnimatePresence>
        {isOpen && (
          <>
            {/* Backdrop */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setIsOpen(false)}
              className="fixed inset-0 bg-black/40 z-40"
            />

            {/* Sheet */}
            <motion.div
              initial={{ y: '100%' }}
              animate={{ y: 0 }}
              exit={{ y: '100%' }}
              transition={{ type: 'spring', damping: 30, stiffness: 300 }}
              className="fixed bottom-0 left-0 right-0 z-50 bg-white rounded-t-3xl shadow-xl max-h-[80vh] flex flex-col"
            >
              {/* Header */}
              <div className="flex items-center justify-between px-5 py-4 border-b border-slate-100 flex-shrink-0">
                <h3 className="text-sm font-bold text-slate-900">Select Option</h3>
                <button
                  aria-label="Close selector"
                  onClick={() => setIsOpen(false)}
                  className="min-h-[44px] px-3 text-sm font-medium text-slate-500 hover:text-slate-700"
                >
                  Done
                </button>
              </div>

              {/* Search */}
              {searchable && (
                <div className="px-5 py-3 border-b border-slate-100 flex-shrink-0">
                  <input
                    type="text"
                    placeholder="Search..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
                  />
                </div>
              )}

              {/* Options list */}
              <div className="flex-1 overflow-y-auto">
                {filteredOptions.map((opt) => (
                  <button
                    key={opt.value}
                    onClick={() => handleSelect(opt.value)}
                    className={cn(
                      'w-full text-left px-5 py-3 border-b border-slate-50 text-sm transition-colors',
                      value === opt.value
                        ? 'bg-indigo-50 text-indigo-700 font-medium'
                        : 'text-slate-700 hover:bg-slate-50'
                    )}
                  >
                    {opt.label}
                  </button>
                ))}
                {filteredOptions.length === 0 && (
                  <div className="px-5 py-4 text-center text-sm text-slate-400">
                    No options found
                  </div>
                )}
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
}

/**
 * PageTransitionWrapper
 *
 * Wraps a page component with a native-feeling entrance animation.
 * Duration: ~180ms — fast enough to feel native, not sluggish.
 * Exit: quick fade to avoid jarring cuts.
 *
 * Respects prefers-reduced-motion: no animation if user has opted out.
 */
import React from "react";
import { motion } from "framer-motion";

function useReducedMotion() {
  if (typeof window === "undefined") return false;
  return window.matchMedia?.("(prefers-reduced-motion: reduce)").matches;
}

export default function PageTransitionWrapper({ children, pageKey }) {
  const reduced = useReducedMotion();

  if (reduced) {
    return <>{children}</>;
  }

  return (
    <motion.div
      key={pageKey}
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 1 }}
      transition={{ duration: 0.08, ease: 'easeOut' }}
      style={{ minHeight: '100%', background: '#f8fafc', backgroundColor: '#f8fafc' }}
    >
      {children}
    </motion.div>
  );
}

