import React, { useState, useEffect } from 'react';

/**
 * NativeSplashScreen — full-screen Reciply splash overlay shown ONLY inside
 * the native Android Capacitor WebView. Designed to feel like a seamless
 * continuation of the native 300ms launch splash.
 *
 * Behavior:
 *  • Native-only detection (Capacitor OR Android WebView "wv" OR Android UA)
 *  • TESTING MODE: shows on EVERY app launch (no sessionStorage gate)
 *  • Total visible: 1800ms, then 300ms fade-out, then unmount
 *  • Pure visual overlay — never blocks auth, routing, or app boot
 */

const VISIBLE_MS = 1800;
const FADE_MS = 300;

// Reciply full splash background image (full-screen cover).
const SPLASH_IMAGE_URL =
  'https://qtrypzzcjebvfcihiynt.supabase.co/storage/v1/object/public/base44-prod/public/c5c70c540_reciply_splash.png';

function detectNativeApp() {
  if (typeof window === 'undefined') return false;
  const ua = (typeof navigator !== 'undefined' && navigator.userAgent) || '';
  return !!window.Capacitor || ua.includes('wv') || ua.includes('Android');
}

export default function NativeSplashScreen() {
  const isNativeApp = detectNativeApp();

  // Decide visibility synchronously on first render to avoid any flash.
  const [visible, setVisible] = useState(isNativeApp);
  const [fading, setFading] = useState(false);

  useEffect(() => {
    console.log('[NativeSplash] mounted');
    console.log('[NativeSplash] isNativeApp', isNativeApp);
    if (!isNativeApp) return;

    console.log('[NativeSplash] showing');
    const fadeTimer = setTimeout(() => {
      console.log('[NativeSplash] hiding');
      setFading(true);
    }, VISIBLE_MS);
    const unmountTimer = setTimeout(() => setVisible(false), VISIBLE_MS + FADE_MS);
    return () => {
      clearTimeout(fadeTimer);
      clearTimeout(unmountTimer);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  if (!visible) return null;

  return (
    <div
      aria-hidden="true"
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        width: '100vw',
        height: '100dvh',
        zIndex: 999999,
        backgroundColor: '#ffffff',
        backgroundImage: `url(${SPLASH_IMAGE_URL})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        opacity: fading ? 0 : 1,
        transition: `opacity ${FADE_MS}ms ease-out`,
        pointerEvents: fading ? 'none' : 'auto',
      }}
    />
  );
}

