    recipe?.source !== 'generated' ? (recipe?.id ?? null) : null,
    isSaved,
    recipe?.saves_count ?? 0
  );

  useEffect(() => {
    return () => {
      if (navTimeoutRef.current) clearTimeout(navTimeoutRef.current);
