              <span className="text-xs text-slate-500">{recipe.author_name}</span>
            </button>
            {recipe.id && (
              <a
                href={cookModeUrl || (createPageUrl("CookMode") + `?id=${recipe.id}`)}
                onClick={(e) => e.stopPropagation()}
                className="w-9 h-9 rounded-full flex items-center justify-center shadow-lg shadow-indigo-200 hover:opacity-90 active:scale-95 transition-all flex-shrink-0"
                style={{ background: "linear-gradient(135deg,#6366f1,#8b5cf6)" }}
              >
                <Play className="w-4 h-4 text-white fill-white ml-0.5" />
              </a>
            )}
          </div>
        )}
      </CardContent>
    </Card>
