}

import React from "react";

/**
 * LoadingSpinner — premium animated loader.
 * - Outer rotating gradient ring
 * - Pulsing inner dot
 * - Animated dots after the loading label (".", "..", "...")
 *
 * Usage:
 *   <LoadingSpinner />
 *   <LoadingSpinner label="Loading" size={64} />
 */
export default function LoadingSpinner({
  label = "Loading",
  size = 56,
  color = "#6366f1",
  bgColor = "#e0e7ff",
  showLabel = true,
}) {
  const ringSize = size;
  const dotSize = Math.max(6, Math.round(size * 0.18));

  return (
    <div className="flex flex-col items-center justify-center gap-3">
      <style>{`
        @keyframes rs-spin {
          to { transform: rotate(360deg); }
        }
        @keyframes rs-pulse {
          0%, 100% { transform: scale(0.85); opacity: 0.6; }
          50% { transform: scale(1.15); opacity: 1; }
        }
        @keyframes rs-dot1 {
          0%, 60%, 100% { opacity: 0.25; transform: translateY(0); }
          20% { opacity: 1; transform: translateY(-2px); }
        }
        @keyframes rs-dot2 {
          0%, 80%, 100% { opacity: 0.25; transform: translateY(0); }
          40% { opacity: 1; transform: translateY(-2px); }
        }
        @keyframes rs-dot3 {
          0%, 20%, 100% { opacity: 0.25; transform: translateY(0); }
          60% { opacity: 1; transform: translateY(-2px); }
        }
      `}</style>

      <div
        style={{
          position: "relative",
          width: ringSize,
          height: ringSize,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        {/* Spinning gradient ring */}
        <div
          style={{
            position: "absolute",
            inset: 0,
            borderRadius: "50%",
            border: `3px solid ${bgColor}`,
            borderTopColor: color,
            borderRightColor: color,
            animation: "rs-spin 0.9s linear infinite",
          }}
        />
        {/* Pulsing inner dot */}
        <div
          style={{
            width: dotSize,
            height: dotSize,
            borderRadius: "50%",
            background: color,
            animation: "rs-pulse 1.2s ease-in-out infinite",
            boxShadow: `0 0 ${dotSize}px ${color}55`,
          }}
        />
      </div>

      {showLabel && label && (
        <div
          style={{
            fontSize: 13,
            fontWeight: 600,
            color: "#64748b",
            letterSpacing: "0.01em",
            display: "inline-flex",
            alignItems: "baseline",
            gap: 1,
          }}
          aria-live="polite"
        >
          <span>{label}</span>
          <span style={{ display: "inline-flex" }}>
            <span style={{ animation: "rs-dot1 1.4s infinite" }}>.</span>
            <span style={{ animation: "rs-dot2 1.4s infinite" }}>.</span>
            <span style={{ animation: "rs-dot3 1.4s infinite" }}>.</span>
          </span>
        </div>
      )}
    </div>
  );
}

