/**
 * ReportSuccessModal — Shows success animation after report submit
 * Spinner → green check morphs in, then "Report Submitted" message
 */
import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';

export default function ReportSuccessModal({ isOpen, onClose }) {
  const [stage, setStage] = useState('loading'); // loading → success → message

  useEffect(() => {
    if (!isOpen) {
      setStage('loading');
      return;
    }

    const timer1 = setTimeout(() => setStage('success'), 1200);
    const timer2 = setTimeout(() => setStage('message'), 1800);
    const timer3 = setTimeout(() => {
      onClose();
      setStage('loading');
    }, 3500);

    return () => {
      clearTimeout(timer1);
      clearTimeout(timer2);
      clearTimeout(timer3);
    };
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-center justify-center">
      <motion.div
        initial={{ scale: 0.8, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        exit={{ scale: 0.8, opacity: 0 }}
        className="bg-white rounded-3xl p-8 flex flex-col items-center gap-4 max-w-sm"
      >
        {/* Spinner or Check */}
        <div className="w-16 h-16 rounded-full flex items-center justify-center overflow-hidden">
          {stage === 'loading' && (
            <motion.div
              animate={{ rotate: 360 }}
              transition={{ repeat: Infinity, duration: 1 }}
              className="w-8 h-8 border-2 border-orange-200 border-t-orange-500 rounded-full"
            />
          )}
          {stage === 'success' && (
            <motion.svg
              viewBox="0 0 24 24"
              className="w-10 h-10"
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ type: 'spring', stiffness: 200 }}
            >
              <motion.circle
                cx="12"
                cy="12"
                r="11"
                fill="none"
                stroke="#10b981"
                strokeWidth="2"
                initial={{ strokeDasharray: '69 69', opacity: 0 }}
                animate={{ strokeDasharray: '69 69', opacity: 1 }}
                transition={{ duration: 0.4 }}
              />
              <motion.path
                d="M9 12l2 2 4-4"
                stroke="#10b981"
                strokeWidth="2"
                fill="none"
                strokeLinecap="round"
                initial={{ pathLength: 0 }}
                animate={{ pathLength: 1 }}
                transition={{ duration: 0.5, delay: 0.1 }}
              />
            </motion.svg>
          )}
          {(stage === 'success' || stage === 'message') && (
            <motion.svg
              viewBox="0 0 24 24"
              className="w-10 h-10"
              initial={stage === 'message' ? { scale: 1 } : {}}
            >
              <circle cx="12" cy="12" r="11" fill="none" stroke="#10b981" strokeWidth="2" />
              <path d="M9 12l2 2 4-4" stroke="#10b981" strokeWidth="2" fill="none" strokeLinecap="round" />
            </motion.svg>
          )}
        </div>

        {/* Message */}
        {stage === 'message' && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-center"
          >
            <h3 className="text-lg font-bold text-slate-900">Report Submitted</h3>
            <p className="text-sm text-slate-500 mt-1">Thank you for helping keep Reciply safe.</p>
          </motion.div>
        )}
      </motion.div>
    </div>
  );
}

