/**
 * RipoStateUploadZone — Individual upload zone for each Ripo state asset
 * Allows drag-drop or click-to-browse for a specific asset key
 */
import React, { useRef, useState } from 'react';
import { Upload, CheckCircle2, AlertCircle, Loader2, X } from 'lucide-react';
import { motion } from 'framer-motion';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

export default function RipoStateUploadZone({
  assetKey,
  assetName,
  currentFile,
  onFileSelect,
  onUpload,
  uploading = false,
  uploadSuccess = false,
  uploadError = null,
}) {
  const fileInputRef = useRef(null);
  const [isDragging, setIsDragging] = useState(false);
  const [selectedFile, setSelectedFile] = useState(null);

  const handleFileChange = (files) => {
    if (!files?.length) return;
    const file = files[0];
    const ext = file.name.split('.').pop()?.toLowerCase();

    if (!['mp4', 'gif', 'jpg', 'jpeg', 'png', 'webp', 'svg'].includes(ext)) {
      toast.error(`Unsupported file type: .${ext}`);
      return;
    }

    setSelectedFile(file);
    onFileSelect?.(file);
  };

  const handleUploadClick = async () => {
    if (!selectedFile && !currentFile) {
      toast.error('Please select a file first');
      return;
    }
    const fileToUpload = selectedFile || currentFile;
    await onUpload?.(fileToUpload);
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      className="border border-white/20 rounded-2xl p-6 space-y-4"
    >
      {/* Header */}
      <div className="flex items-start justify-between">
        <div>
          <h3 className="font-bold text-white mb-1">{assetName}</h3>
          <p className="text-xs text-slate-400">Key: <code className="text-slate-300 font-mono">{assetKey}</code></p>
        </div>
        {uploadSuccess && (
          <div className="px-3 py-1 rounded-full bg-emerald-500/20 text-emerald-300 text-xs font-semibold flex items-center gap-1">
            <CheckCircle2 className="w-3 h-3" />
            Done
          </div>
        )}
        {uploadError && (
          <div className="px-3 py-1 rounded-full bg-rose-500/20 text-rose-300 text-xs font-semibold flex items-center gap-1">
            <AlertCircle className="w-3 h-3" />
            Error
          </div>
        )}
      </div>

      {/* Dropzone */}
      <div
        onDrop={(e) => {
          e.preventDefault();
          setIsDragging(false);
          handleFileChange(e.dataTransfer.files);
        }}
        onDragOver={(e) => {
          e.preventDefault();
          setIsDragging(true);
        }}
        onDragLeave={() => setIsDragging(false)}
        onClick={() => fileInputRef.current?.click()}
        className={cn(
          'border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all',
          isDragging ? 'border-indigo-400 bg-indigo-500/10' : 'border-white/20 hover:border-white/40 hover:bg-white/5'
        )}
      >
        <input
          ref={fileInputRef}
          type="file"
          accept="image/*,video/mp4,.gif"
          onChange={(e) => handleFileChange(e.target.files)}
          className="hidden"
        />
        <Upload className="w-8 h-8 text-slate-400 mx-auto mb-2" />
        <p className="text-sm font-semibold text-slate-200">
          {selectedFile ? selectedFile.name : 'Drop file or click to browse'}
        </p>
        <p className="text-xs text-slate-500 mt-1">MP4, PNG, GIF, WEBP, JPG, SVG</p>
      </div>

      {/* Error message */}
      {uploadError && (
        <div className="p-3 rounded-lg bg-rose-500/10 border border-rose-500/20 flex items-start gap-2">
          <AlertCircle className="w-4 h-4 text-rose-400 flex-shrink-0 mt-0.5" />
          <p className="text-xs text-rose-300">{uploadError}</p>
        </div>
      )}

      {/* Upload button */}
      <button
        onClick={handleUploadClick}
        disabled={uploading || !selectedFile || uploadSuccess}
        className={cn(
          'w-full h-10 rounded-xl font-semibold text-sm flex items-center justify-center gap-2 transition-all',
          uploadSuccess
            ? 'bg-emerald-500/20 text-emerald-300 cursor-default'
            : 'bg-indigo-600 hover:bg-indigo-500 text-white disabled:opacity-50'
        )}
      >
        {uploading ? (
          <>
            <Loader2 className="w-4 h-4 animate-spin" />
            Uploading…
          </>
        ) : uploadSuccess ? (
          <>
            <CheckCircle2 className="w-4 h-4" />
            Uploaded
          </>
        ) : (
          <>
            <Upload className="w-4 h-4" />
            Upload {assetName}
          </>
        )}
      </button>

      {/* Clear button */}
      {selectedFile && (
        <button
          onClick={() => {
            setSelectedFile(null);
            if (fileInputRef.current) fileInputRef.current.value = '';
          }}
          className="w-full h-8 rounded-lg bg-white/5 hover:bg-white/10 text-slate-400 text-xs font-medium flex items-center justify-center gap-2 transition-all"
        >
          <X className="w-3.5 h-3.5" />
          Clear Selection
        </button>
      )}
    </motion.div>
  );
}

/**
 * GoalButton — Task B implementation
 * Selection animation with sparkles on select
