import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

const Sparkle = ({ delay, id }) => {
  const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  if (prefersReducedMotion) return null;

  const angle = (id / 4) * Math.PI * 2;
  const distance = 48;
  const endX = Math.cos(angle) * distance;
  const endY = Math.sin(angle) * distance;

  return (
    <motion.div
      key={`sparkle-${id}`}
      initial={{ x: 0, y: 0, opacity: 1, scale: 1 }}
      animate={{ x: endX, y: endY, opacity: 0, scale: 0 }}
      transition={{ duration: 0.7, ease: "easeOut", delay }}
      className="absolute pointer-events-none"
      style={{
        width: "6px",
        height: "6px",
        top: "50%",
        left: "50%",
        transform: "translate(-50%, -50%)",
      }}
    >
      <div
        className="w-full h-full rounded-full"
        style={{ background: "#fbbf24", boxShadow: "0 0 6px #f97316" }}
      />
    </motion.div>
  );
};

export default function GoalButton({ goal, isSelected, onClick }) {
  const [showSparkles, setShowSparkles] = useState(false);
  const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  const handleClick = () => {
    if (!isSelected && !prefersReducedMotion) {
      // Trigger sparkles on select
      setShowSparkles(true);
      setTimeout(() => setShowSparkles(false), 700);
    }
    onClick();
  };

  return (
    <motion.button
      onClick={handleClick}
      whileTap={prefersReducedMotion ? {} : { scale: 0.96 }}
      className={cn(
        "relative p-4 rounded-2xl border-2 transition-all overflow-hidden",
        isSelected
