/**
 * PricingEnginePro — Production-Grade Ingredient Pricing Engine v2
 *
 * Architecture:
 *   base_price (canonical DB, USD/100g or /100ml or /piece)
 *   × country_multiplier        (ISO country, from CanonicalIngredientDatabase)
 *   × category_multiplier       (per-country category adjustment)
 *   × market_freshness_factor   (stable static layer, not fake live data)
 *   → ingredient_cost_usd
 *
 * Pricing modes:
 *   weight_based   → price_per_100g  (rice, chicken, salmon, yogurt…)
 *   volume_based   → price_per_100ml (olive oil, milk, soy sauce…)
 *   unit_based     → price_per_piece (eggs, lemons, avocado, garlic clove, tuna can…)
 *   hybrid         → per_piece primary, fallback to per gram for weight queries
 *
 * Cross-category sanity:
 *   After computing a price, validate against expected category range.
 *   If result is implausible, apply safe fallback from category floor.
 *
 * Explainability:
 *   Every computed price returns a full _debug trace.
 */

import {
  lookupCanonical,
  CATEGORY_FLOORS,
  PIECE_WEIGHTS,
  getCountryMultiplier,
} from './CanonicalIngredientDatabase';

