  return PRICING_MODE_OVERRIDES[key] ?? null;
}

// ── 2. CATEGORY-LEVEL MULTIPLIERS ────────────────────────────────────────────
// Formula: final_price = base × country_mult × category_mult
//
// Rationale:
//  - Seafood is relatively cheaper in JP (fishing nation) vs IL (import dependent)
//  - Olive oil is cheaper in IT, ES (producer countries) vs JP (imports)
//  - Dairy is costlier in Asia (import/logistics) vs EU (local production)
//  - Meat is cheaper in AR, BR (cattle farming nations)
//  - Grains are cheaper in IN (major producer) vs NO (high cost)
//
// Structure: CATEGORY_COUNTRY_MULTIPLIERS[country][category] = factor
// If a country/category combo is missing, defaults to 1.0
