function getCategoryMultiplier(country = 'US', category = 'default') {
  const countryMap = CATEGORY_COUNTRY_MULTIPLIERS[country?.toUpperCase()];
  if (!countryMap) return 1.0;
  const catMult = countryMap[category] ?? 1.0;

  // ── Anti-stacking guard ────────────────────────────────────────────────────
  // The country_multiplier captures overall cost-of-living.
  // The category_multiplier captures how that specific category deviates WITHIN that country.
  // For countries where the country mult already reflects agricultural advantage (e.g. IN=0.45),
  // a category mult of 0.45 for grains would compound to 0.2025 — unrealistically cheap.
  // Cap the combined product at 0.35 for any non-premium-priced-country to prevent this.
  //
  // Exception: premium countries (CH, NO) stacking UP is intentional (everything expensive).
  const countryMult = getCountryMultiplier(country);
  const combined = countryMult * catMult;
  const COMBINED_FLOOR = 0.30; // No ingredient category should be priced below 30% of US baseline
  const COMBINED_CEILING = 2.50; // Nor above 250%
  if (combined < COMBINED_FLOOR) {
    // Return a catMult that brings combined back to the floor
    return COMBINED_FLOOR / countryMult;
  }
  if (combined > COMBINED_CEILING) {
    return COMBINED_CEILING / countryMult;
  }
  return catMult;
}

