  herb:      { min: 0.40, max: 2.00,  family_min: 0.30 },
  legume:    { min: 0.22, max: 1.20,  family_min: 0.18 },  // canned/cooked legumes are ~$0.35-0.60/100g; dry ~$0.22-0.40/100g
  nut:       { min: 0.60, max: 3.00,  family_min: 0.40 },
  seed:      { min: 0.40, max: 1.50,  family_min: 0.30 },
  condiment: { min: 0.08, max: 2.00,  family_min: 0.06 },
  pantry:    { min: 0.02, max: 5.00,  family_min: 0.02 },   // vanilla bean legitimate
  default:   { min: 0.05, max: 8.00,  family_min: 0.04 },
};

// Cross-family sanity: salmon should never be cheaper than cucumber per gram
// These express minimum expected ratios between premium and base ingredients
const CROSS_FAMILY_GUARDS = [
  // { premium, base, min_ratio }
  // e.g. salmon must cost >= 3x cucumber per gram
  { premium_category: 'seafood',  base_category: 'vegetable', min_ratio: 2.5 },
  { premium_category: 'seafood',  base_category: 'grain',     min_ratio: 5.0 },
  { premium_category: 'meat',     base_category: 'grain',     min_ratio: 4.0 },
  { premium_category: 'poultry',  base_category: 'grain',     min_ratio: 4.0 },
  { premium_category: 'cheese',   base_category: 'grain',     min_ratio: 5.0 },
  { premium_category: 'nut',      base_category: 'grain',     min_ratio: 3.0 },
];

function validateSanity(pricePerGram, category, canonicalName, basePrice) {
  const range = SANITY_RANGES_PER_100G[category] ?? SANITY_RANGES_PER_100G.default;
  const pricePer100g = pricePerGram * 100;

  if (pricePer100g < range.min) {
    const corrected = range.min / 100;
    return {
      passed: false,
      corrected_price_per_gram: corrected,
      reason: `below_category_min (got ${pricePer100g.toFixed(3)}, min ${range.min})`,
    };
  }
  if (pricePer100g > range.max) {
    const corrected = range.max / 100;
    return {
      passed: false,
      corrected_price_per_gram: corrected,
      reason: `above_category_max (got ${pricePer100g.toFixed(3)}, max ${range.max})`,
    };
  }
  return { passed: true };
}

// ── 5. UNIT CONVERSION ────────────────────────────────────────────────────────
const UNIT_TO_GRAMS = {
  g: 1, gram: 1, grams: 1, kg: 1000, kilogram: 1000, kilograms: 1000,
  oz: 28.35, lb: 453.59, pound: 453.59, pounds: 453.59,
};
const UNIT_TO_ML = {
  ml: 1, milliliter: 1, milliliters: 1,
  l: 1000, liter: 1000, litre: 1000, liters: 1000, litres: 1000,
  cup: 240, cups: 240,
  tbsp: 15, tablespoon: 15, tablespoons: 15,
  tsp: 5, teaspoon: 5, teaspoons: 5,
  'fl oz': 29.57, floz: 29.57,
};

// Per-ingredient cup→grams (overrides generic 240ml cup assumption for solids)
const CUP_TO_GRAMS_OVERRIDES = {
  'rice':        185,
  'sushi rice':  195,
  'jasmine rice':195,
  'basmati rice':180,
  'brown rice':  190,
  'arborio rice':210,
  'quinoa':      185,
  'oats':        90,
  'flour':       125,
  'sugar':       200,
  'salt':        288,
  'butter':      227,
  'yogurt':      245,
  'milk':        244,
};

function parseFrac(str) {
  const frac = str.match(/^(\d+)\s*\/\s*(\d+)$/);
  if (frac) return parseFloat(frac[1]) / parseFloat(frac[2]);
  const mixed = str.match(/^(\d+)\s+(\d+)\s*\/\s*(\d+)$/);
  if (mixed) return parseFloat(mixed[1]) + parseFloat(mixed[2]) / parseFloat(mixed[3]);
  return parseFloat(str.replace(',', '.'));
}

function parseAmount(amountStr, ingredientName = '') {
  if (!amountStr) return null;
  const s = String(amountStr).trim().toLowerCase();
  const ing = ingredientName.toLowerCase();

  // Parenthetical gram hint e.g. "1 can (185g)"
  const parenG = s.match(/\((?:about\s*|~\s*)?(\d+(?:\.\d+)?)\s*g\)/i);
  if (parenG) return { grams: parseFloat(parenG[1]), ml: null, pieces: null, raw_unit: 'g_hint' };
  const parenMl = s.match(/\((?:about\s*|~\s*)?(\d+(?:\.\d+)?)\s*ml\)/i);
  if (parenMl) return { grams: null, ml: parseFloat(parenMl[1]), pieces: null, raw_unit: 'ml_hint' };

  const numMatch = s.match(/^([\d.,]+(?:\s+\d+\s*\/\s*\d+)?|\d+\s*\/\s*\d+)/);
  if (!numMatch) return null;
  const quantity = parseFrac(numMatch[1].trim());
  if (!Number.isFinite(quantity) || quantity <= 0) return null;
  const rest = s.slice(numMatch[0].length).trim();

  // Weight unit
  for (const [unit, factor] of Object.entries(UNIT_TO_GRAMS)) {
    if (new RegExp(`^${unit}\\b`, 'i').test(rest)) {
      return { grams: quantity * factor, ml: null, pieces: null, raw_quantity: quantity, raw_unit: unit };
    }
  }

  // Volume unit — use per-ingredient cup override for solids
  for (const [unit, factor] of Object.entries(UNIT_TO_ML)) {
    if (new RegExp(`^${unit}\\b`, 'i').test(rest)) {
      // For cup+solid ingredients, convert to grams directly
      if (unit === 'cup' || unit === 'cups') {
        for (const [ingKey, g] of Object.entries(CUP_TO_GRAMS_OVERRIDES)) {
          if (ing.includes(ingKey)) {
            return { grams: quantity * g, ml: null, pieces: null, raw_quantity: quantity, raw_unit: unit, cup_override: true };
          }
        }
      }
      return { grams: null, ml: quantity * factor, pieces: null, raw_quantity: quantity, raw_unit: unit };
    }
  }

  // Countable piece words
  const pieceWords = [
    'egg','eggs','clove','cloves','piece','pieces','can','cans',
    'fillet','fillets','lemon','lemons','lime','limes','avocado','avocados',
    'slice','slices','bunch','bunches','head','stalk','stalks',
    'breast','breasts','thigh','thighs','strip','strips',
  ];
  for (const word of pieceWords) {
    if (rest.startsWith(word) || (!rest && ing.includes(word.replace(/s$/, '')))) {
      return { grams: null, ml: null, pieces: quantity, raw_quantity: quantity, raw_unit: word };
    }
  }

  // Bare number — check piece weights for known ingredient
  if (!rest || /^(about|~|of|fresh|dried|large|medium|small)/i.test(rest)) {
    for (const [key, g] of Object.entries(PIECE_WEIGHTS)) {
      if (ing.includes(key) || key.includes(ing.split(' ')[0])) {
        return { grams: quantity * g, ml: null, pieces: quantity, raw_quantity: quantity, raw_unit: key };
      }
    }
  }

  return { grams: null, ml: null, pieces: quantity, raw_quantity: quantity, raw_unit: 'unit' };
}

// ── 6. LIQUID DENSITY ─────────────────────────────────────────────────────────
const LIQUID_DENSITIES = {
  oil: 0.92, honey: 1.40, syrup: 1.32, milk: 1.03, cream: 1.01,
  sauce: 1.05, broth: 1.00, stock: 1.00, juice: 1.04, vinegar: 1.01,
  default: 1.00,
};
function getLiquidDensity(name) {
  const lower = (name || '').toLowerCase();
  for (const [key, d] of Object.entries(LIQUID_DENSITIES)) {
    if (lower.includes(key)) return d;
  }
  return LIQUID_DENSITIES.default;
}

// ── 7. CORE COMPUTE FUNCTION ──────────────────────────────────────────────────
/**
 * computeIngredientCostPro
 *
 * Returns { cost: number|null, debug: object }
 * debug contains full explainability trace.
 */
export function computeIngredientCostPro(
  ingredientName,
  amountStr,
  country = 'US',
  baseGrams = null
) {
  const entry = lookupCanonical(ingredientName);
  const pricingModeConfig = entry ? getPricingMode(entry.name) : getPricingMode(ingredientName);
  const countryMult = getCountryMultiplier(country);
  const category = entry?.category ?? 'default';
  const catMult = getCategoryMultiplier(country, category);
  const freshness = getMarketFreshness(entry?.name ?? ingredientName);

  const debug = {
    ingredient_input: ingredientName,
    canonical_matched: entry?.name ?? null,
    match_method: entry?.match_method ?? 'unmatched',
    match_confidence: entry?.match_confidence ?? 0,
    category,
    pricing_mode: pricingModeConfig?.mode ?? 'weight_based',
    amount_input: amountStr,
    normalized_quantity: null,
    normalized_unit: null,
    base_price_used: null,
    base_price_source: null,
    country_multiplier: countryMult,
    category_multiplier: catMult,
    market_freshness_factor: freshness.factor,
    market_freshness_note: freshness.note,
    sanity_check: null,
    final_cost_usd: null,
    formula: null,
  };

  // ── Fast path: pre-computed base_grams ────────────────────────────────────
  if (baseGrams !== null && Number.isFinite(baseGrams) && baseGrams > 0) {
    return _computeFromGramsPro(baseGrams, entry, pricingModeConfig, countryMult, catMult, freshness, debug);
  }

  const parsed = parseAmount(amountStr, ingredientName);
  if (!parsed) {
    debug.error = 'parse_failed';
    return { cost: null, debug };
  }

  let { grams, ml, pieces } = parsed;
  debug.amount_parsed = parsed;

  // ── piece resolution ───────────────────────────────────────────────────────
  if (grams == null && ml == null && pieces != null) {
    // Use price_per_piece if available and mode is unit_based
    if (entry?.price_per_piece != null && (pricingModeConfig?.mode === 'unit_based' || pricingModeConfig?.mode === 'hybrid')) {
      const rawCost = pieces * entry.price_per_piece;
      const allMult = countryMult * catMult * freshness.factor;
      const cost = rawCost * allMult;
      debug.normalized_quantity = pieces;
      debug.normalized_unit = 'pieces';
      debug.base_price_used = entry.price_per_piece;
      debug.base_price_source = 'price_per_piece';
      debug.formula = `${pieces} × $${entry.price_per_piece.toFixed(3)}/pc × ${countryMult.toFixed(3)}(country) × ${catMult.toFixed(3)}(cat) × ${freshness.factor.toFixed(3)}(market) = $${cost.toFixed(3)}`;
      debug.final_cost_usd = parseFloat(cost.toFixed(3));
      return { cost: debug.final_cost_usd, debug };
    }

    // Convert pieces → grams
    const ing = ingredientName.toLowerCase();
    let pieceG = pricingModeConfig?.piece_grams ?? null;
    if (!pieceG) {
      for (const [key, g] of Object.entries(PIECE_WEIGHTS)) {
        if (ing.includes(key) || key.includes(ing.split(' ')[0])) {
          pieceG = g;
          break;
        }
      }
    }
    grams = pieces * (pieceG ?? 100);
    debug.piece_to_grams_used = pieceG ?? 100;
  }

  // ── volume → grams for weight-based entries ───────────────────────────────
  if (grams == null && ml != null) {
    if (entry?.price_per_100g != null && entry?.price_per_100ml == null) {
      grams = ml * getLiquidDensity(ingredientName);
      ml = null;
    }
  }

  if (grams != null && grams > 0) {
    return _computeFromGramsPro(grams, entry, pricingModeConfig, countryMult, catMult, freshness, debug);
  }
  if (ml != null && ml > 0) {
    return _computeFromMlPro(ml, entry, pricingModeConfig, countryMult, catMult, freshness, debug);
  }

  debug.error = 'no_quantity_resolved';
  return { cost: null, debug };
}

function _computeFromGramsPro(grams, entry, modeConfig, countryMult, catMult, freshness, debug) {
  const category = entry?.category ?? 'default';
  const floor = CATEGORY_FLOORS[category] ?? CATEGORY_FLOORS.default;
  const allMult = countryMult * catMult * freshness.factor;

  let rawCostPer100g = null;
  let priceSource = null;

  if (entry?.price_per_100g != null) {
    rawCostPer100g = entry.price_per_100g;
    priceSource = 'canonical_price_per_100g';
  } else if (entry?.price_per_100ml != null) {
    const density = getLiquidDensity(entry.name ?? '');
    rawCostPer100g = entry.price_per_100ml / density * (entry.edible_ratio ?? 1.0);
    priceSource = 'canonical_price_per_100ml_converted';
  } else {
    rawCostPer100g = _inferFallback(entry?.name ?? '', floor);
    priceSource = 'category_fallback';
  }

  const edible = entry?.edible_ratio ?? 1.0;
  const editableG = grams * edible;
  let rawCost = (editableG / 100) * rawCostPer100g;

  // Apply category floor minimum
  const minCost = (grams / 100) * floor;
  rawCost = Math.max(rawCost, minCost);

  const adjustedCost = rawCost * allMult;

  // Sanity check
  const costPerGram = adjustedCost / grams;
  const sanity = validateSanity(costPerGram, category, entry?.name, rawCostPer100g);
  if (!sanity.passed) {
    const correctedCost = sanity.corrected_price_per_gram * grams * allMult;
    debug.normalized_quantity = parseFloat(grams.toFixed(2));
    debug.normalized_unit = 'g';
    debug.base_price_used = rawCostPer100g;
    debug.base_price_source = priceSource;
    debug.sanity_check = { passed: false, reason: sanity.reason, original: adjustedCost, corrected: correctedCost };
    debug.final_cost_usd = parseFloat(Math.min(adjustedCost, correctedCost).toFixed(3));
    debug.formula = `${grams}g × $${rawCostPer100g.toFixed(4)}/100g × ${edible}(edible) × ${countryMult.toFixed(3)}(country) × ${catMult.toFixed(3)}(cat) × ${freshness.factor.toFixed(3)}(market) [sanity_corrected]`;
    return { cost: debug.final_cost_usd, debug };
  }

  const finalCost = _sanityCap(adjustedCost);
  debug.normalized_quantity = parseFloat(grams.toFixed(2));
  debug.normalized_unit = 'g';
  debug.base_price_used = rawCostPer100g;
  debug.base_price_source = priceSource;
  debug.sanity_check = { passed: true };
  debug.formula = `${grams.toFixed(1)}g × $${rawCostPer100g.toFixed(4)}/100g × ${edible}(edible) × ${countryMult.toFixed(3)}(country) × ${catMult.toFixed(3)}(cat) × ${freshness.factor.toFixed(3)}(market) = $${finalCost.toFixed(3)}`;
  debug.final_cost_usd = parseFloat(finalCost.toFixed(3));
  return { cost: debug.final_cost_usd, debug };
}

function _computeFromMlPro(ml, entry, modeConfig, countryMult, catMult, freshness, debug) {
  const category = entry?.category ?? 'oil';
  const floor = CATEGORY_FLOORS[category] ?? CATEGORY_FLOORS.default;
  const allMult = countryMult * catMult * freshness.factor;

  let rawCostPer100ml = null;
  let priceSource = null;

  if (entry?.price_per_100ml != null) {
    rawCostPer100ml = entry.price_per_100ml;
    priceSource = 'canonical_price_per_100ml';
  } else if (entry?.price_per_100g != null) {
    const density = getLiquidDensity(entry.name ?? '');
    rawCostPer100ml = entry.price_per_100g * density;
    priceSource = 'canonical_price_per_100g_converted';
  } else {
    rawCostPer100ml = _inferFallback(entry?.name ?? '', floor);
    priceSource = 'category_fallback';
  }

  const edible = entry?.edible_ratio ?? 1.0;
  let rawCost = (ml * edible / 100) * rawCostPer100ml;

  const minCost = (ml / 100) * floor;
  rawCost = Math.max(rawCost, minCost);

  const adjustedCost = rawCost * allMult;
  const finalCost = _sanityCap(adjustedCost);

  debug.normalized_quantity = parseFloat(ml.toFixed(2));
  debug.normalized_unit = 'ml';
  debug.base_price_used = rawCostPer100ml;
  debug.base_price_source = priceSource;
  debug.sanity_check = { passed: true };
  debug.formula = `${ml.toFixed(1)}ml × $${rawCostPer100ml.toFixed(4)}/100ml × ${edible}(edible) × ${countryMult.toFixed(3)}(country) × ${catMult.toFixed(3)}(cat) × ${freshness.factor.toFixed(3)}(market) = $${finalCost.toFixed(3)}`;
  debug.final_cost_usd = parseFloat(finalCost.toFixed(3));
  return { cost: debug.final_cost_usd, debug };
}

function _inferFallback(name, floor) {
  const n = name.toLowerCase();
  if (/shawarma/.test(n)) return CATEGORY_FLOORS.poultry; // shawarma is always protein-priced
  if (/burger.*patty|patty.*burger|hamburger.*patty/.test(n)) return CATEGORY_FLOORS.meat;
  if (/chicken|turkey|poultry/.test(n)) return CATEGORY_FLOORS.poultry;
  if (/beef|pork|lamb|steak/.test(n)) return CATEGORY_FLOORS.meat;
  if (/fish|salmon|tuna|shrimp|prawn|seafood|cod/.test(n)) return CATEGORY_FLOORS.seafood;
  if (/egg/.test(n)) return CATEGORY_FLOORS.eggs;
  if (/cheese|mozzarella|parmesan/.test(n)) return CATEGORY_FLOORS.cheese;
  if (/milk|cream|yogurt|butter/.test(n)) return CATEGORY_FLOORS.dairy;
  if (/oil/.test(n)) return CATEGORY_FLOORS.oil;
  if (/spice|herb|cumin|paprika/.test(n)) return CATEGORY_FLOORS.spice;
  if (/flour|rice|pasta|bread|grain/.test(n)) return CATEGORY_FLOORS.grain;
  return floor;
}

function _sanityCap(cost) {
  if (!Number.isFinite(cost) || cost < 0) return 0;
  return Math.min(cost, 50); // hard cap at $50/ingredient
}

// ── 8. RECIPE PRICER ─────────────────────────────────────────────────────────
/**
 * priceRecipeIngredientsPro
 *
 * Drop-in upgrade to priceRecipeIngredients.
 * Returns enriched recipe with per-ingredient cost + full debug traces.
 */
export function priceRecipeIngredientsPro(recipe, pantryItems = [], shopProducts = [], country = 'US') {
  if (!recipe?.ingredients?.length) return recipe;

  const baseServings = recipe.servings || 1;
  let totalCost = 0;
  let hasAnyPriced = false;
  let allRequiredPriced = true;

  const pricedIngredients = recipe.ingredients.map(group => ({
    ...group,
    items: (group.items || []).map(item => {
      if (!item?.name) return item;

      const { cost, debug } = computeIngredientCostPro(
        item.name,
        item.amount || '',
        country,
        item.base_grams ?? null
      );

      if (cost != null && cost > 0) {
        hasAnyPriced = true;
        totalCost += cost;
        return {
          ...item,
          ingredient_cost: parseFloat(cost.toFixed(3)),
          _price_source: {
            type: 'canonical_pro',
            canonical_name: debug.canonical_matched,
            category: debug.category,
            pricing_mode: debug.pricing_mode,
            match_method: debug.match_method,
            match_confidence: debug.match_confidence,
            base_price_used: debug.base_price_used,
            country_used: country,
            country_multiplier: debug.country_multiplier,
            category_multiplier: debug.category_multiplier,
            market_freshness_factor: debug.market_freshness_factor,
            formula: debug.formula,
            sanity_passed: debug.sanity_check?.passed ?? true,
          },
        };
      } else {
        if (!item.optional) allRequiredPriced = false;
        return { ...item, ingredient_cost: null, _price_source: { confidence: 'unknown', error: debug.error } };
      }
    }),
  }));

  const pricingStatus = hasAnyPriced
    ? (allRequiredPriced ? 'known' : 'partial')
    : 'unknown';

  return {
    ...recipe,
    ingredients: pricedIngredients,
    total_cost: hasAnyPriced ? parseFloat(totalCost.toFixed(2)) : null,
    cost_per_serving: hasAnyPriced && baseServings > 0
      ? parseFloat((totalCost / baseServings).toFixed(2))
      : null,
    has_unknown_pricing: !hasAnyPriced,
    pricing_status: pricingStatus,
    pricing_currency: 'USD',
    pricing_country: country,
    pricing_engine_version: 'pro_v2',
  };
}

