    { name: 'Garlic', amounts: ['1 clove', '3 cloves'] },
    { name: 'Canned tuna', amounts: ['1 can', '100g'] },
  ];

  const results = {
    reference_examples: examples.map(e => {
      const { cost, debug } = computeIngredientCostPro(e.name, e.amount, e.country);
      return {
        ingredient: e.name,
        amount: e.amount,
        country: e.country,
        canonical_matched: debug.canonical_matched,
        pricing_mode: debug.pricing_mode,
        normalized_quantity: debug.normalized_quantity,
        normalized_unit: debug.normalized_unit,
        base_price_used: debug.base_price_used ? `$${debug.base_price_used.toFixed(4)}/100unit` : null,
        country_multiplier: debug.country_multiplier,
        category_multiplier: debug.category_multiplier,
        market_freshness: debug.market_freshness_factor,
        final_cost_usd: cost != null ? `$${cost.toFixed(3)}` : 'N/A',
        formula: debug.formula,
      };
    }),

    cross_country: crossCountry.map(e => ({
      ingredient: e.name,
      amount: e.amount,
      by_country: e.countries.map(c => {
        const { cost, debug } = computeIngredientCostPro(e.name, e.amount, c);
        return {
          country: c,
          country_mult: debug.country_multiplier,
          cat_mult: debug.category_multiplier,
          market_freshness: debug.market_freshness_factor,
          cost: cost != null ? `$${cost.toFixed(3)}` : 'N/A',
        };
      }),
    })),

    unit_scaling: unitScaling.map(e => ({
      ingredient: e.name,
      amounts: e.amounts.map(a => {
        const { cost, debug } = computeIngredientCostPro(e.name, a, 'US');
        return {
          amount: a,
          normalized: `${debug.normalized_quantity ?? '?'} ${debug.normalized_unit ?? '?'}`,
          cost: cost != null ? `$${cost.toFixed(3)}` : 'N/A',
        };
      }),
    })),
  };

  return results;
}

/**
 * RipoAnimationResolver — unified animation asset loading across the app
 *
 * Sources:
 * - RipoAsset: onboarding / feedback / states
 * - CookingAnimation: cooking mode steps
 *
 * Features:
 * - Aggressive preloading
 * - Instant fallback detection
 * - Caching + reuse
 * - Batch loading
 */
import { base44 } from "@/api/base44Client";

let animationCache = {}; // { key: { url, type, loaded: bool } }
let cacheInitialized = false;

// Initialize cache on first call
async function initializeCache() {
  if (cacheInitialized) return;
  cacheInitialized = true;

  try {
    // Batch load ALL active assets from both sources in parallel
    const [ripoAssets, cookingAnimations] = await Promise.all([
      base44.entities.RipoAsset.filter({ is_active: true }, '-created_date', 100).catch(() => []),
      base44.entities.CookingAnimation.filter({ is_active: true }, '-created_date', 100).catch(() => []),
    ]);

    // Build unified cache
    ripoAssets.forEach(asset => {
      if (asset.key && asset.file_url) {
        animationCache[asset.key] = {
          url: asset.file_url,
          type: asset.asset_type || 'mp4',
          loaded: false,
        };
      }
    });

    cookingAnimations.forEach(anim => {
      if (anim.key && anim.video_url) {
        animationCache[anim.key] = {
          url: anim.video_url,
          type: 'mp4',
          loaded: false,
        };
      }
    });
  } catch (err) {
    console.error('[RipoAnimationResolver] Cache init failed:', err);
  }
}

// Preload a video URL aggressively
export function preloadVideo(url) {
  if (!url) return;
  try {
    const link = document.createElement('link');
    link.rel = 'preload';
    link.as = 'video';
    link.href = url;
    // Detect type from URL extension — webm for transparency, mp4 otherwise
    link.type = /\.webm(\?|$)/i.test(url) ? 'video/webm' : 'video/mp4';
    document.head.appendChild(link);
  } catch (_) {}
}

// Resolve animation by key — returns { url, type } or null
export async function resolveAnimation(assetKey) {
  if (!assetKey) return null;

  // Initialize cache on first call
  if (!cacheInitialized) await initializeCache();

  // Return from cache if exists
  if (animationCache[assetKey]) {
    return animationCache[assetKey];
  }

  // Not in cache — try direct query as fallback
  try {
    const ripoResults = await base44.entities.RipoAsset
      .filter({ key: assetKey, is_active: true }, '-created_date', 1)
      .catch(() => []);

    if (ripoResults.length > 0) {
      const asset = ripoResults[0];
      const resolved = {
        url: asset.file_url,
        type: asset.asset_type || 'mp4',
        loaded: false,
      };
      animationCache[assetKey] = resolved;
      return resolved;
    }

    // Try cooking animation
    const cookResults = await base44.entities.CookingAnimation
      .filter({ key: assetKey, is_active: true }, '-created_date', 1)
      .catch(() => []);

    if (cookResults.length > 0) {
      const anim = cookResults[0];
      const resolved = {
        url: anim.video_url,
        type: 'mp4',
        loaded: false,
      };
      animationCache[assetKey] = resolved;
      return resolved;
    }
  } catch (err) {
    console.warn(`[RipoAnimationResolver] Failed to resolve ${assetKey}:`, err.message);
  }

  return null;
}

// Batch resolve multiple keys
export async function resolveAnimationBatch(assetKeys) {
  if (!Array.isArray(assetKeys)) return [];
  if (!cacheInitialized) await initializeCache();

  const results = {};
  for (const key of assetKeys) {
    results[key] = await resolveAnimation(key);
  }
  return results;
}

// Preload a batch of keys (for performance)
export async function preloadBatch(assetKeys) {
  const batch = await resolveAnimationBatch(assetKeys);
  Object.values(batch).forEach(asset => {
    if (asset?.url) preloadVideo(asset.url);
  });
}

// Warm the cache on app startup
export async function warmCache() {
  if (!cacheInitialized) await initializeCache();
}

