/**
 * Detect current native platform.
 * Returns "android" | "ios" | "web"
 */
function detectPlatform() {
  const ua = navigator.userAgent || '';
  if (/Android/i.test(ua)) return 'android';
  if (/iPhone|iPad|iPod/i.test(ua)) return 'ios';
  return 'web';
}

/**
 * Trigger the real native in-app review flow.
 * Returns { triggered: boolean, method: string }
 */
function requestNativeReview() {
  // Android — Google Play In-App Review API via WebView bridge
  if (window.Android?.requestReview) {
    window.Android.requestReview();
    return { triggered: true, method: 'android_bridge' };
  }

  // iOS — SKStoreReviewController via WKWebView message handler
  if (window.webkit?.messageHandlers?.requestReview) {
    window.webkit.messageHandlers.requestReview.postMessage({});
    return { triggered: true, method: 'ios_webkit_bridge' };
  }

  // Capacitor InAppReview plugin
  if (window.Capacitor?.Plugins?.InAppReview) {
    window.Capacitor.Plugins.InAppReview.requestReview();
    return { triggered: true, method: 'capacitor_inapp_review' };
  }

  // Cordova AppReview plugin
  if (window.cordova?.plugins?.AppReview) {
    window.cordova.plugins.AppReview.requestReview();
    return { triggered: true, method: 'cordova_app_review' };
  }

  // React Native bridge
  if (window.ReactNativeWebView) {
    window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'REQUEST_REVIEW' }));
    return { triggered: true, method: 'react_native_bridge' };
  }

  // No native bridge available — fallback: open store listing
  const platform = detectPlatform();
  if (platform === 'android') {
    const packageName = 'com.reciply.app'; // TODO: match your actual package
    window.open(`https://play.google.com/store/apps/details?id=${packageName}`, '_blank');
    return { triggered: true, method: 'android_store_fallback' };
  }
  if (platform === 'ios') {
    const appId = ''; // TODO: add your App Store ID when available
    if (appId) {
      window.open(`https://apps.apple.com/app/id${appId}?action=write-review`, '_blank');
      return { triggered: true, method: 'ios_store_fallback' };
    }
  }

  return { triggered: false, method: 'none' };
}

function track(eventName, props = {}) {
  try {
    base44.analytics.track({ eventName, properties: props });
  } catch {}
}

