      <AnimatePresence>
        {selectedRating === 0 && (
          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="text-xs font-semibold text-amber-600 mb-6"
          >
            Tap the stars to rate
          </motion.p>
        )}
      </AnimatePresence>

      {/* Primary CTA — 5 stars */}
      <motion.button
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.35 }}
        whileTap={{ scale: 0.97 }}
        onClick={() => handleStarTap(5)}
        className="w-full h-14 rounded-2xl text-white font-bold text-base flex items-center justify-center gap-2 mb-3 shadow-lg"
        style={{
          background: "linear-gradient(135deg, #F59E0B 0%, #D97706 100%)",
          boxShadow: "0 4px 20px rgba(245, 158, 11, 0.4)",
        }}
      >
        <Star className="w-5 h-5 fill-white" />
        Rate 5 Stars
      </motion.button>

      {/* Skip / Continue — visible but secondary */}
      <motion.button
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.45 }}
        onClick={handleSkip}
        className="flex items-center gap-1.5 text-sm font-semibold text-slate-400 hover:text-slate-600 transition-colors py-3"
      >
        Maybe later
        <ArrowRight className="w-3.5 h-3.5" />
      </motion.button>
    </motion.div>
  );
}

