  yellow:  { bg: "bg-yellow-50",  border: "border-yellow-400",  text: "text-yellow-700",  check: "bg-yellow-500",  glow: "rgba(250,204,21,0.3)" },
  purple:  { bg: "bg-purple-50",  border: "border-purple-400",  text: "text-purple-700",  check: "bg-purple-500",  glow: "rgba(168,85,247,0.3)" },
