              style={{
                borderColor: isSelected ? avatar.primaryColor : "rgba(0,0,0,0.07)",
                background: theme.bg,
                boxShadow: isSelected
                  ? `0 0 0 3px ${theme.glow}35, 0 6px 20px ${theme.glow}30`
