              {/* Selected pulsing glow overlay */}
              {isSelected && (
                <motion.div
                  className="absolute inset-0 rounded-2xl pointer-events-none"
                  animate={{ opacity: [0.25, 0.55, 0.25] }}
                  transition={{ duration: 2, repeat: Infinity }}
                  style={{
                    background: `radial-gradient(circle at 50% 45%, ${avatar.primaryColor}30 0%, transparent 70%)`,
                  }}
                />
              )}

              {/* Avatar image */}
              <motion.div
                animate={isSelected ? { scale: [1, 1.12, 1] } : { scale: 1 }}
                transition={{ duration: 0.4 }}
                className="relative z-10"
                style={{ width: 60, height: 60 }}
              >
                <StarterAvatarImage
                  id={avatar.id}
                  size={60}
                  style={{
                    borderRadius: "50%",
                    boxShadow: isSelected
                      ? `0 4px 14px ${avatar.primaryColor}50`
                      : `0 2px 8px rgba(0,0,0,0.12)`,
                  }}
                />
              </motion.div>

              {/* Name */}
              <span
                className="relative z-10 text-[11px] font-bold leading-tight"
                style={{ color: isSelected ? avatar.primaryColor : "#475569" }}
              >
                {avatar.name}
              </span>

              {/* Tagline on selected */}
              {isSelected && (
                <motion.span
                  initial={{ opacity: 0, y: 4 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="relative z-10 text-[9px] font-medium leading-tight text-center px-1"
                  style={{ color: avatar.primaryColor, opacity: 0.8 }}
                >
                  {avatar.tagline.split(' ').slice(1, 4).join(' ')}
                </motion.span>
              )}

              {/* Checkmark badge */}
              {isSelected && (
                <motion.div
                  initial={{ scale: 0, rotate: -20 }}
                  animate={{ scale: 1, rotate: 0 }}
                  transition={{ type: "spring", stiffness: 400, damping: 18 }}
                  className="absolute top-1.5 right-1.5 z-20 w-4 h-4 rounded-full flex items-center justify-center shadow-sm"
                  style={{ background: avatar.primaryColor }}
