export default function StepEquipment({ selected, onToggle, error }) {
  const { t } = useLocalization();
  const EQUIPMENT_OPTIONS = getLocalizedOptions(EQUIPMENT_MANIFEST, t).map(e => ({
    ...e,
    Icon: EQUIP_ICONS[e.value] || StoveIcon,
  }));
  return (
    <motion.div
      key="step-equipment"
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -8 }}
      transition={{ duration: 0.3 }}
      className="space-y-2"
    >
      <div className="text-center -mt-1">
        <h2 className="text-lg font-black text-slate-900 leading-tight">{t('onboarding.equipment_title', 'What equipment do you have?')}</h2>
