import React from "react";
import { cn } from "@/lib/utils";
import { CANONICAL_GOALS } from "../constants/goalsConfig";
import GoalPill from "./GoalPill";
import { useLocalization } from "@/services/localization/LocalizationContext";

/**
 * GoalBadges — Vertical stack of premium goal pills
 * Renders 1-2 goals stacked vertically with clean solid colors
 */
export default function GoalBadges({ goals = [] }) {
  const { t } = useLocalization();

  // Normalize: ensure array, handle null/undefined, cap at 2
  const normalizedGoals = Array.isArray(goals) ? goals.filter(Boolean).slice(0, 2) : [];

  // If no goals, show placeholder
  if (normalizedGoals.length === 0) {
    return <p className="text-xs text-slate-500">{t('goals.not_set', 'Not set')}</p>;
  }

  // Get display info for each goal — use labelKey for localization
  const goalInfos = normalizedGoals.map(goalValue => {
    const canonical = CANONICAL_GOALS.find(g => g.value === goalValue);
    if (canonical) {
      return {
        value: goalValue,
        label: t(canonical.labelKey, canonical.label),
        emoji: canonical.emoji,
        color: canonical.color,
      };
    }
    // Fallback
    const fallbackLabel = goalValue
      .split("_")
      .map(word => word.charAt(0).toUpperCase() + word.slice(1))
      .join(" ");
    return {
      value: goalValue,
      label: fallbackLabel,
      emoji: "🎯",
      color: "slate",
    };
  });

  return (
    <div className="flex flex-col gap-1.5 items-start w-full">
      {goalInfos.map((info, index) => (
        <GoalPill
          key={info.value}
          emoji={info.emoji}
          label={info.label}
          color={info.color}
          index={index}
        />
      ))}
    </div>
  );
}

