/**
 * AvatarPickerSection — used in Edit Profile
 * Shows current avatar with left/right starter cycling + Change Photo with circular crop.
 */
import React, { useState, useRef, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Camera } from 'lucide-react';
import { AnimatePresence, motion } from 'framer-motion';
import { STARTER_AVATARS, StarterAvatarImage } from './StarterAvatars';
import CircularCropModal from './CircularCropModal';
import { useLocalization } from '@/services/localization/LocalizationContext';

/**
 * Props:
 *  user          — current user object (with avatar_url, starter_avatar_id)
 *  onAvatarChange(data) — called whenever selection changes:
 *    { type: 'starter', avatarId }
 *    { type: 'photo',   file: File, previewUrl: string }
 *    null — no change from current
 */
export default function AvatarPickerSection({ user, onAvatarChange }) {
  const { t } = useLocalization();
  const fileInputRef = useRef(null);
  const [mode, setMode] = useState('starter'); // 'starter' | 'photo'
  const [starterIdx, setStarterIdx] = useState(0);
  const [photoPreview, setPhotoPreview] = useState(null); // blob URL for uploaded photo preview
  const [pendingFile, setPendingFile] = useState(null);   // file chosen but not yet cropped
  const [showCrop, setShowCrop] = useState(false);
  const [dir, setDir] = useState(1); // +1 right, -1 left for slide animation

  // ── Initialize from user ─────────────────────────────────────────────────
  useEffect(() => {
    if (!user) return;
    // Determine starter avatar index from avatar_choice or starter_avatar_id
    const starterKey = user.avatar_choice || user.starter_avatar_id;
    const starterIdx = starterKey ? STARTER_AVATARS.findIndex(a => a.id === starterKey) : -1;
    if (starterIdx >= 0) setStarterIdx(starterIdx);

    // If user has a custom photo, show photo mode; keep starter in cycle
    // Check both avatar_url and avatar fields (avatar_url is the primary stored field)
    const customPhoto = user.avatar_url || user.avatar;
    const isCustomPhoto = customPhoto && !customPhoto.includes('data:image/svg');
    if (isCustomPhoto) {
      setMode('photo');
      setPhotoPreview(customPhoto);
    } else {
      setMode('starter');
      if (starterIdx < 0) {
        setStarterIdx(0);
        onAvatarChange?.({ type: 'starter', avatarId: STARTER_AVATARS[0].id });
      }
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [user?.id]);

  // ── Cycling ──────────────────────────────────────────────────────────────
  const goLeft = () => {
    const next = (starterIdx - 1 + STARTER_AVATARS.length) % STARTER_AVATARS.length;
    setDir(-1);
    setStarterIdx(next);
    setMode('starter');
    onAvatarChange?.({ type: 'starter', avatarId: STARTER_AVATARS[next].id });
  };

  const goRight = () => {
    const next = (starterIdx + 1) % STARTER_AVATARS.length;
    setDir(1);
    setStarterIdx(next);
    setMode('starter');
    onAvatarChange?.({ type: 'starter', avatarId: STARTER_AVATARS[next].id });
  };

  // ── Photo upload ─────────────────────────────────────────────────────────
  const handleFileSelect = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    e.target.value = '';
    setPendingFile(file);
    setShowCrop(true);
  };

  const handleCropSave = (croppedFile) => {
    const url = URL.createObjectURL(croppedFile);
    setPhotoPreview(url);
    setMode('photo');
    setShowCrop(false);
    setPendingFile(null);
    onAvatarChange?.({ type: 'photo', file: croppedFile, previewUrl: url });
  };

  const currentAvatar = STARTER_AVATARS[starterIdx];

  return (
    <div className="flex flex-col items-center gap-4">
      {/* Avatar display with cycling arrows */}
      <div className="flex items-center gap-5">
        {/* Left arrow — only shown in starter mode */}
        <button
          onClick={goLeft}
          className="w-10 h-10 rounded-full bg-slate-100 hover:bg-slate-200 flex items-center justify-center transition-colors active:scale-90"
          style={{ transition: 'transform 0.15s, background 0.15s', visibility: mode === 'photo' ? 'hidden' : 'visible' }}
        >
          <ChevronLeft className="w-5 h-5 text-slate-600" />
        </button>

        {/* Avatar */}
        <div className="flex items-center gap-3">
          <div className="relative">
            <AnimatePresence mode="wait" initial={false}>
              <motion.div
                key={mode === 'starter' ? currentAvatar.id : 'photo'}
                initial={{ opacity: 0, x: dir * 30 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: dir * -30 }}
                transition={{ duration: 0.18 }}
                style={{ width: 96, height: 96 }}
              >
                {mode === 'starter' ? (
                  // FIX #2: wrap in a clipping div so globals.css .rounded-full img { border-radius: 0 }
                  // cannot override the shape — the div clips, not the img element itself
                  <div style={{
                    width: 96, height: 96,
                    borderRadius: '50%',
                    overflow: 'hidden',
                    flexShrink: 0,
                    boxShadow: '0 4px 20px rgba(0,0,0,0.18)',
                  }}>
                    <StarterAvatarImage
                      id={currentAvatar.id}
                      size={96}
                      style={{ borderRadius: 0, boxShadow: 'none' }}
                    />
                  </div>
                ) : (
                  // The exported PNG is already a perfect circle with transparent corners.
                  // Display it as-is — no container clipping needed, no CSS border-radius on img.
                  // We use a wrapper div with overflow:hidden + borderRadius to handle the
                  // transparent corner pixels cleanly without relying on img border-radius
                  // (which globals.css can override to 0).
                  <div style={{
                    width: 96,
                    height: 96,
                    borderRadius: '50%',
                    overflow: 'hidden',
                    flexShrink: 0,
                    boxShadow: '0 4px 20px rgba(0,0,0,0.18)',
                    background: 'transparent',
                  }}>
                    <img
                      src={photoPreview}
                      alt="avatar"
                      draggable={false}
                      style={{
                        width: 96,
                        height: 96,
                        display: 'block',
                        objectFit: 'cover',
                        objectPosition: 'center',
                      }}
                    />
                  </div>
                )}
              </motion.div>
            </AnimatePresence>
            {/* Name badge for starter */}
            {mode === 'starter' && (
              <div className="absolute -bottom-1 -right-1 px-1.5 py-0.5 rounded-full bg-white text-[9px] font-bold text-slate-500 shadow border border-slate-100">
                {t(`avatar.name.${currentAvatar.id}`, currentAvatar.name)}
              </div>
            )}
          </div>

          {/* When in photo mode, show starter avatar as a small clickable chip to the right */}
          {mode === 'photo' && (
            <button
              onClick={() => { setMode('starter'); onAvatarChange?.({ type: 'starter', avatarId: currentAvatar.id }); }}
              title={t(`avatar.name.${currentAvatar.id}`, currentAvatar.name)}
              className="flex flex-col items-center gap-1 opacity-80 hover:opacity-100 transition-opacity"
            >
              <StarterAvatarImage
                id={currentAvatar.id}
                size={44}
                style={{ boxShadow: '0 2px 8px rgba(0,0,0,0.15)', opacity: 0.85 }}
              />
              <span className="text-[9px] font-bold text-slate-400">{t(`avatar.name.${currentAvatar.id}`, currentAvatar.name)}</span>
            </button>
          )}
        </div>

        {/* Right arrow — only shown in starter mode */}
        <button
          onClick={goRight}
          className="w-10 h-10 rounded-full bg-slate-100 hover:bg-slate-200 flex items-center justify-center transition-colors active:scale-90"
          style={{ transition: 'transform 0.15s, background 0.15s', visibility: mode === 'photo' ? 'hidden' : 'visible' }}
        >
          <ChevronRight className="w-5 h-5 text-slate-600" />
        </button>
      </div>

      {/* Dots indicator */}
      {mode === 'starter' && (
        <div className="flex gap-1.5">
          {STARTER_AVATARS.map((a, i) => (
            <button
              key={a.id}
              onClick={() => {
                setDir(i > starterIdx ? 1 : -1);
                setStarterIdx(i);
                setMode('starter');
                onAvatarChange?.({ type: 'starter', avatarId: a.id });
              }}
              className="transition-all"
              style={{
                width: i === starterIdx ? 16 : 6,
                height: 6,
                borderRadius: 3,
                background: i === starterIdx
                  ? STARTER_AVATARS[starterIdx].primaryColor
                  : '#CBD5E1',
              }}
            />
          ))}
        </div>
      )}

      {/* Labels */}
      <div className="text-center">
        {mode === 'starter' ? (
          <>
            <p className="text-sm font-bold text-slate-800">{t(`avatar.name.${currentAvatar.id}`, currentAvatar.name)}</p>
            <p className="text-xs text-slate-400">{t(`avatar.tagline.${currentAvatar.id}`, currentAvatar.tagline)}</p>
          </>
        ) : (
          <p className="text-sm font-medium text-slate-600">{t('avatar.custom_photo', 'Custom photo')}</p>
        )}
      </div>

      {/* Change Photo button */}
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        onChange={handleFileSelect}
        className="hidden"
      />
      <button
        onClick={() => fileInputRef.current?.click()}
        className="flex items-center gap-2 px-4 py-2.5 rounded-xl border-2 border-dashed border-indigo-200 text-indigo-600 font-semibold text-sm hover:border-indigo-400 hover:bg-indigo-50 transition-colors"
      >
        <Camera className="w-4 h-4" />
        {t('avatar.change_photo', 'Change Photo')}
      </button>

      {/* Circular crop modal */}
      <AnimatePresence>
        {showCrop && pendingFile && (
          <CircularCropModal
            imageFile={pendingFile}
            onSave={handleCropSave}
            onClose={() => { setShowCrop(false); setPendingFile(null); }}
          />
        )}
      </AnimatePresence>
    </div>
  );
}

import React from "react";
import { base44 } from "@/api/base44Client";
import { useQuery } from "@tanstack/react-query";
import { motion } from "framer-motion";
import { TrendingUp } from "lucide-react";
import { useLocalization } from "@/services/localization/LocalizationContext";

/**
 * FollowerGoalCard — shared component used on both Home and Profile.
 * Uses React Query with the shared "follower-goal" cache key so both pages
 * always show the same data without double-fetching.
 *
 * Props:
 *   followersCount — actual follower count (passed in from parent query, no internal fetch)
 */
export default function FollowerGoalCard({ followersCount = 0 }) {
  const { t } = useLocalization();
  const { data: followerGoal, isLoading } = useQuery({
    queryKey: ["follower-goal"],
    queryFn: async () => {
      const res = await base44.functions.invoke("getFollowerGoal", {});
      return res.data?.follower_goal;
    },
    staleTime: 30 * 60 * 1000,
    gcTime: 60 * 60 * 1000,
    refetchOnMount: false,
    refetchOnWindowFocus: false,
    retry: false,
  });

  if (isLoading || !followerGoal || followersCount === null) return null;

  const goalVal = followerGoal.current_goal || 10;
  const pct = Math.min(100, Math.round((followersCount / goalVal) * 100));
  const achieved = followersCount >= goalVal;
  const next_goal = followerGoal.next_goal;

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className="relative overflow-hidden rounded-2xl bg-gradient-to-r from-purple-50 via-indigo-50 to-blue-50 border border-purple-100"
    >
      {achieved && (
        <motion.div
          animate={{ rotate: 360 }}
          transition={{ duration: 2, repeat: Infinity, ease: "linear" }}
          className="absolute -top-20 -right-20 w-40 h-40 bg-gradient-to-br from-amber-300 to-orange-400 rounded-full opacity-10"
        />
      )}

      <div className="relative z-10 px-4 py-3 flex items-center gap-3">
        <div className="w-8 h-8 rounded-xl bg-purple-100 flex items-center justify-center flex-shrink-0">
          <TrendingUp className="w-4 h-4 text-purple-600" />
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center justify-between mb-1">
            <span className="text-[10px] font-semibold text-slate-500 uppercase tracking-wide flex items-center gap-1">
              {t('home.followers_goal', 'Followers Goal')}
              {achieved && <span className="text-amber-500 font-bold">{t('home.followers_reached', '✓ Reached!')}</span>}
            </span>
            <span className="text-[10px] font-bold text-purple-600">{followersCount} / {achieved && next_goal ? next_goal : goalVal}</span>
          </div>
          <div className="w-full h-1.5 bg-purple-100 rounded-full overflow-hidden">
            <motion.div
              className="h-full rounded-full"
              style={{ background: "linear-gradient(90deg,#8b5cf6,#6366f1)" }}
              initial={{ width: 0 }}
              animate={{ width: `${pct}%` }}
              transition={{ duration: 0.7, ease: "easeOut" }}
            />
          </div>
          {achieved && next_goal && (
            <p className="text-[10px] text-slate-500 mt-0.5">{t('home.followers_next', 'Next:')} {next_goal} {t('analytics.followers', 'followers')}</p>
          )}
        </div>

        <span className="text-sm font-bold text-purple-700 flex-shrink-0">{pct}%</span>
      </div>
    </motion.div>
  );
}

