import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { base44 } from '@/api/base44Client';
import { useQueryClient } from '@tanstack/react-query';
import { createPageUrl } from '../../utils';
import { X, Share2, MessageCircle, Flag, UserX, UserCheck, CheckCircle2, Loader2, UserMinus } from 'lucide-react';
import { toast } from 'sonner';
import QuickShareRow from '../share/QuickShareRow';
import ReciplyShareSheet from '../share/ReciplyShareSheet';

const REPORT_REASONS = [
  'Spam or fake account',
  'Harassment or bullying',
  'Inappropriate content',
  'Impersonation',
  'Hate speech',
  'Other',
];

function ReportModal({ user, currentUser, onClose }) {
  const [reason, setReason] = useState('');
  const [details, setDetails] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [done, setDone] = useState(false);

  const handleSubmit = async () => {
    if (!reason) return;
    setSubmitting(true);
    try {
      await base44.functions.invoke('createReport', {
        target_type: 'user',
        target_id: user.id,
        reporter_user_id: currentUser.id,
        reason,
        details: details.trim(),
      });
      setDone(true);
      setTimeout(onClose, 1800);
    } catch (err) {
      toast.error('Failed to submit report. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[200] bg-black/60 backdrop-blur-sm flex items-end justify-center" onClick={onClose}>
      <motion.div
        initial={{ y: 400, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        exit={{ y: 400, opacity: 0 }}
        transition={{ type: 'spring', stiffness: 320, damping: 26 }}
        className="w-full max-w-sm bg-white rounded-t-3xl p-6 shadow-2xl max-h-[85vh] overflow-y-auto"
        onClick={e => e.stopPropagation()}
      >
        {done ? (
          <div className="flex flex-col items-center py-8 gap-3">
            <CheckCircle2 className="w-12 h-12 text-green-500" />
            <p className="text-base font-bold text-slate-900">Report submitted</p>
            <p className="text-sm text-slate-500 text-center">We'll review this report within 24 hours.</p>
          </div>
        ) : (
          <>
            <div className="flex items-center justify-between mb-5">
              <h3 className="text-lg font-bold text-slate-900">Report {user.display_name}</h3>
              <button onClick={onClose} className="w-8 h-8 rounded-full hover:bg-slate-100 flex items-center justify-center">
                <X className="w-4 h-4 text-slate-500" />
              </button>
            </div>
            <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider mb-3">Select a reason</p>
            <div className="space-y-2 mb-4">
              {REPORT_REASONS.map(r => (
                <button
                  key={r}
                  onClick={() => setReason(r)}
                  className={`w-full text-left px-4 py-3 rounded-2xl text-sm font-medium border-2 transition-all ${reason === r ? 'border-rose-400 bg-rose-50 text-rose-700' : 'border-slate-100 bg-slate-50 text-slate-700 hover:border-slate-200'}`}
                >
                  {r}
                </button>
              ))}
            </div>
            <textarea
              value={details}
              onChange={e => setDetails(e.target.value)}
              placeholder="Additional details (optional)..."
              rows={3}
              className="w-full px-4 py-3 rounded-2xl bg-slate-50 text-sm text-slate-800 outline-none border border-slate-200 resize-none mb-4 placeholder:text-slate-400"
            />
            <button
              onClick={handleSubmit}
              disabled={!reason || submitting}
              className="w-full h-12 rounded-2xl bg-rose-500 text-white font-bold text-sm disabled:opacity-40 flex items-center justify-center gap-2 transition-all active:scale-95"
            >
              {submitting ? <Loader2 className="w-4 h-4 animate-spin" /> : null}
              Submit Report
            </button>
          </>
        )}
      </motion.div>
    </div>
  );
}

/**
 * ShareToContactSheet — multi-select contact list.
 * Sends a structured profile card to all selected chats at once.
 */
function ShareToContactSheet({ user, contacts, loading, onClose }) {
  const [selectedIds, setSelectedIds] = useState(new Set());
  const [sending, setSending] = useState(false);
  const [sent, setSent] = useState(false);
  const sentRef = React.useRef(false);

  // Reset sentRef on every mount so re-opens work correctly
  React.useEffect(() => { sentRef.current = false; }, []);

  const toggleContact = (id) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const handleSend = async () => {
    if (selectedIds.size === 0 || sending || sentRef.current) return;
    sentRef.current = true; // prevent double-send on rapid taps
    setSending(true);
    try {
      const profileCardContent = `[profile_share:${user.id}]`;
      await Promise.all(
        Array.from(selectedIds).map(recipientId =>
          base44.functions.invoke('sendDirectMessage', {
            recipient_id: recipientId,
            content: profileCardContent,
            meta_type: 'profile_share',
            meta_user_id: user.id,
            meta_user_name: user.display_name || '',
            meta_user_avatar: user.avatar_url || '',
          })
        )
      );
      setSent(true);
      setTimeout(onClose, 1200);
    } catch {
      toast.error('Failed to send. Try again.');
      sentRef.current = false;
    } finally {
      setSending(false);
    }
  };

  const n = selectedIds.size;

  return (
    <div className="fixed inset-0 z-[200] bg-black/60 backdrop-blur-sm flex items-end justify-center" onClick={onClose}>
      <motion.div
        initial={{ y: 400, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        exit={{ y: 400, opacity: 0 }}
        transition={{ type: 'spring', stiffness: 320, damping: 26 }}
        className="w-full max-w-sm bg-white rounded-t-3xl shadow-2xl max-h-[80vh] flex flex-col"
        onClick={e => e.stopPropagation()}
      >
        {/* Handle */}
        <div className="flex justify-center pt-3 pb-1 flex-shrink-0">
          <div className="w-10 h-1 bg-slate-200 rounded-full" />
        </div>
        <div className="flex items-center justify-between px-5 py-3 border-b border-slate-100 flex-shrink-0">
          <h3 className="text-base font-bold text-slate-900">Share Profile</h3>
          <button onClick={onClose} className="w-8 h-8 rounded-full hover:bg-slate-100 flex items-center justify-center">
            <X className="w-4 h-4 text-slate-500" />
          </button>
        </div>

        {/* Profile preview card */}
        <div className="mx-5 my-3 rounded-2xl border border-indigo-100 bg-indigo-50 flex items-center gap-3 p-3 flex-shrink-0">
          <div className="w-10 h-10 rounded-full overflow-hidden flex-shrink-0 bg-gradient-to-br from-indigo-400 to-purple-500">
            {user.avatar_url
              ? <img src={user.avatar_url} alt="" className="w-full h-full object-cover" />
              : <span className="w-full h-full flex items-center justify-center text-white font-bold text-sm">{user.display_name?.charAt(0)?.toUpperCase() || '?'}</span>
            }
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-bold text-slate-900 truncate">{user.display_name}</p>
            {user.username && <p className="text-xs text-slate-400">@{user.username}</p>}
          </div>
          <span className="text-[10px] font-semibold text-indigo-500 bg-indigo-100 px-2 py-1 rounded-full">Profile Card</span>
        </div>

        {/* Contact list — multi-select */}
        <div className="flex-1 overflow-y-auto px-5 pb-2">
          <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">
            Send to {n > 0 ? <span className="text-indigo-500">({n} selected)</span> : ''}
          </p>
          {loading ? (
            <div className="space-y-3">
              {[1,2,3].map(i => <div key={i} className="h-14 rounded-2xl bg-slate-100 animate-pulse" />)}
            </div>
          ) : contacts.length === 0 ? (
            <p className="text-xs text-slate-400 text-center py-8">No recent contacts to share with</p>
          ) : (
            <div className="space-y-2">
              {contacts.map(contact => {
                const isSelected = selectedIds.has(contact.id);
                return (
                  <button
                    key={contact.id}
                    onClick={() => toggleContact(contact.id)}
                    className={`w-full flex items-center gap-3 px-4 py-3 rounded-2xl border-2 transition-all ${
                      isSelected ? 'border-indigo-500 bg-indigo-50' : 'border-slate-100 bg-slate-50 hover:border-slate-200'
                    }`}
                  >
                    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-indigo-400 to-purple-400 flex items-center justify-center overflow-hidden flex-shrink-0">
                      {contact.avatar
                        ? <img src={contact.avatar} alt="" className="w-full h-full object-cover" onError={e => { e.target.style.display = 'none'; }} />
                        : <span className="text-sm font-bold text-white">{(contact.name || '?').charAt(0).toUpperCase()}</span>
                      }
                    </div>
                    <span className="flex-1 text-left text-sm font-semibold text-slate-800 truncate">{contact.name}</span>
                    <div className={`w-5 h-5 rounded-full border-2 flex items-center justify-center flex-shrink-0 transition-all ${isSelected ? 'bg-indigo-600 border-indigo-600' : 'border-slate-300'}`}>
                      {isSelected && <CheckCircle2 className="w-3.5 h-3.5 text-white" strokeWidth={3} />}
                    </div>
                  </button>
                );
              })}
            </div>
          )}
        </div>

        {/* Send CTA */}
        <div className="px-5 py-4 border-t border-slate-100 flex-shrink-0">
          <button
            onClick={handleSend}
            disabled={n === 0 || sending || sent}
            className="w-full h-12 rounded-2xl font-bold text-sm text-white disabled:opacity-40 flex items-center justify-center gap-2 transition-all active:scale-95"
            style={{ background: 'linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)' }}
          >
            {sent ? (
              <><CheckCircle2 className="w-4 h-4" /> Sent!</>
            ) : sending ? (
              <><Loader2 className="w-4 h-4 animate-spin" /> Sending...</>
            ) : n > 0 ? (
              `Share in ${n} chat${n > 1 ? 's' : ''}`
            ) : (
              'Select contacts'
            )}
          </button>
        </div>
      </motion.div>
    </div>
  );
}

export default function UserProfileActionSheet({
  isOpen,
  onClose,
  user,
  currentUser,
  onMessageClick,
  doesTargetFollowViewer = false,
  onRemoveFollower,
  removingFollower = false,
}) {
  const queryClient = useQueryClient();
  const [dmContacts, setDmContacts] = useState([]);
  const [dmLoading, setDmLoading] = useState(false);
  const [isBlocked, setIsBlocked] = useState(false);
  const [blockLoading, setBlockLoading] = useState(false);
  const [showReport, setShowReport] = useState(false);
  const [showBlockConfirm, setShowBlockConfirm] = useState(false);
  const [showShareContacts, setShowShareContacts] = useState(false);
  const [showFullShareSheet, setShowFullShareSheet] = useState(false);

  useEffect(() => {
    if (!isOpen || !currentUser?.id || !user?.id) return;

    // Load DM contacts
    if (dmContacts.length === 0 && !dmLoading) {
      setDmLoading(true);
      base44.entities.Message.filter({ sender_id: currentUser.id }, '-created_date', 50)
        .then(sent => {
          const recips = new Map();
          sent.forEach(m => {
            if (m.recipient_id !== user.id && !recips.has(m.recipient_id)) {
              recips.set(m.recipient_id, {
                id: m.recipient_id,
                name: m.recipient_name || '',
                avatar: m.recipient_avatar || '',
              });
            }
          });
          const list = Array.from(recips.values());
          setDmContacts(list);
          if (list.length > 0) {
            Promise.all(
              list.map(c =>
                base44.entities.User.filter({ id: c.id })
                  .then(u => u[0] ? { ...c, name: u[0].display_name || u[0].full_name || c.name, avatar: u[0].avatar_url || c.avatar } : c)
                  .catch(() => c)
              )
            ).then(enriched => setDmContacts(enriched));
          }
        })
        .finally(() => setDmLoading(false));
    }

    // Check block status
    base44.entities.BlockedUser.filter({ blocker_id: currentUser.id, blocked_id: user.id })
      .then(list => setIsBlocked(list.length > 0))
      .catch(() => {});
  }, [isOpen, user?.id, currentUser?.id]);

  const handleShareProfile = async () => {
    const profileUrl = `${window.location.origin}${createPageUrl('UserProfile')}?userId=${user.id}`;
    const shareTitle = `${user.display_name || 'Chef'} on Reciply`;
    const shareText = `Check out ${user.display_name || 'this chef'}'s recipes on Reciply!`;
    if (navigator.share) {
      try {
        await navigator.share({ title: shareTitle, text: shareText, url: profileUrl });
      } catch (err) {
        if (err.name !== 'AbortError') {
          await navigator.clipboard.writeText(profileUrl).catch(() => {});
          toast.success('Profile link copied!');
        }
      }
    } else {
      await navigator.clipboard.writeText(profileUrl).catch(() => {});
      toast.success('Profile link copied!');
    }
  };

  const invalidateAfterBlockChange = (targetUserId) => {
    queryClient.invalidateQueries({ queryKey: ['forYouFeed'] });
    queryClient.invalidateQueries({ queryKey: ['followingFeed'] });
    queryClient.invalidateQueries({ queryKey: ['recommended-feed'] });
    queryClient.invalidateQueries({ queryKey: ['blocked-ids'] });
    queryClient.invalidateQueries({ queryKey: ['user-profile', targetUserId] });
    queryClient.invalidateQueries({ queryKey: ['follow-list-followers'] });
    queryClient.invalidateQueries({ queryKey: ['follow-list-following'] });
    queryClient.invalidateQueries({ queryKey: ['user-engagement'] });
  };

  const handleBlock = async () => {
    setBlockLoading(true);
    try {
      if (isBlocked) {
        await base44.functions.invoke('unblockUser', { target_user_id: user.id });
        setIsBlocked(false);
        invalidateAfterBlockChange(user.id);
        toast.success(`Unblocked ${user.display_name}`);
        setShowBlockConfirm(false);
        setBlockLoading(false);
        onClose();
        setTimeout(() => window.location.reload(), 300);
        return;
      } else {
        await base44.functions.invoke('blockUser', { target_user_id: user.id });
        setIsBlocked(true);
        invalidateAfterBlockChange(user.id);
        toast.success(`Blocked ${user.display_name}`);
        setShowBlockConfirm(false);
        setBlockLoading(false);
        onClose();
        setTimeout(() => window.location.reload(), 300);
        return;
      }
    } catch (err) {
      toast.error('Action failed. Please try again.');
    } finally {
      setBlockLoading(false);
      setShowBlockConfirm(false);
      onClose();
    }
  };

  if (!isOpen || !user) return null;

  return (
    <>
      <div className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-end justify-center" onClick={onClose}>
        <AnimatePresence>
          <motion.div
            initial={{ y: 500, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: 500, opacity: 0 }}
            transition={{ type: 'spring', stiffness: 320, damping: 25 }}
            className="w-full max-w-sm bg-white rounded-t-3xl shadow-2xl overflow-hidden max-h-[85vh] flex flex-col"
            onClick={e => e.stopPropagation()}
          >
            {/* Handle */}
            <div className="flex justify-center pt-3 pb-1">
              <div className="w-10 h-1 bg-slate-200 rounded-full" />
            </div>

            {/* User identity header */}
            <div className="flex items-center gap-3 px-6 py-3 border-b border-slate-100">
              <div className="w-10 h-10 rounded-full bg-gradient-to-br from-indigo-400 to-purple-400 flex items-center justify-center overflow-hidden flex-shrink-0">
                {user.avatar_url
                  ? <img src={user.avatar_url} alt="" className="w-full h-full object-cover" />
                  : <span className="text-sm font-bold text-white">{user.display_name?.charAt(0)?.toUpperCase() || '?'}</span>
                }
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-bold text-slate-900 truncate">{user.display_name}</p>
                {user.username && <p className="text-xs text-slate-400">@{user.username}</p>}
              </div>
              <button onClick={onClose} className="w-8 h-8 rounded-full hover:bg-slate-100 flex items-center justify-center">
                <X className="w-4 h-4 text-slate-500" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto">
              {/* Quick Send To row */}
              <div className="px-5 pt-4 pb-2 border-b border-slate-100">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Send to</p>
                <QuickShareRow
                  onSend={async (recipientIds) => {
                    const profileCardContent = `[profile_share:${user.id}]`;
                    await Promise.all(
                      recipientIds.map(rid =>
                        base44.functions.invoke('sendDirectMessage', {
                          recipient_id: rid,
                          content: profileCardContent,
                          meta_type: 'profile_share',
                          meta_user_id: user.id,
                          meta_user_name: user.display_name || '',
                          meta_user_avatar: user.avatar_url || '',
                        })
                      )
                    );
                  }}
                  shareLabel="Share"
                />
              </div>

              {/* Share section — opens full ReciplyShareSheet for both in-app + external */}
              <div className="px-5 py-4 border-b border-slate-100">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Share</p>
                <button
                  onClick={() => { onClose(); setTimeout(() => setShowFullShareSheet(true), 150); }}
                  className="w-full flex items-center gap-3 px-4 py-3.5 rounded-2xl bg-gradient-to-r from-indigo-50 to-violet-50 text-indigo-700 font-semibold hover:from-indigo-100 hover:to-violet-100 transition-all text-sm border border-indigo-100"
                >
                  <Share2 className="w-5 h-5 flex-shrink-0" />
                  Share Profile
                  <span className="ml-auto text-[10px] text-indigo-400 font-medium">In-app & external</span>
                </button>
              </div>

              {/* Quick actions grid */}
              <div className="px-5 py-4">
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Actions</p>
                <div className="grid grid-cols-3 gap-3">
                  {/* Message */}
                  <button
                    onClick={() => { onMessageClick(); onClose(); }}
                    className="flex flex-col items-center gap-2 p-4 rounded-2xl bg-slate-50 hover:bg-indigo-50 transition-colors"
                  >
                    <div className="w-9 h-9 rounded-xl bg-indigo-100 flex items-center justify-center">
                      <MessageCircle className="w-4 h-4 text-indigo-600" />
                    </div>
                    <span className="text-[10px] font-semibold text-slate-700 text-center">Message</span>
                  </button>

                  {/* Remove Follower — only shown when target follows viewer */}
                  {doesTargetFollowViewer && onRemoveFollower && (
                    <button
                      onClick={() => { onRemoveFollower(); onClose(); }}
                      disabled={removingFollower}
                      className="flex flex-col items-center gap-2 p-4 rounded-2xl bg-slate-50 hover:bg-amber-50 transition-colors disabled:opacity-60"
                    >
                      <div className="w-9 h-9 rounded-xl bg-amber-100 flex items-center justify-center">
                        {removingFollower
                          ? <Loader2 className="w-4 h-4 animate-spin text-amber-600" />
                          : <UserMinus className="w-4 h-4 text-amber-600" />
                        }
                      </div>
                      <span className="text-[10px] font-semibold text-slate-700 text-center">Remove</span>
                    </button>
                  )}

                  {/* Report */}
                  <button
                    onClick={() => { setShowReport(true); }}
                    className="flex flex-col items-center gap-2 p-4 rounded-2xl bg-slate-50 hover:bg-amber-50 transition-colors"
                  >
                    <div className="w-9 h-9 rounded-xl bg-amber-100 flex items-center justify-center">
                      <Flag className="w-4 h-4 text-amber-600" />
                    </div>
                    <span className="text-[10px] font-semibold text-slate-700 text-center">Report</span>
                  </button>

                  {/* Block / Unblock */}
                  <button
                    onClick={() => setShowBlockConfirm(true)}
                    disabled={blockLoading}
                    className={`flex flex-col items-center gap-2 p-4 rounded-2xl transition-colors ${isBlocked ? 'bg-emerald-50 hover:bg-emerald-100' : 'bg-slate-50 hover:bg-rose-50'}`}
                  >
                    <div className={`w-9 h-9 rounded-xl flex items-center justify-center ${isBlocked ? 'bg-emerald-100' : 'bg-rose-100'}`}>
                      {blockLoading
                        ? <Loader2 className="w-4 h-4 animate-spin text-slate-400" />
                        : isBlocked
                          ? <UserCheck className="w-4 h-4 text-emerald-600" />
                          : <UserX className="w-4 h-4 text-rose-600" />
                      }
                    </div>
                    <span className={`text-[10px] font-semibold text-center ${isBlocked ? 'text-emerald-700' : 'text-slate-700'}`}>
                      {isBlocked ? 'Unblock' : 'Block'}
                    </span>
                  </button>
                </div>
              </div>
            </div>
          </motion.div>
        </AnimatePresence>
      </div>

      {/* Block confirm */}
      <AnimatePresence>
        {showBlockConfirm && (
          <div className="fixed inset-0 z-[200] bg-black/60 backdrop-blur-sm flex items-center justify-center p-5" onClick={() => setShowBlockConfirm(false)}>
            <motion.div
              initial={{ opacity: 0, scale: 0.92, y: 12 }}
              animate={{ opacity: 1, scale: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.92 }}
              transition={{ type: 'spring', stiffness: 360, damping: 26 }}
              className="bg-white rounded-3xl p-6 max-w-sm w-full shadow-2xl"
              onClick={e => e.stopPropagation()}
            >
              <h3 className="text-lg font-bold text-slate-900 mb-2">
                {isBlocked ? `Unblock ${user.display_name}?` : `Block ${user.display_name}?`}
              </h3>
              <p className="text-sm text-slate-500 mb-6 leading-relaxed">
                {isBlocked
                  ? 'They will be able to see your profile and contact you again.'
                  : "They won't be able to message you or see your content."}
              </p>
              <div className="flex gap-3">
                <button onClick={() => setShowBlockConfirm(false)} className="flex-1 h-11 rounded-2xl bg-slate-100 text-slate-700 font-semibold text-sm">Cancel</button>
                <button
                  onClick={handleBlock}
                  disabled={blockLoading}
                  className={`flex-1 h-11 rounded-2xl font-semibold text-sm text-white flex items-center justify-center gap-1 transition-all ${isBlocked ? 'bg-emerald-500' : 'bg-rose-500'}`}
                >
                  {blockLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : null}
                  {isBlocked ? 'Unblock' : 'Block'}
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Report modal */}
      <AnimatePresence>
        {showReport && (
          <ReportModal user={user} currentUser={currentUser} onClose={() => setShowReport(false)} />
        )}
      </AnimatePresence>

      {/* Share to contacts sheet (legacy — kept for backward compat) */}
      <AnimatePresence>
        {showShareContacts && (
          <ShareToContactSheet
            user={user}
            contacts={dmContacts}
            loading={dmLoading}
            onClose={() => setShowShareContacts(false)}
          />
        )}
      </AnimatePresence>

      {/* Full ReciplyShareSheet — supports both in-app rich card + external share */}
      <AnimatePresence>
        {showFullShareSheet && (
          <ReciplyShareSheet
            isOpen={showFullShareSheet}
            onClose={() => setShowFullShareSheet(false)}
            type="profile"
            preview={{
              name: user.display_name || user.full_name || '',
              avatar: user.avatar_url || '',
              subtitle: user.username ? `@${user.username}` : '',
            }}
            shareUrl={`${window.location.origin}${createPageUrl('UserProfile')}?userId=${user.id}`}
            shareTitle={`${user.display_name || 'Chef'} on Reciply`}
            shareText={`Check out ${user.display_name || 'this chef'}'s recipes on Reciply!`}
            onSendToContacts={async (recipientIds) => {
              const profileCardContent = `[profile_share:${user.id}]`;
              await Promise.all(
                recipientIds.map(rid =>
                  base44.functions.invoke('sendDirectMessage', {
                    recipient_id: rid,
                    content: profileCardContent,
                    meta_type: 'profile_share',
                    meta_user_id: user.id,
                    meta_user_name: user.display_name || '',
                    meta_user_avatar: user.avatar_url || '',
                  })
                )
              );
            }}
          />
        )}
      </AnimatePresence>
    </>
  );
}

