/**
 * Renders a starter avatar as a circular image.
 * Uses SVG data URL for crisp rendering at any size.
 */
export function StarterAvatarImage({ id, size = 64, className = '', style = {} }) {
  const svg = AVATAR_SVGS[id];
  if (!svg) {
    return (
      <div
        style={{ width: size, height: size, borderRadius: '50%', background: '#e2e8f0', flexShrink: 0, ...style }}
        className={className}
      />
    );
  }
  const dataUrl = `data:image/svg+xml,${encodeURIComponent(svg)}`;
  return (
    <img
      src={dataUrl}
      width={size}
      height={size}
      alt={id}
      draggable={false}
      className={className}
      style={{ borderRadius: '50%', flexShrink: 0, display: 'block', objectFit: 'cover', overflow: 'hidden', ...style }}
    />
  );
}

// ── SVG → File conversion (for uploading to CDN) ─────────────────────────────

/**
 * Converts a starter avatar SVG to a 200×200 PNG File object.
 * Uses canvas to render and export a circular crop.
 */
export async function svgToFile(svgString, size = 200) {
  const dataUrl = `data:image/svg+xml,${encodeURIComponent(svgString)}`;
  return new Promise((resolve, reject) => {
    const img = new window.Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = size;
      canvas.height = size;
      const ctx = canvas.getContext('2d');
      ctx.beginPath();
      ctx.arc(size / 2, size / 2, size / 2, 0, Math.PI * 2);
      ctx.clip();
      ctx.drawImage(img, 0, 0, size, size);
      canvas.toBlob(
        blob => blob
          ? resolve(new File([blob], 'avatar.png', { type: 'image/png' }))
          : reject(new Error('Canvas toBlob failed')),
        'image/png'
      );
    };
    img.onerror = () => reject(new Error('SVG image load failed'));
    img.src = dataUrl;
  });
}

/**
 * Returns a PNG File for the given starter avatar ID.
 */
export async function getStarterAvatarFile(avatarId) {
  const svg = AVATAR_SVGS[avatarId];
  if (!svg) throw new Error(`Unknown starter avatar: ${avatarId}`);
  return svgToFile(svg);
}

