import React from 'react';
import { useNavigate } from 'react-router-dom';
import { createPageUrl } from '@/utils';

export default function UserProfileNavigator({ userId, children }) {
  const navigate = useNavigate();

  const handleClick = (e) => {
    e.preventDefault();
    e.stopPropagation();

    if (!userId) return;

    // Skip navigation for service accounts (system-generated content)
    if (userId.startsWith('service_') || userId.startsWith('service+')) return;

    // Navigate IMMEDIATELY — no async blocking, no pre-fetch
    // UserProfile page handles all account_state cases via progressive loading
    navigate(createPageUrl('UserProfile') + `?userId=${userId}`);
  };

  return (
    <div onClick={handleClick} className="cursor-pointer">
      {children}
    </div>
  );
}

