/**
 * FeatureCard — Task C implementation
 * Auto animation: floating micro motion + glow pulse
 * Respects prefers-reduced-motion
 * Staggered animation between cards
 */
import { motion } from "framer-motion";
import { useEffect, useState } from "react";

export default function FeatureCard({ feature, index }) {
  const [isVisible, setIsVisible] = useState(true);
  const [prefersReducedMotion, setPrefersReducedMotion] = useState(false);

  useEffect(() => {
    const mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)");
    setPrefersReducedMotion(mediaQuery.matches);

    const handleChange = () => setPrefersReducedMotion(mediaQuery.matches);
    mediaQuery.addEventListener("change", handleChange);
    return () => mediaQuery.removeEventListener("change", handleChange);
  }, []);

  // Pause animation when component unmounted (screen not visible)
  useEffect(() => {
    setIsVisible(true);
    return () => setIsVisible(false);
  }, []);

  const IconEl = feature.iconEl;

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5, ease: "easeOut", delay: index * 0.1 }}
      className="relative flex items-center gap-4 px-4 py-4 rounded-2xl overflow-hidden"
      style={{
        background: "linear-gradient(135deg, rgba(249,115,22,0.13) 0%, rgba(239,68,68,0.08) 50%, rgba(20,10,0,0.5) 100%)",
        border: "1.5px solid rgba(249,115,22,0.38)",
        boxShadow: "0 8px 32px rgba(249,115,22,0.18), 0 1px 0 rgba(255,200,100,0.08) inset",
      }}
    >
      {/* Icon box with floating motion + glow pulse */}
      <motion.div
        animate={
          prefersReducedMotion || !isVisible
            ? {}
            : {
                y: [0, -4, 0],
              }
        }
        transition={
          prefersReducedMotion || !isVisible
            ? {}
            : {
                duration: 4,
                repeat: Infinity,
                ease: "easeInOut",
                delay: index * 0.2,
              }
        }
        className="rounded-2xl flex items-center justify-center flex-shrink-0 relative"
        style={{
          width: 54,
          height: 54,
          background: "linear-gradient(135deg, rgba(249,115,22,0.32) 0%, rgba(239,68,68,0.22) 100%)",
          border: "1.5px solid rgba(249,115,22,0.4)",
          color: "#fb923c",
        }}
      >
        {/* Glow pulse */}
        {!prefersReducedMotion && isVisible && (
          <motion.div
            animate={{ opacity: [0.3, 0.7, 0.3] }}
            transition={{
              duration: 3,
              repeat: Infinity,
              ease: "easeInOut",
              delay: index * 0.2,
            }}
            className="absolute inset-0 rounded-2xl pointer-events-none"
            style={{
              boxShadow: "0 0 20px rgba(249,115,22,0.5)",
            }}
          />
        )}

        {/* Icon */}
        <div className="relative z-10">
          <IconEl />
        </div>
      </motion.div>

      {/* Text (no animation) */}
      <div>
        <p className="font-black text-sm text-white" style={{ letterSpacing: "0.01em" }}>
          {feature.label}
        </p>
        <p className="text-xs mt-0.5" style={{ color: "rgba(255,200,140,0.7)" }}>
          {feature.sub}
        </p>
      </div>
    </motion.div>
  );
}

