import React, { useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, TrendingUp, Award } from "lucide-react";
import { RATING_TIERS, computeRatingTier } from "../rating/RatingBadgeTiers";
import { cn } from "@/lib/utils";

const tierColorMap = {
  slate: "text-slate-500 bg-slate-50",
  bronze: "text-amber-700 bg-amber-50",
  silver: "text-slate-600 bg-slate-100",
  gold: "text-amber-600 bg-amber-100",
  platinum: "text-blue-600 bg-blue-50",
  diamond: "text-cyan-600 bg-cyan-50"
};

const tierIconEmoji = {
  crown_outline: "👑",
  bronze_crown: "🥉",
  silver_crown: "🥈",
  gold_crown: "🥇",
  gold_crown_sparkle: "✨👑",
  platinum_crown: "👑💎",
  diamond_crown: "💎👑",
  royal_crown_aura: "👑✨"
};

export default function RatingBadgeModal({ isOpen, onClose, totalRatingsReceived = 0 }) {
  const currentTier = computeRatingTier(totalRatingsReceived);

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className="fixed inset-0 z-50 bg-black/60 backdrop-blur-sm flex items-end sm:items-center justify-center p-4"
        onClick={onClose}
      >
        <motion.div
          initial={{ y: 100, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 100, opacity: 0 }}
          transition={{ type: "spring", damping: 25, stiffness: 300 }}
          className="bg-white rounded-3xl w-full max-w-md max-h-[90vh] overflow-y-auto shadow-2xl"
          onClick={e => e.stopPropagation()}
        >
          {/* Header */}
          <div className="sticky top-0 bg-gradient-to-r from-purple-50 via-indigo-50 to-blue-50 p-6 flex items-center justify-between border-b border-purple-200">
            <h2 className="text-lg font-bold text-slate-900 flex items-center gap-2">
              <Award className="w-5 h-5 text-purple-600" />
              Pro Reputation
            </h2>
            <button onClick={onClose} className="w-8 h-8 rounded-full bg-white/80 hover:bg-white flex items-center justify-center transition-colors">
              <X className="w-4 h-4 text-slate-600" />
            </button>
          </div>

          <div className="p-6 space-y-6">
            {/* Current Tier Card */}
            <motion.div
              initial={{ scale: 0.95 }}
              animate={{ scale: 1 }}
              className={cn(
                "rounded-2xl p-5 text-center border-2",
                tierColorMap[currentTier.color_key]
              )}
            >
              <div className="text-4xl mb-3">{tierIconEmoji[currentTier.icon_key] || "👑"}</div>
              <h3 className="text-lg font-bold mb-1">{currentTier.tier_name}</h3>
              <p className="text-sm opacity-75 mb-4">{currentTier.description}</p>
              <div className="text-2xl font-bold">{totalRatingsReceived}</div>
              <p className="text-xs opacity-60 mt-1">ratings received</p>

              {/* Progress to next tier */}
              {currentTier.next_threshold && (
                <div className="mt-4 space-y-2">
                  <div className="flex items-center justify-between text-xs">
                    <span>Progress to {RATING_TIERS.find(t => t.threshold === currentTier.next_threshold)?.tier_name}</span>
                    <span className="font-semibold">{currentTier.progress_to_next}%</span>
                  </div>
                  <div className="w-full h-2 bg-black/10 rounded-full overflow-hidden">
                    <motion.div
                      initial={{ width: 0 }}
                      animate={{ width: `${currentTier.progress_to_next}%` }}
                      transition={{ duration: 1, ease: "easeOut" }}
                      className="h-full bg-gradient-to-r from-amber-400 to-orange-500"
                    />
                  </div>
                  <p className="text-xs opacity-60 text-right">{currentTier.next_threshold - totalRatingsReceived} more ratings</p>
                </div>
              )}
            </motion.div>

            {/* Tier Ladder */}
            <div>
              <h4 className="font-semibold text-slate-900 mb-3 flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-purple-600" />
                Tier Ladder
              </h4>
              <div className="space-y-2">
                {RATING_TIERS.map((tier, idx) => {
                  const isCurrentOrBelow = totalRatingsReceived >= tier.threshold;
                  const isCurrentTierExact = currentTier.tier_key === tier.tier_key;

                  return (
                    <motion.div
                      key={tier.tier_key}
                      initial={{ opacity: 0, x: -10 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: idx * 0.05 }}
                      className={cn(
                        "p-3 rounded-lg border-2 flex items-center gap-3 transition-all",
                        isCurrentTierExact
                          ? "bg-gradient-to-r from-purple-50 to-indigo-50 border-purple-300 shadow-md scale-105"
                          : isCurrentOrBelow
                          ? "bg-slate-50 border-slate-200"
                          : "bg-slate-50/50 border-slate-100 opacity-60"
