/**
 * FreeGenerateHeader
 * 
 * Shows free weekly usage + banked referral credits.
 * When weekly free is exhausted, shows the referral plus button.
 */
export default function FreeGenerateHeader({
  used = 0,
  total = 2,
  resetDate = null,
  bankedReferralCredits = 0,
  showReferralPlusButton = false,
}) {
  const weeklyRemaining = Math.max(0, total - used);
  const totalAvailable = weeklyRemaining + bankedReferralCredits;
  const isExhausted = weeklyRemaining === 0 && bankedReferralCredits === 0;

  return (
    <motion.div
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      className="rounded-3xl overflow-hidden bg-gradient-to-br from-slate-50 to-slate-100 border border-slate-200 shadow-sm"
    >
      <div className="p-6">
        {/* Header row */}
        <div className="flex items-start justify-between gap-4">
          <div className="flex items-start gap-3 flex-1 min-w-0">
            <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-indigo-100 to-purple-100 flex items-center justify-center flex-shrink-0">
              <Sparkles className="w-6 h-6 text-indigo-600" strokeWidth={2} />
            </div>
            <div className="min-w-0">
              <h2 className="text-lg font-bold text-slate-900">AI Recipe Generator</h2>
              <p className="text-xs text-slate-500 mt-1">
                {bankedReferralCredits > 0
                  ? `${weeklyRemaining} weekly + ${bankedReferralCredits} referral credits`
                  : "Limited to 2 per week on free tier"}
              </p>
            </div>
          </div>

          {/* Usage counter */}
          <motion.div initial={{ scale: 0.95 }} animate={{ scale: 1 }} className="flex-shrink-0 text-center">
            <div className={`text-2xl font-bold ${isExhausted ? "text-rose-500" : "text-slate-900"}`}>
              {totalAvailable}/{total}
            </div>
            <p className="text-xs text-slate-500 mt-1">
              {bankedReferralCredits > 0 ? "Total avail." : "Available"}
            </p>
          </motion.div>
        </div>

        {/* Progress bar (weekly only) */}
        <motion.div className="mt-4 h-2 bg-slate-200 rounded-full overflow-hidden" layout>
          <motion.div
            initial={{ width: 0 }}
            animate={{ width: `${Math.max(0, (used / total) * 100)}%` }}
            transition={{ duration: 0.6 }}
            className="h-full bg-gradient-to-r from-indigo-500 to-purple-500"
          />
        </motion.div>

        {/* Banked credits row */}
        {bankedReferralCredits > 0 && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: "auto" }}
            className="mt-3 flex items-center gap-2 px-3 py-2 bg-indigo-50 border border-indigo-100 rounded-xl"
          >
            <Gift className="w-3.5 h-3.5 text-indigo-500 flex-shrink-0" />
            <span className="text-xs text-indigo-700 font-semibold">
              +{bankedReferralCredits} referral credit{bankedReferralCredits !== 1 ? "s" : ""} banked
            </span>
          </motion.div>
        )}

        {/* Reset info */}
        {resetDate && (
          <div className="mt-3 flex items-center gap-2 text-xs text-slate-600">
            <Clock className="w-3.5 h-3.5" />
            <span>Weekly resets {resetDate}</span>
          </div>
        )}
      </div>

      {/* Referral plus button — when weekly free is exhausted */}
      {showReferralPlusButton && (
        <div className="px-6 pb-5">
          <ReferralPlusButton style="full" />
        </div>
      )}

      {/* Upgrade prompt when truly exhausted (no weekly AND no banked) */}
      {isExhausted && (
        <div className="px-6 pb-5">
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="p-3 bg-indigo-50 border border-indigo-200 rounded-xl text-center"
          >
            <p className="text-xs text-indigo-700 font-semibold">
              Out of generations? Upgrade to Pro for unlimited.
            </p>
          </motion.div>
        </div>
      )}
    </motion.div>
