export default function FunnelPaywall({ onSkip }) {
  const [selectedPlan, setSelectedPlan] = useState("yearly");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const isNative = billingBridge.isAvailable();
  const isYearly = selectedPlan === "yearly";

  const handlePurchase = async () => {
    if (loading) return;
    setLoading(true);
    setError("");

    // ── Native path: use billingBridge for store purchase ──────────────
    if (isNative) {
      const productId = isYearly ? 'reciply_pro_yearly' : 'reciply_pro_monthly';
      const result = await billingBridge.purchase(productId);
      if (result.success) {
        clearEntitlementCache();
        window.location.href = createPageUrl("Home") + "?revalidate_ent=1";
        return;
      }
      if (!result.cancelled) {
        setError(result.error || "Purchase failed. Please try again.");
      }
      setLoading(false);
      return;
    }

    // ── Web path: backend-managed subscriptions ───────────────────────
    try {
      const endpoint = isYearly ? "startFreeTrial" : "startMonthlySubscription";
      const res = await base44.functions.invoke(endpoint, {
        plan_id: isYearly ? 'pro_yearly' : 'pro_monthly',
        source: 'pro_funnel',
      });
      if (res.data?.success || res.data?.already_active) {
        clearEntitlementCache();
        window.location.href = createPageUrl("Home") + "?revalidate_ent=1";
      } else {
        setError(res.data?.message || res.data?.error || "Could not start subscription.");
        setLoading(false);
      }
    } catch (err) {
      setError(err?.response?.data?.error || "Failed to start subscription.");
      setLoading(false);
    }
  };

  const handleRestore = async () => {
    if (!isNative) return;
    const res = await billingBridge.restore();
    if (res.restored > 0) { clearEntitlementCache(); window.location.href = createPageUrl("Home") + "?revalidate_ent=1"; }
    else { setError("No previous purchases found."); }
  };

  return (
    <div className="flex-1 flex flex-col px-6">
      {/* Top bar */}
      <div className="flex items-center justify-end gap-3 pt-2 pb-0.5 flex-shrink-0">
        {isNative && (
          <button onClick={handleRestore} className="text-[11px] font-semibold text-indigo-400" style={{ minHeight: 32, display: "flex", alignItems: "center" }}>Restore</button>
        )}
        <button onClick={onSkip} className="text-[11px] font-semibold text-slate-400 hover:text-slate-600 transition-colors" style={{ minHeight: 32, display: "flex", alignItems: "center" }}>Skip</button>
      </div>

      {/* Headline */}
      <div className="text-center mb-2.5 flex-shrink-0">
        <AnimatePresence mode="wait">
          <motion.div key={isYearly ? "y" : "m"} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }} transition={{ duration: 0.18 }}>
            <h1 className="font-black text-slate-900 leading-[1.1] tracking-tight" style={{ fontSize: "clamp(1.25rem, 5.5vw, 1.6rem)" }}>
              {isYearly ? "Start your 3-day " : "Unlock "}
              <span className="text-indigo-600">{isYearly ? "free trial" : "Reciply Pro"}</span>
            </h1>
            <p className="text-[11px] text-slate-500 font-medium mt-0.5">
              {isYearly ? "Full access · Cancel anytime" : "All Pro features · Cancel anytime"}
