import React, { useState } from "react";

export default function PaywallMedia({
  imageSrc,
  videoSrc,
  alt = "",
  className = "",
  aspectRatio = "4/3",
  rounded = "2xl",
  placeholder,
}) {
  const [videoError, setVideoError] = useState(false);
  const [imgError, setImgError] = useState(false);

  const wrapperStyle = {
    aspectRatio,
    borderRadius: rounded === "2xl" ? 20 : rounded === "3xl" ? 24 : 16,
    overflow: "hidden",
    background: "#1a1a2e",
  };

  // Video mode
  if (videoSrc && !videoError) {
    return (
      <div className={className} style={wrapperStyle}>
        <video
          src={videoSrc}
          autoPlay
          loop
          muted
          playsInline
          onError={() => setVideoError(true)}
          className="w-full h-full object-cover"
          style={{ display: "block" }}
        />
      </div>
    );
  }

  // Image mode
  if (imageSrc && !imgError) {
    return (
      <div className={className} style={wrapperStyle}>
        <img
          src={imageSrc}
          alt={alt}
          onError={() => setImgError(true)}
          className="w-full h-full object-cover"
          draggable={false}
          style={{ display: "block" }}
        />
      </div>
    );
  }

  // Placeholder
  if (placeholder) return <div className={className} style={wrapperStyle}>{placeholder}</div>;

  return (
    <div className={className} style={{ ...wrapperStyle, display: "flex", alignItems: "center", justifyContent: "center" }}>
