import { useState, useEffect, useRef } from 'react';

/**
 * useSmoothProgress — Clean, monotonic progress (0–95 capped, then 100 on completion)
 * 
 * Returns: { progress (0–100), isLoading }
 * - Progress is deterministic and never jitters or decreases
 * - Indeterminate curve: 0→60 in ~900ms, 60→85 in ~1600ms, 85→95 slow approach
 * - Hard cap at 95 until operation resolves
 * - On success: animate 95→100 in 400–650ms
 * - On failure: stop at current progress and show error
 */
export function useSmoothProgress({ isLoading, mode = 'indeterminate', durationHintMs = 2500 }) {
  const [progress, setProgress] = useState(0);
  const timeStartRef = useRef(null);
  const modeRef = useRef(mode);
  const lastProgressRef = useRef(0);

  useEffect(() => {
    modeRef.current = mode;
  }, [mode]);

  useEffect(() => {
    if (!isLoading) {
      // Operation complete: animate current→100 in 500ms
      if (lastProgressRef.current > 0 && lastProgressRef.current < 100) {
        const startVal = lastProgressRef.current;
        const startTime = Date.now();
        const animateComplete = () => {
          const elapsed = Date.now() - startTime;
          const ratio = Math.min(elapsed / 500, 1);
          const nextProgress = Math.round(startVal + (100 - startVal) * ratio);
          setProgress(nextProgress);
          lastProgressRef.current = nextProgress;
          if (ratio < 1) {
            requestAnimationFrame(animateComplete);
          } else {
            // Reset after brief pause so component can re-use
            setTimeout(() => {
              setProgress(0);
              lastProgressRef.current = 0;
              timeStartRef.current = null;
            }, 600);
          }
        };
        requestAnimationFrame(animateComplete);
      }
      return;
    }

    // Reset on load start
    if (isLoading && (lastProgressRef.current === 0 || !timeStartRef.current)) {
      timeStartRef.current = Date.now();
    }

    const interval = setInterval(() => {
      const elapsed = Date.now() - timeStartRef.current;
      let nextProgress;

      if (modeRef.current === 'smart') {
        // Smart mode: fast early, moderate middle, slow near end with shimmer
        if (elapsed < 1000) {
          // 0→30 in first second (fast)
          const ratio = elapsed / 1000;
          nextProgress = Math.round(30 * easeOutCubic(ratio));
        } else if (elapsed < 4000) {
          // 30→70 in next 3 seconds (moderate)
          const ratio = (elapsed - 1000) / 3000;
          nextProgress = Math.round(30 + 40 * easeOutCubic(ratio));
        } else if (elapsed < 8000) {
          // 70→95 in next 4 seconds (slow)
          const ratio = (elapsed - 4000) / 4000;
          nextProgress = Math.round(70 + 25 * easeOutQuad(ratio));
        } else {
          // Stay at 95 with visual shimmer (handled in UI)
          nextProgress = 95;
        }
      } else {
        // Original indeterminate mode
        if (elapsed < 900) {
          // 0→60 in 900ms (easeOut)
          const ratio = elapsed / 900;
          nextProgress = Math.round(60 * easeOutCubic(ratio));
        } else if (elapsed < 2500) {
          // 60→85 in 1600ms
          const ratio = (elapsed - 900) / 1600;
          nextProgress = Math.round(60 + 25 * easeOutCubic(ratio));
        } else {
          // 85→95 slow approach
          const ratio = Math.min((elapsed - 2500) / 3000, 1);
          nextProgress = Math.round(85 + 10 * easeOutQuad(ratio));
        }
      }

      // Cap at 95 (never hit 100 until operation completes)
      nextProgress = Math.min(nextProgress, 95);

      // Ensure monotonic (never decrease)
      if (nextProgress > lastProgressRef.current) {
        setProgress(nextProgress);
        lastProgressRef.current = nextProgress;
      }
    }, 100); // Tick every 100ms for smooth updates

    return () => clearInterval(interval);
  }, [isLoading]);

  return { progress, isLoading };
}

function easeOutCubic(t) {
  return 1 - Math.pow(1 - t, 3);
}

function easeOutQuad(t) {
  return 1 - (1 - t) * (1 - t);
}

/**
 * useOptimisticMutation
 * 
 * A thin wrapper around @tanstack/react-query useMutation that handles
 * the standard optimistic UI pattern:
 *   1. onMutate: snapshot cache, apply optimistic update
 *   2. onError: rollback to snapshot
 *   3. onSettled: invalidate queries for eventual consistency
 * 
 * Usage:
 *   const { mutate } = useOptimisticMutation({
 *     mutationFn: (variables) => api.call(variables),
 *     queryClient,
 *     // Provide either getOptimisticData + queryKey, or use onMutate/onError/onSettled directly
 *     queryKey: ["user-likes"],
 *     getOptimisticData: (variables, oldData) => newData,
 *     invalidateKeys: [["user-likes"], ["recipe", id]],
 *   });
 */
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { toast } from "sonner";

export function useOptimisticMutation({
  mutationFn,
  queryKey,
  getOptimisticData,
  invalidateKeys = [],
  onSuccess,
  onError: onErrorProp,
  errorMessage = "Something went wrong. Please try again.",
}) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn,

    onMutate: async (variables) => {
      if (!queryKey || !getOptimisticData) return {};

      // Cancel in-flight queries so they don't overwrite optimistic update
      await queryClient.cancelQueries({ queryKey });

      // Snapshot current data for rollback
      const previousData = queryClient.getQueryData(queryKey);

      // Apply optimistic update
      queryClient.setQueryData(queryKey, (old) =>
        getOptimisticData(variables, old)
      );

      return { previousData };
    },

    onError: (err, variables, context) => {
      // Rollback on failure
      if (queryKey && context?.previousData !== undefined) {
        queryClient.setQueryData(queryKey, context.previousData);
      }
      if (onErrorProp) {
        onErrorProp(err, variables, context);
      } else {
        toast.error(errorMessage);
      }
    },

    onSuccess: (data, variables, context) => {
      onSuccess?.(data, variables, context);
    },

    onSettled: () => {
      // Always refetch to ensure consistency with server
      const keysToInvalidate = queryKey
        ? [queryKey, ...invalidateKeys]
        : invalidateKeys;
      keysToInvalidate.forEach((key) => {
        queryClient.invalidateQueries({ queryKey: key });
      });
    },
  });
}

import { useState, useEffect, useRef, useCallback } from 'react';

/**
 * Hook for managing progress with simulated curves
 * 
 * @param {Object} config
 * @param {boolean} config.isLoading - whether a request is in progress
 * @param {'determinate'|'indeterminate'} config.mode - progress mode
 * @param {number} config.determinateProgress - actual progress (0-100) for determinate mode
 * @param {string} config.label - display label
 * @param {boolean} config.isError - whether an error occurred
 * 
 * @returns {Object} { progress, displayLabel, isOpen }
 */
export function useProgress({
  isLoading = false,
  mode = 'indeterminate',
  determinateProgress = 0,
  label = 'Loading...',
  isError = false,
}) {
  const [progress, setProgress] = useState(0);
  const animationFrameRef = useRef(null);
  const startTimeRef = useRef(null);
  const lastProgressRef = useRef(0);

  // Simulate progress curve for indeterminate mode
  const simulateProgress = useCallback(() => {
    const elapsed = Date.now() - startTimeRef.current;
    const elapsedSeconds = elapsed / 1000;

    // Curve: quickly go 0→70% in 1.5s, then slowly approach 95%
    let simulated;
    if (elapsedSeconds < 1.5) {
      // Fast phase: 0→70%
      simulated = (elapsedSeconds / 1.5) * 70;
    } else {
      // Slow phase: 70→95% over remaining time
      const slowPhaseProgress = Math.min((elapsedSeconds - 1.5) / 8, 1);
      // Ease curve: slower as it approaches 95%
      const eased = slowPhaseProgress * slowPhaseProgress;
      simulated = 70 + eased * 25;
    }

    return Math.min(Math.round(simulated), 95);
  }, []);

  // Update progress based on mode
  useEffect(() => {
    if (mode === 'determinate') {
      setProgress(determinateProgress);
      return;
    }

    if (!isLoading) {
      setProgress(0);
      return;
    }

    // Start indeterminate simulation
    startTimeRef.current = Date.now();
    lastProgressRef.current = 0;

    const updateProgress = () => {
      const simulated = simulateProgress();
      setProgress(simulated);
      lastProgressRef.current = simulated;
      animationFrameRef.current = requestAnimationFrame(updateProgress);
    };

    animationFrameRef.current = requestAnimationFrame(updateProgress);

    return () => {
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }
    };
  }, [isLoading, mode, determinateProgress, simulateProgress]);

  // Jump to 100% on completion
  useEffect(() => {
    if (!isLoading && progress > 0 && !isError) {
      setProgress(100);
      // Close after a brief delay
      const timer = setTimeout(() => {
        setProgress(0);
      }, 600);
      return () => clearTimeout(timer);
    }
  }, [isLoading, isError, progress]);

  return {
    progress,
    displayLabel: label,
    isOpen: isLoading || (progress > 0 && progress < 100),
  };
}

/**
 * Multi-stage determinate progress helper
 * Maps stages to progress ranges
 */
export function useStageProgress({
  isLoading = false,
  stage = null,
  stageMap = {},
  label = 'Loading...',
}) {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    if (!isLoading) {
      setProgress(0);
      return;
    }

    const stageProgress = stageMap[stage] ?? 0;
    setProgress(Math.min(stageProgress, 95));
  }, [isLoading, stage, stageMap]);

  // Jump to 100% on completion
  useEffect(() => {
    if (!isLoading && progress > 0) {
      setProgress(100);
      const timer = setTimeout(() => {
        setProgress(0);
      }, 600);
      return () => clearTimeout(timer);
    }
  }, [isLoading, progress]);

  return {
    progress,
    displayLabel: label,
    isOpen: isLoading || (progress > 0 && progress < 100),
  };
}

