/**
 * useLikeUnified — Unified hook for all likes (recipes, posts, comments)
 *
 * ARCHITECTURE (persistent global store, not component-local):
 *
 * The store key is `${target_type}:${target_id}`.
 * State lives in a module-level Map that survives component unmount/remount.
 *
 * SEEDING RULES (immutable guarantees):
 * 1. A virgin entry (version=0, source='initial') is seeded from props on first mount.
 * 2. Once a user has interacted (version>0, source='backend_confirmed'|'optimistic'),
 *    props NEVER overwrite the store — the backend result is permanent until page hard-reload.
 * 3. On unmount: we do NOT reset the store. State persists in the global map so that
 *    re-entry to the same page (back navigation, tab switch) keeps the correct liked state.
 * 4. The only time state is cleared is when target_id changes (new recipe/post).
 *
 * TOGGLE RULES:
 * - Optimistic: flip locally, block re-click while in-flight.
 * - On response: apply backend result (authoritative), set cooldown.
 * - On error: revert, keep touched so stale props don't overwrite.
 *
 * STABLE AFTER:
 * - refresh (props re-seed from fresh query data if untouched)
 * - re-entry (global store survives; state persists)
 * - rapid toggle (in-flight guard + cooldown)
 * - card vs detail (same global key → always in sync)
 */
import { useState, useEffect, useCallback } from 'react';
import { base44 } from '@/api/base44Client';
import { toast } from 'sonner';

const COOLDOWN_MS = 800;

// Global persistent store — survives component unmount/remount within the same session.
// Key: `${target_type}:${target_id}`
// Value: { viewer_has_liked, like_count, inFlight, blockedUntil, version, source }
//   source: 'initial' | 'seeded' | 'optimistic' | 'backend_confirmed' | 'error_reverted'
const _store = new Map();
const _subs = new Map();
const _cooldownTimers = new Map();

// CROSS-SURFACE SYNC PROOF: expose store on window for runtime inspection.
// In browser console: window.__likeStore.get('recipe:RECIPE_ID')
// Quick proof helper: window.__likeProof('RECIPE_ID') → dumps state + subscriber count
if (typeof window !== 'undefined') {
  window.__likeStore = _store;
  window.__likeStoreSubs = _subs;
  window.__likeProof = (recipeId) => {
    const k = `recipe:${recipeId}`;
    const state = _store.get(k) ?? { not_seeded: true };
    const subCount = _subs.get(k)?.size ?? 0;
    const result = { key: k, state, subscribers: subCount };
    console.log('[LikeProof]', JSON.stringify(result, null, 2));
    return result;
  };
}

function _key(target_type, target_id) {
  return `${target_type}:${String(target_id)}`;
}

function _get(k) {
  return _store.get(k) ?? {
    viewer_has_liked: false,
    like_count: 0,
    inFlight: false,
    blockedUntil: 0,
    version: 0,
    source: 'initial',
  };
}

function _set(k, patch) {
  const current = _get(k);
  const next = { ...current, ...patch };
  if (patch.version !== undefined) next.version = patch.version;
  _store.set(k, next);
  // CROSS-SURFACE SYNC PROOF: log every store mutation with subscriber count
  const subCount = _subs.get(k)?.size ?? 0;
  if (patch.source && patch.source !== 'seeded' && patch.source !== 'initial') {
    console.log(`[LikeStore] _set key=${k} source=${next.source} liked=${next.viewer_has_liked} count=${next.like_count} version=${next.version} subscribers=${subCount}`);
  }
  // Notify all subscribers for this key
  const subs = _subs.get(k);
  if (subs) subs.forEach(fn => { try { fn(); } catch { subs.delete(fn); } });

  if (patch.blockedUntil && patch.blockedUntil > Date.now()) {
    const existing = _cooldownTimers.get(k);
    if (existing) clearTimeout(existing);
    const remaining = patch.blockedUntil - Date.now();
    const t = setTimeout(() => {
      _cooldownTimers.delete(k);
      const s2 = _subs.get(k);
      if (s2) s2.forEach(fn => { try { fn(); } catch {} });
    }, remaining + 10);
    _cooldownTimers.set(k, t);
  }
}

function _subscribe(k, fn) {
  if (!_subs.has(k)) _subs.set(k, new Set());
  _subs.get(k).add(fn);
}

function _unsubscribe(k, fn) {
  const subs = _subs.get(k);
  if (!subs) return;
  subs.delete(fn);
  // CRITICAL: Do NOT reset state on unsubscribe.
  // Persistent state in the global store means re-entry keeps the correct liked state.
  // State only resets when target_id changes (a new entry is accessed).
}

// Sentinel: caller passes LOADING_SENTINEL to signal "data not ready yet, don't seed"
export const LOADING_SENTINEL = Symbol('loading');

// DEV MISMATCH DETECTOR: tracks what each mounted component sees.
// If two components show different liked state for the same key, log a red-flag warning.
const _mountedViews = new Map(); // key → Map<componentId, { liked, count }>
let _viewIdCounter = 0;

function _registerView(k, liked, count) {
  const viewId = ++_viewIdCounter;
  if (!_mountedViews.has(k)) _mountedViews.set(k, new Map());
  _mountedViews.get(k).set(viewId, { liked, count });
  // Check for mismatches
  const views = _mountedViews.get(k);
  if (views.size > 1) {
    const vals = [...views.values()];
    const likedMismatch = vals.some(v => v.liked !== vals[0].liked);
    const countMismatch = vals.some(v => v.count !== vals[0].count);
    if (likedMismatch || countMismatch) {
      console.warn(`[LIKE_MISMATCH_DETECTED] key=${k} views=${views.size} liked=[${vals.map(v=>v.liked).join(',')}] counts=[${vals.map(v=>v.count).join(',')}]`);
    }
  }
  return viewId;
}

function _unregisterView(k, viewId) {
  const views = _mountedViews.get(k);
  if (views) {
    views.delete(viewId);
    if (views.size === 0) _mountedViews.delete(k);
  }
}

export function useLikeUnified(target_type, target_id, initialLiked = false, initialCount = 0) {
  const [, tick] = useState(0);
  const k = _key(target_type, target_id);

  // Subscribe/unsubscribe to store notifications + mismatch detector
  useEffect(() => {
    if (!target_id) return;
    const cb = () => tick(n => n + 1);
    _subscribe(k, cb);
    const s = _get(k);
    const viewId = _registerView(k, s.viewer_has_liked, s.like_count);
    return () => {
      _unsubscribe(k, cb);
      _unregisterView(k, viewId);
    };
  }, [k, target_id]);

  // SEED from props — after refresh, stores are EMPTY (module-scope, not persisted).
  // The engagement queries (Like.filter, feed data) are the authoritative source.
  // Rules:
  // 1. LOADING_SENTINEL / undefined / null → skip.
  // 2. User-touched (version>0) → NEVER overwrite.
  // 3. Virgin (source==='initial') → seed from props.
  // 4. Already seeded (version===0) → accept ANY prop change as authoritative re-seed.
  //    KEY FIX: The old code blocked true→false re-seeds, treating them as "stale feed."
  //    But after refresh, the viewer-like query IS the backend truth. If it says false,
  //    the store must accept false — not cling to a stale initial true from a feed card.
  useEffect(() => {
    if (!target_id) return;
    if (initialCount === LOADING_SENTINEL || initialCount === undefined || initialCount === null) return;
    const count = Number(initialCount) || 0;
    const newLiked = Boolean(initialLiked);

    const s = _get(k);
    const isUserTouched = s.version > 0 || s.source === 'optimistic' || s.source === 'backend_confirmed' || s.source === 'error_reverted';
    if (isUserTouched || s.inFlight) return;

    if (s.source === 'initial') {
      _set(k, {
        viewer_has_liked: newLiked,
        like_count: count,
        inFlight: false,
        blockedUntil: 0,
        version: 0,
        source: 'seeded',
      });
    } else if (s.source === 'seeded') {
      // Accept ANY change from authoritative queries when version===0.
      const likedChanged = newLiked !== s.viewer_has_liked;
      const countChanged = count !== s.like_count;

      if (likedChanged || countChanged) {
        _set(k, {
          viewer_has_liked: newLiked,
          like_count: countChanged ? count : s.like_count,
          inFlight: false,
          blockedUntil: 0,
          version: 0,
          source: 'seeded',
        });
      }
    }
  }, [k, target_id, initialLiked, initialCount]);

  const toggleLike = useCallback(async (e) => {
    if (e?.stopPropagation) e.stopPropagation();
    if (!target_id) return;

    const s = _get(k);
    if (s.inFlight || Date.now() < (s.blockedUntil || 0)) return;

    const prev = { viewer_has_liked: s.viewer_has_liked, like_count: s.like_count };
    const next = !prev.viewer_has_liked;
    const mutationVersion = (s.version || 0) + 1;

    // Optimistic update — version increments, blocks stale prop re-seeding permanently
    _set(k, {
      viewer_has_liked: next,
      like_count: Math.max(0, prev.like_count + (next ? 1 : -1)),
      inFlight: true,
      blockedUntil: 0,
      version: mutationVersion,
      source: 'optimistic',
    });

    try {
      const res = await base44.functions.invoke('toggleLikeUnified', { target_type, target_id });
      const data = res.data;

      // CRITICAL: Accept this response only if we are still on the same mutation
      // (no newer mutation started while this was in-flight)
      const current = _get(k);
      if (current.version <= mutationVersion) {
        _set(k, {
          viewer_has_liked: data.viewer_has_liked,
          like_count: data.like_count,
          inFlight: false,
          blockedUntil: Date.now() + COOLDOWN_MS,
          version: mutationVersion,
          source: 'backend_confirmed',
        });
      }
    } catch (err) {
      // Revert to previous state — but keep version elevated so stale props can't overwrite
      const current = _get(k);
      if (current.version <= mutationVersion) {
        _set(k, {
          viewer_has_liked: prev.viewer_has_liked,
          like_count: prev.like_count,
          inFlight: false,
          blockedUntil: Date.now() + COOLDOWN_MS,
          version: mutationVersion,
          source: 'error_reverted',
        });
      }
      toast.error("Couldn't update like. Try again.");
    }
  }, [k, target_id, target_type]);

  const s = _get(k);
  const disabled = s.inFlight || Date.now() < (s.blockedUntil || 0);

  return {
    like_count: s.like_count,
    viewer_has_liked: s.viewer_has_liked,
    toggleLike,
    disabled,
    inFlight: s.inFlight,
  };
}

/**
 * useSaveUnified — Unified hook for recipe saves (community/shop/public).
 *
 * ARCHITECTURE: mirrors useLikeUnified exactly.
 * - Module-level singleton Map (_saveStore) persists across mounts.
 * - First-seed-wins: stale cached props never overwrite a fresher seed.
 * - Optimistic toggle: saves_count and is_saved flip instantly.
 * - Backend-confirmed reconciliation on success.
 * - Error revert keeps version elevated so stale props can't overwrite.
 *
 * KEY DISTINCTION: This hook is ONLY for non-generated (community/shop) recipes.
 * AI-generated recipes use recipe.is_saved (Recipe entity field) — separate system.
 */
import { useState, useEffect, useCallback } from 'react';
import { base44 } from '@/api/base44Client';
import { toast } from 'sonner';

const COOLDOWN_MS = 600;

// Global persistent store
// Key: `recipe:${recipe_id}`
// Value: { viewer_has_saved, saves_count, inFlight, blockedUntil, version, source }
const _saveStore = new Map();
const _saveSubs = new Map();
const _saveCooldownTimers = new Map();

// NAVIGATION-SAFE: Track in-flight save promises so they complete even after unmount.
// This prevents saves from being "lost" when user taps save and immediately navigates away.
const _inflightSaves = new Map(); // key → Promise

// Debug/proof helpers + mismatch detector
if (typeof window !== 'undefined') {
  window.__saveStore = _saveStore;
  window.__saveStoreSubs = _saveSubs;
  window.__saveProof = (recipeId) => {
    const k = `recipe:${recipeId}`;
    const state = _saveStore.get(k) ?? { not_seeded: true };
    const subCount = _saveSubs.get(k)?.size ?? 0;
    const result = { key: k, state, subscribers: subCount };
    console.log('[SaveProof]', JSON.stringify(result, null, 2));
    return result;
  };
}

// DEV MISMATCH DETECTOR: tracks mounted components to detect cross-surface divergence
const _saveMountedViews = new Map(); // key → Map<viewId, { saved }>
let _saveViewIdCounter = 0;

function _registerSaveView(k, saved) {
  const viewId = ++_saveViewIdCounter;
  if (!_saveMountedViews.has(k)) _saveMountedViews.set(k, new Map());
  _saveMountedViews.get(k).set(viewId, { saved });
  const views = _saveMountedViews.get(k);
  if (views.size > 1) {
    const vals = [...views.values()];
    const mismatch = vals.some(v => v.saved !== vals[0].saved);
    if (mismatch) {
      console.warn(`[SAVE_MISMATCH_DETECTED] entity_key=${k} views=${views.size} saved=[${vals.map(v => v.saved).join(',')}]`);
    }
  }
  return viewId;
}

function _unregisterSaveView(k, viewId) {
  const views = _saveMountedViews.get(k);
  if (views) {
    views.delete(viewId);
    if (views.size === 0) _saveMountedViews.delete(k);
  }
}

function _key(recipe_id) {
  return `recipe:${String(recipe_id)}`;
}

function _get(k) {
  return _saveStore.get(k) ?? {
    viewer_has_saved: false,
    saves_count: 0,
    inFlight: false,
    blockedUntil: 0,
    version: 0,
    source: 'initial',
  };
}

function _set(k, patch) {
  const current = _get(k);
  const next = { ...current, ...patch };
  _saveStore.set(k, next);
  const subCount = _saveSubs.get(k)?.size ?? 0;
  if (patch.source && patch.source !== 'seeded' && patch.source !== 'initial') {
    console.log(`[SaveStore] _set key=${k} source=${next.source} saved=${next.viewer_has_saved} count=${next.saves_count} version=${next.version} subscribers=${subCount}`);
  }
  const subs = _saveSubs.get(k);
  if (subs) subs.forEach(fn => { try { fn(); } catch { subs.delete(fn); } });

  if (patch.blockedUntil && patch.blockedUntil > Date.now()) {
    const existing = _saveCooldownTimers.get(k);
    if (existing) clearTimeout(existing);
    const remaining = patch.blockedUntil - Date.now();
    const t = setTimeout(() => {
      _saveCooldownTimers.delete(k);
      const s2 = _saveSubs.get(k);
      if (s2) s2.forEach(fn => { try { fn(); } catch {} });
    }, remaining + 10);
    _saveCooldownTimers.set(k, t);
  }
}

function _subscribe(k, fn) {
  if (!_saveSubs.has(k)) _saveSubs.set(k, new Set());
  _saveSubs.get(k).add(fn);
}

function _unsubscribe(k, fn) {
  const subs = _saveSubs.get(k);
  if (!subs) return;
  subs.delete(fn);
  // CRITICAL: Do NOT reset state on unsubscribe — persistent state survives re-entry.
}

export function useSaveUnified(recipe_id, initialSaved = false, initialCount = 0) {
  const [, tick] = useState(0);
  const k = _key(recipe_id);

  // Subscribe to store notifications for this key + mismatch detector
  useEffect(() => {
    if (!recipe_id) return;
    const cb = () => tick(n => n + 1);
    _subscribe(k, cb);
    const s = _get(k);
    const viewId = _registerSaveView(k, s.viewer_has_saved);
    return () => {
      _unsubscribe(k, cb);
      _unregisterSaveView(k, viewId);
    };
  }, [k, recipe_id]);

  // Seed from props — mirrors useLikeUnified seeding rules:
  // 1. Virgin (source==='initial') → seed from props.
  // 2. Already seeded (version===0) → accept ANY change from props.
  //    CRITICAL FIX: After refresh, stores are empty. The RecipeSave query is authoritative.
  //    Both false→true AND true→false must be accepted when version===0 (no user interaction).
  //    The old code blocked true→false, which meant a stale optimistic seed would persist
  //    even after the backend query confirmed the item is NOT saved.
  // 3. User-touched (version>0) → NEVER overwrite.
  useEffect(() => {
    if (!recipe_id) return;
    const s = _get(k);

    const isUserTouched = s.version > 0 || s.source === 'optimistic' || s.source === 'backend_confirmed' || s.source === 'error_reverted';
    // NAVIGATION-SAFE: Also block seeding if a global in-flight save exists for this key.
    // This prevents stale refetch data from overwriting the optimistic state after unmount.
    if (isUserTouched || s.inFlight || _inflightSaves.has(k)) return;

    if (s.source === 'initial') {
      _set(k, {
        viewer_has_saved: Boolean(initialSaved),
        saves_count: initialCount ?? 0,
        inFlight: false,
        blockedUntil: 0,
        version: 0,
        source: 'seeded',
      });
    } else if (s.source === 'seeded') {
      const newSaved = Boolean(initialSaved);
      const newCount = initialCount ?? 0;
      const savedChanged = newSaved !== s.viewer_has_saved;
      const countChanged = newCount !== s.saves_count;

      if (savedChanged || countChanged) {
        _set(k, {
          viewer_has_saved: newSaved,
          saves_count: countChanged ? newCount : s.saves_count,
          inFlight: false,
          blockedUntil: 0,
          version: 0,
          source: 'seeded',
        });
      }
    }
  }, [k, recipe_id, initialSaved, initialCount]);

  const toggleSave = useCallback(async (e) => {
    if (e?.stopPropagation) e.stopPropagation();
    if (!recipe_id) return;

    const s = _get(k);
    if (s.inFlight || Date.now() < (s.blockedUntil || 0)) return;

    const prev = { viewer_has_saved: s.viewer_has_saved, saves_count: s.saves_count };
    const next = !prev.viewer_has_saved;
    const mutationVersion = (s.version || 0) + 1;

    // Optimistic update
    _set(k, {
      viewer_has_saved: next,
      saves_count: Math.max(0, prev.saves_count + (next ? 1 : -1)),
      inFlight: true,
      blockedUntil: 0,
      version: mutationVersion,
      source: 'optimistic',
    });

    // NAVIGATION-SAFE: Fire-and-forget promise stored in module scope.
    // Even if the component unmounts (user navigates away), the promise
    // completes and updates the module-level store correctly.
    const savePromise = base44.functions.invoke('toggleRecipeSave', { recipe_id })
      .then((res) => {
        const data = res.data;
        const current = _get(k);
        if (current.version <= mutationVersion) {
          _set(k, {
            viewer_has_saved: data.saved,
            saves_count: data.saves_count ?? (next ? prev.saves_count + 1 : Math.max(0, prev.saves_count - 1)),
            inFlight: false,
            blockedUntil: Date.now() + COOLDOWN_MS,
            version: mutationVersion,
            source: 'backend_confirmed',
          });
        }
      })
      .catch(() => {
        const current = _get(k);
        if (current.version <= mutationVersion) {
          _set(k, {
            viewer_has_saved: prev.viewer_has_saved,
            saves_count: prev.saves_count,
            inFlight: false,
            blockedUntil: Date.now() + COOLDOWN_MS,
            version: mutationVersion,
            source: 'error_reverted',
          });
        }
        toast.error("Couldn't update save. Try again.");
      })
      .finally(() => {
        _inflightSaves.delete(k);
      });

    // Store promise so it survives component unmount
    _inflightSaves.set(k, savePromise);
  }, [k, recipe_id]);

  const s = _get(k);
  const disabled = s.inFlight || Date.now() < (s.blockedUntil || 0);

  return {
    saves_count: s.saves_count,
    viewer_has_saved: s.viewer_has_saved,
    toggleSave,
    disabled,
    inFlight: s.inFlight,
  };
}

/**
