      <div className="grid grid-cols-2 gap-4">
        {/* Total Cost */}
        <div className="flex flex-col gap-1">
          <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Total Cost</p>
          <div className="flex items-start gap-1 flex-wrap">
            <PriceTag usdAmount={totalCost} variant="plain" className="text-base font-black text-amber-700" />
            <span className="text-xs text-slate-400 mt-1">for {servings} {servings === 1 ? 'serving' : 'servings'}</span>
          </div>
        </div>

        {/* Per Serving */}
        <div className="flex flex-col gap-1">
          <p className="text-xs font-bold text-slate-500 uppercase tracking-wider">Per Serving</p>
          <div className="flex items-start gap-1 flex-wrap">
