/**
 * NUTRITION CALCULATOR V2 — DETERMINISTIC GRAM-BASED MATH
 * base_grams -> scaled_grams -> ingredient_totals -> recipe_totals -> per_serving
 */

export function calculateNutritionV2(ingredients, default_servings, adjusted_servings) {
  if (!ingredients || ingredients.length === 0) {
    return { per_serving: null, total: null, debug_log: 'No ingredients', invariants: { pass: false } };
  }

  const log = [];
  log.push(`scale: ${adjusted_servings}/${default_servings} = ${(adjusted_servings / default_servings).toFixed(3)}`);

  let totals = { calories: 0, protein_g: 0, carbs_g: 0, fat_g: 0, fiber_g: 0 };
  const scale_factor = adjusted_servings / default_servings;

  for (const ingredient of ingredients) {
    if (!ingredient.base_grams || ingredient.base_grams <= 0) {
      return { per_serving: null, total: null, debug_log: `Missing base_grams: ${ingredient.name}`, invariants: { pass: false, reason: 'missing_base_grams' } };
    }
    const n = ingredient.nutrition_per_100g;
    if (!n) {
      return { per_serving: null, total: null, debug_log: `Missing nutrition_per_100g: ${ingredient.name}`, invariants: { pass: false, reason: 'missing_nutrition' } };
    }

    const sg = ingredient.base_grams * scale_factor;
    log.push(`${ingredient.name}: ${ingredient.base_grams}g x ${scale_factor.toFixed(2)} = ${sg.toFixed(1)}g`);

    totals.calories  += sg * (n.calories  / 100);
    totals.protein_g += sg * (n.protein_g / 100);
    totals.carbs_g   += sg * (n.carbs_g   / 100);
    totals.fat_g     += sg * (n.fat_g     / 100);
    totals.fiber_g   += sg * (n.fiber_g   / 100);
  }

  const per_serving = {
    calories:  totals.calories  / adjusted_servings,
    protein_g: totals.protein_g / adjusted_servings,
    carbs_g:   totals.carbs_g   / adjusted_servings,
    fat_g:     totals.fat_g     / adjusted_servings,
    fiber_g:   totals.fiber_g   / adjusted_servings,
  };

  log.push(`TOTAL: cal=${totals.calories.toFixed(1)} p=${totals.protein_g.toFixed(1)}g c=${totals.carbs_g.toFixed(1)}g f=${totals.fat_g.toFixed(1)}g`);
  log.push(`PER SERVING: cal=${per_serving.calories.toFixed(1)} p=${per_serving.protein_g.toFixed(1)}g c=${per_serving.carbs_g.toFixed(1)}g f=${per_serving.fat_g.toFixed(1)}g`);

  return {
    per_serving: round(per_serving),
    total: round(totals),
    debug_log: log.join('\n'),
    invariants: { pass: true },
  };
}

function round(n) {
  return {
    calories:  Math.round(n.calories),
    protein_g: Math.round(n.protein_g * 10) / 10,
    carbs_g:   Math.round(n.carbs_g   * 10) / 10,
    fat_g:     Math.round(n.fat_g     * 10) / 10,
    fiber_g:   Math.round(n.fiber_g   * 10) / 10,
  };
}

