/**
 * GlobalPricingEngine
 * 
 * Complete ingredient pricing system:
 * 1. Normalize ingredient name to canonical ingredient
 * 2. Parse unit → edible grams (with yield ratio)
 * 3. Apply base price per 100g
 * 4. Apply region + store multipliers
 * 5. Return cost with confidence level
 * 
 * Handles edge cases:
 * - Missing ingredients → category fallback
 * - Unknown units → safe estimates
 * - Small amounts → realistic minimum costs
 */

import {
  lookupCanonical,
  CANONICAL_INGREDIENTS,
  CATEGORY_FLOORS,
  COUNTRY_MULTIPLIERS,
  REGION_MULTIPLIERS,
  getCountryMultiplier,
} from './CanonicalIngredientDatabase';

// Adapter aliases so existing callers compile without change
function findCanonicalIngredient(name) { return lookupCanonical(name); }
function findCanonicalIngredientFuzzy(name) { return lookupCanonical(name); }
function getCategoryFallbackPrice(category) {
  return CATEGORY_FLOORS[category] ?? CATEGORY_FLOORS.default ?? 0.25;
}
function getRegionMultiplier(region = 'US', storeType = 'standard') {
  const base = getCountryMultiplier(region);
  const storeAdj = storeType === 'premium' ? 1.15 : storeType === 'budget' ? 0.90 : 1.0;
  return base * storeAdj;
}

