  strip: 20,
  strips: 20,
  can: 400,  // fallback can size
  cans: 400,
  jar: 300,  // fallback jar
  jars: 300,
  bunch: 200,
  bunches: 200,
  stalk: 100,
  stalks: 100,
  fillet: 150,
  fillets: 150,
  breast: 180,
  breasts: 180,
  thigh: 150,
  thighs: 150,
  leaf: 2,
  leaves: 2,
};

/**
 * Parse amount string into normalized form.
 * Returns { value, unit, unit_type } where unit_type = 'weight' | 'volume' | 'piece' | 'unknown'
 */
function parseAmount(amountStr) {
  if (!amountStr) return null;

  const s = String(amountStr).toLowerCase().trim();

  // Extract leading numeric part (handles fractions like "1/2", "2 1/3")
  const numMatch = s.match(/^([\d.]+(?:\s*\/\s*\d+)?|\d+\s+\d+\s*\/\s*\d+)/);
  if (!numMatch) return null;

  // Parse fractions
  function parseFraction(frac) {
    const simpleFrac = frac.match(/^(\d+)\s*\/\s*(\d+)$/);
    if (simpleFrac) {
      return parseFloat(simpleFrac[1]) / parseFloat(simpleFrac[2]);
    }
    const mixedFrac = frac.match(/^(\d+)\s+(\d+)\s*\/\s*(\d+)$/);
    if (mixedFrac) {
      return parseFloat(mixedFrac[1]) + (parseFloat(mixedFrac[2]) / parseFloat(mixedFrac[3]));
    }
    return parseFloat(frac);
  }

  const value = parseFraction(numMatch[1].replace(/\s+/g, ''));
  if (isNaN(value) || value <= 0) return null;

  const restStr = s.slice(numMatch[0].length).trim();

  // Try weight units
  for (const [unit, factor] of Object.entries(WEIGHT_CONVERSIONS)) {
    if (restStr.startsWith(unit)) {
      return { value, unit, unit_type: 'weight', normalized_grams: value * factor };
    }
  }

  // Try volume units
  for (const [unit, factor] of Object.entries(VOLUME_CONVERSIONS)) {
    if (restStr.startsWith(unit)) {
      return { value, unit, unit_type: 'volume', normalized_ml: value * factor };
    }
  }

  // Try piece units
  for (const [unit, weight] of Object.entries(PIECE_WEIGHT_DEFAULTS)) {
    if (restStr.startsWith(unit)) {
      return { value, unit, unit_type: 'piece', piece_count: value, piece_weight_g: weight };
    }
  }

  // Bare number — default to piece
  return { value, unit: 'piece', unit_type: 'piece', piece_count: value, piece_weight_g: 15 };
}

/**
 * Get edible grams from parsed amount + canonical ingredient.
 * Applies yield ratio (e.g., 0.84 for corn = 16% water/waste loss).
 */
function getEditableGrams(parsed, canonical) {
  if (!parsed) return null;

  let grams = null;

  if (parsed.unit_type === 'weight') {
    grams = parsed.normalized_grams;
  } else if (parsed.unit_type === 'volume') {
    // Approximate: assume density close to water (1g/ml) for vegetables, oils different
    if (canonical.category === 'oils') {
      grams = parsed.normalized_ml * 0.92;  // slightly less dense
    } else {
      grams = parsed.normalized_ml * 0.95;  // close to water
    }
  } else if (parsed.unit_type === 'piece') {
    grams = parsed.piece_count * parsed.piece_weight_g;
  }

  if (grams && grams > 0) {
    // Apply edible_ratio (accounts for waste/inedible parts)
    return grams * (canonical.edible_ratio || 1.0);
  }

  return null;
}

/**
 * Calculate ingredient cost with confidence.
 * 
 * @param {string} ingredientName
 * @param {string} amountStr
 * @param {string} region - 2-letter country code (default: US)
 * @param {string} storeType - "premium", "standard", "budget" (default: standard)
 * @returns {object} {
 *   cost: number (USD),
 *   grams: number,
 *   confidence: "exact" | "mapped" | "category_estimated" | "fallback_estimated",
 *   ingredient_canonical: string,
 *   region_adjusted: boolean,
 *   notes: string
 * }
 */
export function calculateIngredientCost(
  ingredientName,
  amountStr,
  region = 'US',
  storeType = 'standard'
) {
  if (!ingredientName || !amountStr) {
    return { cost: null, confidence: 'unknown', notes: 'Missing ingredient or amount' };
  }

  // Step 1: Parse amount
  const parsed = parseAmount(amountStr);
  if (!parsed) {
    return { cost: null, confidence: 'unknown', notes: `Could not parse amount: "${amountStr}"` };
  }

  // Step 2: Find canonical ingredient
  let canonical = findCanonicalIngredient(ingredientName);
  let confidence = 'exact';

  if (!canonical) {
    canonical = findCanonicalIngredientFuzzy(ingredientName);
    confidence = 'mapped';
  }

  // If still not found, use category fallback
  if (!canonical) {
    const fallbackPrice = getCategoryFallbackPrice('misc');
    const grams = parsed.normalized_grams || parsed.normalized_ml || (parsed.piece_count * 15);
    const regionMult = getRegionMultiplier(region, storeType);
    const cost = (grams / 100) * fallbackPrice * regionMult;

    return {
      cost: parseFloat(cost.toFixed(3)),
      grams,
      confidence: 'fallback_estimated',
      ingredient_canonical: null,
      region_adjusted: true,
      notes: `Unknown ingredient "${ingredientName}" — used conservative fallback`,
    };
  }

  // Step 3: Get edible grams (with yield ratio)
  const editableGrams = getEditableGrams(parsed, canonical);
  if (!editableGrams || editableGrams <= 0) {
    return {
      cost: null,
      confidence: 'unknown',
      notes: `Could not determine edible weight from "${amountStr}"`,
    };
  }

  // Step 4: Calculate base cost — use price_per_100g (canonical DB field name)
  const basePrice = canonical.price_per_100g ?? canonical.price_per_100ml ?? 0;
  if (!basePrice) {
    return { cost: null, confidence: 'unknown', notes: `No price data for "${canonical.name}"` };
  }
  const regionMult = getRegionMultiplier(region, storeType);
  const adjustedPrice = basePrice * regionMult;
  const cost = (editableGrams / 100) * adjustedPrice;

  return {
    cost: parseFloat(cost.toFixed(3)),
    grams: parseFloat(editableGrams.toFixed(1)),
    confidence: confidence === 'exact' ? 'exact' : 'mapped',
    ingredient_canonical: canonical.name,
    ingredient_name: canonical.name,
    region_adjusted: region !== 'US' || storeType !== 'standard',
    region_multiplier: regionMult,
    base_price_100g: basePrice,
    adjusted_price_100g: adjustedPrice,
    yield_ratio: canonical.edible_ratio ?? 1.0,
    notes: `${canonical.name} (${editableGrams.toFixed(0)}g)`,
  };
}

/**
 * Price all ingredients in a recipe.
 * 
 * @param {object} recipe - { ingredients: [{ group, items: [{ name, amount }] }] }
 * @param {string} region - country code
 * @param {string} storeType - store type
 * @returns {object} recipe with pricing data + summary
 */
export function priceRecipeGlobal(recipe, region = 'US', storeType = 'standard') {
  if (!recipe?.ingredients?.length) {
    return { ...recipe, total_cost: null, cost_per_serving: null };
  }

  let totalCost = 0;
  let pricedCount = 0;
  let missingCount = 0;

  const pricedIngredients = recipe.ingredients.map(group => ({
    ...group,
    items: (group.items || []).map(item => {
      if (!item?.name || !item?.amount) return item;

      const pricing = calculateIngredientCost(item.name, item.amount, region, storeType);

      if (pricing.cost != null && pricing.cost > 0) {
        totalCost += pricing.cost;
        pricedCount++;
      } else {
        missingCount++;
      }

      return {
        ...item,
        ingredient_cost: pricing.cost,
        _pricing_detail: pricing,
      };
    }),
  }));

  const servings = recipe.servings || 1;
  const hasPricing = pricedCount > 0;

  return {
    ...recipe,
    ingredients: pricedIngredients,
    total_cost: hasPricing ? parseFloat(totalCost.toFixed(2)) : null,
    cost_per_serving: hasPricing && servings > 0
      ? parseFloat((totalCost / servings).toFixed(2))
      : null,
    pricing_summary: {
      priced_ingredients: pricedCount,
      missing_ingredients: missingCount,
      region,
      store_type: storeType,
      region_multiplier: getRegionMultiplier(region, storeType),
    },
  };
}

