/**
 * RecipeVariationTracker — Maintains session-based recipe pattern history
 * to avoid repeating the same recipe structure twice.
 * 
 * Tracks:
 * - Recipe archetypes (skillet, baked tray, stir fry, pasta, etc.)
 * - Ingredient combination patterns
 * - Cooking technique sequences
 * 
 * Used by AI to diversify recipes even with the same pantry items.
 */

const RECIPE_ARCHETYPES = [
  'skillet_meal',
  'baked_tray',
  'stir_fry',
  'pasta',
  'pizza',
  'grain_bowl',
  'salad_bowl',
  'wraps',
  'casserole',
  'soup',
  'stew',
  'roasted_medley',
  'fried_dish',
  'grilled_dish',
  'steamed_dish',
];

export class RecipeVariationTracker {
  constructor() {
    // Session-based history: [{ archetype, ingredientPattern, techniques }, ...]
    this.history = [];
    this.maxHistorySize = 5; // Keep last 5 generated recipes
  }

  /**
   * Analyze a generated recipe and extract its pattern
   */
  analyzeRecipe(recipe) {
    const pattern = {
      archetype: this.detectArchetype(recipe),
      ingredientPattern: this.extractIngredientPattern(recipe),
      techniques: this.extractTechniques(recipe),
      timestamp: Date.now(),
    };
    return pattern;
  }

  /**
   * Record a generated recipe in history
   */
  recordRecipe(recipe) {
    const pattern = this.analyzeRecipe(recipe);
    this.history.push(pattern);
    // Keep only recent history
    if (this.history.length > this.maxHistorySize) {
      this.history.shift();
    }
    return pattern;
  }

  /**
   * Get recipes that are DIFFERENT from the session history
   * Used to suggest archetype diversity
   */
  getUnusedArchetypes() {
    const used = new Set(this.history.map(h => h.archetype).filter(Boolean));
    return RECIPE_ARCHETYPES.filter(a => !used.has(a));
  }

  /**
   * Detect likely archetype based on recipe structure
   */
  detectArchetype(recipe) {
    const title = (recipe.title || '').toLowerCase();
    const ingredients = recipe.ingredients || [];
    const steps = recipe.steps || [];

    // Check title for keywords
    const keywords = {
      skillet_meal: ['skillet', 'pan', 'one-pan'],
      baked_tray: ['baked', 'tray', 'sheet', 'roasted'],
      stir_fry: ['stir-fry', 'stir fry', 'wok'],
      pasta: ['pasta', 'noodle', 'spaghetti', 'penne'],
      pizza: ['pizza', 'flatbread'],
      grain_bowl: ['bowl', 'grain', 'buddha'],
      salad_bowl: ['salad'],
      wraps: ['wrap', 'burrito', 'roll'],
      casserole: ['casserole', 'bake'],
      soup: ['soup', 'broth'],
      stew: ['stew', 'chili'],
      grilled_dish: ['grilled', 'grill'],
      fried_dish: ['fried', 'fry'],
    };

    for (const [archetype, words] of Object.entries(keywords)) {
      if (words.some(w => title.includes(w))) {
        return archetype;
      }
    }

    // Fallback: analyze cooking methods from instructions
    const instructionText = steps.map(s => (s.instruction || '').toLowerCase()).join(' ');
    if (instructionText.includes('bake') || instructionText.includes('oven')) return 'baked_tray';
    if (instructionText.includes('fry') || instructionText.includes('pan')) return 'skillet_meal';
    if (instructionText.includes('boil') || instructionText.includes('simmer')) return 'soup';
    if (instructionText.includes('grill')) return 'grilled_dish';

    return null;
  }

  /**
   * Extract ingredient combination pattern
   * (main protein + starch + veg types)
   */
  extractIngredientPattern(recipe) {
    const allItems = [];
    for (const group of recipe.ingredients || []) {
      for (const item of group.items || []) {
        if (!item.optional) allItems.push((item.name || '').toLowerCase());
      }
    }

    const pattern = {
      proteins: allItems.filter(i => this.isProtein(i)),
      starches: allItems.filter(i => this.isStarch(i)),
      vegetables: allItems.filter(i => this.isVegetable(i)),
      combined: allItems.join('|'), // Full hash for comparison
    };

    return pattern;
  }

  /**
   * Extract cooking techniques from instructions
   */
  extractTechniques(recipe) {
    const techniques = new Set();
    const methods = ['fry', 'bake', 'grill', 'steam', 'simmer', 'boil', 'roast', 'sauté', 'pan'];

    const instructionText = (recipe.steps || [])
      .map(s => (s.instruction || '').toLowerCase())
      .join(' ');

    methods.forEach(m => {
      if (instructionText.includes(m)) techniques.add(m);
    });

    return Array.from(techniques);
  }

  /**
   * Helper: is this ingredient a protein source?
   */
  isProtein(name) {
    const proteins = ['chicken', 'beef', 'pork', 'fish', 'salmon', 'tuna', 'tofu', 'turkey', 'egg', 'shrimp', 'yogurt', 'cottage cheese'];
    return proteins.some(p => name.includes(p));
  }

  /**
   * Helper: is this ingredient a starch?
   */
  isStarch(name) {
    const starches = ['rice', 'pasta', 'noodle', 'bread', 'potato', 'corn', 'wheat', 'grain', 'oat', 'barley'];
    return starches.some(s => name.includes(s));
  }

  /**
   * Helper: is this ingredient a vegetable?
   */
  isVegetable(name) {
    const veggies = ['broccoli', 'carrot', 'spinach', 'kale', 'pepper', 'onion', 'tomato', 'zucchini', 'cucumber', 'lettuce', 'pea', 'bean', 'pumpkin'];
    return veggies.some(v => name.includes(v));
  }

  /**
   * Check if recipe is too similar to previous ones
   */
  isSimilarToPrevious(recipe, similarityThreshold = 0.6) {
    if (this.history.length === 0) return false;

    const current = this.analyzeRecipe(recipe);

    for (const prev of this.history) {
      // Same archetype is too similar
      if (prev.archetype && prev.archetype === current.archetype) {
        return true;
      }

      // Same ingredient combination is too similar
      if (prev.ingredientPattern?.combined === current.ingredientPattern?.combined) {
        return true;
      }

      // Same techniques used
      const sameTechniques = prev.techniques?.filter(t => current.techniques?.includes(t)) || [];
      if (sameTechniques.length === prev.techniques?.length) {
        return true;
      }
    }

    return false;
  }

  /**
   * Get a diversity prompt suggestion for the AI
   */
  getDiversityHint() {
    if (this.history.length === 0) return '';

    const lastRecipe = this.history[this.history.length - 1];
    const unused = this.getUnusedArchetypes();

    if (unused.length === 0) return '';

    const suggestion = unused[Math.floor(Math.random() * Math.min(3, unused.length))];
    const archetypeNames = {
      skillet_meal: 'skillet meal',
      baked_tray: 'baked tray meal',
      stir_fry: 'stir-fry',
      pasta: 'pasta dish',
      pizza: 'pizza or flatbread',
      grain_bowl: 'grain bowl',
      salad_bowl: 'salad',
      wraps: 'wraps',
      casserole: 'casserole',
      soup: 'soup',
      stew: 'stew',
      grilled_dish: 'grilled dish',
      fried_dish: 'fried dish',
    };

    return archetypeNames[suggestion] || suggestion;
  }

  /**
   * Clear history (e.g., on new session)
   */
  reset() {
    this.history = [];
  }
}

// Singleton instance for the app
let trackerInstance = null;

export function getRecipeVariationTracker() {
  if (!trackerInstance) {
    trackerInstance = new RecipeVariationTracker();
  }
  return trackerInstance;
}

export function resetRecipeVariationTracker() {
  trackerInstance = null;
}

