function fmtServings(n) {
  if (n === 0.5)  return "½";
  if (n === 0.75) return "¾";
  if (n === 1.5)  return "1½";
  if (n === 2.5)  return "2½";
  if (Number.isInteger(n)) return String(n);
  return String(Math.round(n * 100) / 100);
}

const QUICK_PICKS = [0.5, 1, 1.5, 2, 3, 4];

export default function ServingsSelectorSheet({ isOpen, onClose, value, defaultServings, onChange }) {
  const [pending, setPending] = useState(value);
  const [showCustom, setShowCustom] = useState(false);
  const [customInput, setCustomInput] = useState("");
  const { resolvedLang } = useLocalization();
  const lt = getServingsSheetText(resolvedLang);

  // Sync pending when sheet opens
  React.useEffect(() => {
    if (isOpen) {
      setPending(value);
      setShowCustom(false);
      setCustomInput(String(value));
    }
  }, [isOpen, value]);

  const clamp = (n) => Math.min(20, Math.max(0.25, Math.round(n * 4) / 4));

  const applyCustom = () => {
    const n = parseFloat(customInput);
    if (!isNaN(n) && n > 0) setPending(clamp(n));
  };

  // Hide bottom nav when sheet is open — use canonical reference-counted lock manager
  useBottomNavLock(isOpen);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />

      {/* Sheet */}
      <div className="relative w-full max-w-lg bg-white rounded-t-3xl px-5 pt-4 pb-8 shadow-2xl"
        style={{ animation: "slideUp 0.22s ease-out" }}>
        <style>{`
          @keyframes slideUp {
            from { transform: translateY(100%); opacity: 0; }
            to   { transform: translateY(0);    opacity: 1; }
          }
        `}</style>

        {/* Handle */}
        <div className="w-10 h-1 bg-slate-200 rounded-full mx-auto mb-4" />

        <div className="flex items-center justify-between mb-1">
          <p className="text-sm font-bold text-slate-800">{lt.title}</p>
          <button onClick={onClose} className="w-7 h-7 rounded-full bg-slate-100 flex items-center justify-center">
            <X className="w-3.5 h-3.5 text-slate-500" />
          </button>
        </div>
        <p className="text-xs text-slate-400 mb-4">
          {lt.recipeMakes} {defaultServings} · {lt.currently}: {fmtServings(pending)}
          {Math.abs(pending - defaultServings) > 0.01 && (
            <span className="ml-1 text-indigo-500 font-medium">({lt.adjusted})</span>
          )}
        </p>

        {/* Quick picks */}
        <div className="grid grid-cols-3 gap-2 mb-3">
          {QUICK_PICKS.map(q => (
            <button
              key={q}
              onClick={() => { setPending(q); setShowCustom(false); }}
              className={cn(
                "h-11 rounded-xl text-sm font-semibold border transition-all",
                Math.abs(q - pending) < 0.01 && !showCustom
                  ? "bg-indigo-600 text-white border-indigo-600 shadow-sm"
                  : "bg-slate-50 text-slate-700 border-slate-200 hover:border-slate-300"
              )}
            >
              {fmtServings(q)}
            </button>
          ))}
        </div>

        {/* Custom */}
        <button
          onClick={() => { setShowCustom(v => !v); setCustomInput(String(pending)); }}
          className={cn(
            "w-full h-10 rounded-xl text-sm font-semibold border transition-all mb-3",
            showCustom ? "bg-slate-900 text-white border-slate-900" : "bg-slate-50 text-slate-600 border-slate-200"
          )}
        >
          {showCustom ? `${lt.custom} ▲` : `${lt.custom}…`}
        </button>

        {showCustom && (
          <div className="flex items-center gap-2 mb-4">
            <button
              onClick={() => { const v = clamp(pending - 0.25); setPending(v); setCustomInput(String(v)); }}
              className="w-10 h-10 rounded-xl border border-slate-200 bg-white flex items-center justify-center font-bold text-lg text-slate-700 flex-shrink-0"
            >−</button>
            <input
              type="number"
              min="0.25"
              max="20"
              step="0.25"
              value={customInput}
              onChange={e => setCustomInput(e.target.value)}
              onBlur={applyCustom}
              onKeyDown={e => e.key === "Enter" && applyCustom()}
              className="flex-1 h-10 rounded-xl border border-slate-200 bg-white text-center text-sm font-bold text-slate-900 focus:border-indigo-400 focus:outline-none min-w-0"
            />
            <button
              onClick={() => { const v = clamp(pending + 0.25); setPending(v); setCustomInput(String(v)); }}
              className="w-10 h-10 rounded-xl border border-slate-200 bg-white flex items-center justify-center font-bold text-lg text-slate-700 flex-shrink-0"
            >+</button>
          </div>
        )}

        {/* Apply / Cancel */}
        <div className="flex gap-3">
          <button
            onClick={onClose}
            className="flex-1 h-11 rounded-2xl border border-slate-200 text-sm font-semibold text-slate-600"
          >
            {lt.cancel}
          </button>
          <button
            onClick={() => onChange(pending)}
            className="flex-2 flex-grow h-11 rounded-2xl bg-indigo-600 text-white text-sm font-bold shadow-sm"
          >
            {lt.apply}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useCallback } from 'react';
import { base44 } from '@/api/base44Client';

/**
 * Hook to send like notification ONLY when user currently has recipe liked.
 * Prevents stale notifications (liked then unliked).
 */
export function useLikeNotification() {
  const sendLikeNotification = useCallback(async (recipeId, recipeAuthorId, liked) => {
    // Only send notification if user currently has it liked
    if (!liked || !recipeAuthorId) {
      return;
    }

    try {
      const response = await base44.functions.invoke('sendRecipeLikeNotification', {
        recipeId,
        recipientId: recipeAuthorId,
      });

      if (!response.data?.sent) {
        console.warn('Notification was not sent (user may have unliked)');
      }
    } catch (error) {
      console.warn('Failed to send like notification:', error);
      // Don't throw — notification failure shouldn't break like functionality
    }
  }, []);

  return { sendLikeNotification };
}

