const CUISINE_EMOJI = {
  italian:"🍕", japanese:"🍣", mexican:"🌮", indian:"🍛",
  thai:"🥘", american:"🍔", french:"🥐", mediterranean:"🫒",
  korean:"🍜", asian:"🍜", middle_eastern:"🧆", other:"🍽️",
};

function getNutrition(recipe) {
  const n = recipe.nutrition_per_serving;
  if (n?.calories > 0) return n;
  const t = recipe.nutrition_total_for_recipe;
  const s = recipe.servings || 1;
  if (t?.calories > 0) return { calories: Math.round(t.calories / s), protein: Math.round((t.protein || 0) / s) };
  return recipe.nutrition?.calories > 0 ? recipe.nutrition : null;
}

function fmt(v) {
  if (!v || v <= 0) return null;
  return v < 1 ? `${Math.round(v * 100)}¢` : `$${v.toFixed(2)}`;
}

function countIngredients(groups) {
  if (!groups?.length) return 0;
  return groups.reduce((sum, g) => sum + (g.items?.length || 0), 0);
}

