import React, { useState, useRef, useEffect } from "react";

const FALLBACK_IMAGE = "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=800&h=600&fit=crop";

/**
 * RecipeHeroImage — single source of truth for recipe hero image rendering.
 * 
 * Retry logic: if the image fails to load on first attempt, retries once after 1.5s
 * before falling back to the default image. This handles CDN cold-start / timing issues
 * that cause false-positive fallbacks on AI-generated images.
 * 
 * CRITICAL: If the parent re-renders with a new `src` (e.g. recipe data loads late),
 * we must update currentSrc to reflect the new prop. Without this, a component
 * initialized with undefined src would stay on fallback forever.
 */
export default function RecipeHeroImage({ src, alt, className = "w-full h-full object-cover", style }) {
  const [currentSrc, setCurrentSrc] = useState(src || FALLBACK_IMAGE);
  const retriedRef = useRef(false);
  const prevSrcRef = useRef(src);

  // Sync currentSrc when the src prop changes (parent loads new data)
  useEffect(() => {
    if (src && src !== prevSrcRef.current) {
      prevSrcRef.current = src;
      retriedRef.current = false;
      setCurrentSrc(src);
    }
  }, [src]);

  const handleError = () => {
    // If we already retried, or this IS the fallback, give up
    if (retriedRef.current || !src || currentSrc === FALLBACK_IMAGE) {
      setCurrentSrc(FALLBACK_IMAGE);
      return;
    }
    // First failure: retry after a short delay (CDN cold start)
    retriedRef.current = true;
    setTimeout(() => {
      // Append cache-buster to force a fresh request
      const separator = src.includes("?") ? "&" : "?";
      setCurrentSrc(src + separator + "_retry=1");
    }, 1500);
  };

  return (
    <img
      src={currentSrc}
      alt={alt || "Recipe"}
      className={className}
      style={{ WebkitTouchCallout: "none", ...style }}
      draggable={false}
      referrerPolicy="no-referrer"
      onError={handleError}
    />
  );
}

