/**
 * AUTHORITATIVE duration formatter for the entire app.
 * Every surface that displays prep/cook/total time MUST use this.
 *
 * Returns structured segments for BiDi-safe rendering.
 * Use formatDurationSegments() for JSX rendering via <DurationDisplay>.
 * Use formatDuration() for plain-string contexts (always LTR-safe).
 */
import React from "react";

/**
 * formatDurationSegments — returns an array of {value, label} segments.
 * Each segment represents one "number + unit" pair.
 * Callers render each segment in its own isolated LTR span.
 */
export function formatDurationSegments(totalMinutes, t) {
  if (!totalMinutes || totalMinutes <= 0) return [];

  const mins = Math.round(totalMinutes);
  const hLabel = t('time.hour_short', 'h');
  const mLabel = t('time.min_short', 'min');

  if (mins < 60) {
    return [{ value: mins, label: mLabel }];
  }

  const hours = Math.floor(mins / 60);
  const remainingMins = mins % 60;

  if (remainingMins === 0) {
    return [{ value: hours, label: hLabel }];
  }

  return [
    { value: hours, label: hLabel },
    { value: remainingMins, label: mLabel },
  ];
}

/**
 * DurationDisplay — BiDi-safe JSX component.
 * Renders each number+label pair in its own dir="ltr" isolated span,
 * preventing RTL reordering of digits and translated labels.
 */
export function DurationDisplay({ minutes, t, className, style }) {
  const segments = formatDurationSegments(minutes, t);
  if (segments.length === 0) return null;

  return (
    <span dir="ltr" style={{ unicodeBidi: 'isolate', display: 'inline-flex', alignItems: 'center', gap: 3, ...style }} className={className}>
      {segments.map((seg, i) => (
        <span key={i} dir="ltr" style={{ unicodeBidi: 'isolate', whiteSpace: 'nowrap' }}>
          {seg.value}&nbsp;{seg.label}
        </span>
      ))}
    </span>
  );
}

/**
 * formatDuration — plain string fallback for non-JSX contexts.
 * Uses Unicode isolate characters to prevent BiDi reordering.
 */
export function formatDuration(totalMinutes, t) {
  if (!totalMinutes || totalMinutes <= 0) return '';

  const mins = Math.round(totalMinutes);
  const hLabel = t('time.hour_short', 'h');
  const mLabel = t('time.min_short', 'min');

  // U+2066 = Left-to-Right Isolate, U+2069 = Pop Directional Isolate
  // These are stronger than LRM and create true BiDi isolation boundaries.
  const LRI = '\u2066';
  const PDI = '\u2069';

  if (mins < 60) {
    return `${LRI}${mins}\u00A0${mLabel}${PDI}`;
  }

  const hours = Math.floor(mins / 60);
  const remainingMins = mins % 60;

  if (remainingMins === 0) {
    return `${LRI}${hours}\u00A0${hLabel}${PDI}`;
  }

  return `${LRI}${hours}\u00A0${hLabel}${PDI} ${LRI}${remainingMins}\u00A0${mLabel}${PDI}`;
}

// Legacy alias
export const formatTimeCompact = formatDuration;

import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { UserPlus, UserCheck, Loader2 } from "lucide-react";
import { base44 } from "@/api/base44Client";
import { cn } from "@/lib/utils";

/**
 * Premium follow button for recipe detail pages.
 * Hides for self-authored recipes and service accounts.
 * Backend-authoritative — checks follow state on mount.
 */
export default function RecipeAuthorFollowButton({ authorId, authorName }) {
  const [followState, setFollowState] = useState("unknown"); // unknown | not_following | following | requested
  const [loading, setLoading] = useState(true);
  const [inFlight, setInFlight] = useState(false);
  const [currentUserId, setCurrentUserId] = useState(null);
  const [burst, setBurst] = useState(false);

  // Don't render for service accounts
  const isServiceAuthor = !authorId || authorId.startsWith("service_") || authorId.startsWith("service+");

  useEffect(() => {
    if (isServiceAuthor) { setLoading(false); return; }
    let cancelled = false;

    const init = async () => {
      try {
        const me = await base44.auth.me();
        if (cancelled) return;
        if (!me?.id) { setLoading(false); return; }
        setCurrentUserId(me.id);

        // Hide for own recipe
        if (me.id === authorId) { setLoading(false); return; }

        // Check follow state
        const follows = await base44.entities.Follow.filter({
          follower_id: me.id,
          followed_id: authorId,
        }).catch(() => []);

        if (cancelled) return;
        if (follows.length === 0) {
          setFollowState("not_following");
        } else if (follows[0].status === "requested") {
          setFollowState("requested");
        } else {
          setFollowState("following");
        }
      } catch {
        setFollowState("not_following");
      } finally {
        if (!cancelled) setLoading(false);
      }
    };

    init();
    return () => { cancelled = true; };
  }, [authorId]);

  const handlePress = async () => {
    if (inFlight || !currentUserId || currentUserId === authorId) return;
    setInFlight(true);

    if (followState === "not_following") {
      // Optimistic
      setFollowState("following");
      setBurst(true);
      setTimeout(() => setBurst(false), 600);
      try {
        await base44.functions.invoke("toggleFollowState", {
          target_user_id: authorId,
        });
      } catch {
        setFollowState("not_following");
      }
    } else if (followState === "following" || followState === "requested") {
      setFollowState("not_following");
      try {
        await base44.functions.invoke("toggleFollowState", {
          target_user_id: authorId,
        });
      } catch {
        setFollowState("following");
      }
    }

    setInFlight(false);
  };

  // Don't render during loading, for service accounts, or when self
  if (isServiceAuthor || loading) return null;
  if (!currentUserId || currentUserId === authorId) return null;
  if (followState === "unknown") return null;

  const isFollowing = followState === "following" || followState === "requested";

  return (
    <div className="relative">
      <AnimatePresence>
        {burst && (
          <motion.div
            key="burst"
            initial={{ scale: 0.5, opacity: 0.8 }}
            animate={{ scale: 2.5, opacity: 0 }}
            exit={{}}
            transition={{ duration: 0.5 }}
            className="absolute inset-0 rounded-full pointer-events-none"
            style={{ background: "radial-gradient(circle, rgba(99,102,241,0.35) 0%, transparent 70%)" }}
          />
        )}
      </AnimatePresence>

      <motion.button
        onClick={handlePress}
        disabled={inFlight}
        whileTap={{ scale: 0.93 }}
        className={cn(
          "relative flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold transition-all overflow-hidden",
          "disabled:opacity-60"
        )}
        style={isFollowing ? {
          background: "rgba(99,102,241,0.08)",
          border: "1.5px solid rgba(99,102,241,0.25)",
          color: "#6366f1",
        } : {
          background: "linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)",
          boxShadow: "0 3px 12px rgba(99,102,241,0.4), inset 0 1px 0 rgba(255,255,255,0.2)",
          color: "#fff",
          border: "1.5px solid transparent",
        }}
      >
        {/* Shimmer on follow state */}
        {!isFollowing && (
          <motion.div
            className="absolute inset-0 pointer-events-none"
            style={{
              background: "linear-gradient(105deg, transparent 40%, rgba(255,255,255,0.22) 50%, transparent 60%)",
              backgroundSize: "200% 100%",
            }}
            animate={{ backgroundPosition: ["-100% center", "200% center"] }}
            transition={{ duration: 2.5, repeat: Infinity, ease: "linear", repeatDelay: 1.5 }}
          />
        )}

        <AnimatePresence mode="wait">
          {inFlight ? (
            <motion.span key="loading" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
              <Loader2 className="w-3 h-3 animate-spin" />
            </motion.span>
          ) : isFollowing ? (
            <motion.span key="following" initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0 }} className="flex items-center gap-1">
              <UserCheck className="w-3 h-3" />
              <span>{followState === "requested" ? "Requested" : "Following"}</span>
            </motion.span>
          ) : (
            <motion.span key="follow" initial={{ opacity: 0, scale: 0.8 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0 }} className="flex items-center gap-1">
              <UserPlus className="w-3 h-3" />
              <span>Follow</span>
            </motion.span>
          )}
        </AnimatePresence>
      </motion.button>
    </div>
  );
}

import React from "react";
