const STEP_COLORS = [
  { bg: "from-blue-50 to-indigo-50", border: "border-l-blue-500", number: "bg-blue-500" },
  { bg: "from-purple-50 to-pink-50", border: "border-l-purple-500", number: "bg-purple-500" },
  { bg: "from-orange-50 to-amber-50", border: "border-l-orange-500", number: "bg-orange-500" },
  { bg: "from-green-50 to-emerald-50", border: "border-l-green-500", number: "bg-green-500" },
