/**
 * AutoFitText — Pure CSS approach to fitting ingredient names.
 * 
 * Uses character-length-based font sizing (instant, no layout thrashing)
 * combined with CSS that guarantees full visibility (no ellipsis, no clipping).
 *
 * This avoids the useLayoutEffect + ResizeObserver + binary-search approach
 * which fails when flex containers don't constrain intrinsic width properly.
 */
import React from "react";

const MAX_FONT = 13;
const MIN_FONT = 9;

/**
 * Compute font size from text length.
 * Tuned for ~100-130px available width on 375px mobile screens.
 * Longer names get progressively smaller to avoid excessive wrapping.
 */
function computeFontSize(text) {
  const len = text.length;
  if (len <= 18) return MAX_FONT;   // short — full size
  if (len <= 25) return 12.5;
  if (len <= 32) return 12;
  if (len <= 40) return 11.5;
  if (len <= 50) return 11;
  if (len <= 60) return 10.5;
  if (len <= 75) return 10;
  return MIN_FONT;                   // very long — minimum readable
}

export default function AutoFitText({ text, className, style }) {
  const fontSize = computeFontSize(text || '');

  return (
    <span
      className={className}
      style={{
        fontSize,
        lineHeight: 1.35,
        overflowWrap: "break-word",
        wordBreak: "break-word",
        display: "block",
        // CRITICAL: no overflow:hidden, no line-clamp, no text-overflow
        // Text is always fully visible
        ...style,
      }}
    >
      {text}
    </span>
  );
}

