/**
 * InsufficientIngredientsModal
 *
 * Shown when simulatePantryDeduction finds problematic ingredients.
 * Works for both RecipeDetail and Generate flows.
 *
 * Props:
 *   isOpen: boolean
 *   problematicItems: array of predicted_deduction objects from simulatePantryDeduction
 *   onContinue(skippedIds): proceed with logging, passing set of pantry_item_ids to skip
 *   onCancel(): abort meal logging entirely
 *   onEditIngredient(pantryItemId): navigate to Pantry edit for that item
 */
import React, { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { AlertTriangle, X, Pencil, Check } from "lucide-react";
import { cn } from "@/lib/utils";
