export default function InsufficientIngredientsModal({
  isOpen,
  problematicItems = [],
  onContinue,
  onCancel,
  onEditIngredient,
}) {
  // Track which pantry_item_ids the user chose to skip (default: all skipped)
  const [skippedIds, setSkippedIds] = useState(() => {
    return new Set(problematicItems.map(i => i.pantry_item_id).filter(Boolean));
  });

  // Re-sync when items change (modal re-opens)
  useEffect(() => {
    if (isOpen) {
      setSkippedIds(new Set(problematicItems.map(i => i.pantry_item_id).filter(Boolean)));
    }
  }, [isOpen, problematicItems]);

  const { t, resolvedLang } = useLocalization();
  const STATUS_LABELS = {
    insufficient: t('pantry.not_enough','Not enough'),
    empty_pantry: t('pantry.out_of_stock','Out of stock'),
    not_found: t('pantry.not_in_pantry','Not in pantry'),
