  // Hide bottom nav while modal is open — canonical reference-counted lock manager
  useBottomNavLock(isOpen);

  if (!isOpen) return null;

  const toggleSkip = (id) => {
    if (!id) return;
    const next = new Set(skippedIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSkippedIds(next);
