            initial={{ y: "100%", opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: "100%", opacity: 0 }}
            transition={{ type: "spring", damping: 30, stiffness: 300 }}
            onClick={(e) => e.stopPropagation()}
            className="relative bg-white rounded-t-3xl sm:rounded-3xl shadow-2xl w-full sm:max-w-sm max-h-[90vh] flex flex-col z-10"
            style={{ paddingBottom: 'env(safe-area-inset-bottom, 0px)' }}
          >
            {/* Header */}
            <div className="flex items-start gap-3 p-5 border-b border-slate-100">
              <div className="w-10 h-10 rounded-2xl bg-amber-50 flex items-center justify-center flex-shrink-0 mt-0.5">
                <AlertTriangle className="w-5 h-5 text-amber-500" />
              </div>
              <div className="flex-1 min-w-0">
                <h3 className="text-base font-bold text-slate-900">{t('pantry.low_stock','Low pantry stock')}</h3>
                <p className="text-xs text-slate-500 mt-0.5">
                  {problematicItems.length} {problematicItems.length !== 1 ? t('pantry.ingredients','ingredients') : t('pantry.ingredient','ingredient')} {t('pantry.may_not_deduct','may not deduct correctly.')} {t('pantry.uncheck_skip','Uncheck to skip deducting specific items.')}
                </p>
