                          {statusLabel}
                        </span>
                        {item.required_amount != null && (
                          <span className="text-[10px] text-slate-500">
                            {t('pantry.need','Need')} {item.required_amount} {item.unit}
                          </span>
                        )}
                        {item.available_amount != null && item.available_amount > 0 && (
                          <span className="text-[10px] text-slate-400">
                            · {t('pantry.have','Have')} {item.available_amount} {item.unit}
