            <div className="px-4 pb-2">
              <p className="text-[11px] text-slate-400 text-center">
                {t('pantry.checked_deducted','Checked items will be deducted from pantry. Unchecked items will be skipped.')}
              </p>
            </div>

            {/* Actions */}
            <div className="p-4 border-t border-slate-100 flex gap-3">
              <button
                onClick={onCancel}
                className="flex-1 h-11 rounded-2xl border-2 border-slate-200 bg-white text-slate-700 font-semibold text-sm"
              >
                {t('action.cancel','Cancel')}
              </button>
              <button
                onClick={handleContinue}
                className="flex-2 flex-grow h-11 rounded-2xl text-white text-sm font-bold"
                style={{ background: "linear-gradient(135deg, #10b981 0%, #059669 100%)" }}
              >
                {t('meal.log_meal_btn','Log Meal')}
              </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

/**
 * RecipePhaseGrouper — Groups recipe steps into logical phases
 * Detects dough/sauce phases and suggests complementary ingredients
 */

/**
 * detectDishPhases — Analyze recipe and group steps into preparation phases
 */
export function detectDishPhases(recipe) {
  if (!recipe?.steps || recipe.steps.length === 0) {
    return [{ phase: 'Preparation', steps: recipe?.steps || [], suggestedIngredients: [] }];
  }

  const steps = recipe.steps;
  const phases = [];
  let currentPhase = null;
  let phaseSteps = [];

  const keywords = {
    dough: ['dough', 'knead', 'mix flour', 'yeast', 'rise', 'proof'],
    sauce: ['sauce', 'reduce', 'simmer', 'blend', 'puree'],
    prep: ['chop', 'dice', 'slice', 'mince', 'prepare', 'peel'],
    cook: ['cook', 'fry', 'bake', 'grill', 'roast', 'broil', 'pan-fry'],
    assemble: ['assemble', 'layer', 'place', 'spread', 'top', 'arrange', 'fill'],
    finish: ['garnish', 'season', 'taste', 'serve', 'plate'],
  };

  const detectPhaseType = (text) => {
    if (!text) return 'other';
    const lower = text.toLowerCase();
    for (const [phase, words] of Object.entries(keywords)) {
      if (words.some(w => lower.includes(w))) return phase;
    }
    return 'other';
  };

  const extractIngredientsFromPhase = (stepTexts) => {
    // Extract ingredient mentions from step instructions
    const ingredientPattern = /(?:add|use|mix in|fold in|spread|top with|sprinkle|layer)\s+([a-z\s]+?)(?:\.|,|and|or|$)/gi;
    const ingredients = new Set();
    for (const text of stepTexts) {
      let match;
      while ((match = ingredientPattern.exec(text)) !== null) {
        const ing = match[1].trim().replace(/\d+\s*(?:cup|tbsp|tsp|g|ml|oz)/gi, '').trim();
        if (ing && ing.length > 2) ingredients.add(ing);
      }
    }
    return Array.from(ingredients).slice(0, 3); // Limit to 3 suggestions
  };

  for (const step of steps) {
    const type = detectPhaseType(step.instruction);
    const phaseName =
      type === 'dough'
        ? 'Prepare Dough'
        : type === 'sauce'
          ? 'Make Sauce'
          : type === 'prep'
            ? 'Prep Ingredients'
            : type === 'cook'
              ? 'Cook'
              : type === 'assemble'
                ? 'Assemble'
                : type === 'finish'
                  ? 'Finish & Serve'
                  : 'Other';

    if (!currentPhase || currentPhase !== phaseName) {
      if (phaseSteps.length > 0) {
        phases.push({ 
          phase: currentPhase, 
          steps: phaseSteps,
          suggestedIngredients: extractIngredientsFromPhase(phaseSteps.map(s => s.instruction))
        });
      }
      currentPhase = phaseName;
      phaseSteps = [step];
    } else {
      phaseSteps.push(step);
    }
  }

  if (phaseSteps.length > 0) {
    phases.push({ 
      phase: currentPhase, 
      steps: phaseSteps,
      suggestedIngredients: extractIngredientsFromPhase(phaseSteps.map(s => s.instruction))
    });
  }

  return phases.length > 0
    ? phases
    : [{ phase: 'Preparation', steps: recipe.steps, suggestedIngredients: [] }];
}

