/**
 * PricingEngine — CLIENT-SIDE DISPLAY HELPERS ONLY
 *
 * NO cost computation happens here.
 * The backend (estimateRecipePricing function) is the single source of truth.
 *
 * These helpers only:
 *   - Format already-computed costs for display
 *   - Derive per-serving cost from stored total_cost when servings change
 *   - Determine what to show vs hide based on pricing_status / has_unknown_pricing
 */

/**
 * Format a cost number for display (DEPRECATED - use formatCostForDisplay from formatCostGlobal)
 * Kept for backward compat but should be removed.
 * Returns null (not "—") if cost is null/undefined/zero — let the caller decide what to render.
 * CRITICAL: cents display for <$1, dollars for ≥$1 (no redundant $0.XX format)
 */
export function formatCost(amount) {
  if (amount == null || amount <= 0) return null;
  // Under $1: display as cents (50¢ not $0.50)
  if (amount < 1) {
    const cents = Math.round(amount * 100);
    return cents > 0 ? `${cents}¢` : null;
  }
  // $1 and above: display as dollars
  return `$${amount.toFixed(2)}`;
}

/**
 * Given a stored recipe and a display servings count, derive scaled costs.
 * All math is proportional scaling of backend-computed values.
 *
 * Returns:
 *   {
 *     scaledTotal: number | null,
 *     scaledPerServing: number | null,
 *     pricingStatus: "known" | "partial" | "unknown",
 *     canShowTotal: boolean,
 *   }
 */
export function deriveDisplayCosts(recipe, displayServings) {
  if (!recipe) {
    return { scaledTotal: null, scaledPerServing: null, pricingStatus: 'unknown', canShowTotal: false };
  }

  const hasUnknown = recipe.has_unknown_pricing === true;
  const storedTotal = recipe.total_cost;
  const defaultServings = Math.max(1, recipe.servings || 1);
  const adjServings = Math.max(1, displayServings || defaultServings);

  // PARTIAL PRICING: If total_cost > 0, always show it — even if some ingredients are unpriced.
  // has_unknown_pricing just means some ingredients were skipped, not that total is invalid.
  // Only collapse pricing if there's truly no pricing data at all.
  if (storedTotal == null || storedTotal <= 0) {
    return { scaledTotal: null, scaledPerServing: null, pricingStatus: 'unknown', canShowTotal: false };
  }

  const scaleFactor = adjServings / defaultServings;
  const scaledTotal = storedTotal * scaleFactor;
  const scaledPerServing = scaledTotal / adjServings;

  return {
    // Do NOT round here — formatCostForDisplay needs the raw value to correctly decide ¢ vs $
    scaledTotal,
    scaledPerServing,
    // Mark as partial if some ingredients are unpriced, so UI can optionally show an indicator
    pricingStatus: hasUnknown ? 'partial' : 'known',
    canShowTotal: true, // Always show if total_cost > 0
  };
}

/**
 * Given an ingredient item and scale factor, compute the display cost.
 * Returns null if ingredient_cost is null/unknown — caller renders "—".
 */
export function getIngredientDisplayCost(item, scaleFactor = 1) {
  if (item == null) return null;
  const cost = item.ingredient_cost;
  if (cost == null) return null;
  // Do NOT round — formatCostForDisplay needs the raw value for correct ¢ display
  return cost * scaleFactor;
}

/**
 * Ingredient Normalizer
 * 
 * Converts ingredient strings with mixed units + grams into canonical format:
 * - base_grams: authoritative weight in grams
 * - display_unit: optional unit name (piece, cup, tbsp, etc)
 * - grams_per_unit: derived or looked-up conversion
 * 
 * Example: "2 pieces (about 300g) Chicken breast"
 * => base_grams: 300, display_unit: "piece", grams_per_unit: 150
 */

/**
 * CANONICAL UNIT CONVERSION TABLE
 * 
 * These are VOLUME/MEASUREMENT conversions only.
 * Do NOT use for generic "pieces" without explicit gram context.
 * 
 * Use only when ingredient amount lacks explicit grams.
 */
const UNIT_CONVERSIONS = {
  // Volume
  'cup': 240, 'cups': 240,
  'tbsp': 15, 'tablespoon': 15, 'tablespoons': 15,
  'tsp': 5, 'teaspoon': 5, 'teaspoons': 5,
  'ml': 1, 'l': 1000,

  // Weight
  'g': 1, 'kg': 1000,
  'oz': 28.35, 'lb': 453.6, 'lbs': 453.6,

  // Removed: generic 'piece' mapping
  // Reason: "1 piece chicken" ≠ "1 piece garlic" in grams
  // Solution: require explicit "(about XXXg)" or ingredient-specific mapping
};

/**
 * INGREDIENT-SPECIFIC PIECE MAPPINGS
 * Only use if explicit grams NOT provided in amount string
 */
const INGREDIENT_PIECE_MAPPINGS = {
  'chicken breast': 150,
  'chicken thigh': 100,
  'egg': 50,
  'potato': 170,
  'tomato': 150,
  'onion': 150,
  'garlic clove': 3,
  'clove': 3,
  'slice': 30,
  'can': 400,
  'bunch': 100,
};

/**
 * Parse ingredient amount string and extract quantity, unit, and grams
 * 
 * Handles formats like:
 * - "2 cups"
 * - "300g"
 * - "2 pieces (about 300g)"
 * - "1 (about 300g)"
 * - "300"
 * 
 * @returns {object} { quantity, unit, grams, raw }
 */
export function parseIngredientAmount(amountStr) {
  if (!amountStr) return { quantity: 1, unit: '', grams: null, raw: amountStr };

  const str = String(amountStr).trim();

  // Match: number [unit] (about XXXg)
  const fullMatch = str.match(/^([\d.]+)\s*([a-z\s]*?)\s*\(\s*about\s+([\d.]+)\s*g\s*\)/i);
  if (fullMatch) {
    return {
      quantity: parseFloat(fullMatch[1]),
      unit: fullMatch[2].trim(),
      grams: parseFloat(fullMatch[3]),
      raw: str,
    };
  }

  // Match: number unit
  const unitMatch = str.match(/^([\d.]+)\s+([a-z\s]+)$/i);
  if (unitMatch) {
    return {
      quantity: parseFloat(unitMatch[1]),
      unit: unitMatch[2].trim(),
      grams: null,
      raw: str,
    };
  }

  // Match: just number (grams assumed)
  const numMatch = str.match(/^([\d.]+)\s*g?$/i);
  if (numMatch) {
    return {
      quantity: parseFloat(numMatch[1]),
      unit: 'g',
      grams: parseFloat(numMatch[1]),
      raw: str,
    };
  }

  return { quantity: 1, unit: '', grams: null, raw: str };
}

/**
 * Normalize ingredient into canonical form
 * 
 * STRICT MODE: No silent fallbacks. Every ingredient must have explicit grams.
 * 
 * @param {object} ingredient - { name, amount, ... }
 * @param {object} options - { strict: false }
 * @returns {object} Normalized: { base_grams, grams_confidence, ... }
 * @throws Error if strict=true and grams cannot be determined
 */
export function normalizeIngredient(ingredient, options = {}) {
  const { strict = false } = options;
  const parsed = parseIngredientAmount(ingredient.amount);

  let baseGrams = null;
  let displayUnit = parsed.unit;
  let gramsPerUnit = null;
  let confidence = 'estimated';

  // Priority 1: Explicit grams in "(about XXXg)" format
  if (parsed.grams !== null) {
    baseGrams = parsed.grams;
    gramsPerUnit = parsed.grams / parsed.quantity;
    confidence = 'explicit';
  }
  // Priority 2: Pure gram units
  else if (parsed.unit === 'g' || parsed.unit === '') {
    baseGrams = parsed.quantity;
    displayUnit = 'g';
    gramsPerUnit = 1;
    confidence = 'explicit';
  }
  // Priority 3: Known volume/weight conversions (cup, tbsp, oz, lb, etc.)
  else {
    const unitKey = parsed.unit.toLowerCase().replace(/s$/, ''); // singular
    const knownConversion = UNIT_CONVERSIONS[unitKey];

    if (knownConversion) {
      baseGrams = parsed.quantity * knownConversion;
      gramsPerUnit = knownConversion;
      confidence = 'volume-converted';
    }
    // Priority 4: Ingredient-specific piece mappings (chicken breast, egg, etc.)
    else if (parsed.unit.toLowerCase() === 'piece' || parsed.unit.toLowerCase() === 'pieces') {
      const ingredientKey = (ingredient.name || '').toLowerCase();
      let pieceGrams = null;

      // Try exact match first
      for (const [key, grams] of Object.entries(INGREDIENT_PIECE_MAPPINGS)) {
        if (ingredientKey === key) {
          pieceGrams = grams;
          break;
        }
      }
      // Try substring match
      if (!pieceGrams) {
        for (const [key, grams] of Object.entries(INGREDIENT_PIECE_MAPPINGS)) {
          if (ingredientKey.includes(key)) {
            pieceGrams = grams;
            break;
          }
        }
      }

      if (pieceGrams) {
        baseGrams = parsed.quantity * pieceGrams;
        gramsPerUnit = pieceGrams;
        confidence = 'ingredient-specific';
      } else if (strict) {
        throw new Error(
          `INGREDIENT_GRAMS_MISSING: "${ingredient.name}" with unit "piece" requires explicit "(about XXXg)" or ingredient-specific mapping. ` +
          `Strict mode enabled—cannot assume default gram weight.`
        );
      } else {
        // Fallback only in non-strict mode (legacy)
        baseGrams = parsed.quantity * 100;
        gramsPerUnit = 100;
        confidence = 'estimated-fallback-unsafe';
      }
    }
    // Unknown unit
    else if (strict) {
      throw new Error(
        `MISSING_UNIT_CONVERSION: Unknown unit "${parsed.unit}" for ingredient "${ingredient.name}". ` +
        `Provide explicit grams in format: amount unit (about XXXg)`
      );
    } else {
      // Fallback only in non-strict mode (legacy)
      baseGrams = 100;
      gramsPerUnit = 100;
      confidence = 'estimated-fallback-unsafe';
    }
  }

  return {
    ...ingredient,
    // Canonical fields (ALWAYS present)
    base_grams: Math.round(baseGrams * 10) / 10,
    display_unit: displayUnit || 'g',
    grams_per_unit: gramsPerUnit,
    // Metadata for verification
    grams_confidence: confidence,
    original_amount: ingredient.amount,
  };
}

/**
 * Scale ingredient for user servings
 * Returns { amount, display_unit, grams_text }
 */
export function scaleIngredientForDisplay(ingredient, scaleFactor) {
  const normalized = normalizeIngredient(ingredient);
  const scaledGrams = normalized.base_grams * scaleFactor;
  const scaledUnits = scaledGrams / normalized.grams_per_unit;

  // Format units
  const displayUnits = formatQuantity(scaledUnits);
  const displayGrams = formatGrams(scaledGrams);

  // Render: "4 pieces (about 600g)" or "0.5 cup (about 120g)"
  let amountStr = '';
  if (normalized.display_unit && normalized.display_unit !== 'g') {
    amountStr = `${displayUnits} ${normalized.display_unit}${displayUnits !== '1' && parseFloat(displayUnits) !== 1 ? 's' : ''} (about ${displayGrams})`;
  } else {
    amountStr = displayGrams;
  }

  return {
    amount: amountStr,
    base_grams: normalized.base_grams,
    scaled_grams: scaledGrams,
    grams_per_unit: normalized.grams_per_unit,
  };
}

/**
 * Format quantity for display (hide 1.0, show decimals otherwise)
 */
function formatQuantity(value) {
  if (Math.abs(value - Math.round(value)) < 0.05) {
    return String(Math.round(value));
  }
  return (Math.round(value * 10) / 10).toString();
}

/**
 * Format grams for display
 * <10g: 0.1 precision
 * 10-999g: 1g precision
 * >=1000g: kg with 1 decimal
 */
function formatGrams(grams) {
  if (grams < 10) {
    return `${(Math.round(grams * 10) / 10).toFixed(1)}g`;
  }
  if (grams < 1000) {
    return `${Math.round(grams)}g`;
  }
  return `${(Math.round(grams / 100) / 10).toFixed(1)}kg`;
}

export { formatGrams, formatQuantity };

/**
 * Global cost formatter — single source of truth for all cost displays.
 *
 * NOTE: This is a STATIC fallback only for non-hook contexts.
 * All React components should use `formatPrice()` from `useLocalization()` instead.
 *
 * This function is kept for backward compatibility in non-React contexts only.
 * It does NOT apply currency conversion (returns USD always).
 *
 * For proper multi-currency support in React components, use:
 *   import { useLocalization } from '@/services/localization/LocalizationContext';
 *   const { formatPrice } = useLocalization();
 *   formatPrice(usdAmount) // → "₪123.45" or "€99.99" etc.
 */

/**
 * Format a USD cost for display — single source of truth for static (non-hook) contexts.
 * Matches the behaviour of formatCurrency('USD') from LocalizationContext exactly:
 *   < $0.005  → null    (don't display)
 *   < $0.10   → "4¢"   (cents, no decimal clutter)
 *   < $1.00   → "$0.57" (two decimal places)
 *   ≥ $1.00   → "$3.20" (two decimal places)
 *
 * React components should prefer formatPrice() from useLocalization() so the user's
 * chosen currency (₪, €, etc.) is respected automatically.
 */
export function formatCostForDisplay(amount) {
  if (amount == null || amount <= 0) return null;
  if (amount < 0.005) return null;
  if (amount < 0.10) {
    const cents = Math.round(amount * 100);
    return cents > 0 ? `${cents}¢` : null;
  }
  return `$${amount.toFixed(2)}`;
}

