  console.assert(
    confidence === 'estimated-fallback-unsafe',
    `[TEST 5 FAIL] Expected 'estimated-fallback-unsafe' confidence, got '${confidence}'`
  );

  console.log('✓ TEST 5 PASSED: Fallback marked as unsafe for tracking');
  return true;
}

/**
 * TEST 6: Recipe macro calculation (Quinoa + Chicken example)
 */
export function testRecipeMacroCalculation() {
  // Quinoa: 0.5 cup = 120g, 120 cal/100g = 144 cal
  // Chicken: 150g, 165 cal/100g = 247.5 cal
  // Total: 391.5 cal

  const ingredients = [
    { name: "quinoa", base_grams: 120, nutrition_per_100g: { kcal: 120, protein_g: 4.4, carbs_g: 21, fat_g: 1.9 } },
    { name: "chicken breast", base_grams: 150, nutrition_per_100g: { kcal: 165, protein_g: 31, carbs_g: 0, fat_g: 3.6 } }
  ];

  let totalCals = 0;
  let totalProtein = 0;

  for (const ing of ingredients) {
    const nut = calculateIngredientNutrition(ing, ing.base_grams);
    totalCals += nut.kcal;
    totalProtein += nut.protein_g;
  }

  const expectedCals = 144 + 247.5; // 391.5
  const expectedProtein = 5.28 + 46.5; // 51.78

  console.assert(
    Math.abs(totalCals - expectedCals) < 1,
    `[TEST 6 FAIL] Expected ~391.5 cal, got ${totalCals}`
  );
  console.assert(
    Math.abs(totalProtein - expectedProtein) < 1,
    `[TEST 6 FAIL] Expected ~51.78g protein, got ${totalProtein}`
  );

  console.log('✓ TEST 6 PASSED: Recipe macro calculation verified');
  return true;
}

/**
 * TEST 7: Per-serving consistency (no double scaling)
 */
export function testPerServingConsistency() {
  const recipeTotalNutrition = {
    kcal: 391.5,
    protein_g: 51.78,
    carbs_g: 25.2,
    fat_g: 5.5
  };

  const servings = 2;
  const perServing = {
    kcal: recipeTotalNutrition.kcal / servings,
    protein_g: recipeTotalNutrition.protein_g / servings,
    carbs_g: recipeTotalNutrition.carbs_g / servings,
    fat_g: recipeTotalNutrition.fat_g / servings
  };

  // Verify scaling is reversible
  const rescaledTotal = {
    kcal: perServing.kcal * servings,
    protein_g: perServing.protein_g * servings,
    carbs_g: perServing.carbs_g * servings,
    fat_g: perServing.fat_g * servings
  };

  const tolerance = 0.1; // Rounding tolerance
  console.assert(
    Math.abs(rescaledTotal.kcal - recipeTotalNutrition.kcal) < tolerance,
    `[TEST 7 FAIL] Double scaling mismatch: ${rescaledTotal.kcal} vs ${recipeTotalNutrition.kcal}`
  );

  console.log('✓ TEST 7 PASSED: Per-serving consistency verified');
  return true;
}

/**
 * TEST 8: Invalid grams validation
 */
export function testInvalidGramsValidation() {
  const testCases = [
    { grams: null, shouldFail: true },
    { grams: 0, shouldFail: true },
    { grams: -10, shouldFail: true },
    { grams: "not a number", shouldFail: true },
    { grams: 150, shouldFail: false }
  ];

  let allPassed = true;

  for (const testCase of testCases) {
    try {
      // Simulate backend validation
      if (testCase.grams === null || testCase.grams === undefined || testCase.grams === 0) {
        throw new Error('INVALID_GRAMS');
      }
      if (typeof testCase.grams !== 'number' || testCase.grams < 0.1) {
        throw new Error('INVALID_GRAMS');
      }

      if (testCase.shouldFail) {
        console.error(`[TEST 8 FAIL] Expected validation to fail for grams=${testCase.grams}`);
        allPassed = false;
      }
    } catch (err) {
      if (!testCase.shouldFail) {
        console.error(`[TEST 8 FAIL] Expected validation to pass for grams=${testCase.grams}`);
        allPassed = false;
      }
    }
  }

  if (allPassed) {
    console.log('✓ TEST 8 PASSED: Invalid grams validation');
  }
  return allPassed;
}

/**
 * Run all tests
 */
export function runAllTests() {
  console.log('\n========== NUTRITION SYSTEM TESTS ==========\n');

  const results = [];
  const tests = [
    testExplicitGrams,
    testVolumeConversion,
    testIngredientSpecificPiece,
    testMissingGramsStrict,
    testNoSilentFallback,
    testRecipeMacroCalculation,
    testPerServingConsistency,
    testInvalidGramsValidation
  ];

  for (const test of tests) {
    try {
      results.push(test());
    } catch (err) {
      console.error(`✗ ${test.name} threw error:`, err.message);
      results.push(false);
    }
  }

  const passed = results.filter(r => r).length;
  const total = results.length;

  console.log(`\n========== RESULTS ==========`);
  console.log(`${passed}/${total} tests passed`);

  if (passed === total) {
    console.log('✓ ALL TESTS PASSED - Nutrition system is canonical');
  } else {
    console.error(`✗ ${total - passed} tests failed`);
  }

  return passed === total;
}

// Auto-run in development
if (typeof window !== 'undefined' && window.__DEBUG_NUTRITION_TESTS) {
  runAllTests();
}

/**
 * useRecipeLikeController — routes recipe likes through the UNIFIED like system.
 *
 * CRITICAL: RecipeCard and RecipeDetail MUST share the SAME store key and SAME backend.
 * The unified system uses key "recipe:<recipeId>" and calls toggleLikeUnified.
 * This shim wraps useLikeUnified so both surfaces are always in sync.
 */
import { useLikeUnified } from '@/components/hooks/useLikeUnified';

export function useRecipeLike(recipeId, initialLiked = false, initialCount = 0) {
  const { like_count, viewer_has_liked, toggleLike, disabled, inFlight } = useLikeUnified(
    'recipe',
    recipeId,
    initialLiked,
    initialCount
  );
  return {
    liked: viewer_has_liked,
    likesCount: like_count,
    count: like_count,
    toggle: toggleLike,
    inFlight,
    blocked: disabled,
  };
}

