  vegan: "bg-emerald-50 text-emerald-600 border-emerald-100",
  vegetarian: "bg-lime-50 text-lime-600 border-lime-100",
  "gluten-free": "bg-purple-50 text-purple-600 border-purple-100",
  "dairy-free": "bg-sky-50 text-sky-600 border-sky-100",
  keto: "bg-orange-50 text-orange-600 border-orange-100",
  "high-protein": "bg-red-50 text-red-600 border-red-100",
