// Low-cost threshold (per serving, USD)
const LOW_COST_MAX_PER_SERVING = 6;

function getNutrition(recipe) {
  const n = recipe.nutrition_per_serving;
  if (n?.calories > 0 || n?.protein > 0) return n;
  const t = recipe.nutrition_total_for_recipe;
  const s = recipe.servings || 1;
  if (t?.calories > 0) return { calories: Math.round(t.calories / s), protein: Math.round((t.protein || 0) / s) };
  const l = recipe.nutrition;
  if (l?.calories > 0) return l;
  return null;
}

function formatCost(cost) {
  if (cost == null || cost <= 0) return null;
  if (cost < 1) return `${Math.round(cost * 100)}¢`;
  return `$${cost.toFixed(2)}`;
}

// Mini star row — always rendered (muted if 0)
function StarRow({ rating = 0, count = 0, size = "sm" }) {
  const filled = Math.round(rating);
  const starSize = size === "sm" ? "w-2.5 h-2.5" : "w-3.5 h-3.5";
  const hasRating = rating > 0;
  return (
    <div className="flex items-center gap-0.5">
      {[1, 2, 3, 4, 5].map(i => (
        <Star
          key={i}
          className={cn(starSize, i <= filled && hasRating ? "text-amber-400 fill-amber-400" : "text-slate-200 fill-slate-100")}
        />
      ))}
      <span className={cn("ml-1 font-semibold", size === "sm" ? "text-[9px]" : "text-[11px]", hasRating ? "text-slate-500" : "text-slate-300")}>
        {hasRating ? `${rating.toFixed(1)}` : "—"}<span className="font-normal text-slate-300"> ({count})</span>
      </span>
    </div>
  );
}

