import React from 'react';
import { Sparkles, CheckCircle2, AlertCircle } from 'lucide-react';
import { cn } from '@/lib/utils';

/**
 * RecipeIntelligenceMetadataPanel — Shows AI enhancements and quality indicators
 * 
 * Props:
 * - metadata: { aiAddedCount, tasteBalance, userSelectedCount }
 * - diversityHint: optional tip about recipe variation
 */
export default function RecipeIntelligenceMetadataPanel({ metadata, diversityHint }) {
  if (!metadata) return null;

  const { aiAddedCount = 0, tasteBalance = {}, userSelectedCount = 0 } = metadata;
  const { balanced, missing = [], analysis = {} } = tasteBalance;

  return (
    <div className="space-y-2 mt-3 pt-3 border-t border-slate-200">
      {/* AI Enhancement Summary */}
      {aiAddedCount > 0 && (
        <div className="flex items-start gap-2 p-2 rounded-lg bg-indigo-50 border border-indigo-150">
          <Sparkles className="w-4 h-4 text-indigo-600 mt-0.5 flex-shrink-0" />
          <div className="text-xs">
            <p className="font-semibold text-indigo-900">AI Enhanced</p>
            <p className="text-indigo-700 mt-0.5">
              Added {aiAddedCount} complementary ingredient{aiAddedCount !== 1 ? 's' : ''} for flavor balance
            </p>
          </div>
        </div>
      )}

      {/* Flavor Balance Status */}
      <div className={cn(
        'flex items-start gap-2 p-2 rounded-lg border',
        balanced
          ? 'bg-emerald-50 border-emerald-200'
          : 'bg-amber-50 border-amber-200'
      )}>
        {balanced ? (
          <CheckCircle2 className="w-4 h-4 text-emerald-600 mt-0.5 flex-shrink-0" />
        ) : (
          <AlertCircle className="w-4 h-4 text-amber-600 mt-0.5 flex-shrink-0" />
        )}
        <div className="text-xs flex-1">
          <p className={cn(
            'font-semibold',
            balanced ? 'text-emerald-900' : 'text-amber-900'
          )}>
            Flavor Balance: {balanced ? 'Complete' : 'Incomplete'}
          </p>
          {balanced ? (
            <p className="text-emerald-700 mt-0.5">
              ✓ Protein • ✓ Sauce/Seasoning • ✓ Texture • ✓ Fresh Elements
            </p>
          ) : (
            <p className="text-amber-700 mt-0.5">
              Missing: {missing.join(', ')}
            </p>
          )}
        </div>
      </div>

      {/* Diversity Hint */}
      {diversityHint && (
        <div className="flex items-start gap-2 p-2 rounded-lg bg-violet-50 border border-violet-200">
          <span className="text-base mt-0.5">🎯</span>
          <p className="text-xs text-violet-900">{diversityHint}</p>
        </div>
      )}

      {/* User-selected vs AI-added ratio */}
      {(userSelectedCount > 0 || aiAddedCount > 0) && (
        <div className="text-[10px] text-slate-500 text-center pt-1">
          {userSelectedCount} from your pantry • {aiAddedCount} AI-added
        </div>
      )}
    </div>
  );
}
